window.HADITH_CACHE["abu-dawud_2"] = {"1001":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ وَمُسَدَّدٌ قَالَا حَدَّثَنَا يَحْيَى عَنْ ابْنِ جُرَيْجٍ ح و حَدَّثَنَا خُشَيْشٌ يَعْنِي ابْنَ أَصْرَمَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ ابْنِ جُرَيْجٍ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي عَمَّارٍ عَنْ عَبْدِ اللَّهِ بْنِ بَابَيْهِ عَنْ يَعْلَى بْنِ أُمَيَّةَ قَالَقُلْتُ لِعُمَرَ بْنِ الْخَطَّابِ أَرَأَيْتَ إِقْصَارَ النَّاسِ الصَّلَاةَ وَإِنَّمَا قَالَ تَعَالَى{ إِنْ خِفْتُمْ أَنْ يَفْتِنَكُمْ الَّذِينَ كَفَرُوا }فَقَدْ ذَهَبَ ذَلِكَ الْيَوْمَ فَقَالَ عَجِبْتُ مِمَّا عَجِبْتَ مِنْهُ فَذَكَرْتُ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ صَدَقَةٌ تَصَدَّقَ اللَّهُ بِهَا عَلَيْكُمْ فَاقْبَلُوا صَدَقَتَهُحَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ وَمُحَمَّدُ بْنُ بَكْرٍ قَالَا أَخْبَرَنَا ابْنُ جُرَيْجٍ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي عَمَّارٍ يُحَدِّثُ فَذَكَرَهُ نَحْوَهُ قَالَ أَبُو دَاوُد رَوَاهُ أَبُو عَاصِمٍ وَحَمَّادُ بْنُ مَسْعَدَةَ كَمَا رَوَاهُ ابْنُ بَكْرٍ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] dan [Musaddad] keduanya berkata; telah menceritakan kepada kami [Yahya] dari [Ibnu Juraij]. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Khusyaisy yaitu Ibnu Ashram] telah menceritakan kepada kami [Abdurrazaq] dari [Ibnu Juraij] dia berkata; telah menceritakan kepadaku [Abdurrahman bin Abdullah bin Abu 'Ammar] dari [Abdullah bin Babaih] dari [Ya'la bin Umayyah] dia berkata; aku bertanya kepada Umar bin Khattab; \"Bagaimana pendapat anda mengenai orang-orang yang meng-qashar shalatnya karena firman Allah; \"…Jika kamu takut di serang oleh orang-orang kafir…\" QS An Nisaa'; 101, padahal rasa takut itu telah hilang saat sekarang ini.\" [Umar] berkata; \"Sebenarnya aku juga heran seperti yang kamu herankan itu, oleh karena itu, aku sampaikan masalah tersebut kepada Rasulullah shallallahu 'alaihi wasallam, justru beliau menjawab: \"Itu merupakan sedekah Allah terhadap kalian, oleh karena itu, terimalah sedekah-Nya.\" Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Abdurrazaq] dan [Muhammad bin Bakr] keduanya berkata; telah mengabarkan kepada kami [Ibnu Juraij] saya mendengar [Abdullah bin Abu 'Ammar] bercerita …\" kemudian ia menyebutkan hadits yang semisalnya, Abu Daud mengatakan; \"Di riwayatkan pula oleh [Abu 'Ashim] dan [Hammad bin Mas'adah] sebagaimana yang di riwayatkan oleh Ibnu Bakr.\""},"1002":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ يَحْيَى بْنِ يَزِيدَ الْهُنَائِيِّ قَالَسَأَلْتُ أَنَسَ بْنَ مَالِكٍ عَنْ قَصْرِ الصَّلَاةِ فَقَالَ أَنَسٌ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَرَجَ مَسِيرَةَ ثَلَاثَةِ أَمْيَالٍ أَوْ ثَلَاثَةِ فَرَاسِخَ شَكَّ شُعْبَةُ يُصَلِّي رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Yahya bin Yazid Al Huna`i] dia berkata; saya bertanya kepada Anas bin Malik tentang mengqashr shalat, maka [Anas] menjawab; \"Apabila Rasulullah shallallahu 'alaihi wasallam bepergian sejauh perjalanan tiga mil atau tiga farsakh -Syu'bah ragu- maka beliau shalat dua raka'at.\""},"1003":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ وَإِبْرَاهِيمَ بْنِ مَيْسَرَةَ سَمِعَا أَنَسَ بْنَ مَالِكٍ يَقُولُصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ بِالْمَدِينَةِ أَرْبَعًا وَالْعَصْرَ بِذِي الْحُلَيْفَةِ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Muhammad bin Al Munkadir] dan [Ibrahim bin Maisarah] keduanya mendengar [Anas bin Malik] berkata; \"Aku shalat dluhur empat raka'at di Madinah bersama Rasulullah shallallahu 'alaihi wasallam, dan shalat Ashar dua raka'at di Dzul Hulaifah.\""},"1004":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ أَنَّ أَبَا عُشَّانَةَ الْمَعَافِرِيَّ حَدَّثَهُ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَعْجَبُ رَبُّكُمْ مِنْ رَاعِي غَنَمٍ فِي رَأْسِ شَظِيَّةٍ بِجَبَلٍ يُؤَذِّنُ بِالصَّلَاةِ وَيُصَلِّي فَيَقُولُ اللَّهُ عَزَّ وَجَلَّ انْظُرُوا إِلَى عَبْدِي هَذَا يُؤَذِّنُ وَيُقِيمُ الصَّلَاةَ يَخَافُ مِنِّي قَدْ غَفَرْتُ لِعَبْدِي وَأَدْخَلْتُهُ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Harun bin Ma'ruf] telah menceritakan kepada kami [Ibnu Wahb] dari ['Amru bin Al harits] bahwa [Abu 'Usyanah Al Ma'afiri] telah menceritakan dari ['Uqbah bin 'Amir] dia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Rabb kalian kagum terhadap seorang yang mengumandangkan shalat di atas bukit, kemudian dia shalat, maka Allah Azza wa Jalla berfirman; \"Lihatlah kepada hamba-Ku ini, dia mengumandangkan adzan lalu shalat karena takut kepada-Ku, Aku telah mengampuni dosa hamba-Ku dan memasukkannya ke dalam surga.\""},"1005":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْمِسْحَاجِ بْنِ مُوسَى قَالَ قُلْتُ لِأَنَسِ بْنِ مَالِكٍحَدِّثْنَا مَا سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُنَّا إِذَا كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي السَّفَرِ فَقُلْنَا زَالَتْ الشَّمْسُ أَوْ لَمْ تَزُلْ صَلَّى الظُّهْرَ ثُمَّ ارْتَحَلَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al Mishaj bin Musa] dia berkata; kataku kepada [Anas bin Malik]; \"Sampaikanlah kepada kami sesuatu yang anda dengar dari Rasulullah shallallahu 'alaihi wasallam!.\" Anas berkata; \"Apabila kami bepergian bersama Rasulullah shallallahu 'alaihi wasallam, maka kami berkata; \"Matahari telah tergelincir atau belum, beliau kemudian shalat dluhur lalu melanjutkan perjalanan.\""},"1006":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ حَدَّثَنِي حَمْزَةُ الْعَائِذِيُّ رَجُلٌ مِنْ بَنِي ضَبَّةَ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا نَزَلَ مَنْزِلًا لَمْ يَرْتَحِلْ حَتَّى يُصَلِّيَ الظُّهْرَ فَقَالَ لَهُ رَجُلٌ وَإِنْ كَانَ بِنِصْفِ النَّهَارِ قَالَ وَإِنْ كَانَ بِنِصْفِ النَّهَارِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Syu'bah] telah menceritakan kepadaku [Hamzah Al 'A`idzi] -seorang laki-laki dari Bani Dlabbah- dia berkata; saya mendengar [Anas bin Malik] berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam singgah di suatu tempat, beliau tidak melanjutkan perjalanannya sehingga beliau shalat dluhur.\" Maka laki-laki tersebut berkata; \"Meskipun berada pada tengah hari?\" Anas menjawab; \"Meskipun berada di tengah hari.\""},"1007":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ أَبِي الزُّبَيْرِ الْمَكِّيِّ عَنْ أَبِي الطُّفَيْلِ عَامِرِ بْنِ وَاثِلَةَ أَنَّ مُعَاذَ بْنَ جَبَلٍ أَخْبَرَهُمْأَنَّهُمْ خَرَجُوا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجْمَعُ بَيْنَ الظُّهْرِ وَالْعَصْرِ وَالْمَغْرِبِ وَالْعِشَاءِ فَأَخَّرَ الصَّلَاةَ يَوْمًا ثُمَّ خَرَجَ فَصَلَّى الظُّهْرَ وَالْعَصْرَ جَمِيعًا ثُمَّ دَخَلَ ثُمَّ خَرَجَ فَصَلَّى الْمَغْرِبَ وَالْعِشَاءَ جَمِيعًا","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Abu Az Zubair Al Makki] dari [Abu Ath Thufail 'Amir bin Watsilah] bahwa [Mu'adz bin Jabal] mengabarkan kepada mereka, bahwa mereka (kaum Muslimin) keluar bersama Rasulullah shallallahu 'alaihi wasallam pada waktu perang Tabuk, dan Rasulullah shallallahu 'alaihi wasallam menjama' shalat antara shalat Dluhur dan Ashar, dan antara shalat Maghrib dan Isya', suatu hari beliau mengakhirkan shalat, kemudian beliau keluar untuk mengerjakan shalat Dluhur dan Ashar secara jama', kemudian beliau masuk (tenda), setelah itu beliau keluar lalu mengerjakan shalat Maghrib dan Isya' secara jama'.\""},"1008":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْعَتَكِيُّ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا أَيُّوبُ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَاسْتُصْرِخَ عَلَى صَفِيَّةَ وَهُوَ بِمَكَّةَ فَسَارَ حَتَّى غَرَبَتْ الشَّمْسُ وَبَدَتْ النُّجُومُ فَقَالَ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا عَجِلَ بِهِ أَمْرٌ فِي سَفَرٍ جَمَعَ بَيْنَ هَاتَيْنِ الصَّلَاتَيْنِفَسَارَ حَتَّى غَابَ الشَّفَقُ فَنَزَلَ فَجَمَعَ بَيْنَهُمَا","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al 'Ataki] telah menceritakan kepada kami [Hammad] telah menceritakan kepada kami [Ayyub] dari [Nafi'] bahwa [Ibnu Umar] di beritahu tentang wafatnya Shafiyah, ketika itu ia berada di Makkah. Kemudian dia berangkat hingga matahari terbenam dan bintang-bintang mulai muncul, lalu dia berkata; \"Sesungguhnya apabila Nabi shallallahu 'alaihi wasallam mengalami kesulitan perkara dalam suatu perjalanan, maka beliau menjama' dua shalat ini, lalu beliau berangkat. Setelah awan merah hilang, ia singgah dan menjama' kedua shalat tersebut.\""},"1009":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ خَالِدِ بْنِ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ مَوْهَبٍ الرَّمْلِيُّ الْهَمْدَانِيُّ حَدَّثَنَا الْمُفَضَّلُ بْنُ فَضَالَةَ وَاللَّيْثُ بْنُ سَعْدٍ عَنْ هِشَامِ بْنِ سَعْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ أَبِي الطُّفَيْلِ عَنْ مُعَاذِ بْنِ جَبَلٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ فِي غَزْوَةِ تَبُوكَ إِذَا زَاغَتْ الشَّمْسُ قَبْلَ أَنْ يَرْتَحِلَ جَمَعَ بَيْنَ الظُّهْرِ وَالْعَصْرِ وَإِنْ يَرْتَحِلْ قَبْلَ أَنْ تَزِيغَ الشَّمْسُ أَخَّرَ الظُّهْرَ حَتَّى يَنْزِلَ لِلْعَصْرِ وَفِي الْمَغْرِبِ مِثْلُ ذَلِكَ إِنْ غَابَتْ الشَّمْسُ قَبْلَ أَنْ يَرْتَحِلَ جَمَعَ بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ وَإِنْ يَرْتَحِلْ قَبْلَ أَنْ تَغِيبَ الشَّمْسُ أَخَّرَ الْمَغْرِبَ حَتَّى يَنْزِلَ لِلْعِشَاءِ ثُمَّ جَمَعَ بَيْنَهُمَاقَالَ أَبُو دَاوُد رَوَاهُ هِشَامُ بْنُ عُرْوَةَ عَنْ حُسَيْنِ بْنِ عَبْدِ اللَّهِ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ حَدِيثِ الْمُفَضَّلِ وَاللَّيْثِ","id":"Telah menceritakan kepada kami [Yazid bin Khalid bin Yazid bin Abdullah bin Mauhab Ar Ramli Al Hamdani] telah menceritakan kepada kami [AL Mufadlal bin Fadlalah] dan [Laits bin Sa'd] dari [Hisyam bin Sa'ad] dari [Abu Az Zubair] dari [Abu Ath Thufail] dari [Mu'adz bin Jabal] bahwa pada waktu Rasulullah shallallahu 'alaihi wasallam perang Tabuk, ketika matahari telah tergelincir sebelum berangkat, maka beliau menjama' antara shalat Dluhur dan shalat Ashar. Dan jika beliau berangkat sebelum matahari tergelincir, maka beliau mengundurkan Dluhur sehingga beliau singgah untuk shalat Ashar, demikian pula ketika shalat Maghrib, apabila Matahari telah terbenam sebelum berangkat, maka beliau menjama' antara Maghrib dan Isya', dan jika berangkat sebelum matahari terbenam, beliau mengakhirkan shalat Maghrib, sehingga beliau singgah pada waktu Isya', kemudian beliau menjama' keduanya.\" Abu Daud mengatakan; \"Telah di riwayatkan pula oleh [Hisyam bin 'Urwah] dari [Husain bin Abdullah] dari [Kuraib] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam sebagaimana hadits Al Mufadlal dan Al Laits.\""},"1010":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نَافِعٍ عَنْ أَبِي مَوْدُودٍ عَنْ سُلَيْمَانَ بْنِ أَبِي يَحْيَى عَنْ ابْنِ عُمَرَ قَالَمَا جَمَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ قَطُّ فِي السَّفَرِ إِلَّا مَرَّةًقَالَ أَبُو دَاوُد وَهَذَا يُرْوَى عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ مَوْقُوفًا عَلَى ابْنِ عُمَرَ أَنَّهُ لَمْ يَرَ ابْنَ عُمَرَ جَمَعَ بَيْنَهُمَا قَطُّ إِلَّا تِلْكَ اللَّيْلَةَ يَعْنِي لَيْلَةَ اسْتُصْرِخَ عَلَى صَفِيَّةَ وَرُوِيَ مِنْ حَدِيثِ مَكْحُولٍ عَنْ نَافِعٍ أَنَّهُ رَأَى ابْنَ عُمَرَ فَعَلَ ذَلِكَ مَرَّةً أَوْ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abdullah bin Nafi'] dari [Abu Maudud] dari [Sulaiman bin Abu Yahya] dari [Ibnu Umar] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam sama sekali tidak pernah menjama' shalat Maghrib dan Isya' dalam suatu perjalanan kecuali hanya sekali.\" Abu Daud mengatakan; \"Hadits ini di riwayatkan dari [Ayyub] dari [Nafi'] dari [Ibnu Umar]. Mauquf sampai Ibnu Umar, bahwa dirinya tidak pernah melihat bila beliau pernah menjama' keduanya kecuali hanya malam itu, yaitu malam ketika dia di beritahu wafatnya Shafiyah, dan di riwayatkan pula dari haditsnya [Makhul] dari [Nafi'] bahwa dia melihat [Ibnu Umar] melakukan hal itu hanya sekali atau dua kali.\""},"1011":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ أَبِي الزُّبَيْرِ الْمَكِّيِّ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ وَالْعَصْرَ جَمِيعًا وَالْمَغْرِبَ وَالْعِشَاءَ جَمِيعًا فِي غَيْرِ خَوْفٍ وَلَا سَفَرٍقَالَ قَالَ مَالِكٌ أَرَى ذَلِكَ كَانَ فِي مَطَرٍ قَالَ أَبُو دَاوُد وَرَوَاهُ حَمَّادُ بْنُ سَلَمَةَ نَحْوَهُ عَنْ أَبِي الزُّبَيْرِ وَرَوَاهُ قُرَّةُ بْنُ خَالِدٍ عَنْ أَبِي الزُّبَيْرِ قَالَ فِي سَفْرَةٍ سَافَرْنَاهَا إِلَى تَبُوكَ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Abu Az Zubair Al Makki] dari [Sa'id bin Jubair] dari [Abdullah bin 'Abbas] dia berkata; Rasulullah mengerjakan shalat Dluhur dan Ashar secara Jama', dan shalat Maghrib dan Isya' secara Jama' tidak dalam kondisi ketakutan atau dalam perjalanan.\" (perawi berkata; Malik berkata; \"Aku berpendapat, beliau melakukan hal itu karena kondisi sedang hujan.\" Abu Daud berkata; \"Dan telah diriwayatkan pula oleh [Hammad bin Salamah] seperti hadits tersebut, dari [Abu Az Zubair], dan di riwayatkan oleh [Qurrah bin Khalid] dari [Abu Az Zubair] dia berkata; \"…Yaitu dalam perjalanan ketika kami ke Tabuk.\""},"1012":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَجَمَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ الظُّهْرِ وَالْعَصْرِ وَالْمَغْرِبِ وَالْعِشَاءِ بِالْمَدِينَةِ مِنْ غَيْرِ خَوْفٍ وَلَا مَطَرٍفَقِيلَ لِابْنِ عَبَّاسٍ مَا أَرَادَ إِلَى ذَلِكَ قَالَ أَرَادَ أَنْ لَا يُحْرِجَ أُمَّتَهُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masy] dari [Habib bin Abu Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah menjama' shalat Dluhur dan Ashar, antara shalat Maghrib dan Isya' di Madinah, tidak dalam kondisi ketakutan, tidak pula hujan.\" Maka di tanyakan hal itu kepada Ibnu Abbas; \"Apa maksud beliau melakukan hal itu?\" Ibnu Abbas menjawab; \"Supaya tidak memberatkan umatnya.\""},"1013":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ الْمُحَارِبِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ أَبِيهِ عَنْ نَافِعٍ وَعَبْدِ اللَّهِ بْنِ وَاقِدٍأَنَّ مُؤَذِّنَ ابْنِ عُمَرَ قَالَ الصَّلَاةُ قَالَ سِرْ سِرْ حَتَّى إِذَا كَانَ قَبْلَ غُيُوبِ الشَّفَقِ نَزَلَ فَصَلَّى الْمَغْرِبَ ثُمَّ انْتَظَرَ حَتَّى غَابَ الشَّفَقُ وَصَلَّى الْعِشَاءَ ثُمَّ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا عَجِلَ بِهِ أَمْرٌ صَنَعَ مِثْلَ الَّذِي صَنَعْتُ فَسَارَ فِي ذَلِكَ الْيَوْمِ وَاللَّيْلَةِ مَسِيرَةَ ثَلَاثٍقَالَ أَبُو دَاوُد رَوَاهُ ابْنُ جَابِرٍ عَنْ نَافِعٍ نَحْوَ هَذَا بِإِسْنَادِهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ أَخْبَرَنَا عِيسَى عَنْ ابْنِ جَابِرٍ بِهَذَا الْمَعْنَى قَالَ أَبُو دَاوُد وَرَوَاهُ عَبْدُ اللَّهِ بْنُ الْعَلَاءِ عَنْ نَافِعٍ قَالَ حَتَّى إِذَا كَانَ عِنْدَ ذَهَابِ الشَّفَقِ نَزَلَ فَجَمَعَ بَيْنَهُمَا","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid Al Muharibi] telah menceritakan kepada kami [Muhammad bin Fudlail] dari [ayahnya] dari [Nafi'] dan [Abdullah bin Waqid] bahwa Mu'adzin [Ibnu Umar] berseru; \"Telah tiba waktu shalat…!\" Maka dia berkata; \"Jalan terus, jalan terus.\" sehingga ketika mega merah hampir hilang, dia singgah lalu mengerjakan shalat Maghrib. Kemudian menunggu sampai mega merah benar-benar hilang, lalu mengerjakan shalat Isya'. Setelah itu dia berkata; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam jika terdesak oleh suatu urusan, beliau melakukan seperti yang aku lakukan tadi.\" Lalu dia berjalan sehari semalam, sejauh perjalanan tiga malam.\" Abu Daud berkata; 'Di riwayatkan pula oleh [Ibnu Jabir] dari [Nafi'] seperti hadits ini dengan sanadnya. Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi] telah mengabarkan kepada kami [Isa] dari [Ibnu Jabir] dengan Makna hadits ini. Abu Daud mengatakan; \"Di riwayatkan pula oleh [Abdullah bin Al 'Ala`] dari [Nafi'] dia berkata; \"…Hingga ketika mega merah telah hilang, maka beliau singgah lalu menjama' keduanya.\""},"1014":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا يَحْيَى بْنُ مُحَمَّدٍ الْجَارِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ مَالِكٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَابَتْ لَهُ الشَّمْسُ بِمَكَّةَ فَجَمَعَ بَيْنَهُمَا بِسَرِفٍحَدَّثَنَا مُحَمَّدُ بْنُ هِشَامٍ جَارُ أَحْمَدَ بْنِ حَنْبَلٍ حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ عَنْ هِشَامِ بْنِ سَعْدٍ قَالَ بَيْنَهُمَا عَشَرَةُ أَمْيَالٍ يَعْنِي بَيْنَ مَكَّةَ وَسَرِفٍ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Yahya bin Muhammad Al Jari] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Malik] dari [Abu Az Zubair] dari [Jabir] bahwa matahari telah tenggelam ketika Rasulullah shallallahu 'alaihi wasallam masih berada di Makkah, namun beliau baru menjama' Shalat di daerah Saraf.\" Telah menceritakan kepada kami Muhammad bin Hisyam tetangga Ahmad bin Hambal, telah menceritakan kepada kami Ja'far bin 'Aun dari Hisyam bin Sa'd dia berkata: \"Jarak antara Makkah dengan Saraf adalah sekitar sepuluh mil.\""},"1015":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ شُعَيْبٍ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ اللَّيْثِ قَالَ قَالَ رَبِيعَةُ يَعْنِي كَتَبَ إِلَيْهِ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ دِينَارٍ قَالَغَابَتْ الشَّمْسُ وَأَنَا عِنْدَ عَبْدِ اللَّهِ بْنِ عُمَرَ فَسِرْنَا فَلَمَّا رَأَيْنَاهُ قَدْ أَمْسَى قُلْنَا الصَّلَاةُ فَسَارَ حَتَّى غَابَ الشَّفَقُ وَتَصَوَّبَتْ النُّجُومُ ثُمَّ إِنَّهُ نَزَلَ فَصَلَّى الصَّلَاتَيْنِ جَمِيعًا ثُمَّ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَدَّ بِهِ السَّيْرُ صَلَّى صَلَاتِي هَذِهِ يَقُولُ يَجْمَعُ بَيْنَهُمَا بَعْدَ لَيْلٍقَالَ أَبُو دَاوُد رَوَاهُ عَاصِمُ بْنُ مُحَمَّدٍ عَنْ أَخِيهِ عَنْ سَالِمٍ وَرَوَاهُ ابْنُ أَبِي نَجِيحٍ عَنْ إِسْمَعِيلَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ ذُؤَيْبٍ أَنَّ الْجَمْعَ بَيْنَهُمَا مِنْ ابْنِ عُمَرَ كَانَ بَعْدَ غُيُوبِ الشَّفَقِ","id":"Telah menceritakan kepada kami [Abdul Malik bin Syu'aib] telah menceritakan kepada kami [Ibnu Wahb] dari [Al Laits] dia berkata; [Rabi'ah] berkata; -yaitu ia menulis surat kepada Al Laits- telah menceritakan kepadaku [Abdullah bin Dinar] dia berkata; \"Matahari telah terbenam, sementara aku berada di samping Abdullah bin Umar, lalu kami berangkat. Ketika kami tahu waktu telah sore, kami berkata; \"Waktu shalat telah tiba!.\" Namun Ibnu Umar masih tetap berjalan, hingga mega merah telah hilang dan bintang-bintang mulai muncul, kemudian [Ibnu Umar] singgah untuk menjama' dua shalat tersebut (Maghrib dan Isya), lalu dia berkata; \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam, apabila dalam suatu perjalanan mengalami kepayahan, beliau mengerjakan dua shalat ini.\" dia berkata; \"yaitu dengan menjama'nya ketika malam telah tiba.\" Abu Daud berkata; \"Di riwayatkan pula oleh ['Ashim bin Muhammad] dari [Saudaranya] dari [Salim]. Dan di riwayatkan pula oleh [Ibnu Abu Najih] dari [Isma'il bin Abdurrahman bin Dzu`aib] bahwa menjama' keduanya yang berasal dari Ibnu Umar adalah setelah hilang mega merah.\""},"1016":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَابْنُ مَوْهَبٍ الْمَعْنَى قَالَا حَدَّثَنَا الْمُفَضَّلُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا ارْتَحَلَ قَبْلَ أَنْ تَزِيغَ الشَّمْسُ أَخَّرَ الظُّهْرَ إِلَى وَقْتِ الْعَصْرِ ثُمَّ نَزَلَ فَجَمَعَ بَيْنَهُمَا فَإِنْ زَاغَتْ الشَّمْسُ قَبْلَ أَنْ يَرْتَحِلَ صَلَّى الظُّهْرَ ثُمَّ رَكِبَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو دَاوُد كَانَ مُفَضَّلٌ قَاضِيَ مِصْرَ وَكَانَ مُجَابَ الدَّعْوَةِ وَهُوَ ابْنُ فَضَالَةَ حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي جَابِرُ بْنُ إِسْمَعِيلَ عَنْ عُقَيْلٍ بِهَذَا الْحَدِيثِ بِإِسْنَادِهِ قَالَ وَيُؤَخِّرُ الْمَغْرِبَ حَتَّى يَجْمَعَ بَيْنَهَا وَبَيْنَ الْعِشَاءِ حِينَ يَغِيبُ الشَّفَقُ","id":"Telah menceritakan kepada kami [Qutaibah] dan [Ibnu Mauhib] sedangkan maksud haditsnya sama, keduanya berkata; telah menceritakan kepada kami [Al Mufadlal] dari ['Uqail] dari [Ibnu Syihab] dari [Anas bin Malik] dia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam berangkat safar sebelum matahari condong (ke barat), maka beliau mengakhirkan Dluhur hingga waktu Ashar, kemudian beliau singgah dan menjama' keduanya, apabila matahari mulai condong sebelum berangkat, maka beliau mengerjakan shalat Dluhur lalu beliau shallallahu 'alaihi wasallam berangkat.\" Abu Daud berkata; \"Mufadlal adalah qadli (hakim) daerah Mesir, sedangkan orang yang di ijabahi do'anya adalah ibnu Fadlalah.\" Telah menceritakan kepada kami [Sulaiman bin Daud Al Mahri] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Jabir bin Isma'il] dari ['Uqail] seperti hadits ini dengan sanadnya, katanya; \"Kemudian beliau mengakhirkan waktu Maghrib hingga beliau menjama' shalat Isya' ketika mega merah telah hilang.\""},"1017":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ الْبَرَاءِ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَصَلَّى بِنَا الْعِشَاءَ الْآخِرَةَ فَقَرَأَ فِي إِحْدَى الرَّكْعَتَيْنِ بِالتِّينِ وَالزَّيْتُونِ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dari ['Adi bin Tsabit] dari [Al Barra`] dia berkata; \"Kami pernah bepergian bersama Rasulullah shallallahu 'alaihi wasallam, lalu beliau mengerjakan shalat Isya', di salah satu raka'atnya beliau membaca: \"At Tiin waz zaitun.\""},"1018":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ أَبِي بُسْرَةَ الْغِفَارِيِّ عَنْ الْبَرَاءِ بْنِ عَازِبٍ الْأَنْصَارِيِّ قَالَصَحِبْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَمَانِيَةَ عَشَرَ سَفَرًا فَمَا رَأَيْتُهُ تَرَكَ رَكْعَتَيْنِ إِذَا زَاغَتْ الشَّمْسُ قَبْلَ الظُّهْرِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari [Shufwan bin Sulaim] dari [Abu Busrah Al Ghifari] dari [Al Barra` bin 'Azib Al Anshari] dia berkata; \"Aku pernah menyertai Rasulullah shallallahu 'alaihi wasallam dalam perjalanan sebanyak delapan belas kali, dan aku tidak pernah sama sekali melihat beliau meninggalkan dua raka'at ketika matahari telah condong.\""},"1019":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ حَدَّثَنَا عِيسَى بْنُ حَفْصِ بْنِ عَاصِمِ بْنِ عُمَرَ بْنِ الْخَطَّابِ عَنْ أَبِيهِ قَالَصَحِبْتُ ابْنَ عُمَرَ فِي طَرِيقٍ قَالَ فَصَلَّى بِنَا رَكْعَتَيْنِ ثُمَّ أَقْبَلَ فَرَأَى نَاسًا قِيَامًا فَقَالَ مَا يَصْنَعُ هَؤُلَاءِ قُلْتُ يُسَبِّحُونَ قَالَ لَوْ كُنْتُ مُسَبِّحًا أَتْمَمْتُ صَلَاتِي يَا ابْنَ أَخِي إِنِّي صَحِبْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي السَّفَرِ فَلَمْ يَزِدْ عَلَى رَكْعَتَيْنِ حَتَّى قَبَضَهُ اللَّهُ عَزَّ وَجَلَّوَصَحِبْتُ أَبَا بَكْرٍ فَلَمْ يَزِدْ عَلَى رَكْعَتَيْنِ حَتَّى قَبَضَهُ اللَّهُ عَزَّ وَجَلَّ وَصَحِبْتُ عُمَرَ فَلَمْ يَزِدْ عَلَى رَكْعَتَيْنِ حَتَّى قَبَضَهُ اللَّهُ تَعَالَى وَصَحِبْتُ عُثْمَانَ فَلَمْ يَزِدْ عَلَى رَكْعَتَيْنِ حَتَّى قَبَضَهُ اللَّهُ تَعَالَى وَقَدْ قَالَ اللَّهُ عَزَّ وَجَلَّ{ لَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ أُسْوَةٌ حَسَنَةٌ }","id":"telah menceritakan kepada kami [Al Qa'nabi] telah menceritakan kepada kami [Isa bin Hafsh bin 'Ashim bin Umar bin Khattab] dari [ayahnya] dia berkata; \"Aku pernah menemani Ibnu Umar dalam suatu perjalanan.\" Hafsh berkata; \"lalu Ibnu Umar melaksanakan shalat dua raka'at bersama kami, Kemudian dia menghadap, ketika dia melihat orang-orang berdiri, dia berkata; \"Apa yang di perbuat mereka?\" Jawabku; \"Mereka sedang mengerjakan shalat sunnah.\" [Ibnu Umar] berkata; \"Sekiranya aku mengerjakan shalat sunnah, tentu aku akan menyempurnakan shalatku. Wahai anak saudaraku, Sesungguhnya aku pernah menyertai Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan, namun beliau tidak pernah menambah dua raka'at hingga Allah Azza Wa Jalla mewafatkannya, aku juga pernah menyertai Abu Bakar, namun dia tidak pernah menambah dua raka'at hingga Allah Azza Wa Jalla mewafatkannya, aku juga menyertai Umar, namun dia tidak pernah menambah dua raka'at hingga Allah Ta'ala mewafatkannya, aku juga pernah menyertai Utsman, namun dia tidak pernah menambah dua raka'at hingga Allah Ta'ala mewafatkannya, sungguh Allah Azza Wa Jalla telah berfirman; \"Sesungguhnya Telah ada pada (diri) Rasulullah itu suri teladan yang baik bagimu.\" QS Al Ahzab; 21. "},"1020":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسَبِّحُ عَلَى الرَّاحِلَةِ أَيَّ وَجْهٍ تَوَجَّهَ وَيُوتِرُ عَلَيْهَا غَيْرَ أَنَّهُ لَا يُصَلِّي الْمَكْتُوبَةَ عَلَيْهَا","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Salim] dari [ayahnya] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah mengerjakan shalat sunnah di atas kendaraannya ke arah mana saja kendaraannya menghadap, dan pernah juga mengerjakan shalat witir di atas kendaraan, namun beliau tidak pernah mengerjakan shalat wajib di atas kendaraan.\""},"1021":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا رِبْعِيُّ بْنُ عَبْدِ اللَّهِ بْنِ الْجَارُودِ حَدَّثَنِي عَمْرُو بْنُ أَبِي الْحَجَّاجِ حَدَّثَنِي الْجَارُودُ بْنُ أَبِي سَبْرَةَ حَدَّثَنِي أَنَسُ بْنُ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا سَافَرَ فَأَرَادَ أَنْ يَتَطَوَّعَ اسْتَقْبَلَ بِنَاقَتِهِ الْقِبْلَةَ فَكَبَّرَ ثُمَّ صَلَّى حَيْثُ وَجَّهَهُ رِكَابُهُ","id":"telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Rib'i bin Abdullah bin Al Jarud] telah menceritakan kepadaku ['Amru bin Abu Al Hajjaj] telah menceritakan kepadaku [Jarud bin Abu Sabrah] telah menceritakan kepadaku [Anas bin Malik] bahwa apabila Rasulullah shallallahu 'alaihi wasallam hendak mengerjakan shalat sunnah, beliau menghadapkan untanya ke arah Kiblat, lalu beliau shalat ke arah mana saja kendaraan (untanya) menghadap.\""},"1022":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ عَمْرِو بْنِ يَحْيَى الْمَازِنِيِّ عَنْ أَبِي الْحُبَابِ سَعِيدِ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّهُ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى حِمَارٍ وَهُوَ مُتَوَجِّهٌ إِلَى خَيْبَرَ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari ['Amru bin Yahya Al Mazini] dari [Abu Al Habbab Sa'id bin Yasar] dari [Abdullah bin Umar] bahwa dia berkata; aku pernah melihat Rasulullah shallallahu 'alaihi wasallam shalat di atas keledai, sedangkan beliau menghadap ke arah Khaibar.\""},"1023":{"ar":"حَدَّثَنَا ابْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَاجَةٍ قَالَ فَجِئْتُ وَهُوَ يُصَلِّي عَلَى رَاحِلَتِهِ نَحْوَ الْمَشْرِقِ وَالسُّجُودُ أَخْفَضُ مِنْ الرُّكُوعِ","id":"Telah menceritakan kepada kami [Ibnu Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abu Az Zubair] dari [Jabir] dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah mengutusku untuk suatu keperluan, katanya; \"lalu aku datang menemui beliau, sementara beliau sedang shalat di atas kendaraannya menghadap ke timur, dan sujud beliau lebih rendah daripada ruku' beliau.\""},"1024":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبٍ عَنْ النُّعْمَانِ بْنِ الْمُنْذِرِ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ أَنَّهُ سَأَلَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاهَلْ رُخِّصَ لِلنِّسَاءِ أَنْ يُصَلِّينَ عَلَى الدَّوَابِّ قَالَتْ لَمْ يُرَخَّصْ لَهُنَّ فِي ذَلِكَ فِي شِدَّةٍ وَلَا رَخَاءٍقَالَ مُحَمَّدٌ هَذَا فِي الْمَكْتُوبَةِ","id":"Telah menceritakan kepada kami [Mahmud bin Khalid] telah menceritakan kepada kami [Muhammad bin Syu'aib] dari [An Nu'man bin Al Mundzir] dari ['Atha` bin Abu Rabah] bahwa dia bertanya kepada [Aisyah] radliallahu 'anha; \"Apakah kaum wanita di beri keringanan untuk mengerjakan shalat di atas kendaraan (binatang tunggangan)?\" dia menjawab; \"Tidak ada keringanan bagi mereka mengenai hal itu, baik dalam keadaan susah atau lapang.\" Muhammad mengatakan; \"Larangan ini merupakan larangan dalam shalat wajib.\""},"1025":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ ح و حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا ابْنُ عُلَيَّةَ وَهَذَا لَفْظُهُ أَخْبَرَنَا عَلِيُّ بْنُ زَيْدٍ عَنْ أَبِي نَضْرَةَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَغَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَشَهِدْتُ مَعَهُ الْفَتْحَ فَأَقَامَ بِمَكَّةَ ثَمَانِي عَشْرَةَ لَيْلَةً لَا يُصَلِّي إِلَّا رَكْعَتَيْنِ وَيَقُولُ يَا أَهْلَ الْبَلَدِ صَلُّوا أَرْبَعًا فَإِنَّا قَوْمٌ سَفْرٌ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad]. Dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Ibnu 'Ulayyah] -lafadz hadits ini dari dia- telah mengabarkan kepada kami [Ali bin Zaid] dari [Abu Nadlrah] dari ['Imran bin Hushain] dia berkata; \"Aku berperang bersama Rasulullah shallallahu 'alaihi wasallam, dan aku juga menyaksikan bersama beliau ketika pembebasan kota Makkah, beliau bermukim di Makkah selama delapan belas hari, dan tidaklah beliau mengerjakan shalat, kecuali hanya dua raka'at, lalu beliau bersabda: 'wahai para penduduk (asli), shalatlah kalian empat raka'at, sebab kami ini adalah para musafir.\""},"1026":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ الْمَعْنَى وَاحِدٌ قَالَا حَدَّثَنَا حَفْصٌ عَنْ عَاصِمٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقَامَ سَبْعَ عَشْرَةَ بِمَكَّةَ يَقْصُرُ الصَّلَاةَقَالَ ابْنُ عَبَّاسٍ وَمَنْ أَقَامَ سَبْعَ عَشْرَةَ قَصَرَ وَمَنْ أَقَامَ أَكْثَرَ أَتَمَّ قَالَ أَبُو دَاوُد قَالَ عَبَّادُ بْنُ مَنْصُورٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ أَقَامَ تِسْعَ عَشْرَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] dan [Utsman bin Abu Syaibah] dengan maksud yang sama, keduanya berkata; telah menceritakan kepada kami [Hafsh] dari ['Ashim] dari ['Ikrimah] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam bermukim di Makkah selama tujuh belas hari, dan selalu mengqashar shalat.\" Ibnu Abbas berkata; \"Barangsiapa bermukim selama tujuh belas hari, maka ia boleh mengqashar shalat, dan barangsiapa bermukim lebih dari itu, dia harus menyempurnakan shalat.\" Abu Daud mengatakan; [Abbad bin Manshur] berkata dari [Ikrimah] dari [Ibnu Abbas] dia berkata; \"Beliau bermukim selama sembilan belas hari.\""},"1027":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَأَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَكَّةَ عَامَ الْفَتْحِ خَمْسَ عَشْرَةَ يَقْصُرُ الصَّلَاةَقَالَ أَبُو دَاوُد رَوَى هَذَا الْحَدِيثَ عَبْدَةُ بْنُ سُلَيْمَانَ وَأَحْمَدُ بْنُ خَالِدٍ الْوَهْبِيُّ وَسَلَمَةُ بْنُ الْفَضْلِ عَنْ أَبِي إِسْحَقَ لَمْ يَذْكُرُوا فِيهِ ابْنَ عَبَّاسٍ","id":"Telah menceritakan kepada kami [An Nufaili] telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dia berkata; \"Pada hari penaklukan kota Makkah, Rasulullah shallallahu 'alaihi wasallam bermukim di sana selama lima belas hari, beliau selalu mengqashar shalat.\" Abu Daud mengatakan; \"Hadits ini di riwayatkan oleh [Abdah bin Sulaiman] dan [Ahmad bin Khalid Al Wahbi] serta [Salamah bin Al Fadl] dari [Abu Ishaq], namun mereka tidak menyebutkan Ibnu Abbas dalam hadits tersebut.\""},"1028":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ أَخْبَرَنِي أَبِي حَدَّثَنَا شَرِيكٌ عَنْ ابْنِ الْأَصْبَهَانِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقَامَ بِمَكَّةَ سَبْعَ عَشْرَةَ يُصَلِّي رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Nashr bin Ali] telah mengabarkan kepadku [ayahku] telah menceritakan kepada kami [Syarik] dari [Ibnu Al Ashbahani] dari ['Ikrimah] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam pernah bermukim di Makkah selama tujuh belas hari, beliau mengerjakan shalat dua raka'at.\""},"1029":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ وَمُسْلِمُ بْنُ إِبْرَاهِيمَ الْمَعْنَى قَالَا حَدَّثَنَا وُهَيْبٌ حَدَّثَنِي يَحْيَى بْنُ أَبِي إِسْحَقَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْمَدِينَةِ إِلَى مَكَّةَ فَكَانَ يُصَلِّي رَكْعَتَيْنِ حَتَّى رَجَعْنَا إِلَى الْمَدِينَةِفَقُلْنَا هَلْ أَقَمْتُمْ بِهَا شَيْئًا قَالَ أَقَمْنَا بِهَا عَشْرًا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] dan [Muslim bin Ibrahim] sedangkan maksud haditsnya sama, keduanya berkata; telah menceritakan kepada kami [Wuhaib] telah menceritakan kepadaku [Yahya bin Abu Ishaq] dari [Anas bin Malik] dia berkata; \"Kami pernah bepergian bersama Rasulullah shallallahu 'alaihi wasallam dari madinah menuju Makkah, beliau selalu mengerjakan shalat dua raka'at sehingga kami kembali tiba di Madinah.\" Kami berkata; 'Apakah kalian bermukim di sana?\" dia berkata; \"Kami bermukim di sana selama sepuluh hari.\""},"1030":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَابْنُ الْمُثَنَّى وَهَذَا لَفْظُ ابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا أَبُو أُسَامَةَ قَالَ ابْنُ الْمُثَنَّى قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عُمَرَ بْنِ عَلِيِّ بْنِ أَبِي طَالِبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّ عَلِيًّا رَضِيَ اللَّهُ عَنْهُكَانَ إِذَا سَافَرَ سَارَ بَعْدَ مَا تَغْرُبُ الشَّمْسُ حَتَّى تَكَادَ أَنْ تُظْلِمَ ثُمَّ يَنْزِلُ فَيُصَلِّي الْمَغْرِبَ ثُمَّ يَدْعُوا بِعَشَائِهِ فَيَتَعَشَّى ثُمَّ يُصَلِّي الْعِشَاءَ ثُمَّ يَرْتَحِلُ وَيَقُولُ هَكَذَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُقَالَ عُثْمَانُ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عُمَرَ بْنِ عَلِيٍّ سَمِعْت أَبَا دَاوُد يَقُولُ وَرَوَى أُسَامَةُ بْنُ زَيْدٍ عَنْ حَفْصِ بْنِ عُبَيْدِ اللَّهِ يَعْنِي ابْنَ أَنَسِ بْنِ مَالِكٍ أَنَّ أَنَسًا كَانَ يَجْمَعُ بَيْنَهُمَا حِينَ يَغِيبُ الشَّفَقُ وَيَقُولُ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ ذَلِكَ وَرِوَايَةُ الزُّهْرِيِّ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلُهُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Ibnu Al Mutsanna] dan lafadz hadits ini dari Ibnul Mutsanna, keduanya berkata; telah menceritakan kepada kami [Abu Usamah], Ibnu Al Mutsanna mengatakan; telah mengabarkan kepadaku [Abdullah bin Muhammad bin Umar bin Ali bin Abu Thalib] dari [ayahnya] dari [kakeknya] bahwa apabila [Ali radliallahu 'anhu] bepergian, dia berangkat setelah matahari terbenam, hingga apabila hampir gelap, dia singgah lalu mengerjakan shalat Maghrib kemudian melakukan makan malam, setelah itu dia mengerjakan shalat Isya'. Lalu dia melanjutkan perjalanannya, katanya; \"Seperti inilah Rasulullah shallallahu 'alaihi wasallam pernah mengerjakan.\" [Utsman] berkata; dari [Abdullah bin Muhammad bin Umar bin Ali]. Aku mendengar Abu Daud berkata; [Usamah bin Zaid] meriwayatkan, dari [Hafsh bin Ubaidullah yaitu Ibnu Anas bin Malik] bahwa [Anas] pernah menjama' keduanya ketika mega merah telah hilang, dia berkata; \"Nabi shallallahu 'alaihi wasallam juga pernah melakukan hal itu.\" Sedangkan riwayatnya [Az Zuhri] dari [Anas] dari Nabi shallallahu 'alaihi wasallam juga seperti hadits di atas.\""},"1031":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ ثَوْبَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَأَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِتَبُوكَ عِشْرِينَ يَوْمًا يَقْصُرُ الصَّلَاةَقَالَ أَبُو دَاوُد غَيْرُ مَعْمَرٍ يُرْسِلُهُ لَا يُسْنِدُهُ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Yahya bin Abu Katsir] dari [Muhammad bin Abdurrahman bin Tsauban] dari [Jabir bin Abdullah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah bermukim di Tabuk selama dua puluh hari, dan selalu mengqashar shalat.\" Abu Daud mengatakan; \"selain Ma'mar, memursalkan hadits ini, dan sanadnya tidak bersambung.\""},"1032":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا جَرِيرُ بْنُ عَبْدِ الْحَمِيدِ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ أَبِي عَيَّاشٍ الزُّرَقِيِّ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعُسْفَانَ وَعَلَى الْمُشْرِكِينَ خَالِدُ بْنُ الْوَلِيدِ فَصَلَّيْنَا الظُّهْرَ فَقَالَ الْمُشْرِكُونَ لَقَدْ أَصَبْنَا غِرَّةً لَقَدْ أَصَبْنَا غَفْلَةً لَوْ كُنَّا حَمَلْنَا عَلَيْهِمْ وَهُمْ فِي الصَّلَاةِ فَنَزَلَتْ آيَةُ الْقَصْرِ بَيْنَ الظُّهْرِ وَالْعَصْرِ فَلَمَّا حَضَرَتْ الْعَصْرُ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُسْتَقْبِلَ الْقِبْلَةِ وَالْمُشْرِكُونَ أَمَامَهُ فَصَفَّ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَفٌّ وَصَفَّ بَعْدَ ذَلِكَ الصَّفِّ صَفٌّ آخَرُ فَرَكَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَكَعُوا جَمِيعًا ثُمَّ سَجَدَ وَسَجَدَ الصَّفُّ الَّذِينَ يَلُونَهُ وَقَامَ الْآخَرُونَ يَحْرُسُونَهُمْ فَلَمَّا صَلَّى هَؤُلَاءِ السَّجْدَتَيْنِ وَقَامُوا سَجَدَ الْآخَرُونَ الَّذِينَ كَانُوا خَلْفَهُمْ ثُمَّ تَأَخَّرَ الصَّفُّ الَّذِي يَلِيهِ إِلَى مَقَامِ الْآخَرِينَ وَتَقَدَّمَ الصَّفُّ الْأَخِيرُ إِلَى مَقَامِ الصَّفِّ الْأَوَّلِ ثُمَّ رَكَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَكَعُوا جَمِيعًا ثُمَّ سَجَدَ وَسَجَدَ الصَّفُّ الَّذِي يَلِيهِ وَقَامَ الْآخَرُونَ يَحْرُسُونَهُمْ فَلَمَّا جَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالصَّفُّ الَّذِي يَلِيهِ سَجَدَ الْآخَرُونَ ثُمَّ جَلَسُوا جَمِيعًا فَسَلَّمَ عَلَيْهِمْ جَمِيعًا فَصَلَّاهَا بِعُسْفَانَ وَصَلَّاهَا يَوْمَ بَنِي سُلَيْمٍقَالَ أَبُو دَاوُد رَوَى أَيُّوبُ وَهِشَامٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ هَذَا الْمَعْنَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَذَلِكَ رَوَاهُ دَاوُدُ بْنُ حُصَيْنٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ وَكَذَلِكَ عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ عَنْ جَابِرٍ وَكَذَلِكَ قَتَادَةُ عَنْ الْحَسَنِ عَنْ حِطَّانَ عَنْ أَبِي مُوسَى فِعْلَهُ وَكَذَلِكَ عِكْرِمَةُ بْنُ خَالِدٍ عَنْ مُجَاهِدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَذَلِكَ هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ قَوْلُ الثَّوْرِيِّ","id":"telah menceritakan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Jarir bin Abdul Hamid] dari [Manshur] dari [Mujahid] dari [Abu 'Ayasy Az Zuraqi] dia berkata; kami bersama Rasulullah shallallahu 'alaihi wasallam di Usfan, sedangkan waktu itu, kaum Musyrikin berada di bawah komando Khalid bin Walid. lalu kami mengerjakan shalat Dluhur, maka orang-orang Musyrik berkata; \"Sungguh kita telah lengah, kita telah lalai. (Alangkah baiknya) sekiranya kita serang mereka ketika mereka tengah mengerjakan shalat.\" lalu turunlah ayat untuk mengqashar shalat antara Dluhur dengan Ashar, ketika waktu Ashar telah tiba, Rasulullah shallallahu 'alaihi wasallam berdiri menghadap ke kiblat, sedangkan orang-orang musyrik berada di hadapannya, sementara satu shaf berbaris di belakang beliau, kemudian ada juga di belakangnya satu shaf lagi, lalu Rasulullah shallallahu 'alaihi wasallam ruku', mereka juga ikut ruku', lalu beliau sujud, dan shaf di belakang beliau juga sujud, sementara shaf berikutnya masih tetap berdiri untuk berjaga-jaga. Setelah shaf pertama selesai sujud dua kali dan berdiri, barulah shaf yang berikutnya (shaf kedua) sujud. Setelah itu, shaf yang ada di belakang beliau (shaf pertama) mundur menempati shaf yang lain (shaf kedua), sedangkan shaf yang kedua maju ke depan menempati shaf pertama, kemudian Rasulullah shallallahu 'alaihi wasallam ruku', mereka semuanya juga ikut ruku', lalu sujud dan shaf yang berada di belakang beliau ikut sujud, sedangkan shaf yang belakangnya (shaf kedua) tetap berdiri berjaga-jaga. Ketika Rasulullah shallallahu 'alaihi wasallam duduk, maka shaf kedua sujud, kemudian mereka semuanya duduk, lalu beliau memberi salam dan mereka pun salam. Cara shalat seperti ini di kerjakan di daerah Usfan, dan juga pernah di kerjakan di Bani Sulaim. ' Abu Daud berkata; [Ayyub] dan [Hisyam] meriwayatkan dari [Abu Az Zubair] dari [Jabir] dengan makna seperti ini dari Nabi shallallahu 'alaihi wasallam, begitu juga [Daud bin Hushain] meriwayatkan dari ['Ikrimah] dari [Ibnu Abbas], begitu juga [Abdul Malik] dari ['Atha`] dari [Jabir]. Begitu juga dengan [Qatadah] dari [Al Hasan] dari [Hithan] dari [Abu Musa] juga pernah mengerjakan seperti itu, begitu juga [Ikrimah bin Khalid] dari [Mujahid] dari Nabi shallallahu 'alaihi wasallam, begitu juga [Hisyam bin 'Urwah] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam, dan itu merupakan perkataan Ats Tsauri \""},"1033":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ صَالِحِ بْنِ خَوَّاتٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِأَصْحَابِهِ فِي خَوْفٍ فَجَعَلَهُمْ خَلْفَهُ صَفَّيْنِ فَصَلَّى بِالَّذِينَ يَلُونَهُ رَكْعَةً ثُمَّ قَامَ فَلَمْ يَزَلْ قَائِمًا حَتَّى صَلَّى الَّذِينَ خَلْفَهُمْ رَكْعَةً ثُمَّ تَقَدَّمُوا وَتَأَخَّرَ الَّذِينَ كَانُوا قُدَّامَهُمْ فَصَلَّى بِهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَةً ثُمَّ قَعَدَ حَتَّى صَلَّى الَّذِينَ تَخَلَّفُوا رَكْعَةً ثُمَّ سَلَّمَ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari [Abdurrahman bin Al Qasim] dari [ayahnya] dari [Shalih bin Khawwat] dari [Sahl bin Abu Hatsmah] bahwa Nabi shallallahu 'alaihi wasallam pernah mengerjakan shalat khauf bersama para sahabatnya, beliau menjadikan mereka dua shaf di belakangnya, lalu beliau mengerjakan shalat dengan shaf yang ada di belakang beliau satu raka'at, kemudian berdiri. Beliau tetap dalam posisi berdiri sehingga orang-orang yang berada di shaf kedua shalat satu raka'at, setelah itu mereka maju ke depan, sedangkan shaf pertama mundur ke belakang, lalu Nabi shallallahu 'alaihi wasallam shalat bersama mereka satu raka'at, kemudian beliau duduk (sambil menanti) sehingga orang-orang yang tertinggal (di shaf ke dua) menyelesaikan satu raka'at yang tertinggal, kemudian beliau salam.\""},"1034":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ يَزِيدَ بْنِ رُومَانَ عَنْ صَالِحِ بْنِ خَوَّاتٍ عَمَّنْصَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ ذَاتِ الرِّقَاعِ صَلَاةَ الْخَوْفِ أَنَّ طَائِفَةً صَفَّتْ مَعَهُ وَطَائِفَةً وِجَاهَ الْعَدُوِّ فَصَلَّى بِالَّتِي مَعَهُ رَكْعَةً ثُمَّ ثَبَتَ قَائِمًا وَأَتَمُّوا لِأَنْفُسِهِمْ ثُمَّ انْصَرَفُوا وَصَفُّوا وِجَاهَ الْعَدُوِّ وَجَاءَتْ الطَّائِفَةُ الْأُخْرَى فَصَلَّى بِهِمْ الرَّكْعَةَ الَّتِي بَقِيَتْ مِنْ صَلَاتِهِ ثُمَّ ثَبَتَ جَالِسًا وَأَتَمُّوا لِأَنْفُسِهِمْ ثُمَّ سَلَّمَ بِهِمْقَالَ مَالِكٌ وَحَدِيثُ يَزِيدَ بْنِ رُومَانَ أَحَبُّ مَا سَمِعْتُ إِلَيَّ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Yazid bin Ruman] dari [Shalih bin Khuwwat] dari [orang] yang pernah mengerjakan shalat khauf bersama Rasulullah shallallahu 'alaihi wasallam pada waktu Perang Dzatur Riqa', yaitu; bahwa satu shaf berbaris bersama beliau, sedangkan shaf yang lain (berjaga-jaga) menghadapi musuh, kemudian orang-orang yang bersama beliau shalat satu raka'at, kemudian beliau tetap dalam kondisi berdiri, sedangkan mereka menyempurnakan satu raka'at sendiri-sendiri, setelah itu mereka beranjak pergi dan berbaris (berjaga-jaga) menghadapi musuh. Setelah itu, kelompok yang lain datang dan shalat bersama beliau satu raka'at dari sisa satu raka'at beliau, kemudian beliau tetap dalam duduk (menunggu), sedangkan mereka menyempurnakan shalat (satu raka'at) sendiri-sendiri, lalu beliau salam bersama mereka.\" Malik berkata; sedangkan haditsnya Yazid bin Ruman lebih aku sukai dari apa yang pernah aku dengar.\""},"1035":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ صَالِحِ بْنِ خَوَّاتٍ الْأَنْصَارِيِّ أَنَّ سَهْلَ بْنَ أَبِي حَثْمَةَ الْأَنْصَارِيَّ حَدَّثَهُأَنَّ صَلَاةَ الْخَوْفِ أَنْ يَقُومَ الْإِمَامُ وَطَائِفَةٌ مِنْ أَصْحَابِهِ وَطَائِفَةٌ مُوَاجِهَةُ الْعَدُوِّ فَيَرْكَعُ الْإِمَامُ رَكْعَةً وَيَسْجُدُ بِالَّذِينَ مَعَهُ ثُمَّ يَقُومُ فَإِذَا اسْتَوَى قَائِمًا ثَبَتَ قَائِمًا وَأَتَمُّوا لِأَنْفُسِهِمْ الرَّكْعَةَ الْبَاقِيَةَ ثُمَّ سَلَّمُوا وَانْصَرَفُوا وَالْإِمَامُ قَائِمٌ فَكَانُوا وِجَاهَ الْعَدُوِّ ثُمَّ يُقْبِلُ الْآخَرُونَ الَّذِينَ لَمْ يُصَلُّوا فَيُكَبِّرُونَ وَرَاءَ الْإِمَامِ فَيَرْكَعُ بِهِمْ وَيَسْجُدُ بِهِمْ ثُمَّ يُسَلِّمُ فَيَقُومُونَ فَيَرْكَعُونَ لِأَنْفُسِهِمْ الرَّكْعَةَ الْبَاقِيَةَ ثُمَّ يُسَلِّمُونَقَالَ أَبُو دَاوُد وَأَمَّا رِوَايَةُ يَحْيَى بْنِ سَعِيدٍ عَنْ الْقَاسِمِ نَحْوَ رِوَايَةِ يَزِيدَ بْنِ رُومَانَ إِلَّا أَنَّهُ خَالَفَهُ فِي السَّلَامِ وَرِوَايَةُ عُبَيْدِ اللَّهِ نَحْوَ رِوَايَةِ يَحْيَى بْنِ سَعِيدٍ قَالَ وَيَثْبُتُ قَائِمًا","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Yahya bin Sa'id] dari [Al Qasim bin Muhammad] dari [Shalih bin Khuwwat Al Anshari] bahwa [Sahl bin Abu Hatsmah Al Anshari] telah menceritakan kepadanya, bahwa shalat khauf itu adalah; \"Imam berdiri bersama satu kelompok sahabatnya, sedangkan satu kelompok yang lainnya menghadap ke arah musuh. Lalu imam ruku' dan sujud bersama kelompok yang menyertainya, lalu berdiri. Apabila telah berdiri tegak, imam tetap berdiri, sedangkan kelompok yang bersamanya menyempurnakan satu raka'at yang tersisa sendiri-sendiri, lalu mereka salam dan beranjak pergi, sedangkan imam masih dalam posisi berdiri, sementara mereka pergi berjaga-jaga menghadapi musuh. Kemudian kelompok yang lain, yang belum shalat datang dan bertakbir di belakang imam. Imam ruku' dan sujud bersama mereka, kemudian imam salam, sementara mereka berdiri dan melanjutkan raka'at yang sisa, lalu mereka salam.\" Abu Daud berkata; adapun riwayat Yahya bin Sa'id dari Al Qasim seperti riwayat Yazid bin Ruman, namun riwayatnya sedikit berbeda ketika salam, sedangkan riwayatnya 'Ubaidullah seperti riwayatnya Yahya bin Sa'id, katanya; \"Imam tetap berdiri.\""},"1036":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا أَبُو عَبْدِ الرَّحْمَنِ الْمُقْرِئُ حَدَّث��نَا حَيْوَةُ وَابْنُ لَهِيعَةَ قَالَا أَخْبَرَنَا أَبُو الْأَسْوَدِ أَنَّهُ سَمِعَ عُرْوَةَ بْنَ الزُّبَيْرِ يُحَدِّثُ عَنْ مَرْوَانَ بْنِ الْحَكَمِأَنَّهُ سَأَلَ أَبَا هُرَيْرَةَ هَلْ صَلَّيْتَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْخَوْفِ قَالَ أَبُو هُرَيْرَةَ نَعَمْ قَالَ مَرْوَانُ مَتَى فَقَالَ أَبُو هُرَيْرَةَ عَامَ غَزْوَةِ نَجْدٍ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى صَلَاةِ الْعَصْرِ فَقَامَتْ مَعَهُ طَائِفَةٌ وَطَائِفَةٌ أُخْرَى مُقَابِلَ الْعَدُوِّ وَظُهُورُهُمْ إِلَى الْقِبْلَةِ فَكَبَّرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَبَّرُوا جَمِيعًا الَّذِينَ مَعَهُ وَالَّذِينَ مُقَابِلِي الْعَدُوِّ ثُمَّ رَكَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَةً وَاحِدَةً وَرَكَعَتْ الطَّائِفَةُ الَّتِي مَعَهُ ثُمَّ سَجَدَ فَسَجَدَتْ الطَّائِفَةُ الَّتِي تَلِيهِ وَالْآخَرُونَ قِيَامٌ مُقَابِلِي الْعَدُوِّ ثُمَّ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَامَتْ الطَّائِفَةُ الَّتِي مَعَهُ فَذَهَبُوا إِلَى الْعَدُوِّ فَقَابَلُوهُمْ وَأَقْبَلَتْ الطَّائِفَةُ الَّتِي كَانَتْ مُقَابِلِي الْعَدُوِّ فَرَكَعُوا وَسَجَدُوا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمٌ كَمَا هُوَ ثُمَّ قَامُوا فَرَكَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَةً أُخْرَى وَرَكَعُوا مَعَهُ وَسَجَدَ وَسَجَدُوا مَعَهُ ثُمَّ أَقْبَلَتْ الطَّائِفَةُ الَّتِي كَانَتْ مُقَابِلِي الْعَدُوِّ فَرَكَعُوا وَسَجَدُوا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاعِدٌ وَمَنْ كَانَ مَعَهُ ثُمَّ كَانَ السَّلَامُ فَسَلَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَلَّمُوا جَمِيعًا فَكَانَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَانِ وَلِكُلِّ رَجُلٍ مِنْ الطَّائِفَتَيْنِ رَكْعَةٌ رَكْعَةٌحَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو الرَّازِيُّ حَدَّثَنَا سَلَمَةُ حَدَّثَنِي مُحَمَّدُ بْنُ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ جَعْفَرِ بْنِ الزُّبَيْرِ وَمُحَمَّدِ بْنِ الْأَسْوَدِ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ أَبِي هُرَيْرَةَ قَالَ خَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى نَجْدٍ حَتَّى إِذَا كُنَّا بِذَاتِ الرِّقَاعِ مِنْ نَخْلٍ لَقِيَ جَمْعًا مِنْ غَطَفَانَ فَذَكَرَ مَعْنَاهُ وَلَفْظُهُ عَلَى غَيْرِ لَفْظِ حَيْوَةَ وَقَالَ فِيهِ حِينَ رَكَعَ بِمَنْ مَعَهُ وَسَجَدَ قَالَ فَلَمَّا قَامُوا مَشَوْا الْقَهْقَرَى إِلَى مَصَافِّ أَصْحَابِهِمْ وَلَمْ يَذْكُرْ اسْتِدْبَارَ الْقِبْلَةِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Abu Abdurrahman Al Muqri`i] telah menceritakan kepada kami [Haiwah] dan [Ibnu Lahi'ah] keduanya berkata; telah mengabarkan kepada kami [Abu Al Aswad] bahwa dia mendengar ['Urwah bin Az Zubair] bercerita dari [Marwan bin Hakam] bahwa dia bertanya kepada [Abu Hurairah]; \"Apakah kamu pernah shalat khauf bersama Rasulullah shallallahu 'alaihi wasallam?\" Abu Hurairah menjawab; \"Ya, pernah.\" Marwan bertanya; \"Kapan?\" Abu Hurairah menjawab; \"Ketika memerangi Bani Najd, Rasulullah shallallahu 'alaihi wasallam hendak mengerjakan shalat Ashar, lalu sekelompok orang berdiri (shalat) bersama beliau, sedangkan kelompok yang lain menghadap ke arah musuh membelakangi Kiblat. Rasulullah shallallahu 'alaihi wasallam bertakbir, lalu mereka juga ikut bertakbir, baik yang bersama beliau atau kelompok yang menghadap musuh. Setelah itu, Rasulullah shallallahu 'alaihi wasallam ruku' sekali bersama dengan kelompok yang menyertai beliau, lalu beliau sujud dan sujud pula orang yang menyertai beliau, sementara kelompok yang lain tetap berdiri menghadap ke arah musuh. Selanjutnya Rasulullah shallallahu 'alaihi wasallam berdiri, begitu juga kelompok yang menyertai beliau, kemudian kelompok ini pindah, menggantikan kelompok yang menghadapi musuh, sedangkan kelompok yang menghadapi musuh pindah ke belakang beliau untuk mengerjakan ruku' dan sujud sendiri-sendiri. Sedangkan Rasulullah shallallahu 'alaihi wasallam tetap berdiri menunggu sampai mereka berdiri pula. Setelah itu Rasulullah shallallahu 'alaihi wasallam ruku' (untuk raka'at kedua), lalu mereka ruku' bersama beliau, beliau sujud, mereka pun ikut sujud. Lalu kelompok yang menghadapi musuh datang, mereka ruku' dan sujud sendiri, sedangkan Rasulullah shallallahu 'alaihi wasallam tetap duduk menunggu bersama kelompok yang menyertai beliau tadi, setelah itu, baru tiba waktu salam. Maka Rasulullah shallallahu 'alaihi wasallam salam dan mereka semuanya pun salam. Maka bagi Rasulullah shallallahu 'alaihi wasallam dua rala'at, sedangkan bagi masing-masing mereka satu raka'at.\" Telah menceritakan kepada kami [Muhammad bin 'Amru Ar Razi] telah menceritakan kepada kami [Salamah] telah menceritakan kepadaku [Muhammad bin Ishaq] dari [Muhammad bin Ja'far bin Zubair] dan [Muhammad bin Al Aswad] dari ['Urwah bin Az Zubair] dari [Abu Hurairah] dua berkata; \"Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam menuju daerah Najd, hingga ketika kami sampai di perkebunan kurma Dzatur Riqa', beliau bertemu dengan sekelompok orang Bani Ghathafan…' kemudian dia menyebutkan makna dan lafadz hadits ini, tidak seperti lafadz hadits sebelumnya. Dalam hadits tersebut, dia berkata; \"…Ketika beliau ruku' dam sujud bersama orang-orang yang berada di belakang beliau. selanjutnya Perawi berkata; \"Setelah mereka berdiri, lalu berjalan mundur ke barisan sahabat mereka.\" dalam hadits ini tidak di sebutkan \"membelakangi Kiblat.\""},"1037":{"ar":"قَالَ أَبُو دَاوُد وَأَمَّا عُبَيْدُ اللَّهِ بْنُ سَعْدٍ فَحَدَّثَنَا قَالَ حَدَّثَنِي عَمِّي حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ حَدَّثَنِي مُحَمَّدُ بْنُ جَعْفَرِ بْنِ الزُّبَيْرِ أَنَّ عُرْوَةَ بْنَ الزُّبَيْرِ حَدَّثَهُ أَنَّ عَائِشَةَ حَدَّثَتْهُ بِهَذِهِ الْقِصَّةِ قَالَتْكَبَّرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَبَّرَتْ الطَّائِفَةُ الَّذِينَ صَفُّوا مَعَهُ ثُمَّ رَكَعَ فَرَكَعُوا ثُمَّ سَجَدَ فَسَجَدُوا ثُمَّ رَفَعَ فَرَفَعُوا ثُمَّ مَكَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسًا ثُمَّ سَجَدُوا لِأَنْفُسِهِمْ الثَّانِيَةَ ثُمَّ قَامُوا فَنَكَصُوا عَلَى أَعْقَابِهِمْ يَمْشُونَ الْقَهْقَرَى حَتَّى قَامُوا مِنْ وَرَائِهِمْ وَجَاءَتْ الطَّائِفَةُ الْأُخْرَى فَقَامُوا فَكَبَّرُوا ثُمَّ رَكَعُوا لِأَنْفُسِهِمْ ثُمَّ سَجَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَجَدُوا مَعَهُ ثُمَّ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَجَدُوا لِأَنْفُسِهِمْ الثَّانِيَةَ ثُمَّ قَامَتْ الطَّائِفَتَانِ جَمِيعًا فَصَلَّوْا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَكَعَ فَرَكَعُوا ثُمَّ سَجَدَ فَسَجَدُوا جَمِيعًا ثُمَّ عَادَ فَسَجَدَ الثَّانِيَةَ وَسَجَدُوا مَعَهُ سَرِيعًا كَأَسْرَعِ الْإِسْرَاعِ جَاهِدًا لَا يَأْلُونَ سِرَاعًا ثُمَّ سَلَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَلَّمُوا فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ شَارَكَهُ النَّاسُ فِي الصَّلَاةِ كُلِّهَا","id":"Abu Daud berkata; telah menceritakan kepada kami ['Ubaidullah bin Sa'd] katanya; telah menceritakan kepadaku [pamanku] telah menceritakan kepada kami [ayahku] dari [Ibnu Ishaq] telah menceritakan kepada kami [Muhammad bin Ja'far bin Az Zubair] bahwa ['Urwah bin Zubair] telah menceritakan kepadanya, bahwa [Aisyah] pernah menceritakan kepadanya dengan kisah seperti ini, kata Asiyah; 'Rasulullah shallallahu 'alaihi wasallam bertakbir, begitu juga dengan kelompok yang shalat bersama beliau ikut bertakbir, kemudian beliau ruku, mereka juga ruku', lalu beliau sujud, mereka juga ikut sujud, lalu beliau mengangkat kepala (duduk di antara dua sujud), lalu mereka ikut bangkit, namun Rasulullah shallallahu 'alaihi wasallam masih tetap duduk, sementara mereka mengerjakan sujud kedua sendiri-sendiri. Kemudian mereka berdiri dan berjalan mundur pelan-pelan sehingga berdiri di belakang mereka (kelompok kedua), dan kelompok kedua datang, lalu mereka berdiri di belakang Rasulullah shallallahu 'alaihi wasallam, mereka bertakbir dan ruku' sendiri-sendiri, setelah ruku', Rasulullah shallallahu 'alaihi wasallam sujud, maka mereka juga sujud bersama beliau. kemudian Rasulullah shallallahu 'alaihi wasallam berdiri, sedangkan mereka mengerjakan sujud kedua sendiri-sendiri, setelah itu kedua kelompok tersebut berdiri semua, mengerjakan shalat bersama dengan Rasulullah shallallahu 'alaihi wasallam. beliau ruku', lalu mereka juga ikut ruku', beliau sujud mereka juga sujud. Lalu beliau kembali duduk, terus sujud lagi yang kedua, maka mereka juga ikut sujud bersama beliau secepatnya dan sangat cepat tanpa mengurangi kesempurnaan (sujud), setelah itu Rasulullah shallallahu 'alaihi wasallam salam dan mereka juga ikut salam bersama beliau.\" Rasulullah shallallahu 'alaihi wasallam berdiri dalam semua shalat yang di sertai oleh semua jama'ah shalat.\""},"1038":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِإِحْدَى الطَّائِفَتَيْنِ رَكْعَةً وَالطَّائِفَةُ الْأُخْرَى مُوَاجِهَةُ الْعَدُوِّ ثُمَّ انْصَرَفُوا فَقَامُوا فِي مَقَامِ أُولَئِكَ وَجَاءَ أُولَئِكَ فَصَلَّى بِهِمْ رَكْعَةً أُخْرَى ثُمَّ سَلَّمَ عَلَيْهِمْ ثُمَّ قَامَ هَؤُلَاءِ فَقَضَوْا رَكْعَتَهُمْ وَقَامَ هَؤُلَاءِ فَقَضَوْا رَكْعَتَهُمْقَالَ أَبُو دَاوُد وَكَذَلِكَ رَوَاهُ نَافِعٌ وَخَالِدُ بْنُ مَعْدَانَ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَذَلِكَ قَوْلُ مَسْرُوقٍ وَيُوسُفُ بْنُ مِهْرَانَ عَنْ ابْنِ عَبَّاسٍ وَكَذَلِكَ رَوَى يُونُسُ عَنْ الْحَسَنِ عَنْ أَبِي مُوسَى أَنَّهُ فَعَلَهُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid bin Zurai'] dari [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat satu raka'at dengan salah satu dari dua kelompok, sedangkan kelompok yang lain berjaga-jaga menghadapi musuh, setelah kelompok pertama selesai melaksanakan shalat, mereka pergi menempati kelompok kedua, dan kelompok kedua menempati tempat kelompok pertama, beliau mengerjakan shalat bersama kelompok kedua satu raka'at sisanya, lalu beliau salam, kemudian kelompok kedua berdiri dan menyelesaikan raka'at mereka, dan mereka berdiri untuk menyelesaikan raka'at mereka.\" Abu Daud berkata; \"Demikian juga yang di riwayatkan oleh [Nafi'] dan [Khalid bin Ma'dan] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, begitu juga dengan perkataannya Masruq dan Yusuf bin Mihran dari Ibnu Abbas, demikian juga yang di riwayatkan Yunus dari Al Hasan dari Abu Musa bahwa dia juga melakukan cara seperti ini.\""},"1039":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مَيْسَرَةَ حَدَّثَنَا ابْنُ فُضَيْلٍ حَدَّثَنَا خُصَيْفٌ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْخَوْفِ فَقَامُوا صَفًّا خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَفٌّ مُسْتَقْبِلَ الْعَدُوِّ فَصَلَّى بِهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَةً ثُمَّ جَاءَ الْآخَرُونَ فَقَامُوا مَقَامَهُمْ وَاسْتَقْبَلَ هَؤُلَاءِ الْعَدُوَّ فَصَلَّى بِهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَةً ثُمَّ سَلَّمَ فَقَامَ هَؤُلَاءِ فَصَلَّوْا لِأَنْفُسِهِمْ رَكْعَةً ثُمَّ سَلَّمُوا ثُمَّ ذَهَبُوا فَقَامُوا مَقَامَ أُولَئِكَ مُسْتَقْبِلِي الْعَدُوِّ وَرَجَعَ أُولَئِكَ إِلَى مَقَامِهِمْ فَصَلَّوْا لِأَنْفُسِهِمْ رَكْعَةً ثُمَّ سَلَّمُواحَدَّثَنَا تَمِيمُ بْنُ الْمُنْتَصِرِ أَخْبَرَنَا إِسْحَقُ يَعْنِي ابْنَ يُوسُفَ عَنْ شَرِيكٍ عَنْ خُصَيْفٍ بِإِسْنَادِهِ وَمَعْنَاهُ قَالَ فَكَبَّرَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَبَّرَ الصَّفَّانِ جَمِيعًا قَالَ أَبُو دَاوُد رَوَاهُ الثَّوْرِيُّ بِهَذَا الْمَعْنَى عَنْ خُصَيْفٍ وَصَلَّى عَبْدُ الرَّحْمَنِ بْنُ سَمُرَةَ هَكَذَا إِلَّا أَنَّ الطَّائِفَةَ الَّتِي صَلَّى بِهِمْ رَكْعَةً ثُمَّ سَلَّمَ مَضَوْا إِلَى مَقَامِ أَصْحَابِهِمْ وَجَاءَ هَؤُلَاءِ فَصَلَّوْا لِأَنْفُسِهِمْ رَكْعَةً ثُمَّ رَجَعُوا إِلَى مَقَامِ أُولَئِكَ فَصَلَّوْا لِأَنْفُسِهِمْ رَكْعَةً قَالَ أَبُو دَاوُد حَدَّثَنَا بِذَلِكَ مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ حَبِيبٍ قَالَ أَخْبَرَنِي أَبِي أَنَّهُمْ غَزَوْا مَعَ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ كَابُلَ فَصَلَّى بِنَا صَلَاةَ الْخَوْفِ","id":"Telah menceritakan kepada kami [Imran bin Maisarah] telah menceritakan kepada kami [Ibnu Fudlail] telah menceritakan kepada kami [Khushaif] dari [Abu 'Ubaidah] dari [Abdullah bin Mas'ud] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah mengerjakan shalat khauf bersama kami, lalu sekelompok mereka berbaris di belakang Rasulullah shallallahu 'alaihi wasallam, sedangkan kelompok yang lain berjaga-jaga menghadapi musuh, maka Rasulullah shallallahu 'alaihi wasallam shalat dengan kelompok pertama satu raka'at, kemudian kelompok kedua datang dan menempati tempat kelompok pertama, sedangkan kelompok pertama bergantian berjaga menghadapi musuh, lalu Nabi shallallahu 'alaihi wasallam shalat dengan kelompok kedua satu raka'at, kemudian beliau salam, sementara kelompok yang shalat bersama beliau berdiri dan menyempurnakan satu raka'at sendiri-sendiri, kemudian mereka salam. Setelah itu mereka kembali dan menempati posisi kelompok yang menghadapi musuh, sedangkan kelompok pertama kembali (ke shaf shalat), kemudian mereka (menyempurnakan) shalat satu raka'at (yang tersisa) sendiri-sendiri, kemudian mereka salam.\" Telah menceritakan kepada kami [Tamim bin Al Muntashir] telah mengabarkan kepada kami [Ishaq yaitu Ibnu Yusuf] dari [Syarik] dari [Khushaif] dengan sanad dan maksud yang sama, katanya; \"Kemudian Nabi shallallahu 'alaihi wasallam bertakbir, dan kedua kelompok juga ikut bertakbir bersama beliau.\" Abu Daud mengatakan; \"Di riwayatkan pula oleh [Ats Tsauri] dengan makna seperti ini, dari [Khushaif], dan Abdurrahman bin Samurah juga mengerjakan cara shalat seperti ini, kecuali kelompok yang shalat satu raka'at, kemudian salam, lalu mereka bergantian menempati tempat sahabatnya yang lain (kelompok kedua), kemudian mereka (kelompok kedua) datang lalu shalat sendiri-sendiri satu raka'at, kemudian mereka kembali ke tempat mereka dan menyempurnakan shalat satu raka'at sendiri-sendiri.\" Abu Daud berkata; telah menceritakan kepada kami hadits seperti itu Muslim bin Ibrahim telah menceritakan kepada kami Abdusshamad bin Habib dia berkata; telah mengabarkan kepadaku ayahku bahwa mereka pernah berperang bersama Abdurrahman bin Samurah di daerah Kabul, kemudian dia mengerjakan shalat khauf bersama kami.\""},"1040":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ حَدَّثَنِي الْأَشْعَثُ بْنُ سُلَيْمٍ عَنْ الْأَسْوَدِ بْنِ هِلَالٍ عَنْ ثَعْلَبَةَ بْنِ زَهْدَمٍ قَالَكُنَّا مَعَ سَعِيدِ بْنِ الْعَاصِ بِطَبَرِسْتَانَ فَقَامَ فَقَالَ أَيُّكُمْ صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْخَوْفِ فَقَالَ حُذَيْفَةُ أَنَا فَصَلَّى بِهَؤُلَاءِ رَكْعَةً وَبِهَؤُلَاءِ رَكْعَةً وَلَمْ يَقْضُواقَالَ أَبُو دَاوُد وَكَذَا رَوَاهُ عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ وَمُجَاهِدٌ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَبْدُ اللَّهِ بْنُ شَقِيقٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيَزِيدُ الْفَقِيرُ وَأَبُو مُوسَى قَالَ أَبُو دَاوُد رَجُلٌ مِنْ التَّابِعِينَ لَيْسَ بِالْأَشْعَرِيِّ جَمِيعًا عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ قَالَ بَعْضُهُمْ عَنْ شُعْبَةَ فِي حَدِيثِ يَزِيدَ الْفَقِيرِ إِنَّهُمْ قَضَوْا رَكْعَةً أُخْرَى وَكَذَلِكَ رَوَاهُ سِمَاكٌ الْحَنَفِيُّ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَذَلِكَ رَوَاهُ زَيْدُ بْنُ ثَابِتٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَكَانَتْ لِلْقَوْمِ رَكْعَةً رَكْعَةً وَلِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Sufyan] telah menceritakan kepadaku [Al Asy'Ats Tsauri bin Sulaim] dari [Al Aswad bin Hilal] dari [Tsa'labah bin Zahdam] dia berkata; \"Kami bersama Sa'id bin Al 'Ash di daerah Thabaristan, kemudian dia berdiri dan berkata \"Siapakah di antara kalian yang pernah mengerjakan shalat khauf bersama Rasulullah shallallahu 'alaihi wasallam?\" maka [Hudzaifah] menjawab; \"Aku, beliau mengerjakan shalat satu raka'at dengan satu kelompok, dan mengerjakan satu raka'at dengan kelompok yang lain, dan mereka tidak menambah (sendiri-sendiri).\" Abu Daud berkata; \"Demikian juga yang di riwayatkan ['Ubaidullah bin Abdullah] dan [Mujahid] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam. Dan [Abdullah bin Syaqiq] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam. Serta [Yazid Al Faqir] dan [Abu Musa]. Abu Daud berkata; \"-Abu Musa yang di maksud adalah seorang tabi'in, bukan (Abu Musa) Asy'ari seorang sahabat, semuanya dari [Jabir] dari Nabi shallallahu 'alaihi wasallam. Sebagian mereka berkata; dari Syu'bah dalam haditsnya Yazid Al Faqir, \"Mereka menyempurnakan satu raka'at lagi.\" Demikian juga yang di riwayatkan [Simak Al Hanafi] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam. Demikian juga yang di riwayatkan Zaid bin Tsabit dari Nabi shallallahu 'alaihi wasallam, dia berkata; \"…Untuk setiap kelompok, mengerjakan satu raka'at-satu raka'at, sedangkan Nabi shallallahu 'alaihi wasallam mengerjakan dua raka'at.\""},"1041":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَسَعِيدُ بْنُ مَنْصُورٍ قَالَا حَدَّثَنَا أَبُو عَوَانَةَ عَنْ بُكَيْرِ بْنِ الْأَخْنَسِ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَفَرَضَ اللَّهُ تَعَالَى الصَّلَاةَ عَلَى لِسَانِ نَبِيِّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْحَضَرِ أَرْبَعًا وَفِي السَّفَرِ رَكْعَتَيْنِ وَفِي الْخَوْفِ رَكْعَةً","id":"Telah menceritakan kepada kami [Musaddad] dan [Sa'id bin Manshur] keduanya berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Bukair bin Al Ahnas] dari [Mujahid] dari [Ibnu Abbas] dia berkata; \"Allah Ta'ala telah mewajibkan shalat lewat lisan Nabi kalian ketika menetap (tidak bepergian) sebanyak empat raka'at, di waktu bepergian dua raka'at dan dalam kondisi takut (dalam Perang) satu raka'at.\""},"1042":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَشْعَثُ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةَ قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي خَوْفٍ الظُّهْرَ فَصَفَّ بَعْضُهُمْ خَلْفَهُ وَبَعْضُهُمْ بِإِزَاءِ الْعَدُوِّ فَصَلَّى بِهِمْ رَكْعَتَيْنِ ثُمَّ سَلَّمَ فَانْطَلَقَ الَّذِينَ صَلَّوْا مَعَهُ فَوَقَفُوا مَوْقِفَ أَصْحَابِهِمْ ثُمَّ جَاءَ أُولَئِكَ فَصَلَّوْا خَلْفَهُ فَصَلَّى بِهِمْ رَكْعَتَيْنِ ثُمَّ سَلَّمَ فَكَانَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعًا وَلِأَصْحَابِهِ رَكْعَتَيْنِ رَكْعَتَيْنِوَبِذَلِكَ كَانَ يُفْتِي الْحَسَنُ قَالَ أَبُو دَاوُد وَكَذَلِكَ فِي الْمَغْرِبِ يَكُونُ لِلْإِمَامِ سِتُّ رَكَعَاتٍ وَلِلْقَوْمِ ثَلَاثٌ ثَلَاثٌ قَالَ أَبُو دَاوُد وَكَذَلِكَ رَوَاهُ يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَذَلِكَ قَالَ سُلَيْمَانُ الْيَشْكُرِيُّ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Al Asy'Ats Tsauri] dari [A Hasan] dari [Abu Bakrah] dia berkata; \"Nabi shallallahu 'alaihi wasallam pernah mengerjakan shalat khauf pada waktu Dluhur, sebagian kelompok berbaris di belakang beliau dan sebagian kelompok yang lain menghadapi musuh, beliau shalat dua raka'at dengan mereka (kelompok pertama), kemudian salam. Lalu kelompok yang tadinya shalat dengan beliau pindah menempati tempat para sahabat mereka (kelompok kedua), kemudian mereka (kelompok kedua) datang dan shalat di belakang beliau, maka beliau shalat dua raka'at bersama mereka, lalu salam. Sehingga Rasulullah shallallahu 'alaihi wasallam shalat empat raka'at, sementara para sahabat beliau shalat dua raka'at-dua raka'at.\" Demikianlah yang di fatwakan oleh Al Hasan. Abu Daud mengatakan; \"Demikian pula dalam shalat Maghrib, maka imam enam raka'at, sementara setiap kelompok tiga raka'at-tiga raka'at.\" Abu Daud mengatakan; \"Demikian pula yang di riwayatkan oleh [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam. [Sulaiman Al Yasykuri] berkata; dari [Jabir] dari Nabi shallallahu 'alaihi wasallam. "},"1043":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ عَبْدُ اللَّهِ بْنُ عَمْرٍو حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ جَعْفَرٍ عَنْ ابْنِ عَبْدِ اللَّهِ بْنِ أُنَيْسٍ عَنْ أَبِيهِ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى خَالِدِ بْنِ سُفْيَانَ الْهُذَلِيِّ وَكَانَ نَحْوَ عُرَنَةَ وَعَرَفَاتٍ فَقَالَ اذْهَبْ فَاقْتُلْهُ قَالَ فَرَأَيْتُهُ وَحَضَرَتْ صَلَاةُ الْعَصْرِ فَقُلْتُ إِنِّي أَخَافُ أَنْ يَكُونَ بَيْنِي وَبَيْنَهُ مَا إِنْ أُؤَخِّرْ الصَّلَاةَ فَانْطَلَقْتُ أَمْشِي وَأَنَا أُصَلِّي أُومِئُ إِيمَاءً نَحْوَهُ فَلَمَّا دَنَوْتُ مِنْهُ قَالَ لِي مَنْ أَنْتَ قُلْتُ رَجُلٌ مِنْ الْعَرَبِ بَلَغَنِي أَنَّكَ تَجْمَعُ لِهَذَا الرَّجُلِ فَجِئْتُكَ فِي ذَاكَ قَالَ إِنِّي لَفِي ذَاكَ فَمَشَيْتُ مَعَهُ سَاعَةً حَتَّى إِذَا أَمْكَنَنِي عَلَوْتُهُ بِسَيْفِي حَتَّى بَرَدَ","id":"Telah menceritakan kepada kami [Abu Ma'mar Abdullah bin 'Amru] telah menceritakan kepada kami [Abdul Warits] telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Muhammad bin ja'far] dari [Ibnu Abdullah bin Unais] dari [ayahnya] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah mengutusku untuk menemui Khalid bin Sufyan Al Hudzali, sedangkan dia berada di daerah antara 'Uranah dan 'Arafat, beliau bersabda: \"Pergilah dan bunuhlah dia.\" Abdullah bin Unais berkata; \"Maka aku dapat melihatnya sedangkan waktu shalat Ashar telah tiba, aku berkata (dalam dalam hati);; \"Aku khawatir jika aku mengakhirkan shalat Ashar, akan terjadi sesuatu antara aku dengan dia.\" Maka aku terus saja berjalan sambil mengerjakan shalat dengan memberi isyarat, ketika jarakku dengannya semakin dekat, dia berkata kepadaku; \"Siapakah kamu?\" jawabku; \"Aku adalah seseorang dari Arab, telah sampai kepadaku bahwa dirimu telah mengumpulkan (orang-orang) untuk memerangi laki-laki ini, maka aku datang untuk urusan tersebut. ' Dia berkata; \"Memang aku berhajat seperti itu.\" Sesaat kemudian aku jalan-jalan bersamanya, ketika keadaan memungkinkan bagiku (untuk membunuhnya), maka aku langsung mengayunkan pedangku menebasnya hingga dia mati terkapar.\""},"1044":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا ابْنُ عُلَيَّةَ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ حَدَّثَنِي النُّعْمَانُ بْنُ سَالِمٍ عَنْ عَمْرِو بْنِ أَوْسٍ عَنْ عَنْبَسَةَ بْنِ أَبِي سُفْيَانَ عَنْ أُمِّ حَبِيبَةَ قَالَتْقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى فِي يَوْمٍ ثِنْتَيْ عَشْرَةَ رَكْعَةً تَطَوُّعًا بُنِيَ لَهُ بِهِنَّ بَيْتٌ فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Ibnu 'Ulayyah] telah menceritakan kepada kami [Daud bin Abu Hind] telah menceritakan kepadaku [An Nu'man bin Salim] dari ['Amru bin Aus] dari ['Anbasah bin Abu Sufyan] dari [Ummu Habibah] dia berkata; Nabi shallallahu 'alaihi wasallam bersabda; \"Barangsiapa mengerjakan shalat sunnah dua belas raka'at dalam sehari, maka akan di bangunkan baginya rumah di surga.\""},"1045":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا خَالِدٌ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا خَالِدٌ الْمَعْنَى عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ قَالَسَأَلْتُ عَائِشَةَ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ التَّطَوُّعِ فَقَالَتْ كَانَ يُصَلِّي قَبْلَ الظُّهْرِ أَرْبَعًا فِي بَيْتِي ثُمَّ يَخْرُجُ فَيُصَلِّي بِالنَّاسِ ثُمَّ يَرْجِعُ إِلَى بَيْتِي فَيُصَلِّي رَكْعَتَيْنِ وَكَانَ يُصَلِّي بِالنَّاسِ الْمَغْرِبَ ثُمَّ يَرْجِعُ إِلَى بَيْتِي فَيُصَلِّي رَكْعَتَيْنِ وَكَانَ يُصَلِّي بِهِمْ الْعِشَاءَ ثُمَّ يَدْخُلُ بَيْتِي فَيُصَلِّي رَكْعَتَيْنِ وَكَانَ يُصَلِّي مِنْ اللَّيْلِ تِسْعَ رَكَعَاتٍ فِيهِنَّ الْوِتْرُ وَكَانَ يُصَلِّي لَيْلًا طَوِيلًا قَائِمًا وَلَيْلًا طَوِيلًا جَالِسًا فَإِذَا قَرَأَ وَهُوَ قَائِمٌ رَكَعَ وَسَجَدَ وَهُوَ قَائِمٌ وَإِذَا قَرَأَ وَهُوَ قَاعِدٌ رَكَعَ وَسَجَدَ وَهُوَ قَاعِدٌ وَكَانَ إِذَا طَلَعَ الْفَجْرُ صَلَّى رَكْعَتَيْنِ ثُمَّ يَخْرُجُ فَيُصَلِّي بِالنَّاسِ صَلَاةَ الْفَجْرِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Khalid]. Dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Khalid] sedangkan maknanya dari [Abdullah bin Syaqiq] dia berkata; saya bertanya kepada [Aisyah] mengenai shalat sunnahnya Rasulullah shallallahu 'alaihi wasallam.\" Jawabnya; \"Beliau biasa mengerjakan shalat (sunnah) sebelum Dluhur empat raka'at di rumahku, kemudian beliau keluar dan shalat bersama orang-orang. Setelah shalat, beliau kembali ke rumahku lalu beliau mengerjakan shalat dua raka'at. Setelah shalat Maghrib (berjama'ah) bersama orang-orang, beliau pulang ke rumahku, kemudian beliau shalat (sunnah) dua raka'at. Setelah shalat Isya' bersama orag-orang, beliau masuk ke rumahku lalu shalat dua raka'at. Beliau juga biasa mengerjakan shalat malam sembilan raka'at bersamaan dengan witirnya. Beliau mengerjakan shalat malam dengan berdiri hingga jangka waktu yang lama, terkadang juga shalat malam sambil duduk hingga jangka waktu yang lama. Apabila membaca (Surat) sambil berdiri, maka beliau ruku' dan sujud sebagaimana (ruku' dan sujud) ketika mengerjakan shalat dengan berdiri, dan apabila beliau duduk, maka beliau ruku' dan sujud dengan posisi duduk. apabila waktu fajar telah terbit, beliau shalat dua raka'at, lalu beliau shallallahu 'alaihi wasallam keluar mengerjakan shalat shubuh (berjama'ah) bersama orang-orang.\""},"1046":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي قَبْلَ الظُّهْرِ رَكْعَتَيْنِ وَبَعْدَهَا رَكْعَتَيْنِ وَبَعْدَ الْمَغْرِبِ رَكْعَتَيْنِ فِي بَيْتِهِ وَبَعْدَ صَلَاةِ الْعِشَاءِ رَكْعَتَيْنِ وَكَانَ لَا يُصَلِّي بَعْدَ الْجُمُعَةِ حَتَّى يَنْصَرِفَ فَيُصَلِّيَ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Nafi'] dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam biasa mengerjakan shalat (sunnah) dua raka'at sebelum dan setelah Dluhur, dua raka'at di rumahnya setelah Maghrib, dua raka'at setelah Isya', dan beliau tidak mengerjakan shalat sunnah setelah Jum'at, sehingga beliau pergi (ke rumah) kemudian shalat dua raka'at.\""},"1047":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يَدَعُ أَرْبَعًا قَبْلَ الظُّهْرَ وَرَكْعَتَيْنِ قَبْلَ صَلَاةِ الْغَدَاةِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Syu'bah] dari [Ibrahim bin Muhammad bin Al Muntasyir] dari [ayahnya] dari [Aisyah] bahwa Nabi shallallahu 'alaihi wasallam tidak pernah meninggalkan empat raka'at sebelum Dluhur dan dua raka'at sebelum shalat subuh.\""},"1048":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ ابْنِ جُرَيْجٍ حَدَّثَنِي عَطَاءٌ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَكُنْ عَلَى شَيْءٍ مِنْ النَّوَافِلِ أَشَدَّ مُعَاهَدَةً مِنْهُ عَلَى الرَّكْعَتَيْنِ قَبْلَ الصُّبْحِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Ibnu Juraij] telah menceritakan kepadaku ['Atha`] dari ['Ubaid bin 'Umair] dari [Aisyah] radliallahu 'anha dia berkata; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam tidak pernah memiliki perhatian yang lebih terhadap shalat sunnah melebihi perhatian beliau terhadap dua raka'at sebelum subuh.\""},"1049":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي شُعَيْبٍ الْحَرَّانِيُّ حَدَّثَنَا زُهَيْرُ بْنُ مُعَاوِيَةَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخَفِّفُ الرَّكْعَتَيْنِ قَبْلَ صَلَاةِ الْفَجْرِ حَتَّى إِنِّي لَأَقُولُ هَلْ قَرَأَ فِيهِمَا بِأُمِّ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Ahmad bin Abu Syu'aib Al Harrani] telah menceritakan kepada kami [Zuhair bin Mu'awiyah] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Muhammad bin Abdurrahman] dari ['Amrah] dari [Aisyah] dia berkata; \"Nabi shallallahu 'alaihi wasallam biasa mempersingkat (shalat) dua raka'at sebelum fajar, sehingga aku berkata (dalam hati), apakah beliau hanya membaca al Fatihah saja dalam dua raka'at tersebut?\""},"1050":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مَعِينٍ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ حَدَّثَنَا يَزِيدُ بْنُ كَيْسَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ فِي رَكْعَتَيْ الْفَجْرِ قُلْ يَا أَيُّهَا الْكَافِرُونَ وَ قُلْ هُوَ اللَّهُ أَحَدٌ","id":"Telah menceritakan kepada kami [Yahya bin Ma'in] telah menceritakan kepada kami [Marwan bin Mu'awiyah] telah menceritakan kepada kami [Yazid bin Kaisan] dari [Abu Hazim] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam membaca \"Qul yaa ayyuhal Kaafiruun\" dan \"Qul huwallahu ahad\" dalam dua raka'at shalat (sunnah) fajar.\""},"1051":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْعَلَاءِ حَدَّثَنِي أَبُو زِيَادَةَ عُبَيْدُ اللَّهِ بْنُ زِيَادَةَ الْكِنْدِيُّ عَنْ بِلَالٍ أَنَّهُ حَدَّثَهُأَنَّهُ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيُؤْذِنَهُ بِصَلَاةِ الْغَدَاةِ فَشَغَلَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا بِلَالًا بِأَمْرٍ سَأَلَتْهُ عَنْهُ حَتَّى فَضَحَهُ الصُّبْحُ فَأَصْبَحَ جِدًّا قَالَ فَقَامَ بِلَالٌ فَآذَنَهُ بِالصَّلَاةِ وَتَابَعَ أَذَانَهُ فَلَمْ يَخْرُجْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا خَرَجَ صَلَّى بِالنَّاسِ وَأَخْبَرَهُ أَنَّ عَائِشَةَ شَغَلَتْهُ بِأَمْرٍ سَأَلَتْهُ عَنْهُ حَتَّى أَصْبَحَ جِدًّا وَأَنَّهُ أَبْطَأَ عَلَيْهِ بِالْخُرُوجِ فَقَالَ إِنِّي كُنْتُ رَكَعْتُ رَكْعَتَيْ الْفَجْرِ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّكَ أَصْبَحْتَ جِدًّا قَالَ لَوْ أَصْبَحْتُ أَكْثَرَ مِمَّا أَصْبَحْتُ لَرَكَعْتُهُمَا وَأَحْسَنْتُهُمَا وَأَجْمَلْتُهُمَا","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Abdullah Al 'Ala`] telah menceritakan kepadaku [Abu Ziyadah 'Ubaidullah bin Ziyadah Al Kindi] dari [Bilal] bahwa dia telah menceritakan kepadanya, bahwa dirinya pernah datang kepada Rasulullah shallallahu 'alaihi wasallam untuk menyerukan adzan subuh, lalu Aisyah menyibukkan Bilal dengan suatu perkara yang ia tanyakan, hingga waktu pagi datang dengan cerah. ' Katanya; 'lalu Bilal berdiri mengumandangkan adzan untuk shalat, dan adzan di kumandangkan dengan sempurna, namun Rasulullah shallallahu 'alaihi wasallam tidak kunjung keluar, setelah beliau keluar mengerjakan shalat dengan orang-orang, di sampaikanlah kepada beliau bahwa dia (Bilal) disibukkan dengan suatu urusan yang di tanyakan Aisyah sampai tiba waktu pagi yang cerah, sehingga dia membuat beliau juga terlambat keluar.\" Beliau bersabda: \"Sesungguhnya aku tengah mengerjakan shalat sunnah fajar dua raka'at.\" Bilal berkata; \"Wahai Rasulullah, sesungguhnya anda berada di pagi yang sangat cerah?\" beliau bersabda: \"Sekiranya aku kesiangan dan lebih siang daripada sekarang ini, pasti aku akan tetap mengerjakan dua raka'at tersebut, dan aku akan memperbaiki dan memperbagus kedua raka'at tersebut.\""},"1052":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا خَالِدٌ حَدَّثَنَا عَبْدُ الرَّحْمَنِ يَعْنِي ابْنَ إِسْحَقَ الْمَدَنِيَّ عَنْ ابْنِ زَيْدٍ عَنْ ابْنِ سَيْلَانَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَدَعُوهُمَا وَإِنْ طَرَدَتْكُمْ الْخَيْلُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Khalid] telah menceritakan kepada kami [Abdurrahman yaitu Ibnu Ishaq Al Madani] dari [Ibnu Zaid] dari [Ibnu Sailan] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian meninggalkan (dua raka'at sunnah fajar), sekalipun kalian terpelanting dari kudanya.\""},"1053":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا عُثْمَانُ بْنُ حَكِيمٍ أَخْبَرَنِي سَعِيدُ بْنُ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّ كَثِيرًا مِمَّا كَانَ يَقْرَأُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَكْعَتَيْ الْفَجْرِ بِ{ آمَنَّا بِاللَّهِ وَمَا أُنْزِلَ إِلَيْنَا }هَذِهِ الْآيَةُ قَالَ هَذِهِ فِي الرَّكْعَةِ الْأُولَى وَفِي الرَّكْعَةِ الْآخِرَةِ بِ{ آمَنَّا بِاللَّهِ وَاشْهَدْ بِأَنَّا مُسْلِمُونَ }","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Utsman bin Hakim] telah menceritakan kepadaku [Sa'id bin Yasar] dari [Abdullah bin Abbas] bahwa kebanyakan yang di baca Rasulullah shallallahu 'alaihi wasallam dalam dua raka'at fajar adalah \"Kami beriman kepada Allah dan apa yang diturunkan kepada kami\" (QS Al Baqarah; 136). Kata Ibnu Abbas; \"ayat ini di baca beliau di raka'at pertama, sedangkan di raka'at terakhir beliau membaca \"……kami beriman kepada Allah; dan saksikanlah bahwa Sesungguhnya kami adalah orang-orang yang berserah diri.\" (QS Ali Imran; 52). "},"1054":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ بْنِ سُفْيَانَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ عُثْمَانَ بْنِ عُمَرَ يَعْنِي ابْنَ مُوسَى عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي رَكْعَتَيْ الْفَجْرِ{ قُلْ آمَنَّا بِاللَّهِ وَمَا أُنْزِلَ عَلَيْنَا }فِي الرَّكْعَةِ الْأُولَى وَفِي الرَّكْعَةِ الْأُخْرَى بِهَذِهِ الْآيَةِ{ رَبَّنَا آمَنَّا بِمَا أَنْزَلْتَ وَاتَّبَعْنَا الرَّسُولَ فَاكْتُبْنَا مَعَ الشَّاهِدِينَ }أَوْ{ إِنَّا أَرْسَلْنَاكَ بِالْحَقِّ بَشِيرًا وَنَذِيرًا وَلَا تُسْأَلُ عَنْ أَصْحَابِ الْجَحِيمِ }شَكَّ الدَّارَوَرْدِيُّ","id":"Telah menceritakan kepada kami [Muhammad bin As Shabbah bin Sufyan] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Utsman bin Umar yaitu Ibnu Musa] dari [Abu Al Ghaits] dari [Abu Hurairah] bahwa dia mendengar Nabi shallallahu 'alaihi wasallam membaca dalam dua raka'at fajar dengan; \"Katakanlah: \"Kami beriman kepada Allah dan kepada apa yang diturunkan kepada kami…\" QS Ali Imran; 84, ayat ini beliau baca di raka'at pertama, sedangkan di raka'at kedua, beliau membaca dengan ayat ini; \"Ya Tuhan kami, kami Telah beriman kepada apa yang Telah Engkau turunkan dan Telah kami ikuti rasul, Karena itu masukanlah kami ke dalam golongan orang-orang yang menjadi saksi (tentang keesaan Allah) \" (QS Ali Imran; 53) atau membaca; \"Sesungguhnya kami Telah mengutusmu (Muhammad) dengan kebenaran; sebagai pembawa berita gembira dan pemberi peringatan, dan kamu tidak akan diminta (pertanggungan jawab) tentang penghuni-penghuni neraka Jahannam.\" (QS Al Baqarah; 119) -Ad Darawardi ragu mengenai redaksi hadits ini-.\""},"1055":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَأَبُو كَامِلٍ وَعُبَيْدُ اللَّهِ بْنُ عُمَرَ بْنِ مَيْسَرَةَ قَالُوا حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى أَحَدُكُمْ الرَّكْعَتَيْنِ قَبْلَ الصُّبْحِ فَلْيَضْطَجِعْ عَلَى يَمِينِهِفَقَالَ لَهُ مَرْوَانُ بْنُ الْحَكَمِ أَمَا يُجْزِئُ أَحَدَنَا مَمْشَاهُ إِلَى الْمَسْجِدِ حَتَّى يَضْطَجِعَ عَلَى يَمِينِهِ قَالَ عُبَيْدُ اللَّهِ فِي حَدِيثِهِ قَالَ لَا قَالَ فَبَلَغَ ذَلِكَ ابْنَ عُمَرَ فَقَالَ أَكْثَرَ أَبُو هُرَيْرَةَ عَلَى نَفْسِهِ قَالَ فَقِيلَ لِابْنِ عُمَرَ هَلْ تُنْكِرُ شَيْئًا مِمَّا يَقُولُ قَالَ لَا وَلَكِنَّهُ اجْتَرَأَ وَجَبُنَّا قَالَ فَبَلَغَ ذَلِكَ أَبَا هُرَيْرَةَ قَالَ فَمَا ذَنْبِي إِنْ كُنْتُ حَفِظْتُ وَنَسَوْا","id":"Telah menceritakan kepada kami [Musaddad] dan [Abu Kamil] serta ['Ubaidullah bin Umar bin Maisarah] mereka berkata; telah menceritakan kepada kami [Abdul Wahid] telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian selesai mengerjakan shalat (sunnah) dua raka'at sebelum subuh, hendaknya ia berbaring ke sebelah kanan.\" Maka Marwan bin Hakam berkata kepadanya; \"Apakah seseorang dari kami cukup waktu berjalan ke masjid kok sehingga dia berbaring ke sebelah kanan segala?\" 'Ubaidullah berkata dalam haditsnya. Abu Hurairah menjawab; \"Tidak.\" Lalu hal itu di sampaikan kepada Ibnu Umar, maka Ibnu Umar berkata; \"Abu Hurairah berlaku berlebih-lebihan atas dirinya sendiri.\" Lalu di katakan kepada Ibnu Umar; \"Apakah anda tidak membenarkan sebagian yang di katakannya?\" dia menjawab; \"Tidak, namun Abu Hurairah berani (karena banyak riwayat), sedangkan kami amat hati-hati (karena sedikit periwayatan hadits).\" Katanya; \"Lalu hal itu sampai kepada Abu Hurairah, kemudian dia berkata; \"Apa salahku, jika aku pernah menghafalnya (hadits) sedangkan ia lupa?.\""},"1056":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا بِشْرُ بْنُ عُمَرَ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ سَالِمٍ أَبِي النَّضْرِ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَضَى صَلَاتَهُ مِنْ آخِرِ اللَّيْلِ نَظَرَ فَإِنْ كُنْتُ مُسْتَيْقِظَةً حَدَّثَنِي وَإِنْ كُنْتُ نَائِمَةً أَيْقَظَنِي وَصَلَّى الرَّكْعَتَيْنِ ثُمَّ اضْطَجَعَ حَتَّى يَأْتِيَهُ الْمُؤَذِّنُ فَيُؤْذِنَهُ بِصَلَاةِ الصُّبْحِ فَيُصَلِّي رَكْعَتَيْنِ خَفِيفَتَيْنِ ثُمَّ يَخْرُجُ إِلَى الصَّلَاةِ","id":"Telah menceritakan kepada kami [Yahya bin Hakim] telah menceritakan kepada kami [Bisyr bin Umar] telah menceritakan kepada kami [Malik bin Anas] dari [Salim Abu An Nadlr] dari [Abu Salamah bin Abdurrahman] dari [Aisyah] dia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam selesai melaksanakan shalat di akhir malam, maka beliau memperhatikanku, apabila aku telah bengun, beliau pun bercakap-cakap denganku, dan apabila aku masih tertidur, beliau akan membangunkanku, kemudian beliau shalat dua raka'at, setelah itu beliau berbaring hingga Mu'adzin datang untuk mengumandangkan adzan shalat shubuh, lalu beliau mengerjakan shalat (sunnah) dua raka'at yang singkat, setelah itu beliau keluar untuk mengerjakan shalat (Subuh).\""},"1057":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ زِيَادِ بْنِ سَعْدٍ عَمَّنْ حَدَّثَهُ ابْنُ أَبِي عَتَّابٍ أَوْ غَيْرُهُ عَنْ أَبِي سَلَمَةَ قَالَ قَالَتْ عَائِشَةُكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى رَكْعَتَيْ الْفَجْرِ فَإِنْ كُنْتُ نَائِمَةً اضْطَجَعَ وَإِنْ كُنْتُ مُسْتَيْقِظَةً حَدَّثَنِي","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Sufyan] dari [Ziyad bin Sa'd] dari seseorang yang pernah menceritakan kepadanya [Ibnu Abi 'Attab] atau yang lainnya, dari [Abu Salamah] dia berkata; [Aisyah] berkata; \"Apabila Nabi shallallahu 'alaihi wasallam selesai mengerjakan shalat dua raka'at fajar, sementara aku masih tidur, beliau akan berbaring, namun apabila aku sudah bangun, maka beliau akan bercakap-cakap denganku.\""},"1058":{"ar":"حَدَّثَنَا عَبَّاسٌ الْعَنْبَرِيُّ وَزِيَادُ بْنُ يَحْيَى قَالَا حَدَّثَنَا سَهْلُ بْنُ حَمَّادٍ عَنْ أَبِي مَكِينٍ حَدَّثَنَا أَبُو الْفُضَيْلِ رَجُلٌ مِنْ الْأَنْصَارِ عَنْ مُسْلِمِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِ قَالَخَرَجْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِصَلَاةِ الصُّبْحِ فَكَانَ لَا يَمُرُّ بِرَجُلٍ إِلَّا نَادَاهُ بِالصَّلَاةِ أَوْ حَرَّكَهُ بِرِجْلِهِ قَالَ زِيَادٌ قَالَ حَدَّثَنَا أَبُو الْفُضَيْلِ","id":"Telah menceritakan kepada kami [Abbas Al 'Anbari] dan [Ziyad bin Yahya] keduanya berkata; telah menceritakan kepada kami [Sahl bin Hammad] dari [Abu Makkin] telah menceritakan kepada kami [Abu Al Fudlail] -seorang laki-laki dari Anshar- dari [Muslim bin Abu Bakrah] dari [ayahnya] dia berkata; \"Aku keluar bersama Nabi shallallahu 'alaihi wasallam untuk shalat subuh, dan tidaklah beliau melewati seseorang melainkan beliau akan memanggilnya untuk shalat atau mengarak-gerakkan dengan kaki beliau.\" Ziyad berkata; \"Telah menceritakan kepada kami Abu Al Fudlail. "},"1059":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَاصِمٍ عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَ قَالَجَاءَ رَجُلٌ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الصُّبْحَ فَصَلَّى الرَّكْعَتَيْنِ ثُمَّ دَخَلَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصَّلَاةِ فَلَمَّا انْصَرَفَ قَالَ يَا فُلَانُ أَيَّتُهُمَا صَلَاتُكَ الَّتِي صَلَّيْتَ وَحْدَكَ أَوْ الَّتِي صَلَّيْتَ مَعَنَا","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari ['Ashim] dari [Abdullah bin Sarjis] dia berkata; \"Seorang laki-laki datang, sementara Nabi shallallahu 'alaihi wasallam tengah mengerjakan shalat shubuh, kemudian laki-laki itu shalat dua raka'at, barulah dia masuk (shaf) untuk mengerjakan shalat bersama Nabi shallallahu 'alaihi wasallam, setelah selesai shalat, beliau bersabda: \"Wahai fulan, dari kedua shalatmu tadi, manakah yang merupakan shalat (shubuh)? yang kamu kerjakan secara sendirian ataukah yang kamu kerjakan bersama kami?\""},"1060":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ ح و حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ وَرْقَاءَ ح و حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ��بْنِ جُرَيْجٍ ح و حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ حَمَّادِ بْنِ زَيْدٍ عَنْ أَيُّوبَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُتَوَكِّلِ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا زَكَرِيَّا بْنُ إِسْحَقَ كُلُّهُمْ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُقِيمَتْ الصَّلَاةُ فَلَا صَلَاةَ إِلَّا الْمَكْتُوبَةَ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hammad bin Salamah]. Dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Warqa`]. Dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij]. Dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Yazid bin Harun] dari [Hammad bin Zaid] dari [Ayyub]. Dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Muhammad bin Al Mutawakkil] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Zakariya bin Ishaq] semuanya dari ['Amru bin Dinar] dari ['Atha` bin Yasar] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"jika iqamah telah di tegakkan, maka tidak ada shalat kecuali shalat wajib.\""},"1061":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ نُمَيْرٍ عَنْ سَعْدِ بْنِ سَعِيدٍ حَدَّثَنِي مُحَمَّدُ بْنُ إِبْرَاهِيمَ عَنْ قَيْسِ بْنِ عَمْرٍو قَالَرَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يُصَلِّي بَعْدَ صَلَاةِ الصُّبْحِ رَكْعَتَيْنِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ الصُّبْحِ رَكْعَتَانِ فَقَالَ الرَّجُلُ إِنِّي لَمْ أَكُنْ صَلَّيْتُ الرَّكْعَتَيْنِ اللَّتَيْنِ قَبْلَهُمَا فَصَلَّيْتُهُمَا الْآنَ فَسَكَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا حَامِدُ بْنُ يَحْيَى الْبَلْخِيُّ قَالَ قَالَ سُفْيَانُ كَانَ عَطَاءُ بْنُ أَبِي رَبَاحٍ يُحَدِّثُ بِهَذَا الْحَدِيثِ عَنْ سَعْدِ بْنِ سَعِيدٍ قَالَ أَبُو دَاوُد وَرَوَى عَبْدُ رَبِّهِ وَيَحْيَى ابْنَا سَعِيدٍ هَذَا الْحَدِيثَ مُرْسَلًا أَنَّ جَدَّهُمْ صَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذِهِ الْقِصَّةِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Ibnu Numair] dari [Sa'd bin Sa'id] telah menceritakan kepadaku [Muhammad bin Ibrahim] dari [Qais bin 'Amru] dia berkata; \"Suatu ketika Rasulullah shallallahu 'alaihi wasallam pernah melihat seorang laki-laki yang mengerjakan shalat dua raka'at setelah shalat shubuh, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat shubuh itu hanya dua raka'at.\" laki-laki itu menjawab; \"Sesungguhnya aku belum mengerjakan shalat dua raka'at (sunnah fajar), karena itu aku mengerjakannya sekarang ini.\" Maka Rasulullah shallallahu 'alaihi wasallam diam.\". Telah menceritakan kepada kami [Hamid bin Yahya Al Balakhi] dia berkata; telah berkata [Sufyan] bahwasanya [Atha' bin Abi Robbah] menceritakan hadits ini dari [Sa'ad bin Sa'id]. Abu Daud berkata; \"dan telah di riwayatkan oleh 'Abdu Rabbihi dan Yahya keduanya adalah putra Sa'id. Hadits ini adalah hadits mursal, sebab dalam kisah ini, kakek mereka ikut shalat bersama Nabi shallallahu 'alaihi wasallam. "},"1062":{"ar":"حَدَّثَنَا مُؤَمَّلُ بْنُ الْفَضْلِ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبٍ عَنْ النُّعْمَانِ عَنْ مَكْحُولٍ عَنْ عَنْبَسَةَ بْنِ أَبِي سُفْيَانَ قَالَ قَالَتْ أُمُّ حَبِيبَةَ زَوْجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَافَظَ عَلَى أَرْبَعِ رَكَعَاتٍ قَبْلَ الظُّهْرِ وَأَرْبَعٍ بَعْدَهَا حَرُمَ عَلَى النَّارِقَالَ أَبُو دَاوُد رَوَاهُ الْعَلَاءُ بْنُ الْحَارِثِ وَسُلَيْمَانُ بْنُ مُوسَى عَنْ مَكْحُولٍ بِإِسْنَادِهِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Fadl] telah menceritakan kepada kami [Muhammad bin Syu'aib] dari [An Nu'man] dari [Makhul] dari ['Anbasah bin Abu Sufyan] dia berkata; [Ummu Habibah isteri Nabi] shallallahu 'alaihi wasallam berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bisa menjaga empat raka'at sebelum Dluhur dan empat raka'at setelahnya, maka neraka akan di haramkan bagi dirinya.\" Abu Daud berkata; \"Di riwayatkan pula oleh [Al 'Ala` bin Al Harits] dan [Sulaiman bin Musa] dari [Makhul] dengan sanad seperti hadits di atas.\""},"1063":{"ar":"حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ عُبَيْدَةَ يُحَدِّثُ عَنْ إِبْرَاهِيمَ عَنْ ابْنِ مِنْجَابَ عَنْ قَرْثَعٍ عَنْ أَبِي أَيُّوبَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَرْبَعٌ قَبْلَ الظُّهْرِ لَيْسَ فِيهِنَّ تَسْلِيمٌ تُفْتَحُ لَهُنَّ أَبْوَابُ السَّمَاءِقَالَ أَبُو دَاوُد بَلَغَنِي عَنْ يَحْيَى بْنِ سَعِيدٍ الْقَطَّانِ قَالَ لَوْ حَدَّثْتُ عَنْ عُبَيْدَةَ بِشَيْءٍ لَحَدَّثْتُ عَنْهُ بِهَذَا الْحَدِيثِ قَالَ أَبُو دَاوُد عُبَيْدَةُ ضَعِيفٌ قَالَ أَبُو دَاوُد ابْنُ مِنْجَابٍ هُوَ سَهْمٌ","id":"Telah menceritakan kepada kami [Ibnu Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dia berkata; saya mendengar ['Ubaidah] pernah bercerita dari [Ibrahim] dari [Ibnu Minjab] dari [Qartsa'] dari [Abu Ayyub] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Empat raka'at sebelum Dluhur yang tidak di pisahkan oleh salam, maka akan di bukakan untuknya pintu-pintu langit.\" Abu Daud berkata; telah sampai kepadaku dari Yahya bin Sa'id Al Qatthan dia berkata; \"sekiranya aku menyampaikan suatu hadits dari 'Ubaidah, tentu aku akan menyampaikan hadits ini darinya. Abu Daud berkata; 'Ubaidah adalah Perawi yang lemah. Abu Daud berkata; Ibnu Minjab adalah Sahm. "},"1064":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا مُحَمَّدُ بْنُ مِهْرَانَ الْقُرَشِيُّ حَدَّثَنِي جَدِّي أَبُو الْمُثَنَّى عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَحِمَ اللَّهُ امْرَأً صَلَّى قَبْلَ الْعَصْرِ أَرْبَعًا","id":"Telah menceritakan kepada kami [Ahmad bin Ibrahim] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Muhammad bin Mihran Al Qurasyi] telah menceritakan kepadaku [Kakekku yaitu Abu Al Mutsanna] dari [Ibnu Umar] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semoga Allah merahmati seseorang yang mengerjakan shalat (sunnah) empat raka'at sebelum Ashar.\""},"1065":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ عَاصِمِ بْنِ ضَمْرَةَ عَنْ عَلِيٍّ عَلَيْهِ السَّلَامأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي قَبْلَ الْعَصْرِ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari ['Ashim bin Dlamrah] dari [Ali] 'alaihi salam, bahwa Nabi shallallahu 'alaihi wasallam biasa mengerjakan shalat (sunnah) dua raka'at sebelum Ashar.\""},"1066":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ بُكَيْرِ بْنِ الْأَشَجِّ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍأَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ وَعَبْدَ الرَّحْمَنِ بْنَ أَزْهَرَ وَالْمِسْوَرَ بْنَ مَخْرَمَةَ أَرْسَلُوهُ إِلَى عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا اقْرَأْ عَلَيْهَا السَّلَامَ مِنَّا جَمِيعًا وَسَلْهَا عَنْ الرَّكْعَتَيْنِ بَعْدَ الْعَصْرِ وَقُلْ إِنَّا أُخْبِرْنَا أَنَّكِ تُصَلِّينَهُمَا وَقَدْ بَلَغَنَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْهُمَا فَدَخَلْتُ عَلَيْهَا فَبَلَّغْتُهَا مَا أَرْسَلُونِي بِهِ فَقَالَتْ سَلْ أُمَّ سَلَمَةَ فَخَرَجْتُ إِلَيْهِمْ فَأَخْبَرْتُهُمْ بِقَوْلِهَا فَرَدُّونِي إِلَى أُمِّ سَلَمَةَ بِمِثْلِ مَا أَرْسَلُونِي بِهِ إِلَى عَائِشَةَ فَقَالَتْ أُمُّ سَلَمَةَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْهُمَا ثُمَّ رَأَيْتُهُ يُصَلِّيهِمَا أَمَّا حِينَ صَلَّاهُمَا فَإِنَّهُ صَلَّى الْعَصْرَ ثُمَّ دَخَلَ وَعِنْدِي نِسْوَةٌ مِنْ بَنِي حَرَامٍ مِنْ الْأَنْصَارِ فَصَلَّاهُمَا فَأَرْسَلْتُ إِلَيْهِ الْجَارِيَةَ فَقُلْتُ قُومِي بِجَنْبِهِ فَقُولِي لَهُ تَقُولُ أُمُّ سَلَمَةَ يَا رَسُولَ اللَّهِ أَسْمَعُكَ تَنْهَى عَنْ هَاتَيْنِ الرَّكْعَتَيْنِ وَأَرَاكَ تُصَلِّيهِمَا فَإِنْ أَشَارَ بِيَدِهِ فَاسْتَأْخِرِي عَنْهُ قَالَتْ فَفَعَلَتْ الْجَارِيَةُ فَأَشَارَ بِيَدِهِ فَاسْتَأْخَرَتْ عَنْهُ فَلَمَّا انْصَرَفَ قَالَ يَا بِنْتَ أَبِي أُمَيَّةَ سَأَلْتِ عَنْ الرَّكْعَتَيْنِ بَعْدَ الْعَصْرِ إِنَّهُ أَتَانِي نَاسٌ مِنْ عَبْدِ الْقَيْسِ بِالْإِسْلَامِ مِنْ قَوْمِهِمْ فَشَغَلُونِي عَنْ الرَّكْعَتَيْنِ اللَّتَيْنِ بَعْدَ الظُّهْرِ فَهُمَا هَاتَانِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku ['Amru bin Al Harits] dari [Bukair bin Al Asyaj] dari [Kuraib] bekas budak Ibnu Abbas, bahwa Abdullah bin Abbas dan Abdurrahman bin Azhar serta Al Miswar bin Al Mahramah pernah mengutusnya untuk menemui Aisyah isteri Nabi shallallahu 'alaihi wasallam, mereka berkata; \"Sampaikanlah salam kami kepada Aisyah dan tanyakan kepadanya tentang shalat (sunnah) setelah Ashar, dan katakan pula kepadanya bahwa kami pernah di beritahukan bahwa anda pernah mengerjakan dua raka'at setelah Ashar padahal Rasulullah shallallahu 'alaihi wasallam telah melarangnya.\" Lalu aku pergi menemui Aisyah dan menyampaikan pesan mereka kepadanya, lalu Aisyah berkata; \"Tanyakanlah kepada Ummu Salamah!.\" Maka aku keluar dan kembali menemui mereka dan menyampaikan apa yang di katakan Aisyah. Mereka mengembalikanku untuk menemui Ummu Salamah dengan berpesan seperti yang di pesankan kepadaku ketika pergi ke rumah Aisyah. Maka [Ummu Salamah] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam melarang dua raka'at setelah Ashar, kemudian aku melihat beliau mengerjakan dua raka'at tersebut, ketika beliau melaksanakannya, yaitu beliau mengerjakan dulu shalat Ashar, lalu beliau masuk, sementara di rumahku ada beberapa wanita Anshar dari Bani Haram. Lalu beliau mengerjakan dua raka'at tersebut, setelah itu aku menyuruh seorang pelayan wanita untuk menemui beliau, kataku; \"Berdirilah di samping beliau dan tanyakan kepadanya; [Ummu Salamah] berkata; \"Wahai Rasulullah, aku pernah mendengar anda telah melarang dua raka'at ini, namun aku melihat justru anda melaksanakannya.\" Beliau memberi isyarat dengan tangannya, karena itu beliau mundur. Setelah selesai shalat, beliau bersabda: \"wahai putri Abu Umayyah, kamu tanyakan dua raka'at setelah Ashar? Sesungguhnya telah datang beberapa orang kepadaku dari kaum Abdul Qais, sementara mereka baru masuk Islam. Karena itu, mereka membuatku sibuk untuk mengerjakan dua raka'at setelah Dluhur, maka dua raka'at (Dluhur) adalah ini.\""},"1067":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ وَهْبِ بْنِ الْأَجْدَعِ عَنْ عَلِيٍّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الصَّلَاةِ بَعْدَ الْعَصْرِ إِلَّا وَالشَّمْسُ مُرْتَفِعَةٌ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Hilal bin Yasaf] dari [Wahb bin Al Ajda'] dari [Ali] bahwa Nabi shallallahu 'alaihi wasallam melarang mengerjakan shalat setelah Ashar kecuali jika matahari masih tinggi.\""},"1068":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ عَاصِمِ بْنِ ضَمْرَةَ عَنْ عَلِيٍّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي إِثْرِ كُلِّ صَلَاةٍ مَكْتُوبَةٍ رَكْعَتَيْنِ إِلَّا الْفَجْرَ وَالْعَصْرَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Abu Ishaq] dari ['Ashim bin Dlamrah] dari [Ali] dia berkata; Rasulullah shallallahu 'alaihi wasallam biasa mengerjakan shalat dua raka'at di sela-sela (setelah) shalat wajib, kecuali shalat subuh dan ashar. '"},"1069":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبَانُ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي الْعَالِيَةِ عَنْ ابْنِ عَبَّاسٍ قَالَشَهِدَ عِنْدِي رِجَالٌ مَرْضِيُّونَ فِيهِمْ عُمَرُ بْنُ الْخَطَّابِ وَأَرْضَاهُمْ عِنْدِي عُمَرُ أَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا صَلَاةَ بَعْدَ صَلَاةِ الصُّبْحِ حَتَّى تَطْلُعَ الشَّمْسُ وَلَا صَلَاةَ بَعْدَ صَلَاةِ الْعَصْرِ حَتَّى تَغْرُبَ الشَّمْسُ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Aban] telah menceritakan kepada kami [Qatadah] dari [Abu Al 'Aliyah] dari [Ibnu Abbas] dia berkata; \"Beberapa orang yang mendapatkan keridlaan (Allah) memberi kesaksian kepadaku, di antara mereka adalah [Umar bin Khattab], dan memang yang paling aku sukai di antara mereka adalah Umar, bahwa Nabi Allah shallallahu 'alaihi wasallam bersabda; \"Tidak ada shalat setelah shalat Shubuh hingga matahari terbit, dan tidak ada shalat setelah shalat Ashar hingga matahari terbenam.\""},"1070":{"ar":"حَدَّثَنَا الرَّبِيعُ بْنُ نَافِعٍ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُهَاجِرِ عَنْ الْعَبَّاسِ بْنِ سَالِمٍ عَنْ أَبِي سَلَّامٍ عَنْ أَبِي أُمَامَةَ عَنْ عَمْرِو بْنِ عَبَسَةَ السُّلَمِيِّ أَنَّهُ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَيُّ اللَّيْلِ أَسْمَعُ قَالَ جَوْفُ اللَّيْلِ الْآخِرُ فَصَلِّ مَا شِئْتَ فَإِنَّ الصَّلَاةَ مَشْهُودَةٌ مَكْتُوبَةٌ حَتَّى تُصَلِّيَ الصُّبْحَ ثُمَّ أَقْصِرْ حَتَّى تَطْلُعَ الشَّمْسُ فَتَرْتَفِعَ قِيسَ رُمْحٍ أَوْ رُمْحَيْنِ فَإِنَّهَا تَطْلُعُ بَيْنَ قَرْنَيْ شَيْطَانٍ وَيُصَلِّي لَهَا الْكُفَّارُ ثُمَّ صَلِّ مَا شِئْتَ فَإِنَّ الصَّلَاةَ مَشْهُودَةٌ مَكْتُوبَةٌ حَتَّى يَعْدِلَ الرُّمْحُ ظِلَّهُ ثُمَّ أَقْصِرْ فَإِنَّ جَهَنَّمَ تُسْجَرُ وَتُفْتَحُ أَبْوَابُهَا فَإِذَا زَاغَتْ الشَّمْسُ فَصَلِّ مَا شِئْتَ فَإِنَّ الصَّلَاةَ مَشْهُودَةٌ حَتَّى تُصَلِّيَ الْعَصْرَ ثُمَّ أَقْصِرْ حَتَّى تَغْرُبَ الشَّمْسُ فَإِنَّهَا تَغْرُبُ بَيْنَ قَرْنَيْ شَيْطَانٍ وَيُصَلِّي لَهَا الْكُفَّارُوَقَصَّ حَدِيثًا طَوِيلًا قَالَ الْعَبَّاسُ هَكَذَا حَدَّثَنِي أَبُو سَلَّامٍ عَنْ أَبِي أُمَامَةَ إِلَّا أَنْ أُخْطِئَ شَيْئًا لَا أُرِيدُهُ فَأَسْتَغْفِرُ اللَّهَ وَأَتُوبُ إِلَيْهِ","id":"Telah menceritakan kepada kami [Ar Rabi' bin Nafi'] telah menceritakan kepada kami [Muhammad bin Al Muhajir] dari [Al 'Abbas bin Salim] dari [Abu Salam] dari [Abu Umamah] dari ['Amru bin 'Abasah As Sulami] bahwa dia berkata; aku bertanya; \"Wahai Rasulullah, pada malam hari yang manakah yang paling di dengar (mustajab)?\" beliau bersabda: \"Di tengah malam yang terakhir, maka shalatlah kamu dengan shalat apa saja yang kamu kehendaki, karena sesungguhnya shalat (pada waktu itu) di saksikan (oleh para malaikat) dan di catat (pahalanya) sampai kamu shalat shubuh, setelah itu, berhentilah sampai matahari terbit dan meninggi sampai seukuran satu atau dua tombak, karena sesungguhnya (antara waktu itu) bertepatan dengan keluarnya tanduk setan dan orang-orang kafir sembahyang kepadanya. Setelah itu, shalatlah kamu dengan shalat apa saja yang kamu kehendaki, karena pada waktu itu, shalat di saksikan (oleh para Malaikat) dan di catat (pahalanya), sehingga tombak sama lurus dengan bayangannya, kemudian berhentilah (sejenak) karena sesungguhnya neraka Jahannam di nyalakan dan semua pintu-pintunya di buka, dan apabila matahari mulai condong (ke barat), Setelah itu, shalatlah kamu dengan shalat apa saja yang kamu kehendaki, karena pada waktu itu, shalat di saksikan (oleh para Malaikat) dan di catat (pahalanya), sampai kamu mengerjakan shalat Ashar, setelah itu berhentilah sampai matahari terbenam, karena (waktu itu) bertepatan dengan terbenamnya kedua tanduk syetan dan orang-orang kafir sembahyang kepadanya…\" selanjutnya Perawi menceritakan hadits yang panjang.\" Abbas berkata; Demikianlah Abu Salam menuturkan haditsnya kepadaku dari Abu Umamah, kecuali kalau ada kesalahan sedikit yang tidak aku sengaja, maka aku meminta ampun kepada Allah dan bertaubat kepada-Nya.\""},"1071":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا قُدَامَةُ بْنُ مُوسَى عَنْ أَيُّوبَ بْنِ حُصَيْنٍ عَنْ أَبِي عَلْقَمَةَ عَنْ يَسَارٍ مَوْلَى ابْنِ عُمَرَ قَالَرَآنِي ابْنُ عُمَرَ وَأَنَا أُصَلِّي بَعْدَ طُلُوعِ الْفَجْرِ فَقَالَ يَا يَسَارُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ عَلَيْنَا وَنَحْنُ نُصَلِّي هَذِهِ الصَّلَاةَ فَقَالَ لِيُبَلِّغْ شَاهِدُكُمْ غَائِبَكُمْ لَا تُصَلُّوا بَعْدَ الْفَجْرِ إِلَّا سَجْدَتَيْنِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Qudamah bin Musa] dari [Ayyub bin Hushain] dari [Abu Alqamah] dari [Yasar] bekas budak Ibnu Umar, dia berkata; [Ibnu Umar] pernah melihatku sedangkan aku tengah mengerjakan shalat setelah terbitnya fajar, dia berkata; \"Ya Yasar, sesungguhnya Rasulullah shallallahu 'alaihi wasallam pernah keluar menemui kami, sedangkan waktu itu kami tengah mengerjakan shalat seperti ini, maka beliau bersabda; \"Hendaknya orang yang menyaksikan (hadir) di antara kalian memberitahu terhadap orang yang tidak hadir, yaitu; janganlah kalian shalat setelah fajar, kecuali dua raka'at (sunnah fajar).\""},"1072":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ وَمَسْرُوقٍ قَالَا نَشْهَدُ عَلَى عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَنَّهَا قَالَتْمَا مِنْ يَوْمٍ يَأْتِي عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا صَلَّى بَعْدَ الْعَصْرِ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al Aswad] dan [Masruq] keduanya berkata; kami bersaksi atas [Aisyah] radliallahu 'anha bahwa dia berkata; \"Tidaklah suatu hari datang kepada Nabi shallallahu 'alaihi wasallam, kecuali beliau pernah mengerjakan shalat dua raka'at setelah Ashar.\""},"1073":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدٍ حَدَّثَنَا عَمِّي حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ عَنْ ذَكْوَانَ مَوْلَى عَائِشَةَ أَنَّهَا حَدَّثَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي بَعْدَ الْعَصْرِ وَيَنْهَى عَنْهَا وَيُوَاصِلُ وَيَنْهَى عَنْ الْوِصَالِ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Sa'd] telah menceritakan kepada kami [pamanku] telah menceritakan kepada kami [ayahku] dari [Ibnu Ishaq] dari [Muhammad bin 'Amru bin 'Atha`] dari [Dzakwan] bekas budak Aisyah bahwa [Aisyah] pernah mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengerjakan shalat (sunnah) setelah Ashar, lalu beliau melarangnya, dan pernah (puasa) wishal (puasa terus), kemudian beliau melarangnya.\""},"1074":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ عَنْ الْحُسَيْنِ الْمُعَلِّمِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ عَبْدِ اللَّهِ الْمُزَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلُّوا قَبْلَ الْمَغْرِبِ رَكْعَتَيْنِ ثُمَّ قَالَ صَلُّوا قَبْلَ الْمَغْرِبِ رَكْعَتَيْنِ لِمَنْ شَاءَ خَشْيَةَ أَنْ يَتَّخِذَهَا النَّاسُ سُنَّةً","id":"Telah menceritakan kepada kami ['Ubaidullah bin Umar] telah menceritakan kepada kami [Abdul Warits bin Sa'id] dari [Al Husain Al Mu'allim] dari ['Abdullah bin Buraidah] dari [Abdullah Al Muzanni] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalatlah kalian dua raka'at sebelum Maghrib.\" Kemudian beliau bersabda: \"Shalatlah kalian dua raka'at sebelum Maghrib bagi yang suka.\" Beliau khawatir orang-orang menjadikannya sebagai sunnah (mu'akkadah).\""},"1075":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ الْبَزَّازُ أَخْبَرَنَا سَعِيدُ بْنُ سُلَيْمَانَ حَدَّثَنَا مَنْصُورُ بْنُ أَبِي الْأَسْوَدِ عَنْ الْمُخْتَارِ بْنِ فُلْفُلٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَصَلَّيْتُ الرَّكْعَتَيْنِ قَبْلَ الْمَغْرِبِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قُلْتُ لِأَنَسٍ أَرَآكُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ رَآنَا فَلَمْ يَأْمُرْنَا وَلَمْ يَنْهَنَا","id":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim Al Bazzaz] telah mengabarkan kepada kami [Sa'id bin Sulaiman] telah menceritakan kepada kami [Manshur bin Abu Al Aswad] dari [Al Mukhtar Al Fulful] dari [Anas bin Malik] dia berkata; \"Aku pernah mengerjakan shalat dua raka'at sebelum Maghrib pada masa Rasulullah shallallahu 'alaihi wasallam.\" Mukhtar berkata; Lalu tanyaku kepada Anas; \"Apakah Rasulullah shallallahu 'alaihi wasallam pernah melihatmu (melakukan hal itu)?\" Anas menjawab; 'Ya, ketika itu beliau melihat kami, namun beliau tidak memerintahkan kami dan tidak juga melarang kami.\""},"1076":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ الْجُرَيْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ كُلِّ أَذَانَيْنِ صَلَاةٌ بَيْنَ كُلِّ أَذَانَيْنِ صَلَاةٌ لِمَنْ شَاءَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Ibnu 'Ulayyah] dari [Al Jurairi] dari [Abdullah bin Buraidah] dari [Abdullah bin Mughaffal] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Di antara setiap dua adzan (adzan dan Iqamah) terdapat shalat (sunnah), dan di antara setiap dua adzan (adzan dan Iqamah) terdapat shalat (sunnah), bagi siapa yang menghendakinya.\""},"1077":{"ar":"حَدَّثَنَا ابْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي شُعَيْبٍ عَنْ طَاوُسٍ قَالَسُئِلَ ابْنُ عُمَرَ عَنْ الرَّكْعَتَيْنِ قَبْلَ الْمَغْرِبِ فَقَالَ مَا رَأَيْتُ أَحَدًا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّيهِمَا وَرَخَّصَ فِي الرَّكْعَتَيْنِ بَعْدَ الْعَصْرِقَالَ أَبُو دَاوُد سَمِعْت يَحْيَى بْنَ مَعِينٍ يَقُولُ هُوَ شُعَيْبٌ يَعْنِي وَهِمَ شُعْبَةُ فِي اسْمِهِ","id":"Telah menceritakan kepada kami [Ibnu Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Syu'aib] dari [Thawus] dia berkata; [Ibnu Umar] pernah di tanya mengenai dua raka'at sebelum Maghrib, dia menjawab; \"Aku tidak pernah melihat seorang pun pada masa Rasulullah shallallahu 'alaihi wasallam yang melakukan dua raka'at tersebut, namun beliau memberi keringanan pada dua raka'at setelah Ashar.\" Abu Daud berkata; aku mendengar Yahya bin Ma'in berkata; \"bahwa Perawi yang meriwayatkan hadits dari Thawus adalah Syu'aib (bukan Abu Syu'aib), Syu'bah ragu mengenai nama Syu'aib.\""},"1078":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ عَنْ عَبَّادِ بْنِ عَبَّادٍ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ الْمَعْنَى عَنْ وَاصِلٍ عَنْ يَحْيَى بْنِ عُقَيْلٍ عَنْ يَحْيَى بْنِ يَعْمَرَ عَنْ أَبِي ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُصْبِحُ عَلَى كُلِّ سُلَامَى مِنْ ابْنِ آدَمَ صَدَقَةٌ تَسْلِيمُهُ عَلَى مَنْ لَقِيَ صَدَقَةٌ وَأَمْرُهُ بِالْمَعْرُوفِ صَدَقَةٌ وَنَهْيُهُ عَنْ الْمُنْكَرِ صَدَقَةٌ وَإِمَاطَتُهُ الْأَذَى عَنْ الطَّرِيقِ صَدَقَةٌ وَبُضْعَةُ أَهْلِهِ صَدَقَةٌ وَيُجْزِئُ مِنْ ذَلِكَ كُلِّهِ رَكْعَتَانِ مِنْ الضُّحَىقَالَ أَبُو دَاوُد وَحَدِيثُ عَبَّادٍ أَتَمُّ وَلَمْ يَذْكُرْ مُسَدَّدٌ الْأَمْرَ وَالنَّهْيَ زَادَ فِي حَدِيثِهِ وَقَالَ كَذَا وَكَذَا وَزَادَ ابْنُ مَنِيعٍ فِي حَدِيثِهِ قَالُوا يَا رَسُولَ اللَّهِ أَحَدُنَا يَقْضِي شَهْوَتَهُ وَتَكُونُ لَهُ صَدَقَةٌ قَالَ أَرَأَيْتَ لَوْ وَضَعَهَا فِي غَيْرِ حِلِّهَا أَلَمْ يَكُنْ يَأْثَمُ","id":"Telah mengabarkan kepada kami [Ahmad bin Mani'] dari ['Abbad bin 'Abbad]. Dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Hammad bin Zaid] sedangkan makna haditsnya dari [Washil] dari [Yahya bin 'Uqail] dari [Yahya bin Ma'mar] dari [Abu Dzar] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Setiap pagi dari setiap ruas yang di miliki oleh ibnu Adam terdapat sedekahnya, memberi salam kepada orang yang di jumpainya adalah sedekah, memerintahkan kepada kebaikan adalah sedekah, mencegah dari kemungkaran adalah sedekah, menyingkirkan duri dari jalan adalah sedekah dan mengumpuli (bersenggama) dengan isterinya adalah sedekah, dan itu semua bisa di gantikan dengan dua raka'at shalat Dluha.\" Abu Daud berkata; \"Haditsnya 'Abbad lebih lengkap, namun Musaddad tidak menyebutkan kalimat \"Memerintahkan (yang ma'ruf) dan mencegah (dari kemungkaran) \", dalam haditsnya ada sedikit tambahan, beliau bersabda seperti ini dan ini, Ibnu Mani' menambahkan dalam haditsnya; para sahabat bertanya; \"Wahai Rasulullah, apakah jika salah seorang dari kami memenuhi tuntutan syahwatnya (mengumpuli isterinya) mendapatkan sedekah?\" beliau menjawab; \"Bagaimana pendapatmu jika dia meletakkan syahwatnya bukan pada yang di halalkannya, apakah dia mendapatkan dosa?\""},"1079":{"ar":"حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ أَخْبَرَنَا خَالِدٌ عَنْ وَاصِلٍ عَنْ يَحْيَى بْنِ عُقَيْلٍ عَنْ يَحْيَى بْنِ يَعْمَرَ عَنْ أَبِي الْأَسْوَدِ الدُّؤَلِيِّ قَالَبَيْنَمَا نَحْنُ عِنْدَ أَبِي ذَرٍّ قَالَ يُصْبِحُ عَلَى كُلِّ سُلَامَى مِنْ أَحَدِكُمْ فِي كُلِّ يَوْمٍ صَدَقَةٌ فَلَهُ بِكُلِّ صَلَاةٍ صَدَقَةٌ وَصِيَامٍ صَدَقَةٌ وَحَجٍّ صَدَقَةٌ وَتَسْبِيحٍ صَدَقَةٌ وَتَكْبِيرٍ صَدَقَةٌ وَتَحْمِيدٍ صَدَقَةٌ فَعَدَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ هَذِهِ الْأَعْمَالِ الصَّالِحَةِ ثُمَّ قَالَ يُجْزِئُ أَحَدَكُمْ مِنْ ذَلِكَ رَكْعَتَا الضُّحَى","id":"Telah menceritakan kepada kami [Wahb bin Baqiyah] telah mengabarkan kepada kami [Khalid] dari [Washil] dari [Yahya bin 'Uqail] dari [Yahya bin Ya'mar] dari [Abu Al Aswad Ad Du`ali] dia berkata; \"ketika kami berada di dekat [Abu Dzar], dia berkata; \"Hendaklah masing-masing dari kalian setiap harinya bersedekah untuk setiap ruas tulangnya. Setiap shalat (yang ia kerjakan) menjadi sedekah baginya, puasa adalah sedekah, haji adalah sedekah, bacaan tasbih adalah sedekah, bacaan takbir juga sedekah, bacaan tahmid adalah sedekah.\" Rasulullah shallallahu 'alaihi wasallam menghitung (menyebutkan) semua amal Shalih ini, lalu bersabda: \"Cukuplah salah seorang dari kalian mengerjakan shalat dua raka'at dhuha untuk menggantikan semua itu.\""},"1080":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ الْمُرَادِيُّ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يَحْيَى بْنِ أَيُّوبَ عَنْ زَبَّانَ بْنِ فَائِدٍ عَنْ سَهْلِ بْنِ مُعَاذِ بْنِ أَنَسٍ الْجُهَنِيِّ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَعَدَ فِي مُصَلَّاهُ حِينَ يَنْصَرِفُ مِنْ صَلَاةِ الصُّبْحِ حَتَّى يُسَبِّحَ رَكْعَتَيْ الضُّحَى لَا يَقُولُ إِلَّا خَيْرًا غُفِرَ لَهُ خَطَايَاهُ وَإِنْ كَانَتْ أَكْثَرَ مِنْ زَبَدِ الْبَحْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Salamah Al Muradi] telah menceritakan kepada kami [Ibnu Wahb] dari [Yahya bin Ayyub] dari [Zabban bin Fa`id] dari [Sahl bin Mu'adz bin Anas Al Juhani] dari [ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa tetap duduk di tempat shalatnya ketika selesai dari shalat shubuh sampai dia mengerjakan dua raka'at dluha dan tidak mengucapkan kata-kata kecuali yang baik, melainkan dosa-dosanya akan terampuni meskipun lebih banyak dari buih di lautan.\""},"1081":{"ar":"حَدَّثَنَا أَبُو تَوْبَةَ الرَّبِيعُ بْنُ نَافِعٍ حَدَّثَنَا الْهَيْثَمُ بْنُ حُمَيْدٍ عَنْ يَحْيَى بْنِ الْحَارِثِ عَنْ الْقَاسِمِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي أُمَامَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةٌ فِي إِثْرِ صَلَاةٍ لَا لَغْوَ بَيْنَهُمَا كِتَابٌ فِي عِلِّيِّينَ","id":"Telah menceritakan kepada kami [Abu Taubah Ar Rabi' bin Nafi'] telah menceritakan kepada kami [Al Haitsam bin Humaid] dari [Yahya bin Al Harits] dari [Al Qasim bin Abdurrahman] dari [Abu Umamah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Suatu shalat yang di kerjakan setelah shalat, yang antara kedua shalat tersebut tidak ada perkataan yang sia-sia, melainkan akan menjadi suatu catatan amal kelak di 'Iliyyin (nama surga).\""},"1082":{"ar":"حَدَّثَنَا دَاوُدُ بْنُ رُشَيْدٍ حَدَّثَنَا الْوَلِيدُ عَنْ سَعِيدِ بْنِ عَبْدِ الْعَزِيزِ عَنْ مَكْحُولٍ عَنْ كَثِيرِ بْنِ مُرَّةَ أَبِي شَجَرَةَ عَنْ نُعَيْمِ بْنِ هَمَّارٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَقُولُ اللَّهُ عَزَّ وَجَلَّ يَا ابْنَ آدَمَ لَا تُعْجِزْنِي مِنْ أَرْبَعِ رَكَعَاتٍ فِي أَوَّلِ نَهَارِكَ أَكْفِكَ آخِرَهُ","id":"Telah menceritakan kepada kami [Daud bin Rusyaid] telah menceritakan kepada kami [Al Walid] dari [Sa'id bin Abdul Aziz] dari [Makhul] dari [Katsir bin Murrah Abu Syajarah] dari [Nu'aim bin Hammar] dia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah 'azza wajalla berfirman; Wahai anak Adam, janganlah kamu meninggalkan-Ku (karena tidak mengerjakan) empat raka'at pada permulaan siang, niscaya aku akan mencukupi kebutuhanmu di sore hari.\""},"1083":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ وَأَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَا حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنِي عَيَّاضُ بْنُ عَبْدِ اللَّهِ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ أُمِّ هَانِئٍ بِنْتِ أَبِي طَالِبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْفَتْحِ صَلَّى سُبْحَةَ الضُّحَى ثَمَانِيَ رَكَعَاتٍ يُسَلِّمُ مِنْ كُلِّ رَكْعَتَيْنِ قَالَ أَحْمَدُ بْنُ صَالِحٍ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى يَوْمَ الْفَتْحِ سُبْحَةَ الضُّحَى فَذَكَرَ مِثْلَهُ قَالَ ابْنُ السَّرْحِ إِنَّ أُمَّ هَانِئٍ قَالَتْ دَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَذْكُرْ سُبْحَةَ الضُّحَى بِمَعْنَاهُ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] dan [Ahmad bin 'Amru bin As Sarh] keduanya berkata; telah menceritakan kepada kami [Ibnu Wahb] telah menceritakan kepadaku ['Ayyadl bin Abdullah] dari [Makhramah bin Sulaiman] dari [Kuraib] bekas budak Ibnu Abbas, dari [Ummu Hani` binti Abu Thalib] bahwa pada hari penaklukan kota Makkah, Rasulullah shallallahu 'alaihi wasallam pernah mengerjakan shalat Dhuha delapan raka'at, di setiap dua raka'at beliau salam.\" [Ahmad bin Shalih] berkata; \"Sesungguhnya pada hari penaklukan kota Makkah, Rasulullah shallallahu 'alaihi wasallam pernah mengerjakan shalat Dhuha …\" kemudian dia menyebutkan seperti hadits di atas.\" [Ibnu As Sarh] mengatakan; Sesungguhnya [Ummu Hani`] berkata; \"Rasulullah shallallahu 'alaihi wasallam masuk menemuiku…\" tanpa menyebutkan kalimat \"Mengerjakan shalat Dhuha\" dengan maksud haditsnya.\""},"1084":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ ابْنِ أَبِي لَيْلَى قَالَمَا أَخْبَرَنَا أَحَدٌ أَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الضُّحَى غَيْرُ أُمِّ هَانِئٍ فَإِنَّهَا ذَكَرَتْ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ اغْتَسَلَ فِي بَيْتِهَا وَصَلَّى ثَمَانِيَ رَكَعَاتٍ فَلَمْ يَرَهُ أَحَدٌ صَلَّاهُنَّ بَعْدُ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dari [Ibnu Abu Laila] dia berkata; Tidak ada seorang pun yang menyampaikan kepada kami bahwa dirinya pernah melihat Nabi shallallahu 'alaihi wasallam mengerjakan shalat Dluha selain [Ummu Hani`], bahwa dirinya menyebutkan bahwa pada hari penaklukan kota Makkah, Nabi shallallahu 'alaihi wasallam pernah mandi di rumahnya kemudian beliau mengerjakan shalat delapan raka'at, dan tidak ada seorang pun yang melihat beliau mengerjakannya setelah itu.\""},"1085":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا الْجُرَيْرِيُّ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ قَالَ سَأَلْتُ عَائِشَةَهَلْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الضُّحَى فَقَالَتْ لَا إِلَّا أَنْ يَجِيءَ مِنْ مَغِيبِهِ قُلْتُ هَلْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرِنُ بَيْنَ السُّورَتَيْنِ قَالَتْ مِنْ الْمُفَصَّلِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Al Jurairi] dari [Abdullah bin Syaqiq] dia berkata; aku pernah bertanya kepada [Aisyah]; \"Apakah Rasulullah shallallahu 'alaihi wasallam biasa melaksanakan shalat Dhuha?\" Aisyah menjawab; \"tidak, kecuali jika beliau tiba dari suatu perjalanan.\" Tanyaku selanjutnya; \"Apakah beliau juga sering menggabungkan antara dua surat?\" Jawab Aisyah; \"Ya, di surat-surat yang di baca pendek (yaitu dari surat Qaaf atau Al Hujurat sampai surat an nas -pent).\""},"1086":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا قَالَتْمَا سَبَّحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُبْحَةَ الضُّحَى قَطُّ وَإِنِّي لَأُسَبِّحُهَا وَإِنْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيَدَعُ الْعَمَلَ وَهُوَ يُحِبُّ أَنْ يَعْمَلَ بِهِ خَشْيَةَ أَنْ يَعْمَلَ بِهِ النَّاسُ فَيُفْرَضَ عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari ['Urwah bin Zubair] dari ['Aisyah istri Nabi shallallahu 'alaihi wasallam] bahwa dia berkata; \"Rasulullah shallallahu 'alaihi wasallam sama sekali tidak pernah mengerjakan shalat sunnah Dluha, dan aku sungguh mengerjakannya, walaupun Rasulullah shallallahu 'alaihi wasallam meninggalkan amal kebaikan yang sebenarnya beliau suka mengerjakannya, hal itu karena beliau khawatir di kerjakan oleh orang-orang yang akhirnya amalan itu di wajibkan atas mereka.\""},"1087":{"ar":"حَدَّثَنَا ابْنُ نُفَيْلٍ وَأَحْمَدُ بْنُ يُونُسَ قَالَا حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا سِمَاكٌ قَالَقُلْتُ لِجَابِرِ بْنِ سَمُرَةَ أَكُنْتَ تُجَالِسُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ كَثِيرًا فَكَانَ لَا يَقُومُ مِنْ مُصَلَّاهُ الَّذِي صَلَّى فِيهِ الْغَدَاةَ حَتَّى تَطْلُعَ الشَّمْسُ فَإِذَا طَلَعَتْ قَامَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ibnu Nufail] dan [Ahmad bin Yunus] keduanya berkata; telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Simak] dia berkata; \"Kataku kepada [Jabir bin Samurah]; \"Apakah kamu pernah bermajlis bersama Rasulullah shallallahu 'alaihi wasallam?\" jawabnya; \"Ya, sering, beliau tidak berdiri dari tempat beliau mengerjakan shalat subuh sehingga matahari terbit, apabila matahari telah terbit, maka beliau shallallahu 'alaihi wasallam berdiri.\""},"1088":{"ar":"حَدَّثَنَا عَمْرُو بْنُ مَرْزُوقٍ أَخْبَرَنَا شُعْبَةُ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ عَلِيِّ بْنِ عَبْدِ اللَّهِ الْبَارِقِيِّ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةُ اللَّيْلِ وَالنَّهَارِ مَثْنَى مَثْنَى","id":"Telah menceritakan kepada kami ['Umar bin Marzuq] telah mengabarkan kepada kami [Syu'bah] dari [Ya'la bin 'Atha`] dari [Ali bin Abdullah Al Bariqi] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Shalat di malam dan siang hari adalah dua-dua (raka'at).\""},"1089":{"ar":"حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنِي عَبْدُ رَبِّهِ بْنُ سَعِيدٍ عَنْ أَنَسِ بْنِ أَبِي أَنَسٍ عَنْ عَبْدِ اللَّهِ بْنِ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ الْمُطَّلِبِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الصَّلَاةُ مَثْنَى مَثْنَى أَنْ تَشَهَّدَ فِي كُلِّ رَكْعَتَيْنِ وَأَنْ تَبَاءَسَ وَتَمَسْكَنَ وَتُقْنِعَ بِيَدَيْكَ وَتَقُولَ اللَّهُمَّ اللَّهُمَّ فَمَنْ لَمْ يَفْعَلْ ذَلِكَ فَهِيَ خِدَاجٌسُئِلَ أَبُو دَاوُد عَنْ صَلَاةِ اللَّيْلِ مَثْنَى قَالَ إِنْ شِئْتَ مَثْنَى وَإِنْ شِئْتَ أَرْبَعًا","id":"Telah menceritakan kepada kami [Ibnu Al Mutsanna] telah menceritakan kepada kami [Mu'adz bin Mu'adz] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepadaku ['Abd Rabbihi bin Sa'id] dari [Anas bin Abu Anas] dari [Abdullah bin Nafi'] dari [Abdullah bin Al Harits] dari [Al Mutthalib] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Shalat itu dua-dua (raka'at), hendaknya kamu (duduk) tasyahud setiap dua raka'at, hendaknya kamu khusyu', tenang dan berdo'a (dengan mengangkat kedua tanganmu), sambil mengucapkan; \"Ya Allah, Ya Allah …, barangsiapa tidak melakukan hal itu, maka shalatnya kurang (sempurna).\" Abu Daud di tanya mengenai shalat malam, apakah dua raka'at-dua raka'at?\" jawabnya; \"Jika mau dua raka'at-dua raka'at, dan jika mau boleh empat raka'at-empat raka'at.\""},"1090":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ بِشْرِ بْنِ الْحَكَمِ النَّيْسَابُورِيُّ حَدَّثَنَا مُوسَى بْنُ عَبْدِ الْعَزِيزِ حَدَّثَنَا الْحَكَمُ بْنُ أَبَانَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِلْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ يَا عَبَّاسُ يَا عَمَّاهُ أَلَا أُعْطِيكَ أَلَا أَمْنَحُكَ أَلَا أَحْبُوكَ أَلَا أَفْعَلُ بِكَ عَشْرَ خِصَالٍ إِذَا أَنْتَ فَعَلْتَ ذَلِكَ غَفَرَ اللَّهُ لَكَ ذَنْبَكَ أَوَّلَهُ وَآخِرَهُ قَدِيمَهُ وَحَدِيثَهُ خَطَأَهُ وَعَمْدَهُ صَغِيرَهُ وَكَبِيرَهُ سِرَّهُ وَعَلَانِيَتَهُ عَشْرَ خِصَالٍ أَنْ تُصَلِّيَ أَرْبَعَ رَكَعَاتٍ تَقْرَأُ فِي كُلِّ رَكْعَةٍ فَاتِحَةَ الْكِتَابِ وَسُورَةً فَإِذَا فَرَغْتَ مِنْ الْقِرَاءَةِ فِي أَوَّلِ رَكْعَةٍ وَأَنْتَ قَائِمٌ قُلْتَ سُبْحَانَ اللَّهِ وَالْحَمْدُ لِلَّهِ وَلَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ خَمْسَ عَشْرَةَ مَرَّةً ثُمَّ تَرْكَعُ فَتَقُولُهَا وَأَنْتَ رَاكِعٌ عَشْرًا ثُمَّ تَرْفَعُ رَأْسَكَ مِنْ الرُّكُوعِ فَتَقُولُهَا عَشْرًا ثُمَّ تَهْوِي سَاجِدًا فَتَقُولُهَا وَأَنْتَ سَاجِدٌ عَشْرًا ثُمَّ تَرْفَعُ رَأْسَكَ مِنْ السُّجُودِ فَتَقُولُهَا عَشْرًا ثُمَّ تَسْجُدُ فَتَقُولُهَا عَشْرًا ثُمَّ تَرْفَعُ رَأْسَكَ فَتَقُولُهَا عَشْرًا فَذَلِكَ خَمْسٌ وَسَبْعُونَ فِي كُلِّ رَكْعَةٍ تَفْعَلُ ذَلِكَ فِي أَرْبَعِ رَكَعَاتٍ إِنْ اسْتَطَعْتَ أَنْ تُصَلِّيَهَا فِي كُلِّ يَوْمٍ مَرَّةً فَافْعَلْ فَإِنْ لَمْ تَفْعَلْ فَفِي كُلِّ جُمُعَةٍ مَرَّةً فَإِنْ لَمْ تَفْعَلْ فَفِي كُلِّ شَهْرٍ مَرَّةً فَإِنْ لَمْ تَفْعَلْ فَفِي كُلِّ سَنَةٍ مَرَّةً فَإِنْ لَمْ تَفْعَلْ فَفِي عُمُرِكَ مَرَّةًحَدَّثَنَا مُحَمَّدُ بْنُ سُفْيَانَ الْأُبُلِّيُّ حَدَّثَنَا حَبَّانُ بْنُ هِلَالٍ أَبُو حَبِيبٍ حَدَّثَنَا مَهْدِيُّ بْنُ مَيْمُونٍ حَدَّثَنَا عَمْرُو بْنُ مَالِكٍ عَنْ أَبِي الْجَوْزَاءِ قَالَ حَدَّثَنِي رَجُلٌ كَانَتْ لَهُ صُحْبَةٌ يَرَوْنَ أَنَّهُ عَبْدُ اللَّهِ بْنُ عَمْرٍو قَالَ قَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ائْتِنِي غَدًا أَحْبُوكَ وَأُثِيبُكَ وَأُعْطِيكَ حَتَّى ظَنَنْتُ أَنَّهُ يُعْطِينِي عَطِيَّةً قَالَ إِذَا زَالَ النَّهَارُ فَقُمْ فَصَلِّ أَرْبَعَ رَكَعَاتٍ فَذَكَرَ نَحْوَهُ قَالَ ثُمَّ تَرْفَعُ رَأْسَكَ يَعْنِي مِنْ السَّجْدَةِ الثَّانِيَةِ فَاسْتَوِ جَالِسًا وَلَا تَقُمْ حَتَّى تُسَبِّحَ عَشْرًا وَتَحْمَدَ عَشْرًا وَتُكَبِّرَ عَشْرًا وَتُهَلِّلَ عَشْرًا ثُمَّ تَصْنَعَ ذَلِكَ فِي الْأَرْبَعِ الرَّكَعَاتِ قَالَ فَإِنَّكَ لَوْ كُنْتَ أَعْظَمَ أَهْلِ الْأَرْضِ ذَنْبًا غُفِرَ لَكَ بِذَلِكَ قُلْتُ فَإِنْ لَمْ أَسْتَطِعْ أَنْ أُصَلِّيَهَا تِلْكَ السَّاعَةَ قَالَ صَلِّهَا مِنْ اللَّيْلِ وَالنَّهَارِ قَالَ أَبُو دَاوُد حَبَّانُ بْنُ هِلَالٍ خَالُ هِلَالٍ الرَّأْيِ قَالَ أَبُو دَاوُد رَوَاهُ الْمُسْتَمِرُّ بْنُ الرَّيَّانِ عَنْ أَبِي الْجَوْزَاءِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو مَوْقُوفًا وَرَوَاهُ رَوْحُ بْنُ الْمُسَيَّبِ وَجَعْفَرُ بْنُ سُلَيْمَانَ عَنْ عَمْرِو بْنِ مَالِكٍ النُّكْرِيِّ عَنْ أَبِي الْجَوْزَاءِ عَنْ ابْنِ عَبَّاسٍ قَوْلُهُ وَقَالَ فِي حَدِيثِ رَوْحٍ فَقَالَ حَدِيثُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا أَبُو تَوْبَةَ الرَّبِيعُ بْنُ نَافِعٍ حَدَّثَنَا مُحَمَّدُ بْنُ مُهَاجِرٍ عَنْ عُرْوَةَ بْنِ رُوَيْمٍ حَدَّثَنِي الْأَنْصَارِيُّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِجَعْفَرٍ بِهَذَا الْحَدِيثِ فَذَكَرَ نَحْوَهُمْ قَالَ فِي السَّجْدَةِ الثَّانِيَةِ مِنْ الرَّكْعَةِ الْأُولَى كَمَا قَالَ فِي حَدِيثِ مَهْدِيِّ بْنِ مَيْمُونٍ","id":"Telah menceritakan kepada kami [Abdurrahman bin Bisyr bin Hakam An Naisabury] telah menceritakan kepada kami [Musa bin Abdul Aziz] telah menceritakan kepada kami [Al Hakam bin Aban] dari [Ikrimah] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda kepada Abbas bin Abdul Mutthalib: \"Wahai Abbas, wahai pamanku, sukakah paman, aku beri, aku karuniai, aku beri hadiah istimewa, aku ajari sepuluh macam kebaikan yang dapat menghapus sepuluh macam dosa? Jika paman mengerjakan ha itu, maka Allah akan mengampuni dosa-dosa paman, baik yang awal dan yang akhir, baik yang telah lalu atau yang akan datang, yang di sengaja ataupun tidak, yang kecil maupun yang besar, yang samar-samar maupun yang terang-terangan. Sepuluh macam kebaikan itu ialah; \"Paman mengerjakan shalat empat raka'at, dan setiap raka'at membaca AL Fatihah dan surat, apabila selesai membaca itu, dalam raka'at pertama dan masih berdiri, bacalah; \"Subhanallah wal hamdulillah walaa ilaaha illallah wallahu akbar (Maha suci Allah, segala puji bagi Allah, tidak ada ilah selain Allah dan Allah Maha besar) \" sebanyak lima belas kali, lalu ruku', dan dalam ruku' membaca bacaan seperti itu sebanyak sepuluh kali, kemudian mengangkat kepala dari ruku' (i'tidal) juga membaca seperti itu sebanyak sepuluh kali, lalu sujud juga membaca sepuluh kali, setelah itu mengangkat kepala dari sujud (duduk di antara dua sujud) juga membaca sepuluh kali, lalu sujud juga membaca sepuluh kali, kemudian mengangkat kepala dan membaca sepuluh kali, Salim bin Abul Ja'd jumlahnya ada tujuh puluh lama kali dalam setiap raka'at, paman dapat melakukannya dalam empat raka'at. jika paman sanggup mengerjakannya sekali dalam sehari, kerjakanlah. Jika tidak mampu, kerjakanlah setiap jum'at, jika tidak mampu, kerjakanlah setiap bulan, jika tidak mampu, kerjakanlah setiap tahun sekali. Dan jika masih tidak mampu, kerjakanlah sekali dalam seumur hidup.\" Telah menceritakan kepada kami [Muhammad bin Sufyan Al Ubuli] telah menceritakan kepada kami [Habban bin Hilal Abu Habib] telah menceritakan kepada kami [Mahdi bin Maimun] telah menceritakan kepada kami ['Amru bin Malik] dari [Abu Jauza`] dia berkata; telah menceritakan kepada kami seseorang laki-laki yang pernah bersahabat dengannya, menurut mereka, dia adalah [Abdullah bin 'Amru] dia berkata; Nabi shallallahu 'alaihi wasallam bersabda kepadaku: \"Datanglah kepadaku besok hari, aku akan memberimu suatu pemberian.\" Hingga aku mengira beliau benar-benar akan memberiku suatu pemberian. Beliau bersabda: \"Apabila siang agak reda, maka berdirilah untuk menunaikan shalat empat raka'at…\" kemudian dia menyebutkan hadits seperti di atas. Beliau lalu bersabda: \"Kemudian kamu mengangkat kepalamu -yaitu dari sujud kedua- sehingga kamu benar-benar duduk, dan janganlah berdiri hingga membaca tasbih, tahmid, takbir dan tahlil masing-masing sepuluh kali, lalu kamu melakukan hal itu di empat raka'at.\" Beliau melanjutkan; \"Seandainya kamu orang yang paling besar dosanya di antara penduduk bumi, maka dosa-dosamu akan di ampuni dengan melakukan hal itu (shalat tasbih).\" Aku bertanya; \"Jika aku tidak mampu melaksanakan shalat tasbih pada waktu itu?\" beliau menjawab: \"Kerjakanlah di malam hari atau siang hari.\" Abu Daud berkata; \"Habban bin Daud adalah pamannya Hilal Ar Ra'yi. Abu Daud berkata; \"Hadits ini di riwayawatkan pula oleh [Al Mustamir Ar Rayyan] dari [Abu Al Jauza`] dari [Abdullah bin 'Amru] secara mauquf. Dan di riwayatkan pula oleh [Rauh bin Al Musayyab] dan [Ja'far bin Sulaiman] dari ['Amru bin Malik An Nukri] dari [Abu Al Jauza`] dari [Ibnu Abbas]. Sedangkan perkataannya mengenai hadits Rauh, dia berkata; yaitu hadits dari Nabi shallallahu 'alaihi wasallam. Telah menceritakan kepada kami [Abu Taubah Ar Rabi' bin Nafi'] telah menceritakan kepada kami [Muhammad bin Muhajir] dari ['Urwah bin Ruwaim] telah menceritakan kepadaku [Al Anshari] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda kepada Ja'far…\" dengan hadits ini, lalu dia menyebutkan seperti hadits mereka, katanya; \"……dalam sujud kedua pada raka'at pertama.\" Sebagaimana dia berkata dalam hadits Mahdi bin Maimun.\""},"1091":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي الْأَسْوَدِ حَدَّثَنِي أَبُو مُطَرِّفٍ مُحَمَّدُ بْنُ أَبِي الْوَزِيرِ حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى الْفِطْرِيُّ عَنْ سَعْدِ بْنِ إِسْحَقَ بْنِ كَعْبِ بْنِ عُجْرَةَ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى مَسْجِدَ بَنِي عَبْدِ الْأَشْهَلِ فَصَلَّى فِيهِ الْمَغْرِبَ فَلَمَّا قَضَوْا صَلَاتَهُمْ رَآهُمْ يُسَبِّحُونَ بَعْدَهَا فَقَالَ هَذِهِ صَلَاةُ الْبُيُوتِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Al Aswad] telah menceritakan kepadaku [Abu Mutharif Muhammad bin Abu Al Wazir] telah menceritakan kepada kami [Muhammad bin Musa Al Fithri] dari [Sa'd bin Ishaq bin Ka'b bin 'Ujrah] dari [ayahnya] dari [kakeknya] bahwa Nabi shallallahu 'alaihi wasallam pernah datang berkunjung ke Masjid Bani Abdul Asyhal, kemudian beliau shalat Maghrib, ketika mereka selesai mengerjakan shalat Maghrib, beliau melihat mereka mengerjakan shalat sunnah, maka beliau bersabda: \"Shalat ini adalah shalat untuk di kerjakan di rumah.\""},"1092":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ عَبْدِ الرَّحْمَنِ الْجَرْجَرَائِيُّ حَدَّثَنَا طَلْقُ بْنُ غَنَّامٍ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ اللَّهِ عَنْ جَعْفَرِ بْنِ أَبِي الْمُغِيرَةِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُطِيلُ الْقِرَاءَةَ فِي الرَّكْعَتَيْنِ بَعْدَ الْمَغْرِبِ حَتَّى يَتَفَرَّقَ أَهْلُ الْمَسْجِدِقَالَ أَبُو دَاوُد رَوَاهُ نَصْرٌ الْمُجَدَّرُ عَنْ يَعْقُوبَ الْقُمِّيِّ وَأَسْنَدَهُ مِثْلَهُ قَالَ أَبُو دَاوُد حَدَّثَنَاه مُحَمَّدُ بْنُ عِيسَى بْنِ الطَّبَّاعِ حَدَّثَنَا نَصْرٌ الْمُجَدَّرُ عَنْ يَعْقُوبَ مِثْلَهُ حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ وَسُلَيْمَانُ بْنُ دَاوُدَ الْعَتَكِيُّ قَالَا حَدَّثَنَا يَعْقُوبُ عَنْ جَعْفَرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ النَّبِيِّ بِمَعْنَاهُ مُرْسَلًا قَالَ أَبُو دَاوُد سَمِعْت مُحَمَّدَ بْنَ حُمَيْدٍ يَقُولُ سَمِعْتُ يَعْقُوبَ يَقُولُ كُلُّ شَيْءٍ حَدَّثْتُكُمْ عَنْ جَعْفَرِ بْنِ الْمُغِيرَةِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهُوَ مُسْنَدٌ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Husain bin Abdurrahman Al Jarjara`i] telah menceritakan kepada kami [Thalq bin Ghanam] telah menceritakan kepada kami [Ya'qub bin Abdullah] dari [Ja'far bin Abu Al Mughirah] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam biasa memanjangkan bacaan di dua raka'at (shalat sunnah) setelah Maghrib sehingga orang-orang dalam masjid bubar.\" Abu Daud berkata; \"Telah di riwayatkan pula oleh [Nahsr Al Mujaddar] dari [Ya'qub Al Qummi] dengan mensanadkan seperti hadits di atas. Abu Daud berkata; telah menceritakan kepada kami [Muhammad bin Isa bin Ath Thaba'] telah menceritakan kepada kami [Nashr Al Mujaddar] dari [Ya'qub] seperti hadits di atas. Telah menceritakan kepada kami [Ahmad bin Yunus] dan [Sulaiman bin Daud Al 'Ataki] keduanya berkata; telah menceritakan kepada kami [Ya'qub] dari [Ja'far] dari [sa'id bin Jubair] dari Nabi shallallahu 'alaihi wasallam dengan maksud yang sama, secara mursal. Abu Daud berkata; aku mendengar Muhammad bin Humaid berkata; aku mendengar Ya'qub berkata; \"Setiap (hadits) yang aku sampaikan kepada kalian dari Ja'far bin Mughirah dari Sa'id bin Jubair dari Nabi shallallahu 'alaihi wasallam adalah musnad (bersambung) dari Ibnu Abbas dari Nabi shallallahu 'alaihi wasallam.\""},"1093":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ الْعُكْلِيُّ حَدَّثَنِي مَالِكُ بْنُ مِغْوَلٍ حَدَّثَنِي مُقَاتِلُ بْنُ بَشِيرٍ الْعِجْلِيُّ عَنْ شُرَيْحِ بْنِ هَانِئٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَسَأَلْتُهَا عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ مَا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعِشَاءَ قَطُّ فَدَخَلَ عَلَيَّ إِلَّا صَلَّى أَرْبَعَ رَكَعَاتٍ أَوْ سِتَّ رَكَعَاتٍ وَلَقَدْ مُطِرْنَا مَرَّةً بِاللَّيْلِ فَطَرَحْنَا لَهُ نِطَعًا فَكَأَنِّي أَنْظُرُ إِلَى ثُقْبٍ فِيهِ يَنْبُعُ الْمَاءُ مِنْهُ وَمَا رَأَيْتُهُ مُتَّقِيًا الْأَرْضَ بِشَيْءٍ مِنْ ثِيَابِهِ قَطُّ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Zaid bin Al Khubbab Al 'Ukali] telah menceritakan kepadaku [Malik bin Mighwal] telah menceritakan kepadaku [Muqatil bin Basyir Al 'Ijli] dari [Syuraih bin Hani`] dari [Aisyah radliallahu 'anha]. Syuraih berkata; aku bertanya kepada Aisyah mengenai shalat Rasulullah shallallahu 'alaihi wasallam.\" Aisyah menjawab; \"Rasulullah shallallahu 'alaihi wasallam tidak pernah mengerjakan shalat Isya` sama sekali kemudian menemuiku melainkan beliau shalat (sunnah) sesudahnya empat atau enam raka'at. Suatu malam kami terkena hujan, kontan kami hamparkan selembar tikar kulit untuk beliau, dan seakan-akan kulihat suatu lubang pada tikar tersebut mengeluarkan rembesan air, dan tidak kulihat beliau menjauhkan tanah dengan bagian manapun dari kainnya.\""},"1094":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيُّ ابْنِ شَبُّوَيْهِ حَدَّثَنِي عَلِيُّ بْنُ حُسَيْنٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَفِي الْمُزَّمِّلِ{ قُمْ اللَّيْلَ إِلَّا قَلِيلًا نِصْفَهُ }نَسَخَتْهَا الْآيَةُ الَّتِي فِيهَا{ عَلِمَ أَنْ لَنْ تُحْصُوهُ فَتَابَ عَلَيْكُمْ فَاقْرَءُوا مَا تَيَسَّرَ مِنْ الْقُرْآنِ }وَنَاشِئَةُ اللَّيْلِ أَوَّلُهُ وَكَانَتْ صَلَاتُهُمْ لِأَوَّلِ اللَّيْلِ يَقُولُ هُوَ أَجْدَرُ أَنْ تُحْصُوا مَا فَرَضَ اللَّهُ عَلَيْكُمْ مِنْ قِيَامِ اللَّيْلِ وَذَلِكَ أَنَّ الْإِنْسَانَ إِذَا نَامَ لَمْ يَدْرِ مَتَى يَسْتَيْق��ظُ وَقَوْلُهُ أَقْوَمُ قِيلًا هُوَ أَجْدَرُ أَنْ يَفْقَهَ فِي الْقُرْآنِ وَقَوْلُهُ{ إِنَّ لَكَ فِي النَّهَارِ سَبْحًا طَوِيلًا }يَقُولُ فَرَاغًا طَوِيلًا","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Mawarzi Ibnu Syabbuwaih] telah menceritakan kepadaku [Ali bin Husain] dari [ayahnya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] dia berkata mengenai surt Al Muzammil, yaitu; \"Bangunlah (shalat) di malam hari, kecuali sedikit daripadanya, (yaitu) separuhnya.\" (QS Al Muzammil; 2-3). Ayat tersebut di hapus dengan surat ini, yaitu; \"Allah mengetahui bahwa kamu sekali-kali tidak dapat menentukan batas-batas waktu itu, maka Dia memberi keringanan kepadamu, karena itu bacalah apa yang mudah (bagimu) dari Al Qur'an.\" (QS Al Muzzamil; 20). Maksud dari \"Nasyi`atul lail\" adalah shalat tahajjudnya mereka (para sahabat) di awal malam (sebelum di mansukh).\" Ibnu Abbas melanjutkan; \"Tahajjud di awal malam lebih sesuai untuk kamu tentukan batas waktu bangun malam yang telah di wajibkan Allah atas kamu. Hal itu karena manusia, apabila telah tidur, ia tidak tahu kapan dirinya bangun.\" Maksud firman Allah; \"Aqwamu qiila\" ialah lebih sesuai untuk memahami AL Qur'an (ketika di baca pada malam hari) \" dan maksud ayat; \"Inna laka fin nahaari sabhan thawiila\" ialah kesempatan yang panjang.\""},"1095":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ يَعْنِي الْمَرْوَزِيَّ حَدَّثَنَا وَكِيعٌ عَنْ مِسْعَرٍ عَنْ سِمَاكٍ الْحَنَفِيِّ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا نَزَلَتْ أَوَّلُ الْمُزَّمِّلِ كَانُوا يَقُومُونَ نَحْوًا مِنْ قِيَامِهِمْ فِي شَهْرِ رَمَضَانَ حَتَّى نَزَلَ آخِرُهَا وَكَانَ بَيْنَ أَوَّلِهَا وَآخِرِهَا سَنَةٌ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad yaitu Al Mawarzi] telah menceritakan kepada kami [Waki'] dari [Mis'ar] dari [Simak Al Hanafi] dari [Ibnu Abbas] dia berkata; \"Ketika turun awal surat Al Muzammil, mereka (para sahabat) bangun (untuk mengerjakan shalat) sebagaimana bangunnya ketika di bulan Ramadhan hingga turun akhir dari surat Al Muzzamil, sedangkan rentang waktu turunnya awal surat Al Muzammil dengan akhir surat itu selama satu tahun.\""},"1096":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَعْقِدُ الشَّيْطَانُ عَلَى قَافِيَةِ رَأْسِ أَحَدِكُمْ إِذَا هُوَ نَامَ ثَلَاثَ عُقَدٍ يَضْرِبُ مَكَانَ كُلِّ عُقْدَةٍ عَلَيْكَ لَيْلٌ طَوِيلٌ فَارْقُدْ فَإِنْ اسْتَيْقَظَ فَذَكَرَ اللَّهَ انْحَلَّتْ عُقْدَةٌ فَإِنْ تَوَضَّأَ انْحَلَّتْ عُقْدَةٌ فَإِنْ صَلَّى انْحَلَّتْ عُقْدَةٌ فَأَصْبَحَ نَشِيطًا طَيِّبَ النَّفْسِ وَإِلَّا أَصْبَحَ خَبِيثَ النَّفْسِ كَسْلَانَ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Syetan mengikat tiga ikatan di tengkuk salah seorang dari kalian ketika dia tidur, dia membuat setiap satu ikatan akan berkata; \"Malam masih panjang\", apabila seseorang bangun kemudian berdzikir kepada Allah, maka akan lepas satu ikatan, jika seseorang berwudlu', maka akan terlepas satu ikatan lagi, jika seseorang shalat, maka akan terlepas satu ikatan lagi, maka di pagi harinya ia menjadi bersemangat dan berhati bersih, apabila tidak, maka di pagi harinya jiwanya menjadi kotor dan akan sangat malas.\""},"1097":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ يَزِيدَ بْنِ خُمَيْرٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي قَيْسٍ يَقُولُ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَالَا تَدَعْ قِيَامَ اللَّيْلِ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يَدَعُهُ وَكَانَ إِذَا مَرِضَ أَوْ كَسِلَ صَلَّى قَاعِدًا","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] dia berkata; telah menceritakan kepada kami [Abu Daud] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Yazid bin Khumair] dia berkata; saya mendengar [Abdullah bin Abu Qais] berkata; [Aisyah radliallahu 'anha] berkata; \"Janganlah kamu meninggalkan shalat malam (qiyamul lail), karena Rasulullah shallallahu 'alaihi wasallam tidak pernah meninggalkannya, bahkan apabila beliau sedang sakit atau kepayahan, beliau shalat dengan duduk.\""},"1098":{"ar":"حَدَّثَنَا ابْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى حَدَّثَنَا ابْنُ عَجْلَانَ عَنْ الْقَعْقَاعِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَحِمَ اللَّهُ رَجُلًا قَامَ مِنْ اللَّيْلِ فَصَلَّى وَأَيْقَظَ امْرَأَتَهُ فَإِنْ أَبَتْ نَضَحَ فِي وَجْهِهَا الْمَاءَ رَحِمَ اللَّهُ امْرَأَةً قَامَتْ مِنْ اللَّيْلِ فَصَلَّتْ وَأَيْقَظَتْ زَوْجَهَا فَإِنْ أَبَى نَضَحَتْ فِي وَجْهِهِ الْمَاءَ","id":"Telah menceritakan kepada kami [Ibnu Basyar] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Ibnu 'Ajlan] dari [Al Qa'qa'] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah akan merahmati seseorang yang bangun malam kemudian shalat lalu membangunkan isterinya, apabila isterinya menolak, dia akan memercikkan air ke mukanya, dan Allah akan merahmati seorang isteri yang bangun malam lalu shalat, kemudian dia membangunkan suaminya, apabila suaminya enggan, maka isterinya akan memercikkan air ke muka suaminya.\""},"1099":{"ar":"حَدَّثَنَا ابْنُ كَثِيرٍ حَدَّثَنَا سُفْيَانُ عَنْ مِسْعَرٍ عَنْ عَلِيِّ بْنِ الْأَقْمَرِ ح و حَدَّثَنَا مُحَمَّدُ بْنُ حَاتِمِ بْنِ بَزِيعٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ شَيْبَانَ عَنْ الْأَعْمَشِ عَنْ عَلِيِّ بْنِ الْأَقْمَرِ الْمَعْنَى عَنْ الْأَغَرِّ عَنْ أَبِي سَعِيدٍ وَأَبِي هُرَيْرَةَ قَالَاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَيْقَظَ الرَّجُلُ أَهْلَهُ مِنْ اللَّيْلِ فَصَلَّيَا أَوْ صَلَّى رَكْعَتَيْنِ جَمِيعًا كُتِبَا فِي الذَّاكِرِينَ وَالذَّاكِرَاتِوَلَمْ يَرْفَعْهُ ابْنُ كَثِيرٍ وَلَا ذَكَرَ أَبَا هُرَيْرَةَ جَعَلَهُ كَلَامَ أَبِي سَعِيدٍ قَالَ أَبُو دَاوُد رَوَاهُ ابْنُ مَهْدِيٍّ عَنْ سُفْيَانَ قَالَ وَأُرَاهُ ذَكَرَ أَبَا هُرَيْرَةَ قَالَ أَبُو دَاوُد وَحَدِيثُ سُفْيَانَ مَوْقُوفٌ","id":"Telah menceritakan kepada kami [Ibnu Katsir] telah menceritakan kepada kami [Sufyan] dari [Mis'ar] dari [Ali bin Al Aqmar]. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Muhammad bin Hatim bin Bazi'] telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Syaiban] dari [Al A'masy] dari [Ali bin Al Aqmar], sedangkan maknanya dari [Al Aghar] dari [Abu Sa'id] dan [Abu Hurairah] keduanya berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila seseorang membangunkan isterinya di malam hari, kemudian keduanya mengerjakan shalat, atau keduanya shalat dua raka'at, maka keduanya akan di catat sebagai orang-orang yang selalu berdzikir.\" Namun Ibnu katsir tidak merafa'kan hadits ini, dan Abu Hurairah juga tidak menjadikan hadits tersebut dari perkataan Abu Sa'id. Abu Daud berkata; \"dan di riwayatkan pula oleh [Ibnu Mahdi] dari [Sufyan] dia berkata; -aku berpendapat bahwa dia menyebutkan \" [Abu Hurairah].\" Abu Daud berkata; \"Sedangkan hadits Sufyan mauquf.\""},"1100":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا نَعَسَ أَحَدُكُمْ فِي الصَّلَاةِ فَلْيَرْقُدْ حَتَّى يَذْهَبَ عَنْهُ النَّوْمُ فَإِنَّ أَحَدَكُمْ إِذَا صَلَّى وَهُوَ نَاعِسٌ لَعَلَّهُ يَذْهَبُ يَسْتَغْفِرُ فَيَسُبَّ نَفْسَهُ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah isteri Nabi] shallallahu 'alaihi wasallam bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian mengantuk dalam shalat, hendaknya ia tidur terlebih dahulu hingga rasa kantuknya hilang, karena apabila salah seorang dari kalian mengerjakan shalat dalam kondisi mengantuk, di khawatirkan ketika dia hendak meminta ampun, tapi sebaliknya dia malah mencela dirinya sendiri.\""},"1101":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ أَحَدُكُمْ مِنْ اللَّيْلِ فَاسْتَعْجَمَ الْقُرْآنُ عَلَى لِسَانِهِ فَلَمْ يَدْرِ مَا يَقُولُ فَلْيَضْطَجِعْ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Abdurrazaq] telah menceritakan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian bangun malam, kemudian terasa berat baginya untuk membaca AL Qur'an (karena mengantuk), hingga ia tidak sadar apa yang di baca, sebaiknya ia tidur terlebih dahulu.\""},"1102":{"ar":"حَدَّثَنَا زِيَادُ بْنُ أَيُّوبَ وَهَارُونُ بْنُ عَبَّادٍ الْأَزْدِيُّ أَنَّ إِسْمَعِيلَ بْنَ إِبْرَاهِيمَ حَدَّثَهُمْ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ أَنَسٍ قَالَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسْجِدَ وَحَبْلٌ مَمْدُودٌ بَيْنَ سَارِيَتَيْنِ فَقَالَ مَا هَذَا الْحَبْلُ فَقِيلَ يَا رَسُولَ اللَّهِ هَذِهِ حَمْنَةُ بِنْتُ جَحْشٍ تُصَلِّي فَإِذَا أَعْيَتْ تَعَلَّقَتْ بِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِتُصَلِّ مَا أَطَاقَتْ فَإِذَا أَعْيَتْ فَلْتَجْلِسْ قَالَ زِيَادٌ فَقَالَ مَا هَذَا فَقَالُوا لِزَيْنَبَ تُصَلِّي فَإِذَا كَسِلَتْ أَوْ فَتَرَتْ أَمْسَكَتْ بِهِ فَقَالَ حُلُّوهُ فَقَالَ لِيُصَلِّ أَحَدُكُمْ نَشَاطَهُ فَإِذَا كَسِلَ أَوْ فَتَرَ فَلْيَقْعُدْ","id":"Telah menceritakan kepada kami [Ziyad bin Ayyub] dan [Harun 'Abbad Al Azdi] bahwa [Isma'il bin Ibrahim] telah menceritakan kepada mereka, telah menceritakan kepada kami [Abdul Aziz] dari [Anas] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah masuk ke dalam masjid, lalu beliau mendapati tali yang membentang antara dua tiang, lantas beliau bertanya; \"Tali apakah ini?\" maka di beritahukan; \"Wahai Rasulullah shallallahu 'alaihi wasallam, ini adalah Hamnah binti Jahsyi, dia sedang mengerjakan shalat, apabila dia merasa kepayahan, maka dia akan bergantung dengan tali tersebut.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaknya ia shalat menurut kemampuannya, apabila telah terasa payah, hendaknya ia duduk.\" Kata Ziyad; beliau bertanya; \"Apakah ini?\" mereka menjawab; \"Ini adalah (tali) milik Zainab, dia sedang mengerjakan shalat, apabila dia terasa capek atau terasa lelah, maka dia akan berpegangan dengannya.\" Maka beliau bersabda: \"Lepaslah tali itu.\" sabdanya lagi; \"Hendaknya salah seorang dari kalian mengerjakan shalat selagi masih segar(semangat), apabila telah lelah atau capek, sebaiknya ia duduk (tidur).\""},"1103":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو صَفْوَانَ عَبْدُ اللَّهِ بْنُ سَعِيدِ بْنِ عَبْدِ الْمَلِكِ بْنِ مَرْوَانَ ح و حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ وَمُحَمَّدُ بْنُ سَلَمَةَ الْمُرَادِيُّ قَالَا حَدَّثَنَا ابْنُ وَهْبٍ الْمَعْنَى عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ أَنَّ السَّائِبَ بْنَ يَزِيدَ وَعُبَيْدَ اللَّهِ أَخْبَرَاهُ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ عَبْدٍ قَالَ عَنْ ابْنِ وَهْبِ بْنِ عَبْدِ الْقَارِيِّ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَامَ عَنْ حِزْبِهِ أَوْ عَنْ شَيْءٍ مِنْهُ فَقَرَأَهُ مَا بَيْنَ صَلَاةِ الْفَجْرِ وَصَلَاةِ الظُّهْرِ كُتِبَ لَهُ كَأَنَّمَا قَرَأَهُ مِنْ اللَّيْلِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abu Shafwan Abdullah bin Sa'id bin Abdul Malik bin Marwan]. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Sulaiman bin Daud] dan [Muhammad bin Salamah Al Muradi] keduanya berkata; telah menceritakan kepada kami [Ibnu Wahb] sedangkan maknanya dari [Yunus] dari [Ibnu Syihab] bahwa [As Sa`ib bin Yazid] dan ['Ubaidullah] telah mengabarkan keduanya, bahwa [Abdurrahman bin 'Abd] dia berkata; dari [Ibnu Wahb bin Abdul Qari] dia berkata; saya mendengar [Umar bin Khattab] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa tertidur dari bacaan wiridnya atau sesuatu yang di biasakannya di waktu malam, kemudian dia membaca antara shalat fajar (subuh) dan shalat Dluhur, maka akan di catat (pahala) baginya seakan-akan dia membaca di malam hari.\""},"1104":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ رَجُلٍ عِنْدَهُ رَضِيٍّ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ امْرِئٍ تَكُونُ لَهُ صَلَاةٌ بِلَيْلٍ يَغْلِبُهُ عَلَيْهَا نَوْمٌ إِلَّا كُتِبَ لَهُ أَجْرُ صَلَاتِهِ وَكَانَ نَوْمُهُ عَلَيْهِ صَدَقَةً","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Muhammad bin Al Munkadir] dari [Sa'id bin Jubair] dari [seseorang] yang ia ridlai, bahwa [Aisyah] isteri Nabi shallallahu 'alaihi wasallam telah mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang yang terbiasa mengerjakan shalat malam, kemudian dia tertidur (tidak mengerjakannya) melainkan akan di catat baginya pahala shalat malam, dan tidurnya di anggap sedekah baginya.\""},"1105":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ وَعَنْ أَبِي عَبْدِ اللَّهِ الْأَغَرِّ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَنْزِلُ رَبُّنَا تَبَارَكَ وَتَعَالَى كُلَّ لَيْلَةٍ إِلَى سَمَاءِ الدُّنْيَا حِينَ يَبْقَى ثُلُثُ اللَّيْلِ الْآخِرُ فَيَقُولُ مَنْ يَدْعُونِي فَأَسْتَجِيبَ لَهُ مَنْ يَسْأَلُنِي فَأُعْطِيَهُ مَنْ يَسْتَغْفِرُنِي فَأَغْفِرَ لَهُ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari [Abu Salamah bin Abdurrahman] dan dari [Abdullah Al Agharru] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Rabb kita Tabaraka wa Ta'ala turun di setiap malamnya ke langit dunia pada sepertiga malam terakhir, lalu Dia berfirman: \"barangsiapa berdo'a kepada-Ku, niscaya Aku kabulkan, barangsiapa memohon kepada-Ku, niscaya Aku akan memberinya, barangsiapa memohon ampunan kepada-Ku, niscaya Aku akan mengampuninya.\""},"1106":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ يَزِيدَ الْكُوفِيُّ حَدَّثَنَا حَفْصٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْإِنْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيُوقِظُهُ اللَّهُ عَزَّ وَجَلَّ بِاللَّيْلِ فَمَا يَجِيءُ السَّحَرُ حَتَّى يَفْرُغَ مِنْ حِزْبِهِ","id":"Telah menceritakan kepada kami [Husain bin Yazid Al Kufi] telah menceritakan kepada kami [Hafsh] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam biasa di bangunkan oleh Allah Azza wa Jalla di setiap malam, dan tidaklah datang waktu sahur melainkan beliau telah menyelesaikan (bacaan) wiridnya.\""},"1107":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى حَدَّثَنَا أَبُو الْأَحْوَصِ ح و حَدَّثَنَا هَنَّادٌ عَنْ أَبِي الْأَحْوَصِ وَهَذَا حَدِيثُ إِبْرَاهِيمَ عَنْ أَشْعَثَ عَنْ أَبِيهِ عَنْ مَسْرُوقٍ قَالَسَأَلْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لَهَا أَيَّ حِينٍ كَانَ يُصَلِّي قَالَتْ كَانَ إِذَا سَمِعَ الصُّرَاخَ قَامَ فَصَلَّى","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah menceritakan kepada kami [Abu Al Ahwash]. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Hannad] dari [Abu Al Ahwash], dan ini adalah hadits Ibrahim dari [Asy'ats] dari [ayahnya] dari [Masruq] dia berkata; saya bertanya kepada [Aisyah] radliallahu 'anha tentang shalatnya Rasulullah shallallahu 'alaihi wasallam, kataku kepadanya; \"Waktu kapankah beliau biasa mengerjakan shalat (malam)?\" jawabnya; \"Apabila beliau mendengar suara kokok ayam, beliau bangun lalu shalat.\""},"1108":{"ar":"حَدَّثَنَا أَبُو تَوْبَةَ عَنْ إِبْرَاهِيمَ بْنِ سَعْدٍ عَنْ أَبِيهِ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ قَالَتْمَا أَلْفَاهُ السَّحَرُ عِنْدِي إِلَّا نَائِمًا تَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Taubah] dari [Ibrahim bin Sa'd] dari [ayahnya] dari [Abu Salamah] dari [Aisyah] dia berkata; \"Tidaklah datang waktu sahur, melainkan beliau tidur berada di dekatku.\" Maksudnya Nabi shallallahu 'alaihi wasallam. "},"1109":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ الدُّؤَلِيِّ عَنْ عَبْدِ الْعَزِيزِ ابْنِ أَخِي حُذَيْفَةَ عَنْ حُذَيْفَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا حَزَبَهُ أَمْرٌ صَلَّى","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Yahya bin Zakariya] dari [Ikrimah bin 'Ammar] dari [Muhammad bin Abdullah Ad Du`ali] dari [Abdul Aziz keponakan Hudzaifah] dari [Hudzaifah] dia berkata; \"Apabila Nabi shallallahu 'alaihi wasallam tertekan oleh suatu urusan, beliau mengerjakan shalat.\""},"1110":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْهِقْلُ بْنُ زِيَادٍ السَّكْسَكِيُّ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ قَالَ سَمِعْتُ رَبِيعَةَ بْنَ كَعْبٍ الْأَسْلَمِيَّ يَقُولُكُنْتُ أَبِيتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آتِيهِ بِوَضُوئِهِ وَبِحَاجَتِهِ فَقَالَ سَلْنِي فَقُلْتُ مُرَافَقَتَكَ فِي الْجَنَّةِ قَالَ أَوَ غَيْرَ ذَلِكَ قُلْتُ هُوَ ذَاكَ قَالَ فَأَعِنِّي عَلَى نَفْسِكَ بِكَثْرَةِ السُّجُودِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Al Hiql bin Ziyad As Saksaki] telah menceritakan kepada kami [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dia berkata; saya mendengar [Rabi'ah bin Ka'b Al Aslami] berkata; \"Aku bermalam bersama Rasulullah shallallahu 'alaihi wasallam, aku juga pernah mengambilkan air wudlu' dan air untuk buang hajat untuk beliau. Lalu beliau bersabda: \"Mohonlah kepadaku.\" Kataku; 'Aku memohon dapat bersama anda di surga'. Beliau menegaskan, 'Adakah yang lain? 'Aku menjawab, 'Itu saja'. Beliau bersabda: 'Bantu aku untuk dirimu sendiri dengan memperbanyak sujud'.\""},"1111":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍفِي هَذِهِ الْآيَةِ{ تَتَجَافَى جُنُوبُهُمْ عَنْ الْمَضَاجِعِ يَدْعُونَ رَبَّهُمْ خَوْفًا وَطَمَعًا وَمِمَّا رَزَقْنَاهُمْ يُنْفِقُونَ }قَالَ كَانُوا يَتَيَقَّظُونَ مَا بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ يُصَلُّونَوَكَانَ الْحَسَنُ يَقُولُ قِيَامُ اللَّيْلِ","id":"Telah menceritakan kepada kami [Abu Kamil] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas bin Malik] mengenai ayat ini; \"Lambung mereka jauh dari tempat tidurnya, sedang mereka berdo'a kepada Rabbnya dengan rasa takut dan penuh harap, dan mereka menafkahkan sebagian dari rizki yang Kami berikan kepada mereka.\" (QS As Sajadah; 16), kata Anas; \"Mereka biasa bangun antara waktu Maghrib hingga Isya' kemudian mereka mengerjakan shalat.\" Sedangkan Al Hasan mengatakan; \"Maksudnya adalah Qiyamul lail.\""},"1112":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَابْنُ أَبِي عَدِيٍّ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسٍفِي قَوْلِهِ عَزَّ وَجَلَّ{ كَانُوا قَلِيلًا مِنْ اللَّيْلِ مَا يَهْجَعُونَ }قَالَ كَانُوا يُصَلُّونَ فِيمَا بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ زَادَ فِي حَدِيثِ يَحْيَى وَكَذَلِكَ تَتَجَافَى جُنُوبُهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Yahya bin Sa'id] dan [Ibnu Abu 'Adi] dari [Sa'id] dari [Qatadah] dari [Anas] mengenai firman Allah Azza wa Jalla; \"Mereka sedikit sekali tidur di waktu malam\" (QS Adz Dzariyat; 17), kata Anas; \"Mereka biasa mengerjakan shalat antara waktu Maghrib dan Isya'.\" Dalam haditsnya Yahya di tambahkan; \"Dan demikian pula lambung mereka (dari tempat tidurnya).\""},"1113":{"ar":"حَدَّثَنَا الرَّبِيعُ بْنُ نَافِعٍ أَبُو تَوْبَةَ حَدَّثَنَا سُلَيْمَانُ بْنُ حَيَّانَ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ أَحَدُكُمْ مِنْ اللَّيْلِ فَلْيُصَلِّ رَكْعَتَيْنِ خَفِيفَتَيْنِحَدَّثَنَا مَخْلَدُ بْنُ خَالِدٍ حَدَّثَنَا إِبْرَاهِيمُ يَعْنِي ابْنَ خَالِدٍ عَنْ رَبَاحِ بْنِ زَيْدٍ عَنْ مَعْمَرٍ عَنْ أَيُّوبَ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَ إِذَا بِمَعْنَاهُ زَادَ ثُمَّ لِيُطَوِّلْ بَعْدُ مَا شَاءَ قَالَ أَبُو دَاوُد رَوَى هَذَا الْحَدِيثَ حَمَّادُ بْنُ سَلَمَةَ وَزُهَيْرُ بْنُ مُعَاوِيَةَ وَجَمَاعَة عَنْ هِشَامٍ عَنْ مُحَمَّدٍ أَوْقَفُوهُ عَلَى أَبِي هُرَيْرَةَ وَكَذَلِكَ رَوَاهُ أَيُّوبُ وَابْنُ عَوْنٍ أَوْقَفُوهُ عَلَى أَبِي هُرَيْرَةَ وَرَوَاهُ ابْنُ عَوْنٍ عَنْ مُحَمَّدٍ قَالَ فِيهِمَا تَجَوُّزٌ","id":"Telah menceritakan kepada kami [Ar Rabi' bin Nafi' Abu Taubah] telah menceritakan kepada kami [Sulaiman bin Hayyan] dari [Hisyam bin Hasan] dari [Ibnu Sirin] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian bangun malam, hendaknya ia mengerjakan shalat dua raka'at yang ringan.\" Telah menceritakan kepada kami [Makhlad bin Khalid] telah menceritakan kepada kami [Ibrahim yaitu Ibnu Khalid] dari [Rabah bin Zaid] dari [Ma'mar] dari [Ayyub] dari [Ibnu Sirin] dari [Abu Hurairah] perawi berkata; makna haditsnya sama namun ada tambahan \"kemudian memanjangkan sesuai dengan yang dia kehendaki\". Abu Daud berkata; telah meriwayatkan hadits ini [Hammad bin Salamah] dan [Zuhair bin Mu'awiyyah] dan jama'ah dari [Hisyam] dari [Muhammad] yang di mauqufkan kepada [Abu Hurairah], demikian juga yang di riwayatkan oleh [Ayyub] dan [Ibnu 'Aun] yang di mauqufkan kepada [Abu Hurairah]. Dan di riwayatkan oleh [Ibnu Aun] dari [Muhammad] katanya; \"Dalam dua raka'at tersebut di persingkat.\""},"1114":{"ar":"حَدَّثَنَا ابْنُ حَنْبَلٍ يَعْنِي أَحْمَدَ حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي عُثْمَانُ بْنُ أَبِي سُلَيْمَانَ عَنْ عَلِيٍّ الْأَزْدِيِّ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ حُبْشِيٍّ الْخَثْعَمِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ أَيُّ الْأَعْمَالِ أَفْضَلُ قَالَ طُولُ الْقِيَامِ","id":"Telah menceritakan kepada kami [Ibnu Hanbal yaitu Ahmad] telah menceritakan kepada kami [Hajjaj] dia berkata; [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Utsman bin Abu Sulaiman] dari [Ali Al Azdi] dari ['Ubaid bin 'Umair] dari [Abdullah bin Habsyi Al Khasy'ami] bahwa Rasulullah shallallahu 'alaihi wasallam pernah di tanya; \"Amalan apakah yang paling utama?\" beliau menjawab; \"Lama berdiri (dalam shalat).\""},"1115":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ وَعَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَجُلًا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَلَاةِ اللَّيْلِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ اللَّيْلِ مَثْنَى مَثْنَى فَإِذَا خَشِيَ أَحَدُكُمْ الصُّبْحَ صَلَّى رَكْعَةً وَاحِدَةً تُوتِرُ لَهُ مَا قَدْ صَلَّى","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Nafi'] dan [Abdullah bin Dinar] dari [Abdullah bin Umar] bahwa seorang laki-laki bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai shalat malam, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat malam dua raka'at-dua raka'at, apabila salah seorang dari kalian khawatir datangnya waktu subuh, hendaknya ia shalat satu raka'at sebagai witir atas shalat yang telah di kerjakan.\""},"1116":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ الْوَرَكَانِيُّ حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو مَوْلَى الْمُطَّلِبِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَتْ قِرَاءَةُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى قَدْرِ مَا يَسْمَعُهُ مَنْ فِي الْحُجْرَةِ وَهُوَ فِي الْبَيْتِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far Al Warakani] telah menceritakan kepada kami [Ibnu Abu Az Zinad] dari ['Amru bin Abu 'Amru] bekas budak Al Mutthalib, dari ['Ikrimah] dari [Ibnu Abbas] dia berkata; \"Bacaan Nabi shallallahu 'alaihi wasallam sekedar dapat di dengar oleh orang yang berada di kamar, sementara beliau berada di rumah.\""},"1117":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَكَّارِ بْنِ الرَّيَّانِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ عِمْرَانَ بْنِ زَائِدَةَ عَنْ أَبِيهِ عَنْ أَبِي خَالِدٍ الْوَالِبِيِّ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ قَالَكَانَتْ قِرَاءَةُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِاللَّيْلِ يَرْفَعُ طَوْرًا وَيَخْفِضُ طَوْرًاقَالَ أَبُو دَاوُد أَبُو خَالِدٍ الْوَالِبِيُّ اسْمُهُ هُرْمُزُ","id":"Telah menceritakan kepada kami [Muhammad bin Bakar bin Ar Rayyan] telah menceritakan kepada kami [Abdullah bin Al Mubarrak] dari [Imran bin Za`idah] dari [ayahnya] dari [Abu Khalid Al Wali] dari [Abu Hurairah] bahwa dia berkata; \"Bacaan Nabi shallallahu 'alaihi wasallam dalam shalat malam, terkadang beliau mengeraskan suara dan terkadang melirihkannya.\" Abu Daud berkata; \"Abu Khalid Al Wali namanya adalah Hurmuz.\""},"1118":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا الْحَسَنُ بْنُ الصَّبَّاحِ حَدَّثَنَا يَحْيَى بْنُ إِسْحَقَ أَخْبَرَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ عَنْ أَبِي قَتَادَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ لَيْلَةً فَإِذَا هُوَ بِأَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ يُصَلِّي يَخْفِضُ مِنْ صَوْتِهِ قَالَ وَمَرَّ بِعُمَرَ بْنِ الْخَطَّابِ وَهُوَ يُصَلِّي رَافِعًا صَوْتَهُ قَالَ فَلَمَّا اجْتَمَعَا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا أَبَا بَكْرٍ مَرَرْتُ بِكَ وَأَنْتَ تُصَلِّي تَخْفِضُ صَوْتَكَ قَالَ قَدْ أَسْمَعْتُ مَنْ نَاجَيْتُ يَا رَسُولَ اللَّهِ قَالَ وَقَالَ لِعُمَرَ مَرَرْتُ بِكَ وَأَنْتَ تُصَلِّي رَافِعًا صَوْتَكَ قَالَ فَقَالَ يَا رَسُولَ اللَّهِ أُوقِظُ الْوَسْنَانَ وَأَطْرُدُ الشَّيْطَانَ زَادَ الْحَسَنُ فِي حَدِيثِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا بَكْرٍ ارْفَعْ مِنْ صَوْتِكَ شَيْئًا وَقَالَ لِعُمَرَ اخْفِضْ مِنْ صَوْتِكَ شَيْئًاحَدَّثَنَا أَبُو حُصَيْنِ بْنُ يَحْيَى الرَّازِيُّ حَدَّثَنَا أَسْبَاطُ بْنُ مُحَمَّدٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذِهِ الْقِصَّةِ لَمْ يَذْكُرْ فَقَالَ لِأَبِي بَكْرٍ ارْفَعْ مِنْ صَوْتِكَ شَيْئًا وَلِعُمَرَ اخْفِضْ شَيْئًا زَادَ وَقَدْ سَمِعْتُكَ يَا بِلَالُ وَأَنْتَ تَقْرَأُ مِنْ هَذِهِ السُّورَةِ وَمِنْ هَذِهِ السُّورَةِ قَالَ كَلَامٌ طَيِّبٌ يَجْمَعُ اللَّهُ تَعَالَى بَعْضَهُ إِلَى بَعْضٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّكُمْ قَدْ أَصَابَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Tsabit Al Bunani] dari Nabi shallallahu 'alaihi wasallam. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Al Hasan bin As Shabah] telah menceritakan kepada kami [Yahya bin Ishaq] telah mengabarkan kepada kami [Hammad bin Salamah] dari [Tsabit Al Bunani] dari [Abdullah bin Rabah] dari [Abu Qatadah] bahwa pada suatu malam Nabi shallallahu 'alaihi wasallam keluar, lalu beliau mendapati Abu Bakar radliallahu 'anhu yang tengah shalat dengan memelankan suaranya.\" Abu Qatadah berkata; \"Dan beliau juga bertemu dengan Umar bin Khattab yang tengah shalat dengan mengangkat suaranya.\" Abu Qatadah melanjutkan; \"Ketika keduanya berkumpul di hadapan Nabi shallallahu 'alaihi wasallam, beliau bersabda kepada Abu Bakar: \"Aku melawatimu ketika kamu sedang shalat dengan memelankan suara.\" Abu Bakar menjawab; \"Suaraku hanya cukup di dengar (Allah) tempatku bermunajat wahai Rasulullah.\" Abu Qatadah berkata; \"Lalu beliau bersabda kepada Umar: \"Sedangkan kamu mengangkat suaramu.\" Abu Qatadah berkata; \"Wahai Rasulullah, supaya saya dapat membangunkan orang tidur dan mengusir syetan.\" Hasan menambahkan dalam haditsnya; \"Lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Abu Bakar, angkatlah suaramu sedikit.\" Dan beliau bersabda kepada Umar: \"Rendahkanlah suaramu sedikit!.\" Telah menceritakan kepada kami [Abu Hushain bin Yahya Ar Razi] telah menceritakan kepada kami [Asbath bin Muhammad] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam dengan kisah seperti ini, namun dia tidak menyebutkan; \"Maka beliau bersabda kepada Abu Bakar: \"Angkatlah suaramu sedikit\" dan bersabda kepada Umar: \"Rendahkanlah suaramu sedikit.\" Dia menambahkan; \"Aku benar-benar telah mendengarmu wahai Bilal, kamu sedang membaca surat ini dan surat ini.\" Bilal menjawab; \"(Al Qur'an) itu adalah kalam (perkataan) yang semuanya baik, di susun oleh Allah Ta'ala dari satu bagian ke bagian yang lainnya.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Kalian semua benar.\""},"1119":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَجُلًا قَامَ مِنْ اللَّيْلِ فَقَرَأَ فَرَفَعَ صَوْتَهُ بِالْقُرْآنِ فَلَمَّا أَصْبَحَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْحَمُ اللَّهُ فُلَانًا كَأَيٍّ مِنْ آيَةٍ أَذْكَرَنِيهَا اللَّيْلَةَ كُنْتُ قَدْ أَسْقَطْتُهَاقَالَ أَبُو دَاوُد رَوَاهُ هَارُونُ النَّحْوِيُّ عَنْ حَمَّادِ بْنِ سَلَمَةَ فِي سُورَةِ آلِ عِمْرَانَ فِي الْحُرُوفِ{ وَكَأَيٍّ مِنْ نَبِيٍّ }","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Hisyam bin 'Urwah] dari [Urwah] dari [Aisyah] radliallahu 'anha, bahwa seorang laki-laki sedang mengerjakan shalat malam, lalu membaca Al Qur'an dengan mengangkat suaranya, keesokan harinya, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semoga Allah merahmati fulan, dia telah mengingatkanku terhadap ayat Al Qur'an yang aku lupa ayat tersebut.\" Abu Daud berkata; \"di riwayatkan pula oleh Harun An Nahwi dari Hammad bin Salamah mengenai surat Ali Imran pada ayat; \"Dan berapa banyak dari para Nabi…\""},"1120":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ قَالَاعْتَكَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ فَسَمِعَهُمْ يَجْهَرُونَ بِالْقِرَاءَةِ فَكَشَفَ السِّتْرَ وَقَالَ أَلَا إِنَّ كُلَّكُمْ مُنَاجٍ رَبَّهُ فَلَا يُؤْذِيَنَّ بَعْضُكُمْ بَعْضًا وَلَا يَرْفَعْ بَعْضُكُمْ عَلَى بَعْضٍ فِي الْقِرَاءَةِ أَوْ قَالَ فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Isma'il bin Umayyah] dari [Abu Salamah] dari [Abu Sa'id] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam beri'tikaf di Masjid, lalu beliau menedengar mereka (para sahabat) mengeraskan bacaan (Al Qur'an) mereka. kemudian beliau membuka tirai sambil bersabda: \"Ketahuilah, sesungguhnya kalian tengah berdialog dengan Rabb, oleh karena itu janganlah sebagian yang satu mengganggu sebagian yang lain dan jangan pula sebagian yang satu mengeraskan terhadap sebagian yang lain di dalam membaca (Al Qur'an) atau dalam shalatnya.\""},"1121":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ بَحِيرِ بْنِ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ كَثِيرِ بْنِ مُرَّةَ الْحَضْرَمِيِّ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجَاهِرُ بِالْقُرْآنِ كَالْجَاهِرِ بِالصَّدَقَةِ وَالْمُسِرُّ بِالْقُرْآنِ كَالْمُسِرِّ بِالصَّدَقَةِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Isma'il bin Ayasy] dari [Bahir bin Sa'd] daru [Khalid bin Ma'dan] dari [Katsir bin Murah Al Hadlrami] dari ['Uqbah bin 'Amir Al Juhani] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang mengeraskan bacaan Al Qur'an bagaikan orang yang menampakkan sedekah, dan orang yang memelankan bacaan Al Qur'an ibarat orang yang bersekah dengan sembunyi-sembunyi.\""},"1122":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي مِنْ اللَّيْلِ إِحْدَى عَشْرَةَ رَكْعَةً يُوتِرُ مِنْهَا بِوَاحِدَةٍ فَإِذَا فَرَغَ مِنْهَا اضْطَجَعَ عَلَى شِقِّهِ الْأَيْمَنِ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dair ['Urwah bin Az Zubair] dari [Aisyah isteri Nabi shallallahu 'alaihi wasallam] bahwa Rasulullah shallallahu 'alaihi wasallam biasa mengerjakan shalat malam sebelas raka'at termasuk witir satu raka'at, apabila beliau selesai dari shalat malam, beliau berbaring di atas rusuk kanannya.\""},"1123":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ وَنَصْرُ بْنُ عَاصِمٍ وَهَذَا لَفْظُهُ قَالَا حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا الْأَوْزَاعِيُّ وَقَالَ نَصْرٌ عَنْ ابْنِ أَبِي ذِئْبٍ وَالْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِيمَا بَيْنَ أَنْ يَفْرُغَ مِنْ صَلَاةِ الْعِشَاءِ إِلَى أَنْ يَنْصَدِعَ الْفَجْرُ إِحْدَى عَشْرَةَ رَكْعَةً يُسَلِّمُ مِنْ كُلِّ ثِنْتَيْنِ وَيُوتِرُ بِوَاحِدَةٍ وَيَمْكُثُ فِي سُجُودِهِ قَدْرَ مَا يَقْرَأُ أَحَدُكُمْ خَمْسِينَ آيَةً قَبْلَ أَنْ يَرْفَعَ رَأْسَهُ فَإِذَا سَكَتَ الْمُؤَذِّنُ بِالْأُولَى مِنْ صَلَاةِ الْفَجْرِ قَامَ فَرَكَعَ رَكْعَتَيْنِ خَفِيفَتَيْنِ ثُمَّ اضْطَجَعَ عَلَى شِقِّهِ الْأَيْمَنِ حَتَّى يَأْتِيَهُ الْمُؤَذِّنُحَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي ابْنُ أَبِي ذِئْبٍ وَعَمْرُو بْنُ الْحَارِثِ وَيُونُسُ بْنُ يَزِيدَ أَنَّ ابْنَ شِهَابٍ أَخْبَرَهُمْ بِإِسْنَادِهِ وَمَعْنَاهُ قَالَ وَيُوتِرُ بِوَاحِدَةٍ وَيَسْجُدُ سَجْدَةً قَدْرَ مَا يَقْرَأُ أَحَدُكُمْ خَمْسِينَ آيَةً قَبْلَ أَنْ يَرْفَعَ رَأْسَهُ فَإِذَا سَكَتَ الْمُؤَذِّنُ مِنْ صَلَاةِ الْفَجْرِ وَتَبَيَّنَ لَهُ الْفَجْرُ وَسَاقَ مَعْنَاهُ قَالَ وَبَعْضُهُمْ يَزِيدُ عَلَى بَعْضٍ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim] dan [Nashr bin 'Ashim] dan ini lafadznya Nashr, keduanya berkata; telah menceritakan kepada kami [Al Walid] telah menceritakan kepada kami [Al Auza'i]. Nashr mengatakan; dari [Ibnu Abu Dzi`b] dan [Auza'i] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] radliallahu 'anha, dia berkata; \"Rasulullah shallallahu 'alaihi wasallam biasa mengerjakan shalat malam di antara setelah shalat Isya' hingga terbit fajar. Beliau biasa mengerjakan sebelas raka'at, beliau salam setiap satu raka'at, dan witir satu raka'at. lama beliau diam dalam sujudnya sekitar salah seorang dari kalian membaca lima puluh ayat, yaitu sebelum beliau mengangkat kepala. Apabila Mu'adzin selesai mengumandangkan adzan yang pertama untuk shalat subuh, beliau berdiri untuk mengerjakan shalat dua raka'at secara singkat, kemudian beliau berbaring di atas rusuk kanannya, sehingga Mu'adzin mengumandangkan adzan (kedua).\" Telah menceritakan kepada kami [Sulaiman bin Daud Al Mahri] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Ibnu Abu Dzi`b], ['Amru bin Al Harits] dan [Yunus bin Yazid], bahwa [Ibnu Syihab] telah mengabarkan kepada mereka, dengan sanad dan maksud yang sama, dia berkata; \"…Beliau witir satu raka'at, dan bersujud sekali (sujud terakhir) yang lamanya sekitar seseorang dari kalian membaca lima puluh ayat, yaitu sebelum beliau mengangkat kepalanya. Dan apabila seorang Mu'adzin selesai mengumandangkan adzan untuk shalat subuh, dan fajar telah nampak…\" kemudian dia melanjutkan maksud hadits tersebut.\" Perawi berkata; \"Dan sebagian dari mereka saling melengkapi atas sebagian yang lain.\""},"1124":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِاللَّيْلِ ثَلَاثَ عَشْرَةَ رَكْعَةً ثُمَّ يُصَلِّي إِذَا سَمِعَ النِّدَاءَ بِالصُّبْحِ رَكْعَتَيْنِ خَفِيفَتَيْنِ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam biasa mengerjakan shalat malam tiga belas raka'at, kemudian beliau mengerjakan dua raka'at (sunnah fajar) secara singkat setelah mendengar adzan shalat shubuh.\""},"1125":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ وَمُسْلِمُ بْنُ إِبْرَاهِيمَ قَالَا حَدَّثَنَا أَبَانُ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي مِنْ اللَّيْلِ ثَلَاثَ عَشْرَةَ رَكْعَةً كَانَ يُصَلِّي ثَمَانِيَ رَكَعَاتٍ وَيُوتِرُ بِرَكْعَةٍ ثُمَّ يُصَلِّي قَالَ مُسْلِمٌ بَعْدَ الْوِتْرِ ثُمَّ اتَّفَقَا رَكْعَتَيْنِ وَهُوَ قَاعِدٌ فَإِذَا أَرَادَ أَنْ يَرْكَعَ قَامَ فَرَكَعَ وَيُصَلِّي بَيْنَ أَذَانِ الْفَجْرِ وَالْإِقَامَةِ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] dan [Muslim bin Ibrahim] keduanya berkata; telah menceritakan kepada kami [Aban] dari [Yahya] dari [Abu Salamah] dari [Aisyah] bahwa Nabi Allah shallallahu 'alaihi wasallam terkadang mengerjakan shalat malam tiga belas raka'at, dan terkadang beliau mengerjakan delapan belas raka'at, lalu witir satu raka'at, setelah itu beliau mengerjakan shalat (sunnah fajar -pent) -Muslim berkata; \"Yaitu setelah witir\"- kemudian hadits Muslim dan Musa sepakat pada kalimat- dua raka'at, beliau mengerjakannya sambil duduk. Apabila hendak ruku', beliau berdiri lalu ruku'. Beliau juga mengerjakan shalat dua raka'at antara adzan dan iqamah.\""},"1126":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ أَنَّهُ أَخْبَرَهُأَنَّهُ سَأَلَ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ كَانَتْ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَمَضَانَ فَقَالَتْ مَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَزِيدُ فِي رَمَضَانَ وَلَا فِي غَيْرِهِ عَلَى إِحْدَى عَشْرَةَ رَكْعَةً يُصَلِّي أَرْبَعًا فَلَا تَسْأَلْ عَنْ حُسْنِهِنَّ وَطُولِهِنَّ ثُمَّ يُصَلِّي أَرْبَعًا فَلَا تَسْأَلْ عَنْ حُسْنِهِنَّ وَطُولِهِنَّ ثُمَّ يُصَلِّي ثَلَاثًا قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا فَقُلْتُ يَا رَسُولَ اللَّهِ أَتَنَامُ قَبْلَ أَنْ تُوتِرَ قَالَ يَا عَائِشَةُ إِنَّ عَيْنَيَّ تَنَامَانِ وَلَا يَنَامُ قَلْبِي","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Salamah bin Abdurrahman] bahwa dia mengabarkan kepadanya bahwa dirinya pernah bertanya kepada [Aisyah isteri Nabi] shallallahu 'alaihi wasallam; \"Bagaimanakah shalatnya Rasulullah shallallahu 'alaihi wasallam di bulan Ramadhan?\" Aisyah menjawab; \"Shalat Rasulullah shallallahu 'alaihi wasallam tidak pernah lebih dari sebelas raka'at, baik pada bulan Ramadhan atau di selain bulan Ramadhan, yaitu beliau mengerjakan empat raka'at, jangan di tanya bagaimana bagus dan panjangnya, setelah itu beliau shalat empat raka'at, dan jangan di tanya bagaimana kwalitas bagus dan panjangnya, kemudian beliau shalat tiga raka'at.\" Aisyah radliallahu 'anha melanjutkan; aku bertanya; \"Wahai Rasulullah, apakah anda tidur sebelum berwitir?\" beliau menjawab: \"Wahai Aisyah, sesungguhnya kedua mataku tertidur, namun hatiku tetap terjaga.\""},"1127":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُسَيْنٍ الدِّرْهَمِيُّ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ بَهْزِ بْنِ حَكِيمٍ حَدَّثَنَا زُرَارَةُ بْنُ أَوْفَىأَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا سُئِلَتْ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جَوْفِ اللَّيْلِ فَقَالَتْ كَانَ يُصَلِّي الْعِشَاءَ فِي جَمَاعَةٍ ثُمَّ يَرْجِعُ إِلَى أَهْلِهِ فَيَرْكَعُ أَرْبَعَ رَكَعَاتٍ ثُمَّ يَأْوِي إِلَى فِرَاشِهِ وَيَنَامُ وَطَهُورُهُ مُغَطًّى عِنْدَ رَأْسِهِ وَسِوَاكُهُ مَوْضُوعٌ حَتَّى يَبْعَثَهُ اللَّهُ سَاعَتَهُ الَّتِي يَبْعَثُهُ مِنْ اللَّيْلِ فَيَتَسَوَّكُ وَيُسْبِغُ الْوُضُوءَ ثُمَّ يَقُومُ إِلَى مُصَلَّاهُ فَيُصَلِّي ثَمَانِيَ رَكَعَاتٍ يَقْرَأُ فِيهِنَّ بِأُمِّ الْكِتَابِ وَسُورَةٍ مِنْ الْقُرْآنِ وَمَا شَاءَ اللَّهُ وَلَا يَقْعُدُ فِي شَيْءٍ مِنْهَا حَتَّى يَقْعُدَ فِي الثَّامِنَةِ وَلَا يُسَلِّمُ وَيَقْرَأُ فِي التَّاسِعَةِ ثُمَّ يَقْعُدُ فَيَدْعُو بِمَا شَاءَ اللَّهُ أَنْ يَدْعُوَهُ وَيَسْأَلَهُ وَيَرْغَ��َ إِلَيْهِ وَيُسَلِّمُ تَسْلِيمَةً وَاحِدَةً شَدِيدَةً يَكَادُ يُوقِظُ أَهْلَ الْبَيْتِ مِنْ شِدَّةِ تَسْلِيمِهِ ثُمَّ يَقْرَأُ وَهُوَ قَاعِدٌ بِأُمِّ الْكِتَابِ وَيَرْكَعُ وَهُوَ قَاعِدٌ ثُمَّ يَقْرَأُ الثَّانِيَةَ فَيَرْكَعُ وَيَسْجُدُ وَهُوَ قَاعِدٌ ثُمَّ يَدْعُو مَا شَاءَ اللَّهُ أَنْ يَدْعُوَ ثُمَّ يُسَلِّمُ وَيَنْصَرِفُ فَلَمْ تَزَلْ تِلْكَ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى بَدَّنَ فَنَقَّصَ مِنْ التِّسْعِ ثِنْتَيْنِ فَجَعَلَهَا إِلَى السِّتِّ وَالسَّبْعِ وَرَكْعَتَيْهِ وَهُوَ قَاعِدٌ حَتَّى قُبِضَ عَلَى ذَلِكَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا بَهْزُ بْنُ حَكِيمٍ فَذَكَرَ هَذَا الْحَدِيثَ بِإِسْنَادِهِ قَالَ يُصَلِّي الْعِشَاءَ ثُمَّ يَأْوِي إِلَى فِرَاشِهِ لَمْ يَذْكُرْ الْأَرْبَعَ رَكَعَاتٍ وَسَاقَ الْحَدِيثَ وَقَالَ فِيهِ فَيُصَلِّي ثَمَانِيَ رَكَعَاتٍ يُسَوِّي بَيْنَهُنَّ فِي الْقِرَاءَةِ وَالرُّكُوعِ وَالسُّجُودِ وَلَا يَجْلِسُ فِي شَيْءٍ مِنْهُنَّ إِلَّا فِي الثَّامِنَةِ فَإِنَّهُ كَانَ يَجْلِسُ ثُمَّ يَقُومُ وَلَا يُسَلِّمُ فِيهِ فَيُصَلِّي رَكْعَةً يُوتِرُ بِهَا ثُمَّ يُسَلِّمُ تَسْلِيمَةً يَرْفَعُ بِهَا صَوْتَهُ حَتَّى يُوقِظَنَا ثُمَّ سَاقَ مَعْنَاهُ حَدَّثَنَا عُمَرُ بْنُ عُثْمَانَ حَدَّثَنَا مَرْوَانُ يَعْنِي ابْنَ مُعَاوِيَةَ عَنْ بَهْزٍ حَدَّثَنَا زُرَارَةُ بْنُ أَوْفَى عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ أَنَّهَا سُئِلَتْ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ كَانَ يُصَلِّي بِالنَّاسِ الْعِشَاءَ ثُمَّ يَرْجِعُ إِلَى أَهْلِهِ فَيُصَلِّي أَرْبَعًا ثُمَّ يَأْوِي إِلَى فِرَاشِهِ ثُمَّ سَاقَ الْحَدِيثَ بِطُولِهِ وَلَمْ يَذْكُرْ يُسَوِّي بَيْنَهُنَّ فِي الْقِرَاءَةِ وَالرُّكُوعِ وَالسُّجُودِ وَلَمْ يَذْكُرْ فِي التَّسْلِيمِ حَتَّى يُوقِظَنَا حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ بَهْزِ بْنِ حَكِيمٍ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا بِهَذَا الْحَدِيثِ وَلَيْسَ فِي تَمَامِ حَدِيثِهِمْ","id":"Telah menceritakan kepada kami [Ali bin Husain Ad Dirhami] telah menceritakan kepada kami [Ibnu Abu Adi] dari [Bahz bin Hakim] telah menceritakan kepada kami [Zurarah bin Aufa] bahwa [Aisyah] radliallahu 'anha pernah di tanya mengenai shalatnya Rasulullah shallallahu 'alaihi wasallam di pertengahan malam, dia menjawab; \"Beliau biasa mengerjakan shalat Isya' dengan berjama'ah, kemudian kembali kepada keluarganya dan mengerjakan shalat (sunnah) empat raka'at, setelah itu beliau pergi ke tempat tidurnya, lalu beliau tidur. Sedangkan tempat air wudlunya tertutup berada di atas kepala beliau dan siwaknya juga di letakkan di situ, sehingga Allah membangunkan beliau pada saatnya yaitu pada malam hari, kemudian beliau bersiwak dan menyempurnakan wudlu'nya, setelah itu beliau berdiri di tempat shalatnya, lalu shalat delapan raka'at, dalam raka'at tersebut beliau membaca Al Fatihah dan surat Al Qur'an serta apa saja yang Allah kehendaki, beliau tidak duduk dalam raka'at tersebut kecuali di raka'at ke delapan, dan beliau juga tidak salam. Beliau membaca (Al Fatihah dan surat Al Qur'an) pada rakaat ke sembilan, lalu beliau duduk dan berdo'a dengan do'a yang di kehendaki Allah, beliau memohon kepada-Nya dan beliau berdo'a dengan penuh harap. Setelah itu beliau mengucapkan satu kali salam dengan keras, hingga hampir saja membangunkan keluarga beliau lantaran kerasnya salam beliau, setelah itu beliau membaca (Al Fatihah dan surat Al Qur'an) dalam keadaan duduk dan ruku' sambil duduk pula, lalu beliau membaca lagi yang kedua kalinya, lalu ruku' dan sujud sembari duduk, kemudian beliau berdo'a sesuai yang di kehendaki Allah, setelah itu beliau salam dan beranjak (meninggalkan tempat shalat). Rasulullah shallallahu 'alaihi wasallam masih tetap mengerjakan shalat seperti itu hingga beliau menjadi gemuk, lalu beliau mengurangi dua rakaat dari sembilan raka'at, hingga menjadi enam hingga tujuh raka'at di tambah dua raka'at yang beliau kerjakan dengan duduk, sampai beliau shallallahu 'alaihi wasallam meninggal dunia.\" Telah menceritakan kepada kami [Harun bin Abdullah] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Bahz bin Hakim] kemudian dia menyebutkan hadits ini dengan sanadnya, katanya; \"Selepas shalat Isya', beliau pergi ke tempat tidurnya…\" tidak menyebutkan \"empat raka'at\" lalu dia menyebutkan hadits ini, dan dalam hadits tersebut dia berkata; \"Kemudian beliau shalat delapan raka'at, beliau menyamakan (lamanya) antara ketika membaca (surat Al Qur'an), ruku' dan sujud. Beliau tidak duduk dalam raka'at tersebut kecuali pada raka'at ke delapan. (dalam raka'at ke delapan) biasanya beliau duduk lalu bediri, tidak salam, lalu beliau melanjutkan satu raka'at sebagai witirnya, setelah itu beliau salam dengan mengeraskan suaranya hingga membangunkan kami semua.\" Kemudian dia melanjutkan maksud hadits tersebut. Telah menceritakan kepada kami [Umar bin Utsman] telah menceritakan kepada kami [Marwan yaitu Ibnu Mu'awiyah] dari [Bahz] telah menceritakan kepada kami [Zurarah bin Aufa] dari [Aisyah Ummul Mukminin] bahwa dia pernah di tanya mengenai shalat (malam) nya Rasulullah shallallahu 'alaihi wasallam, Aisyah menjawab; \"Beliau biasa mengerjakan shalat Isya' bersama orang-orang (berjama'ah), kemudian beliau pulang ke keluarganya, lalu shalat (sunnah) empat raka'at. setelah itu beliau pergi ke tempat tidurnya…\" kemudian perawi melanjutkan hadits panjang tersebut, namun dia tidak menyebutkan \"Beliau menyamakan (lamanya) antara membaca (surat Al Quran), ruku' dan sujudnya.\" Dan tidak pula menyebutkan \"Lalu beliau mengucapkan salam sehingga membangunkan kami.\" Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad yaitu Ibnu Salamah] dari [Bahz bin Hakim] dari [Zurarah bin Aufa] dari [Sa'd bin Hisyam] dari [Aisyah radliallahu 'anha] seperti hadits tersebut, namun hadits mereka tidak sesempurna (hadits yang pertama).\""},"1128":{"ar":"حَدَّثَنَا مُوسَى يَعْنِي ابْنَ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي مِنْ اللَّيْلِ ثَلَاثَ عَشْرَةَ رَكْعَةً يُوتِرُ بِتِسْعٍ أَوْ كَمَا قَالَتْ وَيُصَلِّي رَكْعَتَيْنِ وَهُوَ جَالِسٌ وَرَكْعَتَيْ الْفَجْرِ بَيْنَ الْأَذَانِ وَالْإِقَامَةِ","id":"Telah menceritakan kepada kami [Musa yaitu Ibnu Isma'il] telah menceritakan kepada kami [Hammad yaitu Ibnu Salamah] dari [Muhammad bin 'Amru] dari [Abu Salamah bin Abdurrahman] dari [Aisyah] radliallahu 'anha bahwa Rasulullah shallallahu 'alaihi wasallam biasa mengerjakan shalat malam tiga belas raka'at, beserta witirnya sembilan raka'at atau sebagaimana di katakan oleh Aisyah, dan beliau mengerjakan dua raka'at dengan duduk, dan dua raka'at fajar antara adzan dan Iqamah.\""},"1129":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا حُصَيْنٌ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ ح و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ حُصَيْنٍ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ مُحَمَّدِ بْنِ عَلِيِّ بْنِ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍأَنَّهُ رَقَدَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَآهُ اسْتَيْقَظَ فَتَسَوَّكَ وَتَوَضَّأَ وَهُوَ يَقُولُ{ إِنَّ فِي خَلْقِ السَّمَوَاتِ وَالْأَرْضِ }حَتَّى خَتَمَ السُّورَةَ ثُمَّ قَامَ فَصَلَّى رَكْعَتَيْنِ أَطَالَ فِيهِمَا الْقِيَامَ وَالرُّكُوعَ وَالسُّجُودَ ثُمَّ انْصَرَفَ فَنَامَ حَتَّى نَفَخَ ثُمَّ فَعَلَ ذَلِكَ ثَلَاثَ مَرَّاتٍ بِسِتِّ رَكَعَاتٍ كُلُّ ذَلِكَ يَسْتَاكُ ثُمَّ يَتَوَضَّأُ وَيَقْرَأُ هَؤُلَاءِ الْآيَاتِ ثُمَّ أَوْتَرَ قَالَ عُثْمَانُ بِثَلَاثِ رَكَعَاتٍ فَأَتَاهُ الْمُؤَذِّنُ فَخَرَجَ إِلَى الصَّلَاةِ وَقَالَ ابْنُ عِيسَى ثُمَّ أَوْتَرَ فَأَتَاهُ بِلَالٌ فَآذَنَهُ بِالصَّلَاةِ حِينَ طَلَعَ الْفَجْرُ فَصَلَّى رَكْعَتَيْ الْفَجْرِ ثُمَّ خَرَجَ إِلَى الصَّلَاةِ ثُمَّ اتَّفَقَا وَهُوَ يَقُولُ اللَّهُمَّ اجْعَلْ فِي قَلْبِي نُورًا وَاجْعَلْ فِي لِسَانِي نُورًا وَاجْعَلْ فِي سَمْعِي نُورًا وَاجْعَلْ فِي بَصَرِي نُورًا وَاجْعَلْ خَلْفِي نُورًا وَأَمَامِي نُورًا وَاجْعَلْ مِنْ فَوْقِي نُورًا وَمِنْ تَحْتِي نُورًا اللَّهُمَّ وَأَعْظِمْ لِي نُورًاحَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ عَنْ خَالِدٍ عَنْ حُصَيْنٍ نَحْوَهُ قَالَ وَأَعْظِمْ لِي نُورًا قَالَ أَبُو دَاوُد وَكَذَلِكَ قَالَ أَبُو خَالِدٍ الدَّالَانِيُّ عَنْ حَبِيبٍ فِي هَذَا وَكَذَلِكَ قَالَ فِي هَذَا الْحَدِيثِ وَقَالَ سَلَمَةُ بْنُ كُهَيْلٍ عَنْ أَبِي رِشْدِينَ عَنْ ابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Hushain] dari [Habib bin Abu Tsabit]. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Hushain] dari [Habib bin Abu Tsabit] dari [Muhammad bin Ali bin Abdullah bin 'Abbas] dari [ayahnya] dari [Ibnu Abbas] bahwa dia pernah tidur di samping Nabi shallallahu 'alaihi wasallam, maka dia melihat beliau bangun (malam) lalu bersiwak dan berwudlu', lalu beliau mengucapkan; \"Sesungguhnya dalam penciptaan langit dan bumi…\" hingga akhir ayat, setelah itu mengerjakan shalat dua raka'at, dalam dua raka'at tersebut, beliau panjangkan berdirinya, ruku'nya dan sujudnya. Selesai shalat beliau tidur hingga mendengkur. Beliau kerjakan hal itu hingga tiga kali, yaitu enam raka'at. setiap kali hendak shalat, beliau bersiwak lalu berwudlu dan membaca beberapa ayat. Kemudian beliau shalat witir tiga raka'at. Setelah itu Mu'adzin datang, lalu beliau keluar untuk mengerjakan shalat (subuh).\" Ibnu 'Isa mengatakan; \"…kemudian beliau mengerjakan witir, lalu datanglah Bilal untuk mengumandangkan adzan shalat ketika fajar telah terbit, kemudian beliau mengerjakan dua raka'at (sunnah) fajar. Setelah itu beliau keluar untuk mengerjakan shalat -lalu hadits keduanya sepakat pada kalimat- sambil mengucapkan: \"Allahummaj'al fii qalbii nuuran, waj'al fii lisaani nuuran, waj'al fii basharii nuuran, waj'al khalfii nuuran, wa amaami nuuran, waj'al min fauqii nuuran wa min tahtii nuuran, Allahumma wa a'dzim lii nuuran (Ya Allah, jadikanlah dalam hatiku cahaya, jadikanlah dalam lisanku cahaya, jadikanlah dalam pendengaranku cahaya, jadikanlah dalam penglihatanku cahaya, jadikanlah di belakangku cahaya, jadikanlah di depanku cahaya, jadikanlah di atasku cahaya, jadikanlah di bawahku cahaya. Ya Allah, agungkanlah untukku cahaya.\" Telah menceritakan kepada kami [Wahb bin Baqiyah] dari [Khalid] dari [Hushain] seperti hadits di atas, dia berkata; \"Wa a'dzim lii nuuran (dan agungkanlah untukku cahaya).\" Abu Daud berkata; \"Demikian pula yang di katakan [Abu Khalid Ad Dalalani] dari [Habib] dalam permasalahan ini, demikian pula dia berkata dalam hadits ini, [Salamah bin Kuhail] berkata; dari [Abu Risydin] dari [Ibnu Abbas].\""},"1130":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ عَنْ شَرِيكِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي نَمِرٍ عَنْ كُرَيْبٍ عَنْ الْفَضْلِ بْنِ عَبَّاسٍ قَالَبِتُّ لَيْلَةً عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَنْظُرَ كَيْفَ يُصَلِّي فَقَامَ فَتَوَضَّأَ وَصَلَّى رَكْعَتَيْنِ قِيَامُهُ مِثْلُ رُكُوعِهِ وَرُكُوعُهُ مِثْلُ سُجُودِهِ ثُمَّ نَامَ ثُمَّ اسْتَيْقَظَ فَتَوَضَّأَ وَاسْتَنَّ ثُمَّ قَرَأَ بِخَمْسِ آيَاتٍ مِنْ آلِ عِمْرَانَ{ إِنَّ فِي خَلْقِ السَّمَوَاتِ وَالْأَرْضِ وَاخْتِلَافِ اللَّيْلِ وَالنَّهَارِ }فَلَمْ يَزَلْ يَفْعَلُ هَذَا حَتَّى صَلَّى عَشْرَ رَكَعَاتٍ ثُمَّ قَامَ فَصَلَّى سَجْدَةً وَاحِدَةً فَأَوْتَرَ بِهَا وَنَادَى الْمُنَادِي عِنْدَ ذَلِكَ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَمَا سَكَتَ الْمُؤَذِّنُ فَصَلَّى سَجْدَتَيْنِ خَفِيفَتَيْنِ ثُمَّ جَلَسَ حَتَّى صَلَّى الصُّبْحَقَالَ أَبُو دَاوُد خَفِيَ عَلَيَّ مِنْ ابْنِ بَشَّارٍ بَعْضُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abu 'Ashim] telah menceritakan kepada kami [Zuhair bin Muhammad] dari [Syarik bin Abdullah bin Abu Namir] dari [Kuraib] dari [Al Fadl bin Abbas] dia berkata; \"Aku pernah bermalam di sisi Nabi shallallahu 'alaihi wasallam untuk melihat bagaimana cara beliau shalat (malam). Maka (aku melihat) beliau bangun lalu berwudlu' dan shalat dua raka'at. (lama) beliau berdiri sama seperti ruku' dan sujudnya. Setelah itu beliau tidur, kemudian beliau bangun lagi, lalu berwudlu dan bersiwak, kemudian beliau mengucapkan lima ayat dari surat Ali Imran, yaitu; \"Sesungguhnya dalam penciptaan langit dan bumi, dan silih bergantinya malam dan siang…\" (QS Ali Imran; 190), beliau selalu mengerjakan perbuatan ini, sehingga beliau mengerjakan shalat sepuluh raka'at, kemudian beliau bangun dan mengerjakan shalat satu raka'at sebagai witirnya. Setelah seorang Muadzin menyerukan adzan, maka Rasulullah shallallahu 'alaihi wasallam akan mengerjakan shalat dua raka'at yang ringan, kemudian beliau duduk hingga tiba shalat subuh.\" Abu Daud berkata; \"Aku tidak jelas sebagian (riwayat) dari Ibnu Basyar.\""},"1131":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا مُحَمَّدُ بْنُ قَيْسٍ الْأَسَدِيُّ عَنْ الْحَكَمِ بْنِ عُتَيْبَةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَبِتُّ عِنْدَ خَالَتِي مَيْمُونَةَ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَمَا أَمْسَى فَقَالَ أَصَلَّى الْغُلَامُ قَالُوا نَعَمْ فَاضْطَجَعَ حَتَّى إِذَا مَضَى مِنْ اللَّيْلِ مَا شَاءَ اللَّهُ قَامَ فَتَوَضَّأَ ثُمَّ صَلَّى سَبْعًا أَوْ خَمْسًا أَوْتَرَ بِهِنَّ لَمْ يُسَلِّمْ إِلَّا فِي آخِرِهِنَّ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Muhammad bin Qais Al Asadi] dari [Al Hakam bin 'Utaibah] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata; \"Aku pernah bermalam di rumah bibiku Maimunah, lalu Rasulullah shallallahu 'alaihi wasallam datang setelah waktu sore tiba, maka beliau bersabda: \"Apakah anak ini sudah shalat?\" mereka menjawab; \"Ya, sudah.\" Kemudian beliau berbaring, setelah malam berlalu sebagaimana yang Allah kehendaki, beliau bangun, berwudlu' kemudian shalat tujuh atau lima raka'at dengan shalat witirnya, beliau tidak salam kecuali di raka'at terakhir (raka'at ke tujuh atau ke lima).\""},"1132":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اكْلَفُوا مِنْ الْعَمَلِ مَا تُطِيقُونَ فَإِنَّ اللَّهَ لَا يَمَلُّ حَتَّى تَمَلُّوا وَإِنَّ أَحَبَّ الْعَمَلِ إِلَى اللَّهِ أَدْوَمُهُ وَإِنْ قَلَّ وَكَانَ إِذَا عَمِلَ عَمَلًا أَثْبَتَهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari [Sa'id Al Maqburi] dari [Abu Salamah] dari [Aisyah] radliallahu 'anha bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kerjakanlah suatu amalan itu sesuai dengan kemampuan kalian, karena Allah tidak akan bosan sehingga diri kalianlah yang bosan, sesungguhnya amalan yang paling di cintai Allah adalah yang di kerjakan secara terus menerus walaupun sedikit.\" apabila beliau mengerjakan suatu amalan, beliau akan mengerjakannya secara rutin.\""},"1133":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدٍ حَدَّثَنَا عَمِّي حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ إِلَى عُثْمَانَ بْنِ مَظْعُونٍ فَجَاءَهُ فَقَالَ يَا عُثْمَانُ أَرَغِبْتَ عَنْ سُنَّتِي قَالَ لَا وَاللَّهِ يَا رَسُولَ اللَّهِ وَلَكِنْ سُنَّتَكَ أَطْلُبُ قَالَ فَإِنِّي أَنَامُ وَأُصَلِّي وَأَصُومُ وَأُفْطِرُ وَأَنْكِحُ النِّسَاءَ فَاتَّقِ اللَّهَ يَا عُثْمَانُ فَإِنَّ لِأَهْلِكَ عَلَيْكَ حَقًّا وَإِنَّ لِضَيْفِكَ عَلَيْكَ حَقًّا وَإِنَّ لِنَفْسِكَ عَلَيْكَ حَقًّا فَصُمْ وَأَفْطِرْ وَصَلِّ وَنَمْ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Sa'd] telah menceritakan kepada kami [pamanku] telah menceritakan kepada kami [ayahku] dari [Ibnu Ishaq] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah] bahwa Nabi shallallahu 'alaihi wasallam mengutus seseorang menemui Utsman bin Mazh'un, lalu Utsman datang kepada beliau, maka beliau bersabda: \"Apakah kamu membenci sunnahku?\" Utsman menjawab; \"Tidak, demi Allah wahai Rasulullah… bahkan sunnahmu lah yang amat kami cari.\" Beliau bersabda: \"Sesungguhnya aku tidur, aku juga shalat, aku berpuasa dan juga berbuka, aku juga menikahi wanita. Bertakwalah kepada Allah wahai Utsman, sesungguhnya keluargamu mempunyai hak atas dirimu, dan tamumu mempunyai hak atas dirimu, dan kamu pun memiliki hak atas dirimu sendiri, oleh karena itu berpuasa dan berbukalah, kerjakanlah shalat dan tidurlah.\""},"1134":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَسَأَلْتُ عَائِشَةَ كَيْفَ كَانَ عَمَلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ كَانَ يَخُصُّ شَيْئًا مِنْ الْأَيَّامِ قَالَتْ لَا كَانَ كُلُّ عَمَلِهِ دِيمَةً وَأَيُّكُمْ يَسْتَطِيعُ مَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَطِيعُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dia berkata; aku bertanya kepada [Aisyah]; \"Bagaimanakah amal perbuatan Rasulullah shallallahu 'alaihi wasallam? Apakah beliau pernah mengkhususkan suatu hari yang tertentu?\" Aisyah menjawab; \"Tidak, setiap amalan beliau selalu di kerjakan secara rutin, dan siapakan di antara kalian yang mampu mengerjakan amalan yang di kerjakan oleh Rasulullah shallallahu 'alaihi wasallam?\""},"1135":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ الْمُتَوَكِّلِ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ قَالَ الْحَسَنُ فِي حَدِيثِهِ وَمَالِكُ بْنُ أَنَسٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرَغِّبُ فِي قِيَامِ رَمَضَانَ مِنْ غَيْرِ أَنْ يَأْمُرَهُمْ بِعَزِيمَةٍ ثُمَّ يَقُولُ مَنْ قَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ فَتُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْأَمْرُ عَلَى ذَلِكَ ثُمَّ كَانَ الْأَمْرُ عَلَى ذَلِكَ فِي خِلَافَةِ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ وَصَدْرًا مِنْ خِلَافَةِ عُمَرَ رَضِيَ اللَّهُ عَنْهُقَالَ أَبُو دَاوُد وَكَذَا رَوَاهُ عُقَيْلٌ وَيُونُسُ وَأَبُو أُوَيْسٍ مَنْ قَامَ رَمَضَانَ وَرَوَى عُقَيْلٌ مَنْ صَامَ رَمَضَانَ وَقَامَهُ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] dan [Muhammad bin Al Mutawakkil] keduanya berkata; telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar]; Al Hasan berkata dalam haditsnya; Dan [Malik bin Anas] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam biasa memberi motivasi untuk selalu mengerjakan shalat pada malam bulan Ramadhan tanpa memerintahkan secara ketat kepada mereka, beliau bersabda: \"Barangsiapa bangun (shalat) malam pada bulan Ramadhan dengan penuh keimanan dan mengharap (ridla Allah), maka dosa-dosanya yang telah lalu akan di ampuni.\" Lalu Rasulullah shallallahu 'alaihi wasallam wafat, sedangkan perkara itu masih tetap ada, kemudian perkara itu berlanjut hingga pemerintahan Abu Bakar radliallahu 'anhu dan di awal pemerintahan Umar radliallahu 'anhu. Abu Daud berkata; \"Demikian pula yang di riwayatkan oleh ['Uqail], [Yunus] dan [Abu Uwais] yaitu; \"Barangsiapa berpuasa pada bulan Ramadhan dan bangun (shalat) pada malamnya…\""},"1136":{"ar":"حَدَّثَنَا مَخْلَدُ بْنُ خَالِدٍ وَابْنُ أَبِي خَلَفٍ الْمَعْنَى قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَمَنْ قَامَ لَيْلَةَ الْقَدْرِ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِقَالَ أَبُو دَاوُد وَكَذَا رَوَاهُ يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ وَمُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ","id":"Telah menceritakan kepada kami [Mukhlad bin Khalid] dan [Ibnu Abu Khalaf] yang maksudnya sama, keduanya berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] yang sampai kepada Nabi shallallahu 'alaihi wasallam, sabdanya: \"Barangsiapa berpuasa di bulan Ramadhan dengan keimanan dan penuh harap, maka akan di ampuni dosa-dosanya yang telah lalu. Dan barangsiapa bangun (shalat) pada malam lailatul Qadr dengan keimanan dan penuh harap, maka akan di ampuni dosa-dosanya yang telah lalu.\" Abu Daud berkata; \"Demikian pula yang di riwayatkan [Yahya bin Abu Katsir] dari [Abu Salamah], dan [Muhammad bin 'Amru] dari [Abu salamah].\""},"1137":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي الْمَسْجِدِ فَصَلَّى بِصَلَاتِهِ نَاسٌ ثُمَّ صَلَّى مِنْ الْقَابِلَةِ فَكَثُرَ النَّاسُ ثُمَّ اجْتَمَعُوا مِنْ اللَّيْلَةِ الثَّالِثَةِ فَلَمْ يَخْرُجْ إِلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا أَصْبَحَ قَالَ قَدْ رَأَيْتُ الَّذِي صَنَعْتُمْ فَلَمْ يَمْنَعْنِي مِنْ الْخُرُوجِ إِلَيْكُمْ إِلَّا أَنِّي خَشِيتُ أَنْ تُفْرَضَ عَلَيْكُمْ وَذَلِكَ فِي رَمَضَانَحَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا عَبْدَةُ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ قَالَتْ كَانَ النَّاسُ يُصَلُّونَ فِي الْمَسْجِدِ فِي رَمَضَانَ أَوْزَاعًا فَأَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَضَرَبْتُ لَهُ حَصِيرًا فَصَلَّى عَلَيْهِ بِهَذِهِ الْقِصَّةِ قَالَتْ فِيهِ قَالَ تَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّهَا النَّاسُ أَمَا وَاللَّهِ مَا بِتُّ لَيْلَتِي هَذِهِ بِحَمْدِ اللَّهِ غَافِلًا وَلَا خَفِيَ عَلَيَّ مَكَانُكُمْ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik bin Anas] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] dari [Aisyah isteri Nabi] shallallahu 'alaihi wasallam bahwa Nabi shallallahu 'alaihi wasallam mengerjakan shalat di dalam masjid, kemudian orang-orang turut mengikuti shalat beliau, kemudian beliau mengerjakan lagi di malam berikutnya, ternyata orang-orang yang mengikuti shalat beliau semakin banyak, Dan di malam ketiga, ketika orang-orang telah berkumpul, Rasulullah shallallahu 'alaihi wasallam tidak kunjung keluar. Keesokan harinya, beliau bersabda: \"Aku telah mengetahui apa yang kalian perbuat semalam, dan tidak ada sesuatu pun yang menghalangiku keluar menemui kalian, hanya saja aku khawatir jika shalat tersebut akan diwajibkan atas kalian.\" Kejadian itu terjadi pada bulan Ramadhan.\" Telah menceritakan kepada kami [Hannad bin As Sarri] telah menceritakan kepada kami ['Abdah] dari [Muhammad bin 'Amru] dari [Muhammad bin Ibrahim] dari [Abu Salamah bin Abdurrahman] dari [Aisyah] dia berkata; \"Biasanya orang-orang mengerjakan shalat di masjid pada bulan Ramadhan secara terpisah, lalu Rasulullah shallallahu 'alaihi wasallam memerintahkanku (untuk menghamparkan tikar), maka aku pun menghamparkan tikar untuk beliau, lalu beliau shalat di atas tikar tersebut…\" seperti kisah dalam hadits ini, Aisyah berkata; \"Beliau yaitu Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai sekalian manusia, demi Allah, segala puji bagi Allah, tidaklah aku lalai pada malam hariku ini, dan tidak pula tempat kalian samar bagiku.\""},"1138":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ أَخْبَرَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ الْوَلِيدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِي ذَرٍّ قَالَصُمْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَمَضَانَ فَلَمْ يَقُمْ بِنَا شَيْئًا مِنْ الشَّهْرِ حَتَّى بَقِيَ سَبْعٌ فَقَامَ بِنَا حَتَّى ذَهَبَ ثُلُثُ اللَّيْلِ فَلَمَّا كَانَتْ السَّادِسَةُ لَمْ يَقُمْ بِنَا فَلَمَّا كَانَتْ الْخَامِسَةُ قَامَ بِنَا حَتَّى ذَهَبَ شَطْرُ اللَّيْلِ فَقُلْتُ يَا رَسُولَ اللَّهِ لَوْ نَفَّلْتَنَا قِيَامَ هَذِهِ اللَّيْلَةِ قَالَ فَقَالَ إِنَّ الرَّجُلَ إِذَا صَلَّى مَعَ الْإِمَامِ حَتَّى يَنْصَرِفَ حُسِبَ لَهُ قِيَامُ لَيْلَةٍ قَالَ فَلَمَّا كَانَتْ الرَّابِعَةُ لَمْ يَقُمْ فَلَمَّا كَانَتْ الثَّالِثَةُ جَمَعَ أَهْلَهُ وَنِسَاءَهُ وَالنَّاسَ فَقَامَ بِنَا حَتَّى خَشِينَا أَنْ يَفُوتَنَا الْفَلَاحُ قَالَ قُلْتُ وَمَا الْفَلَاحُ قَالَ السُّحُورُ ثُمَّ لَمْ يَقُمْ بِقِيَّةَ الشَّهْرِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid bin Zurai'] telah mengabarkan kepada kami [Daud bin Abu Hind] dari [Al Walid bin Abdurrahman] dari [Jubair bin Nufair] dari [Abu Dzar] dia berkata; \"Kami pernah berpuasa Ramadhan bersama Rasulullah shallallahu 'alaihi wasallam, dan beliau tidak pernah mengerjakan shalat malam bersama kami sedikitpun dalam sebulan sampai berlalu sepertiga malam, setelah malam ke enam (dari akhir bulan) beliau juga tidak mengerjakan shalat malam bersama kami, ketika di hari ke lima (dari akhir bulan), beliau mengerjakan shalat malam bersama kami hingga tengah malam pun berlalu. Maka kataku; \"wahai Rasulullah, alangkah baiknya sekiranya anda memperbanyak shalat sunnah (qiyamullail) pada malam hari ini untuk kami!.\" Abu Dzar berkata; Maka beliau bersabda: \"Sesungguhnya apabila seseorang shalat (malam) bersama imam hingga selesai, maka akan di catat baginya seperti bangun (untuk mengerjakan shalat malam) semalam suntuk.\" Kata Abu Dzar; \"Ketika malam ke empat (dari akhir bulan) beliau tidak mengerjakan shalat malam (bersama kami), setelah malam ketiga (dari akhir bulan), beliu mengumpulkan keluarganya, isteri-isterinya dan orang-orang, lalu melakukan shalat malam bersama kami, sampai kami khawatir ketinggalah \"Al falah.\" Jabir bertanya; \"Apakah al falah itu?\" jawabnya; \"Waktu sahur, kemudian beliau tidak lagi melakukan shalat malam bersama kami di malam-malam berikutnya dari sebulan itu.\""},"1139":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ وَدَاوُدُ بْنُ أُمَيَّةَ أَنَّ سُفْيَانَ أَخْبَرَهُمْ عَنْ أَبِي يَعْفُورٍ وَقَالَ دَاوُدُ عَنْ ابْنِ عُبَيْدِ بْنِ نِسْطَاسٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ إِذَا دَخَلَ الْعَشْرُ أَحْيَا اللَّيْلَ وَشَدَّ الْمِئْزَرَ وَأَيْقَظَ أَهْلَهُقَالَ أَبُو دَاوُد وَأَبُو يَعْفُورٍ اسْمُهُ عَبْدُ الرَّحْمَنِ بْنُ عُبَيْدِ بْنِ نِسْطَاسٍ","id":"Telah menceritakan kepada kami [Nahsr bin Ali] dan [Daud bin Umayyah] bahwa [Sufyan] mengabarkan kepada mereka, dari [Abu Ya'fur]. [Daud] mengatakan; dari [Abu 'Ubaid bin Nisthasi] dari [Abu Adl Dluha] dari [Masruq] dari [Aisyah] bahwa ketika Nabi shallallahu 'alaihi wasallam memasuki sepuluh malam yang terakhir, beliau menghidupkan malamnya dan mengencangkan ikat pinggang serta membangunkan keluarganya.\" Abu Daud berkata; \"Abu Ya'fur namanya adalah Abdurrahman bin 'Ubaid bin Nisthasi.\""},"1140":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ الْهَمْدَانِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي مُسْلِمُ بْنُ خَالِدٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا أُنَاسٌ فِي رَمَضَانَ يُصَلُّونَ فِي نَاحِيَةِ الْمَسْجِدِ فَقَالَ مَا هَؤُلَاءِ فَقِيلَ هَؤُلَاءِ نَاسٌ مَعَهُمْ قُرْآنٌ وَأُبَيُّ بْنُ كَعْبٍ يُصَلِّي وَهُمْ يُصَلُّونَ بِصَلَاتِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَابُوا وَنِعْمَ مَا صَنَعُواقَالَ أَبُو دَاوُد لَيْسَ هَذَا الْحَدِيثُ بِالْقَوِيِّ مُسْلِمُ بْنُ خَالِدٍ ضَعِيفٌ","id":"Telah menceritakan kepada kami [Ahmad bin Sa'id Al hamdani] telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Muslim bin Khalid] dari [Al 'Ala` bin Abdurrahman] dari [ayahnya] dari [Abu Hurairah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam keluar, dan beliau melihat orang-orang tengah mengerjakan shalat di pojok-pojok masid, beliau bersabda: \"Apa yang sedang di perbuat oleh mereka?\" maka di jawab; \"Beberapa orang yang tidak hafal Al Qur'an, sedangkan Ubay bin Ka'b tengah mengerjakan shalat yang di ikuti oleh mereka.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Mereka benar, alangkah baiknya amal perbuatan mereka.\" Abu Daud berkata; 'Hadits ini tidaklah kuat, sebab Muslim bin Khalid riwayatnya lemah.\""},"1141":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ وَمُسَدَّدٌ الْمَعْنَى قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَاصِمٍ عَنْ زِرٍّ قَالَ قُلْتُ لِأُبَيِّ بْنِ كَعْبٍ أَخْبِرْنِي عَنْ لَيْلَةِ الْقَدْرِ يَا أَبَا الْمُنْذِرِ فَإِنَّ صَاحِبَنَا سُئِلَ عَنْهَا فَقَالَ مَنْ يَقُمْ الْحَوْلَ يُصِبْهَافَقَالَ رَحِمَ اللَّهُ أَبَا عَبْدِ الرَّحْمَنِ وَاللَّهِ لَقَدْ عَلِمَ أَنَّهَا فِي رَمَضَانَ زَادَ مُسَدَّدٌ وَلَكِنْ كَرِهَ أَنْ يَتَّكِلُوا أَوْ أَحَبَّ أَنْ لَا يَتَّكِلُوا ثُمَّ اتَّفَقَا وَاللَّهِ إِنَّهَا لَفِي رَمَضَانَ لَيْلَةَ سَبْعٍ وَعِشْرِينَ لَا يَسْتَثْنِي قُلْتُ يَا أَبَا الْمُنْذِرِ أَنَّى عَلِمْتَ ذَلِكَ قَالَ بِالْآيَةِ الَّتِي أَخْبَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ لِزِرٍّ مَا الْآيَةُ قَالَ تُصْبِحُ الشَّمْسُ صَبِيحَةَ تِلْكَ اللَّيْلَةِ مِثْلَ الطَّسْتِ لَيْسَ لَهَا شُعَاعٌ حَتَّى تَرْتَفِعَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] dan [Musaddad] sedangkan maksudnya sama, keduanya berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari ['Ashim] dari [Zirrin] dia berkata; aku bertanya kepada [Ubay bin Ka'b]; \"wahai Abu Mundzir, beritahukanlah kepadaku mengenai lailatul qadr!, karena sesungguhnya sahabat kami (Ibnu Mas'ud) pernah di tanya tentang lailatul qadr, lalu dia menjawab; \"Barangsiapa melakukan (qiyamullail) setahun penuh, maka ia akan mendapatkannya.\" Ubay bin Ka'b berkata; \"Semoga Allah merahmati Abu Abdurrahman, sungguh dirinya telah mengetahui bahwa lailatul qadr terjadi pada bulan Ramadhan.\" Musaddad menambahkan; \"Tapi beliau tidak senang jika kalian bergantung pada lailatul qadr -atau- beliau lebih suka jika kalian tidak bergantung pada lailatul qadr. Demi Allah, sesungguhnya lailatul qadr itu terjadi pada bulan Ramadhan yaitu pada tanggal dua puluh tujuh tanpa terkecuali.\" Tanyaku; \"Wahai Abu Mundzir, bagaimana kamu dapat mengetahui hal itu?\" dia menjawab; \"yaitu dengan tanda-tanda yang pernah di beritahukan Rasulullah shallallahu 'alaihi wasallam.\" aku berkata kepada Zirr; \"Apakah tanda-tandanya?\" dia menjawab; \"Matahari pada pagi harinya seperti baskom, tidak bercahaya hingga ia meninggi.\""},"1142":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَفْصِ بْنِ عَبْدِ اللَّهِ السُّلَمِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ عَبَّادِ بْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ مُسْلِمٍ الزُّهْرِيِّ عَنْ ضَمْرَةَ بْنِ عَبْدِ اللَّهِ بْنِ أُنَيْسٍ عَنْ أَبِيهِ قَالَكُنْتُ فِي مَجْلِسِ بَنِي سَلَمَةَ وَأَنَا أَصْغَرُهُمْ فَقَالُوا مَنْ يَسْأَلُ لَنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لَيْلَةِ الْقَدْرِ وَذَلِكَ صَبِيحَةَ إِحْدَى وَعِشْرِينَ مِنْ رَمَضَانَ فَخَرَجْتُ فَوَافَيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْمَغْرِبِ ثُمَّ قُمْتُ بِبَابِ بَيْتِهِ فَمَرَّ بِي فَقَالَ ادْخُلْ فَدَخَلْتُ فَأُتِيَ بِعَشَائِهِ فَرَآنِي أَكُفُّ عَنْهُ مِنْ قِلَّتِهِ فَلَمَّا فَرَغَ قَالَ نَاوِلْنِي نَعْلِي فَقَامَ وَقُمْتُ مَعَهُ فَقَالَ كَأَنَّ لَكَ حَاجَةً قُلْتُ أَجَلْ أَرْسَلَنِي إِلَيْكَ رَهْطٌ مِنْ بَنِي سَلَمَةَ يَسْأَلُونَكَ عَنْ لَيْلَةِ الْقَدْرِ فَقَالَ كَمْ اللَّيْلَةُ فَقُلْتُ اثْنَتَانِ وَعِشْرُونَ قَالَ هِيَ اللَّيْلَةُ ثُمَّ رَجَعَ فَقَالَ أَوْ الْقَابِلَةُ يُرِيدُ لَيْلَةَ ثَلَاثٍ وَعِشْرِينَ","id":"Telah menceritakan kepada kami [Ahmad bin Hafsh bin Abdullah As Sulami] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Ibrahim bin Thahman] dari ['Abbad bin Ishaq] dari [Muhammad bin Muslim Az Zuhri] dari [Dlamrah bin Abdullah bin Unais] dari [ayahnya] dia berkata; \"Aku pernah berada di majlisnya Bani Salamah, sementara waktu itu aku lah yang paling muda, mereka berkata; \"Siapakah yang akan menanyakan untuk kita kepada Rasulullah shallallahu 'alaihi wasallam tentang lailatul qadr?\" pada pagi itu adalah tanggal dua puluh satu Ramadhan, lalu aku keluar, maka aku dapati beliau tengah mengerjakan shalat Maghrib, kemudian aku berdiri di depan pintu rumah beliau, lalu beliau lewat di depanku, beliau bersabda; \"Masuklah.\" Lalu aku pun masuk, saat itu makan malam beliau telah terhidang, maka aku menahan diri karena memang makan malam beliau sangat sedikit. setelah selesai, beliau bersabda: \"Tolong ambilkan sandalku!.\" Lalu beliau berdiri dan aku pun berdiri bersama beliau, beliau bersabda: \"Sepertinya kamu mempunyai keperluan?\" jawabku; \"Ya benar, beberapa pemuda dari Bani Salamah mengutusku untuk menyakan lailatul qadr kepada anda.\" Beliau bertanya; \"Tanggal berapakah malam ini?\" jawabku; \"Malam ke dua puluh dua.\" Beliau bersabda: \"Pada malam inilah lailatul qadr terjadi.\" Kemudian beliau kembali dan bersabda: \"atau malam berikutnya.\" Yang beliau maksudkan adalah malam ke dua puluh tiga.\""},"1143":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَقَ حَدَّثَنَا مُحَمَّدُ بْنُ إِبْرَاهِيمَ عَنْ ابْنِ عَبْدِ اللَّهِ بْنِ أُنَيْسٍ الْجُهَنِيِّ عَنْ أَبِيهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ لِي بَادِيَةً أَكُونُ فِيهَا وَأَنَا أُصَلِّي فِيهَا بِحَمْدِ اللَّهِ فَمُرْنِي بِلَيْلَةٍ أَنْزِلُهَا إِلَى هَذَا الْمَسْجِدِ فَقَالَ انْزِلْ لَيْلَةَ ثَلَاثٍ وَعِشْرِينَفَقُلْتُ لِابْنِهِ كَيْفَ كَانَ أَبُوكَ يَصْنَعُ قَالَ كَانَ يَدْخُلُ الْمَسْجِدَ إِذَا صَلَّى الْعَصْرَ فَلَا يَخْرُجُ مِنْهُ لِحَاجَةٍ حَتَّى يُصَلِّيَ الصُّبْحَ فَإِذَا صَلَّى الصُّبْحَ وَجَدَ دَابَّتَهُ عَلَى بَابِ الْمَسْجِدِ فَجَلَسَ عَلَيْهَا فَلَحِقَ بِبَادِيَتِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah mengabarkan kepada kami [Muhammad bin Ishaq] telah menceritakan kepada kami [Muhammad bin Ibrahim] dari [Ibnu Abdullah bin Unais Al Juhani] dari [ayahnya] berkata; saya berkata; wahai Rasulullah, sesungguhnya saya memiliki perkampungan yang aku tinggal di sana dan alhamdulillah aku dapat melaksanakan shalat di dalamnya, maka perintahkanlah kepadaku satu malam sehingga pada malam itu aku dapat tinggal di masjid ini, maka Rasulullah Shallallahu 'alaihi wasallam menjawab: \"Tinggallah pada malam ke dua puluh tiga\". (perawi berkata) Kemudian aku bertanya kepada anaknya (Ibnu Abdullah bin Unais): \"bagaimana bapakmu melakukannya?\" dia menjawab: \"Bapakku masuk ke Masjid jika hendak shalat asar, dan dia tidak keluar untuk memenuhi hajatnya sampai dia shalat shubuh, apabila ia selesai shalat shubuh dia menghampiri kendaraannya di depan pintu masjid, kemudian ia menaikinya dan kembali ke perkampungannya. "},"1144":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا وُهَيْبٌ أَخْبَرَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْتَمِسُوهَا فِي الْعَشْرِ الْأَوَاخِرِ مِنْ رَمَضَانَ فِي تَاسِعَةٍ تَبْقَى وَفِي سَابِعَةٍ تَبْقَى وَفِي خَامِسَةٍ تَبْقَى","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Wuhaib] telah mengabarkan kepada kami [Ayyub] dari ['Ikrimah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Carilah lailatul qadar pada sepuluh terakhir bulan Ramadlan, sembilan tersisa, tujuh tersisa atau lima tersisa.\""},"1145":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ التَّيْمِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْتَكِفُ الْعَشْرَ الْأَوْسَطَ مِنْ رَمَضَانَ فَاعْتَكَفَ عَامًا حَتَّى إِذَا كَانَتْ لَيْلَةُ إِحْدَى وَعِشْرِينَ وَهِيَ اللَّيْلَةُ الَّتِي يَخْرُجُ فِيهَا مِنْ اعْتِكَافِهِ قَالَ مَنْ كَانَ اعْتَكَفَ مَعِي فَلْيَعْتَكِفْ الْعَشْرَ الْأَوَاخِرَ وَقَدْ رَأَيْتُ هَذِهِ اللَّيْلَةَ ثُمَّ أُنْسِ��تُهَا وَقْدَ رَأَيْتُنِي أَسْجُدُ مِنْ صَبِيحَتِهَا فِي مَاءٍ وَطِينٍ فَالْتَمِسُوهَا فِي كُلِّ وِتْرٍ قَالَ أَبُو سَعِيدٍ فَمَطَرَتْ السَّمَاءُ مِنْ تِلْكَ اللَّيْلَةِ وَكَانَ الْمَسْجِدُ عَلَى عَرِيشٍ فَوَكَفَ الْمَسْجِدُ فَقَالَ أَبُو سَعِيدٍ فَأَبْصَرَتْ عَيْنَايَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَى جَبْهَتِهِ وَأَنْفِهِ أَثَرُ الْمَاءِ وَالطِّينِ مِنْ صَبِيحَةِ إِحْدَى وَعِشْرِينَ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Yazid bin Abdullah bin Al Had] dari [Muhammad bin Ibrahim bin Al Harits At Taimi] dari [Abu Salamah bin Abdurrahman] dari [Abu Sa'id Al Khudri] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam memulai beri'tikaf pada sepuluh kedua pada bulan Ramadan. Beliau beri'tikaf pada tahun itu, hingga ketika tiba malam kedua puluh satu, yaitu hari ketika beliau keluar dari I'tikafnya, beliau bersabda: 'Barangsiapa ingin melaksanakan I'tikaf bersamaku, hendaklah dia mengerjakannya pada sepuluh hari yang terakhir ini. Aku telah melihat dalam mimpiku, namun aku lupa. Aku mimpi pada waktu paginya aku bersujud pada air dan tanah. Carilah lailatul qadar pada malam yang ganjil. ' Abu Sa'id berkata; \"Pada malam itu terjadi hujan, dan saat itu masjidnya laksana bangsal untuk berteduh dan bocor, \" Abu Sa'id menambahkan; \"Dengan kedua mataku, aku melihat Rasulullah shallallahu 'alaihi wasallam pergi, sementara pada dahi dan hidungnya ada bekas tanah dan air. Itu terjadi pada pagi hari malam ke dua puluh satu.\""},"1146":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْأَعْلَى أَخْبَرَنَا سَعِيدٌ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْتَمِسُوهَا فِي الْعَشْرِ الْأَوَاخِرِ مِنْ رَمَضَانَ وَالْتَمِسُوهَا فِي التَّاسِعَةِ وَالسَّابِعَةِ وَالْخَامِسَةِقَالَ قُلْتُ يَا أَبَا سَعِيدٍ إِنَّكُمْ أَعْلَمُ بِالْعَدَدِ مِنَّا قَالَ أَجَلْ قُلْتُ مَا التَّاسِعَةُ وَالسَّابِعَةُ وَالْخَامِسَةُ قَالَ إِذَا مَضَتْ وَاحِدَةٌ وَعِشْرُونَ فَالَّتِي تَلِيهَا التَّاسِعَةُ وَإِذَا مَضَى ثَلَاثٌ وَعِشْرُونَ فَالَّتِي تَلِيهَا السَّابِعَةُ وَإِذَا مَضَى خَمْسٌ وَعِشْرُونَ فَالَّتِي تَلِيهَا الْخَامِسَةُ قَالَ أَبُو دَاوُد لَا أَدْرِي أَخَفِيَ عَلَيَّ مِنْهُ شَيْءٌ أَمْ لَا","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abdul A'laa] telah mengabarkan kepada kami [Sa'id] dari [Abu Nadlrah] dari [Abu Sa'id Al Khudri] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Carilah (Laiatul Qadr) pada sepuluh malam yang terakhir bulan ramadhan, dan carilah pada malam sembilan, ketujuh dan kelima.\" Abu Nadlrah berkata; tanyaku; \"Wahai Abu Sa'id, sesungguhnya kamu lebih mengetahui bilangan tersebut daripada kami.\" Dia menjawab; \"ya, betul.\" Tanyaku selanjutnya; \"apakah maksud malam kesembilan, ketujuh dan kelima?\" dia menjawab; \"Jika malam kedua puluh satu telah berlalu, maka berikutnya tinggal sembilan, jika malam ketiga puluh satu telah berlalu, maka malam berikutnya tinggal tinggal tujuh, jika malam kedua puluh lima telah berlalu, maka malam berikutnya tinggal lima.\" Abu Daud berkata; \"Apakah dia (Perawi) menyembunyikan sesuatu dariku apakah tidak.\""},"1147":{"ar":"حَدَّثَنَا حَكِيمُ بْنُ سَيْفٍ الرَّقِّيُّ أَخْبَرَنَا عُبَيْدُ اللَّهِ يَعْنِي ابْنَ عَمْرٍو عَنْ زَيْدٍ يَعْنِي ابْنَ أَبِي أُنَيْسَةَ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ أَبِيهِ عَنْ ابْنِ مَسْعُودٍ قَالَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اطْلُبُوهَا لَيْلَةَ سَبْعَ عَشْرَةَ مِنْ رَمَضَانَ وَلَيْلَةَ إِحْدَى وَعِشْرِينَ وَلَيْلَةَ ثَلَاثٍ وَعِشْرِينَ ثُمَّ سَكَتَ","id":"Telah menceritakan kepada kami [Hakim bin Saif Ar Raqi] telah mengabarkan kepada kami ['Ubaidullah yaitu Ibnu 'Amru] dari [Zaid yaitu Ibnu Abu Unaisah] dari [Abu Ishaq] dari [Abdurrahman bin Al Aswad] dari [ayahnya] dari [Ibnu Mas'ud] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada kami; \"Carilah (lailatul Qadar) pada malam ke tujuh belas bulan Ramadhan dan malam kedua puluh satu dan malam kedua puluh tiga.\" Kemudian beliau diam.\""},"1148":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَحَرَّوْا لَيْلَةَ الْقَدْرِ فِي السَّبْعِ الْأَوَاخِرِ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Abdullah bin Dinar] dari [Ibnu Umar] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Carilah malam lailatul qadr di tujuh malam terakhir (bulan Ramadhan).\""},"1149":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي أَخْبَرَنَا شُعْبَةُ عَنْ قَتَادَةَ أَنَّهُ سَمِعَ مُطَرِّفًا عَنْ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي لَيْلَةِ الْقَدْرِ قَالَ لَيْلَةُ الْقَدْرِ لَيْلَةُ سَبْعٍ وَعِشْرِينَ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku] telah mengabarkan kepada kami [Syu'bah] dari [Qatadah] bahwa dia mendengar [Muttharif] dari [Mu'awiyah bin Abu Sufyan] dari Nabi shallallahu 'alaihi wasallam mengenai lailatul qadr, beliau bersabda: \"Lailatul qadr adalah malam ke dua puluh tujuh.\""},"1150":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ زَنْجُوَيْهِ النَّسَائِيُّ أَخْبَرَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرِ بْنِ أَبِي كَثِيرٍ أَخْبَرَنَا مُوسَى بْنُ عُقْبَةَ عَنْ أَبِي إِسْحَقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أَسْمَعُ عَنْ لَيْلَةِ الْقَدْرِ فَقَالَ هِيَ فِي كُلِّ رَمَضَانَقَالَ أَبُو دَاوُد رَوَاهُ سُفْيَانُ وَشُعْبَةُ عَنْ أَبِي إِسْحَقَ مَوْقُوفًا عَلَى ابْنِ عُمَرَ لَمْ يَرْفَعَاهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Humaid bin Zanjuwaih An Nasa`i] telah mengabarkan kepada kami [Sa'id bin Abu Maryam] telah menceritakan kepada kami [Muhammad bin Ja'far bin Abu Katsir] telah mengabarkan kepada kami [Musa bin 'Uqbah] dari [Abu Ishaq] dari [Sa'id bin Jubair] dari [Abdullah bin Umar] dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah di tanya, dan aku mendengar mengenai lailatul qadr, beliau bersabda: \"lailatul qadr terjadi setiap bulan Ramadhan.\" Abu Daud berkata; di riwayatkan pula oleh [Sufyan] dan [Syu'bah] dari [Abu Ishaq] secara mauquf sampai [Ibnu Umar], dan dia tidak merafa'kan sampai kepada Nabi shallallahu 'alaihi wasallam.\""},"1151":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ وَمُوسَى بْنُ إِسْمَعِيلَ قَالَا أَخْبَرَنَا أَبَانُ عَنْ يَحْيَى عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ اقْرَأْ الْقُرْآنَ فِي شَهْرٍ قَالَ إِنِّي أَجِدُ قُوَّةً قَالَ اقْرَأْ فِي عِشْرِينَ قَالَ إِنِّي أَجِدُ قُوَّةً قَالَ اقْرَأْ فِي خَمْسَ عَشْرَةَ قَالَ إِنِّي أَجِدُ قُوَّةً قَالَ اقْرَأْ فِي عَشْرٍ قَالَ إِنِّي أَجِدُ قُوَّةً قَالَ اقْرَأْ فِي سَبْعٍ وَلَا تَزِيدَنَّ عَلَى ذَلِكَقَالَ أَبُو دَاوُد وَحَدِيثُ مُسْلِمٍ أَتَمُّ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] dan [Musa bin Isma'il] keduanya berkata; telah mengabarkan kepada kami [Aban] dari [Yahya] dari [Muhammad bin Ibrahim] dari [Abu Salamah] dari [Abdullah bin 'Amru] bahwa Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Bacalah Al Qur'an (hingga khatam) dalam sebulan.\" Abdullah berkata; \"Aku bisa (mengkhatamkan) lebih dari itu (sebulan).\" Beliau bersabda: \"Kalau begitu (khatamkan) selama dua puluh hari.\" Abdullah berkata; \"Aku bisa (mengkhatamkan) lebih dari itu.\" Beliau bersabda: \"Kalau begitu, (khatamkan) selama lima belas hari.\" Abdullah berkata; \"Aku bisa (mengkhatamkan) lebih dari itu.\" Beliau bersabda: \"Kalau begitu, (khatamkan) selama sepuluh hari.\" Abdullah berkata; \"Aku bisa (mengkhatamkan) lebih dari itu.\" Beliau bersabda \"Kalau begitu, (khatamkan) selama tujuh hari, jangan kamu kurangi dari itu.\" Abu Daud berkata; \"Hadits muslim lebih lengkap (dari haditsnya Musa).\""},"1152":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ أَخْبَرَنَا حَمَّادٌ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صُمْ مِنْ كُلِّ شَهْرٍ ثَلَاثَةَ أَيَّامٍ وَاقْرَأْ الْقُرْآنَ فِي شَهْرٍ فَنَاقَصَنِي وَنَاقَصْتُهُ فَقَالَ صُمْ يَوْمًا وَأَفْطِرْ يَوْمًاقَالَ عَطَاءٌ وَاخْتَلَفْنَا عَنْ أَبِي فَقَالَ بَعْضُنَا سَبْعَةَ أَيَّامٍ وَقَالَ بَعْضُنَا خَمْسًا","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah mengabarkan kepada kami [Hammad] dari ['Atha` bin As Sa`ib] dari [ayahnya] dari [Abdullah bin 'Amru] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Puasalah tiga hari dalam setiap bulan, dan bacalah Al Qur'an (khatamkan) dalam sebulan.\" Beliau mengajukan pengurangan terhadapku, dan aku pun demikian, lalu beliau bersabda: 'Berpuasalah sehari dan berbukalah sehari. ' 'Atha` berkata; \"kami berbeda (periwayatan) dari ayahku, sebagian dari kami mengatakan; \"Tujuh hari.\" Sebagian lagi mengatakan; \"Lima hari.\""},"1153":{"ar":"حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الصَّمَدِ أَخْبَرَنَا هَمَّامٌ أَخْبَرَنَا قَتَادَةُ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو أَنَّهُ قَالَيَا رَسُولَ اللَّهِ فِي كَمْ أَقْرَأُ الْقُرْآنَ قَالَ فِي شَهْرٍ قَالَ إِنِّي أَقْوَى مِنْ ذَلِكَ يُرَدِّدُ الْكَلَامَ أَبُو مُوسَى وَتَنَاقَصَهُ حَتَّى قَالَ اقْرَأْهُ فِي سَبْعٍ قَالَ إِنِّي أَقْوَى مِنْ ذَلِكَ قَالَ لَا يَفْقَهُ مَنْ قَرَأَهُ فِي أَقَلَّ مِنْ ثَلَاثٍ","id":"Telah menceritakan kepada kami [Ibnu Al Mutsanna] telah menceritakan kepada kami [Abdusshamad] telah mengabarkan kepada kami [Hammam] telah mengabarkan kepada kami [Qatadah] dari [Yazid bin Abdullah bin 'Amru] dari [Abdullah bin 'Amru] bahwa dia berkata; \"Wahai Rasulullah, berapa lamakah aku harus mengkhatamkan Al Qur'an?\" beliau bersabda: \"Dalam sebulan.\" Abdullah bin 'Amru berkata; \"Sesungguhnya aku bisa lebih dari itu.\" -Abu Musa (Ibnu Mutsanna) mengulang-ulang perkataan ini- dan Abdullah selalu meminta dipensasi hingga beliau bersabda: \"Jika demikian, bacalah al Qur'an (hingga khatam) dalam tujuh hari.\" Abdullah berkata; \"Aku masih dapat menyelesaikannya lebih dari itu.\" Beliau bersabda: \"Tidak akan dapat memahaminya orang yang mengkhatamkan Al Qur'an kurang dari tiga hari.\""},"1154":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حَفْصٍ أَبُو عَبْدِ الرَّحْمَنِ الْقَطَّانُ خَالُ عِيسَى بْنِ شَاذَانَ أَخْبَرَنَا أَبُو دَاوُدَ أَخْبَرَنَا الْحَرِيشُ بْنُ سُلَيْمٍ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ عَنْ خَيْثَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ الْقُرْآنَ فِي شَهْرٍ قَالَ إِنَّ بِي قُوَّةً قَالَ اقْرَأْهُ فِي ثَلَاثٍقَالَ أَبُو عَلِيٍّ سَمِعْت أَبَا دَاوُد يَقُولُ سَمِعْتُ أَحْمَدَ يَعْنِي ابْنَ حَنْبَلٍ يَقُولُ عِيسَى بْنُ شَاذَانَ كَيِّسٌ","id":"Telah menceritakan kepada kami [Muhammad bin Hafsh Abu Abdurrahman Al Qatthan] pamannya Isa bin Syadzan, telah mengabarkan kepada kami [Abu Daud] telah mengabarkan kepada kami [Al Harisy bin Sulaim] dari [Thalhah bin Musharif] dari [Khaitsamah] dari [Abdullah bin 'Amru] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Khatamkanlah Al Qur'an dalam sebulan.\" Abdullah berkata; \"Aku bisa (menghatamkannya) lebih dari itu.\" Beliau bersabda: \"Khatamkan selama tiga hari.\" Abu Ali mengatakan; \"Aku mendengar Abu Daud berkata; saya mendengar Ahmad yaitu Ibnu Hanbal berkata; Isa bin Syadzan adalah orang yang bijaksana.\""},"1155":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ أَخْبَرَنَا ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا يَحْيَى بْنُ أَيُّوبَ عَنْ ابْنِ الْهَادِ قَالَ سَأَلَنِي نَافِعُ بْنُ جُبَيْرِ بْنِ مُطْعِمٍفَقَالَ لِي فِي كَمْ تَقْرَأُ الْقُرْآنَ فَقُلْتُ مَا أُحَزِّبُهُ فَقَالَ لِي نَافِعٌ لَا تَقُلْ مَا أُحَزِّبُهُ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ��َرَأْتُ جُزْءًا مِنْ الْقُرْآنِقَالَ حَسِبْتُ أَنَّهُ ذَكَرَهُ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] telah mengabarkan kepada kami [Ibnu Abu Maryam] telah mengabarkan kepada kami [Yahya bin Ayyub] dari [Ibnu Al Haad] dia berkata; [Nafi' bin Jubair bin Muth'im] pernah bertanya kepadaku, tanyanya; \"Berapa lamakah kamu biasa menghatamkan Al Qur'an?\" maka aku menjawab; \"Aku tidak biasa menghimpunnya sebagai suatu wirid.\" Lalu Nafi' berkata kepadaku; \"Janganlah kamu berkata \"Aku tidak biasa menghimpunnya sebagai suatu wirid\" karena Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku telah membaca sebagian dari Al Qur'an.\" Kata Ibnu Al Haad; \"Saya kira, dia menyebutkan hadits ini dari [Al Mughirah bin Syu'bah].\""},"1156":{"ar":"حَدَّثَنَا مُسَدَّدٌ أَخْبَرَنَا قُرَّانُ بْنُ تَمَّامٍ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ أَخْبَرَنَا أَبُو خَالِدٍ وَهَذَا لَفْظُهُ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ يَعْلَى عَنْ عُثْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ أَوْسٍ عَنْ جَدِّهِ قَالَ عَبْدُ اللَّهِ بْنُ سَعِيدٍ فِي حَدِيثِهِ أَوْسُ بْنُ حُذَيْفَةَ قَالَقَدِمْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي وَفْدِ ثَقِيفٍ قَالَ فَنَزَلَتْ الْأَحْلَافُ عَلَى الْمُغِيرَةِ بْنِ شُعْبَةَ وَأَنْزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَنِي مَالِكٍ فِي قُبَّةٍ لَهُ قَالَ مُسَدَّدٌ وَكَانَ فِي الْوَفْدِ الَّذِينَ قَدِمُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ ثَقِيفٍ قَالَ كَانَ كُلَّ لَيْلَةٍ يَأْتِينَا بَعْدَ الْعِشَاءِ يُحَدِّثُنَا و قَالَ أَبُو سَعِيدٍ قَائِمًا عَلَى رِجْلَيْهِ حَتَّى يُرَاوِحُ بَيْنَ رِجْلَيْهِ مِنْ طُولِ الْقِيَامِ وَأَكْثَرُ مَا يُحَدِّثُنَا مَا لَقِيَ مِنْ قَوْمِهِ مِنْ قُرَيْشٍ ثُمَّ يَقُولُ لَا سَوَاءَ كُنَّا مُسْتَضْعَفِينَ مُسْتَذَلِّينَ قَالَ مُسَدَّدٌ بِمَكَّةَ فَلَمَّا خَرَجْنَا إِلَى الْمَدِينَةِ كَانَتْ سِجَالُ الْحَرْبِ بَيْنَنَا وَبَيْنَهُمْ نُدَالُ عَلَيْهِمْ وَيُدَالُونَ عَلَيْنَا فَلَمَّا كَانَتْ لَيْلَةً أَبْطَأَ عَنْ الْوَقْتِ الَّذِي كَانَ يَأْتِينَا فِيهِ فَقُلْنَا لَقَدْ أَبْطَأْتَ عَنَّا اللَّيْلَةَ قَالَ إِنَّهُ طَرَأَ عَلَيَّ جُزْئِي مِنْ الْقُرْآنِ فَكَرِهْتُ أَنْ أَجِيءَ حَتَّى أُتِمَّهُقَالَ أَوْسٌ سَأَلْتُ أَصْحَابَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ يُحَزِّبُونَ الْقُرْآنَ قَالُوا ثَلَاثٌ وَخَمْسٌ وَسَبْعٌ وَتِسْعٌ وَإِحْدَى عَشْرَةَ وَثَلَاثَ عَشْرَةَ وَحِزْبُ الْمُفَصَّلِ وَحْدَهُ قَالَ أَبُو دَاوُد وَحَدِيثُ أَبِي سَعِيدٍ أَتَمُّ","id":"Telah menceritakan kepada kami [Musaddad] telah mengabarkan kepada kami [Qurran bin Tammam]. Dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Abdullah bin Sa'id] telah mengabarkan kepada kami [Abu Khalid], dan ini adalah redaksi dari dia, dari [Abdullah bin Abdurrahman bin Ya'laa] dari [Utsman bin Abdullah bin Aus] dari [kakeknya]. Abdullah bin Sa'id berkata dalam haditsnya Aus bin Hudzaifah, dia berkata; \"Kami mendatangi Rasulullah shallallahu 'alaihi wasallam dalam rombongan delegasi Bani Tsaqif, sekutu-sekutu (aliansi-aliansi) Tsaqif singgah menemui Al-Mughirah bin Syu'bah, sementara Rasulullah shallallahu 'alaihi wasallam memberi persinggahan kepada Bani Malik di tenda besar miliknya. Musaddad berkata dengan redaksi; \"Sedangkan seseorang dari utusan dari Tsaqif yang datang kepada Rasulullah shallallahu 'alaihi wasallam, berkata; \"Setiap habis Isya', beliau selalu menemui kami kami untuk bercakap-cakap.\" Abu Sa'id mengatakan; \"Sambil berdiri di atas salah satu kakinya secara berganti-gantian di antara kedua kakinya, karena lamanya berdiri. Dan yang paling banyak yang diceritakan adalah apa yang beliau alami dari kaumnya, Quraisy. Beliau bersabda: \"Tidaklah sama kami orang-orang yang lemah dan terhina - [Musaddad] berkata- selama kami di Makkah. Ketika kami keluar menuju Madinah, peperangan silih berganti di antara kami dan mereka. Terkadang kami mengalahkan mereka dan terkadang mereka mengalahkan kami.\" Di suatu malam, Beliau terlambat dari kebiasaan waktu kedatangannya kepada kami. Maka aku berkata, \"Anda terlambat datang kepada kami pada malam ini\". Beliau bersabda: \"Sesungguhnya telah datang kepadaku bagian yang aku harus baca dari Al-Qur'an, maka aku tidak senang untuk keluar hingga selesai menyempurnakannya.\" Aus berkata, \"Aku bertanya kepada para sahabat Rasulullah shallallahu 'alaihi wasallam, bagaimanakah kalian membagi-bagi (memilah atau mengelompokkan) dan menertibkan Al-Qur'an? Mereka menjawab: \"Tiga, lima, tujuh, sembilan, sebelas, tigabelas dan bagian surat-surat yang mufashshal (dari surat Qaaf atau al Hujurat sampai an nas).\" Abu Daud berkata; \"Haditsnya Abu Sa'id lebih lengkap.\""},"1157":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمِنْهَالِ الضَّرِيرُ أَخْبَرَنَا يَزِيدُ بْنُ زُرَيْعٍ أَخْبَرَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَبِي الْعَلَاءِ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ عَبْدِ اللَّهِ يَعْنِي ابْنَ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَفْقَهُ مَنْ قَرَأَ الْقُرْآنَ فِي أَقَلَّ مِنْ ثَلَاثٍ","id":"Telah menceritakan kepada kami [Muhammad bin Al Minhal Adl Dlarir] telah mengabarkan kepada kami [Yazid bin Zurai'] telah mengabarkan kepada kami [Sa'id] dari [Qatadah] dari [Abu Al 'Ala` Yazid bin Abdullah bin Asy Syihir] dari [Abdullah yaitu Ibnu 'Amru] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan dapat memahami orang yang membaca Al Qur'an kurang dari tiga hari.\""},"1158":{"ar":"حَدَّثَنَا نُوحُ بْنُ حَبِيبٍ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ سِمَاكِ بْنِ الْفَضْلِ عَنْ وَهْبِ بْنِ مُنَبِّهٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّهُ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي كَمْ يُقْرَأُ الْقُرْآنُ قَالَ فِي أَرْبَعِينَ يَوْمًا ثُمَّ قَالَ فِي شَهْرٍ ثُمَّ قَالَ فِي عِشْرِينَ ثُمَّ قَالَ فِي خَمْسَ عَشْرَةَ ثُمَّ قَالَ فِي عَشْرٍ ثُمَّ قَالَ فِي سَبْعٍ لَمْ يَنْزِلْ مِنْ سَبْعٍ","id":"Telah menceritakan kepada kami [Nuh bin Habib] telah mengabarkan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Simak bin Al Fadl] dari [Wahb bin Munabbih] dari [Abdullah bin 'Amru] bahwa dia bertanya kepada Nabi shallallahu 'alaihi wasallam; \"Berapa lamakah Al Qur'an di baca (hingga khatam)?\" beliau bersabda: \"Dalam jangka waktu empat puluh hari.\" Kemudian beliau bersabda: \"Dalam jangka waktu sebulan.\" Kemudian beliau bersabda: \"Dalam jangka waktu dua puluh hari.\" Kemudian beliau bersabda: \"Dalam jangka waktu lima belas hari.\" Kemudian beliau bersabda: \"Dalam jangka waktu sepuluh hari.\" Kemudian beliau bersabda: \"Dalam jangka waktu tujuh hari, dan tidak kurang dari tujuh hari.\""},"1159":{"ar":"حَدَّثَنَا عَبَّادُ بْنُ مُوسَى أَخْبَرَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ عَلْقَمَةَ وَالْأَسْوَدِ قَالَاأَتَى ابْنَ مَسْعُودٍ رَجُلٌ فَقَالَ إِنِّي أَقْرَأُ الْمُفَصَّلَ فِي رَكْعَةٍ فَقَالَ أَهَذًّا كَهَذِّ الشِّعْرِ وَنَثْرًا كَنَثْرِ الدَّقَلِ لَكِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ النَّظَائِرَ السُّورَتَيْنِ فِي رَكْعَةٍ النَّجْمَ وَالرَّحْمَنَ فِي رَكْعَةٍ وَاقْتَرَبَتْ وَالْحَاقَّةَ فِي رَكْعَةٍ وَالطُّورَ وَالذَّارِيَاتِ فِي رَكْعَةٍ وَإِذَا وَقَعَتْ وَنُونَ فِي رَكْعَةٍ وَسَأَلَ سَائِلٌ وَالنَّازِعَاتِ فِي رَكْعَةٍ وَوَيْلٌ لِلْمُطَفِّفِينَ وَعَبَسَ فِي رَكْعَةٍ وَالْمُدَّثِّرَ وَالْمُزَّمِّلَ فِي رَكْعَةٍ وَهَلْ أَتَى وَلَا أُقْسِمُ بِيَوْمِ الْقِيَامَةِ فِي رَكْعَةٍ وَعَمَّ يَتَسَاءَلُونَ وَالْمُرْسَلَاتِ فِي رَكْعَةٍ وَالدُّخَانَ وَإِذَا الشَّمْسُ كُوِّرَتْ فِي رَكْعَةٍقَالَ أَبُو دَاوُد هَذَا تَأْلِيفُ ابْنِ مَسْعُودٍ رَحِمَهُ اللَّهُ","id":"Telah menceritakan kepada kami ['Abbad bin Musa] telah mengabarkan kepada kami [Isma'il bin Ja'far] dari [Isra`il] dari [Abu Ishaq] dari ['Alqomah] dan [Al Aswad] keduanya berkata; seorang laki-laki datang kepada [Ibnu Mas'ud] seraya berkata; \"Aku biasa membaca Al Mufashal (dari surat Qaaf atau Al Hujurat sampai an Naas) dalam satu raka'at.\" Maka Ibnu Mas'ud berkata; \"Apakah membaca al Qur'an itu seperti melantunkan sya'ir atau prosa prosa tentang runtuhnya kurma dari pohonnya? Padahal Nabi shallallahu 'alaihi wasallam biasa membaca surat-surat yang sepadan, dua surat dalam satu raka'at, yaitu An Najm dan Ar Rahman dalam satu raka'at.\"Iqtarabat\" dan \"Al Haqqah\" dalam satu raka'at.\"At Thur\" dan \"Adz Dzariyat\" dalam satu raka'at.\"Idza Waqa'at\" dan \"Nuun\" dalam satu raka'at.\"sa`ala saa`ilu\" dan \"wan naazi'aati\" dalam satu raka'at.\"wailul lil muthaffifin\" dan \"abasa\" dalam satu raka'at.\"Al Mudattsir\" dan \"Al Muzammil\" dalam satu raka'at.\"Hal attaa\" dan \"Laa uqsimu bi yaumil Qiyaamah\" dalam satu raka'at.\"Amma yatasaa`alun\" dan \"Wal mursalaati\" dalam satu raka'at.\"Ad dukhaan\" dan \"Idzas syamsu kuwwirat\" dalam satu raka'at.\" Abu Daud berkata; \"Ini adalah tulisan Ibnu Mas'ud rahimahullah.\""},"1160":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ أَخْبَرَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَقَالَ سَأَلْتُ أَبَا مَسْعُودٍ وَهُوَ يَطُوفُ بِالْبَيْتِ فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَرَأَ الْآيَتَيْنِ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ فِي لَيْلَةٍ كَفَتَاهُ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah mengabarkan kepada kami [Syu'bah] dari [Manshur] dari [Ibrahim] dari [Abdurrahman bin Yazid] dia berkata; aku pernah bertanya kepada [Abu Mas'ud] ketika dia sedang Thawaf di Ka'bah, dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membaca dua ayat dari akhir surat Al Baqarah pada malam harinya, maka dianggap cukup.\" "},"1161":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنَا عَمْرٌو أَنَّ أَبَا سَوِيَّةَ حَدَّثَهُ أَنَّهُ سَمِعَ ابْنَ حُجَيْرَةَ يُخْبِرُ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَامَ بِعَشْرِ آيَاتٍ لَمْ يُكْتَبْ مِنْ الْغَافِلِينَ وَمَنْ قَامَ بِمِائَةِ آيَةٍ كُتِبَ مِنْ الْقَانِتِينَ وَمَنْ قَامَ بِأَلْفِ آيَةٍ كُتِبَ مِنْ الْمُقَنْطِرِينَقَالَ أَبُو دَاوُد ابْنُ حُجَيْرَةَ الْأَصْغَرُ عَبْدُ اللَّهِ ابْنُ عَبْدِ الرَّحْمَنِ ابْنِ حُجَيْرَةَ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepada kami ['Amru] bahwa [Abu Sawiyah] telah mengabarkan kepadanya, bahwa dia pernah mendengar [Ibnu Hujairah] mengabarkan dari [Abdullah bin 'Amru bin Al 'Ash] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bangun (shalat malam) dan membaca sepuluh ayat, maka dia tidak akan di catat sebagai orang-orang yang lalai. Barangsiapa bangun (shalat malam) dengan membaca seratus ayat, maka dia akan di catat sebagai orang-orang yang tunduk dan patuh, dan barangsiapa bangun (shalat malam) dengan membaca seribu ayat, maka dia akan di catat sebagai orang-orang yang dermawan.\" Abu Daud berkata; Ibnu Hujairah Al Ashgar adalah Abdullah bin Abdurrahman ibnu Hujairah.\""},"1162":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى الْبَلْخِيُّ وَهَارُونُ بْنُ عَبْدِ اللَّهِ قَالَا أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ أَخْبَرَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ حَدَّثَنِي عَيَّاشُ بْنُ عَبَّاسٍ الْقِتْبَانِيُّ عَنْ عِيسَى بْنِ هِلَالٍ الصَّدَفِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَأَتَى رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَقْرِئْنِي يَا رَسُولَ اللَّهِ فَقَالَ اقْرَأْ ثَلَاثًا مِنْ ذَوَاتِ الر فَقَالَ كَبُرَتْ سِنِّي وَاشْتَدَّ قَلْبِي وَغَلُظَ لِسَانِي قَالَ فَاقْرَأْ ثَلَاثًا مِنْ ذَوَاتِ حاميم فَقَالَ مِثْلَ مَقَالَتِهِ فَقَالَ اقْرَأْ ثَلَاثًا مِنْ الْمُسَبِّحَاتِ فَقَالَ مِثْلَ مَقَالَتِهِ فَقَالَ الرَّجُلُ يَا رَسُولَ اللَّهِ أَقْرِئْنِي سُورَةً جَامِعَةً فَأَقْرَأَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا زُلْزِلَتْ الْأَرْضُ حَتَّى فَرَغَ مِنْهَا فَقَالَ الرَّجُلُ وَالَّذِي بَعَ��َكَ بِالْحَقِّ لَا أَزِيدُ عَلَيْهَا أَبَدًا ثُمَّ أَدْبَرَ الرَّجُلُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْلَحَ الرُّوَيْجِلُ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Yahya bin Musa Al Balhi] dan [Harun bin Abdullah] keduanya berkata; telah mengabarkan kepada kami [Abdullah bin Yazid] telah mengabarkan kepada kami [Sa'id bin Abu Ayyub] telah menceritakan kepadaku ['Ayyasy bin Abbas Al Qitbani] dari [Isa bin Hilal Ash Shadafi] dari [Abdullah bin 'Amru] dia berkata; seorang laki-laki datang kepada Rasulullah shallallahu 'alaihi wasallam sambil berkata; \"Wahai Rasulullah, koreksilah bacaanku!\" Maka beliau pun berkata kepadanya: \"Bacalah tiga surat yang di dahului Alif Laam Ra'.\" Lelaki itu berkata; \"Umurku sudah tua, dan hatiku sudah mengeras, serta lidahku juga sudah kelu.\" Beliau berkata: \"Kalau begitu bacalah surat yang di dahului Haa' Mim.\" Maka lelaki itupun mengatakan seperti perkataannya yang tadi. Beliau berkata: \"Bacalah tiga surat yang diawali dengan sabbaha.\" Dan lelaki itupun mengatakan seperti perkataannya yang pertama, lalu dia mengatakan, \"Wahai Rasulullah, yang aku mau anda membacakan kepadaku satu surat yang mencakup keseluruhan.\" Maka beliau menyuruhnya membaca surat Idzaa zulzilatil ardlu, hingga selesai. Laki-laki itu berkata; \"Demi Dzat Yang telah mengutusmu dengan kebenaran, aku tidak akan menambahinya untuk selamanya.\" Lalu orang itupun berpaling dan pergi meninggalkan beliau, lalu Rasulullah pun bersabda: \"Sungguh beruntung orang itu, sungguh beruntung orang itu\" Beliau mengucapkannya hingga dua kali. "},"1163":{"ar":"حَدَّثَنَا عَمْرُو بْن�� مَرْزُوقٍ أَخْبَرَنَا شُعْبَةُ أَخْبَرَنَا قَتَادَةُ عَنْ عَبَّاسٍ الْجُشَمِيِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سُورَةٌ مِنْ الْقُرْآنِ ثَلَاثُونَ آيَةً تَشْفَعُ لِصَاحِبِهَا حَتَّى يُغْفَرَ لَهُ تَبَارَكَ الَّذِي بِيَدِهِ الْمُلْكُ","id":"Telah menceritakan kepada kami ['Amru bin Marzuq] telah mengabarkan kepada kami [Syu'bah] telah mengabarkan kepada kami [Qatadah] dari ['Abbas Al Jusyami] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda: 'Ada suatu surat dari al qur'an yang terdiri dari tiga puluh ayat dan dapat memberi syafa'at bagi yang membacanya, sampai dia di ampuni, yaitu; \"Tabaarakalladzii biyadihil mulku…\""},"1164":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ بْنِ الْبَرْقِيِّ حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا نَافِعُ بْنُ يَزِيدَ عَنْ الْحَارِثِ بْنِ سَعِيدٍ الْعُتَقِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مُنَيْنٍ مِنْ بَنِي عَبْدِ كُلَالٍ عَنْ عَمْرِو بْنِ الْعَاصِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْرَأَهُ خَمْسَ عَشْرَةَ سَجْدَةً فِي الْقُرْآنِ مِنْهَا ثَلَاثٌ فِي الْمُفَصَّلِ وَفِي سُورَةِ الْحَجِّ سَجْدَتَانِقَالَ أَبُو دَاوُد رُوِيَ عَنْ أَبِي الدَّرْدَاءِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِحْدَى عَشْرَةَ سَجْدَةً وَإِسْنَادُهُ وَاهٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim bin Al Buraqi] telah menceritakan kepada kami [Ibnu Abu Maryam] telah mengabarkan kepada kami [Nafi' bin Yazid] dari [Al Harits bin Sa'id Al 'Utaqi] dari [Abdullah bin Munain] dari Bani Abdul Kulal, dari ['Amru bin Al 'Ash] bahwa Rasulullah shallallahu 'alaihi wasallam pernah membacakan untuknya lima belas ayat sajadah dalam Al Qur'an, di antaranya tiga ayat terdapat dalam surat Al Mufashal (dari surat Qaaf atau Al Hujurat sampai an naas), dan dalam surat Al Hajj dua ayat sajadah.\" Abu Daud berkata; \"di riwayatkan dari Abu Darda` dari Nabi shallallahu 'alaihi wasallam terdapat sebelas ayat sajadah, sedangkan sanadnya lemah.\""},"1165":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي ابْنُ لَهِيعَةَ أَنَّ مِشْرَحَ بْنَ هَاعَانَ أَبَا الْمُصْعَبِ حَدَّثَهُ أَنَّ عُقْبَةَ بْنَ عَامِرٍ حَدَّثَهُ قَالَقُلْتُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفِي سُورَةِ الْحَجِّ سَجْدَتَانِ قَالَ نَعَمْ وَمَنْ لَمْ يَسْجُدْهُمَا فَلَا يَقْرَأْهُمَا","id":"Telah menceritakan kepada kami [Ahmad bin 'Amru bin As Sarh] telah mengabarkan kepada kami [Ibnu Wahb] telah menceritakan kepadaku [Ibnu Lahi'ah] bahwa [Misrah bin Ha'an Abu Al Mush'ab] telah bercerita kepadanya bahwa ['Ubah bin 'Amir] telah menceritakan kepadanya, dia berkata; aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam; \"Apakah dalam surat Al Haj terdapat dua ayat sajadah?\" beliau menjawab: \"ya, benar. Barangsiapa tidak sujud ketika membacanya, maka janganlah ia membaca kedua ayat sajadah tersebut.\""},"1166":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا أَزْهَرُ بْنُ الْقَاسِمِ قَالَ مُحَمَّدٌ رَأَيْتُهُ بِمَكَّةَ حَدَّثَنَا أَبُو قُدَامَةَ عَنْ مَطَرٍ الْوَرَّاقِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَسْجُدْ فِي شَيْءٍ مِنْ الْمُفَصَّلِ مُنْذُ تَحَوَّلَ إِلَى الْمَدِينَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Azhar bin Al Qasim] -Muhammad mengatakan; \"aku mengetahuinya ketika dia berada di Makkah- telah menceritakan kepada kami [Abu Qudamah] dari [Mathar Al Waraq] dari [Ikrimah] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam tidak pernah sujud sama sekali ketika membaca surat Al Mufashal (dari surat Qaaf atau Al Hujurat sampai An Naas) hingga beliau pindah ke Madinah.\""},"1167":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا وَكِيعٌ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ قُسَيْطٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَقَرَأْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّجْمَ فَلَمْ يَسْجُدْ فِيهَاحَدَّثَنَا ابْنُ السَّرْحِ أَخْبَرَنَا ابْنُ وَهْبٍ حَدَّثَنَا أَبُو صَخْرٍ عَنْ ابْنِ قُسَيْطٍ عَنْ خَارِجَةَ بْنِ زَيْدِ بْنِ ثَابِتٍ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ قَالَ أَبُو دَاوُد كَانَ زَيْدٌ الْإِمَامَ فَلَمْ يَسْجُدْ فِيهَا","id":"Telah menceritakan kepada kami [Hannad bin As Sarri] telah menceritakan kepada kami [Waki'] dari [Abu Ad Dzi`b] dari [Yazid bin Abdullah bin Qusaith] dari ['Atha` bin Yasar] dari [Zaid bin Tsabit] dia berkata; \"Aku pernah membaca surat An Najm di hadapan Rasulullah shallallahu 'alaihi wasallam, namun beliau tidak sujud.\" Telah menceritakan kepada kami [Ibnu As Sarh] telah mengabarkan kepada kami [Ibnu Wahb] telah menceritakan kepada kami [Abu Shakhr] dari [Ibnu Qusaith] dari [Kharijah bin Zaid bin Tsabit] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam semakna dengan hadits di atas. Abu Daud berkata; \"Zaid adalah seorang Imam, namun dia tidak sujud ketika membaca surat tersebut.\""},"1168":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ سُورَةَ النَّجْمِ فَسَجَدَ فِيهَا وَمَا بَقِيَ أَحَدٌ مِنْ الْقَوْمِ إِلَّا سَجَدَ فَأَخَذَ رَجُلٌ مِنْ الْقَوْمِ كَفًّا مِنْ حَصًى أَوْ تُرَابٍ فَرَفَعَهُ إِلَى وَجْهِهِ وَقَالَ يَكْفِينِي هَذَاقَالَ عَبْدُ اللَّهِ فَلَقَدْ رَأَيْتُهُ بَعْدَ ذَلِكَ قُتِلَ كَافِرًا","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al Aswad] dari [Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam pernah membaca surat An Najm, lalu beliau sujud, dan tidak seorang pun dari kaum tersebut yang tidak turut sujud. Setelah itu seorang laki-laki dari kaum tersebut mengambil segenggam kerikil atau tanah, lalu di angkat ke wajahnya sambil berkata; \"Sujud bagiku cukuplah sekali ini saja.\" Abdullah berkata; \"Sungguh, setelah peristiwa tersebut, aku melihat laki-laki tersebut mati terbunuh dalam keadaan kafir.\" "},"1169":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ عَطَاءِ بْنِ مِينَاءَ عَنْ أَبِي هُرَيْرَةَ قَالَسَجَدْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي إِذَا السَّمَاءُ انْشَقَّتْ وَاقْرَأْ بِاسْمِ رَبِّكَ الَّذِي خَلَقَقَالَ أَبُو دَاوُد أَسْلَمَ أَبُو هُرَيْرَةَ سَنَةَ سِتٍّ عَامَ خَيْبَرَ وَهَذَا السُّجُودُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آخِرُ فِعْلِهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Sufyan] dari [Ayyub bin Musa] dari ['Atha` bin Mina`] dari [Abu Hurairah] dia berkata; \"Kami pernah bersujud (tilawah) bersama Rasulullah shallallahu 'alaihi wasallam pada surat \"idzaas samaa'un syaqqat\" dan \"iqra` bismirabbikal ladzii khalaq\" Abu Daud berkata; \"Abu Hurairah masuk Islam pada tahun ke enam (hijriyah) yaitu ketika hari penaklukan Khaibar, sedangkan sujud ini adalah yang terakhir kali di kerjakan oleh Rasulullah shallallahu 'alaihi wasallam.\""},"1170":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ أَبِي حَدَّثَنَا بَكْرٌ عَنْ أَبِي رَافِعٍ قَالَصَلَّيْتُ مَعَ أَبِي هُرَيْرَةَ الْعَتَمَةَ فَقَرَأَ إِذَا السَّمَاءُ انْشَقَّتْ فَسَجَدَ فَقُلْتُ مَا هَذِهِ السَّجْدَةُ قَالَ سَجَدْتُ بِهَا خَلْفَ أَبِي الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا أَزَالُ أَسْجُدُ بِهَا حَتَّى أَلْقَاهُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Al Mu'tamir] dia berkata; saya mendengar [ayahku], telah menceritakan kepada kami [Bakr] dari [Abu Rafi'] dia berkata; \"Aku pernah shalat Isya' bersama [Abu Hurairah], lalu dia membaca; \"Idzas samaa'un syaqqat\" kemudian dia sujud.\" Aku pun bertanya; \"Sujud apakah ini?\" dia menjawab; \"Aku juga pernah sujud seperti ini di belakang Abu Qasim shallallahu 'alaihi wasallam, dan aku akan senantiasa sujud pada bacaan ini sehingga aku bertemu dengan-Nya (meninggal dunia).\""},"1171":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَلَيْسَ ص مِنْ عَزَائِمِ السُّجُودِ وَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْجُدُ فِيهَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] dia berkata; Surat Shaad sebenarnya bukan termasuk surat yang di haruskan untuk sujud, akan tetapi aku pernah melihat Rasulullah shallallahu 'alaihi wasallam sujud pada surat tersebut.\""},"1172":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو يَعْنِي ابْنَ الْحَارِثِ عَنْ ابْنِ أَبِي هِلَالٍ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ بْنِ سَعْدِ بْنِ أَبِي سَرْحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّهُ قَالَقَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الْمِنْبَرِ ص فَلَمَّا بَلَغَ السَّجْدَةَ نَزَلَ فَسَجَدَ وَسَجَدَ النَّاسُ مَعَهُ فَلَمَّا كَانَ يَوْمٌ آخَرُ قَرَأَهَا فَلَمَّا بَلَغَ السَّجْدَةَ تَشَزَّنَ النَّاسُ لِلسُّجُودِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا هِيَ تَوْبَةُ نَبِيٍّ وَلَكِنِّي رَأَيْتُكُمْ تَشَزَّنْتُمْ لِلسُّجُودِ فَنَزَلَ فَسَجَدَ وَسَجَدُوا","id":"Telah menceritakan kepada Kami [Ahmad bin Shalih] telah menceritakan kepada Kami [Ibnu Wahb], telah mengkhabarkan kepadaku ['Amr yaitu Ibnu Al Harits] dari [Ibnu Abu Hilal] dari ['Iyadh bin Abdullah bin Sa'd bin Abu Sarh] dari [Abu Sa'id Al Khudri] bahwa ia berkata; Rasulullah shallallahu 'alaihi wasallam di atas mimbar membaca Surat Shaad. Kemudian tatkala beliau telah sampai pada ayat as sajdah beliau turun kemudian sujud, dan orang-orang pun bersujud bersamanya. Kemudian tatkala pada hari yang lainnya beliau membacanya, lalu tatkala telah sampai pada ayat as sajdah orang-orang bersiap-siap untuk bersujud. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya ayat tersebut adalah taubat seorang nabi, akan tetapiaku melihat kalian telah bersiap-siap untuk bersujud, lalu beliau bersujud dan mereka pun bersujud.\""},"1173":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُثْمَانَ الدِّمَشْقِيُّ أَبُو الْجَمَاهِرِ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ مُصْعَبِ بْنِ ثَابِتِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ عَامَ الْفَتْحِ سَجْدَةً فَسَجَدَ النَّاسُ كُلُّهُمْ مِنْهُمْ الرَّاكِبُ وَالسَّاجِدُ فِي الْأَرْضِ حَتَّى إِنَّ الرَّاكِبَ لَيَسْجُدُ عَلَى يَدِهِ","id":"Telah menceritakan kepada Kami [Muhammad bin Utsman Ad Dimasyqi Abu Al Jamahir], telah menceritakan kepada Kami [Abdul Aziz yaitu Ibnu Muhammad] dari [Mush'ab bin Tsabit bin Abdullah bin Az Zubair] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam pada saat penaklukan Mekkah membaca ayat Sajdah, kemudian seluruh manusia bersujud, diantara mereka ada yang berkendaraan dan ada yang bersujud di tanah hingga orang yang berkendaraan bersujud di atas tangannya."},"1174":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ ح و حَدَّثَنَا أَحْمَدُ بْنُ أَبِي شُعَيْبٍ الْحَرَّانِيُّ حَدَّثَنَا ابْنُ نُمَيْرٍ الْمَعْنَى عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ عَلَيْنَا السُّورَةَ قَالَ ابْنُ نُمَيْرٍ فِي غَيْرِ الصَّلَاةِ ثُمَّ اتَّفَقَا فَيَسْجُدُ وَنَسْجُدُ مَعَهُ حَتَّى لَا يَجِدَ أَحَدُنَا مَكَانًا لِمَوْضِعِ جَبْهَتِهِ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Yahya bin Sa'id], dan diriwayatkan dari jalur yang lain: Telah menceritakan kepada Kami [Ahmad bin Abu Syu'aib Al Harrani] telah menceritakan kepada Kami [Ibnu Numair] secara makna dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam membacakan kepada Kami sebuah surat. Ibnu Numair berkata; tidak ketika melakukan shalat. Kemudian keduanya sama lafazh mereka yaitu, \"Kemudian beliau bersujud dan Kamipun bersujud bersamanya hingga salah seorangpun diantara Kami yang tidak mendapatkan tempat untuk meletakkan keningnya."},"1175":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْفُرَاتِ أَبُو مَسْعُودٍ الرَّازِيُّ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ عَلَيْنَا الْقُرْآنَ فَإِذَا مَرَّ بِالسَّجْدَةِ كَبَّرَ وَسَجَدَ وَسَجَدْنَا مَعَهُقَالَ عَبْدُ الرَّزَّاقِ وَكَانَ الثَّوْرِيُّ يُعْجِبُهُ هَذَا الْحَدِيثُ قَالَ أَبُو دَاوُد يُعْجِبُهُ لِأَنَّهُ كَبَّرَ","id":"Telah menceritakan kepada Kami [Ahmad bin Al Furat Abu Mas'ud Ar Razi] telah mengabarkan kepada Kami [Abdurrazzaq], telah mengabarkan kepada Kami [Abdullah bin Umar] dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam membacakan Al Qur'an kepada Kami, dan apabila melewati ayat sajdah beliau bertakbir dan bersujud dan Kami bersujud bersamanya. Abdurrazzaq berkata; Ats Tsauri kagum dengan hadits ini. Abu Daud berkata; ia kagum kepada hadits tersebut karena disebutkan bahwa Rasulullah shallallahu 'alaihi wasallam bertakbir."},"1176":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَعِيلُ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ رَجُلٍ عَنْ أَبِي الْعَالِيَةِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي سُجُودِ الْقُرْآنِ بِاللَّيْلِ يَقُولُ فِي السَّجْدَةِ مِرَارًا سَجَدَ وَجْهِي لِلَّذِي خَلَقَهُ وَشَقَّ سَمْعَهُ وَبَصَرَهُ بِحَوْلِهِ وَقُوَّتِهِ","id":"Telah menceritakan kepada Kami [Musaddad] telah menceritakan kepada Kami [Isma'il], telah menceritakan kepada Kami [Khalid Al Hadzdza`] dari [seorang laki-laki] dari [Abu Al 'Aliyah] dari [Aisyah] radliallahu 'anha ia berkata; \" Rasulullah shallallahu 'alaihi wasallam ketika melakukan sujud Al Qur'an (sajdah) pada malam hari beliau mengucapkan beberapa kali: \" SAJADA WAJHIYA LILLADZII KHALAQAHU WA SYAQQA SAM'AHU WA BASHARAHU BIHAULIHI WA QUWWATIHI\" (Wajahku bersujud kepada Dzat yang telah menciptakannya dan telah membuka pendengaran serta penglihatannya dengan daya dan kekuatanNya). "},"1177":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الصَّبَّاحِ الْعَطَّارُ حَدَّثَنَا أَبُو بَحْرٍ حَدَّثَنَا ثَابِتُ بْنُ عُمَارَةَ حَدَّثَنَا أَبُو تَمِيمَةَ الْهُجَيْمِيُّ قَالَلَمَّا بَعَثْنَا الرَّكْبَ قَالَ أَبُو دَاوُد يَعْنِي إِلَى الْمَدِينَةِ قَالَ كُنْتُ أَقُصُّ بَعْدَ صَلَاةِ الصُّبْحِ فَأَسْجُدُ فَنَهَانِي ابْنُ عُمَرَ فَلَمْ أَنْتَهِ ثَلَاثَ مِرَارٍ ثُمَّ عَادَ فَقَالَ إِنِّي صَلَّيْتُ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَ أَبِي بَكْرٍ وَعُمَرَ وَعُثْمَانَ رَضِيَ اللَّهُ عَنْهُمْ فَلَمْ يَسْجُدُوا حَتَّى تَطْلُعَ الشَّمْسُ","id":"Telah menceritakan kepada Kami [Abdullah bin Ash Shabah Al 'Aththar], telah menceritakan kepada Kami [Abu Bahr], telah menceritakan kepada Kami [Tsabit bin 'Umarah], telah menceritakan kepada Kami [Abu Tamimah Al Hujaimi], ia berkata; tatkala Kami mengutus seorang penunggang kuda... Abu Daud berkata; yaitu ia menuju ke Madinah ia berkata; saya membaca (ayat As Sajdah) setelah sholat Subuh, kemudian aku bersujud, lalu [Ibnu Umar] melarangku dan aku tidak berhenti hingga tiga kali. Kemudian ia kembali dan berkata; sesungguhnya aku pernah melakukan shalat di belakang Rasulullah shallAllahu wa'alaihi wa sallam bersama Abu Bakr, Umar dan Utsman radliallahu 'anhum dan mereka tidak bersujud hingga matahari terbit. "},"1178":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا عِيسَى عَنْ زَكَرِيَّا عَنْ أَبِي إِسْحَقَ عَنْ عَاصِمٍ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَهْلَ الْقُرْآنِ أَوْتِرُوا فَإِنَّ اللَّهَ وِتْرٌ يُحِبُّ الْوِتْرَحَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو حَفْصٍ الْأَبَّارُ عَنْ الْأَعْمَشِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ زَادَ فَقَالَ أَعْرَابِيٌّ مَا تَقُولُ فَقَالَ لَيْسَ لَكَ وَلَا لِأَصْحَابِكَ","id":"Telah menceritakan kepada [Ibrahim bin Musa] telah mengabarkan kepada Kami [Isa] dari [Zakaria] dari [Abu Ishaq] dari ['Ashim] dari [Ali] radliallahu 'anhu ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam berkata; wahai ahli Al Qur'an, shalat witirlah kalian karena Allah adalah Dzat yang Maha Tunggal dan menyukai sesuatu yang ganjil. Telah berkata kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Abu Hafsh Al Abbar] dari [Al A'masy] dari ['Amr bin Murrah] dari [Abu Ubaidah] dari [Abdullah] dari Nabi Shalla Allahu 'alaihi wa sallam dengan makna yang sama namun ia menambahkan; kemudian terdapat seorang badui berkata; apa yang kamu katakan? Dia menjawab; bukan urusanmu dan bukan urusan para sahabatmu. "},"1179":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ وَقُتَيْبَةُ بْنُ سَعِيدٍ الْمَعْنَى قَالَا حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عَبْدِ اللَّهِ بْنِ رَاشِدٍ الزَّوْفِيِّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُرَّةَ الزَّوْفِيِّ عَنْ خَارِجَةَ بْنِ حُذَافَةَ قَالَ أَبُو الْوَلِيدِ الْعَدَوِيُّخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ قَدْ أَمَدَّكُمْ بِصَلَاةٍ وَهِيَ خَيْرٌ لَكُمْ مِنْ حُمْرِ النَّعَمِ وَهِيَ الْوِتْرُ فَجَعَلَهَا لَكُمْ فِيمَا بَيْنَ الْعِشَاءِ إِلَى طُلُوعِ الْفَجْرِ","id":"Telah menceritakan kepada Kami [Abul Walid Ath Thayalisi] dan [Qutaibah bin Sa'id] secara makna, mereka mengatakan; telah menceritakan kepada Kami [Al Laits] dari [Yazid bin Abu Habib] dari [Abdullah bin Rasyid Az Zaufi] dari [Abdullah bin Abu Murrah Az Zaufi] dari [Kharijah bin Hudzafah], Abu Al Walid Al Adawi berkata; Rasulullah shallAllahu wa'alaihi wa sallam keluar menemui Kami dan berkata: \"Sesungguhnya Allah telah mewajibkan bagi kalian sebuah shalat yang dia lebih baik bagi kalian dari pada unta merah, yaitu shalat witir, dan telah menjadikannya berada diantara shalat Isya hingga terbit fajar.\""},"1180":{"ar":"حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا أَبُو إِسْحَقَ الطَّالْقَانِيُّ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ الْعَتَكِيِّ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْوِتْرُ حَقٌّ فَمَنْ لَمْ يُوتِرْ فَلَيْسَ مِنَّا الْوِتْرُ حَقٌّ فَمَنْ لَمْ يُوتِرْ فَلَيْسَ مِنَّا الْوِتْرُ حَقٌّ فَمَنْ لَمْ يُوتِرْ فَلَيْسَ مِنَّا","id":"Telah menceritakan kepada Kami [Ibnu Al Mutsanna], telah menceritakan kepada Kami [Abu Ishaq Ath Thaqani], telah menceritakan kepada Kami [Al Fadhl bin Musa] dari ['Ubaidullah bin Abdullah Al 'Ataki] dari [Abdullah bin Buraidah] dari [ayahnya], ia berkata; saya mendengar Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Shalat witir adalah sebuah hak, barang siapa yang tidak melakukan shalat witir maka ia bukan dari golongan Kami, shalat witir adalah sebuah hak, barang siapa yang tidak melakukan shalat witir maka bukan dari golongan Kami, shalat witir adalah sebuah hak, barang siapa yang tidak melakukan shalat witir, barang siapa yang tidak melakukan shalat witir maka bukan dari golongan Kami.\""},"1181":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ ابْنِ مُحَيْرِيزٍأَنَّ رَجُلًا مِنْ بَنِي كِنَانَةَ يُدْعَى الْمَخْدَجِيَّ سَمِعَ رَجُلًا بِالشَّامِ يُدْعَى أَبَا مُحَمَّدٍ يَقُولُ إِنَّ الْوِتْرَ وَاجِبٌ قَالَ الْمَخْدَجِيُّ فَرُحْتُ إِلَى عُبَادَةَ بْنِ الصَّامِتِ فَأَخْبَرْتُهُ فَقَالَ عُبَادَةُ كَذَبَ أَبُو مُحَمَّدٍ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ خَمْسُ صَلَوَاتٍ كَتَبَهُنَّ اللَّهُ عَلَى الْعِبَادِ فَمَنْ جَاءَ بِهِنَّ لَمْ يُضَيِّعْ مِنْهُنَّ شَيْئًا اسْتِخْفَافًا بِحَقِّهِنَّ كَانَ لَهُ عِنْدَ اللَّهِ عَهْدٌ أَنْ يُدْخِلَهُ الْجَنَّةَ وَمَنْ لَمْ يَأْتِ بِهِنَّ فَلَيْسَ لَهُ عِنْدَ اللَّهِ عَهْدٌ إِنْ شَاءَ عَذَّبَهُ وَإِنْ شَاءَ أَدْخَلَهُ الْجَنَّةَ","id":"Telah menceritakan kepada Kami [Al Qa'nabi] dari [Malik] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari [Ibnu Muhairiz] bahwa seorang laki-laki dari Bani Kinanah yang dipanggil Al Makhdaji telah mendengar seorang laki-laki di Syam yang dipanggil Abu Muhammad berkata; sesungguhnya shalat witir adalah wajib. [Al Makhdaji] berkata; kemudian aku pergi kepada 'Ubadah bin Ash Shamid dan mengabarkan hal tersebut kepadanya. ['Ubadah] berkata; Abu Muhammad telah berdusta, aku telah mendengar Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Lima shalat, telah Allah wajibkan bagi para hamba, barang siapa yang melakukannya dan tidak memenyia-nyiakan sedikitpun darinya karena meremehkan haknya maka baginya di sisi Allah sebuah perjanjian untuk Allah masukkan dirinya ke dalam Surga. Sedangkan orang yang tidak melaksanakannya maka ia tidak memiliki perjanjian di sisi Allah, apabila Allah menghendaki maka Dia akan menyiksanya aan apabila menghendaki maka Allah akan memasukkannya ke dalam Surga.\""},"1182":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ ابْنِ عُمَرَأَنَّ رَجُلًا مِنْ أَهْلِ الْبَادِيَةِ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَلَاةِ اللَّيْلِ فَقَالَ بِأُصْبُعَيْهِ هَكَذَا مَثْنَى مَثْنَى وَالْوِتْرُ رَكْعَةٌ مِنْ آخِرِ اللَّيْلِ","id":"Telah menceritakan kepada Kamin [Muhammad bin Katsir] telah mengabarkan kepada Kami [Hammam] dari [Qatadah] dari [Abdullah bin Syaqiq] dari [Ibnu Umar] bahwa seorang laki-laki badui bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai shalat malam. Kemudian beliau mengatakan menggunakan jari-jarinya: \"Dua, dua, dan witir satu reka'at pada akhir malam.\""},"1183":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْمُبَارَكِ حَدَّثَنِي قُرَيْشُ بْنُ حَيَّانَ الْعِجْلِيُّ حَدَّثَنَا بَكْرُ بْنُ وَائِلٍ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوِتْرُ حَقٌّ عَلَى كُلِّ مُسْلِمٍ فَمَنْ أَحَبَّ أَنْ يُوتِرَ بِخَمْسٍ فَلْيَفْعَلْ وَمَنْ أَحَبَّ أَنْ يُوتِرَ بِثَلَاثٍ فَلْيَفْعَلْ وَمَنْ أَحَبَّ أَنْ يُوتِرَ بِوَاحِدَةٍ فَلْيَفْعَلْ","id":"Telah menceritakan kepada Kami [Abdurrahman bin Al Mubarak], telah menceritakan kepadaku [Quraisy bin Hayyan Al 'Ijli] telah menceritakan kepada Kami [Bakr bin Wail] dari [Az Zuhri] dari ['Atha` bin Yazid Al Laitsi] dari [Abu Ayyub Al Anshari] ia berkata; rasul shallallahu 'alaihi wasallam bersabda: \"Witir adalah sebuah hak atas setiap muslim, barang siapa yang hendak melakukan witir lima raka'at maka hendaknya ia melakukankannya dan barang siapa yang hendak melakukan witir tiga raka'at maka hendaknya ia melakukannya, dan barang siapa yang hendak melakukan witir satu raka'at maka hendaknya ia melakukannya.\""},"1184":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو حَفْصٍ الْأَبَّارُ ح و حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا مُحَمَّدُ بْنُ أَنَسٍ وَهَذَا لَفْظُهُ عَنْ الْأَعْمَشِ عَنْ طَلْحَةَ وَزُبَيْدٍ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ لِلَّذِينَ كَفَرُوا وَاللَّهُ الْوَاحِدُ الصَّمَدُحَدَّثَنَا أَحْمَدُ بْنُ أَبِي شُعَيْبٍ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ حَدَّثَنَا خُصَيْفٌ عَنْ عَبْدِ الْعَزِيزِ بْنِ جُرَيْجٍ قَالَ سَأَلْتُ عَائِشَةَ أُمَّ الْمُؤْمِنِينَ بِأَيِّ شَيْءٍ كَانَ يُوتِرُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مَعْنَاهُ قَالَ وَفِي الثَّالِثَةِ بِقُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِ","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Abu Hafsh Al Abbar], dan diriwayatkan dari jalur yang lain: Telah menceritakan kepada Kami [Ibrahim bin Musa] telah mengabarkan kepada Kami [Muhammad bin Anas] dan ini adalah lafazhnya, dari [Al A'masy] dari [Thalhah] dan [Zubaid] dari [Sa'id? bin Abdurrahman bin Abza] dari [ayahnya] dari [Ubai bin Ka'bin] ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam melakukan witir dengan membaca \"Sabbihisma rabbikal a'laa\" (Surat Al A'la) dan \"Qul lilladzina kafaruu\" (Surat Al Kaafiruun) serta \"WAllahul wahidush shamad\" (Surat Al Ikhlash). Telah berkata kepada Kami [Ahmad bin Abu Syu'aib], telah menceritakan kepada Kami [Muhammad bin Salamah], telah menceritakan kepada Kami [Khushaif] dari [Abdul Aziz bin Juraij] berkata; aku bertanya kepada [Aisyah] ummul mukminin radhiyAllahu; surat apakah yang dibaca Rasulullah shallAllahu wa'alaihi wa sallam ketika melakukan witir? Kemudian ia menyebutkan maknanya; dan pada raka'at yang ketiga beliau membaca \"Qul Huwallaahu Ahad\" dan \"Mu'awwidzatain\" (Surat Al Falaq dan An Naas). "},"1185":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَأَحْمَدُ بْنُ جَوَّاسٍ الْحَنَفِيُّ قَالَا حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ بُرَيْدِ بْنِ أَبِي مَرْيَمَ عَنْ أَبِي الْحَوْرَاءِ قَالَ قَالَ الْحَسَنُ بْنُ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُمَاعَلَّمَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلِمَاتٍ أَقُولُهُنَّ فِي الْوِتْرِ قَالَ ابْنُ جَوَّاسٍ فِي قُنُوتِ الْوِتْرِ اللَّهُمَّ اهْدِنِي فِيمَنْ هَدَيْتَ وَعَافِنِي فِيمَنْ عَافَيْتَ وَتَوَلَّنِي فِيمَنْ تَوَلَّيْتَ وَبَارِكْ لِي فِيمَا أَعْطَيْتَ وَقِنِي شَرَّ مَا قَضَيْتَ إِنَّكَ تَقْضِي وَلَا يُقْضَى عَلَيْكَ وَإِنَّهُ لَا يَذِلُّ مَنْ وَالَيْتَ وَلَا يَعِزُّ مَنْ عَادَيْتَ تَبَارَكْتَ رَبَّنَا وَتَعَالَيْتَحَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَقَ بِإِسْنَادِهِ وَمَعْنَاهُ قَالَ فِي آخِرِهِ قَالَ هَذَا يَقُولُ فِي الْوِتْرِ فِي الْقُنُوتِ وَلَمْ يَذْكُرْ أَقُولُهُنَّ فِي الْوِتْرِ أَبُو الْحَوْرَاءِ رَبِيعَةُ بْنُ شَيْبَانَ","id":"Telah menceritakan kepada Kami [Qutaibah bin Sa'id] dan [Ahmad bin Jawwas Al Hanafi] mereka berkata; telah menceritakan kepada Kami [Abu Al Ahwash] dari [Abu Ishaq] dari [Buraid bin Abu Maryam] dari [Abu Al Haura`], ia berkata; telah berkata [Al Hasan bin Ali radliallahu 'anhuma]; Rasulullah shallAllahu wa'alaihi wa sallam telah mengajarkan kepada beberapa kalimat yang aku ucapkan ketika melakukan witir.. Ibnu Hawwas berkata; ketika melakukan qunut witir yaitu; ALLAAHUMMAH DINII FIIMAN HADAIT, WA 'AAFINII FIIMAN TAWALLAIT, WA BAARIK LII FIIMAA A'THAIT, WA QINII SYARRA MAA QADHAIT, INNAKA TAQDHII WA LAA YUQDHAA 'ALAIK, WA INNAHU LAA YADZILLU MAN WAALAIT, WA LAA YA'IZZU MAN 'AADAIT, TABAARAKTA RABBANAA WA TA'AALAIT (Ya Allah, berilah aku petunjuk diantara orang-orang yang Engkau beri petunjuk, dan berilah aku keselamatan diantara orang-orang yang telah Engkau beri keselamatan, uruslah diriku diantara orang-orang yang telah Engkau urus, berkahilah untukku apa yang telah Engkau berikan kepadaku, lindungilah aku dari keburukan apa yang telah Engkau putuskan, sesungguhnya Engkau Yang memutuskan dan tidak diputuskan kepadaku, sesungguhnya tidak akan hina orang yang telah Engkau jaga dan Engkau tolong, dan tidak akan mulia orang yang Engkau musuhi. Engkau Maha Suci dan Maha Tinggi). Telah menceritakan kepada Kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada Kami [Zuhair], telah menceritakan kepada Kami [Abu Ishaq] dengan sanad serta maknannya, ia berkata pada akhir hadits tersebut; Abu Al Haura` Rabi'ah bin Syaiban mengatakan hal ini yaitu; beliau mengucapkan ketika melakukan qunud dalam witir: \"…..\" dan ia tidak menyebutkan; aku mengucapkannya dalam witir. "},"1186":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ هِشَامِ بْنِ عَمْرٍو الْفَزَارِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ فِي آخِرِ وِتْرِهِ اللَّهُمَّ إِنِّي أَعُوذُ بِرِضَاكَ مِنْ سُخْطِكَ وَبِمُعَافَاتِكَ مِنْ عُقُوبَتِكَ وَأَعُوذُ بِكَ مِنْكَ لَا أُحْصِي ثَنَاءً عَلَيْكَ أَنْتَ كَمَا أَثْنَيْتَ عَلَى نَفْسِكَقَالَ أَبُو دَاوُد هِشَامٌ أَقْدَمُ شَيْخٍ لِحَمَّادٍ وَبَلَغَنِي عَنْ يَحْيَى بْنِ مَعِينٍ أَنَّهُ قَالَ لَمْ يَرْوِ عَنْهُ غَيْرُ حَمَّادِ بْنِ سَلَمَةَ قَالَ أَبُو دَاوُد رَوَى عِيسَى بْنُ يُونُسَ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَنَتَ يَعْنِي فِي الْوِتْرِ قَبْلَ الرُّكُوعِ قَالَ أَبُو دَاوُد رَوَى عِيسَى بْنُ يُونُسَ هَذَا الْحَدِيثَ أَيْضًا عَنْ فِطْرِ بْنِ خَلِيفَةَ عَنْ زُبَيْدٍ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ وَرُوِيَ عَنْ حَفْصِ بْنِ غِيَاثٍ عَنْ مِسْعَرٍ عَنْ زُبَيْدٍ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَنَتَ فِي الْوِتْرِ قَبْلَ الرُّكُوعِ قَالَ أَبُو دَاوُد وَحَدِيثُ سَعِيدٍ عَنْ قَتَادَةَ رَوَاهُ يَزِيدُ بْنُ زُرَيْعٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ عَزْرَةَ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَذْكُرْ الْقُنُوتَ وَلَا ذَكَرَ أُبَيًّا وَكَذَلِكَ رَوَاهُ عَبْدُ الْأَعْلَى وَمُحَمَّدُ بْنُ بِشْرٍ الْعَبْدِيُّ وَسَمَاعُهُ بِالْكُوفَةِ مَعَ عِيسَى بْنِ يُونُسَ وَلَمْ يَذْكُرُوا الْقُنُوتَ وَقَدْ رَوَاهُ أَيْضًا هِشَامٌ الدَّسْتُوَائِيُّ وَشُعْبَةُ عَنْ قَتَادَةَ وَلَمْ يَذْكُرَا الْقُنُوتَ وَحَدِيثُ زُبَيْدٍ رَوَاهُ سُلَيْمَانُ الْأَعْمَشُ وَشُعْبَةُ وَعَبْدُ الْمَلِكِ بْنُ أَبِي سُلَيْمَانَ وَجَرِيرُ بْنُ حَازِمٍ كُلُّهُمْ عَنْ زُبَيْدٍ لَمْ يَذْكُرْ أَحَدٌ مِنْهُمْ الْقُنُوتَ إِلَّا مَا رُوِيَ عَنْ حَفْصِ بْنِ غِيَاثٍ عَنْ مِسْعَرٍ عَنْ زُبَيْدٍ فَإِنَّهُ قَالَ فِي حَدِيثِهِ إِنَّهُ قَنَتَ قَبْلَ الرُّكُوعِ قَالَ أَبُو دَاوُد وَلَيْسَ هُوَ بِالْمَشْهُورِ مِنْ حَدِيثِ حَفْصٍ نَخَافُ أَنْ يَكُونَ عَنْ حَفْصٍ عَنْ غَيْرِ مِسْعَرٍ قَالَ أَبُو دَاوُد وَيُرْوَى أَنَّ أُبَيًّا كَانَ يَقْنُتُ فِي النِّصْفِ مِنْ شَهْرِ رَمَضَانَ","id":"Telah menceritakan kepada Kami [Musa bin Isma'il], telah menceritakan kepada Kami [Hammad] dari [Hisyam bin 'Amr Al Fazari] dari [Abdurrahman bin Al Harits bin Hisyam] dari [Ali bin Abu Thalib] radliallahu 'anhu bahwa Rasulullah shallAllahu wa'alaihi wa sallam di akhir shalat witirnya membaca: \"ALLAAHUMMA INNII A'UUDZU BIRIDHAAKA MIN SAKHATHIKA WA BIMU'AAFAATIK, MIN 'UQUUBATIK, WA A'UUDZU BIKA MINKA LAA UHSHII TSANAA-AN 'ALAIK, ANTA KAMAA ATSNAITA 'ALAA NAFSIK.\" (Ya Allah, aku berlindung dengan keridhaanMU dari murkaMu dan kepada ampunanMu dari adzabMu, dan aku berlindung kepadaMu dariMu, aku tidak dapat menghitung pujian kepadaMu, Engkau sebagaimana yang telah Engkau puji diri-Mu). Abu Daud berkata; Hisyam adalah guru Hammad yang paling tua, dan telah sampai kepadaku dari Yahya bin Ma'in bahwa ia berkata; tidak ada yang meriwayatkan dari Hisyam selain Hammad bin Salamah. Abu Daud berkata; [Isa bin Yunus] telah meriwayatkan dari [Sa'id? bin Abu Arubah] dari [Qatadah] dari [Sa'id? bin Abdurrahman bin Abza] dari [bapaknya] dari [Ubai bin Ka'b] bahwa Rasulullah shallAllahu wa'alaihi wa sallam melaksanakan qunut pada waktu witir sebelum ruku'. Abu Daud berkata; [Isa bin Yunus] meriwayatkan hadits ini juga dari [Fithr bin Khalifah] dari [Zubaid] dari [Sa'id? bin Abdurrahman bin Abza] dari [ayahnya] dari [Ubai bin Ka'b] dari Nabi Shalla Allahu 'alaihi wa sallam seperti itu. Dan telah diriwayatkan dari [Hafsh bin ghiyats] dari [Mis'ar] dari [Zubaid] dari [Sa'id? bin Abdurrahman bin Abza] dari [ayahnya] dari [Ubai bin Ka'b] bahwa Rasulullah shallAllahu wa'alaihi wa sallam melakukan qunut pada waktu shalat witir sebelum ruku'. Abu Daud berkata; dan hadits Sa'id dari Qatadah diriwayatkan oleh [Yazid bin Zurai'] dari [Sa'id?] dari [Qatadah] dari [Azrah] dari [Sa'id? bin Abdurrahman bin Abza] dari [bapaknya] dari Nabi Shalla Allahu 'alaihi wa sallam, ia tidak menyebutkan qunut dan tidak pula menyebutkan Ubai. Dan begitu juga diriwayatkan oleh [Abdul A'la] dan [Muhammad bin Bisyr Al 'Abdi] dan ia mendengarnya di Kufah bersama [Isa bin Yunus] dan mereka tidak menyebutkan qunut. Dan telah diriwayatkan pula oleh [Hisyam Ad Dastuwa-i] dan [Syu'bah] dari [Qatadah] dan mereka berdua tidak menyebutkan qunut. Hadits Zubaid diriwayatkan oleh [Sulaiman Al A'masy], [Syu'bah], [Abdul Malik bin Abu Sulaiman] dan [Jarir bin Hazim], mereka semua meriwayatkan dari [Zubaid] dan tidak ada seorangpun dari mereka yang menyebutkan qunut kecuali hadits yang diriwayatkan dari [Hafsh bin ghiyats] dari [Mis'ar] dari [Zubaid], sesungguhnya ia menyebutkan dalam haditsnya bahwa beliau melakukan qunut sebelum ruku'. Abu Daud berkata; hal tersebut tidaklah yang dikenal dari hadits Hafsh, Kami hal tersebut berasal dari Hafsh dari selain Mis'ar. Abu Daud berkata; dan diriwayatkan bahwasanya [Ubai bin Kaab] melaksanakan witir pada pertengahan bulan Ramadhan. "},"1187":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ حَنْبَلٍ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا هِشَامٌ عَنْ مُحَمَّدٍ عَنْ بَعْضِ أَصْحَابِهِأَنَّ أُبَيَّ بْنَ كَعْبٍ أَمَّهُمْ يَعْنِي فِي رَمَضَانَ وَكَانَ يَقْنُتُ فِي النِّصْفِ الْآخِرِ مِنْ رَمَضَانَ","id":"Telah menceritakan kepada Kami [Ahmad bin Muhammad bin Hanbal], telah menceritakan kepada Kami [Muhammad bin Bakr], telah mengabarkan kepadaku [Hisyam] dari [Muhammad] dari [sebagian sahabatnya] bahwa [Ubai bin Ka'b] mengimami mereka pada bulan ramadhan dan dia qunut pada pertengahan terakhir bulan Ramadhan. "},"1188":{"ar":"حَدَّثَنَا شُجَاعُ بْنُ مَخْلَدٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا يُونُسُ بْنُ عُبَيْدٍ عَنْ الْحَسَنِ أَنَّعُمَرَ بْنَ الْخَطَّابِ جَمَعَ النَّاسَ عَلَى أُبَيِّ بْنِ كَعْبٍ فَكَانَ يُصَلِّي لَهُمْ عِشْرِينَ لَيْلَةً وَلَا يَقْنُتُ بِهِمْ إِلَّا فِي النِّصْفِ الْبَاقِي فَإِذَا كَانَتْ الْعَشْرُ الْأَوَاخِرُ تَخَلَّفَ فَصَلَّى فِي بَيْتِهِ فَكَانُوا يَقُولُونَ أَبَقَ أُبَيٌّقَالَ أَبُو دَاوُد وَهَذَا يَدُلُّ عَلَى أَنَّ الَّذِي ذُكِرَ فِي الْقُنُوتِ لَيْسَ بِشَيْءٍ وَهَذَانِ الْحَدِيثَانِ يَدُلَّانِ عَلَى ضَعْفِ حَدِيثِ أُبَيٍّ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَنَتَ فِي الْوِتْرِ","id":"Telah menceritakan kepada Kami [Syuja' bin Makhlad], telah menceritakan kepada Kami [Husyaim], telah mengabarkan kepada Kami [Yunus bin 'Ubaid] dari [Al Hasan] bahwa [Umar bin Khathab] RhadhiyAllahu 'anhu mengumpulkan orang-orang untuk melakukan shalat dibelakang Ubai bin Kaab, ia melakukan shalat sebagai imam mereka selama dua puluh malam, dan dia tidak melakukan qunut bersama mereka kecuali pada setengah bulan terakhir. Dan apabila sudah masuk hari kesepuluh terakhir ia mengundurkan diri dan melakukan shalat dirumahnya, hingga orang-orang mengatakan bahwa Ubai telah kabur. Abu Daud berkata; hadits ini menunjukkan bahwa hadits yang telah disebutkan mengenai qunut tidak berarti apa-apa, dan dua hadits ini menunjukkan kelemahan hadits Ubai bahwa Nabi Shalla Allahu 'alaihi wa sallam melakukan qunut pada waktu witir. "},"1189":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُبَيْدَةَ حَدَّثَنَا أَبِي عَنْ الْأَعْمَشِ عَنْ طَلْحَةَ الْأَيَامِيِّ عَنْ ذَرٍّ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَلَّمَ فِي الْوِتْرِ قَالَ سُبْحَانَ الْمَلِكِ الْقُدُّوسِ","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Muhammad bin Abu 'Ubaidah], telah menceritakan kepada Kami [ayahku] dari [Al A'masy] dari [Thalhah Al Ayami] dari [Dzar] dari [Sa'id? bin Abdurrahman bin Abza] dari [ayahnya] dari [Ubai bin Ka'b], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam apabila telah melakukan salam dalam shalat witir beliau mengucapkan: \"SUBHAANAL MALIKIL QUDDUUS\" (Maha suci Raja Yang Maha Suci). "},"1190":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَوْفٍ حَدَّثَنَا عُثْمَانُ بْنُ سَعِيدٍ عَنْ أَبِي غَسَّانَ مُحَمَّدِ بْنِ مُطَرِّفٍ الْمَدَنِيِّ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَامَ عَنْ وِتْرِهِ أَوْ نَسِيَهُ فَلْيُصَلِّهِ إِذَا ذَكَرَهُ","id":"Telah menceritakan kepada Kami [Muhammad bin 'Auf], telah menceritakan kepada Kami [Utsman bin Sa'id] dari [Abu Gassan Muhammad bin Mutharrif Al Madani] dari [Zaid bin Aslam] dari ['Atha` bin Yasar] dari [Abu Sa'id], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Barang siapa yang tertidur dari melakukan witir atau lupa untuk melakukannya maka hendaknya ia melakukannya apabila ia ingat.\""},"1191":{"ar":"حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا أَبَانُ بْنُ يَزِيدَ عَنْ قَتَادَةَ عَنْ أَبِي سَعِيدٍ مِنْ أَزْدِ شَنُوءَةَ عَنْ أَبِي هُرَيْرَةَ قَالَأَوْصَانِي خَلِيلِي صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِثَلَاثٍ لَا أَدَعُهُنَّ فِي سَفَرٍ وَلَا حَضَرٍ رَكْعَتَيْ الضُّحَى وَصَوْمِ ثَلَاثَةِ أَيَّامٍ مِنْ الشَّهْرِ وَأَنْ لَا أَنَامَ إِلَّا عَلَى وِتْرٍ","id":"Telah menceritakan kepada Kami [Ibnu Al Mutsanna], telah menceritakan kepada Kami [Abu Daud], telah menceritakan kepada Kami [Aban bin Yazid] dari [Qatadah] dari [Abu Sa'id?] yang berasal dari Azd Syanuah, dari [Abu Hurairah], ia berkata; kekasihku shallallahu 'alaihi wasallam telah berwasiat kepadaku dengan tiga perkara, aku tidak meninggalkannya ketika bepergian mupun ketika bermukim, yaitu melakukan shalat dua raka'at shalat Dhuha, serta berpuasa tiga hari setiap bulan, dan agar aku tidak tidur kecuali telah melakukan shalat witir. "},"1192":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ نَجْدَةَ حَدَّثَنَا أَبُو الْيَمَانِ عَنْ صَفْوَانَ بْنِ عَمْرٍو عَنْ أَبِي إِدْرِيسَ السَّكُونِيِّ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِي الدَّرْدَاءِ قَالَأَوْصَانِي خَلِيلِي صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِثَلَاثٍ لَا أَدَعُهُنَّ لِشَيْءٍ أَوْصَانِي بِصِيَامِ ثَلَاثَةِ أَيَّامٍ مِنْ كُلِّ شَهْرٍ وَلَا أَنَامُ إِلَّا عَلَى وِتْرٍ وَبِسُبْحَةِ الضُّحَى فِي الْحَضَرِ وَالسَّفَرِ","id":"Telah menceritakan kepada Kami [Abdul Wahhab bin Najdah], telah menceritakan kepada Kami [Abu Al Yaman] dari [Shafwan bin 'Amr] dari [Abu Idris As Sakuni] dari [Jubair bin Nufair] dari [Abu Ad Darda`], ia berkata; kekasihku shallallahu 'alaihi wasallam telah berwasiat kepadaku dengan tiga perkara, aku tidak meninggalkannya karena sesuatu, beliau berwasiat kepadaku agar melakukan puasa tiga hari setiap bulan, tidak tidur kecuali telah melakukan witir, dan melakukan shalat Dhuha disaat bermukim dan sedang bepergian. "},"1193":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَحْمَدَ بْنِ أَبِي خَلَفٍ حَدَّثَنَا أَبُو زَكَرِيَّا يَحْيَى بْنُ إِسْحَقَ السَّيْلَحِينِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ عَنْ أَبِي قَتَادَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَبِي بَكْرٍ مَتَى تُوتِرُ قَالَ أُوتِرُ مِنْ أَوَّلِ اللَّيْلِ وَقَالَ لِعُمَرَ مَتَى تُوتِرُ قَالَ آخِرَ اللَّيْلِ فَقَالَ لِأَبِي بَكْرٍ أَخَذَ هَذَا بِالْحَزْمِ وَقَالَ لِعُمَرَ أَخَذَ هَذَا بِالْقُوَّةِ","id":"Telah menceritakan kepada Kami [Muhammad bin Ahmad bin Abu Khalaf] telah menceritakan kepada Kami [Abu Zakariya Yahya bin Ishaq As Sailahini] telah menceritakan kepada Kami [Hammad bin Salamah] dari [Tsabit] dari [Abdullah bin Rabah] dari [Abu Qatadah] bahwa Nabi shallallahu 'alaihi wasallam bertanya kepada Abu Bakar: \" Kapankah kamu melaksanakan witir?\" Dia menjawab; saya melakukan witir dipermulaan malam. Dan beliau bertanya kepada Umar: \"Kapankah kamu melaksanakan witir?\" Dia menjawab: saya melakukan witir pada akhir malam. Kemudian beliau berkata kepada Abu Bakar; \"Orang ini telah melakukan dengan keteguhan hati, \" dan kepada Umar beliau mengatakan: \"Sedangkan orang ini telah melakukan dengan kemantapan.\""},"1194":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ قَالَ قُلْتُ لِعَائِشَةَمَتَى كَانَ يُوتِرُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ كُلَّ ذَلِكَ قَدْ فَعَلَ أَوْتَرَ أَوَّلَ اللَّيْلِ وَوَسَطَهُ وَآخِرَهُ وَلَكِنْ انْتَهَى وِتْرُهُ حِينَ مَاتَ إِلَى السَّحَرِ","id":"Telah menceritakan kepada Kami [Ahmad bin Yunus], telah menceritakan kepada Kami [Abu Bakr bin 'Ayyasy] dari [Al A'masy] dari [Muslim] dari [Masruq], ia berkata; aku katakan kepada [Aisyah]; kapankah Rasulullah shallallahu 'alaihi wasallam melakukan witir? Ia berkata; semua itu telah beliau lakukan, beliau telah melakukan witir di permulaan malam, di pertengahan malam, dan di akhir malam, akan tetapi witir beliau selesai tatkala beliau akan meninggal hingga waktu pagi. "},"1195":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ قَالَ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَادِرُوا الصُّبْحَ بِالْوِتْرِ","id":"Telah menceritakan kepada Kami [Harun bin Ma'ruf], telah menceritakan kepada Kami [Ibnu Abu Zaidah], ia berkata; telah menceritakan kepadaku ['Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Bersegeralah melakukan witir sebelum waktu Subuh.\""},"1196":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَيْسٍ قَالَسَأَلْتُ عَائِشَةَ عَنْ وِتْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ رُبَّمَا أَوْتَرَ أَوَّلَ اللَّيْلِ وَرُبَّمَا أَوْتَرَ مِنْ آخِرِهِ قُلْتُ كَيْفَ كَانَتْ قِرَاءَتُهُ أَكَانَ يُسِرُّ بِالْقِرَاءَةِ أَمْ يَجْهَرُ قَالَتْ كُلَّ ذَلِكَ كَانَ يَفْعَلُ رُبَّمَا أَسَرَّ وَرُبَّمَا جَهَرَ وَرُبَّمَا اغْتَسَلَ فَنَامَ وَرُبَّمَا تَوَضَّأَ فَنَامَقَالَ أَبُو دَاوُد و قَالَ غَيْرُ قُتَيْبَةَ تَعْنِي فِي الْجَنَابَةِ","id":"Telah menceritakan kepada Kami [Qutaibah bin Sa'id?], telah menceritakan kepada Kami [Al Laits bin Sa'd] dari [Mu'awiyah bin Shalih] dari [Abdullah bin Abu Qais], ia berkata; saya bertanya kepada [Aisyah] mengenai witir Rasulullah shallAllahu wa'alaihi wa sallam, ia berkata; terkadang beliau melakukan witir pada awal malam, dan terkadang melakukan witir di akhirnya. Saya katakan; bagaimana bacaan beliau, apakah beliau menyamarkan bacaan atau mengeraskannya? Aisyah berkata; semua itu pernah beliau lakukan. Beliau terkadang menyamarkan dan terkadang mengeraskan, terkadang beliau mandi kemudian tidur terkadang beliau berwudhu kemudian tidur. Abu Daud berkata; selain Qutaibah berkata; yang dimaksudkan Aisyah adalah ketika dalam keadaan junub. "},"1197":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اجْعَلُوا آخِرَ صَلَاتِكُمْ بِاللَّيْلِ وِتْرًا","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal] telah menceritakan kepada Kami [Yahya] dari ['Ubaidullah] telah menceritakan kepadaku [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Jadikan shalat terakhir kalian adalah shalat witir.\""},"1198":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا مُلَازِمُ بْنُ عَمْرٍو حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَدْرٍ عَنْ قَيْسِ بْنِ طَلْقٍ قَالَزَارَنَا طَلْقُ بْنُ عَلِيٍّ فِي يَوْمٍ مِنْ رَمَضَانَ وَأَمْسَى عِنْدَنَا وَأَفْطَرَ ثُمَّ قَامَ بِنَا اللَّيْلَةَ وَأَوْتَرَ بِنَا ثُمَّ انْحَدَرَ إِلَى مَسْجِدِهِ فَصَلَّى بِأَصْحَابِهِ حَتَّى إِذَا بَقِيَ الْوِتْرُ قَدَّمَ رَجُلًا فَقَالَ أَوْتِرْ بِأَصْحَابِكَ فَإِنِّي سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا وِتْرَانِ فِي لَيْلَةٍ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Mulazim bin 'Amr], telah menceritakan kepada Kami [Abdullah bin Badr] dari [Qais bin Thalq], ia berkata; [Thalq bin Ali] telah mengunjungi Kami pada Bulan Ramadhan hingga sore dan berbuka bersama Kami, kemudian dia melakukan shalat sebagai Imam bagi Kami pada malam itu, dan melakukan witir, kemudian dia turun kemasjidnya dan melaksanakan shalat menjadi imam bagi sahabat-sahabatnya hingga tatkala tinggal shalat witir, ia mempersilahkan seseorang kedepan dan mengatakan kepadanya: shalat witirlah kamu sebagai imam bagi sahabat-sahabatmu, karena aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada dua witir dalam semalam!\""},"1199":{"ar":"حَدَّثَنَا دَاوُدُ بْنُ أُمَيَّةَ حَدَّثَنَا مُعَاذٌ يَعْنِي ابْنَ هِشَامٍ حَدَّثَنِي أَبِي عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا أَبُو هُرَيْرَةَ قَالَوَاللَّهِ لَأُقَرِّبَنَّ لَكُمْ صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَكَانَ أَبُو هُرَيْرَةَ يَقْنُتُ فِي الرَّكْعَةِ الْآخِرَةِ مِنْ صَلَاةِ الظُّهْرِ وَصَلَاةِ الْعِشَاءِ الْآخِرَةِ وَصَلَاةِ الصُّبْحِ فَيَدْعُو لِلْمُؤْمِنِينَ وَيَلْعَنُ الْكَافِرِينَ","id":"Telah menceritakan kepada Kami [Daud bin Umayyah], telah menceritakan kepada Kami [Mu'adz yaitu Ibnu Hisyam], telah menceritakan kepadaku [ayahku] dari [Yahya bin Abu Katsir] ia berkata; telah menceritakan kepadaku [Abu Salamah bin Abdurrahman], telah menceritakan kepada Kami [Abu Hurairah], ia berkata; Demi Allah aku akan mendekatkan bagi kalian shalat Rasulullah shallAllahu wa'alaihi wa sallam. Abu Salamah berkata; Abu Hurairah melakukan qunut pada raka'at terakhir pada shalat Zhuhur, shalat Isya`, dan shalat Subuh. Ia mendoakan orang-orang mukmin dan melaknat orang-orang kafir. "},"1200":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ وَمُسْلِمُ بْنُ إِبْرَاهِيمَ وَحَفْصُ بْنُ عُمَرَ ح و حَدَّثَنَا ابْنُ مُعَاذٍ حَدَّثَنِي أَبِي قَالُوا كُلُّهُمْ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ ابْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْنُتُ فِي صَلَاةِ الصُّبْحِ زَادَ ابْنُ مُعَاذٍ وَصَلَاةِ الْمَغْرِبِ","id":"Telah menceritakan kepada Kami [Abu Al Walid], [Muslim bin Ibrahim], serta [Hafsh bin Umar].. dan diriwayatkan dari jalur yang lain: Telah menceritakan kepada Kami [Ibnu Mu'adz], telah menceritakan kepada Kami [ayahku], mereka semua berkata; telah menceritakan kepada Kami [Syu'bah] dari ['Amr bin Murrah] dari [Ibnu Abu Laila] dari [Al Bara`] bahwa Nabi shallallahu 'alaihi wasallam melakukan qunut ketika shalat Subuh. Ibnu Mu'adz menambahkan; serta shalat Maghrib. "},"1201":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَقَنَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاةِ الْعَتَمَةِ شَهْرًا يَقُولُ فِي قُنُوتِهِ اللَّهُمَّ نَجِّ الْوَلِيدَ بْنَ الْوَلِيدِ اللَّهُمَّ نَجِّ سَلَمَةَ بْنَ هِشَامٍ اللَّهُمَّ نَجِّ الْمُسْتَضْعَفِينَ مِنْ الْمُؤْمِنِينَ اللَّهُمَّ اشْدُدْ وَطْأَتَكَ عَلَى مُضَرَ اللَّهُمَّ اجْعَلْهَا عَلَيْهِمْ سِنِينَ كَسِنِي يُوسُفَ قَالَ أَبُو هُرَيْرَةَ وَأَصْبَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ فَلَمْ يَدْعُ لَهُمْ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ وَمَا تُرَاهُمْ قَدْ قَدِمُوا","id":"Telah menceritakan kepada Kami [Abdurrahman bin Ibrahim], telah menceritakan kepada Kami [Al Walid], telah menceritakan kepada Kami [Al Auza'i], telah menceritakan kepadaku [Yahya bin Abu Katsir], telah menceritakan kepadaku [Abu Salamah bin Abdurrahman] dari [Abu Hurairah], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam melakukan qunut pada saat shalat Isya` selama satu bulan, ketika qunut beliau berdoa: \"Ya Allah, selamatkan Al Walid bin Al Walid, ya Allah, selamatkan Salamah bin Hisyam, ya Allah, selamatkan orang-orang mukmin yang lemah, ya Allah, keraskan siksaMu kepada Mudhar, ya Allah, jadikan siksaMu kepada mereka selama bertahun-tahun seperti beberapa tahun yang dialami Yusuf.\" Abu Hurairah berkata; pada suatu pagi beliau tidak mendoakan untuk mereka, kemudian aku tanyakan hal tersebut kepada beliau, kemudian beliau berkata: \"Bagaimana pendapatmu, sementara mereka telah meninggal.\""},"1202":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُعَاوِيَةَ الْجُمَحِيُّ حَدَّثَنَا ثَابِتُ بْنُ يَزِيدَ عَنْ هِلَالِ بْنِ خَبَّابٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَنَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَهْرًا مُتَتَابِعًا فِي الظُّهْرِ وَالْعَصْرِ وَالْمَغْرِبِ وَالْعِشَاءِ وَصَلَاةِ الصُّبْحِ فِي دُبُرِ كُلِّ صَلَاةٍ إِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ مِنْ الرَّكْعَةِ الْآخِرَةِ يَدْعُو عَلَى أَحْيَاءٍ مِنْ بَنِي سُلَيْمٍ عَلَى رِعْلٍ وَذَكْوَانَ وَعُصَيَّةَ وَيُؤَمِّنُ مَنْ خَلْفَهُ","id":"Telah menceritakan kepada Kami [Abdullah bin Mu'awiyah Al Jumahi], telah menceritakan kepada Kami [Tsabit bin Yazid] dari dari [Hilal bin Khabbab] dari [Ikrimah] dari [Ibnu Abbas], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam melakukan qunut selama satu bulan berturut-turut ketika shalat Zhuhur, Ashar, Maghrib, Isya` dan Subuh di akhir setiap shalat, tatkala mengucapkan: \"SAMI'ALLAAHU LIMAN HAMIDAH\" pada raka'at terakhir. Beliau mendoakan atas beberapa perkampungan dari Bani Sulaim, yaitu Ri'l, Dzakwan, serta 'Ushayyah, dan orang-orang yang dibelakangnya mengamininya. "},"1203":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ وَمُسَدَّدٌ قَالَا حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّهُ سُئِلَ هَلْ قَنَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاةِ الصُّبْحِ فَقَالَ نَعَمْ فَقِيلَ لَهُ قَبْلَ الرُّكُوعِ أَوْ بَعْدَ الرُّكُوعِ قَالَ بَعْدَ الرُّكُوعِ قَالَ مُسَدَّدٌ بِيَسِيرٍ","id":"Telah menceritakan kepada Kami [Sulaiman bin Harb] serta [Musaddad] mereka berkata; telah menceritakan kepada Kami [Hammad] dari [Ayyub] dari [Muhammad] dari [Anas bin Malik] RhadhiyAllahu 'anhu bahwa ia ditanya; apakah Rasulullah shallAllahu wa'alaihi wa sallam melaksanakan qunut pada waktu shalat subuh? Beliau menjawab: \"Ya.\" Lalu beliau ditanya lagi; sebelum atau sesudah ruku'? Beliau menjawab; \"Setelah ruku'.\" Musaddad berkata; sebentar. "},"1204":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَنَسِ بْنِ سِيرِينَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَنَتَ شَهْرًا ثُمَّ تَرَكَهُ","id":"Telah menceritakan kepada Kami [Abu Al Walid Ath Thayalisi], telah menceritakan kepada Kami [Hammad bin Salamah] dari [Anas bin Sirin] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam melakukan qunut selama satu bulan kemudian beliau meninggalkannya. "},"1205":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرُ بْنُ مُفَضَّلٍ حَدَّثَنَا يُونُسُ بْنُ عُبَيْدٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ قَالَحَدَّثَنِي مَنْ صَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْغَدَاةِ فَلَمَّا رَفَعَ رَأْسَهُ مِنْ الرَّكْعَةِ الثَّانِيَةِ قَامَ هُنَيَّةً","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Bisyr bin Mufadhdhal], telah menceritakan kepada Kami [Yunus bin 'Ubaid] dari [Muhammad bin Sirin], ia berkata; telah menceritakan kepadaku [orang yang melakukan shalat Subuh bersama Nabi] shallallahu 'alaihi wasallam; kemudian tatkala beliau mengangkat kepalanya dari raka'at yang kedua beliau berdiri sesaat. "},"1206":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ الْبَزَّازُ حَدَّثَنَا مَكِّيُّ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ سَعِيدِ بْنِ أَبِي هِنْدٍ عَنْ أَبِي النَّضْرِ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ ثَابِتٍ أَنَّهُ قَالَاحْتَجَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ حُجْرَةً فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْرُجُ مِنْ اللَّيْلِ فَيُصَلِّي فِيهَا قَالَ فَصَلَّوْا مَعَهُ لِصَلَاتِهِ يَعْنِي رِجَالًا وَكَانُوا يَأْتُونَهُ كُلَّ لَيْلَةٍ حَتَّى إِذَا كَانَ لَيْلَةٌ مِنْ اللَّيَالِي لَمْ يَخْرُجْ إِلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَنَحْنَحُوا وَرَفَعُوا أَصْوَاتَهُمْ وَحَصَبُوا بَابَهُ قَالَ فَخَرَجَ إِلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُغْضَبًا فَقَالَ يَا أَيُّهَا النَّاسُ مَا زَالَ بِكُمْ صَنِيعُكُمْ حَتَّى ظَنَنْتُ أَنْ سَتُكْتَبَ عَلَيْكُمْ فَعَلَيْكُمْ بِالصَّلَاةِ فِي بُيُوتِكُمْ فَإِنَّ خَيْرَ صَلَاةِ الْمَرْءِ فِي بَيْتِهِ إِلَّا الصَّلَاةَ الْمَكْتُوبَةَ","id":"Telah menceritakan kepada Kami [Harun bin Abdullah Al Bazzar] telah menceritakan kepada Kami [Makki bin Ibrahim] telah menceritakan kepada Kami [Abdullah yaitu Ibnu Sirin bin Abu Hindun] dari [Abu An Nadhr] dari [Busr bin Sa'id] dari [Zaid bin Tsabit] bahwa ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam membuat sebuah ruangan di masjid, beliau keluar pada malam hari dan melakukan shalat padanya. Zaid berkata; kemudian orang-orang melakukan shalat bersama beliau dengan sholat beliau. Mereka datang setiap malam hingga ketika suatu malam Rasulullah shallAllahu wa'alaihi wa sallam tidak keluar kepada mereka, kemudian mereka berdehem dan mengeraskan suara mereka, dan melempar pintu beliau menggunakan kerikil. Zaid berkata; kemudian beliau keluar menemui mereka dalam keadaan marah seraya berkata: \"Wahai manusia, masih saja apa yang kalian lakukan hingga aku mengira shalat tersebut diwajibkan atas kalian, hendaknya kalian melakukan shalat di rumah kalian, sesungguhnya sebaik-baik shalat seseorang adalah dirumahnya kecuali shalat wajib.\""},"1207":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ أَخْبَرَنَا نَافِعٌ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْعَلُوا فِي بُيُوتِكُمْ مِنْ صَلَاتِكُمْ وَلَا تَتَّخِذُوهَا قُبُورًا","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Yahya] dari ['Ubaidullah], telah mengabarkan kepada Kami [Nafi'] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jadikanlah sebagian shalat kalian di rumah kalian, dan janganlah kalian menjadikan rumah tersebut sebagai kuburan.\""},"1208":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ حَدَّثَنِي عُثْمَانُ بْنُ أَبِي سُلَيْمَانَ عَنْ عَلِيٍّ الْأَزْدِيِّ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ حُبْشِيٍّ الْخَثْعَمِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ أَيُّ الْأَعْمَالِ أَفْضَلُ قَالَ طُولُ الْقِيَامِ قِيلَ فَأَيُّ الصَّدَقَةِ أَفْضَلُ قَالَ جَهْدُ الْمُقِلِّ قِيلَ فَأَيُّ الْهِجْرَةِ أَفْضَلُ قَالَ مَنْ هَجَرَ مَا حَرَّمَ اللَّهُ عَلَيْهِ قِيلَ فَأَيُّ الْجِهَادِ أَفْضَلُ قَالَ مَنْ جَاهَدَ الْمُشْرِكِينَ بِمَالِهِ وَنَفْسِهِ قِيلَ فَأَيُّ الْقَتْلِ أَشْرَفُ قَالَ مَنْ أُهَرِيقَ دَمُهُ وَعُقِرَ جَوَادُهُ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Hajjaj], ia berkata; [Ibnu Juraij] berkata; telah menceritakan kepada Kami [Utsman bin Abu Sulaiman] dari [Ali Al Azdi] dari ['Ubaid bin 'Umair] dari [Abdullah bin Hubsyi Al Khats'ami] bahwa Nabi shallallahu 'alaihi wasallam ditanya; amalan apakah yang lebih utama? Beliau bersabda; lama berdiri. Ia ditanya; sedekah apakah yang paling utama? Ia berkata; pemberian orang miskin, ia ditanya; hijrah apakah yang paling utama? Beliau bersabda; orang yang meninggalkan apa yang Allah haramkan. Ia ditanya; jihad apakah yang paling utama? Beliau bersabda; orang yang berjihad memerangi orang-orang musyrik dengan harta dan jiwanya. Ia ditanya; terbunuh bagaimana yang paling mulia? Beliau bersabda; orang yang ditumpahkan darahnya dan kudanya disembelih."},"1209":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى عَنْ ابْنِ عَجْلَانَ حَدَّثَنَا الْقَعْقَاعُ بْنُ حَكِيمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَحِمَ اللَّهُ رَجُلًا قَامَ مِنْ اللَّيْلِ فَصَلَّى وَأَيْقَظَ امْرَأَتَهُ فَصَلَّتْ فَإِنْ أَبَتْ نَضَحَ فِي وَجْهِهَا الْمَاءَ رَحِمَ اللَّهُ امْرَأَةً قَامَتْ مِنْ اللَّيْلِ فَصَلَّتْ وَأَيْقَظَتْ زَوْجَهَا فَإِنْ أَبَى نَضَحَتْ فِي وَجْهِهِ الْمَاءَ","id":"Telah menceritakan kepada Kami [Muhammad bin Basysyar] telah menceritakan kepada Kami [Yahya] dari [Ibnu 'Ajlan], telah menceritakan kepada Kami [Al Qa'qa' bin Hakim] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Semoga Allah merahmati orang yang bangun malam hari kemudian melakukan shalat dan membangunkan isterinya lalu iapun melakukan shalat, apabila isterinya enggan maka ia memperciki wajahnya dengan air, dan semoga Allah merahmati seorang wanita yang bangun malam hari kemudian melakukan shalat, dan membangunkan suaminya. Apabila suaminya enggan maka ia memerciki wajahnya dengan air.\""},"1210":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حَاتِمِ بْنِ بَزِيعٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ شَيْبَانَ عَنْ الْأَعْمَشِ عَنْ عَلِيِّ بْنِ الْأَقْمَرِ عَنْ الْأَغَرِّ أَبِي مُسْلِمٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ وَأَبِي هُرَيْرَةَ قَالَاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اسْتَيْقَظَ مِنْ اللَّيْلِ وَأَيْقَظَ امْرَأَتَهُ فَصَلَّيَا رَكْعَتَيْنِ جَمِيعًا كُتِبَا مِنْ الذَّاكِرِينَ اللَّهَ كَثِيرًا وَالذَّاكِرَاتِ","id":"Telah menceritakan kepada Kami [Muhammad bin Hatim bin Bazi'], telah menceritakan kepada Kami ['Ubaidullah bin Musa] dari [Syaiban] dari [Al A'masy] dari [Ali bin Al Qamar] dari [Al Agharr Abu Muslim] dari [Abu Sa'id? Al Khudri] dan [Abu Hurairah] RhadhiyAllahu 'anhuma, mereka Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Barangsiapa yang bangun malam dan membangunkan istrinya kemudian mereka berdua melaksanakan shalat dua rakaat secara bersama, maka mereka berdua akan dicatat sebagai orang yang selalu mengingat Allah Ta'ala. "},"1211":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عُثْمَانَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُكُمْ مَنْ تَعَلَّمَ الْقُرْآنَ وَعَلَّمَهُ","id":"Telah menceritakan kepada Kami [Hafsh bin Umar] telah menceritakan kepada Kami [Syu'bah] dari ['Alqamah bin Martsad] dari [Sa'd bin 'Ubaidah] dari [Abu Abdurrahman] dari [Utsman] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sebaik-baik kalian adalah orang yang mempelajari Al Qur'an dan mengajarkannya.\""},"1212":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يَحْيَى بْنُ أَيُّوبَ عَنْ زَبَّانِ بْنِ فَائِدٍ عَنْ سَهْلِ بْنِ مُعَاذٍ الْجُهَنِيِّ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَرَأَ الْقُرْآنَ وَعَمِلَ بِمَا فِيهِ أُلْبِسَ وَالِدَاهُ تَاجًا يَوْمَ الْقِيَامَةِ ضَوْءُهُ أَحْسَنُ مِنْ ضَوْءِ الشَّمْسِ فِي بُيُوتِ الدُّنْيَا لَوْ كَانَتْ فِيكُمْ فَمَا ظَنُّكُمْ بِالَّذِي عَمِلَ بِهَذَا","id":"Telah menceritakan kepada Kami [Ahmad bin 'Amr bin As Sarh] telah mengabarkan kepada Kami [Ibnu Wahb] telah mengabarkan kepada Kami [Yahya bin Ayyub] dari [Zabban bin Faid] dari [Sahl bin Muadz Al Juhani] dari [ayahnya] bahwa Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Barangsiapa yang membaca AlQur'an dan melaksanakan apa yang terkandung di dalamnya, maka kedua orang tuanya pada hari kiamat nanti akan dipakaikan mahkota yang sinarnya lebih terang dari pada sinar matahari di dalam rumah-rumah didunia, jika matahari tersebut ada diantara kalian, maka bagaimana perkiraan kalian dengan orang yang melaksanakan isi Al Qur'an?\""},"1213":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ وَهَمَّامٌ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الَّذِي يَقْرَأُ الْقُرْآنَ وَهُوَ مَاهِرٌ بِهِ مَعَ السَّفَرَةِ الْكِرَامِ الْبَرَرَةِ وَالَّذِي يَقْرَؤُهُ وَهُوَ يَشْتَدُّ عَلَيْهِ فَلَهُ أَجْرَانِ","id":"Telah menceritakan kepada Kami [Muslim bin Ibrahim], telah menceritakan kepada Kami [Hisyam] dan [Hammam] dari [Qatadah] dari [Zurarah bin Aufa] dari [Sa'd bin Hisyam] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Orang yang membaca Al Qur'an dan ia pandai membacanya maka ia bersama para malaikat yang mulia, dan orang yang membaca Al Qur'an sedangkan ia mengalami kesulitan dalam membacanya maka baginya dua pahala.\""},"1214":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا اجْتَمَعَ قَوْمٌ فِي بَيْتٍ مِنْ بُيُوتِ اللَّهِ تَعَالَى يَتْلُونَ كِتَابَ اللَّهِ وَيَتَدَارَسُونَهُ بَيْنَهُمْ إِلَّا نَزَلَتْ عَلَيْهِمْ السَّكِينَةُ وَغَشِيَتْهُمْ الرَّحْمَةُ وَحَفَّتْهُمْ الْمَلَائِكَةُ وَذَكَرَهُمْ اللَّهُ فِيمَنْ عِنْدَهُ","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah] telah menceritakan kepada Kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tidaklah sebuah kaum berkumpul di dalam rumah diantara rumah-rumah Allah ta'ala, membaca kitab Allah, dan saling mempelajarinya diantara mereka melainkan akan turun kepada mereka ketenangan, mereka diliputi rahmat, serta dikelilingi malaikat, dan Allah menyebut-nyebut mereka diantara malaikat yang ada di sisiNya.\""},"1215":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنَا مُوسَى بْنُ عَلِيِّ بْنِ رَبَاحٍ عَنْ أَبِيهِ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ فِي الصُّفَّةِ فَقَالَ أَيُّكُمْ يُحِبُّ أَنْ يَغْدُوَ إِلَى بُطْحَانَ أَوْ الْعَقِيقِ فَيَأْخُذَ نَاقَتَيْنِ كَوْمَاوَيْنِ زَهْرَاوَيْنِ بِغَيْرِ إِثْمٍ بِاللَّهِ عَزَّ وَجَلَّ وَلَا قَطْعِ رَحِمٍ قَالُوا كُلُّنَا يَا رَسُولَ اللَّهِ قَالَ فَلَأَنْ يَغْدُوَ أَحَدُكُمْ كُلَّ يَوْمٍ إِلَى الْمَسْجِدِ فَيَتَعَلَّمَ آيَتَيْنِ مِنْ كِتَابِ اللَّهِ عَزَّ وَجَلَّ خَيْرٌ لَهُ مِنْ نَاقَتَيْنِ وَإِنْ ثَلَاثٌ فَثَلَاثٌ مِثْلُ أَعْدَادِهِنَّ مِنْ الْإِبِلِ","id":"Telah menceritakan kepada Kami [Sulaiman bin Daud Al Mahri], telah menceritakan kepada Kami [Ibnu Wahb], telah menceritakan kepada Kami [Musa bin Ali bin Rabah] dari [Ayahnya] dari ['Uqbah bin 'Amir Al Juhani], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam keluar menemui Kami sementara Kami berada di Shuffah, kemudian beliau bertanya: \"Siapakah diantara kalian ingin pergi ke Bathhan atau 'Aqiq, kemudian mengambil dua ekor unta gemuk dan putih tanpa berbuat dosa kepada Allah 'azza wajalla, dan tidak memutuskan hubungan kekerabatan?\" Mereka mengatakan; Kami semua wahai Rasul! Beliau bersabda: \"Sungguh salah seorang diantara kalian setiap hari datang ke Masjid, mempelajari dua ayat dari Kitab Allah 'azza wajalla adalah lebih baik baginya daripada dua ekor unta, dua ayat lebih baik daripada tiga unta, seperti bilangan-bilangan unta tersebut.\""},"1216":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي شُعَيْبٍ الْحَرَّانِيُّ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ أُمُّ الْقُرْآنِ وَأُمُّ الْكِتَابِ وَالسَّبْعُ الْمَثَانِي","id":"Telah menceritakan kepada Kami [Ahmad bin Abu Syu'aib Al Harani], telah menceritakan kepada Kami [Isa bin Yunus], telah menceritakan kepada Kami [Ibnu Abu Dzi`b] dari [Al Maburi] dari [Abu Hurairah], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Al Hamdulillaahi rabbil 'aalamiin (Surat Al Faatihah) adalah Ummul Kitab, serta As Sab'ul matsani.\""},"1217":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا خَالِدٌ حَدَّثَنَا شُعْبَةُ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ قَا��َ سَمِعْتُ حَفْصَ بْنَ عَاصِمٍ يُحَدِّثُ عَنْ أَبِي سَعِيدِ بْنِ الْمُعَلَّىأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِهِ وَهُوَ يُصَلِّي فَدَعَاهُ قَالَ فَصَلَّيْتُ ثُمَّ أَتَيْتُهُ قَالَ فَقَالَ مَا مَنَعَكَ أَنْ تُجِيبَنِي قَالَ كُنْتُ أُصَلِّي قَالَ أَلَمْ يَقُلْ اللَّهُ عَزَّ وَجَلَّ{ يَا أَيُّهَا الَّذِينَ آمَنُوا اسْتَجِيبُوا لِلَّهِ وَلِلرَّسُولِ إِذَا دَعَاكُمْ لِمَا يُحْيِيكُمْ }لَأُعَلِّمَنَّكَ أَعْظَمَ سُورَةٍ مِنْ الْقُرْآنِ أَوْ فِي الْقُرْآنِ شَكَّ خَالِدٌ قَبْلَ أَنْ أَخْرُجَ مِنْ الْمَسْجِدِ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ قَوْلُكَ قَالَ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ هِيَ السَّبْعُ الْمَثَانِي الَّتِي أُوتِيتُ وَالْقُرْآنُ الْعَظِيمُ","id":"Telah menceritakan kepada Kami ['Ubaidullah bin Mu'adz], telah menceritakan kepada Kami [Khalid], telah menceritakan kepada Kami [Syu'bah] dari [Khubaib bin Abdurrahman] ia berkata; saya mendengar [Hafsh bin 'Ashim] menceritakan dari [Abu Sa'id bin Al Ma'alli] bahwa Nabi shallallahu 'alaihi wasallam melewatinya sementara ia sedang melakukan shalat, kemudian beliau memanggilnya. Ia berkata; aku melakukan shalat kemudian datang kepada beliau. Ia berkata; kemudian beliau berkata: \"Apakah yang menghalangimu untuk menjawabku?\" Ia berkata; saya sedang melakukan shalat. Beliau berkata; bukankah Allah 'azza wajalla berfirman: \"Hai orang-orang yang beriman, penuhilah seruan Allah dan seruan Rasul apabila Rasul menyeru kamu kepada suatu yang memberi kehidupan kepada kamu?\" Aku akan mengajarkan kepadamu surat Al Qur'an dalam Al Qur'an yang terbesar -Khalid merasa ragu- sebelum aku keluar dari Masjid?\" Ia berkata; aku katakan; wahai Rasulullah, aku akan mendengar ucapanmu. Beliau bersabda: \"Al Hamdulillahi rabbil 'aalamiin (Surat Al Fatihah), surat tersebut adalah As Sab'ul Matsaani (tujuh ayat yang dibaca berulang-ulang) yang telah diberikan kepadaku, dan Al Qur'an Al Azhiim (Al Qur'an yang agung).\""},"1218":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ الْبَطِينِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَأُوتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعًا مِنْ الْمَثَانِي الطُّوَلِ وَأُوتِيَ مُوسَى عَلَيْهِ السَّلَام سِتًّا فَلَمَّا أَلْقَى الْأَلْوَاحَ رُفِعَتْ ثِنْتَانِ وَبَقِيَ أَرْبَعٌ","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Jarir] dari [Al A'masy] dari [Muslim Al Bathin] dari [Sa'id? bin Jubair] dari [Ibnu Abbas], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam telah diberikan tujuh ayat yang dibaca berulang-ulang yang panjang, sedangkan Musa telah diberikan enam, namun ketika dia membuang lembaran-lembaran taurat maka yang dua diangkat dan tersisa empat. "},"1219":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدُ بْنُ إِيَاسٍ عَنْ أَبِي السَّلِيلِ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ الْأَنْصَارِيِّ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَا الْمُنْذِرِ أَيُّ آيَةٍ مَعَكَ مِنْ كِتَابِ اللَّهِ أَعْظَمُ قَالَ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ أَبَا الْمُنْذِرِ أَيُّ آيَةٍ مَعَكَ مِنْ كِتَابِ اللَّهِ أَعْظَمُ قَالَ قُلْتُ{ اللَّهُ لَا إِلَهَ إِلَّا هُوَ الْحَيُّ الْقَيُّومُ }قَالَ فَضَرَبَ فِي صَدْرِي وَقَالَ لِيَهْنَ لَكَ يَا أَبَا الْمُنْذِرِ الْعِلْمُ","id":"Telah menceritakan kepada Kami [Muhammad bin Al Mutsanna], telah menceritakan kepada Kami [Abdul A'la] telah menceritakan kepada Kami [Sa'id? bin Iyas] dari [Abu As Salil] dari [Abdullah bin Rabah Al Anshari] dari [Ubai bin Ka'b], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam: \"Wahai Abu Al Mundzir, ayat apakah dari Kitab Allah paling besar menurutmu?\" Saya katakan; Allah dan RasulNya yang lebih mengetahui. Beliau bertanya lagi: \"Wahai Abul Mundzir ayat manakah yang kamu hafal dari Kitab Allah yang lebih besar menurutmu?\" Aku menjawab; ALLAAHU LAA ILAAHA ILLAA HUWAL HAYYUL QAYYUUM\" (ayat Kursi). Kemudian Rasulullah shallAllahu wa'alaihi wa sallam menepuk dadaku dan berkata: \"Wahai Abu Al Mundzir, sungguh engkau adalah orang yang berilmu. "},"1220":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَجُلًا سَمِعَ رَجُلًا يَقْرَأُ قُلْ هُوَ اللَّهُ أَحَدٌ يُرَدِّدُهَا فَلَمَّا أَصْبَحَ جَاءَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ لَهُ وَكَأَنَّ الرَّجُلَ يَتَقَالُّهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ إِنَّهَا لَتَعْدِلُ ثُلُثَ الْقُرْآنِ","id":"Telah menceritakan kepada Kami [Al Qa'nabi] dari [Malik] dari [Abdurrahman bin Abdullah bin Abdurrahman] dari [Ayahnya] dari [Abu Sa'id Al Khudri] bahwa seorang laki-laki mendengar orang lain membaca; QUL HUWALLAAHU AHAD, ia mengulang-ulangnya. Kemudian tatkala pagi hari ia datang kepada Rasulullah shallAllahu wa'alaihi wa sallam dan menyebutkannya kepada beliau, seolah-olah orang tersebut menganggapnya sedikit. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Demi Dzat yang jiwaku ada di tangannya, sesungguhnya ayat tersebut sama dengan sepertiga Al Qur'an.\""},"1221":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي مُعَاوِيَةُ عَنْ الْعَلَاءِ بْنِ الْحَارِثِ عَنْ الْقَاسِمِ مَوْلَى مُعَاوِيَةَ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَكُنْتُ أَقُودُ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَاقَتَهُ فِي السَّفَرِ فَقَالَ لِي يَا عُقْبَةُ أَلَا أُعَلِّمُكَ خَيْرَ سُورَتَيْنِ قُرِئَتَا فَعَلَّمَنِي قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ وَقُلْ أَعُوذُ بِرَبِّ النَّاسِ قَالَ فَلَمْ يَرَنِي سُرِرْتُ بِهِمَا جِدًّا فَلَمَّا نَزَلَ لِصَلَاةِ الصُّبْحِ صَلَّى بِهِمَا صَلَاةَ الصُّبْحِ لِلنَّاسِ فَلَمَّا فَرَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الصَّلَاةِ الْتَفَتَ إِلَيَّ فَقَالَ يَا عُقْبَةُ كَيْفَ رَأَيْتَ","id":"Telah menceritakan kepada Kami [Ahmad bin 'Amr bin As Sarh], telah memberitakan kepada Kami [Ibnu Wahb], telah memberitakan kepadaku [Mu'awiyah] dari [Al 'Ala`bin Al Harits] dari [Al Qasim] mantan budak Mu'awiyah dari ['Uqbah bin 'Amir], ia berkata; aku menuntun unta Rasulullah shallAllahu wa'alaihi wa sallam yang beliau tunggangi dalam suatu perjalanan. Kemudian beliau berkata: \"Wahai 'Uqbah, maukah aku ajarkan kepadamu dua surat terbaik yang dibaca?\" Kemudian beliau mengajarkan kepadaku QUL A'UUDZU BIRABBIL FALAQ, dan QUL A'UUDZU BIRABBINNAAS. Kemudian tatkala Rasulullah shallAllahu wa'alaihi wa sallam selesai dari shalat beliau menoleh kepadaku dan berkata: \"Wahai 'Uqbah, bagaimana pendapatmu?\""},"1222":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِيهِ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَبَيْنَا أَنَا أَسِيرُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ الْجُحْفَةِ وَالْأَبْوَاءِ إِذْ غَشِيَتْنَا رِيحٌ وَظُلْمَةٌ شَدِيدَةٌ فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَعَوَّذُ بِأَعُوذُ بِرَبِّ الْفَلَقِ وَأَعُوذُ بِرَبِّ النَّاسِ وَيَقُولُ يَا عُقْبَةُ تَعَوَّذْ بِهِمَا فَمَا تَعَوَّذَ مُتَعَوِّذٌ بِمِثْلِهِمَا قَالَ وَسَمِعْتُهُ يَؤُمُّنَا بِهِمَا فِي الصَّلَاةِ","id":"Telah menceritakan kepada Kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada Kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Sa'id? bin Abu Sa'id Al Maqburi] dari [ayahnya] dari ['Uqbah bin Amir], ia berkata; ketika aku sedang berjalan bersama Rasulullah shallAllahu wa'alaihi wa sallam antara Juhfah dan Abwa`, tiba-tiba Kami tertutupi angin sangat dan terjadi kegelapan yang sangat, kemudian Rasulullah shallAllahu wa'alaihi wa sallam berlindung dengan mengucapkan: \"QUL A'UUDZU BIRABBIL FALAQ, \" dan \"QUL A'UUDZU BIRABBINNAAS\". Dan beliau berkata: \"Wahai Uqbah, berlindunglah dengan keduanya, tidak ada orang yang berlindung dengan sebuah perlindungan yang menyamai keduanya.\" 'Uqbah berkata; aku mendengar beliau mengimami Kami dengan membaca kedua surat tersebut dalam shalat. "},"1223":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ حَدَّثَنِي عَاصِمُ بْنُ بَهْدَلَةَ عَنْ زِرٍّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَالُ لِصَاحِبِ الْقُرْآنِ اقْرَأْ وَارْتَقِ وَرَتِّلْ كَمَا كُنْتَ تُرَتِّلُ فِي الدُّنْيَا فَإِنَّ مَنْزِلَكَ عِنْدَ آخِرِ آيَةٍ تَقْرَؤُهَا","id":"Telah menceritakan kepada Kami [Musaddad] telah menceritakan kepada Kami [Yahya] dari [Sufyan], telah menceritakan kepadaku ['Ashim bin Bahdalah] dari [Zirr] dari [Abdullah bin 'Amr], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Dikatakan kepada orang yang membaca Al Qur'an: \"Bacalah, dan naiklah, serta bacalah dengan tartil (jangan terburu-buru), sebagaimana engkau membaca dengan tartil di dunia, sesungguhnya tempatmu adalah pada akhir ayat yang engkau baca.\""},"1224":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا جَرِيرٌ عَنْ قَتَادَةَ قَالَسَأَلْتُ أَنَسًا عَنْ قِرَاءَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كَانَ يَمُدُّ مَدًّا","id":"Telah menceritakan kepada Kami [Muslim bin Ibrahim], telah menceritakan kepada Kami [Jarir] dari [Qatadah], ia berkata; saya bertanya kepada [Anas] mengenai bacaan Nabi shallallahu 'alaihi wasallam, kemudian ia berkata; beliau benar-benar memanjangkannya. "},"1225":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ خَالِدِ بْنِ مَوْهَبٍ الرَّمْلِيُّ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ يَعْلَى بْنِ مَمْلَكٍأَنَّهُ سَأَلَ أُمَّ سَلَمَةَ عَنْ قِرَاءَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَلَاتِهِ فَقَالَتْ وَمَا لَكُمْ وَصَلَاتَهُ كَانَ يُصَلِّي وَيَنَامُ قَدْرَ مَا صَلَّى ثُمَّ يُصَلِّي قَدْرَ مَا نَامَ ثُمَّ يَنَامُ قَدْرَ مَا صَلَّى حَتَّى يُصْبِحَ وَنَعَتَتْ قِرَاءَتَهُ فَإِذَا هِيَ تَنْعَتُ قِرَاءَتَهُ حَرْفًا حَرْفًا","id":"Telah menceritakan kepada Kami [Yazid bin Khalid bin Mauhib Ar Ramli], telah menceritakan kepada Kami [Al Laits] dari [Ibnu Abu Mulaikah] dari [Ya'la bin Mamlak] bahwa ia bertanya kepada [Ummu Salamah] mengenai bacaan Rasulullah shallAllahu wa'alaihi wa sallam serta shalat beliau. Kemudian ia berkata; ada apa dengan kalian dan shalatnya, beliau melakukan shalat dan tidur seukuran lamanya shalat beliau, kemudian beliau melakukan shalat seukuran lamanya tidur beliau, kemudian beliau tidur seukuran lama beliau melakukan shalat hingga pagi hari. Kemudian Ummu Salamah menggambarkan bacaan Nabi Shalla Allahu 'alaihi wa sallam dan ia menggambarkan bacaannya sehuruf-sehuruf. "},"1226":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ وَهُوَ عَلَى نَاقَةٍ يَقْرَأُ بِسُورَةِ الْفَتْحِ وَهُوَ يُرَجِّعُ","id":"Telah menceritakan kepada Kami [Hafsh bin Umar], telah menceritakan kepada Kami [Syu'bah] dari [Mu'awiyah bin Qurrah] dari [Abdullah bin Mughaffal], ia berkata; saya melihat Rasulullah shallAllahu wa'alaihi wa sallam pada saat penaklukan Mekkah berada di atas unta membaca surat Al Fath, dan beliau mengulang-ulangnya. "},"1227":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ طَلْحَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْسَجَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيِّنُوا الْقُرْآنَ بِأَصْوَاتِكُمْ","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Jarir] dari [Al A'masy] dari [Thalhah] dari [Abdurrahman bin 'Ausajah] dari [Al Bara` bin 'Azib] ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Perindahlah Al Qur'an dengan suara kalian.\""},"1228":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ وَقُتَيْبَةُ بْنُ سَعِيدٍ وَيَزِيدُ بْنُ خَالِدِ بْن�� مَوْهَبٍ الرَّمْلِيُّ بِمَعْنَاهُ أَنَّ اللَّيْثَ حَدَّثَهُمْ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي نَهِيكٍ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍ وَقَالَ يَزِيدُ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ وَقَالَ قُتَيْبَةُ هُوَ فِي كِتَابِي عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ مِنَّا مَنْ لَمْ يَتَغَنَّ بِالْقُرْآنِحَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي نَهِيكٍ عَنْ سَعْدٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada Kami [Abu Al Walid Ath Thayalisi], serta [Qutaibah bin Sa'id] serta [Yazid bin Khalid bin Mauhib Ar Ramli] secara makna bahwa [Al Laits] telah menceritakan kepada mereka dari [Abdullah bin Abu Mulaikah] dari [Abdullah bin Abu Nuhaik] dari [Sa'd bin Abu Waqqash]. [Yazid] berkata dari [Ibnu Mulaikah] dari [Sa'id? bin Abu Sa'id], Qutaibah berkata; dalam catatanku adalah dari Sa'id? bin Abu Sa'id, ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Bukan dari golongan Kami orang yang tidak memperindah bacaan Al Qur'an.\" Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Sufyan bin 'Uyainah] dari ['Amr] dari [Ibnu Abu Mulaikah] dari ['Ubaidullah bin Abu Nuhaik] dari [Sa'd], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam berkata seperti itu. "},"1229":{"ar":"حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ حَدَّثَنَا عَبْدُ الْجَبَّارِ بْنُ الْوَرْدِ قَالَ سَمِعْتُ ابْنَ أَبِي مُلَيْكَةَ يَقُولُ قَالَ عُبَيْدُ اللَّهِ بْنُ أَبِي يَزِيدَمَرَّ بِنَا أَبُو لُبَابَةَ فَاتَّبَعْنَاهُ حَتَّى دَخَلَ بَيْتَهُ فَدَخَلْنَا عَلَيْهِ فَإِذَا رَجُلٌ رَثُّ الْبَيْتِ رَثُّ الْهَيْئَةِ فَسَمِعْتُهُ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيْسَ مِنَّا مَنْ لَمْ يَتَغَنَّ بِالْقُرْآنِقَالَ فَقُلْتُ لِابْنِ أَبِي مُلَيْكَةَ يَا أَبَا مُحَمَّدٍ أَرَأَيْتَ إِذَا لَمْ يَكُنْ حَسَنَ الصَّوْتِ قَالَ يُحَسِّنُهُ مَا اسْتَطَاعَ حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ قَالَ قَالَ وَكِيعٌ وَابْنُ عُيَيْنَةَ يَعْنِي يَسْتَغْنِي بِهِ","id":"Telah menceritakan kepada Kami [Abdul A'la bin Hammad], telah menceritakan [Abdul Jabbar bin Al Ward], ia berkata; saya mendengar [Ibnu Abu Mulaikah] berkata; [Ubaidullah bin Abu Yazid] berkata; [Abu Lubabah] lewat didepan Kami, lalu Kami mengikutinya hingga dia masuk ke rumahnya dan Kamipun masuk menemuinya, ternyata ia adalah seorang laki-laki perabotan rumahnya sedikit dan kondisinya memburuk, kemudian aku mendengar dia berkata; aku mendengar Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Bukan dari golongan Kami orang yang tidak memperindah bacaan Al Qur'an.\" Abdul Jabbar berkata; aku bertanya kepada Ibnu Abu Malikah; wahai Abu Muhammad, bagaimana pendapatmu apabila ia tidak bagus suaranya? Ia menjawab; ia perindah suaranya semampunya. Telah menceritakan kepada kami Muhammad bin Sulaiman Al Anbari, ia berkata; Waki' dan Ibnu 'Uyainah berkata; yaitu ia menyibukkan dengan Al Qur'an. "},"1230":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ حَدَّثَنِي عُمَرُ بْنُ مَالِكٍ وَحَيْوَةُ عَنْ ابْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا أَذِنَ اللَّهُ لِشَيْءٍ مَا أَذِنَ لِنَبِيٍّ حَسَنِ الصَّوْتِ يَتَغَنَّى بِالْقُرْآنِ يَجْهَرُ بِهِ","id":"Telah menceritakan kepada Kami [Sulaiman bin Daud Al Mahri], telah mengabarkan kepada Kami [Ibnu Wahb], telah menceritakan kepadaku [Umar bin Malik] serta [Haiwah] dari [Ibnu Al Had] dari [Muhammad bin Ibrahim bin Al Harits] dari [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] bahwa Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Tidaklah Allah memberikan izin untuk melakukan sesuatu sebagaimana Allah memberikan izin kepada seorang nabi yang indah suaranya memperindah bacaan Al Qur'an, dan mengeraskannya.\""},"1231":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ أَخْبَرَنَا ابْنُ إِدْرِيسَ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ عِيسَى بْنِ فَائِدٍ عَنْ سَعْدِ بْنِ عُبَادَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ امْرِئٍ يَقْرَأُ الْقُرْآنَ ثُمَّ يَنْسَاهُ إِلَّا لَقِيَ اللَّهَ عَزَّ وَجَلَّ يَوْمَ الْقِيَامَةِ أَجْذَمَ","id":"Telah menceritakan kepada Kami [Muhammad bin Al 'Ala`], telah mengabarkan kepada Kami [Ibnu Idris] dari [Yazid bin Abu Ziyad] dari [Isa bin Faid] dari [Sa'd bin 'Ubadah] ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Tidaklah seseorang membaca Al Qur'an kemudian ia melupakannya melainkan ia bertemu Allah 'azza wajalla pada hari Kiamat dalam keadaan mulutnya ompong.\""},"1232":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ الْقَارِيِّ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُسَمِعْتُ هِشَامَ بْنَ حَكِيمِ بْنِ حِزَامٍ يَقْرَأُ سُورَةَ الْفُرْقَانِ عَلَى غَيْرِ مَا أَقْرَؤُهَا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْرَأَنِيهَا فَكِدْتُ أَنْ أَعْجَلَ عَلَيْهِ ثُمَّ أَمْهَلْتُهُ حَتَّى انْصَرَفَ ثُمَّ لَبَّبْتُهُ بِرِدَائِهِ فَجِئْتُ بِهِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي سَمِعْتُ هَذَا يَقْرَأُ سُورَةَ الْفُرْقَانِ عَلَى غَيْرِ مَا أَقْرَأْتَنِيهَا فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ فَقَرَأَ الْقِرَاءَةَ الَّتِي سَمِعْتُهُ يَقْرَأُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا أُنْزِلَتْ ثُمَّ قَالَ لِيَ اقْرَأْ فَقَرَأْتُ فَقَالَ هَكَذَا أُنْزِلَتْ ثُمَّ قَالَ إِنَّ هَذَا الْقُرْآنَ أُنْزِلَ عَلَى سَبْعَةِ أَحْرُفٍ فَاقْرَءُوا مَا تَيَسَّرَ مِنْهُحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ قَالَ قَالَ الزُّهْرِيُّ إِنَّمَا هَذِهِ الْأَحْرُفُ فِي الْأَمْرِ الْوَاحِدِ لَيْسَ تَخْتَلِفُ فِي حَلَالٍ وَلَا حَرَامٍ","id":"Telah menceritakan kepada Kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] dari [Abdurrahman bin Abdul Qari], ia berkata; saya mendengar [Umar bin Al Khathab] berkata; aku mendengar Hisyam bin Hakim bin Hizam membaca Surat Al Furqan tidak seperti yang aku baca, dan Rasulullah telah membacakannya kepadaku, maka hampir aku tergesa-gesa untuk bertindak terhadapnya, kemudian aku mengurungkannya hingga ia pergi. Kemudian aku menarik selendangnya dan membawanya kepada Rasulullah shallallahu 'alaihi wasallam. Aku katakan; wahai Rasul, sesungguhnya aku telah mendengar orang ini membaca Surat Al Furqan tidak seperti yang telah engkau bacakan kepadaku. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepadanya: \"Bacalah, kemudian ia membaca bacaan yang telah aku dengar. kemudian Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Demikianlah Surat tersebut diturunkan.\" Kemudian beliau berkata kepadaku: \"Bacalah.\" Lalu aku membacanya. Kemudian beliau berkata: \"Demikianlah surat tersebut diturunkan.\" Kemudian beliau bersabda: \"Sesungguhnya Al Qur'an ini diturunkan dengan tujuh gaya bahasa, maka bacalah apa yang mudah darinya.\" Telah menceritakan kepada Kami Muhammad bin Yahya bin Faris, telah menceritakan kepada Kami Abdurrazzaq, telah mengabarkan kepada Kami Ma'mar, ia berkata; Az Zuhri berkata; sesungguhnya gaya bahasa ini dalam satu perkara dan tidak berbeda-beda dalam hal halal dan haram. "},"1233":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى عَنْ قَتَادَةَ عَنْ يَحْيَى بْنِ يَعْمَرَ عَنْ سُلَيْمَانَ بْنِ صُرَدٍ الْخُزَاعِيِّ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أُبَيُّ إِنِّي أُقْرِئْتُ الْقُرْآنَ فَقِيلَ لِي عَلَى حَرْفٍ أَوْ حَرْفَيْنِ فَقَالَ الْمَلَكُ الَّذِي مَعِي قُلْ عَلَى حَرْفَيْنِ قُلْتُ عَلَى حَرْفَيْنِ فَقِيلَ لِي عَلَى حَرْفَيْنِ أَوْ ثَلَاثَةٍ فَقَالَ الْمَلَكُ الَّذِي مَعِي قُلْ عَلَى ثَلَاثَةٍ قُلْتُ عَلَى ثَلَاثَةٍ حَتَّى بَلَغَ سَبْعَةَ أَحْرُفٍ ثُمَّ قَالَ لَيْسَ مِنْهَا إِلَّا شَافٍ كَافٍ إِنْ قُلْتَ سَمِيعًا عَلِيمًا عَزِيزًا حَكِيمًا مَا لَمْ تَخْتِمْ آيَةَ عَذَابٍ بِرَحْمَةٍ أَوْ آيَةَ رَحْمَةٍ بِعَذَابٍ","id":"Telah menceritakan kepada Kami [Abu Al Walid Ath Thayalisi], telah menceritakan kepada Kami [Hammam bin Yahya] dari [Qatadah] dari [Yahya bin Ya'mar] dari [Sulaiman bin Shurad Al Khuza'i] dari [Ubai bin Ka'b], ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Ubai, sesungguhnya telah dibacakan Al Qur'an kepadaku, dan aku ditanya; dengan satu gaya bahasa atau dua gaya bahasa? Kemudian malaikat yang bersamaku berkata; katakan; dengan dua gaya bahasa! Maka aku katakan; dengan dua gaya bahasa. Kemudian aku ditanya; dengan dua gaya bahasa atau tiga gaya bahasa? Kemudian malaikat yang bersamaku berkata; katakan; dengan tiga gaya bahasa! Maka aku katakan; dengan tiga gaya bahasa. Hingga sampai tujuh gaya bahasa.\" Kemudian beliau berkata: \"Tidak ada diantara gaya bahasa tersebut kecuali merupakan sesuatu yang memuaskan dan cukup. Apabila engkau membaca; SAMII'AN 'ALIIMAN, 'AZIIZAN HAKIIMAN selama engkau tidak menutup ayat yang berbicara mengenai adzab dengan rahmat atau ayat yang berbicara mengenai rahmat dengan adzab.\""},"1234":{"ar":"حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ مُجَاهِدٍ عَنْ ابْنِ أَبِي لَيْلَى عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ عِنْدَ أَضَاةِ بَنِي غِفَارٍ فَأَتَاهُ جِبْرِيلُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ يَأْمُرُكَ أَنْ تُقْرِئَ أُمَّتَكَ عَلَى حَرْفٍ قَالَ أَسْأَلُ اللَّهَ مُعَافَاتَهُ وَمَغْفِرَتَهُ إِنَّ أُمَّتِي لَا تُطِيقُ ذَلِكَ ثُمَّ أَتَاهُ ثَانِيَةً فَذَكَرَ نَحْوَ هَذَا حَتَّى بَلَغَ سَبْعَةَ أَحْرُفٍ قَالَ إِنَّ اللَّهَ يَأْمُرُكَ أَنْ تُقْرِئَ أُمَّتَكَ عَلَى سَبْعَةِ أَحْرُفٍ فَأَيُّمَا حَرْفٍ قَرَءُوا عَلَيْهِ فَقَدْ أَصَابُوا","id":"Telah menceritakan kepada Kami [Ibnu Al Mutsanna], telah menceritakan kepada Kami [Muhammad bin Ja'far], telah menceritakan kepada Kami [Syu'bah] dari [Al Hakam] dari [Mujahid] dari [Ibnu Abu Laila] dari [Ubai bin Ka'b] bahwa Nabi shallallahu 'alaihi wasallam berada di air rawa Bani Ghifar, kemudian Jibril shallallahu 'alaihi wasallam datang kepadanya, dan berkata; sesungguhnya Allah 'azza wajalla memerintahkanmu untuk membacakan Al Qur'an kepada umatmu dengan satu gaya bahasa. Beliau berkata: \"Aku meminta maaf dan Ampunan kepada Allah. Sesungguhnya umatku tidak akan mampu melakukan hal tersebut.\" Kemudian ia datang kepada beliau kedua kalinya dan menyebutkan seperti ini hingga sampai tujuh gaya bahasa. Ia berkata; sesungguhnya Allah memerintahkamu agar membacakan Al Qur'an kepada umatmu dengan tujuh gaya bahasa. Gaya bahasa yang mana saja yang mereka baca maka mereka telah benar. "},"1235":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ عَنْ زِيَادِ بْنِ مِخْرَاقٍ عَنْ أَبِي نَعَامَةَ عَنْ ابْنٍ لِسَعْدٍ أَنَّهُ قَالَسَمِعَنِي أَبِي وَأَنَا أَقُولُ اللَّهُمَّ إِنِّي أَسْأَلُكَ الْجَنَّةَ وَنَعِيمَهَا وَبَهْجَتَهَا وَكَذَا وَكَذَا وَأَعُوذُ بِكَ مِنْ النَّارِ وَسَلَاسِلِهَا وَأَغْلَالِهَا وَكَذَا وَكَذَا فَقَالَ يَا بُنَيَّ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ سَيَكُونُ قَوْمٌ يَعْتَدُونَ فِي الدُّعَاءِ فَإِيَّاكَ أَنْ تَكُونَ مِنْهُمْ إِنَّكَ إِنْ أُعْطِيتَ الْجَنَّةَ أُعْطِيتَهَا وَمَا فِيهَا مِنْ الْخَيْرِ وَإِنْ أُعِذْتَ مِنْ النَّارِ أُعِذْتَ مِنْهَا وَمَا فِيهَا مِنْ الشَّرِّ","id":"Telah menceritakan kepadaku [Musaddad], telah menceritakan kepada Kami [Yahya] dari [Syu'bah] dari [Ziyad bin Mikhraq] dari [Abu Na'amah] dari [anak Sa'd] bahwa ia berkata; [ayahku] mendengarku berkata; ya Allah, aku memohon kepadaMu Surga dan kenikmatannya, keindahannya dan demikian dan demikian…. dan aku berlindung kepadaMu dari Neraka, rantai serta belenggu-belenggunya, dan demikian dan demikian.. Kemudian ia berkata; wahai anakku, sesungguhnya aku mendengar Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Akan ada sebuah kaum berlebihan dalam berdoa.\" Maka hati-hatilah engkau menjadi bagian dari mereka, sesungguhnya apabila engkau diberi Surga maka engkau telah diberi kebaikan yang ada padanya, dan apabila engkau dilindungi dari Neraka maka engkau telah dilindungi darinya dan dari keburukan yang ada padanya. "},"1236":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا حَيْوَةُ أَخْبَرَنِي أَبُو هَانِئٍ حُمَيْدُ بْنُ هَانِئٍ أَنَّ أَبَا عَلِيٍّ عَمْرَو بْنَ مَالِكٍ حَدَّثَهُ أَنَّهُ سَمِعَ فَضَالَةَ بْنَ عُبَيْدٍ صَاحِبَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُسَمِعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يَدْعُو فِي صَلَاتِهِ لَمْ يُمَجِّدْ اللَّهَ تَعَالَى وَلَمْ يُصَلِّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَجِلَ هَذَا ثُمَّ دَعَاهُ فَقَالَ لَهُ أَوْ لِغَيْرِهِ إِذَا صَلَّى أَحَدُكُمْ فَلْيَبْدَأْ بِتَمْجِيدِ رَبِّهِ جَلَّ وَعَزَّ وَالثَّنَاءِ عَلَيْهِ ثُمَّ يُصَلِّي عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ يَدْعُو بَعْدُ بِمَا شَاءَ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Abdullah bin Yazid], telah menceritakan kepada Kami [Haiwah], telah mengabarkan kepadaku [Abu Hani` Humaid bin Hani`] bahwa [Abu Ali 'Amr bin Malik] telah menceritakan kepadanya bahwa ia mendengar [Fadhalah bin 'Ubaid] seorang sahabat Rasulullah shallallahu 'alaihi wasallam berkata; Rasulullah shallAllahu wa'alaihi wa sallam mendengar seorang laki-laki berdoa dalam shalatnya dan tidak mengagungkan Allah ta'ala serta tidak bershalawat kepada Nabi shallallahu 'alaihi wasallam, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang ini telah terburu-buru.\" Kemudian beliau memanggilnya dan berkata kepadanya atau kepada orang lain: \"Apabila salah seorang diantara kalian melakukan shalat maka hendaknya memulai dengan mengagungkan Tuhannya yang Maha Agung dan Perkasa, serta dengan memuji kepadaNya, kemudian bershalawat kepada Nabi shallallahu 'alaihi wasallam kemudian berdoa setelah itu dengan apa yang ia kehendaki.\""},"1237":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَقُولَنَّ أَحَدُكُمْ اللَّهُمَّ اغْفِرْ لِي إِنْ شِئْتَ اللَّهُمَّ ارْحَمْنِي إِنْ شِئْتَ لِيَعْزِمْ الْمَسْأَلَةَ فَإِنَّهُ لَا مُكْرِهَ لَهُ","id":"Telah menceritakan kepada Kami [Al Qa'nabi] dari [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Janganlah salah seorang diantara kalian mengucapkan; ya Allah, ampunilah aku jika Engkau menghendaki, rahmatilah aku jika Engkau menghendaki. Hendaknya ia membulatkan permohonan karena sesungguhnya tidak ada yang memaksa Allah.\""},"1238":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي عُبَيْدٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُسْتَجَابُ لِأَحَدِكُمْ مَا لَمْ يَعْجَلْ فَيَقُولُ قَدْ دَعَوْتُ فَلَمْ يُسْتَجَبْ لِي","id":"Telah menceritakan kepada Kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari [Abu 'Ubaid] dari [Abu Hurairah] bahwa Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Diperkenankan bagi salah seorang diantara kalian selama ia tidak terburu-buru, ia mengatakan; aku telah berdoa namun belum dikabulkan.\""},"1239":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ مُحَمَّدِ بْنِ أَيْمَنَ عَنْ عَبْدِ اللَّهِ بْنِ يَعْقُوبَ بْنِ إِسْحَقَ عَمَّنْ حَدَّثَهُ عَنْ مُحَمَّدِ بْنِ كَعْبٍ الْقُرَظِيِّ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَسْتُرُوا الْجُدُرَ مَنْ نَظَرَ فِي كِتَابِ أَخِيهِ بِغَيْرِ إِذْنِهِ فَإِنَّمَا يَنْظُرُ فِي النَّارِ سَلُوا اللَّهَ بِبُطُونِ أَكُفِّكُمْ وَلَا تَسْأَلُوهُ بِظُهُورِهَا فَإِذَا فَرَغْتُمْ فَامْسَحُوا بِهَا وُجُوهَكُمْقَالَ أَبُو دَاوُد رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ عَنْ مُحَمَّدِ بْنِ كَعْبٍ كُلُّهَا وَاهِيَةٌ وَهَذَا الطَّرِيقُ أَمْثَلُهَا وَهُوَ ضَعِيفٌ أَيْضًا","id":"Telah menceritakan kepada Kami [Abdullah bin Maslamah], telah menceritakan kepada Kami [Abdul Malik bin Muhammad bin Aiman] dari [Abdullah bin Ya'qub bin Ishaq] dari [orang yang telah bercerita kepadanya] dari [Muhammad bin Ka'b Al Qurazhi], telah menceritakan kepadaku [Abdullah bin Abbas] bahwa Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Janganlah kalian menutupi tembok-tembok dengan kain kalian, barang siapa yang melihat tulisan saudaranya tanpa seizinnya maka sesungguhnya ia telah melihat kepada Neraka, mintalah kepada Allah dengan menengadahkan telapak tanganmu dan jangan meminta dengan belakang telapak tangan dan apabila kalian telah selesai maka usaplah muka kalian dengan keduanya. Abu Daud berkata: hadits ini diriwayatkan bukan hanya dari satu sisi dari Muhammad bin Ka'bin, semuanya lemah dan jalur ini yang paling bagus, namun hadits tersebut lemah juga. "},"1240":{"ar":"حَدَّثَنَا عُقْبَةُ بْنُ مُكْرَمٍ حَدَّثَنَا سَلْمُ بْنُ قُتَيْبَةَ عَنْ عُمَرَ بْنِ نَبْهَانَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو هَكَذَا بِبَاطِنِ كَفَّيْهِ وَظَاهِرِهِمَا","id":"Telah menceritakan kepada Kami ['Uqbah bin Mukram] telah menceritakan kepada Kami [Salm bin Qutaibah] dari [Umar bin Nabhan] dari [Qatadah] dari [Anas bin Malik] radliallahu 'anhu berkata; aku melihat Rasulullah shallAllahu wa'alaihi wa sallam berdo'a seperti ini dengan menggunakan telapak tangannya dan belakangnya. "},"1241":{"ar":"حَدَّثَنَا مُؤَمَّلُ بْنُ الْفَضْلِ الْحَرَّانِيُّ حَدَّثَنَا عِيسَى يَعْنِي ابْنَ يُونُسَ حَدَّثَنَا جَعْفَرٌ يَعْنِي ابْنَ مَيْمُونٍ صَاحِبَ الْأَنْمَاطِ حَدَّثَنِي أَبُو عُثْمَانَ عَنْ سَلْمَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ رَبَّكُمْ تَبَارَكَ وَتَعَالَى حَيِيٌّ كَرِيمٌ يَسْتَحْيِي مِنْ عَبْدِهِ إِذَا رَفَعَ يَدَيْهِ إِلَيْهِ أَنْ يَرُدَّهُمَا صِفْرًا","id":"Telah menceritakan kepada Kami [Muammal bin Al Fadhl Al Harrani], telah menceritakan kepada Kami [Isa yaitu Ibnu Yunus] telah menceritakan kepada Kami [Ja'far yaitu Ibnu Maimun] pemilik beberapa anmath, telah menceritakan kepadaku [Abu Utsman] dari [Salman], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Sesungguhnya Tuhan kalina Yang Maha Suci dan Maha Tinggi adalah Maha Hidup dan Mulia, Dia merasa malu dari hambanya apabila ia mengangkat kedua tanganya kepadaNya dan mengembalikannya dalam keadaan kosong.\""},"1242":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ حَفْصِ بْنِ هَاشِمِ بْنِ عُتْبَةَ بْنِ أَبِي وَقَّاصٍ عَنْ السَّائِبِ بْنِ يَزِيدَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا دَعَا فَرَفَعَ يَدَيْهِ مَسَحَ وَجْهَهُ بِيَدَيْهِ","id":"Telah menceritakan kepada Kami [Qutaibah bin Sa'id], telah menceritakan kepada Kami [Ibnu Lahi'ah] dari [Hafsh bin Hasyim bin 'Utbah bin Abu Waqqash] dari [As Saib bin Yazid] dari [ayahnya] bahwa Nabi shallallahu 'alaihi wasallam apabila berdoa maka beliau mengangkat kedua tangannya dan mengusap wajahnya dengan keduanya. "},"1243":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ مَالِكِ بْنِ مِغْوَلٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعَ رَجُلًا يَقُولُ اللَّهُمَّ إِنِّي أَسْأَلُكَ أَنِّي أَشْهَدُ أَنَّكَ أَنْتَ اللَّهُ لَا إِلَهَ إِلَّا أَنْتَ الْأَحَدُ الصَّمَدُ الَّذِي لَمْ يَلِدْ وَلَمْ يُولَدْ وَلَمْ يَكُنْ لَهُ كُفُوًا أَحَدٌ فَقَالَ لَقَدْ سَأَلْتَ اللَّهَ بِالِاسْمِ الَّذِي إِذَا سُئِلَ بِهِ أَعْطَى وَإِذَا دُعِيَ بِهِ أَجَابَحَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ الرَّقِّيِّ حَدَّثَنَا زَيْدُ بْنُ حُبَابٍ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ بِهَذَا الْحَدِيثِ قَالَ فِيهِ لَقَدْ سَأَلْتَ اللَّهَ عَزَّ وَجَلَّ بِاسْمِهِ الْأَعْظَمِ","id":"Telah menceritakan kepada Kami [Musaddad] telah menceritakan kepada Kami [Yahya] dari [Malik bin Mighwal] telah menceritakan kepada Kami [Abdullah bin Buraidah] dari [ayahnya] bahwa Rasulullah shallAllahu wa'alaihi wa sallam mendengar seorang laki-laki mengucapkan; ALLAAHUMMA INNII AS-ALUKA ANNII ASYHADU ANNAKA ANTALLAAHU LAA ILAAHA ILLAA ANTA Al AHAD, ASH SHAMAD ALLADZII LAM YALID WA LAM YUULAD WA LAM YAKUN LAHU KUFUWAN AHAD (ya Allah sesungguhnya aku meminta kepada-Mu dengan bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Engkau Dzat Yang Maha Esa dan tempat bergantung Yang tidak beranak dan tidak diperanakkan dan tidak ada seorang pun yang menandingi-Nya). Kemudian beliau berkata: \"Sunngguh engkau telah meminta kepada Allah dengan perantara nama yang apabila Dia diminta dengannya pasti Dia akan mengabulkan.\" Telah menceritakan kepada Kami [Abdurrahman bin Khalid Ar Raqqi], telah menceritakan kepada Kami [Zaid bin Hubbab], telah menceritakan kepada Kami kepada Kami [Malik bin Mighwal] dengan hadits ini dan padanya beliau bersabda: \"Sungguh engkau telah meminta kepada Allah dengan namaNya yang agung.\""},"1244":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عُبَيْدِ اللَّهِ الْحَلَبِيُّ حَدَّثَنَا خَلَفُ بْنُ خَلِيفَةَ عَنْ حَفْصٍ يَعْنِي ابْنَ أَخِي أَنَسٍ عَنْ أَنَسٍأَنَّهُ كَانَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسًا وَرَجُلٌ يُصَلِّي ثُمَّ دَعَا اللَّهُمَّ إِنِّي أَسْأَلُكَ بِأَنَّ لَكَ الْحَمْدُ لَا إِلَهَ إِلَّا أَنْتَ الْمَنَّانُ بَدِيعُ السَّمَوَاتِ وَالْأَرْضِ يَا ذَا الْجَلَالِ وَالْإِكْرَامِ يَا حَيُّ يَا قَيُّومُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ دَعَا اللَّهَ بِاسْمِهِ الْعَظِيمِ الَّذِي إِذَا دُعِيَ بِهِ أَجَابَ وَإِذَا سُئِلَ بِهِ أَعْطَى","id":"Telah menceritakan kepada Kami [Abdurrahman bin 'Ubaidullah Al Halabi], telah menceritakan kepada Kami [Khalaf bin Khalifah] dari [Hafsh yaitu anak saudara Anas] dari [Anas] bahwa ia duduk bersama Rasulullah shallAllahu wa'alaihi wa sallam dan terdapat seorang laki-laki yang melakukan shalat, kemudian ia berdoa; ALLAAHUMMA INNII AS-ALUKA BIANNA LAKAL HAMDU LAA ILAAHA ILLAA ANTA, Al MANNAANU, BADII'US SAMAAWAATI WAL ARDHI, YAA DZAL JALAALI WAL IKRAAM, YAA HAYYU YAA QAYYUUM (ya Allah, aku memohon kepadaMu bahwa bagiMu segala pujian, tidak ada tuhan yang berhak disembah kecuali Engkau, Maha Pemberi, Pencipta langit dan bumi. Wahai Dzat yang memiliki keagungan, serta kemuliaan, wahai Dzat yang Maha Hidup, lagi terus menerus mengurus (makhluk-Nya)). Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Sungguh ia telah berdoa kepada Allah dengan namaNya yang agung, yang apabila dipanjatkan doa kepadaNya dengan nama tersebut maka Dia akan mengabulkannya, dan apabila Dia diminta dengan nama tersebut maka Dia akan memberinya.\""},"1245":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو أَنَّ سَعِيدَ بْنَ أَبِي هِلَالٍ حَدَّثَهُ عَنْ خُزَيْمَةَ عَنْ عَائِشَةَ بِنْتِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ أَبِيهَاأَنَّهُ دَخَلَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى امْرَأَةٍ وَبَيْنَ يَدَيْهَا نَوًى أَوْ حَصًى تُسَبِّحُ بِهِ فَقَالَ أُخْبِرُكِ بِمَا هُوَ أَيْسَرُ عَلَيْكِ مِنْ هَذَا أَوْ أَفْضَلُ فَقَالَ سُبْحَانَ اللَّهِ عَدَدَ مَا خَلَقَ فِي السَّمَاءِ وَسُبْحَانَ اللَّهِ عَدَدَ مَا خَلَقَ فِي الْأَرْضِ وَسُبْحَانَ اللَّهِ عَدَدَ مَا خَلَقَ بَيْنَ ذَلِكَ وَسُبْحَانَ اللَّهِ عَدَدَ مَا هُوَ خَالِقٌ وَاللَّهُ أَكْبَرُ مِثْلُ ذَلِكَ وَالْحَمْدُ لِلَّهِ مِثْ��ُ ذَلِكَ وَلَا إِلَهَ إِلَّا اللَّهُ مِثْلُ ذَلِكَ وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ مِثْلُ ذَلِكَ","id":"Telah menceritakan kepada Kami [Ahmad bin Shalih] telah menceritakan kepada Kami [Abdullah bin Wahb], telah mengabarkan kepadaku ['Amr] bahwa [Sa'id? bin Abu Hilal] telah menceritakan kepadanya dari [Khuzaimah] dari [Aisyah binti Sa'd bin Abu Waqqash] dari [ayahnya] bahwa ia bersama Rasulullah shallla Allahu 'alaihi wa sallam menemui seorang wanita sementara dihadapannya terdapat biji-bijian atau kerikil yang dipergunakan untuk bertasbih. Kemudian Nabi Shalla Allahu 'alaihi wa sallam berkata: \"Aku akan memberitahukan kepadamu sesuatu yang lebih mudah bagimu dari pada ini dan lebih utama!\" Lalu beliau mengucapkan: \"SUBHAANALLAAHI 'ADADA MAA KHALAQA FIS SAMAAI WA SUBHAANALLAAHI 'ADADA MAA KHALAQA FIL ARDHI WA SUBHAANALLAAHI 'ADADA MAA KHALAQA BAINA DZAALIKA WA SUBHAANALLAAHI 'ADADA MAA HUWA KHAALIQUN, WALLAAHU AKBARU MITSLU DZAALIKA, WAL HAMDU LILLAAHI MITSLU DZAALIKA WA LAA ILAAHA ILLALLAAHU MITSLU DZAALIKA WA LAA HAULA WA LAA QUWWATA ILLAA BILLAAHI MITSLU DZAALIKA\" (Maha Suci Allah sebanyak makhluk yang Dia ciptakan dilangit, dan Maha Suci Allah sebanyak makhluk yang Dia ciptakan di bumi, dan Maha Suci Allah sebanyak makhluk yang Dia ciptakan diantara keduanya dan Maha Suci Allah sebanyak apa yang Dia ciptakan, dan Allah Maha Besar seperti itu, segala puji bagi Allah seperti itu, dan tidak ada tuhan yang berhak disembah kecuali Allah seperti itu, dan tidak ada daya serta kekuatan kecuali karena Allah seperti itu) "},"1246":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ عَنْ هَانِئِ بْنِ عُثْمَانَ عَنْ حُمَيْضَةَ بِنْتِ يَاسِرٍ عَنْ يُسَيْرَةَ أَخْبَرَتْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهُنَّ أَنْ يُرَاعِينَ بِالتَّكْبِيرِ وَالتَّقْدِيسِ وَالتَّهْلِيلِ وَأَنْ يَعْقِدْنَ بِالْأَنَامِلِ فَإِنَّهُنَّ مَسْئُولَاتٌ مُسْتَنْطَقَاتٌ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Abdullah bin Daud] dari [Hani` bin Utsman] dari [Humaidhah binti Yasir] dari [Yusairah] ia telah mengabarkan kepadanya bahwa Nabi shallallahu 'alaihi wasallam memerintahkan mereka (para wanita) agar menjaga takbir, pensucian Allah, serta tahlil, dan menghitung dzikir menggunakan ruas-ruas jari, karena ruas-ruas tersebut akan ditanya dan diminta untuk berbicara. "},"1247":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ بْنِ مَيْسَرَةَ وَمُحَمَّدُ بْنُ قُدَامَةَ فِي آخَرِينَ قَالُوا حَدَّثَنَا عَثَّامٌ عَنْ الْأَعْمَشِ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْقِدُ التَّسْبِيحَ قَالَ ابْنُ قُدَامَةَ بِيَمِينِهِ","id":"Telah menceritakan kepada Kami ['Ubaidullah bin Umar bin Maisarah] dan [Muhammad bin Qudamah] diantara orang-orang yang lain, mereka berkata; \"Telah menceritakan kepada Kami ['Atstsam] dari [Al A'masy] dari ['Atho` bin As Saib] dari [ayahnya] dari [Abdullah bin 'Amr], ia berkata; aku melihat Rasulullah shallla Allahu 'alaihi wa sallam menghitung tasbih. Ibnu Qudamah berkata: yaitu dengan tangan kanannya. "},"1248":{"ar":"حَدَّثَنَا دَاوُدُ بْنُ أُمَيَّةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ مَوْلَى آلِ طَلْحَةَ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عِنْدِ جُوَيْرِيَةَ وَكَانَ اسْمُهَا بُرَّةَ فَحَوَّلَ اسْمَهَا فَخَرَجَ وَهِيَ فِي مُصَلَّاهَا وَرَجَعَ وَهِيَ فِي مُصَلَّاهَا فَقَالَ لَمْ تَزَالِي فِي مُصَلَّاكِ هَذَا قَالَتْ نَعَمْ قَالَ قَدْ قُلْتُ بَعْدَكِ أَرْبَعَ كَلِمَاتٍ ثَلَاثَ مَرَّاتٍ لَوْ وُزِنَتْ بِمَا قُلْتِ لَوَزَنَتْهُنَّ سُبْحَانَ اللَّهِ وَبِحَمْدِهِ عَدَدَ خَلْقِهِ وَرِضَا نَفْسِهِ وَزِنَةَ عَرْشِهِ وَمِدَادَ كَلِمَاتِهِ","id":"Telah menceritakan kepada Kami [Daud bin Umayyah], telah menceritakan kepada Kami [Sufyan bin 'Uyainah] dari [Muhammad bin Abdurrahman] mantan budak keluarga Thalhah, dari [Kuraib] dari [Ibnu Abbas], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam keluar dari sisi Juwairiyah, dan namanya adalah Burrah, kemudian beliau mengganti namanya, beliau keluar sementara ia berada dalam tempat shalatnya, beliau kembali dan ia masih berada di tempat shalatnya. Kemudian beliau berkata: \"Apakah engkau akan tetap berada dalam tempat shalatmu ini?\" Juwairiyah berkata; \"ya.\" Beliau bersabda: \"Setelah pergi darimu aku telah mengucapkan empat kalimat selama tiga kali, apabila empat kalimat tersebut ditimbang dengan apa yang engkau ucapkan niscaya akan lebih berat, yaitu: SUBHAANALLAAHI WA BIHAMDIHI 'ADADA KHALQIHI WA RIDHAA NAFSIHI WA ZINATA 'ARSYIHI WA MIDAADA KALIMAATIHI (Maha Suci Allah, dengan memuji kepadaNya sebanyak makhlukNya, dan keridhaan diriNya, berat 'ArsyNya, dan keluasan kalimat-kalimatNya).\""},"1249":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي حَسَّانُ بْنُ عَطِيَّةَ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي عَائِشَةَ قَالَ حَدَّثَنِي أَبُو هُرَيْرَةَ قَالَ قَالَ أَبُو ذَرٍّيَا رَسُولَ اللَّهِ ذَهَبَ أَصْحَابُ الدُّثُورِ بِالْأُجُورِ يُصَلُّونَ كَمَا نُصَلِّي وَيَصُومُونَ كَمَا نَصُومُ وَلَهُمْ فُضُولُ أَمْوَالٍ يَتَصَدَّقُونَ بِهَا وَلَيْسَ لَنَا مَالٌ نَتَصَدَّقُ بِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا ذَرٍّ أَلَا أُعَلِّمُكَ كَلِمَاتٍ تُدْرِكُ بِهِنَّ مَنْ سَبَقَكَ وَلَا يَلْحَقُكَ مَنْ خَلْفَكَ إِلَّا مَنْ أَخَذَ بِمِثْلِ عَمَلِكَ قَالَ بَلَى يَا رَسُولَ اللَّهِ قَالَ تُكَبِّرُ اللَّهَ عَزَّ وَجَلَّ دُبُرَ كُلِّ صَلَاةٍ ثَلَاثًا وَثَلَاثِينَ وَتَحْمَدُهُ ثَلَاثًا وَثَلَاثِينَ وَتُسَبِّحُهُ ثَلَاثًا وَثَلَاثِينَ وَتَخْتِمُهَا بِلَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ غُفِرَتْ لَهُ ذُنُوبُهُ وَلَوْ كَانَتْ مِثْلَ زَبَدِ الْبَحْرِ","id":"Telah menceritakan kepada Kami [Abdurrahman bin Ibrahim] telah menceritakan kepada Kami [Al Walid bin Muslim], telah menceritakan kepada Kami [Al Auza'i], telah menceritakan kepadaku [Hassan bin 'Athiyyah], ia berkata; telah menceritakan kepadaku [Muhammad bin Abu Aisyah], ia berkata; telah menceritakan kepadaku [Abu Hurairah RhadhiyAllahu 'anhu], ia berkata; Abu Dzar berkata; wahai RasulAllah! Orang-orang kaya pergi dengan membawa banyak pahala, mereka melakukan shalat sebagaimana Kami melakukan shalat, mereka berpuasa sebagaimana Kami berpuasa, mereka mempunyai kelebihan harta yang mereka sedekahkan sementara Kami tidak memiliki harta untuk bersedekah. Kemudian Rasulullah shalallAllahu 'alaihi wa sallam berkata: \"Wahai Abu Dzar, maukah aku ajarkan kepadamu beberapa kalimat yang dengannya kamu dapat menyusul orang yang telah mendahuluimu dan orang yang di belakangmu tidak dapat mengejarmu kecuali orang yang mengerjakan seperti apa yang kamu kerjakan?\" Dia menjawab; ya, wahai Rasulullah! Beliau bersabda: \"Engkau bertakbir kepada tiga puluh tiga kali setiap selesai shalat, bertahmid tiga puluh tiga kali, bertasbih tiga puluh tiga kali dan kamu tutup dengan ucapan LAA ILAAHA ILLALLAAHU WAHDAU LAA SYARIIKALAHU, LAHUL MULKU WA LAHUL HAMDU WA HUWA 'ALAA KULLI SYAI-IN QADIIR (tidak ada tuhan yang berhak disembah kecuali Allah semata, tidak ada sekutu bagiNya, milikNya seluruh kerajaan, dan bagi-Nya segala puji dan Dia Maha Mampu melakukan segala sesuatu) niscaya dosa-dosanya akan diampuni walaupun sebanyak buih lautan.\""},"1250":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ الْمُسَيَّبِ بْنِ رَافِعٍ عَنْ وَرَّادٍ مَوْلَى الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَكَتَبَ مُعَاوِيَةُ إِلَى الْمُغِيرَةِ بْنِ شُعْبَةَ أَيُّ شَيْءٍ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا سَلَّمَ مِنْ الصَّلَاةِ فَأَمْلَاهَا الْمُغِيرَةُ عَلَيْهِ وَكَتَبَ إِلَى مُعَاوِيَةَ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى الل��َهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ اللَّهُمَّ لَا مَانِعَ لِمَا أَعْطَيْتَ وَلَا مُعْطِيَ لِمَا مَنَعْتَ وَلَا يَنْفَعُ ذَا الْجَدِّ مِنْكَ الْجَدُّ","id":"Telah menceritakan kepada Kami [Musaddad], ia berkata; telah menceritakan kepada Kami [Abu Mu'awiyah] dari [Al A'masy] dari [Al Musayyab bin Rafi'] dari [Warrad] mantan budak Al Mughirah bin Syu'bah, dari [Al Mughirah bin Syu'bah], Mu'awiyah menulis surat kepada Al Mughirah bin Syu'bah; apakah yang diucapkan Rasulullah apabila telah mengucapkan salam dari shalatnya? Kemudian Al Mughirah mendektekannya kepadanya dan menulis kepada Mu'awiyah, ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam mengucapkan: \"LAA ILAAHA ILLALLAAHU WAHDAU LAA SYARIIKALAHU, LAHUL MULKU WA LAHUL HAMDU WA HUWA 'ALAA KULLI SYAI-IN QADIIR, ALLAAHUMMA LAA MAANI'A LIMAA A'THAITA WA LAA MU'THIYA LIMAA MANA'TA WA LAA YANFA'U DZAL JADDI MINKAL JADDU\" (tidak ada tuhan yang berhak disembah kecuali Allah semata, tidak ada sekutu bagiNya, milikNya seluruh kerajaan, dan bagi-Nya segala puji dan Dia Maha Mampu melakukan segala sesuatu. Ya Allah, tidak ada yang dapat menahan apa yang Engkau berikan, dan tidak ada yang dapat memberikan apa yang Engkau tahan, serta tidaklah bermanfaat kekayaan bagi orang yang kaya dari adzabMu) "},"1251":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ الْحَجَّاجِ بْنِ أَبِي عُثْمَانَ عَنْ أَبِي الزُّبَيْرِ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ عَلَى الْمِنْبَرِ يَقُولُكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا انْصَرَفَ مِنْ الصَّلَاةِ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ لَا إِلَهَ إِلَّا اللَّهُ مُخْلِصِينَ لَهُ الدِّينَ وَلَوْ كَرِهَ الْكَافِرُونَ أَهْلُ النِّعْمَةِ وَالْفَضْلِ وَالثَّنَاءِ الْحَسَنِ لَا إِلَهَ إِلَّا اللَّهُ مُخْلِصِينَ لَهُ الدِّينَ وَلَوْ كَرِهَ الْكَافِرُونَحَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا عَبْدَةُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِي الزُّبَيْرِ قَالَ كَانَ عَبْدُ اللَّهِ بْنُ الزُّبَيْرِ يُهَلِّلُ فِي دُبُرِ كُلِّ صَلَاةٍ فَذَكَرَ نَحْوَ هَذَا الدُّعَاءِ زَادَ فِيهِ وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ لَا إِلَهَ إِلَّا اللَّهُ لَا نَعْبُدُ إِلَّا إِيَّاهُ لَهُ النِّعْمَةُ وَسَاقَ بَقِيَّةَ الْحَدِيثِ","id":"Telah menceritakan kepada Kami [Muhammad bin Isa], ia berkata; telah menceritakan kepada Kami [Ibnu 'Ulayyah] dari [Al Hajjaj bin Abu 'Utsman] dari [Abu Az Zubair], ia berkata; saya mendengar [Abdullah bin Az Zubair] di atas mimbar berkata; Nabi shallallahu 'alaihi wasallam apabila selesai dari shalat mengucapkan: \"LAA ILAAHA ILLALLAAHU WAHDAHU LAA SYARIIKALAHU, LAHUL MULKU WA LAHUL HAMDU WA HUWA 'ALAA KULLI SYAI-IN QADIIR, LAA ILAAHA ILLALLAAHU MUKHLISHIINA LAHUD DIIN, WALAU KARIHAL KAAFIRUUN, AHLUN NI'MATI WAL FADHLI WATS TSANAAIL HASAN, LAA ILAAHA ILLALLAAHU MUKHLISHIINA LAHUD DIIN WALAU KARIHAL KAAFIRUUN.\" (Tidak ada tuhan yang berhak disembah kecuali Allah semata, tidak ada sekutu bagiNya, milikNya seluruh kerajaan, dan bagi-Nya segala puji dan Dia Maha Mampu melakukan segala sesuatu, tidak ada tuhan yang berhak disembah kecuali Allah, Kami memurnikan ketundukan kepadaNya, walaupun orang-orang kafir merasa tidak senang. Dialah Yang Pemilik segala kenikmatan, karunia serta pujian yang baik. Tidak ada tuhan yang berhak disembah kecuali Allah, Kami memurnikan ketundukan kepadaNya walaupun orang-orang kafir merasa tidak senang). Telah menceritakan kepada Kami [Muhammad bin Sulaiman Al Anbari], telah menceritakan kepada Kami ['Abdah] dari [Hisyam bin 'Urwah] dari [Abu Az Zubair], ia berkata; [Abdullah bin Az Zubair] bertahlil setiap selesai shalat, kemudian menyebutkan doa seperti ini dan ia menambahkan; LAA HAULA WA LAA QUWWATA ILLAA BILLAAH, LAA ILAAHA ILLALLAAHU, LAA NA'BUDU ILLAA IYYAAHU, LAHUN NI'MATU (tidak ada daya dan kekuatan kecuali karena Allah, tidak ada tuhan yang berhak disembah kecuali Allah, Kami tidak menyembah kecuali hanya kepadaNya, bagiNya segala kenikmatan), dan ia menyebutkan kelanjutan hadits tersebut. "},"1252":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَسُلَيْمَانُ بْنُ دَاوُدَ الْعَتَكِيُّ وَهَذَا حَدِيثُ مُسَدَّدٍ قَالَا حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ دَاوُدَ الطُّفَاوِيَّ قَالَ حَدَّثَنِي أَبُو مُسْلِمٍ الْبَجَلِيُّ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَسَمِعْتُ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَقَالَ سُلَيْمَانُ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي دُبُرِ صَلَاتِهِ اللَّهُمَّ رَبَّنَا وَرَبَّ كُلِّ شَيْءٍ أَنَا شَهِيدٌ أَنَّكَ أَنْتَ الرَّبُّ وَحْدَكَ لَا شَرِيكَ لَكَ اللَّهُمَّ رَبَّنَا وَرَبَّ كُلِّ شَيْءٍ أَنَا شَهِيدٌ أَنَّ مُحَمَّدًا عَبْدُكَ وَرَسُولُكَ اللَّهُمَّ رَبَّنَا وَرَبَّ كُلِّ شَيْءٍ أَنَا شَهِيدٌ أَنَّ الْعِبَادَ كُلَّهُمْ إِخْوَةٌ اللَّهُمَّ رَبَّنَا وَرَبَّ كُلِّ شَيْءٍ اجْعَلْنِي مُخْلِصًا لَكَ وَأَهْلِي فِي كُلِّ سَاعَةٍ فِي الدُّنْيَا وَالْآخِرَةِ يَا ذَا الْجَلَالِ وَالْإِكْرَامِ اسْمَعْ وَاسْتَجِبْ اللَّهُ أَكْبَرُ الْأَكْبَرُ اللَّهُمَّ نُورَ السَّمَوَاتِ وَالْأَرْضِ قَالَ سُلَيْمَانُ بْنُ دَاوُدَ رَبَّ السَّمَوَاتِ وَالْأَرْضِ اللَّهُ أَكْبَرُ الْأَكْبَرُ حَسْبِيَ اللَّهُ وَنِعْمَ الْوَكِيلُ اللَّهُ أَكْبَرُ الْأَكْبَرُ","id":"Telah menceritakan kepada Kami [Musaddad] serta [Sulaiman bin Daud Al 'Ataki], dan ini adalah hadits Musaddad. Mereka berdua mengatakan; telah menceritakan kepada Kami [Al Mu'tamir] ia berkata; saya mendengar [Daud Ath Thufawi] berkata; telah menceritakan kepadaku [Abu Muslim Al Bajali] dari [Zaid bin Arqam] ia berkata; saya mendengar Nabi shallallahu 'alaihi wasallam mengucapkan: …. Sedangkan Sulaiman berkata; Rasulullah shallAllahu wa'alaihi wa sallam mengucapkan setiap selesai shalat: \"ALLAAHUMMA RABBANAA WA RABBA KULLI SYAI-IN WA ANA SYAHIIDUN ANNAKAR RABBU WAHDAKA LAA SYARIIKA LAKA, ALLAAHUMMA RABBANAA WA RABBA KULLI SYAI-IN, ANA SYAHIIDUN ANNA MUHAMMADAN 'ABDUKA WA RUSUULUKA. ALLAAHUMMA RABBANAA WA RABBA KULLI SYAI-IN ANA SYAHIIDUN ANNAL 'IBAADA KULLAHUM IKHWATUN, ALLAAHUMMA RABBANAA WA RABBA KULLI SYAI-IN, IJ'ALNII MUKHLISHAN LAKA WA AHLII FII KULLI SAA'ATIN FID DUNYAA WAL AAKHIRAH, YAA DZAL JALAALI WAL IKRAAM, ISMA' WAS TAJIB. ALLAAHU AKBARUL AKBAR, ALLAAHUMMA NUURAS SAMAAWAATI WAL ARDHI (Ya Allah, Tuhan Kami dan Tuhan segala sesuatu, aku bersaksi bahwa Engkau adalah Tuhan satu-satunya, tidak ada sekutu bagiMu. Ya Allah, Tuhan Kami dan Tuhan segala sesuatu, aku bersaksi bahwa Muhammad adalah hamba dan utusanMu. Ya Allah, Tuhan Kami dan Tuhan segala sesuatu, aku bersaksi bahwa seluruh hamba adalah bersaudara, ya Allah, Tuhan Kami dan Tuhan segala sesuatu, jadikanlah aku orang yang mengikhlaskan ibadah kepadaMu, begitu juga keluargaku, di dalam setiap saat, di dunia serta Akhirat, wahai Dzat Yang Memiliki keagungan serta kemuliaan. Dengarkan perkenankanlah. Allah Maha Besar, ya Allah, Pemberi cahaya langit dan bumi). Sulaiman bin Daud mengucapkan; RABBAS SAMAAWAATI WAL ARDHI, ALLAAHU AKBARUL AKBARU, HASBIYALLAAHU WA NI'MAL WAKIIL, ALLAAHU AKBARUL AKBARU (Tuhan langit dan bumi, Allah Maha Besar, cukuplah Allah bagiku, dan Dialah sebaik-baik wakil, Allah Maha Besar). "},"1253":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ قَالَ حَدَّثَنَا أَبِي حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ عَنْ عَمِّهِ الْمَاجِشُونِ بْنِ أَبِي سَلَمَةَ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَلَّمَ مِنْ الصَّلَاةِ قَالَ اللَّهُمَّ اغْفِرْ لِي مَا قَدَّمْتُ وَمَا أَخَّرْتُ وَمَا أَسْرَرْتُ وَمَا أَعْلَنْتُ وَمَا أَسْرَفْتُ وَمَا أَنْتَ أَعْلَمُ بِهِ مِنِّي أَنْتَ الْمُقَدِّمُ وَأَنْتَ الْمُؤَخِّرُ لَا إِلَهَ إِلَّا أَنْتَ","id":"Telah menceritakan kepada Kami ['Ubaidullah bin Mu'adz] ia berkata; telah menceritakan kepada Kami [ayahku], telah menceritakan kepada Kami [Abdul Aziz bin Abu Salamah] dari [pamannya yaitu Al Majisyun bin Abu Salamah] dari [Abdurrahman Al A'raj] dari ['Ubaidullah bin Abu Rafi'] dari [Ali bin Abu Thalib] ia berkata; Nabi shallallahu 'alaihi wasallam apabila mengucapkan salam setelah shalat beliau mengucapkan: \"ALLAAHUMMAGHFIRLII MAA QADDAMTU WA MAA AKHKHARTU WA MAA ASRARTU WA MAA A'LANTU WA MAA ASRAFTU, WA MAA ANTA A'LAMU BIHI MINNII, ANTAL MUQADDIMU WA ANTAL MUAKHKHIRU LAA ILAAHA ILLAA ANTA\" (Ya Allah, ampunilah bagiku apa yang telah aku lakukan dan apa yang belum aku lakukan, apa yang aku sembunyikan dan apa yang aku nampakkan, apa yang lakukan secara berlebihan, dan apa yang Engkau lebih tahu daripada diriku. Engkau Yang mendahulukan dan Yang mengakhirkan, tidak ada tuhan yang berhak disembah kecuali Engkau.\""},"1254":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ طُلَيْقِ بْنِ قَيْسٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو رَبِّ أَعِنِّي وَلَا تُعِنْ عَلَيَّ وَانْصُرْنِي وَلَا تَنْصُرْ عَلَيَّ وَامْكُرْ لِي وَلَا تَمْكُرْ عَلَيَّ وَاهْدِنِي وَيَسِّرْ هُدَايَ إِلَيَّ وَانْصُرْنِي عَلَى مَنْ بَغَى عَلَيَّ اللَّهُمَّ اجْعَلْنِي لَكَ شَاكِرًا لَكَ ذَاكِرًا لَكَ رَاهِبًا لَكَ مِطْوَاعًا إِلَيْكَ مُخْبِتًا أَوْ مُنِيبًا رَبِّ تَقَبَّلْ تَوْبَتِي وَاغْسِلْ حَوْبَتِي وَأَجِبْ دَعْوَتِي وَثَبِّتْ حُجَّتِي وَاهْدِ قَلْبِي وَسَدِّدْ لِسَانِي وَاسْلُلْ سَخِيمَةَ قَلْبِيحَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ سَمِعْتُ عَمْرَو بْنَ مُرَّةَ بِإِسْنَادِهِ وَمَعْنَاهُ قَالَ وَيَسِّرْ الْهُدَى إِلَيَّ وَلَمْ يَقُلْ هُدَايَ","id":"Telah menceritakan kepada Kami [Muhammad bin Katsir], telah mengabarkan kepada Kami [Sufyan] dari ['Amr bin Murrah] dari [Abdullah bin Al Harits] dari [Thalq bin Qais] dari [Ibnu Abbas], ia berkata; Nabi shallallahu 'alaihi wasallam berdoa dengan mengucapkan: \"RABBI A'INNII WA LAA TU'IN 'ALAYYA, WAN SHURNII WA LAA TANSHUR 'ALAYYA WAMKUR LII WA LAA TAMKUR 'ALAYYA, WAHDINII WA YASSIR HUDAYA ILAYYA WAN SHURNII 'ALAA MAN BAGHAA 'ALAYYA. ALLAAHUMMAJ'ALNII LAKA SYAAKIRAN, DZAAKIRAN LAKA, RAAHIBAN, LAKA MITHWAA'AN ILAIKA, MUKHBITAN AU MUNIIBAN. RABBI TAQABBAL TAUBATII WAGHSIL HAUBATII WA AJIB DA'WATII WA TSABBIT HUJJATII, WAHDI QALBII, WA SADDID LISAANII, WASLUL SAKHIIMATA QALBII\" (Ya Allah, bantulah aku dan jangan Engkau bantu untuk memusuhiku, tolonglah aku dan jangan Engkau tolong untuk memusuhiku, lakukan tipu daya untukku dan jangan Engkau melakukan tipu daya terhadap diriku, berilah kau petunjuk dan permudahlah petunjuk kepadaku, tolonglah aku menghadapi orang yang berbuat lalim terhadap diriku. Ya Allah, jadikanlah aku orang yang bersyukur kepadaMu, ingat kepadaMu, takut kepadaMu, taat kepadaMu, tunduk kepadaMu, atau kembali kepadaMu. Tuhanku, terimalah taubatku, hilangkan kegelisahanku, dan kabulkan doaku, teguhkan hujjahku, dan berilah petunjuk hatiku, luruskan lisanku, dan cabutlah kedengkian hatiku). Telah menceritakan kepada Kami [Musaddad] telah menceritakan kepada Kami [Yahya] dari [Sufyan], ia berkata; aku mendengar ['Amr bin Murrah] dengan sanad dan maknanya ia berkata; \"dan mudahkanlah petunjuk kepadaku\" bukan \"petunjukku\". "},"1255":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ الْأَحْوَلِ وَخَالِدٍ الْحَذَّاءِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا سَلَّمَ قَالَ اللَّهُمَّ أَنْتَ السَّلَامُ وَمِنْكَ السَّلَامُ تَبَارَكْتَ يَا ذَا الْجَلَالِ وَالْإِكْرَامِقَالَ أَبُو دَاوُد سَمِعَ سُفْيَانُ مِنْ عَمْرِو بْنِ مُرَّةَ قَالُوا ثَمَانِيَةَ عَشَرَ حَدِيثًا حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا عِيسَى عَنْ الْأَوْزَاعِيِّ عَنْ أَبِي عَمَّارٍ عَنْ أَبِي أَسْمَاءَ عَنْ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَرَادَ أَنْ يَنْصَرِفَ مِنْ صَلَاتِهِ اسْتَغْفَرَ ثَلَاثَ مَرَّاتٍ ثُمَّ قَالَ اللَّهُمَّ فَذَكَرَ مَعْنَى حَدِيثِ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا","id":"Telah menceritakan kepadaku [Muslim bin Ibrahim] telah menceritakan kepada Kami [Syu'bah] dari ['Ashim Al Ahwal] dan [Khalid Al Hadzdza`] dari [Abdullah bin Al Harits] dari [Aisyah] radliallahu 'anha bahwa Nabi shallallahu 'alaihi wasallam apabila mengucapkan salam beliau berdoa: \"ALLAAHUMMA ANTAS SALAAM WA MINKAS SALAAM TABAARAKTA YAA DZAL JALAALI WAL IKRAAM\" (Ya Allah, Engkau adalah Dzat Yang Memberikan keselamatan, dan darimu datang keselamatan, Maha Suci Engkau wahai Dzat yang memiliki keagungan dan kemuliaan). Abu Daud berkata; Sufyan telah mendengar dari 'Amr bin Murrah (mereka mengatakan sebayak delapan belas hadits), telah menceritakan kepada Kami [Ibrahim bin Musa], telah mengabarkan kepada Kami [Isa] dari [Al Auza'i] dari [Abu 'Ammar] dari [Abu Asma`] dari [Tsauban] mantan budak Rasulullah shallAllahu wa'alaihi wa sallam bahwa Nabi shallallahu 'alaihi wasallam apabila hendak berpaling dari shalat beliau beristighfar tiga kali, kemudian mengucapkan, \"ALLAAHUMMA…..\" kemudian ia menyebutkan hadits Aisyah radliallahu 'anha. "},"1256":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ وَمُسَدَّدٌ قَالَا حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ عَنْ أَبِي بُرْدَةَ عَنْ الْأَغَرِّ الْمُزَنِيِّ قَالَ مُسَدَّدٌ فِي حَدِيثِهِ وَكَانَتْ لَهُ صُحْبَةٌ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ لَيُغَانُ عَلَى قَلْبِي وَإِنِّي لَأَسْتَغْفِرُ اللَّهَ فِي كُلِّ يَوْمٍ مِائَةَ مَرَّةٍ","id":"Telah menceritakan kepada Kami [Sulaiman bin Harb] serta [Musaddad] mereka berkata; telah menceritakan kepada Kami [Hammad] dari [Tsabit] dari [Abu Burdah] dari [Al Agharr Al Muzani], Musaddad yang pernah menyertai Nabi shallallahu 'alaihi wasallam dalam haditsnya mengatakan; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Sesungguhnya hatiku pernah tertutup dan aku beristighfar kepada Allah dalam sehari sebanyak seratus kali.\""},"1257":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ مَالِكِ بْنِ مِغْوَلٍ عَنْ مُحَمَّدِ بْنِ سُوقَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَإِنْ كُنَّا لَنَعُدُّ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَجْلِسِ الْوَاحِدِ مِائَةَ مَرَّةٍ رَبِّ اغْفِرْ لِي وَتُبْ عَلَيَّ إِنَّكَ أَنْتَ التَّوَّابُ الرَّحِيمُ","id":"Telah menceritakan kepada Kami [Al Hasan bin Ali], telah menceritakan kepada Kami [Abu Usamah] dari [Malik bin Mighwal] dari [Muhammad bin Suqah] dari [Nafi'] dari [Ibnu Umar], ia berkata; sungguh Kami telah menghitung ucapan Rasulullah shallla Allahu 'alaihi wa sallam dalam satu majlis beliau \"RABBIGHFIRLII WA TUB 'ALAYYA, INNAKAT TAWWAABUR RAHIIM\" (Ya Tuhanku, ampunilah aku dan terimalah taubatku sesungguhnya Engkau adalah Dzat yang Maha menerima taubat lagi Maha Penyayang) sebanyak seratus kali."},"1258":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْحَكَمُ بْنُ مُصْعَبٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَلِيِّ بْنِ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ أَبِيهِ أَنَّهُ حَدَّثَهُ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ حَدَّثَهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَزِمَ الِاسْتِغْفَارَ جَعَلَ اللَّهُ لَهُ مِنْ كُلِّ ضِيقٍ مَخْرَجًا وَمِنْ كُلِّ هَمٍّ فَرَجًا وَرَزَقَهُ مِنْ حَيْثُ لَا يَحْتَسِبُ","id":"Telah menceritakan dari Kami [Hisyam bin 'Ammar], telah menceritakan kepada Kami [Al Walid bin Muslim], telah menceritakan kepada Kami [Al Hakam bin Mush'ab], telah menceritakan kepada Kami [Muhammad bin Ali bin Abdullah bin Abbas] dari [ayahnya] bahwa ia bercerita kepadanya, dari [Ibnu Abbas] bahwa ia bercerita kepadanya, ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Barang siapa yang senantiasa beristighfar, maka Allah pasti akan selalu memberikannya jalan keluar dari setiap kesempitan dan kelapangan dari segala kegundahan serta Allah akan memberikan rizki kepadanya dari arah yang tidak ia sangka-sangka.\""},"1259":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ ح و حَدَّثَنَا زِيَادُ بْنُ أَيُّوبَ حَدَّثَنَا إِسْمَعِيلُ الْمَعْنَى عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ قَالَ سَأَلَ قَتَادَةُ أَنَسًاأَيُّ دَعْوَةٍ كَانَ يَدْعُو بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْثَرُ قَالَ كَانَ أَكْثَرُ دَعْوَةٍ يَدْعُو بِهَا اللَّهُمَّ رَبَّنَا آتِنَا فِي الدُّنْيَا حَسَنَةً وَفِي الْآخِرَةِ حَسَنَةً وَقِنَا عَذَابَ النَّارِوَزَادَ زِيَادٌ وَكَانَ أَنَسٌ إِذَا أَرَادَ أَنْ يَدْعُوَ بِدَعْوَةٍ دَعَا بِهَا وَإِذَا أَرَادَ أَنْ يَدْعُوَ بِدُعَاءٍ دَعَا بِهَا فِيهَا","id":"Telah menceritakan kepada Kami [Musaddad] telah menceritakan kepada Kami [Abdul Harits] dan telah diriwayatkan melalui jalur yang lain: Telah menceritakan kepada Kami [Ziyad bin Ayyub], telah menceritakan kepada Kami [Isma'il Al Ma'na] dari [Abdul Aziz bin Shuhaib], ia berkata; Qatadah bertanya kepada [Anas] doa apakah yang lebih sering diucapkan Rasulullah shallAllahu wa'alaihi wa sallam? Doa yang lebih sering diucapkan Rasulullah shallAllahu wa'alaihi wa sallam adalah ALLAAHUMMA RABBANAA AATINAA FIDDUNYAA HASANATA WA QINAA 'ADZAABAN NAAR (Ya Allah Tuhan Kami, berikanlah kepada Kami kebaikan di dunia, dan lindungilah Kami dari adzab Neraka). Ziyad menambahkan; Anas apabila hendak menyeru dengan sebuah seruan maka ia menyeru dengannya dan apabila hendak berdoa dengan sebuah doa maka ia berdoa dengannya. "},"1260":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ خَالِدٍ الرَّمْلِيُّ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ شُرَيْحٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَأَلَ اللَّهَ الشَّهَادَةَ صَادِقًا بَلَّغَهُ اللَّهُ مَنَازِلَ الشُّهَدَاءِ وَإِنْ مَاتَ عَلَى فِرَاشِهِ","id":"Telah menceritakan kepada Kami [Yazid bin Khalid Ar Ramli], telah menceritakan kepada Kami [Ibnu Wahb], telah menceritakan kepada Kami [Abdurrahman bin Syuraih] dari [Abu Umamah bin Sahl bin Hunaif] dari [ayahnya], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Barang siapa yang memohon kepada Allah agar meninggal dalam keadaan syahid dengan jujur, maka Allah akan menyampaikannya kepada derajat para syuhada walaupun dia mati diatas tempat tidurnya.\""},"1261":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ بْنِ مَيْسَرَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ الْمُقْرِئُ حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ قَالَ سَمِعْتُ عُقْبَةَ بْنَ مُسْلِمٍ يَقُولُ حَدَّثَنِي أَبُو عَبْدِ الرَّحْمَنِ الْحُبُلِيُّ عَنْ الصُّنَابِحِيِّ عَنْ مُعَاذِ بْنِ جَبَلٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَ بِيَدِهِ وَقَالَ يَا مُعَاذُ وَاللَّهِ إِنِّي لَأُحِبُّكَ وَاللَّهِ إِنِّي لَأُحِبُّكَ فَقَالَ أُوصِيكَ يَا مُعَاذُ لَا تَدَعَنَّ فِي دُبُرِ كُلِّ صَلَاةٍ تَقُولُ اللَّهُمَّ أَعِنِّي عَلَى ذِكْرِكَ وَشُكْرِكَ وَحُسْنِ عِبَادَتِكَوَأَوْصَى بِذَلِكَ مُعَاذٌ الصُّنَابِحِيَّ وَأَوْصَى بِهِ الصُّنَابِحِيُّ أَبَا عَبْدِ الرَّحْمَنِ","id":"Telah menceritakan kepada Kami ['Ubaidullah bin Umar bin Maisarah] telah menceritakan kepada Kami [Abdullah bin Yazid Al Muqri`], telah menceritakan kepada Kami [Haiwah bin Syuraih], ia berkata; aku mendengar ['Uqbah bin Muslim] berkata; telah menceritakan kepadaku [Abu Abdurrahman Al Hubuli] dari [Ash Shunabihi] dari [Mu'adz bin Jabal] bahwa Rasulullah shallAllahu wa'alaihi wa sallam menggandeng tangannya dan berkata: \"Wahai Mu'adz, demi Allah, aku mencintaimu.\" Kemudian beliau berkata: \"Aku wasiatkan kepadamu wahai Mu'adz, janganlah engkau tinggalkan setiap selesai shalat untuk mengucapkan, \"ALLAAHUMMA A'INNII 'ALAA DZIKRIKA WA SYUKRIKA WA HUSNI 'IBAADATIK\" (Ya Allah, bantulah aku untuk berdzikir dan bersyukur kepadaMu serta beribadah kepadaMu dengan baik.) Mu'adz mewasiatkan dengan hal tersebut kepada Ash Shunabihi dan Ash Shunabihi mewasiatkan hal tersebut kepada Abdurrahman. "},"1262":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ الْمُرَادِيُّ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ اللَّيْثِ بْنِ سَعْدٍ أَنَّ حُنَيْنَ بْنَ أَبِي حَكِيمٍ حَدَّثَهُ عَنْ عَلِيِّ بْنِ رَبَاحٍ اللَّخْمِيِّ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَأَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَقْرَأَ بِالْمُعَوِّذَاتِ دُبُرَ كُلِّ صَلَاةٍ","id":"Telah menceritakan kepada Kami [Muhammad bin Salamah Al Muradi], telah menceritakan kepada Kami [Ibnu Wahb] dari [Al Laits bin Sa'd] bahwa [Hunain bin Abu Hakim] telah menceritakan kepadanya dari [Ali bin Rabah Al Lakhmi] dari ['Uqbah bin 'Amir], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam telah memerintahkan Kami untuk membaca surat-surat mu'awwidzât (surat yang berisi permintaan perlindungan kepada Allah, seperti Al Falaq, dan An Nâs) setiap selesai shalat. "},"1263":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ عَنْ عَبْدِ الْعَزِيزِ بْنِ عُمَرَ عَنْ هِلَالٍ عَنْ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ ابْنِ جَعْفَرٍ عَنْ أَسْمَاءَ بِنْتِ عُمَيْسٍ قَالَتْقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أُعَلِّمُكِ كَلِمَاتٍ تَقُولِينَهُنَّ عِنْدَ الْكَرْبِ أَوْ فِي الْكَرْبِ أَللَّهُ أَللَّهُ رَبِّي لَا أُشْرِكُ بِهِ شَيْئًاقَالَ أَبُو دَاوُد هَذَا هِلَالٌ مَوْلَى عُمَرَ بْنِ عَبْدِ الْعَزِيزِ وَابْنُ جَعْفَرٍ هُوَ عَبْدُ اللَّهِ بْنُ جَعْفَرٍ","id":"Telah menceritakan [Musaddad], telah menceritakan kepada Kami [Abdullah bin Daud] dari [Abdul Aziz bin Umar] dari [Hilal] dari [Umar bin Abdul Aziz] dari [Ibnu Ja'far] dari [Asma` bintu 'Umais], ia berkata; Rasulullah shallla Allahu 'alaihi wa sallam berkata kepadaku: \"Maukah aku ajarkan kamu kalimat-kalimat yang dapat kamu baca ketika dalam keadaan susah yaitu \"ALLAAHU, ALLAAHU RABBII, LAA USYRIKU BIHI SYAIAN\" (Allah, Allah adalah tuhanku, aku tidak menyekutukanNya dengan sesuatu apapun). Abu Daud berkata; Hilal yang ini adalah mantan budak Umar bin Abdul aziz sedangkan Ibnu Ja'far adalah Abdullah bin Ja'far. "},"1264":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ وَعَلِيِّ بْنِ زَيْدٍ وَسَعِيدٍ الْجُرَيْرِيِّ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ أَنَّ أَبَا مُوسَى الْأَشْعَرِيَّ قَالَكُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَلَمَّا دَنَوْا مِنْ الْمَدِينَةِ كَبَّرَ النَّاسُ وَرَفَعُوا أَصْوَاتَهُمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَيُّهَا النَّاسُ إِنَّكُمْ لَا تَدْعُونَ أَصَمَّ وَلَا غَائِبًا إِنَّ الَّذِي تَدْعُونَهُ بَيْنَكُمْ وَبَيْنَ أَعْنَاقِ رِكَابِكُمْ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا مُوسَى أَلَا أَدُلُّكَ عَلَى كَنْزٍ مِنْ كُنُوزِ الْجَنَّةِ فَقُلْتُ وَمَا هُوَ قَالَ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِحَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سُلَيْمَانُ التَّيْمِيُّ عَنْ أَبِي عُثْمَانَ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ أَنَّهُمْ كَانُوا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُمْ يَتَصَعَّدُونَ فِي ثَنِيَّةٍ فَجَعَلَ رَجُلٌ كُلَّمَا عَلَا الثَّنِيَّةَ نَادَى لَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ فَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكُمْ لَا تُنَادُونَ أَصَمَّ وَلَا غَائِبًا ثُمَّ قَالَ يَا عَبْدَ اللَّهِ بْنَ قَيْسٍ فَذَكَرَ مَعْنَاهُ حَدَّثَنَا أَبُو صَالِحٍ مَحْبُوبُ بْنُ مُوسَى أَخْبَرَنَا أَبُو إِسْحَقَ الْفَزَارِيُّ عَنْ عَاصِمٍ عَنْ أَبِي عُثْمَانَ عَنْ أَبِي مُوسَى بِهَذَا الْحَدِيثِ وَقَالَ فِيهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَيُّهَا النَّاسُ ارْبَعُوا عَلَى أَنْفُسِكُمْ","id":"Telah menceritakan kepada Kami [Musa bin Isma'il] telah menceritakan kepada Kami [Hammad] dari [Tsabit] dan [Ali bin Zaid] serta [Sa'id Al Jurairi] dari [Abu Utsman An Nahdi] bahwa [Abu Musa Asy'ari] berkata; aku pernah bersama Rasulullah shallAllahu wa'alaihi wa sallam dalam suatu perjalanan, kemudian tatkala mereka mendekati Madinah orang-orang bertakbir, dan mengeraskan suara mereka. Kemudian Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Wahai para manusia, sesungguhnya kalian tidak berdoa kepada Dzat Yang tuli, dan tidak pula Yang tidak hadir. Sesungguhnya Dzat kalian seru ada diantara kalian dan leher hewan kendaraan kalian.\" Kemudian Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Wahai Abu Musa, maukah aku tunjukkan kepada harta terpendam diantara harta-harta terpendam Surga?\" Maka aku katakan; apakah itu? Beliau berkata: \"LAA HAULA WA LAA QUWWATA ILLAA BILLAAH\" (Tidak ada daya dan kekuatan kecuali karena Allah). Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Yazid bin Zurai'] telah menceritakan kepada Kami [Sulaiman At Taimi] dari [Abu Utsman] dari [Abu Musa Asy'ari] bahwa mereka pernah bersama Nabi shallallahu 'alaihi wasallam sementara mereka menaiki Tsaniyah, kemudian seseorang setiap kali menaiki Tsaniyah berseru: LAA ILAAHA ILLALLAAHU, WALLAAHU AKBAR. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kalian tidak berseru kepada Dzat yang Tuli, dan tidak pula Yang tidak hadir.\" Kemudian beliau berkata: \"Wahai Abdullah bin Qais!.....\" kemudian Sulaiman menyebutkan hadits tersebut secara makna. Telah menceritakan kepada Kami [Abu Shalih Mahbub bin Musa], telah mengabarkan kepada Kami [Abu Ishaq Al Fazari] dari ['Ashim] dari [Abu Utsman] dari [Abu Musa] dengan hadits ini. Dan dalam hadits tersebut ia berkata; kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai para manusia, pelankan suara dalam hati kalian!\""},"1265":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا أَبُو الْحُسَيْنِ زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ شُرَيْحٍ الْإِسْكَنْدَرَانِيُّ حَدَّثَنِي أَبُو هَانِئٍ الْخَوْلَانِيُّ أَنَّهُ سَمِعَ أَبَا عَلِيٍّ الْجَنْبِيَّ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَالَ رَضِيتُ بِاللَّهِ رَبًّا وَبِالْإِسْلَامِ دِينًا وَبِمُحَمَّدٍ رَسُولًا وَجَبَتْ لَهُ الْجَنَّةُ","id":"Telah menceritakan kepada Kami [Muhammad bin Rafi'], telah menceritakan kepada Kami [Abu Al Husain Zaid bin Al Hubab], telah menceritakan kepada Kami [Abdurrahman bin Syuraih Al Iskandarani], telah menceritakan kepadaku [Abu Hani` Al Khaulani] bahwa ia mendengar [Abu Ali Al Hanbi] bahwa ia mendengar [Abu Sa'id Alkhudri] radliallahu 'anhu mengatakan bahwa Rasulullah shallla Allahu 'alaihi wa sallam bersabda: \"Barangsiapa yang mengatakan; RADHIITU BILLAAHI RABBAN WA BIL-ISLAAMI DIINAN WA BIMUHAMMADIN RASUULAN (Aku ridha Allah sebagai Tuhanku, Islam sebagai agamaku dan Muhammad sebagai rasul), maka wajib baginya untuk masuk Surga. "},"1266":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَيَحْيَى بْنُ الْفَضْلِ وَسُلَيْمَانُ بْنُ عَبْدِ الرَّحْمَنِ قَالُوا حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ حَدَّثَنَا يَعْقُوبُ بْنُ مُجَاهِدٍ أَبُو حَزْرَةَ عَنْ عُبَادَةَ بْنِ الْوَلِيدِ بْنِ عُبَادَةَ بْنِ الصَّامِتِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَدْعُوا عَلَى أَنْفُسِكُمْ وَلَا تَدْعُوا عَلَى أَوْلَادِكُمْ وَلَا تَدْعُوا عَلَى خَدَمِكُمْ وَلَا تَدْعُوا عَلَى أَمْوَالِكُمْ لَا تُوَافِقُوا مِنْ اللَّهِ تَبَارَكَ وَتَعَالَى سَاعَةَ نَيْلٍ فِيهَا عَطَاءٌ فَيَسْتَجِيبَ لَكُمْقَالَ أَبُو دَاوُد هَذَا الْحَدِيثُ مُتَّصِلٌ عُبَادَةُ بْنُ الْوَلِيدِ بْنِ عُبَادَةَ لَقِيَ جَابِراً","id":"Telah menceritakan kepada Kami [Hisyam bin 'Ammar] dan [Yahya bin Al Fadhl] serta [Sulaiman bin Abdurrahma], mereka berkata; telah menceritakan kepada Kami [Hatim bin Ismail], telah menceritakan kepada Kami [Ya'qub bin Mujahid Abu Hazrah] dari ['Ubadah bin Al Walid bin 'Ubadah bin Ash Shamit] dari [Jabir bin Abdullah], ia berkata; Rasulullah shallla Allahu 'alaihi wa sallam bersabda: \"Janganlah kalian mendo'akan kecelakaan atas diri kalian, janganlah kalian mendo'akan kecelakaan bagi anak-anak kalian, dan janganlah kalian mendo'akan kecelakaan atas pembantu kalian, dan janganlah kalian mendo'akan kecelakaan atas harta kalian, jangan sampai kalian berdoa tepat saat diperolehnya pemberian sehingga Allah mengabulkan do'a kalian. Abu Daud berkata; hadits ini adalah hadits yang muttashil (yaitu yang sanadnya bersambung kepada Rasulullah shallAllahu wa'alaihi wa sallam) sebab 'Ubadah bin Al Walid bin 'Ubadah bertemu dengan Jabir. "},"1267":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ عَنْ نُبَيْحٍ الْعَنَزِيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ امْرَأَةً قَالَتْ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلِّ عَلَيَّ وَعَلَى زَوْجِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى اللَّهُ عَلَيْكِ وَعَلَى زَوْجِكِ","id":"Telah menceritakan kepada Kami [Muhammad bin Isa] telah menceritakan kepada Kami [Abu 'Awanah] dari [Al Aswad bin Qais] dari [Nubaih Al 'Anazi] dari [Jabir bin Abdullah] bahwa terdapat seorang wanita yang berkata kepada Rasulullah shallla Allahu 'alaihi wa sallam; doakan untukku dan suamiku! Maka Nabi Shalla Allahu 'alaihi wa sallam berkata: \"Semoga Allah bershalawat untukmu dan suamimu\". "},"1268":{"ar":"حَدَّثَنَا رَجَاءُ بْنُ الْمُرَجَّى حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ أَخْبَرَنَا مُوسَى بْنُ ثَرْوَانَ حَدَّثَنِي طَلْحَةُ بْنُ عُبَيْدِ اللَّهِ بْنِ كَرِيزٍ حَدَّثَتْنِي أُمُّ الدَّرْدَاءِ قَالَتْ حَدَّثَنِي سَيِّدِي أَبُو الدَّرْدَاءِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا دَعَا الرَّجُلُ لِأَخِيهِ بِظَهْرِ الْغَيْبِ قَالَتْ الْمَلَائِكَةُ آمِينَ وَلَكَ بِمِثْلٍ","id":"Telah menceritakan kepada Kami [Raja` bin Al murajji] telah menceritakan kepada Kami [An Nadhr bin Syumail], telah mengabarkan kepada Kami [Musa bin Tsarwan] telah menceritakan kepadaku [Thalhah bin 'Ubaidullah bin Kariz], telah menceritakan kepadaku [Ummu Ad Darda`], ia berkata; telah menceritakan kepadaku suamiku [Abu Ad Darda`] bahwa ia mendengar Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Apabila seseorang mendoakan saudaranya secara sembunyi-sembunyi maka Malaikat akan berkata; aamiin, dan semoga engkau mendapatkan hal yang sama.\""},"1269":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ زِيَادٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَسْرَعَ الدُّعَاءِ إِجَابَةً دَعْوَةُ غَائِبٍ لِغَائِبٍ","id":"Telah menceritakan kepada Kami [Ahmad bin 'Amru bin As Sarh], telah menceritakan kepada Kami [Ibnu Wahb], telah menceritakan kepadaku [Abdurrahman bin Ziyad] dari [Abu Abdurrahman] dari [Abdullah bin 'Amr bin Al 'Ash] bahwa Rasulullah shallla Allahu 'alaihi wa sallam bersabda: \"Sesungguhnya do'a yang paling cepat dikabulkan adalah do'a orang yang ghaib (tidak hadir) untuk saudaranya yang tidak hadir.\""},"1270":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ الدَّسْتُوَائِيُّ عَنْ يَحْيَى عَنْ أَبِي جَعْفَرٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثُ دَعَوَاتٍ مُسْتَجَابَاتٌ لَا شَكَّ فِيهِنَّ دَعْوَةُ الْوَالِدِ وَدَعْوَةُ الْمُسَافِرِ وَدَعْوَةُ الْمَظْلُومِ","id":"Telah menceritakan kepada Kami [Muslim bin Ibrahim], telah menceritakan kepada Kami [Hisyam Ad Dastuwai] dari [Yahya] dari [Abu Ja'far] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tiga doa yang akan dikabulkan, dan tidak diragukan padanya, yaitu: doa orang tua, doa orang yang bersafar, dan doa orang yang dizhalimi.\""},"1271":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ أَبِي بُرْدَةَ بْنِ عَبْدِ اللَّهِ أَنَّ أَبَاهُ حَدَّثَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا خَافَ قَوْمًا قَالَ اللَّهُمَّ إِنَّا نَجْعَلُكَ فِي نُحُورِهِمْ وَنَعُوذُ بِكَ مِنْ شُرُورِهِمْ","id":"Telah menceritakan dari Kami [Muhammad bin Al Mutsanna], telah menceritakan kepada Kami [Mu'adz bin Hisyam], telah menceritakan kepadaku [ayahku] dari [Qatadah] dari [Abu Burdah bin Abdullah] bahwa [ayahnya] telah menceritakan kepadanya bahwa Nabi shallallahu 'alaihi wasallam apabila khawatir kepada suatu kaum beliau berdoa: \"Ya Allah, sesungguhnya Kami menjadikanMu di leher-leher mereka (yaitu menghadapi mereka) dan Kami berlindung kepadaMu dari kejahatan mereka.\""},"1272":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ وَعَبْدُ الرَّحْمَنِ بْنُ مُقَاتِلٍ خَالُ الْقَعْنَبِيِّ وَمُحَمَّدُ بْنُ عِيسَى الْمَعْنَى وَاحِدٌ قَالُوا حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الْمَوَالِ حَدَّثَنِي مُحَمَّدُ بْنُ الْمُنْكَدِرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُنَا الِاسْتِخَارَةَ كَمَا يُعَلِّمُنَا السُّورَةَ مِنْ الْقُرْآنِ يَقُولُ لَنَا إِذَا هَمَّ أَحَدُكُمْ بِالْأَمْرِ فَلْيَرْكَعْ رَكْعَتَيْنِ مِنْ غَيْرِ الْفَرِيضَةِ وَلْيَقُلْ اللَّهُمَّ إِنِّي أَسْتَخِيرُكَ بِعِلْمِكَ وَأَسْتَقْدِرُكَ بِقُدْرَتِكَ وَأَسْأَلُكَ مِنْ فَضْلِكَ الْعَظِيمِ فَإِنَّكَ تَقْدِرُ وَلَا أَقْدِرُ وَتَعْلَمُ وَلَا أَعْلَمُ وَأَنْتَ عَلَّامُ الْغُيُوبِ اللَّهُمَّ إِنْ كُنْتَ تَعْلَمُ أَنَّ هَذَا الْأَمْرَ يُسَمِّيهِ بِعَيْنِهِ الَّذِي يُرِيدُ خَيْرٌ لِي فِي دِينِي وَمَعَاشِي وَمَعَادِي وَعَاقِبَةِ أَمْرِي فَاقْدُرْهُ لِي وَيَسِّرْهُ لِي وَبَارِكْ لِي فِيهِ اللَّهُمَّ وَإِنْ كُنْتَ تَعْلَمُهُ شَرًّا لِي مِثْلَ الْأَوَّلِ فَاصْرِفْنِي عَنْهُ وَاصْرِفْهُ عَنِّي وَاقْدِرْ لِي الْخَيْرَ حَيْثُ كَانَ ثُمَّ رَضِّنِي بِهِ أَوْ قَالَ فِي عَاجِلِ أَمْرِي وَآجِلِهِقَالَ ابْنُ مَسْلَمَةَ وَابْنُ عِيسَى عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابَرٍ","id":"Telah menceritakan kepada Kami [Abdullah bin Maslamah Al Qa'nabi] dan [Abdurrahman bin Muqatil] paman Al Qa'nabi, serta [Muhammad bin Isa] dengan makna yang sama, mereka berkata; telah menceritakan kepada Kami [Abdurrahman bin Abu Al Mawal], telah menceritakan kepadaku [Muhammad bin Al Munkadir] bahwa ia mendengar [Jabir bin Abdullah], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam mengajari Kami istikharah, sebagaimana mengajari Kami sebuah surat dari Al Qur'an. Beliau berkata kepada Kami: \"Apabila salah seorang diantara kalian merasakan kesedihan maka hendaknya ia melakukan ruku' dua kali yang tidak wajib, dan mengucapkan; ALLAAHUMMA INNII ASTAKHIIRUKA BI'ILMIKA WA ASTAQDIRUKA BIQADRIKA WA AS-ALUKA MIN FADHLIKAL 'AZHIIM, FAINNAKA TAQDIRU WA LAA AQDIRU WA TA'LAMU WA LAA A'LAMU WA ANTA 'ALLAAMUL GHUYUUB, ALLAAHUMMA IN KUNTA TA'LAMU ANNAD HADZAL AMRA ……KHAIRUN LII FII DIINII WA MA'AASYII, WA MA'AADII, WA 'AAQIBATI AMRII FAQDURHU LII WA YASSIRHU LII WA BAARIK LII FIIHI. ALLAAHUMMA IN KUNTA TA'LAMUHU SYARRAN LII MITSLAL AWWALI FASHRIFNII 'ANHU WASHRIFHU 'ANNII, WAQDUR LII Al KHAIRA HAITSU KAANA TSUMMA RADHDHINII BIHI.\" (Ya Allah, aku memohon petunjukMu dengan ilmuMu, dan memohon kemampuan kepadaMu dengan kemampuanMu, serta memohon sebagian karuniaMu yang besar. Sesungguhnya Engkau mampu dan aku tidak mampu, Engkau mengetahui dan aku tidak mengetahui, dan Engkau adalah Dzat Yang Maha mengetahui. Ya Allah seandainya Engkau mengetahui bahwa bahwa perkara ini (kemudian ia menyebutkan perkara yang ia inginkan) adalah lebih baik bagiku, dalam agama, kehidupan, serta tempat kembaliku dan akibat urusanku maka tetapkanlah bagiku, dan mudahkanlah perkara tersebut untukku, serta berilah aku berkah padanya. Ya Allah, apabila Engkau mengetahui perkara tersebut buruk bagiku seperti yang pertama maka palingkanlah aku darinya dan palingkan perkara tersebut dariku, serta tetapkan bagiku segala kebaikan dimanapun berada, kemudian jadikanlah aku ridha kepadanya.) Atau berkata: \"FII 'AAJILI AMRII WA AAJILIHI.\" (dalam perkara yang segera akan datang dan akan datang.\" Hal tersebut dikatakan oleh [Ibnu Maslamah] dan [Ibnu Isa] dari [Muhammad bin Al Munkadir] dari [Jabir]."},"1273":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَعَوَّذُ مِنْ خَمْسٍ مِنْ الْجُبْنِ وَالْبُخْلِ وَسُوءِ الْعُمُرِ وَفِتْنَةِ الصَّدْرِ وَعَذَابِ الْقَبْرِ","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah] telah menceritakan kepada Kami [Waki'], telah menceritakan kepada Kami [Israil] dari [Abu Ishaq] dari ['Amr bin Maimun] dari [Umar bin Al Khathab], ia berkata; Nabi Shalla Allahu 'alaihi wa sallam pernah berlindung dari lima perkara yaitu dari sifat pengecut, bakhil, umur yang jelek, fitnah hati dan adzab kubur. "},"1274":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ أَبِي الزُّبَيْرِ الْمَكِّيِّ عَنْ طَاوُسٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُعَلِّمُهُمْ هَذَا الدُّعَاءَ كَمَا يُعَلِّمُهُمْ السُّورَةَ مِنْ الْقُرْآنِ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ عَذَابِ جَهَنَّمَ وَأَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ","id":"Telah menceritakan kepada Kami [Al Qa'nabi] dari [Malik] dari [Abu Az Zubair Al Makki] dari [Thawus] dari [Abdullah bin Abbas] bahwa Rasulullah shallAllahu wa'alaihi wa sallam pernah mengajari mereka doa ini sebagaimana mengajarkan kepada mereka satu surat dari Al Qur'an. Beliau mengucapkan: \"ALLAAHUMMA INNII A'UUDZU BIKA MIN 'ADZAABI JAHANNAMA WA A'UUDZU BIKA MIN 'ADZAABIL QABRI WA A'UUDZU BIKA MIN FITNATIL MASIIHID DAJJAAL, WA A'UUDZU BIKA MIN FITNATIL MAHYAA WAL MAMAAT\" (Ya Allah, aku berlindung kepadaMu dari adzab Jahannam, dan berlindung kepadaMu dari adzab kubur, dan berlindung kepadaMu dari fitnah Al Masih Ad Dajjal, serta berlindung kepadaMu dari fitnah kehidupan serta fitnah kematian.) "},"1275":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ أَخْبَرَنَا عِيسَى حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو بِهَؤُلَاءِ الْكَلِمَاتِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ فِتْنَةِ النَّارِ وَعَذَابِ النَّارِ وَمِنْ شَرِّ الْغِنَى وَالْفَقْرِ","id":"Telah menceritakan kepada Kami [Ibrahim bin Musa Ar Razi], telah memberitakan kepadaku [Isa] telah menceritakan kepada Kami [Hisyam] dari [ayahnya] dari [Aisyah] radliallahu 'anha bahwa Nabi shallallahu 'alaihi wasallam pernah berdoa dengan kalimat-kalimat ini, yaitu: \"ALLAAHUMMA INNII A'UUDZU BIKA MIN FITNATIN NAARI WA 'ADZAABIN NAARI, WA MIN SYARRIL GHINAA WAL FAQRI\" (Ya Allah, aku berlindung kepadaMu dari fitnah Neraka dan adzab Neraka, dari keburukan kekayaan dan kefakiran.\""},"1276":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا إِسْحَقُ بْنُ عَبْدِ اللَّهِ عَنْ سَعِيدِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْفَقْرِ وَالْقِلَّةِ وَالذِّلَّةِ وَأَعُوذُ بِكَ مِنْ أَنْ أَظْلِمَ أَوْ أُظْلَمَ","id":"Telah menceritakan kepada Kami [Musa bin Ismail], telah menceritakan kepada Kami [Hammad], telah mengabarkan kepada Kami [Ishaq bin Abdullah] dari [Sa'id? bin Yasar] dari [Abu Hurairah] rhadhiyAllahu 'anhu bahwa Nabi shallallahu 'alaihi wasallam pernah mengucapkan: \"ALLAAHUMMA INNII A'UUDZU BIKA MINAL FAQRI WALQILLATI WADZ DZILLATI, WA A'UUDZU BIKA MIN AN AZHLIMA AU UZHLAMA\" (Ya Allah aku berlindung kepada-Mu dari kafakiran, kekurangan dan kehinaan dan aku berlindung kepada-Mu dari aku berbuat dzalim atau didzalimi). "},"1277":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ حَدَّثَنَا بَقِيَّةُ حَدَّثَنَا ضُبَارَةُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي السُّلَيْكِ عَنْ دُوَيْدِ بْنِ نَافِعٍ حَدَّثَنَا أَبُو صَالِحٍ السَّمَّانُ قَالَ قَالَ أَبُو هُرَيْرَةَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الشِّقَاقِ وَالنِّفَاقِ وَسُوءِ الْأَخْلَاقِ","id":"Telah menceritakan kepada Kami ['Amr bin Utsman], telah menceritakan kepada Kami [Baqiyyah], telah menceritakan kepada Kami [Dhubarah bin Abdullah bin Abu As Sulaik] dari [Duwaid bin Nafi'], telah menceritakan kepada Kami [Abu Shalih As Samman], ia berkata; [Abu Hurairah] radliallahu 'anhu berkata; sesungguhnya Rasulullah shallAllahu wa'alaihi wa sallam pernah berdo'a: \"ALLAAHUMMA INNII A'UUDZU BIKA MINASY SYIQAAQI WAN NIFAAQI WA SUUIL AKHLAAQ\" (Ya Allah aku berlindung kepadaMu dari perpecahan dan kemunafikan serta akhlak yang jelek). "},"1278":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ عَنْ ابْنِ إِدْرِيسَ عَنْ ابْنِ عَجْلَانَ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْجُوعِ فَإِنَّهُ بِئْسَ الضَّجِيعُ وَأَعُوذُ بِكَ مِنْ الْخِيَانَةِ فَإِنَّهَا بِئْسَتِ الْبِطَانَةُ","id":"Telah menceritakan kepada Kami [Muhammad bin Al 'Ala`] dari [Ibnu Idris] dari [Ibnu 'Ajlan] dari [Al Maqburi] dari [Abu Hurairah] radliallahu 'anhu, ia berkata; Rasulullah shallallahu 'alaihi wasallam berdo'a: \"ALLAAHUMMA INNII A'UUDZU BIKA MINAL JUU'I, FAINNAHU BI`SADH DHAJII'U, WA A'UUDZU BIKA MINAL KHIYAANATI FAINNAHAA BI`SATIL BITHAANAH\" (Ya Allah sesungguhnya aku berlindung kepadaMu dari kelaparan, karena itu adalah seburuk-buruk teman tidur. Dan aku berlindung kepadaMu dari khianat karena itu adalah seburuk-buruk teman). "},"1279":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُتَوَكِّلِ حَدَّثَنَا الْمُعْتَمِرُ قَالَ قَالَ أَبُو الْمُعْتَمِرِ أُرَى أَنَّ أَنَسَ بْنَ مَالِكٍ حَدَّثَنَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ صَلَاةٍ لَا تَنْفَعُ وَذَكَرَ دُعَاءً آخَرَ","id":"Telah menceritakan kepada Kami [Muhammad bin Al Mutawakkil], telah menceritakan kepada kami [Al Mu'tamir] ia berkata; [Abul Al Mu'tamir] berkata; aku diperlihatkan bahwa [Anas bin Malik] radliallahu 'anhu telah berkata; bahwa Rasulullah shallallahu 'alaihi wasallam berkata; \"ALLAAHUMMA INNII A'UUDZU BIKA MIN SHALAATIN LAA TANFA'\" (Ya Allah, aku berlindung kepadaMu dari shalat yang tidak bermanfaat) dan dia menyebutkan do'a yang lain. "},"1280":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ فَرْوَةَ بْنِ نَوْفَلٍ الْأَشْجَعِيِّ قَالَسَأَلْتُ عَائِشَةَ أُمَّ الْمُؤْمِنِينَ عَمَّا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو بِهِ قَالَتْ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ شَرِّ مَا عَمِلْتُ وَمِنْ شَرِّ مَا لَمْ أَعْمَلْ","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Jarir] dari [Manshur] dari [Hilal bin Yasaf] dari [Farwah bin Naufal Al Asyja'i], ia berkata; aku pernah bertanya kepada [Aisyah Ummul mukminin] mengenai doa yang diucapkan Rasulullah shallAllahu wa'alaihi wa sallam. Ia berkata; beliau pernah mengucapkan: \"ALLAAHUMMA INNII A'UUDZU BIKA MIN SYARRI MAA 'ALIMTU WA MIN SYARRI MAA LAM A'LAM\" (Ya Allah, aku berlindung kepadaMu dari keburukan apa yang aku ketahui dan dari keburukan apa yang tidak aku ketahui). "},"1281":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ حَنْبَلٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ ح و حَدَّثَنَا أَحْمَدُ حَدَّثَنَا وَكِيعٌ الْمَعْنَى عَنْ سَعْدِ بْنِ أَوْسٍ عَنْ بِلَالٍ الْعَبْسِيِّ عَنْ شُتَيْرِ بْنِ شَكَلٍ عَنْ أَبِيهِ فِي حَدِيثِ أَبِي أَحْمَدَ شَكَلِ بْنِ حُمَيْدٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ عَلِّمْنِي دُعَاءً قَالَ قُلْ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ شَرِّ سَمْعِي وَمِنْ شَرِّ بَصَرِي وَمِنْ شَرِّ لِسَانِي وَمِنْ شَرِّ قَلْبِي وَمِنْ شَرِّ مَنِيِّي","id":"Telah menceritakan kepada Kami [Ahmad bin Muhammad bin Hanbal], telah menceritakan kepada Kami [Muhammad bin Abdullah bin Az Zubair], dan diriwayatkan dari jalur yang lain: Telah menceritakan kepada Kami [Ahmad], telah menceritakan kepada Kami [Waki'] secara makna dar [Sa'd bin Aus] dari [Bilal Al 'Abasi] dari [Syutair bin Syakal] dari [ayahnya] -dalam hadits Abu Ahmad Syakal bin Humaid ia berkata; aku katakan; wahai Rasulullah, ajarkanlah keadaku sebuah doa! Beliau berkata: \"Katakanlah; ALLAAHUMMA INNII A'UUDZU BIKA MIN SYARRI SAM'II WA MIN SYARRI BASHARII WA MIN SYARRI LISAANII, WA MIN SYARRI QALBII, WA MIN SYARRI MANIYYII\" (Ya Allah, aku berlindung kepadaMu dari kejahatan pendengaranku, dari kejahatan pandanganku, dari kejahatan lisanku, dari kejahatan hatiku dan dari kejahatan air maniku). "},"1282":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا قَتَادَةُ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْبَرَصِ وَالْجُنُونِ وَالْجُذَامِ وَمِنْ سَيِّئْ الْأَسْقَامِ","id":"Telah menceritakan kepada Kami [Musa bin Ismail], telah menceritakan kepada Kami [Hammad], telah mengabarkan kepada Kami [Qatadah] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam mengucapkan: \"ALLAAHUMMA INNII A'UUDZU BIKA MINAL BARASHI WAL JUNUUNI WAL JUDZAAMI WA MIN SAYYI-IL ASQAAM\" (Ya Allah, aku berlindung kepadaMu dari kusta, gila, lepra, dan dari penyakit yang buruk). "},"1283":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ الثَّقَفِيُّ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أَبِي هُرَيْرَةَ قَالَلَمَّا تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْتُخْلِفَ أَبُو بَكْرٍ بَعْدَهُ وَكَفَرَ مَنْ كَفَرَ مِنْ الْعَرَبِ قَالَ عُمَرُ بْنُ الْخَطَّابِ لِأَبِي بَكْرٍ كَيْفَ تُقَاتِلُ النَّاسَ وَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ فَمَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ عَصَمَ مِنِّي مَالَهُ وَنَفْسَهُ إِلَّا بِحَقِّهِ وَحِسَابُهُ عَلَى اللَّهِ عَزَّ وَجَلَّ فَقَالَ أَبُو بَكْرٍ وَاللَّهِ لَأُقَاتِلَنَّ مَنْ فَرَّقَ بَيْنَ الصَّلَاةِ وَالزَّكَاةِ فَإِنَّ الزَّكَاةَ حَقُّ الْمَالِ وَاللَّهِ لَوْ مَنَعُونِي عِقَالًا كَانُوا يُؤَدُّونَهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَاتَلْتُهُمْ عَلَى مَنْعِهِ فَقَالَ عُمَرُ بْنُ الْخَطَّابِ فَوَاللَّهِ مَا هُوَ إِلَّا أَنْ رَأَيْتُ اللَّهَ عَزَّ وَجَلَّ قَدْ شَرَحَ صَدْرَ أَبِي بَكْرٍ لِلْقِتَالِ قَالَ فَعَرَفْتُ أَنَّهُ الْحَقُّقَالَ أَبُو دَاوُد وَرَوَاهُ رَبَاحُ بْنُ زَيْدٍ وَرَوَاهُ عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ بِإِسْنَادِهِ وَقَالَ بَعْضُهُمْ عِقَالًا وَرَوَاهُ ابْنُ وَهْبٍ عَنْ يُونُسَ قَالَ عَنَاقًا قَالَ أَبُو دَاوُد قَالَ شُعَيْبُ بْنُ أَبِي حَمْزَةَ وَمَعْمَرٌ وَالزُّبَيْدِيُّ عَنْ الزُّهْرِيِّ فِي هَذَا الْحَدِيثِ لَوْ مَنَعُونِي عَنَاقًا وَرَوَى عَنْبَسَةُ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ فِي هَذَا الْحَدِيثِ قَالَ عَنَاقًا حَدَّثَنَا ابْنُ السَّرْحِ وَسُلَيْمَانُ بْنُ دَاوُدَ قَالَا أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ الزُّهْرِيِّ هَذَا الْحَدِيثَ قَال�� قَالَ أَبُو بَكْرٍ إِنَّ حَقَّهُ أَدَاءُ الزَّكَاةِ وَقَالَ عِقَالًا","id":"Telah menceritakan kepada Kami [Qutaibah bin Sa'id Ats Tsaqafi], telah menceritakan kepada Kami [Al Laits] dari ['Uqail] dari [Az Zuhri], telah mengabarkan kepadaku ['Ubaidullah bin Abdullah bin 'Utbah] dari [Abu Hurairah], ia berkata; tatkala Rasulullah shallAllahu wa'alaihi wa sallam meninggal dan Abu Bakr diangkat sebagai khalifah setelah beliau dan telah kafir sebagian orang Arab, [Umar bin Al Khathab] berkata kepada Abu Bakr; bagaimana engkau memerangi orang-orang tersebut padahal Rasulullah shallAllahu wa'alaihi wa sallam telah bersabda: \"Aku diperintahkan untuk memerangi manusia hingga mereka mengucapkan; LAA ILAAHA ILLALLAAH. Barang siapa yang mengucapkan; LAA ILAAHA ILLALLAAH maka ia telah melindungi dariku harga dan jiwanya kecuali dengan haknya, sedangkan perhitungannya kembali kepada Allah 'azza wajalla.\" Maka [Abu Bakr] berkata; sungguh aku akan memerangi orang yang memisahkan antara shalat dan zakat, sesungguhnya zakat adalah hak harta. Demi Allah seandainya mereka menahanku satu 'iqal yang dahulunya mereka tunaikan kepada Rasulullah shallAllahu wa'alaihi wa sallam niscaya aku akan memerangi mereka karena penolakannya. Kemudian [Umar bin Al Khathab] berkata; Demi Allah sungguh aku melihat Allah 'azza wajalla telah melapangkan dada Abu Bakr untuk memerangi orang-orang tersebut. Umar berkata; maka aku mengetahui bahwa ia adalah yang benar. Abu Daud berkata; dan hadits tersebut diriwayatkan oleh [Rabah bin Zaid], dan diriwayatkan oleh [Abdurrazzaq] dari [Ma'mar] dari [Az Zuhri] dengan sanadnya. Sebagian ulama mengatakan; 'iqal, sedangkan [Ibnu Wahb] dari [Yunus] meriwayatkannya, ia mengatakan; anak kambing. Abu Daud berkata; [Syu'aib bin Abu Hamzah] serta [Ma'mar] dan [Az Zubaidi] dari [Az Zuhri] berkata; seandainya mereka menolakku satu ekor anak kambing, sedangkan ['Anbasah] telah meriwayatkan dari [Yunus] dari [Az Zuhri] dalam hadits ini, ia berkata; anak kambing. Telah menceritakan kepada Kami [Ibnu As Sarh] dan [Sulaiman bin Daud] mereka berkata; telah mengabarkan kepada Kami [Ibnu Wahb], telah mengabarkan kepadaku [Yunus] dari [Az Zuhri] hadits ini, ia berkata; Abu Bakr berkata; sesungguhnya haknya adalah menunaikan zakat. Dan ia menyebutkan; 'iqal."},"1284":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ قَالَ قَرَأْتُ عَلَى مَالِكِ بْنِ أَنَسٍ عَنْ عَمْرِو بْنِ يَحْيَى الْمَازِنِيِّ عَنْ أَبِيهِ قَالَ سَمِعْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ فِيمَا دُونَ خَمْسِ ذَوْدٍ صَدَقَةٌ وَلَيْسَ فِيمَا دُونَ خَمْسِ أَوَاقٍ صَدَقَةٌ وَلَيْسَ فِيمَا دُونَ خَمْسَةِ أَوْسُقٍ صَدَقَةٌ","id":"Telah menceritakan kepada Kami [Abdullah bin Maslamah], ia berkata; saya membacakan riwayat kepada [Malik bin Anas] dari ['Amr bin Yahya Al Mazini] dari [ayahnya], ia berkata; saya mendengar [Abu Sa'id Al Khudri] berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Tidak ada zakat pada unta yang kurang dari lima dzaud (dzaud adalah antara tiga hingga sepuluh), tidak ada zakat pada perak yang kurang dari lima uqiyah, dan tidak ada zakat pada buah-buahan yang kurang dari lima wasaq.\""},"1285":{"ar":"حَدَّثَنَا أَيُّوبُ بْنُ مُحَمَّدٍ الرَّقِّيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا إِدْرِيسُ بْنُ يَزِيدَ الْأَوْدِيُّ عَنْ عَمْرِو بْنِ مُرَّةَ الْجَمَلِيِّ عَنْ أَبِي الْبَخْتَرِيِّ الطَّائِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّيَرْفَعُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ فِيمَا دُونَ خَمْسَةِ أَوْسُقٍ زَكَاةٌ وَالْوَسْقُ سِتُّونَ مَخْتُومًاقَالَ أَبُو دَاوُد أَبُو الْبَخْتَرِيُّ لَمْ يَسْمَعْ مِنْ أَبِي سَعِيدٍ حَدَّثَنَا مُحَمَّدُ بْنُ قُدَامَةَ بْنِ أَعْيَنَ حَدَّثَنَا جَرِيرٌ عَنْ الْمُغِيرَةِ عَنْ إِبْرَاهِيمَ قَالَ الْوَسْقُ سِتُّونَ صَاعًا مَخْتُومًا بِالْحَجَّاجِيِّ","id":"Telah menceritakan kepada Kami [Ayyub bin Muhammad Ar Raqi], telah menceritakan kepada Kami [Muhammad bin 'Ubaid], telah menceritakan kepada Kami [Idris bin Yazid Al Audi] dari ['Amr bin Murrah Al Hamali] dari [Abu Al Bakhtari Ath Thai] dari [Abu Sa'id Al Khudri] dan ia mengangkat hadits tersebut hingga sampai kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada zakat pada buah-buahan yang kurang dari lima wasaq, dan satu wasaq adalah enam puluh sha'.\" Abu Daud berkata; Abu Al Bakhtari tidak mendengar dari Abu Sa'id. Telah menceritakan kepada Kami Muhammad bin Qudamah bin A'yan, telah menceritakan kepada Kami Jarir dari Al Mughirah dari Ibrahim, ia berkata; satu wasaq adalah enam puluh sha' yang distempel dengan tanda Al Hajjaj."},"1286":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّ حَدَّثَنَا صُرَدُ بْنُ أَبِي الْمَنَازِلِ قَالَ سَمِعْتُ حَبِيبًا الْمَالِكِيَّ قَالَقَالَ رَجُلٌ لِعِمْرَانَ بْنِ حُصَيْنٍ يَا أَبَا نُجَيْدٍ إِنَّكُمْ لَتُحَدِّثُونَنَا بِأَحَادِيثَ مَا نَجِدُ لَهَا أَصْلًا فِي الْقُرْآنِ فَغَضِبَ عِمْرَانُ وَقَالَ لِلرَّجُلِ أَوَجَدْتُمْ فِي كُلِّ أَرْبَعِينَ دِرْهَمًا دِرْهَمٌ وَمِنْ كُلِّ كَذَا وَكَذَا شَاةً شَاةٌ وَمِنْ كُلِّ كَذَا وَكَذَا بَعِيرًا كَذَا وَكَذَا أَوَجَدْتُمْ هَذَا فِي الْقُرْآنِ قَالَ لَا قَالَ فَعَنْ مَنْ أَخَذْتُمْ هَذَا أَخَذْتُمُوهُ عَنَّا وَأَخَذْنَاهُ عَنْ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَكَرَ أَشْيَاءَ نَحْوَ هَذَا","id":"Telah menceritakan kepada Kami [Muhamad bin Basysyar] telah menceritakan kepadaku [Muhammad bin Abdullah Al Anshari], telah menceritakan kepada Kami [Shurad bin Abu Al Manazil], ia berkata; saya mendengar [Habib Al Maliki] berkata; seorang laki-laki berkata kepada 'Imran bin Hushain; wahai Abu Nujaid, sesungguhnya kalian telah menceritakan kepada Kami dengan hadits-hadits yang tidak Kami dapatkan dasarnya dalam Al Qur'an! Maka [Imran] berkata kepada orang tersebut; apakah kalian dapatkan dalam setiap empat puluh dirham terdapat zakat satu dirham, dan dalam setiap sekian kambing zakat satu kambing, dan dalam setiap sekian unta zakat sekian dan sekian unta, apakah kalian mendapatkannya dalam Al Qur'an? Orang tersebut menjawab: tidak! Imran berkata lagi: jadi, dari siapa kalian mengambilnya? Kalian mengambilnya dari Kami dan Kami mengambilnya dari Nabi Shalla Allahu 'alaihi wa sallam. Dan dia menyebutkan perkara-perkara lain seperti ini. "},"1287":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ دَاوُدَ بْنِ سُفْيَانَ حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا سُلَيْمَانُ بْنُ مُوسَى أَبُو دَاوُدَ حَدَّثَنَا جَعْفَرُ بْنُ سَعْدِ بْنِ سَمُرَةَ بْنِ جُنْدُبٍ حَدَّثَنِي خُبَيْبُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ سُلَيْمَانَ عَنْ سَمُرَةَ بْنِ جُنْدُبٍ قَالَأَمَّا بَعْدُ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْمُرُنَا أَنْ نُخْرِجَ الصَّدَقَةَ مِنْ الَّذِي نُعِدُّ لِلْبَيْعِ","id":"Telah menceritakan kepada Kami [Muhammad bin Daud bin Sufyan], telah menceritakan kepada Kami [Yahya bin Hassan], telah menceritakan kepada Kami [Sulaiman bin Musa Abu Daud], telah menceritakan kepada Kami [Ja'far bin Sa'd bin Samurah bin Jundab bin Sulaiman] telah menceritakan kepadaku [Hubaib bin Sulaiman] dari [ayahnya yaitu Sulaiman] dari [Samurah bin Jundab], ia berkata; adapun selanjutnya, sesungguhnya Rasulullah shallallahu 'alaihi wasallam memerintahkan Kami untuk mengeluarkan zakat dari sesuatu yang Kami persiapkan untuk dijual. "},"1288":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ وَحُمَيْدُ بْنُ مَسْعَدَةَ الْمَعْنَى أَنَّ خَالِدَ بْنَ الْحَارِثِ حَدَّثَهُمْ حَدَّثَنَا حُسَيْنٌ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ امْرَأَةً أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهَا ابْنَةٌ لَهَا وَفِي يَدِ ابْنَتِهَا مَسَكَتَانِ غَلِيظَتَانِ مِنْ ذَهَبٍ فَقَالَ لَهَا أَتُعْطِينَ زَكَاةَ هَذَا قَالَتْ لَا قَالَ أَيَسُرُّكِ أَنْ يُسَوِّرَكِ اللَّهُ بِهِمَا يَوْمَ الْقِيَامَةِ سِوَارَيْنِ مِنْ نَارٍ قَالَ فَخَلَعَتْهُمَا فَأَلْقَتْهُمَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَتْ هُمَا لِلَّهِ عَزَّ وَجَلَّ وَلِرَسُولِهِ","id":"Telah menceritakan kepada Kami [Abu Kamil] dan [Humaid bin Mas'adah] secara makna bahwa [Khalid bin Al Harits] telah menceritakan kepada mereka; telah menceritakan kepada Kami [Husain] dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya] bahwa seorang wanita datang kepada Rasulullah shallAllahu wa'alaihi wa sallam membawa anak wanitanya, dan di tangan anak wanita tersebut terdapat dua gelang tebal yang terbuat dari emas, kemudian beliau berkata kepadanya: \"Apakah engkau memberikan zakat emas ini?\" Wanita tersebut berkata; tidak. Beliau bersabda: \"Apakah engkau senang karena kedua gelang tersebut Allah memberimu gelang dari api pada Hari Kiamat?\" Khalid berkata; kemudian wanita tersebut melepas kedua gelang tersebut dan melemparkannya kepada Nabi shallallahu 'alaihi wasallam dan berkata; kedua gelang itu untuk Allah 'azza wajalla dan rasulNya. "},"1289":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا عَتَّابٌ يَعْنِي ابْنَ بَشِيرٍ عَنْ ثَابِتِ بْنِ عَجْلَانَ عَنْ عَطَاءٍ عَنْ أُمِّ سَلَمَةَ قَالَتْكُنْتُ أَلْبَسُ أَوْضَاحًا مِنْ ذَهَبٍ فَقُلْتُ يَا رَسُولَ اللَّهِ أَكَنْزٌ هُوَ فَقَالَ مَا بَلَغَ أَنْ تُؤَدَّى زَكَاتُهُ فَزُكِّيَ فَلَيْسَ بِكَنْزٍ","id":"Telah menceritakan kepada Kami [Muhammad bin Isa], telah menceritakan kepada Kami ['Attab yaitu Ibnu Basyir] dari [Tsabit bin 'Ajlan] dari ['Atha`] dari [Ummu Salamah], ia berkata; aku mengenakan perhiasan dari emas, lalu aku bertanya; wahai Rasulullah, apakah ini termasuk barang timbunan? Beliau menjawab: \"Apa yang sudah mencapai nishabnya untuk dizakati kemudian telah dikeluarkan zakatnya maka bukanlah termasuk barang timbunan.\""},"1290":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِدْرِيسَ الرَّازِيُّ حَدَّثَنَا عَمْرُو بْنُ الرَّبِيعِ بْنِ طَارِقٍ حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ أَنَّ مُحَمَّدَ بْنَ عَمْرِو بْنِ عَطَاءٍ أَخْبَرَهُ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادِ بْنِ الْهَادِ أَنَّهُ قَالَدَخَلْنَا عَلَى عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ دَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَأَى فِي يَدَيَّ فَتَخَاتٍ مِنْ وَرِقٍ فَقَالَ مَا هَذَا يَا عَائِشَةُ فَقُلْتُ صَنَعْتُهُنَّ أَتَزَيَّنُ لَكَ يَا رَسُولَ اللَّهِ قَالَ أَتُؤَدِّينَ زَكَاتَهُنَّ قُلْتُ لَا أَوْ مَا شَاءَ اللَّهُ قَالَ هُوَ حَسْبُكِ مِنْ النَّارِحَدَّثَنَا صَفْوَانُ بْنُ صَالِحٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا سُفْيَانُ عَنْ عُمَرَ بْنِ يَعْلَى فَذَكَرَ الْحَدِيثَ نَحْوَ حَدِيثِ الْخَاتَمِ قِيلَ لِسُفْيَانَ كَيْفَ تُزَكِّيهِ قَالَ تَضُمُّهُ إِلَى غَيْرِهِ","id":"Telah menceritakan kepada Kami [Muhammad bin Idris Ar Razi], telah menceritakan kepada Kami ['Amr bin Ar Rabi' bin Thariq], telah menceritakan kepada Kami [Yahya bin Ayyub] dari ['Ubaidullah bin Abu Ja'far] bahwa [Muhammad bin 'Amr bin 'Atha`] telah mengabarkan kepadanya dari [Abdullah bin Syaddad bin Al Had] bahwa ia berkata; Kami menemui [Aisyah] istri Nabi shalla Allahu 'alaihi wa sallam, lalu ia berkata; Rasulullah shallallahu 'alaihi wasallam menemuiku dan melihat ditanganku ada cincin dari perak, lalu beliau berkata: \"Apakah ini wahai Aisyah?\" Aku menjawab; aku menggunakannya untuk berhias di hadapanmu. Beliau berkata: \"Apakah kamu mengeluarkan zakatnya?\" Aku menjawab: tidak! -atau- maasyaa Allah! Beliau berkata: Itu adalah bagianmu dari Neraka!\" Telah menceritakan kepada Kami [Shafwan bin Shalih], telah menceritakan kepada Kami [Al Walid bin Muslim], telah menceritakan kepada Kami [Sufyan] dari [Umar bin Ya'la], kemudian ia menyebutkan hadits seperti hadits mengenai cincin. Sufyan ditanya; bagaimana engkau menzakatinya? Dia menjawab; engkau gabungkan dengan yang lain. "},"1291":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ قَالَأَخَذْتُ مِنْ ثُمَامَةَ بْنِ عَبْدِ اللَّهِ بْنِ أَنَسٍ كِتَابًا زَعَمَ أَنَّ أَبَا بَكْرٍ كَتَبَهُ لِأَنَسٍ وَعَلَيْهِ خَاتِمُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ بَعَثَهُ مُصَدِّقًا وَكَتَبَهُ لَهُ فَإِذَا فِيهِ هَذِهِ فَرِيضَةُ الصَّدَقَةِ الَّتِي فَرَضَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمُسْلِمِينَ الَّتِي أَمَرَ اللَّهُ عَزَّ وَجَلَّ بِهَا نَبِيَّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَنْ سُئِلَهَا مِنْ الْمُسْلِمِينَ عَلَى وَجْهِهَا فَلْيُعْطِهَا وَمَنْ سُئِلَ فَوْقَهَا فَلَا يُعْطِهِ فِيمَا دُونَ خَمْسٍ وَعِشْرِينَ مِنْ الْإِبِلِ الْغَنَمُ فِي كُلِّ خَمْسِ ذَوْدٍ شَاةٌ فَإِذَا بَلَغَتْ خَمْسًا وَعِشْرِينَ فَفِيهَا بِنْتُ مَخَاضٍ إِلَى أَنْ تَبْلُغَ خَمْسًا وَثَلَاثِينَ فَإِنْ لَمْ يَكُنْ فِيهَا بِنْتُ مَخَاضٍ فَابْنُ لَبُونٍ ذَكَرٌ فَإِذَا بَلَغَتْ سِتًّا وَثَلَاثِينَ فَفِيهَا بِنْتُ لَبُونٍ إِلَى خَمْسٍ وَأَرْبَعِينَ فَإِذَا بَلَغَتْ سِتًّا وَأَرْبَعِينَ فَفِيهَا حِقَّةٌ طَرُوقَةُ الْفَحْلِ إِلَى سِتِّينَ فَإِذَا بَلَغَتْ إِحْدَى وَسِتِّينَ فَفِيهَا جَذَعَةٌ إِلَى خَمْسٍ وَسَبْعِينَ فَإِذَا بَلَغَتْ سِتًّا وَسَبْعِينَ فَفِيهَا ابْنَتَا لَبُونٍ إِلَى تِسْعِينَ فَإِذَا بَلَغَتْ إِحْدَى وَتِسْعِينَ فَفِيهَا حِقَّتَانِ طَرُوقَتَا الْفَحْلِ إِلَى عِشْرِينَ وَمِائَةٍ فَإِذَا زَادَتْ عَلَى عِشْرِينَ وَمِائَةٍ فَفِي كُلِّ أَرْبَعِينَ بِنْتُ لَبُونٍ وَفِي كُلِّ خَمْسِينَ حِقَّةٌ فَإِذَا تَبَايَنَ أَسْنَانُ الْإِبِلِ فِي فَرَائِضِ الصَّدَقَاتِ فَمَنْ بَلَغَتْ عِنْدَهُ صَدَقَةُ الْجَذَعَةِ وَلَيْسَتْ عِنْدَهُ جَذَعَةٌ وَعِنْدَهُ حِقَّةٌ فَإِنَّهَا تُقْبَلُ مِنْهُ وَأَنْ يَجْعَلَ مَعَهَا شَاتَيْنِ إِنْ اسْتَيْسَرَتَا لَهُ أَوْ عِشْرِينَ دِرْهَمًا وَمَنْ بَلَغَتْ عِنْدَهُ صَدَقَةُ الْحِقَّةِ وَلَيْسَتْ عِنْدَهُ حِقَّةٌ وَعِنْدَهُ جَذَعَةٌ فَإِنَّهَا تُقْبَلُ مِنْهُ وَيُعْطِيهِ الْمُصَدِّقُ عِشْرِينَ دِرْهَمًا أَوْ شَاتَيْنِ وَمَنْ بَلَغَتْ عِنْدَهُ صَدَقَةُ الْحِقَّةِ وَلَيْسَ عِنْدَهُ حِقَّةٌ وَعِنْدَهُ ابْنَةُ لَبُونٍ فَإِنَّهَا تُقْبَلُقَالَ أَبُو دَاوُد مِنْ هَاهُنَا لَمْ أَضْبِطْهُ عَنْ مُوسَى كَمَا أُحِبُّ وَيَجْعَلُ مَعَهَا شَاتَيْنِ إِنْ اسْتَيْسَرَتَا لَهُ أَوْ عِشْرِينَ دِرْهَمًا وَمَنْ بَلَغَتْ عِنْدَهُ صَدَقَةُ بِنْتِ لَبُونٍ وَلَيْسَ عِنْدَهُ إِلَّا حِقَّةٌ فَإِنَّهَا تُقْبَلُ مِنْهُ قَالَ أَبُو دَاوُد إِلَى هَاهُنَا ثُمَّ أَتْقَنْتُهُ وَيُعْطِيهِ الْمُصَدِّقُ عِشْرِينَ دِرْهَمًا أَوْ شَاتَيْنِ وَمَنْ بَلَغَتْ عِنْدَهُ صَدَقَةُ ابْنَةِ لَبُونٍ وَلَيْسَ عِنْدَهُ إِلَّا بِنْتُ مَخَاضٍ فَإِنَّهَا تُقْبَلُ مِنْهُ وَشَاتَيْنِ أَوْ عِشْرِينَ دِرْهَمًا وَمَنْ بَلَغَتْ عِنْدَهُ صَدَقَةُ ابْنَةِ مَخَاضٍ وَلَيْسَ عِنْدَهُ إِلَّا ابْنُ لَبُونٍ ذَكَرٌ فَإِنَّهُ يُقْبَلُ مِنْهُ وَلَيْسَ مَعَهُ شَيْءٌ وَمَنْ لَمْ يَكُنْ عِنْدَهُ إِلَّا أَرْبَعٌ فَلَيْسَ فِيهَا شَيْءٌ إِلَّا أَنْ يَشَاءَ رَبُّهَا وَفِي سَائِمَةِ الْغَنَمِ إِذَا كَانَتْ أَرْبَعِينَ فَفِيهَا شَاةٌ إِلَى عِشْرِينَ وَمِائَةٍ فَإِذَا زَادَتْ عَلَى عِشْرِينَ وَمِائَةٍ فَفِيهَا شَاتَانِ إِلَى أَنْ تَبْلُغَ مِائَتَيْنِ فَإِذَا زَادَتْ عَلَى مِائَتَيْنِ فَفِيهَا ثَلَاثُ شِيَاهٍ إِلَى أَنْ تَبْلُغَ ثَلَاثَ مِائَةٍ فَإِذَا زَادَتْ عَلَى ثَلَاثِ مِائَةٍ فَفِي كُلِّ مِائَةِ شَاةٍ شَاةٌ وَلَا يُؤْخَذُ فِي الصَّدَقَةِ هَرِمَةٌ وَلَا ذَاتُ عَوَارٍ مِنْ الْغَنَمِ وَلَا تَيْسُ الْغَنَمِ إِلَّا أَنْ يَشَاءَ الْمُصَدِّقُ وَلَا يُجْمَعُ بَيْنَ مُفْتَرِقٍ وَلَا يُفَرَّقُ بَيْنَ مُجْتَمِعٍ خَشْيَةَ الصَّدَقَةِ وَمَا كَانَ مِنْ خَلِيطَيْنِ فَإِنَّهُمَا يَتَرَاجَعَانِ بَيْنَهُمَا بِالسَّوِيَّةِ فَإِنْ لَمْ تَبْلُغْ سَائِمَةُ الرَّجُلِ أَرْبَعِينَ فَلَيْسَ فِيهَا شَيْءٌ إِلَّا أَنْ يَشَاءَ رَبُّهَا وَفِي الرِّقَةِ رُبْعُ الْعُشْرِ فَإِنْ لَمْ يَكُنْ الْمَالُ إِلَّا تِسْعِينَ وَمِائَةً فَلَيْسَ فِيهَا شَيْءٌ إِلَّا أَنْ يَشَاءَ رَبُّهَا","id":"Telah menceritakan kepada Kami [Musa bin Ismail], telah menceritakan kepada Kami [Hammad], ia berkata; aku mengambil sebuah tulisan dari [Tsumamah bin Abdullah bin Anas], ia mengaku bahwa [Abu Bakar] telah menulis [Anas] dan padanya terdapat stempel Rasulullah shallAllahu wa'alaihi wa sallam ketika ia mengutusnya sebagai petugas pengambil zakat, dan ia menulis untuknya, dan ternyata tulisan tersebut berisi: Ini adalah kewajiban zakat yang telah diwajibkan Rasulullah shallAllahu wa'alaihi wa sallam kepada orang-orang muslim yang telah Allah 'azza wajalla perintahkan kepada NabiNya shallallahu 'alaihi wasallam. Maka barangsiapa diantara orang-orang muslim yang diminta zakatnya sesuai dengan ketentuannya, maka hendaknya ia memberikannya. Dan barang siapa yang diminta lebih dari itu maka janganlah ia memberinya. Unta yang kurang dari dua puluh lima zakatnya adalah satu ekor kambing, setiap lima dzaud terdapat zakat satu ekor kambing, kemudian apabila telah mencapai dua puluh lima ekor maka padanya terdapat zakat satu ekor bintu makhadh hingga menjacapai tiga puluh lima, apabila tidak ada bintu makhadh maka ibnu labun (yang memiliki umur dua tahun) jantan, kemudian apabila telah mencapai tiga puluh enam maka padanya zakat bintu labun (yang memiliki umur dua tahun) hingga mencapai empat puluh lima, kemudian apabila telah mencapai empat puluh enam maka padanya hiqqah (yang memiliki umur tiga tahun) yang siap untuk hamil, hingga mencapai enam puluh. Kemudian apabila enam puluh satu maka padanya terdapat zakat tujuh puluh lima. Kemudian apabila telah mencapai tujuh puluh enam maka padanya zakat dua bintu labun (yang memiliki umur dua tahun), hingga mencapai sembilan puluh, kemudian apabila telah mencapai sembilan puluh satu maka padanya zakat dua ekor Hiqqah (yang memiliki umur tiga tahun) yang siap hamil, hingga mencapai seratus dua puluh. Kemudian apabila melebihi seratus dua puluh maka pada setiap empat puluh terdapat zakat satu ekor bintu labun (yang memiliki umur dua tahun), dan pada setiap lima puluh terdapat zakat satu ekor hiqqah (yang memiliki umur tiga tahun). Kemudian apabila telah nampak umur-umur unta dalam zakat-zakat wajib, maka barang siapa yang telah sampai padanya zakat jadza'ah (yang memiliki umur empat tahun) dan ia tidak memiliki jadza'ah (yang memiliki umur empat tahun) akan tetapi memiliki hiqqah (yang memiliki umur tiga tahun) maka diterima darinya, dan bersamanya ia memberikan dua ekor kambing apabila keduanya mudah baginya, uang atau dua puluh dirham. Dan barang siapa yang telah sampai padanya zakat hiqqah (yang memiliki umur tiga tahun) dan ia tidak memiliki hiqqah (yang memiliki umur tiga tahun) akan tetapi memiliki jadza'ah (yang memiliki umur empat tahun) maka diterima darinya dan petugas zakat memberinya uang dua puluh dirham, atau dua ekor kambing. Dan barang siapa yang telah sampai padanya zakat hiqqah (yang memiliki umur tiga tahun) dan ia tidak memiliki hiqqah (yang memiliki umur tiga tahun) akan tetapi memiliki bintu labun (yang memiliki umur dua tahun) maka diterima darinya. -Abu Daud berkata; dari sini aku tidak hafal dari Musa sebagaimana yang aku inginkan. - dan bersamanya ia memberikan dua ekor kambing apabila keduanya mudah baginya, atau dua puluh dirham. Dan barang siapa yang telah sampai padanya zakat bintu labun (yang memiliki umur dua tahun) dan ia hanya memiliki hiqqah (yang memiliki umur tiga tahun) maka diterima darinya -Abu Daud berkata; hingga sini kemudian aku meyakininya ia berkata; dan petugas pengambil zakat memberinya uang dua puluh dirham, atau dua ekor kambing. Dan barang siapa yang sampai padanya zakat bintu labun (yang memiliki umur dua tahun) dan ia hanya memiliki bintu makhadh maka diterima darinya disertai dengan dua ekor kambing atau uang dua dirham. Dna brang siapa yang telah sampai (nishab) zakat bintu makhadh dan ia hanya memiliki ibnu labun (yang memiliki umur dua tahun) jantan, maka diterima darinya dan tidak disertai dengan apapun. Dan barang siapa yang hanya memiliki dua ekor maka tidak ada zakat padanya kecuali pemiliknya menginginkannya. Pada kambing yang digembala di padang rumput apabila berjumlah empat puluh maka padanya zakat satu ekor kambing hingga seratus dua puluh ekor, kemudian apabila melebihi seratus dua puluh maka padanya zakat dua ekor kambing hingga mencapai dua ratus ekor. Kemudian apabila melebihi dua ratus ekor maka padanya terdapat zkaat tiga ekor kambing hingga mencapai tiga ratus, kemudian apabila telah melebihi tiga ratus ekor maka setiap seratus kambing terdapat zakat satu ekor kambing. Dan dalam zakat tidak diambil kambing yang tua dan telah tanggal gigi-giginya, kambing yang memiliki aib, dan kambing pejantan, kecuali petugas pengambil zakat menghendakinya. Tidak boleh digambungkan antara kambing yang dipisahkan dan tidak boleh dipisahkan antara kambing yang digabungkan karena khawatir wajib mengeluarkan zakat. Kambing yang berasal dari gabungan dua orang maka keduanya membagi dengan sama. Kemudian apabila kambing yang digembalakan di padang rumput tidak mencapai empat puluh ekor maka tidak ada zakat padanya kecuali pemiliknya menghendakinya. Pada perak terdapat zakat seperempat puluh, kemudian apabila harta tersebut hanya mencapai seratus sembilan puluh maka tidak ada zakat padanya kecuali pemiliknya menghendakinya. "},"1292":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ عَنْ سُفْيَانَ بْنِ الْحُسَيْنِ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَكَتَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كِتَابَ الصَّدَقَةِ فَلَمْ يُخْرِجْهُ إِلَى عُمَّالِهِ حَتَّى قُبِضَ فَقَرَنَهُ بِسَيْفِهِ فَعَمِلَ بِهِ أَبُو بَكْرٍ حَتَّى قُبِضَ ثُمَّ عَمِلَ بِهِ عُمَرُ حَتَّى قُبِضَ فَكَانَ فِيهِ فِي خَمْسٍ مِنْ الْإِبِلِ شَاةٌ وَفِي عَشْرٍ شَاتَانِ وَفِي خَمْسَ عَشْرَةَ ثَلَاثُ شِيَاهٍ وَفِي عِشْرِينَ أَرْبَعُ شِيَاهٍ وَفِي خَمْسٍ وَعِشْرِينَ ابْنَةُ مَخَاضٍ إِلَى خَمْسٍ وَثَلَاثِينَ فَإِنْ زَادَتْ وَاحِدَةً فَفِيهَا ابْنَةُ لَبُونٍ إِلَى خَمْسٍ وَأَرْبَعِينَ فَإِذَا زَادَتْ وَاحِدَةً فَفِيهَا حِقَّةٌ إِلَى سِتِّينَ فَإِذَا زَادَتْ وَاحِدَةً فَفِيهَا جَذَعَةٌ إِلَى خَمْسٍ وَسَبْعِينَ فَإِذَا زَادَتْ وَاحِدَةً فَفِيهَا ابْنَتَا لَبُونٍ إِلَى تِسْعِينَ فَإِذَا زَادَتْ وَاحِدَةً فَفِيهَا حِقَّتَانِ إِلَى عِشْرِينَ وَمِائَةٍ فَإِنْ كَانَتْ الْإِبِلُ أَكْثَرَ مِنْ ذَلِكَ فَفِي كُلِّ خَمْسِينَ حِقَّةٌ وَفِي كُلِّ أَرْبَعِينَ ابْنَةُ لَبُونٍ وَفِي الْغَنَمِ فِي كُلِّ أَرْبَعِينَ شَاةً شَاةٌ إِلَى عِشْرِينَ وَمِائَةٍ فَإِنْ زَادَتْ وَاحِدَةً فَشَاتَانِ إِلَى مِائَتَيْنِ فَإِنْ زَادَتْ وَاحِدَةً عَلَى الْمِائَتَيْنِ فَفِيهَا ثَلَاثُ شِيَاهٍ إِلَى ثَلَاثِ مِائَةٍ فَإِنْ كَانَتْ الْغَنَمُ أَكْثَرَ مِنْ ذَلِكَ فَفِي كُلِّ مِائَةِ شَاةٍ شَاةٌ وَلَيْسَ فِيهَا شَيْءٌ حَتَّى تَبْلُغَ الْمِائَةَ وَلَا يُفَرَّقُ بَيْنَ مُجْتَمِعٍ وَلَا يُجْمَعُ بَيْنَ مُتَفَرِّقٍ مَخَافَةَ الصَّدَقَةِ وَمَا كَانَ مِنْ خَلِيطَيْنِ فَإِنَّهُمَا يَتَرَاجَعَانِ بَيْنَهُمَا بِالسَّوِيَّةِ وَلَا يُؤْخَذُ فِي الصَّدَقَةِ هَرِمَةٌ وَلَا ذَاتُ عَيْبٍقَالَ و قَالَ الزُّهْرِيُّ إِذَا جَاءَ الْمُصَدِّقُ قُسِّمَتْ الشَّاءُ أَثْلَاثًا ثُلُثًا شِرَارًا وَثُلُثًا خِيَارًا وَثُلُثًا وَسَطًا فَأَخَذَ الْمُصَدِّقُ مِنْ الْوَسَطِ وَلَمْ يَذْكُرْ الزُّهْرِيُّ الْبَقَرَ حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ يَزِيدَ الْوَاسِطِيُّ أَخْبَرَنَا سُفْيَانُ بْنُ حُسَيْنٍ بِإِسْنَادِهِ وَمَعْنَاهُ قَالَ فَإِنْ لَمْ تَكُنْ ابْنَةُ مَخَاضٍ فَابْنُ لَبُونٍ وَلَمْ يَذْكُرْ كَلَامَ الزُّهْرِيِّ حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ أَخْبَرَنَا ابْنُ الْمُبَارَكِ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ ابْنِ شِهَابٍ قَالَ هَذِهِ نُسْخَةُ كِتَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِي كَتَبَهُ فِي الصَّدَقَةِ وَهِيَ عِنْدَ آلُ عُمَرَ بْنِ الْخَطَّابِ قَالَ ابْنُ شِهَابٍ أَقْرَأَنِيهَا سَالِمُ بْنُ عَبْدِ اللَّهِ بْنِ عُمَرَ فَوَعَيْتُهَا عَلَى وَجْهِهَا وَهِيَ الَّتِي انْتَسَخَ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ مِنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ وَسَالِمِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ فَذَكَرَ الْحَدِيثَ قَالَ فَإِذَا كَانَتْ إِحْدَى وَعِشْرِينَ وَمِائَةً فَفِيهَا ثَلَاثُ بَنَاتِ لَبُونٍ حَتَّى تَبْلُغَ تِسْعًا وَعِشْرِينَ وَمِائَةً فَإِذَا كَانَتْ ثَلَاثِينَ وَمِائَةً فَفِيهَا بِنْتَا لَبُونٍ وَحِقَّةٌ حَتَّى تَبْلُغَ تِسْعًا وَثَلَ��ثِينَ وَمِائَةً فَإِذَا كَانَتْ أَرْبَعِينَ وَمِائَةً فَفِيهَا حِقَّتَانِ وَبِنْتُ لَبُونٍ حَتَّى تَبْلُغَ تِسْعًا وَأَرْبَعِينَ وَمِائَةً فَإِذَا كَانَتْ خَمْسِينَ وَمِائَةً فَفِيهَا ثَلَاثُ حِقَاقٍ حَتَّى تَبْلُغَ تِسْعًا وَخَمْسِينَ وَمِائَةً فَإِذَا كَانَتْ سِتِّينَ وَمِائَةً فَفِيهَا أَرْبَعُ بَنَاتِ لَبُونٍ حَتَّى تَبْلُغَ تِسْعًا وَسِتِّينَ وَمِائَةً فَإِذَا كَانَتْ سَبْعِينَ وَمِائَةً فَفِيهَا ثَلَاثُ بَنَاتِ لَبُونٍ وَحِقَّةٌ حَتَّى تَبْلُغَ تِسْعًا وَسَبْعِينَ وَمِائَةً فَإِذَا كَانَتْ ثَمَانِينَ وَمِائَةً فَفِيهَا حِقَّتَانِ وَابْنَتَا لَبُونٍ حَتَّى تَبْلُغَ تِسْعًا وَثَمَانِينَ وَمِائَةً فَإِذَا كَانَتْ تِسْعِينَ وَمِائَةً فَفِيهَا ثَلَاثُ حِقَاقٍ وَبِنْتُ لَبُونٍ حَتَّى تَبْلُغَ تِسْعًا وَتِسْعِينَ وَمِائَةً فَإِذَا كَانَتْ مِائَتَيْنِ فَفِيهَا أَرْبَعُ حِقَاقٍ أَوْ خَمْسُ بَنَاتِ لَبُونٍ أَيُّ السِّنَّيْنِ وُجِدَتْ أُخِذَتْ وَفِي سَائِمَةِ الْغَنَمِ فَذَكَرَ نَحْوَ حَدِيثِ سُفْيَانَ بْنِ حُسَيْنٍ وَفِيهِ وَلَا يُؤْخَذُ فِي الصَّدَقَةِ هَرِمَةٌ وَلَا ذَاتُ عَوَارٍ مِنْ الْغَنَمِ وَلَا تَيْسُ الْغَنَمِ إِلَّا أَنْ يَشَاءَ الْمُصَدِّقُ","id":"Telah menceritakan kepada Kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada Kami ['Abbad bin Al 'Awwam] dari [Sufyan bin Al Husain] dari [Az Zuhri] dari [Salim] dari [ayahnya], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam telah menulis catatan mengenai zakat dan beliau tidak mengeluarkannya kepada para pegawainya hingga beliau meninggal. Beliau menyertakan pada pedangnya. Kemudian Abu Bakr melaksanakannya hingga ia meninggal, kemudian dilaksanakan oleh Umar hingga ia meninggal. Catatan tersebut berisi: Pada lima ekor unta terdapat zakat satu ekor kambing, dan pada sepuluh ekor terdapat zakat dua ekor kambing, pada lima belas ekor unta terdapat zakat tiga ekor kambing, pada dua puluh ekor unta terdapat empat ekor kambing, pada dua puluh lima ekor unta terdapat zakat satu ekor bintu makhadh hingga tiga puluh lima ekor, kemudian apabila lebih satu maka padanya terdapat zakat satu ekor bintu labun (yang memiliki umur dua tahun) hingga empat puluh lima ekor, kemudian apabila lebih satu maka padanya terdapat zakat satu ekor hiqqah (yang memiliki umur tiga tahun) hingga enam ekor, kemudian apabila lebih satu ekor maka padanya terdapat zakat satu ekor jadza'ah (yang memiliki umur empat tahun) hingga tujuh puluh lima ekor, kemudian apabila lebih satu ekor maka padanya terdapat zakat dua ekor bintu labun (yang memiliki umur dua tahun), hingga sembilan puluh ekor, kemudian apabila lebih satu ekor maka padanya terdapat zakat dua ekor hiqqah (yang memiliki umur tiga tahun), hingga seratus dua puluh ekor. Kemudian apabila lebih banyak dari itu maka pada setiap lima puluh ekor terdapat zakat satu ekor hiqqah (yang memiliki umur tiga tahun), dan pada setiap empat ekor terdapat zakat satu ekor bintu labun (yang memiliki umur dua tahun). Pada kambing setiap empat puluh ekor kambing terdapat zakat satu kambing, hingga seratus dua puluh ekor kambing. Kemudian apabila lebih satu ekor maka padanya terdapat zakat dua ekor kambing, hingga dua ratus ekor. Kemudian apabila satu ekor melebihi dua ratus ekor maka padanya terdapat zakat tiga ekor kambing, hingga tiga ratus ekor, kemudian apabila kambing tersebut lebih dari itu, maka pada setiap seratus ekor terdapat zakat satu ekor kambing, dan padanya tidak terdapat zakat hingga mencapai seratus ekor. Dan tidak dipisahkan antara kambing yang digabungkan dan tidak digabungkan antara kambing yang terpisah karena khawatir wajib zakat. Dan kambing yang berasal dari gabungan dua orang maka keduanya membagi dengan sama. Tidak diambil dalam zakat kambing yang sudah tua dan tanggal giginya, serta kambing yang memiliki aib. 'Abbad bin Al 'Awwam berkata; Az Zuhri berkata; apabila petugas zakat telah datang maka kambing dibagi menjadi tiga, seperti tiga adalah kambing jelek, sepertiga kambing pilihan, dan sepertiga kambing pertengahan. Kemudian petugas zakat mengambil dari kambing yang pertengahan, dan Az Zuhri tidak menyebutkan sapi. Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Muhammad bin Yazid Al Wasithi], telah mengabarkan kepada Kami [Sufyan bin Husain] dengan sanad dan maknanya, ia berkata; apabila tidak ada bintu makhadh, maka dikeluarkan ibnu labun (yang memiliki umur dua tahun). Dan ia tidak menyebutkan perkataan Az Zuhri. Telah menceritakan kepada Kami [Muhammad bin Al 'Ala`], telah mengabarkan kepada Kami [Ibnu Al Mubarak] dari [Yunus bin Yazid] dari [Ibnu Syihab], ia berkata; ini adalah naskah catatan Rasulullah shallAllahu wa'alaihi wa sallam yang beliau tulis mengenai zakat, dan naskah tersebut ada pada keluarga Umar bin Al Khathab. Ibnu Syihab berkata; Salim bin Abdullah bin Umar telah membacakannya kepadaku, kemudian aku menghafalnya sesuai dengan keandaanya, dan naskah itu yang disalin oleh Umar bin Abdul 'Aziz dari Abdullah bin Abdullah bin Umar, serta Salim bin Abdullah bin Umar. Kemudian ia menyebutkan hadits tersebut, ia berkata; apabila berjumlah seratus dua puluh satu maka padanya terdapat zakat tiga bintu labun (yang memiliki umur dua tahun), hingga mencapai seratus dua puluh sembilan. Kemudian apabila berjumlah seratus tiga puluh maka padanya terdapat zakat dua bintu labun (yang memiliki umur dua tahun), dan satu ekor hiqqah (yang memiliki umur tiga tahun), hingga mencapai seratus sembilan puluh sembilan. Kemudian apabila berjumlah seratus empat puluh maka padanya terdapat zakat dua hiqqah (yang memiliki umur tiga tahun) dan satu bintu labun (yang memiliki umur dua tahun), hingga mencapai seratus empat puluh sembilan. Kemudian apabila berjumlah seratus lima puluh maka padanya terdapat zakat tiga hiqqah (yang memiliki umur tiga tahun), hingga mencapai seratus lima puluh sembilan. Kemudian apabila berjumlah seratus sembilan puluh maka padanya terdapat zakat empat bintu labun (yang memiliki umur dua tahun), hingga mencapai seratus enam puluh sembilan. Kemudian apabila berjumlah seratus tujuh puluh maka padanya terdapat zakat tiga bintu labun (yang memiliki umur dua tahun) dan satu hiqqah (yang memiliki umur tiga tahun), hingga mencapai seratus tujuh puluh sembilan. Kemudian apabila berjumlah seratus delapan puluh maka padanya terdapat zakat dua hiqqah (yang memiliki umur tiga tahun), dan dua bintu labun (yang memiliki umur dua tahun), hingga mencapai seratus delapan puluh sembilan. Kemudian apabila berjumlah seratus sembilan puluh maka padanya terdapat zakat tiga hiqqah (yang memiliki umur tiga tahun), dan satu bintu labun (yang memiliki umur dua tahun), hingga mencapai seratus sembilan puluh sembilan. Kemudian apabila berjumlah dua ratus maka padanya terdapat zakat empat hiqqah (yang memiliki umur tiga tahun), atau lima bintu labun (yang memiliki umur dua tahun), kambing manapun yang berumur dua tahun didapat maka diambil. Dan pada hewan yang digembalakan di padang rumput ….. kemudian ia menyebutkan seperti hadits Sufyan bin Husain, dan padanya disebutkan; dan tidak diambil dalam zakat kambing yang tua dan telah tanggal giginya, serta yang memiliki aib, serta kambing pejantan, kecuali petugas zakat menghendakinya. "},"1293":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ قَالَ قَالَ مَالِكٌوَقَوْلُ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ لَا يُجْمَعُ بَيْنَ مُتَفَرِّقٍ وَلَا يُفَرَّقُ بَيْنَ مُجْتَمِعٍ هُوَ أَنْ يَكُونَ لِكُلِّ رَجُلٍ أَرْبَعُونَ شَاةً فَإِذَا أَظَلَّهُمْ الْمُصَدِّقُ جَمَعُوهَا لِئَلَّا يَكُونَ فِيهَا إِلَّا شَاةٌ وَلَا يُفَرَّقُ بَيْنَ مُجْتَمِعٍ أَنَّ الْخَلِيطَيْنِ إِذَا كَانَ لِكُلِّ وَاحِدٍ مِنْهُمَا مِائَةُ شَاةٍ وَشَاةٌ فَيَكُونُ عَلَيْهِمَا فِيهَا ثَلَاثُ شِيَاهٍ فَإِذَا أَظَلَّهُمَا الْمُصَدِّقُ فَرَّقَا غَنَمَهُمَا فَلَمْ يَكُنْ عَلَى كُلِّ وَاحِدٍ مِنْهُمَا إِلَّا شَاةٌ فَهَذَا الَّذِي سَمِعْتُ فِي ذَلِكَ","id":"Telah menceritakan kepada Kami [Abdullah bin Maslamah], ia berkata; [Malik] berkata; dan perkataan Umar bin Al Khathab radliallahu 'anhu; tidak digabungkan antara kambing yang terpisah, dan tidak dipisahkan antara kambing yang digabungkan, artinya bahwa setiap orang memiliki empat puluh kambing, kemudian apabila petugas zakat telah datang kepada mereka maka mereka menggabungkankannya agar mereka hanya mengeluarkan zakat satu ekor kambing. Dan tidak dipisahkan antara kambing yang digabungkan, bahwa dua orang yang menggabungkan kambing milik mereka apabila setiap mereka memiliki seratus satu ekor kambing maka kewajiban mereka berdua adalah zakat tiga ekor kambing. Kemudian apabila petugas zakat telah datang kepada mereka maka mereka memisahkan kambing mereka sehingga setiap orang hanya berkewajiban membayar zakat satu ekor kambing. Inilah yang aku dengar mengenai hal tersebut. "},"1294":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا أَبُو عَوَانَةَ عَنْ أَبِي إِسْحَقَ عَنْ عَاصِمِ بْنِ ضَمْرَةَ عَنْ عَلِيٍّ عَلَيْهِ السَّلَام قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ عَفَوْتُ عَنْ الْخَيْلِ وَالرَّقِيقِ فَهَاتُوا صَدَقَةَ الرِّقَةِ مِنْ كُلِّ أَرْبَعِينَ دِرْهَمًا دِرْهَمًا وَلَيْسَ فِي تِسْعِينَ وَمِائَةٍ شَيْءٌ فَإِذَا بَلَغَتْ مِائَتَيْنِ فَفِيهَا خَمْسَةُ دَرَاهِمَقَالَ أَبُو دَاوُد رَوَى هَذَا الْحَدِيثَ الْأَعْمَشُ عَنْ أَبِي إِسْحَقَ كَمَا قَالَ أَبُو عَوَانَةَ وَرَوَاهُ شَيْبَانُ أَبُو مُعَاوِيَةَ وَإِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ قَالَ أَبُو دَاوُد وَرَوَى حَدِيثَ النُّفَيْلِيِّ شُعْبَةُ وَسُفْيَانُ وَغَيْرُهُمَا عَنْ أَبِي إِسْحَقَ عَنْ عَاصِمٍ عَنْ عَلِيٍّ لَمْ يَرْفَعُوهُ أَوْقَفُوهُ عَلَى عَلِيٍّ","id":"Telah menceritakan kepada Kami ['Amr bin 'Aun], telah mengabarkan kepada Kami [Abu 'Awanah] dari [Abu Ishaq] dari ['Ashim bin Dhamrah] dari [Ali] 'alaihis salam, ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda; Sungguh aku telah memaafkan dari mengambil zakat kuda dan budak, maka berikan zakat perak dari setiap empat puluh dirham, satu dirham. Tidak ada zakat sedikitpun pada jumlah seratus sembilan puluh, kemudian apabila telah mencapai dua ratus maka padanya terdapat zakat lima dirham. Abu Daud berkata; hadits ini telah diriwayatkan oleh [Al A'masy] dari [Abu Ishaq] sebagaimana yang dikatakan Abu 'Awanah, dan telah diriwayatkan oleh [Syaiban Abu Mu'awiyah] dan [Ibrahim bin Thahman] dari [Abu Ishaq] dari [Al Harits] dari [Ali] dari Nabi shallallahu 'alaihi wasallam seperti itu. Abu Daud berkata; dan hadits An Nufaili telah diriwayatkan oleh [Syu'bah] serta [Sufyan] dan yang lainnya dari [Abu Ishaq] dari ['Ashim] dari [Ali]. Mereka tidak merafa'kannya melainkan mereka memauqufkan kepada Ali. "},"1295":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا بَهْزُ بْنُ حَكِيمٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ وَأَخْبَرَنَا أَبُو أُسَامَةَ عَنْ بَهْزِ بْنِ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي كُلِّ سَائِمَةِ إِبِلٍ فِي أَرْبَعِينَ بِنْتُ لَبُونٍ وَلَا يُفَرَّقُ إِبِلٌ عَنْ حِسَابِهَا مَنْ أَعْطَاهَا مُؤْتَجِرًا قَالَ ابْنُ الْعَلَاءِ مُؤْتَجِرًا بِهَا فَلَهُ أَجْرُهَا وَمَنْ مَنَعَهَا فَإِنَّا آخِذُوهَا وَشَطْرَ مَالِهِ عَزْمَةً مِنْ عَزَمَاتِ رَبِّنَا عَزَّ وَجَلَّ لَيْسَ لِآلِ مُحَمَّدٍ مِنْهَا شَيْءٌ","id":"Telah menceritakan kepada Kami [Musa bin Ismail], telah menceritakan kepada Kami [Hammad], telah mengabarkan kepada Kami [Bahz bin Hakim] dan jalur periwayatan lain telah menceritakan kepada kami [Muhammad bin Al 'Ala'] dan telah mengabarkan kepada kami [Abu Usamah] dari [Bahz bin Hakim] dari [ayahnya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam Bersabda: \"Pada setiap empat puluh unta saimah (yang digembala lebih dari satu tahun) terdapat zakat satu bintu labun (yang memiliki umur dua tahun), dan unta tidak boleh dipisahkan dari hitungannya, barangsiapa yang memberikan zakatnya karena mengharap pahala, maka baginya pahala. Dan barangsiapa yang enggan membayarnya, maka Kami akan mengambilnya dan setengah hartanya; sebagai kewajiban diantara kewajiban-kewajiban Allah Azza wa jalla, dan keluarga Muhammad tidak berhak sedikitpun dari harta tersebut."},"1296":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ هِلَالِ بْنِ خَبَّابٍ عَنْ مَيْسَرَةَ أَبِي صَالِحٍ عَنْ سُوَيْدِ بْنِ غَفَلَةَ قَالَ سِرْتُ أَوْ قَالَ أَخْبَرَنِي مَنْسَارَ مَعَ مُصَدِّقِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ لَا تَأْخُذَ مِنْ رَاضِعِ لَبَنٍ وَلَا تَجْمَعَ بَيْنَ مُفْتَرِقٍ وَلَا تُفَرِّقَ بَيْنَ مُجْتَمِعٍ وَكَانَ إِنَّمَا يَأْتِي الْمِيَاهُ حِينَ تَرِدُ الْغَنَمُ فَيَقُولُ أَدُّوا صَدَقَاتِ أَمْوَالِكُمْ قَالَ فَعَمَدَ رَجُلٌ مِنْهُمْ إِلَى نَاقَةٍ كَوْمَاءَ قَالَ قُلْتُ يَا أَبَا صَالِحٍ مَا الْكَوْمَاءُ قَالَ عَظِيمَةُ السَّنَامِ قَالَ فَأَبَى أَنْ يَقْبَلَهَا قَالَ إِنِّي أُحِبُّ أَنْ تَأْخُذَ خَيْرَ إِبِلِي قَالَ فَأَبَى أَنْ يَقْبَلَهَا قَالَ فَخَطَمَ لَهُ أُخْرَى دُونَهَا فَأَبَى أَنْ يَقْبَلَهَا ثُمَّ خَطَمَ لَهُ أُخْرَى دُونَهَا فَقَبِلَهَا وَقَالَ إِنِّي آخِذُهَا وَأَخَافُ أَنْ يَجِدَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لِي عَمَدْتَ إِلَى رَجُلٍ فَتَخَيَّرْتَ عَلَيْهِ إِبِلَهُقَالَ أَبُو دَاوُد وَرَوَاهُ هُشَيْمٌ عَنْ هِلَالِ بْنِ خَبَّابٍ نَحْوَهُ إِلَّا أَنَّهُ قَالَ لَا يُفَرَّقُ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Abu 'Awanah] dari [Hilal bin Khabba] dari [Maisarah Abu Shalih] dari [Suwaid bin Ghafalah], ia berkata; aku berjalan -atau ia berkata; telah mengabarkan kepadaku [orang yang berjalan] bersama petugas pengambil zakat Nabi shallallahu 'alaihi wasallam, ternyata pada zaman Rasulullah shallAllahu wa'alaihi wa sallam dikata; janganlah engkau mengambil zakat dari anak yang sedang menetek susu, dan janganlah engkau menggabungkan antara hewan yang dipisahkandan jangan memisahkan antara hewan yang telah dijadikan satu. Dan sesungguhnya air datang ketika kambing datang, kemudian petugas pengambil zakat berkata; Tunaikan zakat harta kalian. Maisarah berkata; kemudian salah seorang diantara mereka mendatangi unta kauma`. Kemudian aku katakan; wahai Abu Shalih, apakah kauma` itu? Ia berkata; yang besar punuknya. Maisarah berkata; kemudian ia enggan menerimanya. Orang tersebut berkata; sesungguhnya aku ingin anda mengambil unta terbaikku. Maisarah berkata; kemudian ia enggan untuk menerimanya. Maisarah berkata; kemudian orang tersebut menuntun untanya yang lain, lalu petugas zakat tersebut enggan untuk menerimanya, kemudian orang tersebut menuntun untanya yang lain selain unta tersebut, lalu petugas zakat tersebut menerimanya dan berkata; sesungguhnya aku mengambilnya dan aku merasa khawatir Rasulullah shallallahu 'alaihi wasallam marah kepadaku dan berkata: \"Engkau mendatangi seseorang dan memilih unta terbaiknya.\" Abu Daud berkata; dan [Husyaim] telah meriwayatkannya dari [Hilal bin Khabbab] seperti itu, hanya saja ia berkata; tidak dipisahkan….. "},"1297":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ الْبَزَّازُ حَدَّثَنَا شَرِيكٌ عَنْ عُثْمَانَ بْنِ أَبِي زُرْعَةَ عَنْ أَبِي لَيْلَى الْكِنْدِيِّ عَنْ سُوَيْدِ بْنِ غَفَلَةَ قَالَأَتَانَا مُصَدِّقُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذْتُ بِيَدِهِ وَقَرَأْتُ فِي عَهْدِهِ لَا يُجْمَعُ بَيْنَ مُفْتَرِقٍ وَلَا يُفَرَّقُ بَيْنَ مُجْتَمِعٍ خَشْيَةَ الصَّدَقَةِ وَلَمْ يَذْكُرْ رَاضِعَ لَبَنٍ","id":"Telah menceritakan kepada Kami [Muhammad bin Ash Shabbah Al Bazzar], telah menceritakan kepada Kami [Syarik] dari [Utsman bin Abu Zur'ah] dari [Abu Laila Al Kindi] dari [Suwaid bin Ghafalah], ia berkata; [petugas zakat Nabi shallallahu 'alaihi wasallam] telah datang kepada Kami, kemudian aku gandeng tangannya dan aku membaca isi catatannya: Tidak boleh digabungkan antara hewan yang terpisah, dan tidak boleh dipisahkan antara hilang yang digabungkan karena khawatir wajib zakat. Dan ia tidak menyebutkan; hewan yang menetek susu. "},"1298":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا وَكِيعٌ عَنْ زَكَرِيَّا بْنِ إِسْحَقَ الْمَكِّيِّ عَنْ عَمْرِو بْنِ أَبِي سُفْيَانَ الْجُمَحِيِّ عَنْ مُسْلِمِ بْنِ ثَفِنَةَ الْيَشْكُرِيِّ قَالَ الْحَسَنُ رَوْحٌ يَقُولُ مُسْلِمُ بْنُ شُعْبَةَ قَالَاسْتَعْمَلَ نَافِعُ بْنُ عَلْقَمَةَ أَبِي عَلَى عِرَافَةِ قَوْمِهِ فَأَمَرَهُ أَنْ يُصَدِّقَهُمْ قَالَ فَبَعَثَنِي أَبِي فِي طَائِفَةٍ مِنْهُمْ فَأَتَيْتُ شَيْخًا كَبِيرًا يُقَالُ لَهُ سِعْرُ بْنُ دَيْسَمٍ فَقُلْتُ إِنَّ أَبِي بَعَثَنِي إِلَيْكَ يَعْنِي لِأُصَدِّقَكَ قَالَ ابْنُ أَخِي وَأَيَّ نَحْوٍ تَأْخُذُونَ قُلْتُ نَخْتَارُ حَتَّى إِنَّا نَتَبَيَّنَ ضُرُوعَ الْغَنَمِ قَالَ ابْنُ أَخِي فَإِنِّي أُحَدِّثُكَ أَنِّي كُنْتُ فِي شِعْبٍ مِنْ هَذِهِ الشِّعَابِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَنَمٍ لِي فَجَاءَنِي رَجُلَانِ عَلَى بَعِيرٍ فَقَالَا لِي إِنَّا رَسُولَا رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْكَ لِتُؤَدِّيَ صَدَقَةَ غَنَمِكَ فَقُلْتُ مَا ��َلَيَّ فِيهَا فَقَالَا شَاةٌ فَأَعْمَدُ إِلَى شَاةٍ قَدْ عَرَفْتُ مَكَانَهَا مُمْتَلِئَةٍ مَحْضًا وَشَحْمًا فَأَخْرَجْتُهَا إِلَيْهِمَا فَقَالَا هَذِهِ شَاةُ الشَّافِعِ وَقَدْ نَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَأْخُذَ شَافِعًا قُلْتُ فَأَيَّ شَيْءٍ تَأْخُذَانِ قَالَا عَنَاقًا جَذَعَةً أَوْ ثَنِيَّةً قَالَ فَأَعْمَدُ إِلَى عَنَاقٍ مُعْتَاطٍ وَالْمُعْتَاطُ الَّتِي لَمْ تَلِدْ وَلَدًا وَقَدْ حَانَ وِلَادُهَا فَأَخْرَجْتُهَا إِلَيْهِمَا فَقَالَا نَاوِلْنَاهَا فَجَعَلَاهَا مَعَهُمَا عَلَى بَعِيرِهِمَا ثُمَّ انْطَلَقَاقَالَ أَبُو دَاوُد رَوَاهُ أَبُو عَاصِمٍ عَنْ زَكَرِيَّاءَ قَالَ أَيْضًا مُسْلِمُ بْنُ شُعْبَةَ كَمَا قَالَ رَوْحٌ حَدَّثَنَا مُحَمَّدُ بْنُ يُونُسَ النَّسَائِيُّ حَدَّثَنَا رَوْحٌ حَدَّثَنَا زَكَرِيَّاءُ بْنُ إِسْحَقَ بِإِسْنَادِهِ بِهَذَا الْحَدِيثِ قَالَ مُسْلِمُ بْنُ شُعْبَةَ قَالَ فِيهِ وَالشَّافِعُ الَّتِي فِي بَطْنِهَا الْوَلَدُ","id":"Telah menceritakan kepada Kami [Al Hasan bin Ali], telah menceritakan kepada Kami [Waki'] dari [Zakariya bin Ishaq Al Makki] dari ['Amr bin Abu Sufyan Al Jumahi] dari [Muslim bin Tsafinah Al Yasykuri], [Al Hasan] berkata; [Rauh] berkata; [Muslim bin Syu'bah] berkata; Nafi' bin 'Alqamah mempekerjakan ayahku untuk melakukan urusan kaumnya, ia memerintahkannya agar mengambil zakat mereka. Muslim bin Syu'bah berkata; kemudian ayahku mengutusku pada sekelompok orang diantara mereka, kemudian aku datang kepada seseorang yang sudah tua yang dipanggil [Si'r bin Daisam], lalu aku katakan; sesungguhnya ayahku mengutusku untuk datang kepadamu yaitu agar aku mengambil zakatmu. Ia berkata; wahai anak saudaraku, semisal apakah kalian mengambilnya? Aku katakan; Kami akan memilih hingga Kami mengetahui kantong-kantong susu kambing. Ia berkata; wahai anak saudaraku, aku akan menceritakan kepadamu bahwa aku dahulu berada pada lembah diantara lembah-lembah ini pada zaman Rasulullah shallAllahu wa'alaihi wa sallam diantara kambing-kambingku, kemudian terdapat [dua orang laki-laki datang kepadaku dengan menunggang unta] dan berkata; sesungguhnya Kami adalah utusan Rasulullah shallallahu 'alaihi wasallam kepadamu agar engkau menunaikan zakat kambingmu. Kemudian aku katakan; apa yang harus aku tunaikan diantara kambing-kambingku? Kemudian mereka berkata; ini adalah kambing yang memiliki anak, dan Rasulullah shallAllahu wa'alaihi wa sallam telah melarang Kami untuk mengambil kambing yang memiliki anak. Aku katakan; apakah yang akan kalian ambil? Mereka berkata; kambing yang berumur empat tahun memasuki lima tahun atau yang berumur dua tahun memasuki tiga tahun. Si'r bin Daisam berkata; kemudian aku mengambil kambing yang berumur empat tahun yang mu'tath, mu'tath adalah yang belum melahirkan, dan telah datang waktunya melahirkan. Kemudian aku membawanya kepada mereka. Kemudian mereka berkata; berikan kepada Kami! Kemudian mereka membawanya bersama mereka di atas unta mereka, kemudian mereka pergi. Abu Daud berkata; [Abu 'Ashim] telah meriwayatkannya dari [Zakariya`], [Muslim bin Syu'bah] mengatakan pula sebagaimana yang dikatakan Rauh. Telah menceritakan kepada Kami [Muhammad bin Yunus An Nasai], telah menceritakan kepada Kami [Rauh], telah menceritakan kepada Kami [Zakariya` bin Ishaq] dengan sanadnya dengan hadits ini. [Muslim bin Syu'bah] berkata dalam hadits tersebut; dan syafi' adalah yang di dalam perutnya terdapat anak. "},"1299":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَنْصُورٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي بَكْرٍ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ سَعْدِ بْنِ زُرَارَةَ عَنْ عُمَارَةَ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَبَعَثَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُصَدِّقًا فَمَرَرْتُ بِرَجُلٍ فَلَمَّا جَمَعَ لِي مَالَهُ لَمْ أَجِدْ عَلَيْهِ فِيهِ إِلَّا ابْنَةَ مَخَاضٍ فَقُلْتُ لَهُ أَدِّ ابْنَةَ مَخَاضٍ فَإِنَّهَا صَدَقَتُكَ فَقَالَ ذَاكَ مَا لَا لَبَنَ فِيهِ وَلَا ظَهْرَ وَلَكِنْ هَذِهِ نَاقَةٌ فَتِيَّةٌ عَظِيمَةٌ سَمِينَةٌ فَخُذْهَا فَقُلْتُ لَهُ مَا أَنَا بِآخِذٍ مَا لَمْ أُومَرْ بِهِ وَهَذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْكَ قَرِيبٌ فَإِنْ أَحْبَبْتَ أَنْ تَأْتِيَهُ فَتَعْرِضَ عَلَيْهِ مَا عَرَضْتَ عَلَيَّ فَافْعَلْ فَإِنْ قَبِلَهُ مِنْكَ قَبِلْتُهُ وَإِنْ رَدَّهُ عَلَيْكَ رَدَدْتُهُ قَالَ فَإِنِّي فَاعِلٌ فَخَرَجَ مَعِي وَخَرَجَ بِالنَّاقَةِ الَّتِي عَرَضَ عَلَيَّ حَتَّى قَدِمْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ يَا نَبِيَّ اللَّهِ أَتَانِي رَسُولُكَ لِيَأْخُذَ مِنِّي صَدَقَةَ مَالِي وَايْمُ اللَّهِ مَا قَامَ فِي مَالِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا رَسُولُهُ قَطُّ قَبْلَهُ فَجَمَعْتُ لَهُ مَالِي فَزَعَمَ أَنَّ مَا عَلَيَّ فِيهِ ابْنَةُ مَخَاضٍ وَذَلِكَ مَا لَا لَبَنَ فِيهِ وَلَا ظَهْرَ وَقَدْ عَرَضْتُ عَلَيْهِ نَاقَةً فَتِيَّةً عَظِيمَةً لِيَأْخُذَهَا فَأَبَى عَلَيَّ وَهَا هِيَ ذِهْ قَدْ جِئْتُكَ بِهَا يَا رَسُولَ اللَّهِ خُذْهَا فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاكَ الَّذِي عَلَيْكَ فَإِنْ تَطَوَّعْتَ بِخَيْرٍ آجَرَكَ اللَّهُ فِيهِ وَقَبِلْنَاهُ مِنْكَ قَالَ فَهَا هِيَ ذِهْ يَا رَسُولَ اللَّهِ قَدْ جِئْتُكَ بِهَا فَخُذْهَا قَالَ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَبْضِهَا وَدَعَا لَهُ فِي مَالِهِ بِالْبَرَكَةِ","id":"Telah menceritakan kepada Kami [Muhammad bin Manshur], telah menceritakan kepada Kami [Ya'qub bin Ibrahim] Telah menceritakan kepada Kami [ayahku] dari [Ibnu Ishaq], ia berkata; telah menceritakan kepadaku [Abdullah bin Abu Bakr] dari [Yahya bin Abdullah bin Abdurrahman bin Sa'd bin Zurarah] dari ['Umarah bin 'Amr bin Hazm] dari [Ubai bin Ka'b], ia berkata; Nabi shallallahu 'alaihi wasallam telah mengutusku sebagai petugas pengambil zakat, kemudian aku melewati seseorang, tatkala ia telah mengumpulkan hartanya maka aku tidak mendapatkan ia memiliki kewajiban padanya, kecuali satu ekor bintu makhadh (yang berumur satu tahun), kemudian aku katakan kepadanya; berikan bintu makhadh, sesungguhnya itulah zakatmu. Ia berkata; itu tidak memiliki susu, dan tidak dapat ditunggangi. Akan tetapi ini, ini adalah unta muda yang besar dan gemuk. Ambillah unta tersebut. Kemudian aku katakan kepadanya; aku tidak akan mengambilnya, selama aku tidak diperintahkan untuk mengambilnya. Ini, Rasulullah shallAllahu wa'alaihi wa sallam dekat, apabila engkau ingin datang kepada beliau dan menawarkan kepada beliau apa yang telah engkau tawarkan kepadaku maka lakukanlah. Apabila beliau menerimanya maka aku menerimanya dan apabila beliau menolaknya maka aku menolaknya. Ia berkata; aku akan lakukan. Kemudian ia keluar bersamaku, ia keluar dengan membawa unta yang telah ditawarkan kepadaku hingga Kami sampai kepada Rasulullah shallAllahu wa'alaihi wa sallam. Kemudian ia berkata; wahai Nabi Allah, utusanmu telah datang kepadaku untuk mengambil zakat harta dariku. Demi Allah, Rasulullah dan utusannya tidak mengambil hartaku sama sekali sebelumnya, kemudian saya kumpulkan hartaku untuknya, dan ia mengaku bahwa yang harus saya berikan adalah bintu makhadh, dan itu tidak memiliki susu dan tidak dapat dinaiki. Saya menawarkan kepadanya unta muda yang besar agar ia mengambilnya. Kemudian ia menolak. Dan inilah unta tersebut, saya telah membawanya kepada anda wahai Rasulullah, ambillah. Kemudian Rasulullah shallAllahu wa'alaihi wa sallam berkata kepadanya: \"Itu adalah yang menjadi kewajibanmu, kemudian apabila engkau merelakan untuk memberikan yang terbaik maka Allah akan memberimu pahala karenanya, dan Kami menerimanya darimu.\" Ia berkata; ini unta tersebut wahai Rasulullah, aku telah membawanya kepada anda, ambillah. Ubai berkata; kemudian Rasulullah shallAllahu wa'alaihi wa sallam memerintahkan untuk menerimanya dan mendoakan untuknya agar hartanya berkah. "},"1300":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا زَكَرِيَّا بْنُ إِسْحَقَ الْمَكِّيُّ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ صَيْفِيٍّ عَنْ أَبِي مَعْبَدٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ مُعَاذًا إِلَى الْيَمَنِ فَقَالَ إِنَّكَ تَأْتِي قَوْمًا أَهْلَ كِتَابٍ فَادْعُهُمْ إِلَى شَهَادَةِ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ فَإِنْ هُمْ أَطَاعُوكَ لِذَلِكَ فَأَعْلِمْهُمْ أَنَّ اللَّهَ افْتَرَضَ عَلَيْهِمْ خَمْسَ صَلَوَاتٍ فِي كُلِّ يَوْمٍ وَلَيْلَةٍ فَإِنْ هُمْ أَطَاعُوكَ لِذَلِكَ فَأَعْلِمْهُمْ أَنَّ اللَّهَ افْتَرَضَ عَلَيْهِمْ صَدَقَةً فِي أَمْوَالِهِمْ تُؤْخَذُ مِنْ أَغْنِيَائِهِمْ وَتُرَدُّ عَلَى فُقَرَائِهِمْ فَإِنْ هُمْ أَطَاعُوكَ لِذَلِكَ فَإِيَّاكَ وَكَرَائِمَ أَمْوَالِهِمْ وَاتَّقِ دَعْوَةَ الْمَظْلُومِ فَإِنَّهَا لَيْسَ بَيْنَهَا وَبَيْنَ اللَّهِ حِجَابٌ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal] telah menceritakan kepada Kami [Waki'], telah menceritakan kepada Kami [Zakariya bin Ishaq Al Makki] dari [Yahya bin Abdullah bin Shaifi] dari [Abu Ma'bad] dari [Ibnu Abbas] bahwa Rasulullah shallAllahu wa'alaihi wa sallam mengutus Mu'adz ke Yaman, kemudian beliau mengatakan: \"Sesungguhnya engkau akan mendatangi suatu kaum dari ahli kitab, maka ajaklah mereka untuk bersaksi bahwa tidak ada tuhan kecuali Allah dan aku adalah Rasulullah, kemudian apabila mereka mentaatimu untuk itu maka beritahukan kepada mereka bahwa Allah telah mewajibkan atas mereka melakukan shalat lima waktu dalam sehari semalam, kemudian apabila mereka mentaatimu untuk itu maka beritahukan kepda mereka bahwa Allah telah mewajibkan atas mereka sedekah pada harta mereka yang diambil dari orang-orang kaya mereka dan dikembalikan kepada orang-orang miskin mereka, kemudian apabila mereka mentaatimu untuk itu maka jauhilah harta-harta mereka yang berharga, dan berhati-hatilah terhadap doa orang yang dizhalimi, sesungguhnya tidak ada penghalang antara doa tersebut dengan Allah.\""},"1301":{"ar":"حَدَّثَنَا مَهْدِيُّ بْنُ حَفْصٍ وَمُحَمَّدُ بْنُ عُبَيْدٍ الْمَعْنَى قَالَا حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ رَجُلٍ يُقَالُ لَهُ دَيْسَمٌ وَقَالَ ابْنُ عُبَيْدٍ مِنْ بَنِي سَدُوسٍ عَنْ بَشِيرِ ابْنِ الْخَصَاصِيَّةِ قَالَ ابْنُ عُبَيْدٍ فِي حَدِيثِهِ وَمَا كَانَ اسْمُهُ بَشِيرًا وَلَكِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمَّاهُ بَشِيرًاقَالَ قُلْنَا إِنَّ أَهْلَ الصَّدَقَةِ يَعْتَدُونَ عَلَيْنَا أَفَنَكْتُمُ مِنْ أَمْوَالِنَا بِقَدْرِ مَا يَعْتَدُونَ عَلَيْنَا فَقَالَ لَاحَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ وَيَحْيَى بْنُ مُوسَى قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ أَيُّوبَ بِإِسْنَادِهِ وَمَعْنَاهُ إِلَّا أَنَّهُ قَالَ قُلْنَا يَا رَسُولَ اللَّهِ إِنَّ أَصْحَابَ الصَّدَقَةِ يَعْتَدُونَ قَالَ أَبُو دَاوُد رَفَعَهُ عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ","id":"Telah menceritakan kepada Kami [Mahdi bin Hafsh] dan [Muhammad bin 'Ubaid] secara makna, mereka mengatakan; telah menceritakan kepada Kami [Hammad] dari [Ayyub] dari [seseorang yang dipanggil Daisam]. [Ibnu'Ubaid] berkata; ia berasal dari Bani Sadus, dari [Basyir bin Al Khashashiyyah], [Ibnu 'Ubaid] berkata dalam haditsnya; namanya bukanlah Basyir, akan tetapi Rasulullah shallAllahu wa'alaihi wa sallam menamakannya Basyir. Ia berkata; sesungguhnya para para ahli zakat telah bertindak lalim kepada Kami, apakah boleh Kami menyembunyikan sebagian harta Kami sesuai dengan kelaliman yang mereka lakukan kepada Kami? Maka beliau berkata: \"Tidak.\" Telah menceritakan kepada Kami [Al Hasan bin Ali] dan [Yahya bin Musa], mereka mengatakan; telah menceritakan kepada Kami [Abdurrazzaq] dari [Ma'mar] dari [Ayyub] dengan sanad dan maknanya, hanya saja ia mengatakan; Kami katakan; wahai rasul, sesungguhnya para pemberi zakat berlaku lalim. Abu Daud berkata; Abdurrazzaq telah merafa'kannya menyandarkan perkataan kepada Rasulullah shallAllahu wa'alaihi wa sallam dari Ma'mar."},"1302":{"ar":"حَدَّثَنَا عَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا بِشْرُ بْنُ عُمَرَ عَنْ أَبِي الْغُصْنِ عَنْ صَخْرِ بْنِ إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جَابِرِ بْنِ عَتِيكٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَيَأْتِيكُمْ رُكَيْبٌ مُبْغَضُونَ فَإِنْ جَاءُوكُمْ فَرَحِّبُوا بِهِمْ وَخَلُّوا بَيْنَهُمْ وَبَيْنَ مَا يَبْتَغُونَ فَإِنْ عَدَلُوا فَلِأَنْفُسِهِمْ وَإِنْ ظَلَمُوا فَعَلَيْهَا وَأَرْضُوهُمْ فَإِنَّ تَمَامَ زَكَاتِكُمْ رِضَاهُمْ وَلْيَدْعُوا لَكُمْقَالَ أَبُو دَاوُد أَبُو الْغُصْنِ هُوَ ثَابِتُ بْنُ قَيْسِ بْنِ غُصْنٍ","id":"Telah menceritakan kepada Kami [Abbas bin 'Abdul 'Azhim] dan [Muhammad bin Al Mutsanna], mereka berkata; telah menceritakan kepada Kami [Bisyr bin Umar] dari [Abu Al Ghushn] dari [Shakhr bin Ishaq] dari [Abdurrahman bin Jabir bin 'Atik] dari [ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: akan datang kepada kalian para petugas pengambil zakat, jika mereka sudah datang kepada kalian, maka sambutlah mereka dan biarkanlah mereka mengambil apa yang mereka inginkan, jika mereka berbuat adil maka itu adalah kebaikan buat kalian dan jika mereka berbuat dzalim maka dosanya bagi mereka, buatlah mereka ridha, sebab kesempurnaan zakat kalian pada keridhaan mereka, dan hendaklah mereka mendo'akan kalian. Abu Daud berkata; Abu Al Ghushn adalah Tsabit bin Qais bin Ghushn. "},"1303":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ يَعْنِي ابْنَ زِيَادٍ ح و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ وَهَذَا حَدِيثُ أَبِي كَامِلٍ عَنْ مُحَمَّدِ بْنِ أَبِي إِسْمَعِيلَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ هِلَالٍ الْعَبْسِيُّ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَجَاءَ نَاسٌ يَعْنِي مِنْ الْأَعْرَابِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا إِنَّ نَاسًا مِنْ الْمُصَدِّقِينَ يَأْتُونَا فَيَظْلِمُونَا قَالَ فَقَالَ أَرْضُوا مُصَدِّقِيكُمْ قَالُوا يَا رَسُولَ اللَّهِ وَإِنْ ظَلَمُونَا قَالَ أَرْضُوا مُصَدِّقِيكُمْ زَادَ عُثْمَانُ وَإِنْ ظُلِمْتُمْقَالَ أَبُو كَامِلٍ فِي حَدِيثِهِ قَالَ جَرِيرٌ مَا صَدَرَ عَنِّي مُصَدِّقٌ بَعْدَ مَا سَمِعْتُ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا وَهُوَ عَنِّي رَاضٍ","id":"Telah menceritakan kepada Kami [Abu Kamil] telah menceritakan kepada Kami [Abdul Wahid] yaitu Ibnu Ziyad. Dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Abdurrahim bin Sulaiman] dan ini adalah hadits Abu Kamil, dari [Muhammad bin Abu Isma'il] telah menceritakan kepada kami [Abdurrahman bin Hilal Al 'Absi] dari [Jarir bin Abdullah], ia berkata; telah datang beberapa orang yaitu dari kalangan badui kepada Rasulullah shallAllahu wa'alaihi wa sallam dan berkata; sesungguhnya beberapa orang petugas pengambil zakat datang kepada Kami dan berbuat zhalim kepada Kami. Jarir berkata; kemudian beliau berkata; \"Buatlah para petugas zakat kalian ridha.\" Mereka berkata; wahai Rasulullah, walaupun mereka berbuat zhalim kepada Kami? Beliau berkata: \"Buatlah para petugas tersebut zakat kalian ridha.\" Utsman menambahkan; walaupun kalian dizhalimi. Abu Kamil berkata dalam haditsnya; Jarir berkata; tidaklah seorangpun petugas zakat pergi dariku setelah aku mendengar hal ini dari Rasulullah shallAllahu wa'alaihi wa sallam melainkan ia ridha kepadaku. "},"1304":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ النَّمَرِيُّ وَأَبُو الْوَلِيدِ الطَّيَالِسِيُّ الْمَعْنَى قَالَا حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى قَالَكَانَ أَبِي مِنْ أَصْحَابِ الشَّجَرَةِ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَتَاهُ قَوْمٌ بِصَدَقَتِهِمْ قَالَ اللَّهُمَّ صَلِّ عَلَى آلِ فُلَانٍ قَالَ فَأَتَاهُ أَبِي بِصَدَقَتِهِ فَقَالَ اللَّهُمَّ صَلِّ عَلَى آلِ أَبِي أَوْفَى","id":"Telah menceritakan kepada Kami [Hafsh bin Umar An Namari] dan [Abu Al Walid Ath Thayalisi] secara makna, mereka berkata; telah menceritakan kepada Kami [Syu'bah] dari ['Amr bin Murrah] dari [Abdullah bin Abu Aufa], ia berkata; ayahku termasuk orang-orang yang melakukan bai'at Ridhwan di bawah pohon, dan Nabi shallallahu 'alaihi wasallam apabila terdapat beberapa orang yang datang kepada beliau membawa zakat mereka maka beliau mengucapkan; ya Allah, sampaikan shalawat kepada keluarga fulan. Abdullah bin Abu Aufa berkata; kemudian ayahku datang kepada beliau dengan membawa zakatnya. Kemudian beliau berdoa: \"Ya Allah, sampaikan shalawat kepada keluarta Abu Aufa.\""},"1305":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ ابْنِ إِسْحَقَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا جَلَبَ وَلَا جَنَبَ وَلَا تُؤْخَذُ صَدَقَاتُهُمْ إِلَّا فِي دُورِهِمْحَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ سَمِعْتُ أَبِي يَقُولُ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ فِي قَوْلِهِ لَا جَلَبَ وَلَا جَنَبَ قَالَ أَنْ تُصَدَّقَ الْمَاشِيَةُ فِي مَوَاضِعِهَا وَلَا تُجْلَبَ إِلَى الْمُصَدِّقِ وَالْجَنَبُ عَنْ غَيْرِ هَذِهِ الْفَرِيضَةِ أَيْضًا لَا يُجْنَبُ أَصْحَابُهَا يَقُولُ وَلَا يَكُونُ الرَّجُلُ بِأَقْصَى مَوَاضِعِ أَصْحَابِ الصَّدَقَةِ فَتُجْنَبُ إِلَيْهِ وَلَكِنْ تُؤْخَذُ فِي مَوْضِعِهِ","id":"Telah menceritakan kepada Kami [Qutaibah bin Sa'id], telah menceritakan kepada Kami [Ibnu Abu 'Adi] dari [Ibnu Ishaq] dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya] dari Nabi shallallahu 'alaihi wasallam beliau bersabda; \"Tidak ada jalab dan janab dan tidaklah zakat mereka diambil kecuali di rumah-rumah mereka.\" Telah menceritakan kepada Kami Al Hasan bin Ali, telah menceritakan kepada Kami Ya'qub bin Ibrahim, ia berkata; saya mendengar ayahku berkata; dari Muhammad bin Ishaq mengenai sabda beliau: \"Tidak ada jalab dan tidak ada janab, \" ia berkata; yaitu hewan ternak dizakatkan di tempat-tempatnya, dan tidak dibawa kepada petugas zakat, sedangkan janab mengenai selain kewajiban ini, juga para pemilik zakat tidak diperlakukan janab kepadanya. Ia mengatakan; seseorang (petugas zakat) tidak berada di tempat terjauh orang yang menunaikan zakat kemudian zakat tersebut dibawa kepadanya, akan tetapi hendaknya zakat tersebut diambil di tempatnya."},"1306":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ حَمَلَ عَلَى فَرَسٍ فِي سَبِيلِ اللَّهِ فَوَجَدَهُ يُبَاعُ فَأَرَادَ أَنْ يَبْتَاعَهُ فَسَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَقَالَ لَا تَبْتَعْهُ وَلَا تَعُدْ فِي صَدَقَتِكَ","id":"Telah menceritakan kepada Kami [Abdullah bin Maslamah] dari [Malik] dari [Nafi'] dari [Abdullah bin Umar] bahwa Umar bin Al Khathab radliallahu 'anhu telah mewakafkan kuda di jalan Allah, kemudian ia melihat kuda tersebut dijual, kemudian ia ingin membelinya. Lalu ia bertanya kepada Rasulullah shallAllahu wa'alaihi wa sallam mengenai hal tersebut, kemudian beliau bersabda: \"Jangan engkau beli, dan janganlah engkau mengambil kembali sedekahmu.\""},"1307":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ يَحْيَى بْنِ فَيَّاضٍ قَالَا حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ رَجُلٍ عَنْ مَكْحُولٍ عَنْ عِرَاكِ بْنِ مَالِكٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ فِي الْخَيْلِ وَالرَّقِيقِ زَكَاةٌ إِلَّا زَكَاةُ الْفِطْرِ فِي الرَّقِيقِ","id":"Telah menceritakan kepada Kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Yahya bin Fayyadh], mereka berkata; telah menceritakan kepada Kami [Abdul Wahhab], telah menceritakan kepada Kami ['Ubaidullah] dari [seorang laki-laki] dari [Makhul] dari ['Irak bin Malik] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada zakat pada kuda, dan budak, kecuali zakat fithrah pada budak.\""},"1308":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عِرَاكِ بْنِ مَالِكٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ عَلَى الْمُسْلِمِ فِي عَبْدِهِ وَلَا فِي فَرَسِهِ صَدَقَةٌ","id":"Telah menceritakan kepada Kami [Abdullah bin Maslamah], telah menceritakan kepada Kami [Malik] dari [Abdullah bin Dinar] dari [Sulaiman bin Yasar] dari ['Irak bin Malik] dari [Abu Hurairah] bahwa Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"seorang muslim tidak memiliki kewajiban zakat pada budak dan kudanya.\""},"1309":{"ar":"حَدَّثَنَا هَارُونُ بْنُ سَعِيدِ بْنِ الْهَيْثَمِ الْأَيْلِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ بْنُ يَزِيدَ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا سَقَتْ السَّمَاءُ وَالْأَنْهَارُ وَالْعُيُونُ أَوْ كَانَ بَعْلًا الْعُشْرُ وَفِيمَا سُقِيَ بِالسَّوَانِي أَوْ النَّضْحِ نِصْفُ الْعُشْرِ","id":"Telah menceritakan kepada Kami [Harun bin Sa'id bin Al Haitsam Al Aili], telah menceritakan kepada Kami [Abdullah bin Wahb], telah mengabarkan kepadaku [Yunus bin Yazid] dari [Ibnu Syihab] dari [Salim bin Abdullah] dari [ayahnya], ia berkata; Rasulullah shallla Allahu 'alaihi wa sallam bersabda: \"Pertanian yang diairi hujan, sungai dan mata air atau dibiarkan begitu saja maka zakatnya adalah sepersepuluh, dan pertanian yang diairi dengan menggunakan alat pengairan atau dengan ember maka zakatnya seperdua puluh.\""},"1310":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِيمَا سَقَتْ الْأَنْهَارُ وَالْعُيُونُ الْعُشْرُ وَمَا سُقِيَ بِالسَّوَانِي فَفِيهِ نِصْفُ الْعُشْرِ","id":"Telah menceritakan kepada Kami [Ahmad bin Shalih], telah menceritakan kepada Kami [Abdullah bin Wahb] telah mengabarkan kepadaku ['Amr], dari [Abu Az Zubair] dari [Jabir bin Abdullah] bahwa Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Pertanian yang diairi sungai dan mata air zakatnya adalah sepersepuluh, dan yang diairi menggunakan alat pengairan maka zakatnya adalah seperdua puluh.\""},"1311":{"ar":"حَدَّثَنَا الْهَيْثَمُ بْنُ خَالِدٍ الْجُهَنِيُّ وَحُسَيْنُ بْنُ الْأَسْوَدِ الْعَجَلِيُّ قَالَا قَالَ وَكِيعٌالْبَعْلُ الْكَبُوسُ الَّذِي يَنْبُتُ مِنْ مَاءِ السَّمَاءِقَالَ ابْنُ الْأَسْوَدِ وَقَالَ يَحْيَى يَعْنِي ابْنَ آدَمَ سَأَلْتُ أَبَا إِيَاسٍ الْأَسَدِيَّ عَنْ الْبَعْلِ فَقَالَ الَّذِي يُسْقَى بِمَاءِ السَّمَاءِ و قَالَ النَّضْرُ بْنُ شُمَيْلٍ الْبَعْلُ مَاءُ الْمَطَرِ","id":"Telah menceritakan kepada Kami [Al Haitsam bin Khalid Al Juahani] serta [Husain bin Al Aswad Al 'Ajali], ia berkata; [Waki'] berkata; Al Ba'lu dan Al Kabus adalah tanaman yang tumbuh dari air hujan. [Ibnu Al Aswad] berkata; dan [Yahya yaitu Ibnu Adam] berkata; aku bertanya kepada [Abu Iyaz Al Asadi] mengenai Al Ba'lu, kemudian ia berkata; yaitu yang disirami dengan air hujan. An Nadhr bin Syumail berkata; Al Ba'lu adalah air hujan."},"1312":{"ar":"حَدَّثَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ سُلَيْمَانَ يَعْنِي ابْنَ بِلَالٍ عَنْ شَرِيكِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي نَمِرٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ مُعَاذِ بْنِ جَبَلٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَهُ إِلَى الْيَمَنِ فَقَالَ خُذْ الْحَبَّ مِنْ الْحَبِّ وَالشَّاةَ مِنْ الْغَنَمِ وَالْبَعِيرَ مِنْ الْإِبِلِ وَالْبَقَرَةَ مِنْ الْبَقَرِقَالَ أَبُو دَاوُد شَبَرْتُ قِثَّاءَةً بِمِصْرَ ثَلَاثَةَ عَشَرَ شِبْرًا وَرَأَيْتُ أُتْرُجَّةً عَلَى بَعِيرٍ بِقِطْعَتَيْنِ قُطِّعَتْ وَصُيِّرَتْ عَلَى مِثْلِ عِدْلَيْنِ","id":"Telah menceritakan kepada Kami [Ar Rabi' bin Sulaiman] telah menceritakan kepada Kami [Ibnu Wahb] dari [Sulaiman yaitu Ibnu Bilal] dari [Syarik bin Abdullah bin Abu Namir] dari ['Atho` bin Yasar] dari [Muadz bin Jabal] bahwa Rasulullah shallallahu 'alaihi wasallam mengutusnya ke Yaman dan berkata: \"Ambillah biji-bijian dari biji-bijian, kambing dari domba, unta dari unta, dan sapi dari sapi.\" Abu Daud berkata: aku mengukur mentimun di Mesir mencapai tiga belas jengkal, dan aku melihat dua potong buah limau (sejenis jeruk nipis) yang telah dipotong diatas unta dan ditempatkan pada tempat seperti dua kantong. "},"1313":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي شُعَيْبٍ الْحَرَّانِيُّ حَدَّثَنَا مُوسَى بْنُ أَعْيَنَ عَنْ عَمْرِو بْنِ الْحَارِثِ الْمِصْرِيِّ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَجَاءَ هِلَالٌ أَحَدُ بَنِي مُتْعَانَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعُشُورِ نَحْلٍ لَهُ وَكَانَ سَأَلَهُ أَنْ يَحْمِيَ لَهُ وَادِيًا يُقَالُ لَهُ سَلَبَةُ فَحَمَى لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَلِكَ الْوَادِي فَلَمَّا وُلِّيَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ كَتَبَ سُفْيَانُ بْنُ وَهْبٍ إِلَى عُمَرَ بْنِ الْخَطَّابِ يَسْأَلُهُ عَنْ ذَلِكَ فَكَتَبَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ إِنْ أَدَّى إِلَيْكَ مَا كَانَ يُؤَدِّي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عُشُورِ نَحْلِهِ فَاحْمِ لَهُ سَلَبَةَ وَإِلَّا فَإِنَّمَا هُوَ ذُبَابُ غَيْثٍ يَأْكُلُهُ مَنْ يَشَاءُحَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ حَدَّثَنَا الْمُغِيرَةُ وَنَسَبَهُ إِلَى عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ الْمَخْزُومِيِّ قَالَ حَدَّثَنِي أَبِي عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّ شَبَابَةَ بَطْنٌ مِنْ فَهْمٍ فَذَكَرَ نَحْوَهُ قَالَ مِنْ كُلِّ عَشْرِ قِرَبٍ قِرْبَةٌ وَقَالَ سُفْيَانُ بْنُ عَبْدِ اللَّهِ الثَّقَفِيُّ قَالَ وَكَانَ يَحْمِي لَهُمْ وَادِيَيْنِ زَادَ فَأَدَّوْا إِلَيْهِ مَا كَانُوا يُؤَدُّونَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَمَى لَهُمْ وَادِيَيْهِمْ حَدَّثَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ الْمُؤَذِّنُ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي أُسَامَةُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّ بَطْنًا مِنْ فَهْمٍ بِمَعْنَى الْمُغِيرَةِ قَالَ مِنْ عَشْرِ قِرَبٍ قِرْبَةٌ وَقَالَ وَادِيَيْنِ لَهُمْ","id":"Telah menceritakan kepada Kami [Ahmad bin Abu Syu'aib Al Harrani], telah menceritakan kepada Kami [Musa bin A'yan] dari ['Amr bin Al Harits Al Mishri] dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya], ia berkata: Hilal salah seorang dari Bani Mut'an datang kepada Rasulullah shallallahu 'alaihi wasallam dengan membawa sepersepuluh dari hasil madunya, ia pernah meminta Rasulullah shallla Allahu 'alaihi wa sallam agar melindungi bukitnya yang bernama Salabah, dan Rasulullah shallla Allahu 'alaihi wa sallam pun melindunginya. Dan ketika Umar ditunjuk menjadi khalifah, Sufyan bin Wahb bertanya mengenai hal itu, kemudian Umar radliallahu 'anhu menulis surat kepadanya; jika dia menunaikan zakatnya kepada kalian sebagaimana yang telah dia berikan kepada Rasulullah shallla Allahu 'alaihi wa sallam, maka lindungilah bukit Salabahnya, jika tidak, maka sesungguhnya madu itu adalah terambil dari lebah hujan yang dapat dimakan oleh siapapun yang menghendakinya. Telah menceritakan kepada Kami [Ahmad bin Abdah Adh Dhabbi], telah menceritakan kepada Kami [Al Mughirah] dan ia menisbatkannya kepada Abdurrahman bin Al Harits Al Makhzumi, ia berkata; telah menceritakan kepada Kami [ayahku] dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya] bahwa Syababah pertengahan daerah Fahm ….. kemudian ia menyebutkan seperti itu. Ia berkata; dari setiap sepuluh griba terdapat zakat satu geriba. Sufyan bin Abdullah Ats Tsaqafi berkata; \"Umar melindungi dua bukit mereka. Ia menambahkan; dan mereka memberikan kepadanya apa yang dahulu mereka berikan kepada Rasulullah shallallahu 'alaihi wasallam, dan ia melindungi melindungi dua bukit mereka. Telah menceritakan kepada Kami [Ar Rabi' bin Sulaiman Al Muadzin], telah menceritakan kepada Kami [Ibnu Wahb], telah menceritakan kepada Kami [Usamah bin Zaid] dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya] bahwa suatu daerah di tengah kota …. Fahm dengan makna yang dikatakan Mughirah yaitu \"dari setiap sepuluh geriba terdapat zakat satu geriba. Dan ia berkata; mereka memiliki dua bukit."},"1314":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ السَّرِيِّ النَّاقِطُ حَدَّثَنَا بِشْرُ بْنُ مَنْصُورٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ عَتَّابِ بْنِ أَسِيدٍ قَالَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُخْرَصَ الْعِنَبُ كَمَا يُخْرَصُ النَّخْلُ وَتُؤْخَذُ زَكَاتُهُ زَبِيبًا كَمَا تُؤْخَذُ زَكَاةُ النَّخْلِ تَمْرًاحَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ الْمُسَيَّبِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نَافِعٍ عَنْ مُحَمَّدِ بْنِ صَالِحٍ التَّمَّارِ عَنْ ابْنِ شِهَابٍ بِإِسْنَادِهِ وَمَعْنَاهُ قَالَ أَبُو دَاوُد سَعِيدٌ لَمْ يَسْمَعْ مِنْ عَتَّابٍ شَيْئًا","id":"Telah menceritakan kepada Kami [Abdul Aziz bin As Sari An Naqith], telah menceritakan kepada Kami [Bisyr bin Manshur] dari [Abdurrahman bin Ishaq] dari [Az Zuhri] dari [Sa'id? bin Al Musayyab] dari ['Attab bin Usaid], ia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk memperkirakan jumlah anggur sebagaimana memperkirakan jumlah kurma dan diambil zakatnya dalam bentuk kismis sebagaimana pohon kurma diambil zakatnya dalam bentuk kurma. Telah menceritakan kepada Kami [Muhammad bin Ishak Al Musayyabi], telah menceritakan kepada Kami [Abdullah bin Nafi'] dari [Muhammad bin Sholih At Tammar] dari [Ibnu Syihab] dengan sanad dan maknanya. Abu daud berkata Sa'id tidak mendengar dari 'Atab sedikit pun. "},"1315":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مَسْعُودٍ قَالَجَاءَ سَهْلُ بْنُ أَبِي حَثْمَةَ إِلَى مَجْلِسِنَا قَالَ أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا خَرَصْتُمْ فَجُذُّوا وَدَعُوا الثُّلُثَ فَإِنْ لَمْ تَدَعُوا أَوْ تَجُذُّوا الثُّلُثَ فَدَعُوا الرُّبْعَقَالَ أَبُو دَاوُد الْخَارِصُ يَدَعُ الثُّلُثَ لِلْحِرْفَةِ","id":"Telah menceritakan kepada Kami [Hafsh bin Umar], telah menceritakan kepada Kami [Syu'bah] dari [Khubaib bin Abdurrahman] dari [Abdurrahman bin Mas'ud], ia berkata; [Sahl bin Abu Hatsmah] telah datang ke majelis Kami, ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam telah memerintahkan Kami, beliau bersabda: \"Apabila kalian telah memperkirakan buah yang ada di pohon maka potonglah dan biarkan sepertiganya, apabila kalian tidak membiarkan atau tidak memotong sepertiga maka tinggalkan seperempat.\" Abu Daud berkata; orang yang memperkirakan meninggalkan sepertiga untuk pekerjaan. "},"1316":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مَعِينٍ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ أُخْبِرْتُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةِ رَضِيَ اللَّهُ عَنْهَا أَنَّهَا قَالَتْ وَهِيَ تَذْكُرُ شَأْنَ خَيْبَرَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَبْعَثُ عَبْدَ اللَّهِ بْنَ رَوَاحَةَ إِلَى يَهُودَ فَيَخْرُصُ النَّخْلَ حِينَ يَطِيبُ قَبْلَ أَنْ يُؤْكَلَ مِنْهُ","id":"Telah menceritakan kepada Kami [Yahya bin Ma'in] telah menceritakan kepada Kami [Hajjaj] dari [Ibnu Juraij], ia berkata; aku diberi kabar dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah] radliallahu 'anha bahwa ia menyebutkan perkara Khaibar dan berkata; Nabi shallallahu 'alaihi wasallam mengutus Abdullah bin Rawahah kepada orang-orang Yahudi, kemudian ia memperkirakan kurma yang ada dipohon, ketika telah matang sebelum dimakan sebagian darinya. "},"1317":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ حَدَّثَنَا عَبَّادٌ عَنْ سُفْيَانَ بْنِ حُسَيْنٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلٍ عَنْ أَبِيهِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْجُعْرُورِ وَلَوْنِ الْحُبَيْقِ أَنْ يُؤْخَذَا فِي الصَّدَقَةِقَالَ الزُّهْرِيُّ لَوْنَيْنِ مِنْ تَمْرِ الْمَدِينَةِ قَالَ أَبُو دَاوُد وَأَسْنَدَهُ أَيْضًا أَبُو الْوَلِيدِ عَنْ سُلَيْمَانَ بْنِ كَثِيرٍ عَنْ الزُّهْرِيِّ","id":"Telah menceritakan kepada Kami [Muhammad bin Yahya bin Faris], telah menceritakan kepada Kami [Sa'id? bin Sulaiman], telah menceritakan kepada Kami ['Abbad] dari [Sufyan bin Husain] dari [Az Zuhri] dari [Abu Umamah bin Sahl] dari [ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang untuk mengambil Ju'rur dan Launu Al Hubaiki (keduanya adalah jenis kurma yang jelek) untuk zakat. Az Zuhri berkata: itu adalah dua macam kurma madinah. Abu Daud berkata: [Abu Al Walid] juga menyebutkan sanad hadits tersebut dari [Sulaiman bin Katsir] dari [Az Zuhri]."},"1318":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَاصِمٍ الْأَنْطَاكِيُّ حَدَّثَنَا يَحْيَى يَعْنِي الْقَطَّانَ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ حَدَّثَنِي صَالِحُ بْنُ أَبِي عَرِيبٍ عَنْ كَثِيرِ بْنِ مُرَّةَ عَنْ عَوْفِ بْنِ مَالِكٍ قَالَدَخَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسْجِدَ وَبِيَدِهِ عَصَا وَقَدْ عَلَّقَ رَجُلٌ قَنَا حَشَفًا فَطَعَنَ بِالْعَصَا فِي ذَلِكَ الْقِنْوِ وَقَالَ لَوْ شَاءَ رَبُّ هَذِهِ الصَّدَقَةِ تَصَدَّقَ بِأَطْيَبَ مِنْهَا وَقَالَ إِنَّ رَبَّ هَذِهِ الصَّدَقَةِ يَأْكُلُ الْحَشَفَ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada Kami [Nashr bin 'Ashim Al Anthaki], telah menceritakan kepada Kami [Yahya yaitu Al Qaththan] dari [Abdul Hamid bin Ja'far], telah menceritakan kepadaku [Shalih bin Abu 'Arib] dari [Katsir bin Murrah] dari ['Aur bin Malik], ia berkata; Rasulullah shallallahu 'alaihi wasallam menemui Kami di masjid dengan membawa tongkat ditangannya, sementara seseorang telah menggantungkan kurma basah yang rusak, kemudian beliau menusuk tandan tersebut dengan tongkat dan berkata: \"Kalau pemilik sedekah ini hendak bersedekah maka ia bersedekah dengan kurma yang lebih baik darinya.\" Dan beliau bersabda: \"Sesungguhnya pemilik sedekah ini akan makan kurma basah dan rusak di Hari Kiamat.\""},"1319":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ الدِّمَشْقِيُّ وَعَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ السَّمْرَقَنْدِيُّ قَالَا حَدَّثَنَا مَرْوَانُ قَالَ عَبْدُ اللَّهِ حَدَّثَنَا أَبُو يَزِيدَ الْخَوْلَانِيُّ وَكَانَ شَيْخَ صِدْقٍ وَكَانَ ابْنُ وَهْبٍ يَرْوِي عَنْهُ حَدَّثَنَا سَيَّارُ بْنُ عَبْدِ الرَّحْمَنِ قَالَ مَحْمُودٌ الصَّدَفِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَفَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَكَاةَ الْفِطْرِ طُهْرَةً لِلصَّائِمِ مِنْ اللَّغْوِ وَالرَّفَثِ وَطُعْمَةً لِلْمَسَاكِينِ مَنْ أَدَّاهَا قَبْلَ الصَّلَاةِ فَهِيَ زَكَاةٌ مَقْبُولَةٌ وَمَنْ أَدَّاهَا بَعْدَ الصَّلَاةِ فَهِيَ صَدَقَةٌ مِنْ الصَّدَقَاتِ","id":"Telah menceritakan kepada Kami [Mahmud bin Khalid Ad Dimasyqi] dan [Abdullah bin Abdurrahman As Samarqandi] berkata; telah menceritakan kepada Kami [Marwan], Abdullah berkata; telah menceritakan kepada Kami [Abu Yazid Al Khaulani] ia adalah syekh yang jujur, dan Ibnu Wahb telah meriwayatkan darinya, telah menceritakan kepada Kami [Sayyar bin Abdurrahman], Mahmud Ash Shadafi berkata; dari [Ikrimah] dari [Ibnu Abbas], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam mewajibkan zakat fitrah untuk mensucikan orang yang berpuasa dari bersenda gurau dan kata-kata keji, dan juga untuk memberi makan miskin. Barangsiapa yang menunaikannya sebelum shalat maka zakatnya diterima dan barangsiapa yang menunaikannya setelah shalat maka itu hanya sedekah diantara berbagai sedekah."},"1320":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِزَكَاةِ الْفِطْرِ أَنْ تُؤَدَّى قَبْلَ خُرُوجِ النَّاسِ إِلَى الصَّلَاةِقَالَ فَكَانَ ابْنُ عُمَرَ يُؤَدِّيهَا قَبْلَ ذَلِكَ بِالْيَوْمِ وَالْيَوْمَيْنِ","id":"Telah menceritakan kepada Kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada Kami [Zuhair] telah menceritakan kepada Kami [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam telah memerintahkan Kami untuk menunaikan zakat fitrah sebelum orang-orang keluar untuk melakukan shalat. Ia berkata; Ibnu Umar menunaikannya sehai atau dua hari sebelum itu. "},"1321":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا مَالِكٌ وَقَرَأَهُ عَلَيَّ مَالِكٌ أَيْضًا عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَضَ زَكَاةَ الْفِطْرِ قَالَ فِيهِ فِيمَا قَرَأَهُ عَلَيَّ مَالِكٌ زَكَاةُ الْفِطْرِ مِنْ رَمَضَانَ صَاعٌ مِنْ تَمْرٍ أَوْ صَاعٌ مِنْ شَعِيرٍ عَلَى كُلِّ حُرٍّ أَوْ عَبْدٍ ذَكَرٍ أَوْ أُنْثَى مِنْ الْمُسْلِمِينَحَدَّثَنَا يَحْيَى بْنُ مُحَمَّدِ بْنِ السَّكَنِ حَدَّثَنَا مُحَمَّدُ بْنُ جَهْضَمٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ عُمَرَ بْنِ نَافِعٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَ فَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَكَاةَ الْفِطْرِ صَاعًا فَذَكَرَ بِمَعْنَى مَالِكٍ زَادَ وَالصَّغِيرِ وَالْكَبِيرِ وَأَمَرَ بِهَا أَنْ تُؤَدَّى قَبْلَ خُرُوجِ النَّاسِ إِلَى الصَّلَاةِ قَالَ أَبُو دَاوُد رَوَاهُ عَبْدُ اللَّهِ الْعُمَرِيُّ عَنْ نَافِعٍ بِإِسْنَادِهِ قَالَ عَلَى كُلِّ مُسْلِمٍ وَرَوَاهُ سَعِيدٌ الْجُمَحِيُّ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ قَالَ فِيهِ مِنْ الْمُسْلِمِينَ وَالْمَشْهُورُ عَنْ عُبَيْدِ اللَّهِ لَيْسَ فِيهِ مِنْ الْمُسْلِمِينَ","id":"Telah menceritakan kepada Kami [Abdullah bin Maslamah], Telah menceritakan kepada Kami [Malik] dan Malik membacakannya kepadaku juga, dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallAllahu wa'alaihi wa sallam mewajibkan zakat fitrah, ia berkata padanya; diantara yang dibacakan Malik kepadaku adalah; zakat fitrah pada Bulan Ramadhan, satu sha' kurma, atau satu sha' gandum atas setiap orang merdeka, atau budak laki-laki dan perempuan dari kalangan muslimin. Telah menceritakan kepada Kami [Yahya bin Muhammad bin As Sakan], telah menceritakan kepada Kami [Muhammad bin Jahdham], telah menceritakan kepada Kami [Ismail bin Ja'far] dari [Umar bin Nafi'] dari [ayahnya] dari [Abdullah bin Umar], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam mewajibkan zakat fitrah satu sebanyak satu sha'. Kemudian ia menyebutkan secara makna yang disebutkan Malik, dan ia menambahkan; dan atas anak kecil, dan orang dewasa. Dan beliau memerintahkan agar ditunaikan sebelum orang-orang keluar untuk melakukan shalat. Abu Daud berkata; [Abdullah Al 'Umari] telah meriwayatkannya dari [Nafi'] dengan sanadnya. Ia berkata; wajib atas setiap muslim. Dan [Sa'id? Al Jumahi] telah meriwayatkan dari ['Ubaidullah] dari [Nafi'] ia berkata dalam hadits tersebut; dari kalangan muslimin. Dan yang masyhur dari 'Ubaidullah tidak ada padanya kata; dari kalangan muslimin. "},"1322":{"ar":"حَدَّثَنَا مُسَدَّدٌ أَنَّ يَحْيَى بْنَ سَعِيدٍ وَبِشْرَ بْنَ الْمُفَضَّلِ حَدَّثَاهُمْ عَنْ عُبَيْدِ اللَّهِ ح و حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبَانُ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ فَرَضَ صَدَقَةَ الْفِطْرِ صَاعًا مِنْ شَعِيرٍ أَوْ تَمْرٍ عَلَى الصَّغِيرِ وَالْكَبِيرِ وَالْحُرِّ وَالْمَمْلُوكِ زَادَ مُوسَى وَالذَّكَرِ وَالْأُنْثَىقَالَ أَبُو دَاوُد قَالَ فِيهِ أَيُّوبُ وَعَبْدُ اللَّهِ يَعْنِي الْعُمَرِيَّ فِي حَدِيثِهِمَا عَنْ نَافِعٍ ذَكَرٍ أَوْ أُنْثَى أَيْضًا","id":"Telah menceritakan kepada Kami [Musaddad], bahwa [Yahya bin Sa'id] dan [Bisyr bin Al Mufadlal] menceritakan kepada mereka dari [Ubaidillah] dan di ganti dengan jalur periwayatan lain, Telah menceritakan kepada Kami [Musa bin Isma'il] telah menceritakan kepada kami [Aban] dari [Ubaidullah] dari [Nafi'] dari [Abdullah] dari Nabi shallAllahu wa'alaihi wa sallam bahwa beliau mewajibkan zakat fitrah, satu sha' kurma, atau satu sha' gandum atas setiap orang dewasa maupun anak kecil, merdeka, atau budak Musa menambahkan laki-laki dan wanita. Abu Daud berkata; [Ayyub dan Abdullah Al 'Umari] juga meriwayatkan seperti itu dalam hadits mereka berdua, dari [Nafi'] juga kalangan laki-laki maupun wanita. "},"1323":{"ar":"حَدَّثَنَا الْهَيْثَمُ بْنُ خَالِدٍ الْجُهَنِيُّ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ الْجُعْفِيُّ عَنْ زَائِدَةَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي رَوَّادٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَكَانَ النَّاسُ يُخْرِجُونَ صَدَقَةَ الْفِطْرِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَاعًا مِنْ شَعِيرٍ أَوْ تَمْرٍ أَوْ سُلْتٍ أَوْ زَبِيبٍقَالَ قَالَ عَبْدُ اللَّهِ فَلَمَّا كَانَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ وَكَثُرَتْ الْحِنْطَةُ جَعَلَ عُمَرُ نِصْفَ صَاعٍ حِنْطَةً مَكَانَ صَاعٍ مِنْ تِلْكَ الْأَشْيَاءِ","id":"Telah menceritakan kepada Kami [Al Haitsam bin Khalid Al Juhani] telah menceritakan kepada Kami [Husain bin Ali Al Ju'fi] dari [Zaidah] telah menceritakan kepada Kami [Abdul 'Aziz bin Abu Rawwad] dari [Nafi'] dari [Abdullah bin Umar], ia berkata; dahulu orang-orang mengeluarkan zakat fitrah pada zaman Nabi shallallahu 'alaihi wasallam satu sha' gandum, atau kurma atau sult (jenis tanaman gandum), atau kismis. Nafi' berkata; Abdullah berkata; tatkala Umar menjabat sebagai khalifah dan gandum telah banyak maka Umar menjadikan setengah sha' gandum menggantikan satu sha' hal-hal tersebut. "},"1324":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَسُلَيْمَانُ بْنُ دَاوُدَ الْعَتَكِيُّ قَالَا حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ قَالَقَالَ عَبْدُ اللَّهِ فَعَدَلَ النَّاسُ بَعْدُ نِصْفَ صَاعٍ مِنْ بُرٍّ قَالَ وَكَانَ عَبْدُ اللَّهِ يُعْطِي التَّمْرَ فَأُعْوِزَ أَهْلُ الْمَدِينَةِ التَّمْرَ عَامًا فَأَعْطَى الشَّعِيرَ","id":"Telah menceritakan kepada Kami [Musaddad] serta [Sulaiman bin Daud Al 'Ataki], mereka berkata; telah menceritakan kepada Kami [Hammad] dari [Ayyub] dari [Nafi'], ia berkata; [Abdullah] berkata; setelah itu orang-orang beralih kepada setengah sha' gandum. Nafi' berkata; dan Abdullah memberikan kurma, kemudian penduduk Madinah sulit mendapatkan kurma selama satu tahun, kemudian ia memberikan gandum. "},"1325":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا دَاوُدُ يَعْنِي ابْنَ قَيْسٍ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَكُنَّا نُخْرِجُ إِذْ كَانَ فِينَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَكَاةَ الْفِطْرِ عَنْ كُلِّ صَغِيرٍ وَكَبِيرٍ حُرٍّ أَوْ مَمْلُوكٍ صَاعًا مِنْ طَعَامٍ أَوْ صَاعًا مِنْ أَقِطٍ أَوْ صَاعًا مِنْ شَعِيرٍ أَوْ صَاعًا مِنْ تَمْرٍ أَوْ صَاعًا مِنْ زَبِيبٍفَلَمْ نَزَلْ نُخْرِجُهُ حَتَّى قَدِمَ مُعَاوِيَةُ حَاجًّا أَوْ مُعْتَمِرًا فَكَلَّمَ النَّاسَ عَلَى الْمِنْبَرِ فَكَانَ فِيمَا كَلَّمَ بِهِ النَّاسَ أَنْ قَالَ إِنِّي أَرَى أَنَّ مُدَّيْنِ مِنْ سَمْرَاءِ الشَّامِ تَعْدِلُ صَاعًا مِنْ تَمْرٍ فَأَخَذَ النَّاسُ بِذَلِكَ فَقَالَ أَبُو سَعِيدٍ فَأَمَّا أَنَا فَلَا أَزَالُ أُخْرِجُهُ أَبَدًا مَا عِشْتُ قَالَ أَبُو دَاوُد رَوَاهُ ابْنُ عُلَيَّةَ وَعَبْدَةُ وَغَيْرِهِمَا عَنْ ابْنِ إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُثْمَانَ بْنِ حَكِيمِ بْنِ حِزَامٍ عَنْ عِيَاضٍ عَنْ أَبِي سَعِيدٍ بِمَعْنَاهُ وَذَكَرَ رَجُلٌ وَاحِدٌ فِيهِ عَنْ ابْنِ عُلَيَّةَ أَوْ صَاعًا مِنْ حِنْطَةٍ وَلَيْسَ بِمَحْفُوظٍ حَدَّثَنَا مُسَدَّدٌ أَخْبَرَنَا إِسْمَعِيلُ لَيْسَ فِيهِ ذِكْرُ الْحِنْطَةِ قَالَ أَبُو دَاوُد وَقَدْ ذَكَرَ مُعَاوِيَةُ بْنُ هِشَامٍ فِي هَذَا الْحَدِيثِ عَنْ الثَّوْرِيِّ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عِيَاضٍ عَنْ أَبِي سَعِيدٍ نِصْفَ صَاعٍ مِنْ بُرٍّ وَهُوَ وَهْمٌ مِنْ مُعَاوِيَةَ بْنِ هِشَامٍ أَوْ مِمَّنْ رَوَاهُ عَنْهُ","id":"Telah menceritakan kepada Kami [Abdullah bin Maslamah], telah menceritakan kepada Kami [Daud yaitu Ibnu Qais] dari ['Iyash bin Abdullah] dari [Abu Sa'id Al Khudri], ia berkata; Kami dahulu disaat Rasulullah shallAllahu wa'alaihi wa sallam bersama Kami mengeluarkan zakat fitrah untuk setiap anak kecil, dan orang dewasa, orang merdeka atau budak satu sha' makanan atau satu sha' keju, atau satu sha' gandum, atau satu sha' kurma, atau satu sha' kismis. Dan Kami tetap mengeluarkannya hingga [Mu'awiyah] datang untuk melakukan haji, atau umrah. Kemudian ia berbicara kepada orang-orang di atas minbar, dan diantara yang ia katakan kepada orang-orang adalah; saya melihat dua mud gandum Syam setara dengan satu sha' kurma. Kemudian orang-orang mengambil pendapat tersebut. Kemudian Abu Sa'id berkata; adapun aku maka aku tetap mengeluarkannya (sebagaimana dahulu aku mengeluarkannya) untuk selamanya selama aku hidup. Abu Daud berkata; [Ibu 'Ulayyah] dan ['Abdah] serta yang lainnya telah meriwayatkannya dari [Ibnu Ishaq] dari [Abdullah bin Abdullah bin Utsman bin Hakim bin Hizam], dari ['Iyadh] dari [Abu Sa'id] dengan maknanya. Dan satu orang dalam hadits tersebut telah menyebutkan dari Ibnu 'Ulayyah; atau satu sha' dari gandum. Dan hal tersebut bukanlah hadits mahfuzh. Telah menceritakan kepada Kami [Musaddad], telah mengabarkan kepada Kami [Ismail], tidak ada padanya penyebutkan; gandum. Abu Daud berkata; [Mu'awiyah bin Hisyam] dalam hadits ini telah menyebutkan dari [Atsauri] dari [Zaid bin Aslam] dari ['Iyadh] dari [Abu Sa'id]; setengah sha' gandum. Dan hal tersebut merupakan kesalahan dari Mu'awiyah bin Hisyam, atau dari orang yang meriwayatkan darinya."},"1326":{"ar":"حَدَّثَنَا حَامِدُ بْنُ يَحْيَى أَخْبَرَنَا سُفْيَانُ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ ابْنِ عَجْلَانَ سَمِعَ عِيَاضًا قَالَ سَمِعْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُلَا أُخْرِجُ أَبَدًا إِلَّا صَاعًا إِنَّا كُنَّا نُخْرِجُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَاعَ تَمْرٍ أَوْ شَعِيرٍ أَوْ أَقِطٍ أَوْ زَبِيبٍ هَذَا حَدِيثُ يَحْيَى زَادَ سُفْيَانُ أَوْ صَاعًا مِنْ دَقِيقٍقَالَ حَامِدٌ فَأَنْكَرُوا عَلَيْهِ فَتَرَكَهُ سُفْيَانُ قَالَ أَبُو دَاوُد فَهَذِهِ الزِّيَادَةُ وَهْمٌ مِنْ ابْنِ عُيَيْنَةَ","id":"Telah menceritakan kepada Kami [Hamid bin Yahya], telah mengabarkan kepada Kami [Sufyan]. Dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada Kami [Musaddad] telah menceritakan kepada Kami [Yahya] dari [Ibnu 'Ajlan], ia mendengar ['Iyadh] berkata; saya mendengar [Abu Sa'id Al Khudri] berkata; aku tidak akan mengeluarkannya selamanya kecuali satu sha'. Sesungguhnya Kami dahulu mengeluarkan pada zaman Nabi shallallahu 'alaihi wasallam satu sha' kurma atau gandum atau keju atau kismis. Ini adalah hadits Yahya, Sufyan menambahkan; atau satu sha' dari gandum. Hamid berkata; kemudian mereka mengingkarinya, dan Sufyan meninggalakannya. Abu Daud berkata; tambahan ini adalah kesalahan dari Ibnu'Uyainah. "},"1327":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَسُلَيْمَانُ بْنُ دَاوُدَ الْعَتَكِيُّ قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ النُّعْمَانِ بْنِ رَاشِدٍ عَنْ الزُّهْرِيِّ قَالَ مُسَدَّدٌ عَنْ ثَعْلَبَةَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي صُعَيْرٍ عَنْ أَبِيهِ وَقَالَ سُلَيْمَانُ بْنُ دَاوُدَ عَنْ عَبْدِ اللَّهِ بْنِ ثَعْلَبَةَ أَوْ ثَعْلَبَةَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي صُعَيْرٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَاعٌ مِنْ بُرٍّ أَوْ قَمْحٍ عَلَى كُلِّ اثْنَيْنِ صَغِيرٍ أَوْ كَبِيرٍ حُرٍّ أَوْ عَبْدٍ ذَكَرٍ أَوْ أُنْثَى أَمَّا غَنِيُّكُمْ فَيُزَكِّيهِ اللَّهُ وَأَمَّا فَقِيرُكُمْ فَيَرُدُّ اللَّهُ تَعَالَى عَلَيْهِ أَكْثَرَ مِمَّا أَعْطَى زَادَ سُلَيْمَانُ فِي حَدِيثِهِ غَنِيٍّ أَوْ فَقِيرٍ","id":"Telah menceritakan kepada Kami [Musaddad] dan [Sulaiman bin Daud Al 'Ataki], mereka berkata; telah menceritakan kepada Kami [Hammad bin Zaid] dari [An Nu'man bin Rasyid] dari [Az Zuhri]. [Musaddad] berkata dari [Tsa'labah bin Abdullah bin Abu Shu'air] dari [ayahnya], dan [Sulaiman bin Daud] berkata; dari [Abdullah bin Tsa'labah] atau [Tsa'labah bin Abdullah bin Abu Shu'air] dari [ayahnya], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Satu sha' gandum atas setiap anak kecil dan orang dewasa, yang merdeka dan budak, laki-laki atau perempuanl. Adapun orang kaya kalian maka Allah menzakatinya, dan adapun orang fakir kalian maka Allah mengembalikan kepadanya lebih banyak daripada apa yang telah ia berikan.\" Sulaiman menambahkan dalam haditsnya; orang kaya maupun miskin."},"1328":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْحَسَنِ الدَّرَابِجِرْدِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا بَكْرٌ هُوَ ابْنُ وَائِلٍ عَنْ الزُّهْرِيِّ عَنْ ثَعْلَبَةَ بْنِ عَبْدِ اللَّهِ أَوْ قَالَ عَبْدِ اللَّهِ بْنِ ثَعْلَبَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى النَّيْسَابُورِيُّ حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا هَمَّامٌ عَنْ بَكْرٍ الْكُوفِيِّ قَالَ مُحَمَّدُ بْنُ يَحْيَى هُوَ بَكْرُ بْنُ وَائِلِ بْنِ دَاوُدَ أَنَّ الزُّهْرِيَّ حَدَّثَهُمْ عَنْ عَبْدِ اللَّهِ بْنِ ثَعْلَبَةَ بْنِ صُعَيْرٍ عَنْ أَبِيهِ قَالَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطِيبًا فَأَمَرَ بِصَدَقَةِ الْفِطْرِ صَاعِ تَمْرٍ أَوْ صَاعِ شَعِيرٍ عَنْ كُلِّ رَأْسٍ زَادَ عَلِيٌّ فِي حَدِيثِهِ أَوْ صَاعِ بُرٍّ أَوْ قَمْحٍ بَيْنَ اثْنَيْنِ ثُمَّ اتَّفَقَا عَنْ الصَّغِيرِ وَالْكَبِيرِ وَالْحُرِّ وَالْعَبْدِحَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ وَقَالَ ابْنُ شِهَابٍ قَالَ عَبْدُ اللَّهِ بْنُ ثَعْلَبَةَ قَالَ ابْنُ صَالِحٍ قَالَ الْعَدَوِيُّ وَإِنَّمَا هُوَ الْعُذْرِيُّ خَطَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّاسَ قَبْلَ الْفِطْرِ بِيَوْمَيْنِ بِمَعْنَى حَدِيثِ الْمُقْرِئِ","id":"Telah menceritakan kepada Kami [Ali bin Al Hasan Ad Darabijirdi], telah menceritakan kepada Kami [Abdullah bin Yazid], telah menceritakan kepada Kami [Hammam], telah menceritakan kepada Kami [Bakr yaitu Ibnu Wail] dari [Az Zuhri] dari [Tsa'labah bin Abdullah] atau Abdullah bin Tsa'labah, dari Nabi shallallahu 'alaihi wasallam. Dan telah diriwayatkan melalui jalur yang lain: Telah menceritakan kepada Kami [Muhammad bin Yahya An Naisaburi], telah menceritakan kepada Kami [Musa bin Ismail], telah menceritakan kepada Kami [Hammam] dari [Bakr Al Kufi], Muhammad bin Yahya berkata; ia adalah Bakr bin Wail bin Daud, bahwa [Az Zuhri] telah menceritakan kepada mereka dar [Abdullah bin Tsa'labah bin Shu'air] dari [ayahnya], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam berdiri berkhutbah, dan memerintahkan untuk menunaikan zakat fitrah, satu sha' kurma, atau satu sha' gandum untuk setiap kepala. Ali menambahkan dalam haditsnya; atau satu sha' kurma diantara dua orang. Kemudian mereka sama mengenai anak kecil, orang dewasa, orang merdeka, dan seorang budak. Telah menceritakan kepada Kami [Ahmad bin Shalih], telah menceritakan kepada Kami [Abdurrazzaq], telah mengabarkan kepada Kami [Ibnu Juraij], ia berkata; [Ibnu Syihab] berkata; [Abdullah bin Tsa'labah] berkata; [Ibnu Shalih] berkata; [Al 'Adawi] berkata; sesungguhnya ia adalah Al 'Udzri; Rasulullah shallAllahu wa'alaihi wa sallam berkhutbah kepada orang-orang dua hari sebelum 'Idul Fitri, seperti makna hadits Al Muqri`."},"1329":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا سَهْلُ بْنُ يُوسُفَ قَالَ حُمَيْدٌ أَخْبَرَنَا عَنْ الْحَسَنِ قَالَخَطَبَ ابْنُ عَبَّاسٍ رَحِمَهُ اللَّهُ فِي آخِرِ رَمَضَانَ عَلَى مِنْبَرِ الْبَصْرَةِ فَقَالَ أَخْرِجُوا صَدَقَةَ صَوْمِكُمْ فَكَأَنَّ النَّاسَ لَمْ يَعْلَمُوا فَقَالَ مَنْ هَاهُنَا مِنْ أَهْلِ الْمَدِينَةِ قُومُوا إِلَى إِخْوَانِكُمْ فَعَلِّمُوهُمْ فَإِنَّهُمْ لَا يَعْلَمُونَ فَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذِهِ الصَّدَقَةَ صَاعًا مِنْ تَمْرٍ أَوْ شَعِيرٍ أَوْ نِصْفَ صَاعٍ مِنْ قَمْحٍ عَلَى كُلِّ حُرٍّ أَوْ مَمْلُوكٍ ذَكَرٍ أَوْ أُنْثَى صَغِيرٍ أَوْ كَبِيرٍفَلَمَّا قَدِمَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ رَأَى رُخْصَ السِّعْرِ قَالَ قَدْ أَوْسَعَ اللَّهُ عَلَيْكُمْ فَلَوْ جَعَلْتُمُوهُ صَاعًا مِنْ كُلِّ شَيْءٍ قَالَ حُمَيْدٌ وَكَانَ الْحَسَنُ يَرَى صَدَقَةَ رَمَضَانَ عَلَى مَنْ صَامَ","id":"Telah menceritakan kepada Kami [Muhammad bin Al Mutsanna], telah menceritakan kepada Kami [Sahl bin Yusuf], ia berkata; [Humaid] telah mengabarkan kepada Kami dari [Al Hasan], ia berkata; [Ibnu Abbas] rahimahullah berkhutbah pada akhir Ramadhan diatas mimbar Bashrah, lalu berkata: keluarkanlah zakat puasa kalian! Seakan orang-orang belum mengetahuinya, lalu dia berkata lagi; siapakah disini dari penduduk madinah, ajarkanlah mereka karena sesungguhnya mereka belum mengetahui. Rasulullah shallla Allahu 'alaihi wa sallam telah mewajibkan zakat ini satu sha' dari kurma atau gandum atau setengah sha' dari biji gandum, bagi setiap orang yang merdeka maupun budak, laki-laki maupun wanita, yang besar maupun yang kecil. Ketika Ali Bin Abi Thalib radliallahu 'anhu datang ia melihat murahnya harga, ia berkata; Allah telah melapangkan rizki kalian kalau seandainya kalian menjadikan satu sha' pada segala sesuatu. Humaid berkata; Al Hasan berpendapat bahwa zakat Ramadhan (fitrah) adalah kewajiban orang yang berpuasa. "},"1330":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ الصَّبَّاحِ حَدَّثَنَا شَبَابَةُ عَنْ وَرْقَاءَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُمَرَ بْنَ الْخَطَّابِ عَلَى الصَّدَقَةِ فَمَنَعَ ابْنُ جَمِيلٍ وَخَالِدُ بْنُ الْوَلِيدِ وَالْعَبَّاسُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَنْقِمُ ابْنُ جَمِيلٍ إِلَّا أَنْ كَانَ فَقِيرًا فَأَغْنَاهُ اللَّهُ وَأَمَّا خَالِدُ بْنُ الْوَلِيدِ فَإِنَّكُمْ تَظْلِمُونَ خَالِدًا فَقَدْ احْتَبَسَ أَدْرَاعَهُ وَأَعْتُدَهُ فِي سَبِيلِ اللَّهِ وَأَمَّا الْعَبَّاسُ عَمُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهِيَ عَلَيَّ وَمِثْلُهَا ثُمَّ قَالَ أَمَا شَعَرْتَ أَنَّ عَمَّ الرَّجُلِ صِنْوُ الْأَبِ أَوْ صِنْوُ أَبِيهِ","id":"Telah menceritakan kepada Kami [Al Hasan bin Ash Shabbah], telah menceritakan kepada Kami [Syababah] dari [Warqa`] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] radliallahu 'anhu, ia berkata; Nabi shalla Allahu 'alaihi wa sallam mengutus Umar bin Khathab radliallahu 'anhu untuk mengambil zakat, lalu Ibnu Jamil, Khalid bin Walid dan Al Abbas menolak untuk membayar, maka Rasulullah shallla Allahu 'alaihi wa sallam berkata: \"Tidaklah Ibnu jamil membalas dendam kecuali ia dahulu adalah orang yang miskin lalu Allah memberikannya kekayaan, adapun Khalid bin Al Walid, maka sesungguhnya kalian telah mendzalimi Khalid, sungguh ia telah menahan baju-baju besinya dan perlengkapan perangnya dijalan Allah, adapun Al Abbas paman Rasulullah shallla Allahu 'alaihi wa sallam, maka zakatnya dan yang sepertinya menjadi kewajibanku. Kemudian beliau berkata: \"Tidakkah engkau merasakan bahwa paman seseorang adalah saudara sebapak atau saudara bapaknya?\""},"1331":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ زَكَرِيَّا عَنْ الْحَجَّاجِ بْنِ دِينَارٍ عَنْ الْحَكَمِ عَنْ حُجَيَّةَ عَنْ عَلِيٍّأَنَّ الْعَبَّاسَ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي تَعْجِيلِ صَدَقَتِهِ قَبْلَ أَنْ تَحِلَّ فَرَخَّصَ لَهُ فِي ذَلِكَ قَالَ مَرَّةً فَأَذِنَ لَهُ فِي ذَلِكَقَالَ أَبُو دَاوُد رَوَى هَذَا الْحَدِيثَ هُشَيْمٌ عَنْ مَنْصُورِ بْنِ زَاذَانَ عَنْ الْحَكَمِ عَنْ الْحَسَنِ بْنِ مُسْلِمٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَدِيثُ هُشَيْمٍ أَصَحُّ","id":"Telah menceritakan kepada Kami [Sa'id? bin Manshur], telah menceritakan kepada Kami [Ismail bin Zakariya] dari [Al Hajjaj bin Dinar] dari [Al Hakam] dari [Hujayyah] dari [Ali] bahwa Al Abbas bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai menyegerakan zakat sebelum wajib atas mereka? Kemudian beliau memberikan rukhshah baginya dalam hal tersebut. Abu Daud berkata; [Husyaim] telah meriwayatkan hadits ini dari [Manshur bin Zadzan] dari [Al Hakam] dari [Al Hasan bin Muslim] dari Nabi shallallahu 'alaihi wasallam, dan hadits Husyaim lebih shahih."},"1332":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ أَخْبَرَنَا أَبِي أَخْبَرَنَا إِبْرَاهِيمُ بْنُ عَطَاءٍ مَوْلَى عِمْرَانَ بْنِ حُصَيْنٍ عَنْ أَبِيهِأَنَّ زِيَادًا أَوْ بَعْضَ الْأُمَرَاءِ بَعَثَ عِمْرَانَ بْنَ حُصَيْنٍ عَلَى الصَّدَقَةِ فَلَمَّا رَجَعَ قَالَ لِعِمْرَانَ أَيْنَ الْمَالُ قَالَ وَلِلْمَالِ أَرْسَلْتَنِي أَخَذْنَاهَا مِنْ حَيْثُ كُنَّا نَأْخُذُهَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَوَضَعْنَاهَا حَيْثُ كُنَّا نَضَعُهَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada Kami [Nashr bin Ali], telah mengabarkan kepada Kami [ayahku], telah mengabarkan kepada Kami [Ibrahim bin 'Atha`] mantan budak Imran bin Hushain dari [ayahnya] bahwa Ziyad atau sebagian pemimpin telah mengutus [Imran bin Hushain] untuk mengambil, kemudian tatkala ia kembali maka Ziyad bertanya kepadanya; dimanakah hartanya? Dia menjawab; apakah untuk harta engkau mengutusku? Kami telah mengambilnya dari tempat yang dahulu Kami pada masa Rasulullah shallla Allahu 'alaihi wa sallam mengambilnya dan Kami telah menempatkannya di tempat yang dahulu Kami tempatkan pada masa Rasulullah shallallahu 'alaihi wasallam."},"1333":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا سُفْيَانُ عَنْ حَكِيمِ بْنِ جُبَيْرٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَأَلَ وَلَهُ مَا يُغْنِيهِ جَاءَتْ يَوْمَ الْقِيَامَةِ خُمُوشٌ أَوْ خُدُوشٌ أَوْ كُدُوحٌ فِي وَجْهِهِ فَقَالَ يَا رَسُولَ اللَّهِ وَمَا الْغِنَى قَالَ خَمْسُونَ دِرْهَمًا أَوْ قِيمَتُهَا مِنْ الذَّهَبِقَالَ يَحْيَى فَقَالَ عَبْدُ اللَّهِ بْنُ عُثْمَانَ لِسُفْيَانَ حِفْظِي أَنَّ شُعْبَةَ لَا يَرْوِي عَنْ حَكِيمِ بْنِ جُبَيْرٍ فَقَالَ سُفْيَانُ حَدَّثَنَاهُ زُبَيْدٌ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ","id":"Telah menceritakan kepada Kami [Al Hasan bin Ali], telah menceritakan kepada Kami [Yahya bin Adam], telah menceritakan kepada Kami [Sufyan] dari [Hakim bin Jubair] dari [Muhammad bin Abdurrahman bin Yazid] dari [ayahnya] dari [Abdullah], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Barang siapa yang meminta-minta sementara ia memiliki sesuatu yang mencukupinya maka pada Hari Kiamat terdapat luka pada wajahnya.\" Abdullah berkata; wahai Rasulullah, apa yang kecukupan itu? Beliau berkata: \"Lima puluh dirham, atau senilai dengannya dari emas.\" Yahya berkata; kemudian Abdullah bin Utsman berkata kepada Sufyan; aku hafal bahwa Syu'bah tidak meriwayatkan dari Hakim bin Jubair. Sufyan berkata; telah menceritakan kepadanya Zubaid dari Muhammad bin Abdurrahman bin Yazid. "},"1334":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ رَجُلٍ مِنْ بَنِي أَسَدٍأَنَّهُ قَالَ نَزَلْتُ أَنَا وَأَهْلِي بِبَقِيعِ الْغَرْقَدِ فَقَالَ لِي أَهْلِي اذْهَبْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلْهُ لَنَا شَيْئًا نَأْكُلُهُ فَجَعَلُوا يَذْكُرُونَ مِنْ حَاجَتِهِمْ فَذَهَبْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدْتُ عِنْدَهُ رَجُلًا يَسْأَلُهُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا أَجِدُ مَا أُعْطِيكَ فَتَوَلَّى الرَّجُلُ عَنْهُ وَهُوَ مُغْضَبٌ وَهُوَ يَقُولُ لَعَمْرِي إِنَّكَ لَتُعْطِي مَنْ شِئْتَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْضَبُ عَلَيَّ أَنْ لَا أَجِدَ مَا أُعْطِيهِ مَنْ سَأَلَ مِنْكُمْ وَلَهُ أُوقِيَّةٌ أَوْ عِدْلُهَا فَقَدْ سَأَلَ إِلْحَافًا قَالَ الْأَسَدِيُّ فَقُلْتُ لَلِقْحَةٌ لَنَا خَيْرٌ مِنْ أُوقِيَّةٍ وَالْأُوقِيَّةُ أَرْبَعُونَ دِرْهَمًا قَالَ فَرَجَعْتُ وَلَمْ أَسْأَلْهُ فَقَدِمَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ ذَلِكَ شَعِيرٌ وَزَبِيبٌ فَقَسَمَ لَنَا مِنْهُ أَوْ كَمَا قَالَ حَتَّى أَغْنَانَا اللَّهُ عَزَّ وَجَلَّقَالَ أَبُو دَاوُد هَكَذَا رَوَاهُ الثَّوْرِيُّ كَمَا قَالَ مَالِكٌ","id":"Telah menceritakan kepada Kami [Abdullah bin Maslamah] dari [Malik] dari [Zaid bin Aslam] dari ['Atho` bin Yasar] dari [seorang laki-laki dari Bani Asad] bahwa ia berkata; aku dan keluargaku singgah di Baqi' yang terdapat padanya pohon Gharqad. Kemudian keluargaku berkata; pergilah kepada Rasulullah shallAllahu wa'alaihi wa sallam dan mintakan kepada Rasulullah shallAllahu wa'alaihi wa sallam untuk kita sesuatu yang dapat kita makan. Kemudian mereka menyebutkan sebagian dari keperluan mereka, lalu aku pergi kepada Rasulullah shallAllahu wa'alaihi wa sallam dan aku dapati seorang laki-laki sedang meminta-minta kepada beliau sementara Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Aku tidak memiliki sesuatu yang dapat aku berikan kepadamu.\" Kemudian orang tersebut pergi dari beliau dalam keadaan marah, dan berkata; demi umurku, sungguh engkau memberi orang yang engkau kehendaki. Maka Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Ia marah kepadaku karena aku tidak mendapatkan sesuatu yang dapat aku berikan kepadanya. Barang siapa diantara kalian yang meminta-minta sedangkan ia memiliki satu uqiyah atau yang setara dengannya maka sungguh ia telah meminta-minta dengan mendesak.\" Al Asadi berkata; sungguh unta Kami yang hampir melahirkan lebih baik daripada satu uqiyah. Satu uqiyah adalah empat puluh dirham. Laki-laki tersebut berkata; kemudian aku kembali dan tidak meminta-minta kepada beliau. Kemudian Rasulullah shallAllahu wa'alaihi wa sallam setelah itu datang membawa gandum, dan kismis. Kemudian beliau membagikannya kepada Kami, atau sebagaimana ia katakana, hingga Allah 'azza wajalla memberikan kecukupan kepada Kami. Abu Daud berkata; demikianlah [Ats Tsauri] meriwayatkan sebagaimana yang dikatakan oleh Malik."},"1335":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَهِشَامُ بْنُ عَمَّارٍ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الرِّجَالِ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ أَبِيهِ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَأَلَ وَلَهُ قِيمَةُ أُوقِيَّةٍ فَقَدْ أَلْحَفَ فَقُلْتُ نَاقَتِي الْيَاقُوتَةُ هِيَ خَيْرٌ مِنْ أُوقِيَّةٍ قَالَ هِشَامٌ خَيْرٌ مِنْ أَرْبَعِينَ دِرْهَمًا فَرَجَعْتُ فَلَمْ أَسْأَلْهُ شَيْئًا زَادَ هِشَامٌ فِي حَدِيثِهِ وَكَانَتْ الْأُوقِيَّةُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعِينَ دِرْهَمًا","id":"Telah menceritakan kepada Kami [Qutaibah bin Sa'id] serta [Hisyam bin 'Ammar], mereka berkata; telah menceritakan kepada Kami [Abdurrahman bin Abu Ar Rijal] dari ['Umarah bin Ghaziyyah] dari [Abdurrahman bin Abu Sa'id Al Khudri] dari [ayahnya yaitu Abu Sa'id], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Barang siapa yang meminta-minta sedangkan ia memiliki harta senilai satu uqiyah maka sungguh ia telah mendesak dalam meminta.\" Maka aku katakan; untaku yang bernama Al Yaqutah lebih baik dari pada satu uqiyah, -Hisyam berkata; lebih baik daripada empat puluh dirham-, kemudian aku kembali dan tidak lagi meminta kepada beliau sesuatupun. Hisyam berkata dalam haditsnya; satu uqiyah pada masa Rasulullah shallAllahu wa'alaihi wa sallam adalah empat puluh dirham. "},"1336":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا مِسْكِينٌ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُهَاجِرِ عَنْ رَبِيعَةَ بْنِ يَزِيدَ عَنْ أَبِي كَبْشَةَ السَّلُولِيِّ حَدَّثَنَا سَهْلُ ابْنُ الْحَنْظَلِيَّةِ قَالَقَدِمَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُيَيْنَةُ بْنُ حِصْنٍ وَالْأَقْرَعُ بْنُ حَابِسٍ فَسَأَلَاهُ فَأَمَرَ لَهُمَا بِمَا سَأَلَا وَأَمَرَ مُعَاوِيَةَ فَكَتَبَ لَهُمَا بِمَا سَأَلَا فَأَمَّا الْأَقْرَعُ فَأَخَذَ كِتَابَهُ فَلَفَّهُ فِي عِمَامَتِهِ وَانْطَلَقَ وَأَمَّا عُيَيْنَةُ فَأَخَذَ كِتَابَهُ وَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَانَهُ فَقَالَ يَا مُحَمَّدُ أَتُرَانِي حَامِلًا إِلَى قَوْمِي كِتَابًا لَا أَدْرِي مَا فِيهِ كَصَحِيفَةِ الْمُتَلَمِّسِ فَأَخْبَرَ مُعَاوِيَةُ بِقَوْلِهِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَأَلَ وَعِنْدَهُ مَا يُغْنِيهِ فَإِنَّمَا يَسْتَكْثِرُ مِنْ النَّارِ وَقَالَ النُّفَيْلِيُّ فِي مَوْضِعٍ آخَرَ مِنْ جَمْرِ جَهَنَّمَ فَقَالُوا يَا رَسُولَ اللَّهِ وَمَا يُغْنِيهِ وَقَالَ النُّفَيْلِيُّ فِي مَوْضِعٍ آخَرَ وَمَا الْغِنَى الَّذِي لَا تَنْبَغِي مَعَهُ الْمَسْأَلَةُ قَالَ قَدْرُ مَا يُغَدِّيهِ وَيُعَشِّيهِ وَقَالَ النُّفَيْلِيُّ فِي مَوْضِعٍ آخَرَ أَنْ يَكُونَ لَهُ شِبْعُ يَوْمٍ وَلَيْلَةٍ أَوْ لَيْلَةٍ وَيَوْمٍوَكَانَ حَدَّثَنَا بِهِ مُخْتَصَرًا عَلَى هَذِهِ الْأَلْفَاظِ الَّتِي ذَكَرْتُ","id":"Telah menceritakan kepada Kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada Kami [Miskin], telah menceritakan kepada Kami [Muhammad bin Al Muhajir], dari [Rabi'ah bin Yazid] dari [Abu Kabsyah As Saluli], telah menceritakan kepada Kami [Sahl bin Al Hanzhalah], ia berkata; 'Uyainah bin Hishn dan Al Aqra' bin Habis datang kepada Rasulullah shallAllahu wa'alaihi wa sallam dan meminta kepada beliau. Kemudian beliau memerintahkan agar keduanya diberi apa yang mereka minta dan memerintahkan kepada Mu'awiyah agar menuliskan untuk mereka apa yang mereka minta. Adapun Al Aqra' maka ia mengambil catatannya dan melipatnya pada surbannya dan pergi, adapun 'Uyainah maka ia mengambil catatannya dan datang kepada Nabi shallallahu 'alaihi wasallam di tempatnya, dan berkata; wahai Rasulullah, apakah anda berpendapat saya akan membawa sebuah catatan kepada kaumku yang tidak saya ketahui apa isinya, seperti selembar kertas Al Mutalammis? Kemudian Mu'awiyah memberitahukan perkataannya tersebut kepada Rasulullah shallAllahu wa'alaihi wa sallam, kemudian Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Barang siapa yang meminta-minta sementara ia memiliki sesuatu yang mencukupinya maka sesungguhnya ia memperbanyak api Neraka.\" An Nufaili pada tempat yang lain berkata; bara Neraka Jahannam. Kemudian mereka berkata; wahai Rasulullah, apa yang mencukupinya? -An Nufaili berkata pada tempat yang lain; apakah kecukupan yang tidak layak karenanya untuk meminta-minta? - Beliau bersabda: \"Seukuran sesuatu yang dapat memberinya makan siang dan malam.\" An Nufaili berkata pada tempat yang lain; ia kenyang satu hari semalam, atau semalam dan sehari. Ia menceritakan kepada Kami secara ringkas sesuai dengan lafazh yang telah Kami sebutkan ini. "},"1337":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ عُمَرَ بْنِ غَانِمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ زِيَادٍ أَنَّهُ سَمِعَ زِيَادَ بْنَ نُعَيْمٍ الْحَضْرَمِيَّ أَنَّهُ سَمِعَ زِيَادَ بْنَ الْحَارِثِ الصُّدَائِيَّ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَايَعْتُهُ فَذَكَرَ حَدِيثًا طَوِيلًا قَالَ فَأَتَاهُ رَجُلٌ فَقَالَ أَعْطِنِي مِنْ الصَّدَقَةِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ تَعَالَى لَمْ يَرْضَ بِحُكْمِ نَبِيٍّ وَلَا غَيْرِهِ فِي الصَّدَقَاتِ حَتَّى حَكَمَ فِيهَا هُوَ فَجَزَّأَهَا ثَمَانِيَةَ أَجْزَاءٍ فَإِنْ كُنْتَ مِنْ تِلْكَ الْأَجْزَاءِ أَعْطَيْتُكَ حَقَّكَ","id":"Telah menceritakan kepada Kami [Abdullah bin Maslamah], telah menceritakan kepada Kami [Abdullah] yaitu Ibnu Umar bin Ghanim dari [Abdurrahman bin Ziyad] bahwa ia mendengar [Ziyad bin Nu'aim Al Hadhrami] bahwa ia telah mendengar [Ziyad bin Harits Ash Shuda'i] berkata; aku menemui Rasulullah shallallahu 'alaihi wasallam lalu membaiatnya. Kemudan ia menyebutkan hadits yang panjang. Ia berkata; kemudian terdapat seseorang yang datang kepada beliau dan berkata; berikanlah aku sebagian dari sedekah! Maka Rasulullah shallallahu 'alaihi wasallam berkata kepadanya: \"Sesungguhnya Allah tidak tidak ridha kepada hukum seorang Nabi atau yang lainnya, Dialah yang telah menentukannya dan telah menetapkannya bagi delapan bagian dalam perkara zakat, hingga Dia sendiri yang memutuskan. Maka Allah membaginya menjadi delapan bagian, seandainya engkau termasuk dari bagian itu maka aku akan memberikan hakmu kepadamu. "},"1338":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ الْمِسْكِينُ الَّذِي تَرُدُّهُ التَّمْرَةُ وَالتَّمْرَتَانِ وَالْأَكْلَةُ وَالْأَكْلَتَانِ وَلَكِنَّ الْمِسْكِينَ الَّذِي لَا يَسْأَلُ النَّاسَ شَيْئًا وَلَا يَفْطِنُونَ بِهِ فَيُعْطُونَهُحَدَّثَنَا مُسَدَّدٌ وَعُبَيْدُ اللَّهِ بْنُ عُمَرَ وَأَبُو كَامِلٍ الْمَعْنَى قَالُوا حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَ��دٍ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ قَالَ وَلَكِنَّ الْمِسْكِينَ الْمُتَعَفِّفُ زَادَ مُسَدَّدٌ فِي حَدِيثِهِ لَيْسَ لَهُ مَا يَسْتَغْنِي بِهِ الَّذِي لَا يَسْأَلُ وَلَا يُعْلَمُ بِحَاجَتِهِ فَيُتَصَدَّقَ عَلَيْهِ فَذَاكَ الْمَحْرُومُ وَلَمْ يَذْكُرْ مُسَدَّدٌ الْمُتَعَفِّفُ الَّذِي لَا يَسْأَلُ قَالَ أَبُو دَاوُد رَوَى هَذَا الْحَدِيثَ مُحَمَّدُ بْنُ ثَوْرٍ وَعَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ وَجَعَلَا الْمَحْرُومَ مِنْ كَلَامِ الزُّهْرِيِّ وَهُوَ أَصَحُّ","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah] dan [Zuhair bin Harb], mereka berkata; telah menceritakan kepada Kami [Jarir] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang miskin bukanlah orang yang kembali karena diberi satu atau dua butir kurma, serta satu atau dua kali makan, akan tetapi orang miskin adalah orang yang tidak meminta sesuatu kepada orang-orang dan mereka tidak memahaminya, sehingga mereka dapat memberi kepadanya.\" Telah menceritakan kepada Kami [Musaddad] serta ['Ubaidullah bin Umar] dan [Abu Kamil] secara makna, mereka mengatakan; telah menceritakan kepada Kami [Abdul Wahid bin Ziyad], telah menceritakan kepada Kami [Ma'mar] dari [Az Zuhri] dari [Abu Salahamah] dari [Abu Hurairah], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda seperti itu: \"Akan tetapi orang yang miskin adalah orang yang menjaga kehormatan dirinya…\" Musaddad dalam haditsnya menambahkan; ia tidak memiliki sesuatu yang mencukupinya, orang yang tidak meminta-minta dan tidak diketahui kebutuhannya, sehingga dapat diberi sedekah. Maka itulah orang yang terhalang mendapatkan pemberian. Musaddad tidak menyebutkan; orang yang menjaga kehormatan dirinya yang tidak meminta-minta. Abu Daud berkata; [Muhammad bin Tsaur] serta [Abdurrazzaq] telah meriwayatkan dari [Ma'mar], dan mereka menjadikan kata; orang yang terhalang mendapatkan pemberian merupakan perkataan Az Zuhri, dan hal itu yang paling benar. "},"1339":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَدِيِّ بْنِ الْخِيَارِ قَالَ أَخْبَرَنِي رَجُلَانِأَنَّهُمَا أَتَيَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ وَهُوَ يُقَسِّمُ الصَّدَقَةَ فَسَأَلَاهُ مِنْهَا فَرَفَعَ فِينَا الْبَصَرَ وَخَفَضَهُ فَرَآنَا جَلْدَيْنِ فَقَالَ إِنَّ شِئْتُمَا أَعْطَيْتُكُمَا وَلَا حَظَّ فِيهَا لِغَنِيٍّ وَلَا لِقَوِيٍّ مُكْتَسِبٍ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Isa bin Yunus], telah menceritakan kepada Kami [Hisyam bin 'Urwah] dari [ayahnya] dari [Ubaidillah bin Adi bin Al Khiyar] berkata; telah telah mengabarkan kepadaku [dua orang yang telah menemui Rasulullah shallallahu 'alaihi wasallam pada waktu haji wada'] sementara beliau sedang membagikan zakat, mereka berdua meminta kepada beliau sebagian dari zakat tersebut, lalu beliau mengangkat pandangannya kepada Kami lalu menundukkannya dan beliau melihat Kami adalah orang yang kuat, lalu beliau berkata: \"Kalau kalian berdua menginginkannya maka Kami akan memberikan kepada kalian berdua, dan tidak ada bagian dalam zakat tersebut bagi orang yang kaya dan orang yang mampu untuk bekerja.\""},"1340":{"ar":"حَدَّثَنَا عَبَّادُ بْنُ مُوسَى الْأَنْبَارِيُّ الْخُتُّلِيُّ حَدَّثَنَا إِبْرَاهِيمُ يَعْنِي ابْنَ سَعْدٍ قَالَ أَخْبَرَنِي أَبِي عَنْ رَيْحَانَ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَحِلُّ الصَّدَقَةُ لِغَنِيٍّ وَلَا لِذِي مِرَّةٍ سَوِيٍّقَالَ أَبُو دَاوُد رَوَاهُ سُفْيَانُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ كَمَا قَالَ إِبْرَاهِيمُ وَرَوَاهُ شُعْبَةُ عَنْ سَعْدٍ قَالَ لِذِي مِرَّةٍ قَوِيٍّ وَالْأَحَادِيثُ الْأُخَرُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْضُهَا لِذِي مِرَّةٍ قَوِيٍّ وَبَعْضُهَا لِذِي مِرَّةٍ سَوِيٍّ و قَالَ عَطَاءُ بْنُ زُهَيْرٍ أَنَّهُ لَقِيَ عَبْدَ اللَّهِ بْنَ عَمْرٍو فَقَالَ إِنَّ الصَّدَقَةَ لَا تَحِلُّ لِقَوِيٍّ وَلَا لِذِي مِرَّةٍ سَوِيٍّ","id":"Telah menceritakan kepada Kami ['Abbad bin Musa Al Anbari Al Khuttuli], telah menceritakan kepada Kami [Ibrahim yaitu Ibnu Sa'd], ia berkata; telah mengabarkan kepadaku [ayahku] dari [Raihan bin Yazid] dari [Abdullah bin 'Amr] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tidak halal zakat bagi orang kaya dan orang yang kuat dan sehat badan.\" Abu Daud berkata; [Sufyan] telah meriwayatkannya dari [Sa'd bin Ibrahim] sebagaimana yang dikatakan Ibrahim. Dan [Syu'bah] telah meriwayatkannya dari [Sa'd], ia berkata; lidzii mirratin qawiyyin. Sedangkan hadits-hadits yang lain dari Nabi shallallahu 'alaihi wasallam sebagiannya dengan kata; lidzii mirratin qawiyyin, dan sebagiannya; lidzii mirratin sawiyyin. 'Atha` bin Zuhair berkata; bahwa ia telah berjumpa dengan Abdullah bin 'Amr dan berkata; sesungguhnya zakat tidak halal bagi orang yang kuat, dan orang yang kuat lagi sehat badan. "},"1341":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَحِلُّ الصَّدَقَةُ لِغَنِيٍّ إِلَّا لِخَمْسَةٍ لِغَازٍ فِي سَبِيلِ اللَّهِ أَوْ لِعَامِلٍ عَلَيْهَا أَوْ لِغَارِمٍ أَوْ لِرَجُلٍ اشْتَرَاهَا بِمَالِهِ أَوْ لِرَجُلٍ كَانَ لَهُ جَارٌ مِسْكِينٌ فَتُصُدِّقَ عَلَى الْمِسْكِينِ فَأَهْدَاهَا الْمِسْكِينُ لِلْغَنِيِّحَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ قَالَ أَبُو دَاوُد وَرَوَاهُ ابْنُ عُيَيْنَةَ عَنْ زَيْدٍ كَمَا قَالَ مَالِكٌ وَرَوَاهُ الثَّوْرِيُّ عَنْ زَيْدٍ قَالَ حَدَّثَنِي الثَّبْتُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada Kami [Abdullah bin Maslamah] dari [Malik] dari [Zaid bin Aslam] dari ['Atha` bin Yasar] bahwa Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Tidak halal zakat bagi orang kaya kecuali bagi lima orang, yaitu orang yang berperang di jalan Allah, atau petugas zakat, atau orang yang berhutang, atau seseorang yang membelinya dengan hartanya, atau orang yang memiliki tetangga miskin kemudian orang miskin tersebut diberi zakat, lalu ia memberikannya kepada orang yang kaya.\" Telah menceritakan kepada Kami [Al Hasan bin Ali], telah menceritakan kepada Kami [Abdurrazzaq], telah mengabarkan kepada Kami [Ma'mar] dari [Zaid bin Aslam] dari ['Atha' bin Yasar] dari [Abu Sa'id Al Khudri], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: ……. sama dengan makna hadits tersebut. Abu Daud berkata; [Ibnu 'Uyainah] telah meriwayatkannya dari [Zaid] sebagaimana yang dikatakan Malik. Dan Ats Tsauri telah meriwayatkannya dari Zaid, ia berkata; telah menceritakan kepadaku Ats Tsabtu dari Nabi shallallahu 'alaihi wasallam …."},"1342":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَوْفٍ الطَّائِيُّ حَدَّثَنَا الْفِرْيَابِيُّ حَدَّثَنَا سُفْيَانُ عَنْ عِمْرَانَ الْبَارِقِيِّ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَحِلُّ الصَّدَقَةُ لِغَنِيٍّ إِلَّا فِي سَبِيلِ اللَّهِ أَوْ ابْنِ السَّبِيلِ أَوْ جَارٍ فَقِيرٍ يُتَصَدَّقُ عَلَيْهِ فَيُهْدِي لَكَ أَوْ يَدْعُوكَقَالَ أَبُو دَاوُد وَرَوَاهُ فِرَاسٌ وَابْنُ أَبِي لَيْلَى عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada Kami [Muhammad bin 'Auf Ath Thai], telah menceritakan kepada Kami [Al Firyabi], telah menceritakan kepada Kami [Sufyan] dari [Imran Al Bariqi] dari ['Athiyyah] dari [Abu Sa'id], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Tidak halal zakat bagi orang kaya, kecuali di jalan Allah, atau orang yang dalam perjalanan, atau tetangga fakir yang diberi zakat kemudian ia memberikan hadiah kepadamu atau mengundangmu.\" Abu Daud berkata; dan hadits tersebut telah diriwayatkan oleh [Firas], dan [Ibnu Abu Laila] dari ['Athiyyah], dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam seperti itu. "},"1343":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدِ بْنِ الصَّبَّاحِ حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنِي سَعِيدُ بْنُ عُبَيْدٍ الطَّائِيُّ عَنْ بُشَيْرِ بْنِ يَسَارٍ زَعَمَ أَنَّ رَجُلًا مِنْ الْأَنْصَارِ يُقَالُ لَهُ سَهْلُ بْنُ أَبِي حَثْمَةَ أَخْبَرَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَدَاهُ بِمِائَةٍ مِنْ إِبِلِ الصَّدَقَةِ يَعْنِي دِيَةَ الْأَنْصَارِيِّ الَّذِي قُتِلَ بِخَيْبَرَ","id":"Telah menceritakan kepada Kami [Al Hasan bin Muhamad bin Ash Shabbah], telah menceritakan kepada Kami [Abu Nu'aim], telah menceritakan kepadaku [Sa'id bin 'Ubaid Ath Thai] dari [Busyair bin Yasar] ia menyangka bahwa seseorang dari kalangan anshar yang dikenal dengan nama [Sahl bin Abu Hatsmah] telah mengabarkan kepadanya bahwa Nabi shalla Allahu 'alaihi wa sallam membayar diyahnya dengan seratus unta dari unta zakat, yaitu diyah seorang anshar yang terbunuh di Khaibar."},"1344":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ النَّمَرِيُّ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ زَيْدِ بْنِ عُقْبَةَ الْفَزَارِيِّ عَنْ سَمُرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَسَائِلُ كُدُوحٌ يَكْدَحُ بِهَا الرَّجُلُ وَجْهَهُ فَمَنْ شَاءَ أَبْقَى عَلَى وَجْهِهِ وَمَنْ شَاءَ تَرَكَ إِلَّا أَنْ يَسْأَلَ الرَّجُلُ ذَا سُلْطَانٍ أَوْ فِي أَمْرٍ لَا يَجِدُ مِنْهُ بُدًّا","id":"Telah menceritakan kepada Kami [Hafsh bin Umar An Namari], telah menceritakan kepada Kami [Syu'bah] dari [Abdul Malik bin 'Umair] dari [Zaid bin 'Uqbah Al Fazari] dari [Samurah] dari Nabi shalla Allahu 'alaihi wa sallam beliau bersabda: \"Sesungguhnya meminta-minta itu perbuatan buruk, dengannya seseorang mencoreng wajahnya, barangsiapa yang mau maka ia biarkan coreng di wajahnya dan barangsiapa yang mau maka ia tinggalkan, kecuali jika seseorang meminta kepada pemimpin atau meminta sesuatu yang harus ia dapatkan.\""},"1345":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ هَارُونَ بْنِ رِئَابٍ قَالَ حَدَّثَنِي كِنَانَةُ بْنُ نُعَيْمٍ الْعَدَوِيُّ عَنْ قَبِيصَةَ بْنِ مُخَارِقٍ الْهِلَالِيِّ قَالَتَحَمَّلْتُ حَمَالَةً فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَقِمْ يَا قَبِيصَةُ حَتَّى تَأْتِيَنَا الصَّدَقَةُ فَنَأْمُرَ لَكَ بِهَا ثُمَّ قَالَ يَا قَبِيصَةُ إِنَّ الْمَسْأَلَةَ لَا تَحِلُّ إِلَّا لِأَحَدِ ثَلَاثَةٍ رَجُلٍ تَحَمَّلَ حَمَالَةً فَحَلَّتْ لَهُ الْمَسْأَلَةُ فَسَأَلَ حَتَّى يُصِيبَهَا ثُمَّ يُمْسِكُ وَرَجُلٍ أَصَابَتْهُ جَائِحَةٌ فَاجْتَاحَتْ مَالَهُ فَحَلَّتْ لَهُ الْمَسْأَلَةُ فَسَأَلَ حَتَّى يُصِيبَ قِوَامًا مِنْ عَيْشٍ أَوْ قَالَ سِدَادًا مِنْ عَيْشٍ وَرَجُلٍ أَصَابَتْهُ فَاقَةٌ حَتَّى يَقُولَ ثَلَاثَةٌ مِنْ ذَوِي الْحِجَى مِنْ قَوْمِهِ قَدْ أَصَابَتْ فُلَانًا الْفَاقَةُ فَحَلَّتْ لَهُ الْمَسْأَلَةُ فَسَأَلَ حَتَّى يُصِيبَ قِوَامًا مِنْ عَيْشٍ أَوْ سِدَادًا مِنْ عَيْشٍ ثُمَّ يُمْسِكُ وَمَا سِوَاهُنَّ مِنْ الْمَسْأَلَةِ يَا قَبِيصَةُ سُحْتٌ يَأْكُلُهَا صَاحِبُهَا سُحْتًا","id":"Telah menceritakan kepada Kami [Musaddad] telah menceritakan kepada Kami [Hammad bin Zaid], dari [Harun bin Riab], ia berkata; ia berkata; telah menceritakan kepadaku [Kinanah bin Nu'aim Al 'Adawi] dari [Qabishah bin Mukhariq Al Hilali], ia berkata; saya menanggung sebuah denda kemudian datang kepada Rasulullah shallallahu 'alaihi wasallam dan bertanya kepadanya mengenai hal tersebut. Kemudian beliau berkata: \"Bangunlah wahai Qabishah hingga datang zakat kepada Kami kemudian Kami perintahkan agar diberikan kepadamu.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Qabishah, sesungguhnya sedekah tidaklah halal kecuali bagi salah satu dari tiga orang yaitu; orang yang menanggung denda maka halal baginya untuk meminta-minta, kemudian meminta-minta hingga ia mendapatkannya kemudian ia menahan diri dari meminta-minta, dan seorang laki-laki yang tertimpa bencana hingga menghancurkan hartanya, maka halal baginya untuk meminta-minta, kemudian ia meminta-minta hingga mendapatkan penopang hidup kemudian menahan diri dari meminta-minta. Dan seorang laki-laki yang tertimpa kemiskinan hingga terdapat tiga orang yang bijaksana dari kaumnya bersaksi bahwa Fulan telah tertimpa kemiskinan. Maka halal baginya untuk meminta-minta hingga ia mendapatkan penopang hidup, dan sikap meminta-minta selain itu wahai Qabishah adalah perbuatan haram yang dimakan pelakunya sebagai sesuatu yang haram.\""},"1346":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ عَنْ الْأَخْضَرِ بْنِ عَجْلَانَ عَنْ أَبِي بَكْرٍ الْحَنَفِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَجُلًا مِنْ الْأَنْصَارِ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْأَلُهُ فَقَالَ أَمَا فِي بَيْتِكَ شَيْءٌ قَالَ بَلَى حِلْسٌ نَلْبَسُ بَعْضَهُ وَنَبْسُطُ بَعْضَهُ وَقَعْبٌ نَشْرَبُ فِيهِ مِنْ الْمَاءِ قَالَ ائْتِنِي بِهِمَا قَالَ فَأَتَاهُ بِهِمَا فَأَخَذَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ وَقَالَ مَنْ يَشْتَرِي هَذَيْنِ قَالَ رَجُلٌ أَنَا آخُذُهُمَا بِدِرْهَمٍ قَالَ مَنْ يَزِيدُ عَلَى دِرْهَمٍ مَرَّتَيْنِ أَوْ ثَلَاثًا قَالَ رَجُلٌ أَنَا آخُذُهُمَا بِدِرْهَمَيْنِ فَأَعْطَاهُمَا إِيَّاهُ وَأَخَذَ الدِّرْهَمَيْنِ وَأَعْطَاهُمَا الْأَنْصَارِيَّ وَقَالَ اشْتَرِ بِأَحَدِهِمَا طَعَامًا فَانْبِذْهُ إِلَى أَهْلِكَ وَاشْتَرِ بِالْآخَرِ قَدُومًا فَأْتِنِي بِهِ فَأَتَاهُ بِهِ فَشَدَّ فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُودًا بِيَدِهِ ثُمَّ قَالَ لَهُ اذْهَبْ فَاحْتَطِبْ وَبِعْ وَلَا أَرَيَنَّكَ خَمْسَةَ عَشَرَ يَوْمًا فَذَهَبَ الرَّجُلُ يَحْتَطِبُ وَيَبِيعُ فَجَاءَ وَقَدْ أَصَابَ عَشْرَةَ دَرَاهِمَ فَاشْتَرَى بِبَعْضِهَا ثَوْبًا وَبِبَعْضِهَا طَعَامًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا خَيْرٌ لَكَ مِنْ أَنْ تَجِيءَ الْمَسْأَلَةُ نُكْتَةً فِي وَجْهِكَ يَوْمَ الْقِيَامَةِ إِنَّ الْمَسْأَلَةَ لَا تَصْلُحُ إِلَّا لِثَلَاثَةٍ لِذِي فَقْرٍ مُدْقِعٍ أَوْ لِذِي غُرْمٍ مُفْظِعٍ أَوْ لِذِي دَمٍ مُوجِعٍ","id":"Telah menceritakan kepada Kami [Abdullah bin Maslamah], telah mengabarkan kepada Kami [Isa bin Yunus] dari [Al Akhdhar bin 'Ajlan] dari [Abu Bakr Al Hanafi] dari [Anas bin Malik] bahwa seorang laki-laki dari kalangan Anshar datang kepada Nabi shallallahu 'alaihi wasallam meminta kepada beliau, kemudian beliau bertanya: \"Apakah di rumahmu terdapat sesuatu?\" Ia berkata; ya, alas pelana yang Kami pakai sebagiannya dan Kami hamparkan sebagiannya, serta gelas besar yang gunakan untuk minum air. Beliau berkata: \"Bawalah keduanya kepadaku.\" Anas berkata; kemudian ia membawanya kepada beliau, lalu Rasulullah shallAllahu wa'alaihi wa sallam mengambilnya dengan tangan beliau dan berkata; \"Siapakah yang mau membeli kedua barang ini?\" seorang laki-laki berkata; saya membelinya dengan satu dirham. Beliau berkata: \"Siapa yang menambah lebih dari satu dirham?\" Beliau mengatakannya dua atau tiga kali. Seorang laki-laki berkata; saya membelinya dengan dua dirham. Kemudian beliau memberikannya kepada orang tersebut, dan mengambil uang dua dirham. Beliau memberikan uang tersebut kepada orang anshar tersebut dan berkata: \"Belilah makanan dengan satu dirham kemudian berikan kepada keluargamu, dan belilah kapak kemudian bawalah kepadaku.\" Kemudian orang tersebut membawanya kepada beliau, lalu Rasulullah shallAllahu wa'alaihi wa sallam mengikatkan kayu pada kapak tersebut dengan tangannya kemudian berkata kepadanya: \"Pergilah kemudian carilah kayu dan juAllah. Jangan sampai aku melihatmu selama lima belas hari.\" Kemudian orang tersebut pergi dan mencari kayu serta menjualnya, lalu datang dan ia telah memperoleh uang sepuluh dirham. Kemudian ia membeli pakaian dengan sebagiannya dan makanan dengan sebagiannya. Kemudian Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Ini lebih baik bagimu daripada sikap meminta-minta datang sebagai noktah di wajahmu pada Hari Kiamat. Sesungguhnya sikap meminta-minta tidak layak kecuali untuk tiga orang, yaitu untuk orang fakir dan miskin, atau orang yang memiliki hutang sangat berat, atau orang yang menanggung diyah (sementara ia tidak mampu membayarnya).\""},"1347":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الْعَزِيزِ عَنْ رَبِيعَةَ يَعْنِي ابْنَ يَزِيدَ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ أَبِي مُسْلِمٍ الْخَوْلَانِيِّ قَالَ حَدَّثَنِي الْحَبِيبُ الْأَمِينُ أَمَّا هُوَ إِلَيَّ فَحَبِيبٌ وَأَمَّا هُوَ عِنْدِي فَأَمِينٌ عَوْفُ بْنُ مَالِكٍقَالَ كُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعَةً أَوْ ثَمَانِيَةً أَوْ تِسْعَةً فَقَالَ أَلَا تُبَايِعُونَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكُنَّا حَدِيثَ عَهْدٍ بِبَيْعَةٍ قُلْنَا قَدْ بَايَعْنَاكَ حَتَّى قَالَهَا ثَلَاثًا فَبَسَطْنَا أَيْدِيَنَا فَبَايَعْنَاهُ فَقَالَ قَائِلٌ يَا رَسُولَ اللَّهِ إِنَّا قَدْ بَايَعْنَاكَ فَعَلَامَ نُبَايِعُكَ قَالَ أَنْ تَعْبُدُوا اللَّهَ وَلَا تُشْرِكُوا بِهِ شَيْئًا وَتُصَلُّوا الصَّلَوَاتِ الْخَمْسَ وَتَسْمَعُوا وَتُطِيعُوا وَأَسَرَّ كَلِمَةً خَفِيَّةً قَالَ وَلَا تَسْأَلُوا النَّاسَ شَيْئًا قَالَ فَلَقَدْ كَانَ بَعْضُ أُولَئِكَ النَّفَرِ يَسْقُطُ سَوْطُهُ فَمَا يَسْأَلُ أَحَدًا أَنْ يُنَاوِلَهُ إِيَّاهُقَالَ أَبُو دَاوُد حَدِيثُ هِشَامٍ لَمْ يَرْوِهِ إِلَّا سَعِيدٌ","id":"Telah menceritakan kepada Kami [Hisyam bin 'Ammar] telah menceritakan kepada Kami [Al Walid] telah menceritakan kepada Kami [Sa'id? bin Abdul Aziz] dari [Rabi'ah yaitu Ibnu Yazid] dari [Abu Idris Al Khaulani] dari [Abu Muslim Al Khaulani], ia berkata; telah menceritakan kepadaku Al Habib Al Amin, ia adalah orang yang aku cintai dan ia bagiku adalah orang yang dapat dipercaya yaitu ['Auf bin Malik], ia berkata; Kami pernah bersama Rasulullah shallAllahu wa'alaihi wa sallam berjumlah tujuh, atau delapan atau sembilan orang. Beliau berkata: \"Tidakkah kalian membaiat Rasulullah shallAllahu wa'alaihi wa sallam?\" Sementara Kami baru saja berbaiat kepada beliau. Kami katakan; Kami telah membaiat anda. Hingga beliau mengatakannya sebanyak tiga kali. Kemudian Kami menghamparkan tangan Kami dan membaiat beliau. Kemudian seseorang berkata; wahai Rasulullah, Kami telah membaiat anda, kepada apakah Kami membaiat anda? Beliau bersabda: \"Agar kalian beribadah kepada Allah dan tidak menyekutukan sesuatupun denganNya, melakukan shalat lima waktu, mendengar dan mentaati…. -dan beliau berkata pelan-: dan kalian tidak meminta-minta kepada orang sesuatupun.\" Ia berkata; sungguh sebagian orang-orang tersebut cemetinya terjatuh dan ia tidak meminta seorangpun untuk mengambilkannya. Abu Daud berkata; Hadits Hisyam tidak diriwayatkan kecuali oleh Sa'id. "},"1348":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ عَنْ أَبِي الْعَالِيَةِ عَنْ ثَوْبَانَ قَالَ وَكَانَ ثَوْبَانُ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يَكْفُلُ لِي أَنْ لَا يَسْأَلَ النَّاسَ شَيْئًا وَأَتَكَفَّلُ لَهُ بِالْجَنَّةِ فَقَالَ ثَوْبَانُ أَنَا فَكَانَ لَا يَسْأَلُ أَحَدًا شَيْئًا","id":"Telah menceritakan kepada Kami ['Ubaidullah bin Mu'adz], telah menceritakan kepada Kami [ayahku], telah menceritakan kepada Kami [Syu'bah] dari ['Ashim] dari [Abu Al 'Aliyah] dari [Tsauban] mantan budak Rasulullah shallAllahu wa'alaihi wa sallam, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapakah yang menjamin untukku untuk tidak meminta-minta sesuatupun kepada orang lain, dan aku menjaminnya masuk Surga? Tsauban berkata; saya! Dan Tsauban tidak pernah meminta sesuatupun kepada orang lain. "},"1349":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ نَاسًا مِنْ الْأَنْصَارِ سَأَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَاهُمْ ثُمَّ سَأَلُوهُ فَأَعْطَاهُمْ حَتَّى إِذَا نَفَدَ مَا عِنْدَهُ قَالَ مَا يَكُونُ عِنْدِي مِنْ خَيْرٍ فَلَنْ أَدَّخِرَهُ عَنْكُمْ وَمَنْ يَسْتَعْفِفْ يُعِفَّهُ اللَّهُ وَمَنْ يَسْتَغْنِ يُغْنِهِ اللَّهُ وَمَنْ يَتَصَبَّرْ يُصَبِّرْهُ اللَّهُ وَمَا أَعْطَى اللَّهُ أَحَدًا مِنْ عَطَاءٍ أَوْسَعَ مِنْ الصَّبْرِ","id":"Telah menceritakan kepada Kami [Abdullah bin Maslamah] dari [Malik] dari [Ibnu Syihab] dari ['Atho` bin Yazid Al Laitsi] dari [Abu Sa'id Al Khudri] bahwa beberapa orang Anshar meminta kepada Rasulullah, lalu beliau memberi mereka. Kemudian mereka meminta lagi kepadanya, lalu beliau beliau memberi mereka hingga habis apa yang beliau miliki. Beliau bersabda: \"Kebaikan (harta) yang ada padaku tidak akan aku simpan dari kalian. Dan barang siapa yang menjaga kehormatan dirinya maka Allah Azza wa Jalla akan menjaga kehormatannya, dan barang siapa yang bersabar maka Allah akan menjadikannya bersabar. Tidaklah seseorang diberi suatu pemberian yang lebih baik dan lebih luas daripada kesabaran.\""},"1350":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ ح و حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ حَبِيبٍ أَبُو مَرْوَانَ حَدَّثَنَا ابْنُ الْمُبَارَكِ وَهَذَا حَدِيثُهُ عَنْ بَشِيرِ بْنِ سَلْمَانَ عَنْ سَيَّارٍ أَبِي حَمْزَةَ عَنْ طَارِقٍ عَنْ ابْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَصَابَتْهُ فَاقَةٌ فَأَنْزَلَهَا بِالنَّاسِ لَمْ تُسَدَّ فَاقَتُهُ وَمَنْ أَنْزَلَهَا بِاللَّهِ أَوْشَكَ اللَّهُ لَهُ بِالْغِنَى إِمَّا بِمَوْتٍ عَاجِلٍ أَوْ غِنًى عَاجِلٍ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Abdullah bin Daud], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada Kami [Abdul Malik bin Habib Abu Marwan], telah menceritakan kepada Kami [Ibnu Al Mubarak], dan ini adalah haditsnya, dari [Basyir bin Salman] dari [Sayyar Abu Hamzah], dari [Thariq] dari [Ibnu Mas'ud], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Barangsiapa yang tertimpa kemiskinan lalu menampakkannya kepada manusia, maka kemiskinannya tidak hilang, dan barangsiapa yang menampakkannya kepada Allah, maka Allah akan mempercepat kekayaan baginya, baik dengan kematian yang segera atau dengan kekayaan yang cepat. "},"1351":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ بَكْرِ بْنِ سَوَادَةَ عَنْ مُسْلِمِ بْنِ مَخْشِيٍّ عَنْ ابْنِ الْفِرَاسِيِّأَنَّ الْفِرَاسِيَّ قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْأَلُ يَا رَسُولَ اللَّهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا وَإِنْ كُنْتَ سَائِلًا لَا بُدَّ فَاسْأَلْ الصَّالِحِينَ","id":"[Qutaibah], ia berkata; Telah menceritakan kepada Kami [Al Laits] dari [Ja'far bin Rabi'ah] dari [Bakr bin Sawadah] dari [Muslim bin Makhsyi] dari [Ibnu Al Firasi], ia berkata kepada Rasulullah shallallahu 'alaihi wasallam; Apakah saya boleh meminta wahai Rasulullah!\" Rasulullah menjawab: \"Tidak, dan seandainya engkau harus meminta maka mintalah kepada orang-orang shaleh.\""},"1352":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا اللَّيْثُ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ ابْنِ السَّاعِدِيِّ قَالَاسْتَعْمَلَنِي عُمَرُ رَضِيَ اللَّهُ عَنْهُ عَلَى الصَّدَقَةِ فَلَمَّا فَرَغْتُ مِنْهَا وَأَدَّيْتُهَا إِلَيْهِ أَمَرَ لِي بِعُمَالَةٍ فَقُلْتُ إِنَّمَا عَمِلْتُ لِلَّهِ وَأَجْرِي عَلَى اللَّهِ قَالَ خُذْ مَا أُعْطِيتَ فَإِنِّي قَدْ عَمِلْتُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَمَّلَنِي فَقُلْتُ مِثْلَ قَوْلِكَ فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُعْطِيتَ شَيْئًا مِنْ غَيْرِ أَنْ تَسْأَلَهُ فَكُلْ وَتَصَدَّقْ","id":"Telah? mengabarkan kepada Kami [Abu Al Walid Ath Thayalisi], telah? menceritakan kepada Kami [Al Laits] dari [Bukair bin Abdullah bin Al Asyajj] dari [Busr bin Sa'id] dari [Ibnu As Sa'idi], ia berkata; saya pernah ditunjuk Umar untuk mengurusi zakat, lalu tatkala saya telah selesai darinya dan menyampaikannya kepadanya, ia memerintahkan agar saya diberi uang, maka saya katakan; sesungguhnya saya bekerja hanya untuk Allah Azza wa Jalla, dan pahalaku di sisi Allah 'azza wajalla. Kemudian ia berkata; ambillah apa yang telah diberikan kepadamu, karena sesungguhnya saya telah bekerja pada masa? Rasulullah shallallahu 'alaihi wasallam kemudian beliau memberiku uang lalu aku katakan seperti apa yang telah engkau katakan, kemudian beliau berkata kepadaku: \"Apabila engkau diberi sesuatu dengan tanpa meminta maka makan dan sedekahkan.\""},"1353":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَهُوَ عَلَى الْمِنْبَرِ وَهُوَ يَذْكُرُ الصَّدَقَةَ وَالتَّعَفُّفَ مِنْهَا وَالْمَسْأَلَةَ الْيَدُ الْعُلْيَا خَيْرٌ مِنْ الْيَدِ السُّفْلَى وَالْيَدُ الْعُلْيَا الْمُنْفِقَةُ وَالسُّفْلَى السَّائِلَةُقَالَ أَبُو دَاوُد اخْتُلِفَ عَلَى أَيُّوبَ عَنْ نَافِعٍ فِي هَذَا الْحَدِيثِ قَالَ عَبْدُ الْوَارِثِ الْيَدُ الْعُلْيَا الْمُتَعَفِّفَةُ و قَالَ أَكْثَرُهُمْ عَنْ حَمَّادِ بْنِ زَيْدٍ عَنْ أَيُّوبَ الْيَدُ الْعُلْيَا الْمُنْفِقَةُ و قَالَ وَاحِدٌ عَنْ حَمَّادٍ الْمُتَعَفِّفَةُ","id":"Telah menceritakan kepada Kami [Abdullah bin Maslamah] dari [Malik], dari [Nafi'] dari [Abdullah bin Umar], bahwa Rasulullah shallAllahu wa'alaihi wa sallam di atas mimbar bersabda dan beliau menyebutkan mengenai sedekah, menahan diri darinya, serta mengenai sikap meminta-minta: \"Tangan yang di atas lebih baik daripada tangan yang di bawah. Tangan yang di atas adalah yang berinfak, sedangkan tangan yang di bawah adalah yang meminta-minta.\" Abu Daud berkata; telah diperselisihkan pada Ayyub dari Nafi' dalam hadits ini. [Abdul Warits] mengatakan; tangan di atas adalah yang menahan diri (dari meminta-minta). [Kebanyakan mereka] mengatakan; dari [Hammad bin Zaid] dari [Ayyub]; tangan yang di atas adalah yang berinfak. [salah seorang dari mereka] mengatakan dari [Hammad]; yaitu yang menahan diri (dari meminta-minta). "},"1354":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبِيدَةُ بْنُ حُمَيْدٍ التَّيْمِيُّ حَدَّثَنِي أَبُو الزَّعْرَاءِ عَنْ أَبِي الْأَحْوَصِ عَنْ أَبِيهِ مَالِكِ بْنِ نَضْلَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَيْدِي ثَلَاثَةٌ فَيَدُ اللَّهِ الْعُلْيَا وَيَدُ الْمُعْطِي الَّتِي تَلِيهَا وَيَدُ السَّائِلِ السُّفْلَى فَأَعْطِ الْفَضْلَ وَلَا تَعْجِزْ عَنْ نَفْسِكَ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami ['Ubaidah bin Humaid At Taimi], telah menceritakan kepadaku [Abu Az Za'ra`] dari [Abu Al Ahwash] dari [ayahnya yaitu Malik bin Nadhlah], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Tangan ada tiga macam, tangan Allah yang Maha Tinggi, tangan orang yang memberi setelah tangan Allah, dan tangan orang yang meminta yaitu tangan yang di bawah. Maka berikan harta dan jangan lemah untuk menafkahi dirimu.\""},"1355":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ ابْنِ أَبِي رَافِعٍ عَنْ أَبِي رَافِعٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ رَجُلًا عَلَى الصَّدَقَةِ مِنْ بَنِي مَخْزُومٍ فَقَالَ لِأَبِي رَافِعٍ اصْحَبْنِي فَإِنَّكَ تُصِيبُ مِنْهَا قَالَ حَتَّى آتِيَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْأَلَهُ فَأَتَاهُ فَسَأَلَهُ فَقَالَ مَوْلَى الْقَوْمِ مِنْ أَنْفُسِهِمْ وَإِنَّا لَا تَحِلُّ لَنَا الصَّدَقَةُ","id":"Telah menceritakan kepada Kami [Muhammad bin Katsir] telah mengabarkan kepada Kami [Syu'bah] dari [Al Hakam] dari [Ibnu Abu Rafi'] dari [Abu Rafi'] bahwa Nabi shallallahu 'alaihi wasallam mengutus seorang laki-laki aga mengambil zakat dari Bani Makhzum, kemudian ia berkata kepada Abu Rafi'; temani aku, sesungguhnya engkau akan memperoleh sebagian darinya. Ia berkata; hingga aku datang kepada Nabi shallallahu 'alaihi wasallam dan meminta kepada beliau. Kemudian ia datang kepada Nabi shallallahu 'alaihi wasallam dan meminta kepadanya, lalu beliau bersabda: \"Mantan budak sebuah kaum adalah bagian dari mereka, dan sesungguhnya tidak halal zakat bagi Kami.\""},"1356":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ وَمُسْلِمُ بْنُ إِبْرَاهِيمَ الْمَعْنَى قَالَا حَدَّثَنَا حَمَّادٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَمُرُّ بِالتَّمْرَةِ الْعَائِرَةِ فَمَا يَمْنَعُهُ مِنْ أَخْذِهَا إِلَّا مَخَافَةَ أَنْ تَكُونَ صَدَقَةً","id":"Telah menceritakan kepada Kami [Musa bin Isma'il], serta [Muslim bin Ibrahim] secara makna, mereka berkata; telah menceritakan kepada Kami [Hammad] dari [Qatadah] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam pernah melewati sebuah kurma yang terjatuh, dan tidak ada yang menghalangi beliau untuk mengambilnya kecuali khawatir merupakan kurma zakat. "},"1357":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ أَخْبَرَنَا أَبِي عَنْ خَالِدِ بْنِ قَيْسٍ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَدَ تَمْرَةً فَقَالَ لَوْلَا أَنِّي أَخَافُ أَنْ تَكُونَ صَدَقَةً لَأَكَلْتُهَاقَالَ أَبُو دَاوُد رَوَاهُ هِشَامٌ عَنْ قَتَادَةَ هَكَذَا","id":"Telah menceritakan kepada Kami [Nashr bin Ali], telah mengabarkan kepada Kami [ayahku] dari [Khalid bin Qais] dari [Qatadah] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam mendapatkan sebuah kurma kemudian berkata; seandainya aku tidak khawatir kurma tersebut merupakan kurma zakat niscaya aku memakannya. Abu Daud berkata; [Hisyam] meriwayatkannya dari [Qatadah] seperti ini. "},"1358":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ الْمُحَارِبِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ الْأَعْمَشِ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ قَالَبَعَثَنِي أَبِي إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي إِبِلٍ أَعْطَاهَا إِيَّاهُ مِنْ الصَّدَقَةِحَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ قَالَا حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ أَبِي عُبَيْدَةَ عَنْ أَبِيهِ عَنْ الْأَعْمَشِ عَنْ سَالِمٍ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ نَحْوَهُ زَادَ أَبِي يُبَدِّلُهَا لَهُ","id":"Telah menceritakan kepada Kami [Muhammad bin 'Ubaid Al Muharibi], telah menceritakan kepada Kami [Muhammad bin Fudhail] dari [Al A'masy] dari [Habib bin Abu Tsabit], dari [Kuraib] mantan budak Ibnu Abbas, ia berkata; ayahku mengutusku pergi kepada Nabi shalla Allahu 'alaihi wa sallam membawa unta shadaqah yang diberikan kepadanya. Telah menceritakan kepada Kami [Muhammad bin Al Ala`] dan [Utsman bin Abu Syaibah], mereka berkata; telah menceritakan kepada Kami [Muhammad bin Abu 'Ubaidah] dari [ayahnya] dari [Al A'masy] dari [Salim] dari [Kuraib] mantan budak Ibnu Abbas dari [Ibnu Abbas] seperti hadits tersebut, ia menambahkan \"ayahku menggantinya untuk beliau\". "},"1359":{"ar":"حَدَّثَنَا عَمْرُو بْنُ مَرْزُوقٍ قَالَ أَخْبَرَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِلَحْمٍ قَالَ مَا هَذَا قَالُوا شَيْءٌ تُصُدِّقَ بِهِ عَلَى بَرِيرَةَ فَقَالَ هُوَ لَهَا صَدَقَةٌ وَلَنَا هَدِيَّةٌ","id":"Telah menceritakan kepada Kami ['Amr bin Marzuq], ia berkata; telah mengabarkan kepada Kami [Syu'bah] dari [Qatadah] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam diberi daging, beliau mengatakan; apakah ini? Mereka berkata; sesuatu yang disedekahkan kepada Barirah. Kemudian beliau bersabda: \"Sesuatu tersebut adalah sedekah baginya dan hadiah bagi kita.\""},"1360":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَطَاءٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ بُرَيْدَةَأَنَّ امْرَأَةً أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ كُنْتُ تَصَدَّقْتُ عَلَى أُمِّي بِوَلِيدَةٍ وَإِنَّهَا مَاتَتْ وَتَرَكَتْ تِلْكَ الْوَلِيدَةَ قَالَ قَدْ وَجَبَ أَجْرُكِ وَرَجَعَتْ إِلَيْكِ فِي الْمِيرَاثِ","id":"Telah menceritakan kepada Kami [Ahmad bin Abdullah bin Yunus], telah menceritakan kepada Kami [Zuhair], telah menceritakan kepada Kami [Abdullah bin 'Atha`] dari [Abdullah bin Buraidah] dari [ayahnya yaitu Buraidah] bahwa seorang wanita datang kepada Rasulullah shallAllahu wa'alaihi wa sallam dan berkata; saya bersedekah kepada ibuku dengan seorang budak perempuan. Kemudian ia meninggal dan meninggalkan budak tersebut. Beliau bersabda: \"Telah tetap pahalamu dan budak tersebut kembali kepadamu dalam warisan.\""},"1361":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَاصِمِ بْنِ أَبِي النَّجُودِ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ قَالَكُنَّا نَعُدُّ الْمَاعُونَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَوَرَ الدَّلْوِ وَالْقِدْرِ","id":"Telah menceritakan kepada Kami [Qutaibah bin Sa'id], telah menceritakan kepada Kami [Abu 'Awanah], dari ['Ashim bin Abu An Najud] dari [Syaqiq] dari [Abdullah], ia berkata: Kami pada zaman Rasulullah shallla Allahu 'alaihi wa sallam menganggap Al Ma'un adalah ember serta periuk. "},"1362":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ صَاحِبِ كَنْزٍ لَا يُؤَدِّي حَقَّهُ إِلَّا جَعَلَهُ اللَّهُ يَوْمَ الْقِيَامَةِ يُحْمَى عَلَيْهَا فِي نَارِ جَهَنَّمَ فَتُكْوَى بِهَا جَبْهَتُهُ وَجَنْبُهُ وَظَهْرُهُ حَتَّى يَقْضِيَ اللَّهُ تَعَالَى بَيْنَ عِبَادِهِ فِي يَوْمٍ كَانَ مِقْدَارُهُ خَمْسِينَ أَلْفَ سَنَةٍ مِمَّا تَعُدُّونَ ثُمَّ يَرَى سَبِيلَهُ إِمَّا إِلَى الْجَنَّةِ وَإِمَّا إِلَى النَّارِ وَمَا مِنْ صَاحِبِ غَنَمٍ لَا يُؤَدِّي حَقَّهَا إِلَّا جَاءَتْ يَوْمَ الْقِيَامَةِ أَوْفَرَ مَا كَانَتْ فَيُبْطَحُ لَهَا بِقَاعٍ قَرْقَرٍ فَتَنْطَحُهُ بِقُرُونِهَا وَتَطَؤُهُ بِأَظْلَافِهَا لَيْسَ فِيهَا عَقْصَاءُ وَلَا جَلْحَاءُ كُلَّمَا مَضَتْ أُخْرَاهَا رُدَّتْ عَلَيْهِ أُولَاهَا حَتَّى يَحْكُمَ اللَّهُ بَيْنَ عِبَادِهِ فِي يَوْمٍ كَانَ مِقْدَارُهُ خَمْسِينَ أَلْفَ سَنَةٍ مِمَّا تَعُدُّونَ ثُمَّ يَرَى سَبِيلَهُ إِمَّا إِلَى الْجَنَّةِ وَإِمَّا إِلَى النَّارِ وَمَا مِنْ صَاحِبِ إِبِلٍ لَا يُؤَدِّي حَقَّهَا إِلَّا جَاءَتْ يَوْمَ الْقِيَامَةِ أَوْفَرَ مَا كَانَتْ فَيُبْطَحُ لَهَا بِقَاعٍ قَرْقَرٍ فَتَطَؤُهُ بِأَخْفَافِهَا كُلَّمَا مَضَتْ عَلَيْهِ أُخْرَاهَا رُدَّتْ عَلَيْهِ أُولَاهَا حَتَّى يَحْكُمَ اللَّهُ تَعَالَى بَيْنَ عِبَادِهِ فِي يَوْمٍ كَانَ مِقْدَارُهُ خَمْسِينَ أَلْفَ سَنَةٍ مِمَّا تَعُدُّونَ ثُمَّ يَرَى سَبِيلَهُ إِمَّا إِلَى الْجَنَّةِ وَإِمَّا إِلَى النَّارِحَدَّثَنَا جَعْفَرُ بْنُ مُسَافِرٍ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ هِشَامِ بْنِ سَعْدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ فِي قِصَّةِ الْإِبِلِ بَعْدَ قَوْلِهِ لَا يُؤَدِّي حَقَّهَا قَالَ وَمِنْ حَقِّهَا حَلَبُهَا يَوْمَ وِرْدِهَا حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَبِي عُمَرَ الْغُدَانِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذِهِ الْقِصَّةِ فَقَالَ لَهُ يَعْنِي لِأَبِي هُرَيْرَةَ فَمَا حَقُّ الْإِبِلِ قَالَ تُعْطِي الْكَرِيمَةَ وَتَمْنَحُ الْغَزِيرَةَ وَتُفْقِرُ الظَّهْرَ وَتُطْرِقُ الْفَحْلَ وَتَسْقِي اللَّبَنَ حَدَّثَنَا يَحْيَى بْنُ خَلَفٍ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ قَالَ قَالَ أَبُو الزُّبَيْرِ سَمِعْتُ عُبَيْدَ بْنَ عُمَيْرٍ قَالَ قَالَ رَجُلٌ يَا رَسُولَ اللَّهِ مَا حَقُّ الْإِبِلِ فَذَكَرَ نَحْوَهُ زَادَ وَإِعَارَةُ دَلْوِهَا","id":"Telah menceritakan kepada Kami [Musa bin Isma'il], telah menceritakan kepada Kami [Hammad] dari [Suhail bin Abu Shalih], dari [ayahnya] dari [Abu Hurairah] bahwa Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Tidaklah pemilik barang simpanan yang tidak menunaikan haknya kecuali Allah menjadikannya pada Hari Kiamat dipanaskan barang simpanan tersebut dalam neraka jahannam, lalu dibakar dengannya dahinya, lambung dan punggungnya, hingga Allah memberikan keputusan diantara para hambaNya pada hari yang kadarnya adalah lima puluh ribu tahun menurut perhitungan kalian, kemudian ia akan melihat jalannya, ke Surga atau ke Neraka. Dan tidaklah pemilik kambing yang tidak menunaikan haknya melainkan kambing tersebut akan datang pada Hari Kiamat lebih banyak daripada dahulunya dan pemiliknya di dudukkan di hadapannya pada tanah terbuka yang datar, kambing tersebut menanduknya dengan tanduknya dan menginjaknya dengan sepatu-sepatunya, tidak ada padanya kambing yang bertanduk bengkok serta yang tidak bertanduk. Setiap kali kambing yang terakhir selesai maka kambing yang pertama dikembalikan lagi, hingga Allah memberikan keputusan diantara para hambaNya pada hari yang kadarnya adalah lima puluh ribu tahun menurut perhitungan kalian. Kemudian ia akan melihat jalannya, ke Surga atau ke Neraka. Dan tidaklah pemilik unta yang tidak menunaikan haknya melainkan unta tersebut akan datang pada Hari Kiamat lebih banyak daripada dahulunya dan orang tersebut didudukkan di hadapannya pada tanah terbuka yang datar, unta tersebut menginjaknya dengan sepatunya. Setiap kali unta yang terakhir selesai maka unta yang pertama dikembalikan kepadanya hingga Allah ta'ala memberikan keputusan diantara para hambaNya pada hari kadarnya adalah lima puluh ribu tahun menurut perhitungan kalian. Kemudian ia akan melihat jalannya, ke Surga atau ke Neraka.\" Telah menceritakan kepada Kami [Ja'far bin Musafir], telah menceritakan kepada Kami [Ibnu Abu Fudaik] dari [Hisyam bin Sa'd] dari [Zaid bin Aslam] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti itu. Ia berkata dalam kisah unta, setelah sabdanya: \"Tidak menunaikan haknya….\" Beliau bersabda: \"Dan diantara haknya adalah memerahnya pada hari kedatangannya ke air.\" Telah menceritakan kepada Kami [Al Hasan bin Ali], telah menceritakan kepada Kami [Yazid bin Harun], telah mengabarkan kepada Kami [Syu'bah] dari [Qatadah] dari [Abu Umar Al Ghudani], dari [Abu Hurairah], ia berkata; saya mendengar Rasulullah shallAllahu wa'alaihi wa sallam seperti kisah ini. Kemudian Abu Umar berkata kepada Abu Hurairah; apakah hak unta? Ia berkata; engkau memberikan yang berharga, memberikan susunya yang deras, meminjamkan untuk dikendarai, mengawinkan pejantan, dan memberi minum susu. Telah menceritakan kepada Kami [Yahya bin Khalaf], telah menceritakan kepada Kami [Abu 'Ashim] dari [Ibnu Juraij], ia berkata; [Abu Az Zubair] berkata; saya mendengar ['Ubaid bin 'Umair] berkata; seorang laki-laki berkata; wahai Rasulullah shallallahu 'alaihi wasallam, apakah hak unta? Kemudian 'Ubaid menyebutkan hadits seperti itu dan menambahkan; \"Dan meminjamkan embernya.\""},"1363":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ يَحْيَى الْحَرَّانِيُّ حَدَّثَنِي مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ عَمِّهِ وَاسِعِ بْنِ حَبَّانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ مِنْ كُلِّ جَادِّ عَشْرَةِ أَوْسُقٍ مِنْ التَّمْرِ بِقِنْوٍ يُعَلَّقُ فِي الْمَسْجِدِ لِلْمَسَاكِينِ","id":"Telah menceritakan kepada Kami [Abdul Aziz bin Yahya Al Harrani], telah menceritakan kepadaku [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Muhammad bin Yahya bin Hibban] dari [pamannya yaitu Wasi' bin Habban] dari [Jabir bin Abdullah] bahwa Nabi shallallahu 'alaihi wasallam memerintahkan dari setiap buah yang berjumlah sepuluh wasaq kurma diambil satu tandan dan digantungkan di masjid untuk orang-orang miskin. "},"1364":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْخُزَاعِيُّ وَمُوسَى بْنُ إِسْمَعِيلَ قَالَا حَدَّثَنَا أَبُو الْأَشْهَبِ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَبَيْنَمَا نَحْنُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ إِذْ جَاءَ رَجُلٌ عَلَى نَاقَةٍ لَهُ فَجَعَلَ يُصَرِّفُهَا يَمِينًا وَشِمَالًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ عِنْدَهُ فَضْلُ ظَهْرٍ فَلْيَعُدْ بِهِ عَلَى مَنْ لَا ظَهْرَ لَهُ وَمَنْ كَانَ عِنْدَهُ فَضْلُ زَادٍ فَلْيَعُدْ بِهِ عَلَى مَنْ لَا زَادَ لَهُ حَتَّى ظَنَنَّا أَنَّهُ لَا حَقَّ لِأَحَدٍ مِنَّا فِي الْفَضْلِ","id":"Telah menceritakan kepada Kami [Muhammad bin Abdullah Al Khuza'i] dan [Musa bin Isma'il], mereka berkata; telah menceritakan kepada Kami [Abu Al Asyhab] dari [Abu Nadhrah] dari [Abu Sa'id Al Khudri], ia berkata; ketika Kami bersama Rasulullah shallAllahu wa'alaihi wa sallam dalam sebuah safar tiba-tiba terdapat seorang laki-laki yang datang menunggang untanya. Ia memalingkan unta tersebut ke kanan dan ke kiri, kemudian Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Barang siapa yang memiliki kelebihan tunggangan maka hendaknya ia memberikan tunggangan kepada orang yang tidak memiliki tunggangan, dan barang siapa yang memiliki kelebihan perbekalan maka hendaknya ia memberikan perbekalan kepada orang yang tidak memiliki perbekalan.\" Hingga Kami menyangka bahwa tidak ada seorangpun diantara Kami terhadap sesuatu yang lebih. "},"1365":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ يَعْلَى الْمُحَارِبِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا غَيْلَانُ عَنْ جَعْفَرِ بْنِ إِيَاسٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَالَّذِينَ يَكْنِزُونَ الذَّهَبَ وَالْفِضَّةَ }قَالَ كَبُرَ ذَلِكَ عَلَى الْمُسْلِمِينَ فَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ أَنَا أُفَرِّجُ عَنْكُمْ فَانْطَلَقَ فَقَالَ يَا نَبِيَّ اللَّهِ إِنَّهُ كَبُرَ عَلَى أَصْحَابِكَ هَذِهِ الْآيَةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ لَمْ يَفْرِضْ الزَّكَاةَ إِلَّا لِيُطَيِّبَ مَا بَقِيَ مِنْ أَمْوَالِكُمْ وَإِنَّمَا فَرَضَ الْمَوَارِيثَ لِتَكُونَ لِمَنْ بَعْدَكُمْ فَكَبَّرَ عُمَرُ ثُمَّ قَالَ لَهُ أَلَا أُخْبِرُكَ بِخَيْرِ مَا يَكْنِزُ الْمَرْءُ الْمَرْأَةُ الصَّالِحَةُ إِذَا نَظَرَ إِلَيْهَا سَرَّتْهُ وَإِذَا أَمَرَهَا أَطَاعَتْهُ وَإِذَا غَابَ عَنْهَا حَفِظَتْهُ","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Yahya bin Ya'la Al Muharibi], telah menceritakan kepada Kami [ayahku], telah menceritakan kepada Kami [Ghailan] dari [Ja'far bin Iyas] dari [Mujahid] dari [Ibnu Abbas], ia berkata; tatkala turun ayat: \"Dan orang-orang yang menyimpan emas dan perak…..\" Maka hal tersebut terasa berat atas orang-orang muslim. Kemudian Umar radliallahu 'anhu berkata; aku akan melapangkan hal itu dari kalian. Kemudian ia pergi dan berkata; wahai Rasulullah, sesungguhnya ayat ini telah terasa berat atas orang-orang muslim. Kemudian Rasulullah shallla Allahu 'alaihi wa sallam berkata: \"Sesungguhnya Allah tidak mewajibkan zakat kecuali untuk mensucikan apa yang tersisa dari harta kalian, dan mewajibkan warisan untuk orang-orang yang kalian tinggalkan.\" Maka Umar pun bertakbir, kemudian Rasulullah shallla Allahu 'alaihi wa sallam berkata kepada Umar: \"Maukah aku beritahukan simpanan paling baik yang disimpan oleh seseorang? Yaitu istri yang shalih yang apabila suaminya melihatnya maka ia akan menyenangkannya, dan apabilla ia memerintahkannya, maka diapun mentaatinya, dan kalau suaminya pergi maka dia akan menjaga amanahnya.\""},"1366":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ حَدَّثَنَا مُصْعَبُ بْنُ مُحَمَّدِ بْنِ شُرَحْبِيلَ حَدَّثَنِي يَعْلَى بْنُ أَبِي يَحْيَى عَنْ فَاطِمَةَ بِنْتِ حُسَيْنٍ عَنْ حُسَيْنِ بْنِ عَلِيٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلسَّائِلِ حَقٌّ وَإِنْ جَاءَ عَلَى فَرَسٍحَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا زُهَيْرٌ عَنْ شَيْخٍ قَالَ رَأَيْتُ سُفْيَانَ عِنْدَهُ عَنْ فَاطِمَةَ بِنْتِ حُسَيْنٍ عَنْ أَبِيهَا عَنْ عَلِيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada Kami [Muhammad bin Katsir], telah mengabarkan kepada Kami [Sufyan], telah menceritakan kepada Kami [Mush'ab bin Muhammad bin Syurahbil], telah menceritakan kepadaku [Ya'la bin Abu Yahya], dari [Fathimah binti Humais], dari [Husain bin Ali], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Orang yang meminta-minta memiliki hak walaupun ia berada di atas kuda.\" Telah menceritakan kepada Kami [Muhammad bin Rafi'], telah menceritakan kepada Kami [Yahya bin Adam], telah menceritakan kepada Kami [Zuhair] dari [seorang laki-laki tua], ia berkata; aku melihat Sufyan di sisinya dari [Fathimah binti Husain] dari [ayahnya] dari [Ali] dari Nabi shallallahu 'alaihi wasallam seperti itu. "},"1367":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ بُجَيْدٍ عَنْ جَدَّتِهِ أُمِّ بُجَيْدٍ وَكَانَتْ مِمَّنْ بَايَعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّهَا قَالَتْ لَهُ يَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْكَ إِنَّ الْمِسْكِينَ لَيَقُومُ عَلَى بَابِي فَمَا أَجِدُ لَهُ شَيْئًا أُعْطِيهِ إِيَّاهُ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ لَمْ تَجِدِي لَهُ شَيْئًا تُعْطِينَهُ إِيَّاهُ إِلَّا ظِلْفًا مُحْرَقًا فَادْفَعِيهِ إِلَيْهِ فِي يَدِهِ","id":"Telah menceritakan kepada Kami [Qutaibah bin Sa'id], telah menceritakan kepada Kami [Al Laits] dari [Sa'id bin Abu Sa'id] dari [Abdurrahman bin Bujaid] dari [neneknya yaitu Ummu Bujaid], dan ia adalah diantara orang yang membaiat Rasulullah shallAllahu wa'alaihi wa sallam, bahwa ia berkata kepada beliau; wahai Rasulullah, semoga Allah melimpahkan shalat kepada anda. Sesungguhnya terdapat seorang miskin yang berdiri di depan pintuku, dan aku tidak memiliki sesuatu yang dapat aku berikan kepadanya. Kemudian Rasulullah shallAllahu wa'alaihi wa sallam berkata kepadanya: \"Apabila engkau tidak mendapatkan sesuatu yang dapat engkau berikan kepadanya kecuali kaki kambing yang terbakar, maka berikan kepadanya di tangannya.\""},"1368":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي شُعَيْبٍ الْحَرَّانِيُّ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ أَسْمَاءَ قَالَتْقَدِمَتْ عَلَيَّ أُمِّي رَاغِبَةً فِي عَهْدِ قُرَيْشٍ وَهِيَ رَاغِمَةٌ مُشْرِكَةٌ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ أُمِّي قَدِمَتْ عَلَيَّ وَهِيَ رَاغِمَةٌ مُشْرِكَةٌ أَفَأَصِلُهَا قَالَ نَعَمْ فَصِلِي أُمَّكِ","id":"Telah menceritakan kepada Kami [Ahmad bin Abu Syu'aib Al Harrani], telah menceritakan kepada Kami [Isa bin Yunus], telah menceritakan kepada Kami [Hisyam bin 'Urwah] dari [ayahnya] dari [Asma`], ia berkata; ibuku datang menemuiku dalam keadaan mengharapkan baktiku, sementara ia membenci keislamanku dan ia adalah wanita musyrik. Lalu aku katakan; wahai Rasulullah, sesungguhnya ibuku datang menemuiku dalam keadaan mengharapkan baktiku, sementara ia membenci keislamanku dan ia adalah wanita musyrik. Apakah aku boleh berhubungan dengannya? Beliau berkata: \"Ya, hubungilah ibumu.\""},"1369":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا كَهْمَسٌ عَنْ سَيَّارِ بْنِ مَنْظُورٍ رَجُلٌ مِنْ بَنِي فَزَارَةَ عَنْ أَبِيهِ عَنْ امْرَأَةٍ يُقَالُ لَهَا بُهَيْسَةُ عَنْ أَبِيهَا قَالَتْاسْتَأْذَنَ أَبِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلَ بَيْنَهُ وَبَيْنَ قَمِيصِهِ فَجَعَلَ يُقَبِّلُ وَيَلْتَزِمُ ثُمَّ قَالَ يَا رَسُولَ اللَّهِ مَا الشَّيْءُ الَّذِي لَا يَحِلُّ مَنْعُهُ قَالَ الْمَاءُ قَالَ يَا نَبِيَّ اللَّهِ مَا الشَّيْءُ الَّذِي لَا يَحِلُّ مَنْعُهُ قَالَ الْمِلْحُ قَالَ يَا رَسُولَ اللَّهِ مَا الشَّيْءُ الَّذِي لَا يَحِلُّ مَنْعُهُ قَالَ أَنْ تَفْعَلَ الْخَيْرَ خَيْرٌ لَكَ","id":"Telah menceritakan kepada Kami ['Ubaidullah bin Mu'adz], telah menceritakan kepada Kami [ayahku], telah menceritakan kepada Kami [Kahmas] dari [Sayyar bin Manzhur] yaitu seorang laki-laki dari Bani Fazarah, dari [ayahnya], dari seorang wanita yang dipanggil [Buhaisah] dari [ayahnya], ia berkata; ayahku meminta izin kepada Nabi shallallahu 'alaihi wasallam, kemudian ia memasuki jubah beliau dan mencium beliau dan terus menyertai beliau. Kemudian berkata; wahai Rasulullah, sesuatu apakah yang tidak boleh untuk dihalangi? Beliau bersabda: \"Air.\" Ia berkata; wahai Rasulullah, sesuatu apakah yang tidak boleh untuk dihalangi? Beliau bersabda: \"Garam.\" Ia berkata; wahai Rasulullah, sesuatu apakah yang tidak boleh untuk dihalangi? Beliau bersabda: \"Engkau melakukan kebaikan adalah lebih baik bagimu.\""},"1370":{"ar":"حَدَّثَنَا بِشْرُ بْنُ آدَمَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَكْرٍ السَّهْمِيُّ حَدَّثَنَا مُبَارَكُ بْنُ فَضَالَةَ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ مِنْكُمْ أَحَدٌ أَطْعَمَ الْيَوْمَ مِسْكِينًا فَقَالَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ دَخَلْتُ الْمَسْجِدَ فَإِذَا أَنَا بِسَائِلٍ يَسْأَلُ فَوَجَدْتُ كِسْرَةَ خُبْزٍ فِي يَدِ عَبْدِ الرَّحْمَنِ فَأَخَذْتُهَا مِنْهُ فَدَفَعْتُهَا إِلَيْهِ","id":"Telah menceritakan kepada Kami [Bisyr bin Adam], telah menceritakan kepada Kami [Abdullah bin Bakr As Sahmi], telah menceritakan kepada Kami [Mubarak bin Fadhalah] dari [Tsabit Al Bunani] dari [Abdurrahman bin Abu Laila] dari [Abdurrahman bin Abu Bakr], ia berkata: Rasulullah shallallahu 'alaihi wasallam bertanya: \"Apakah diantara kalian pada hari ini ada orang yang telah memberi makan seorang miskin?\" Abu Bakr radliallahu 'anhu menjawab; saya masuk masjid, dan ternyata saya mendapati seorang miskin yang sedang meminta-minta dan aku dapati sepotong roti ditangan Abdurrahman, maka aku mengambilnya dan aku berikan kepada orang miskin tersebut. "},"1371":{"ar":"حَدَّثَنَا أَبُو الْعَبَّاسِ الْقِلَّوْرِيُّ حَدَّثَنَا يَعْقُوبُ بْنُ إِسْحَقَ الْحَضْرَمِيُّ عَنْ سُلَيْمَانَ بْنِ مُعَاذٍ التَّمِيمِيِّ حَدَّثَنَا ابْنُ الْمُنْكَدِرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُسْأَلُ بِوَجْهِ اللَّهِ إِلَّا الْجَنَّةُ","id":"Telah menceritakan kepada Kami [Abu Al 'Abbas Al Qillauri], telah menceritakan kepada Kami [Ya'qub bin Ishaq Al Hadhrami] dari [Sulaiman bin Mu'adz At Taimi], telah menceritakan kepada Kami [Ibnu Al Munkadir] dari [Jabir], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Tidak boleh ada sesuatu yang diminta dengan wajah Allah kecuali Surga.\""},"1372":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ مُجَاهِدٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اسْتَعَاذَ بِاللَّهِ فَأَعِيذُوهُ وَمَنْ سَأَلَ بِاللَّهِ فَأَعْطُوهُ وَمَنْ دَعَاكُمْ فَأَجِيبُوهُ وَمَنْ صَنَعَ إِلَيْكُمْ مَعْرُوفًا فَكَافِئُوهُ فَإِنْ لَمْ تَجِدُوا مَا تُكَافِئُونَهُ فَادْعُوا لَهُ حَتَّى تَرَوْا أَنَّكُمْ قَدْ كَافَأْتُمُوهُ","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Jarir] dari [Al A'masy] dari [Mujahid] dari [Abdullah bin Umar], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Barang siapa yang berlindung dengan nama Allah, maka lindungilah dia, barang siapa yang meminta-minta dengan nama Allah maka berikanlah kepadanya, barang siapa yang mengundang kalian maka penuhilah undangannya, dan barang siapa yang berbuat kebaikan kepada kalian maka balaslah, kemudian apabila kalian tidak mendapat sesuatu untuk membalasnya maka doakanlah dia hingga kalian melihat bahwa kalian telah membalasnya.\""},"1373":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَاصِمِ بْنِ عُمَرَ بْنِ قَتَادَةَ عَنْ مَحْمُودِ بْنِ لَبِيدٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ الْأَنْصَارِيِّ قَالَكُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ جَاءَهُ رَجُلٌ بِمِثْلِ بَيْضَةٍ مِنْ ذَهَبٍ فَقَالَ يَا رَسُولَ اللَّهِ أَصَبْتُ هَذِهِ مِنْ مَعْدِنٍ فَخُذْهَا فَهِيَ صَدَقَةٌ مَا أَمْلِكُ غَيْرَهَا فَأَعْرَضَ عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ أَتَاهُ مِنْ قِبَلِ رُكْنِهِ الْأَيْمَنِ فَقَالَ مِثْلَ ذَلِكَ فَأَعْرَضَ عَنْهُ ثُمَّ أَتَاهُ مِنْ قِبَلِ رُكْنِهِ الْأَيْسَرِ فَأَعْرَضَ عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ أَتَاهُ مِنْ خَلْفِهِ فَأَخَذَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَذَفَهُ بِهَا فَلَوْ أَصَابَتْهُ لَأَوْجَعَتْهُ أَوْ لَعَقَرَتْهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْتِي أَحَدُكُمْ بِمَا يَمْلِكُ فَيَقُولُ هَذِهِ صَدَقَةٌ ثُمَّ يَقْعُدُ يَسْتَكِفُّ النَّاسَ خَيْرُ الصَّدَقَةِ مَا كَانَ عَنْ ظَهْرِ غِنًىحَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ ابْنِ إِسْحَقَ بِإِسْنَادِهِ وَمَعْنَاهُ زَادَ خُذْ عَنَّا مَالَكَ لَا حَاجَةَ لَنَا بِهِ","id":"Telah menceritakan kepada Kami [Musa bin Isma'il], telah menceritakan kepada Kami [Hammad] dari [Muhammad bin Ishaq], dari ['Ashim bin Umar bin Qatadah] dari [Mahmud bin Labid] dari [Jabir bin Abdullah Al Anshari], ia berkata; Kami pernah bersama Rasulullah shallAllahu wa'alaihi wa sallam, tiba-tiba terdapat seorang laki-laki yang datang membawa emas seperti telur, kemudian ia berkata; wahai Rasulullah, aku mendapatkan ini dari sebagian barang tambang, ambillah, itu adalah sedekah, aku tidak memiliki harta selainnya. Lalu Rasulullah shallAllahu wa'alaihi wa sallam berpaling darinya, kemudian ia datang dari sisi kanan beliau, dan berkata seperti itu, kemudian datang dari kiri beliau dan Rasulullah shallAllahu wa'alaihi wa sallam berpaling darinya, kemudian datang dari belakangnya, lalu Rasulullah shallAllahu wa'alaihi wa sallam mengambilnya dan melempar dengannya, apabila mengenainya niscaya akan menyakitinya atau melukainya. Kemudian Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Salah seorang diantara kalian datang membawa harta yang ia miliki, dan berkata; ini adalah sedekah, kemudian ia duduk dan meminta-minta kepada orang. Sebaik-baik sedekah adalah dalam keadaan lebih.\" Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Ibnu Idris], dari [Ibnu Ishaq] dengan sanad serta maknanya, dan ia menambahkan kata: \"Ambillah milikmu, Kami tidak membutuhkannya.\""},"1374":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِسْمَعِيلَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ عَجْلَانَ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ بْنِ سَعْدٍ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُدَخَلَ رَجُلٌ الْمَسْجِدَ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَطْرَحُوا ثِيَابًا فَطَرَحُوا فَأَمَرَ لَهُ بِثَوْبَيْنِ ثُمَّ حَثَّ عَلَى الصَّدَقَةِ فَجَاءَ فَطَرَحَ أَحَدَ الثَّوْبَيْنِ فَصَاحَ بِهِ وَقَالَ خُذْ ثَوْبَكَ","id":"Telah menceritakan kepada Kami [Ishaq bin Isma'il], telah menceritakan kepada Kami [Sufyan] dari [Ibnu 'Ajlan], dari ['Iyadh bin Abdullah bin Sa'd], ia mendengar [Abu Sa'id Al Khudri], berkata; seorang laki-laki masuk masjid, kemudian Nabi shalla Allahu 'alaihi wa sallam memerintahkan mereka untuk menanggalkan baju mereka, dan mereka pun mensedekahkan pakaian, kemudian mereka melemparkan beberapa pakaian. Lalu beliau memerintahkan agar orang tersebut diberi dua pakaian. Kemudian beliau menganjurkan untuk bersedekah, lalu orang-orang tersebut datang dan melemparkan salah satu pakaian tersebut. Kemudian beliau menteriakinya dan berkata: \"Ambillah pakaianmu!\""},"1375":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ خَيْرَ الصَّدَقَةِ مَا تَرَكَ غِنًى أَوْ تُصُدِّقَ بِهِ عَنْ ظَهْرِ غِنًى وَابْدَأْ بِمَنْ تَعُولُ","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Jarir] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Sesungguhnya sebaik-baik sedekah adalah sedekah yang masih meninggalkan kecukupan (bagi yang bersedekah), atau yang disedekahkan dalam kondisi kecukupan. Dan mulailah dengan orang yang engkau tanggung.\""},"1376":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَيَزِيدُ بْنُ خَالِدِ بْنِ مَوْهَبٍ الرَّمْلِيُّ قَالَا حَدَّثَنَا اللَّيْثُ عَنْ أَبِي الزُّبَيْرِ عَنْ يَحْيَى بْنِ جَعْدَةَ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ قَالَيَا رَسُولَ اللَّهِ أَيُّ الصَّدَقَةِ أَفْضَلُ قَالَ جُهْدُ الْمُقِلِّ وَابْدَأْ بِمَنْ تَعُولُ","id":"Telah menceritakan kepada Kami [Qutaibah bin Sa'id], serta [Yazid bin Khalid bin Mauhib Ar Ramli], mereka berkata; telah menceritakan kepada Kami [Al Laits] dari [Abu Az Zubair] dari [Yahya bin Ja'dah] dari [Abu Hurairah] bahwa ia berkata; wahai Rasulullah, sedekah apakah yang lebih utama? Beliau bersabda: \"Kadar yang mampu ditanggung orang fakir, dan mulailah dari orang yang engkau tanggung.\""},"1377":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ وَهَذَا حَدِيثُهُ قَالَا حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ حَدَّثَنَا هِشَامُ بْنُ سَعْدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يَقُولُأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا أَنْ نَتَصَدَّقَ فَوَافَقَ ذَلِكَ مَالًا عِنْدِي فَقُلْتُ الْيَوْمَ أَسْبِقُ أَبَا بَكْرٍ إِنْ سَبَقْتُهُ يَوْمًا فَجِئْتُ بِنِصْفِ مَالِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَبْقَيْتَ لِأَهْلِكَ قُلْتُ مِثْلَهُ قَالَ وَأَتَى أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ بِكُلِّ مَا عِنْدَهُ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَبْقَيْتَ لِأَهْلِكَ قَالَ أَبْقَيْتُ لَهُمْ اللَّهَ وَرَسُولَهُ قُلْتُ لَا أُسَابِقُكَ إِلَى شَيْءٍ أَبَدًا","id":"Telah menceritakan kepada Kami [Ahmad bin Shalih] serta [Utsman bin Abu Syaibah bin Abu Syaibah], dan ini adalah haditsnya, mereka berkata; telah menceritakan kepada Kami [Al Fadhl bin Dukain], telah menceritakan kepada Kami [Hisyam bin Sa'd] dari [Zaid bin Aslam] dari [ayahnya], ia berkata: aku mendengar [Umar bin Al Khathab radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan Kami agar bersedekah, dan hal tersebut bertepatan dengan keberadaan harta yang saya miliki. Lalu saya mengatakan; apabila aku dapat mendahului Abu Bakr pada suatu hari maka hari ini aku akan mendahuluinya. Kemudian saya datang dengan membawa setengah hartaku, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah yang engkau tinggalkan untuk keluargamu?\" Saya katakan; harta yang sama seperti itu. Ia berkata; kemudian Abu Bakar datang dengan membawa seluruh yang ia miliki. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Abu Bakr, apakah yang engkau tinggalkan untuk keluargamu?\" Ia berkata; saya tinggalkan untuk mereka Allah dan RasulullahNya. Maka saya katakan; saya tidak akan dapat mendahuluimu kepada sesuatupun selamanya. "},"1378":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ سَعِيدٍ أَنَّسَعْدًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَيُّ الصَّدَقَةِ أَعْجَبُ إِلَيْكَ قَالَ الْمَاءُحَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ حَدَّثَنَا مُحَمَّدُ بْنُ عَرْعَرَةَ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ وَالْحَسَنِ عَنْ سَعْدِ بْنِ عُبَادَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada Kami [Muhammad bin Katsir], telah mengabarkan kepada Kami [Hammam] dari [Qatadah] dari [Sa'id] bahwa [Sa'd] datang kepada Nabi shalla Allahu 'alaihi wa sallam lalu bertanya; shadaqah apa yang lebih anda sukai? Beliau menjawab: \"Air!\" Telah berkata kepada Kami [Muhammad bin Abdurrahim], telah berkata kepada Kami [Muhammad bin Ararah] dari [Syu'bah] dari [Qatadah] dari [Sa'id bin Musayyab] dan [Al Hasan] dari [Sa'd bin 'Ubadah] dari Nabi shalla Allahu 'alaihi wa sallam sama seperti itu. "},"1379":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ رَجُلٍ عَنْ سَعْدِ بْنِ عُبَادَةَ أَنَّهُ قَالَيَا رَسُولَ اللَّهِ إِنَّ أُمَّ سَعْدٍ مَاتَتْ فَأَيُّ الصَّدَقَةِ أَفْضَلُ قَالَ الْمَاءُقَالَ فَحَفَرَ بِئْرًا وَقَالَ هَذِهِ لِأُمِّ سَعْدٍ","id":"Telah menceritakan kepada Kami [Muhammad bin Katsir], telah mengabarkan kepada Kami [Israil], [Abu Ishaq] dari seorang [laki-laki], dari [Sa'd bin 'Ubadah], bahwa ia berkata; wahai Rasulullah, sesungguhnya ibuku yaitu Ummu Sa'd telah meninggal, maka sedekah apakah yang paling utama? Beliau bersabda: \"Air.\" Orang tersebut mengatakan; kemudian Sa'd menggali sebuah sumur dan mengatakan; ini adalah untuk Ummu Sa'd. "},"1380":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ إِبْرَاهِيمَ بْنِ إِشْكَابَ حَدَّثَنَا أَبُو بَدْرٍ حَدَّثَنَا أَبُو خَالِدٍ الَّذِي كَانَ يَنْزِلُ فِي بَنِي دَالَانَ عَنْ نُبَيْحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا مُسْلِمٍ كَسَا مُسْلِمًا ثَوْبًا عَلَى عُرْيٍ كَسَاهُ اللَّهُ مِنْ خُضْرِ الْجَنَّةِ وَأَيُّمَا مُسْلِمٍ أَطْعَمَ مُسْلِمًا عَلَى جُوعٍ أَطْعَمَهُ اللَّهُ مِنْ ثِمَارِ الْجَنَّةِ وَأَيُّمَا مُسْلِمٍ سَقَى مُسْلِمًا عَلَى ظَمَإٍ سَقَاهُ اللَّهُ مِنْ الرَّحِيقِ الْمَخْتُومِ","id":"Telah menceritakan kepada Kami [Ali bin Al Husain bin Ibrahim bin Isykab], telah menceritakan kepada Kami [Abu Badr], telah menceritakan kepada Kami [Abu Khalid] yang pernah singgah di Bani Dalan, dari [Nubaih] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Siapapun seorang muslim yang memakaikan pakaian kepada muslim yang lainnya karena ia tidak berpakaian maka Allah akan memakaikan kepadanya pakaian dari pakaian yang hijau di Surga, dan siapapun seorang muslim yang memberikan makan kepada muslim lainnya yang dalam keadaan lapar maka Allah memberinya makanan dari buah-buahan di Surga, dan siapapun seorang muslim yang memberi minum muslim lainnya yang dalam keadaan haus maka Allah akan memberinya minum dari Ar Rahiq Al Makhtum (arak Surga).\""},"1381":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى قَالَ أَخْبَرَنَا إِسْرَائِيلُ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عِيسَى وَهَذَا حَدِيثُ مُسَدَّدٍ وَهُوَ أَتَمُّ عَنْ الْأَوْزَاعِيِّ عَنْ حَسَّانَ بْنِ عَطِيَّةَ عَنْ أَبِي كَبْشَةَ السَّلُولِيِّ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرٍو يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعُونَ خَصْلَةً أَعْلَاهُنَّ مَنِيحَةُ الْعَنْزِ مَا يَعْمَلُ رَجُلٌ بِخَصْلَةٍ مِنْهَا رَجَاءَ ثَوَابِهَا وَتَصْدِيقَ مَوْعُودِهَا إِلَّا أَدْخَلَهُ اللَّهُ بِهَا الْجَنَّةَ قَالَ أَبُو دَاوُد فِي حَدِيثِ مُسَدَّدٍ قَالَ حَسَّانُ فَعَدَدْنَا مَا دُونَ مَنِيحَةِ الْعَنْزِ مِنْ رَدِّ السَّلَامِ وَتَشْمِيتِ الْعَاطِسِ وَإِمَاطَةِ الْأَذَى عَنْ الطَّرِيقِ وَنَحْوَهُ فَمَا اسْتَطَعْنَا أَنْ نَبْلُغَ خَمْسَةَ عَشَرَ خَصْلَةً","id":"Telah menceritakan kepada Kami [Ibrahim bin Musa], ia berkata; telah mengabarkan kepada Kami [Israil], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Isa], dan ini adalah haditsnya Musaddad, dan ia lebih sempurna, dari [Al Auza'i], dari [Hassan bin 'Athiyyah], dari [Abu Kabsyah As Saluli], ia berkata; saya mendengar [Abdullah bin 'Amr] berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Terdapat empat puluh sifat, paling tinggi adalah memberikan kambing betina untuk diambil manfaat susu dan bulunya. Tidaklah seseorang melakukan salah satu sifat dari sifat-sifat tersebut karena mengharap pahalanya dan membenarkan apa yang dijanjikan kecuali dengannya Allah akan memasukkannya ke dalam Surga.\" Abu Daud dalam hadits Musaddad berkata; Hassan berkata; kemudian Kami menghitung selain memberikan kambing betina untuk diambil manfaat susu dan bulunya yaitu; membalas salam, menjawab orang yang bersin, menyingkirkan gangguan dari jalan, dan yang semisalnya. Dan Kami tidak mampu mencapai lima belas sifat. "},"1382":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الْعَلَاءِ الْمَعْنَى وَاحِدٌ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْخَازِنَ الْأَمِينَ الَّذِي يُعْطِي مَا أُمِرَ بِهِ كَامِلًا مُوَفَّرًا طَيِّبَةً بِهِ نَفْسُهُ حَتَّى يَدْفَعَهُ إِلَى الَّذِي أُمِرَ لَهُ بِهِ أَحَدُ الْمُتَصَدِّقَيْنِ","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah] dan [Muhammad bin Al 'Ala`], dan maknanya satu, mereka berkata; telah menceritakan kepada Kami [Abu Usamah] dari [Buraid bin Abdullah bin Abu Burdah] dari [Abu Burdah] dari [Abu Musa], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Sesungguhnya bendahara yang dapat dipercaya adalah orang yang memberikan apa yang diperintahkan kepadanya secara sempurna, dan hatinya merasa rela hingga ia menyerahkannya kepada orang yang diperintahkan untuk diberi oleh salah seorang dari para pemberi sedekah.\""},"1383":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مَنْصُورٍ عَنْ شَقِيقٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَنْفَقَتْ الْمَرْأَةُ مِنْ بَيْتِ زَوْجِهَا غَيْرَ مُفْسِدَةٍ كَانَ لَهَا أَجْرُ مَا أَنْفَقَتْ وَلِزَوْجِهَا أَجْرُ مَا اكْتَسَبَ وَلِخَازِنِهِ مِثْلُ ذَلِكَ لَا يَنْقُصُ بَعْضُهُمْ أَجْرَ بَعْضٍ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Abu 'Awanah] dari [Manshur] dari [Syaqiq] dari [Masruq] dari [Aisyah] radliallahu 'anha, ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila seorang wanita berinfak dari harta suaminya tanpa membuat kerusakan maka baginya pahala apa yang telah ia infakkan, dan bagi suaminya pahala apa yang ia usahakan, dan bagi orang menyimpannya mendapatkan pahala seperti itu tanpa sebagian mereka mengurangi pahala sebagian yang lain.\""},"1384":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَوَّارٍ الْمِصْرِيِّ حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ حَرْبٍ عَنْ يُونُسَ بْنِ عُبَيْدٍ عَنْ زِيَادِ بْنِ جُبَيْرِ بْنِ حَيَّةَ عَنْ سَعْدٍ قَالَلَمَّا بَايَعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النِّسَاءُ قَامَتْ امْرَأَةٌ جَلِيلَةٌ كَأَنَّهَا مِنْ نِسَاءِ مُضَرَ فَقَالَتْ يَا نَبِيَّ اللَّهِ إِنَّا كَلٌّ عَلَى آبَائِنَا وَأَبْنَائِنَاقَالَ أَبُو دَاوُد وَأُرَى فِيهِ وَأَزْوَاجِنَا فَمَا يَحِلُّ لَنَا مِنْ أَمْوَالِهِمْ فَقَالَ الرَّطْبُ تَأْكُلْنَهُ وَتُهْدِينَهُ قَالَ أَبُو دَاوُد الرَّطْبُ الْخُبْزُ وَالْبَقْلُ وَالرُّطَبُ قَالَ أَبُو دَاوُد وَكَذَا رَوَاهُ الثَّوْرِيُّ عَنْ يُونُسَ","id":"Telah menceritakan kepada Kami [Muhammad bin Sawwar Al Mishri], Telah menceritakan kepada Kami [Abdussalam bin Harb] dari [Yunus bin 'Ubaid] dari [Ziyad bin Jubair bin Hayyah] dari [Sa'd], ia berkata; tatkala para wanita berbaiat kepada Rasulullah shallallahu 'alaihi wasallam, terdapat seorang wanita yang bertubuh besar sepertinya dia termasuk wanita dari kabilah Mudhar, ia berkata; wahai Nabi Allah, sesungguhnya Kami adalah beban bagi bapak-bapak Kami dan anak laki-laki Kami -Abu Daud berkata; aku menganggap ada kata: dan suami Kami- maka apakah yang halal bagi Kami untuk Kami dari harta mereka? Beliau menjawab: makanan basah yang kalian makan dan kalian hadiahkan. Abu Daud berkata; makanan basah adalah roti dan sayur-sayuran serta ruthab, AbuDaud berkata; seperti inilah yang diriwayatkan [Ats Tsauri] dari [Yunus]. "},"1385":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَنْفَقَتْ الْمَرْأَةُ مِنْ كَسْبِ زَوْجِهَا مِنْ غَيْرِ أَمْرِهِ فَلَهَا نِصْفُ أَجْرِهِ","id":"Telah menceritakan kepada Kami [Al Hasan bin Ali], telah menceritakan kepada Kami [Abdurrazzaq], telah mengabarkan kepada Kami [Ma'mar] dari [Hammam bin Munabbih], ia berkata; saya mendengar [Abu Hurairah] berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Apabila seorang wanita berinfak dari sebagian usaha suaminya tanpa perintahnya maka baginya setengah pahala suaminya.\""},"1386":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَوَّارٍ الْمِصْرِيُّ حَدَّثَنَا عَبْدَةُ عَنْ عَبْدِ الْمَلِكِ عَنْ عَطَاءٍ عَنْ أَبِي هُرَيْرَةَفِي الْمَرْأَةِ تَصَدَّقُ مِنْ بَيْتِ زَوْجِهَا قَالَ لَا إِلَّا مِنْ قُوتِهَا وَالْأَجْرُ بَيْنَهُمَا وَلَا يَحِلُّ لَهَا أَنْ تَصَدَّقَ مِنْ مَالِ زَوْجِهَا إِلَّا بِإِذْنِهِقَالَ أَبُو دَاوُد هَذَا يُضَعِّفُ حَدِيثَ هَمَّامٍ","id":"Telah menceritakan kepada kami [Muhammad bin Siwar Al Mishri] telah menceritakan kepada kami [Abdah] dari [Abdul Malik] dari [Atha'] dari [Abu Hurairah] RhadhiyAllahu 'anhu mengenai seorang wanita yang bersedekah dari harta suaminya. Ia berkata: tidak boleh, kecuali dari sebagian bahan pokoknya dan pahalanya dibagi anara keduanya, dan tidak halal bagi seorang istri untuk bersedekah dengan harta suaminya kecuali dengan izinnya. Abu Daud berkata: hadits ini melemahkan hadits Hammam. "},"1387":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ هُوَ ابْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَلَمَّا نَزَلَتْ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }قَالَ أَبُو طَلْحَةَ يَا رَسُولَ اللَّهِ أَرَى رَبَّنَا يَسْأَلُنَا مِنْ أَمْوَالِنَا فَإِنِّي أُشْهِدُكَ أَنِّي قَدْ جَعَلْتُ أَرْضِي بِأَرِيحَاءَ لَهُ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْعَلْهَا فِي قَرَابَتِكَ فَقَسَمَهَا بَيْنَ حَسَّانَ بْنِ ثَابِتٍ وَأُبَيِّ بْنِ كَعْبٍقَالَ أَبُو دَاوُد بَلَغَنِي عَنْ الْأَنْصَارِيِّ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ قَالَ أَبُو طَلْحَةَ زَيْدُ بْنُ سَهْلِ بْنِ الْأَسْوَدِ بْنِ حَرَامِ بْنِ عَمْرِو بْنِ زَيْدِ مَنَاةَ بْنِ عَدِيِّ بْنِ عَمْرِو بْنِ مَالِكِ بْنِ النَّجَّارِ وَحَسَّانُ بْنُ ثَابِتِ بْنِ الْمُنْذِرِ بْنِ حَرَامٍ يَجْتَمِعَانِ إِلَى حَرَامٍ وَهُوَ الْأَبُ الثَّالِثُ وَأُبَيُّ بْنُ كَعْبِ بْنِ قَيْسِ بْنِ عَتِيكِ بْنِ زَيْدِ بْنِ مُعَاوِيَةَ بْنِ عَمْرِو بْنِ مَالِكِ بْنِ النَّجَّارِ فَعَمْرٌو يَجْمَعُ حَسَّانَ وَأَبَا طَلْحَةَ وَأُبَيًّا قَالَ الْأَنْصَارِيُّ بَيْنَ أُبَيٍّ وَأَبِي طَلْحَةَ سِتَّةُ آبَاءٍ","id":"Telah menceritakan kepada Kami [Musa bin Isma'il], telah menceritakan kepada Kami [Hammad yaitu Ibnu Salamah] dari [Tsabit] dari [Anas], ia berkata; tatkala turun ayat: \"Kamu sekali-kali tidak sampai kepada kebajikan (yang sempurna), sebelum kamu menafkahkan sehahagian harta yang kamu cintai.\" Abu Thalhah berkata; wahai Rasulullah, aku melihat Tuhan kita meminta sebagian harta kita, aku meminta persaksianmu bahwa aku telah menjadikan tanahku yang berada di Ariha` untuk Allah. Kemudian Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Berikanlah tanah tersebut untuk para kerabatmu!\" Kemudian ia membaginya diantara Hassan bin Tsabit dan Ubai bin Ka'b. Abu Daud berkata; telah sampai kepadaku dari seorang anshar yaitu Muhammad bin Abdullah, ia berkata; Abu Thalhah Zaid bin Sahl bin Al Aswad bin Haram bin 'Amr bin Zaid Manah bin 'Adi bin 'Amr bin Malik bin An Najjar, serta Hassan bin Tsabit bin Al Mundzir bin Haram bertemu nasabnya di Haram, ia adalah ayah ketiga. Sedangkan Ubai bin Ka'b bin Qais bin 'Atik, bin Zaid bin Mu'awiyah bin 'Amr bin Malik bin An Najjar, maka 'Amr mengumpulkan antara Hassan, Abu Thalhah serta Ubai. Orang Anshar tersebut berkata; antara Abu Thalhah dan Ubai terdapat enam ayah. "},"1388":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ عَبْدَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَتْ لِي جَارِيَةٌ فَأَعْتَقْتُهَا فَدَخَلَ عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ فَقَالَ آجَرَكِ اللَّهُ أَمَا إِنَّكِ لَوْ كُنْتِ أَعْطَيْتِهَا أَخْوَالَكِ كَانَ أَعْظَمَ لِأَجْرِكِ","id":"Telah menceritakan kepada Kami [Hannad bin As Sarri] dari ['Abdah] dari [Muhammad bin Ishaq], dari [Bukair bin Abdullah bin Al Asyajj] dari [Sulaiman bin Yasar] dari [Maimunah] istri Rasulullah shallallahu 'alaihi wasallam, ia berkata; aku pernah mempunyai budak wanita yang telah aku bebaskan. Lalu Nabi shalla Allahu 'alaihi wa sallam masuk menemuiku dan aku memberitahukan hal tersebut kepadanya, lalu beliau berkata: \"Mudah-mudahan Allah memberimu pahala, adapun kalau seandainya kamu berikan budak wanita tersebut kepada paman-pamanmu, maka akan menjadi pahala lebih besar bagimu. "},"1389":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالصَّدَقَةِ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ عِنْدِي دِينَارٌ فَقَالَ تَصَدَّقْ بِهِ عَلَى نَفْسِكَ قَالَ عِنْدِي آخَرُ قَالَ تَصَدَّقْ بِهِ عَلَى وَلَدِكَ قَالَ عِنْدِي آخَرُ قَالَ تَصَدَّقْ بِهِ عَلَى زَوْجَتِكَ أَوْ قَالَ زَوْجِكَ قَالَ عِنْدِي آخَرُ قَالَ تَصَدَّقْ بِهِ عَلَى خَادِمِكَ قَالَ عِنْدِي آخَرُ قَالَ أَنْتَ أَبْصَرُ","id":"Telah menceritakan kepada Kami [Muhammad bin Katsir], telah mengabarkan kepada Kami [Sufyan] dari [Muhammad bin 'Ajlan] dari [Al Maqburi] dari [Abu Hurairah], ia berkata; Nabi shallallahu 'alaihi wasallam memerintahkan untuk bersedekah. Kemudian seorang laki-laki berkata; wahai Rasulullah, aku memiliki uang satu dinar. Kemudian beliau bersabda: \"Sedekahkan kepada dirimu!\" Ia berkata; aku memiliki yang lain. Beliau bersabda: \"Sedekahkan kepada anakmu!\" Ia berkata; aku memiliki yang lain. Beliau bersabda: \"Sedekahkan kepada isterimu!\" Ia berkata; aku memiliki yang lain. Beliau bersabda: \"Sedekahkan kepada pembantumu!\" Ia berkata; aku memiliki yang lain. Beliau bersabda: \"Engkau lebih tahu.\""},"1390":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ وَهْبِ بْنِ جَابِرٍ الْخَيْوَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَفَى بِالْمَرْءِ إِثْمًا أَنْ يُضَيِّعَ مَنْ يَقُوتُ","id":"Telah menceritakan kepada Kami [Muhammad bin Katsir], telah mengabarkan kepada Kami [Sufyan], telah menceritakan kepada Kami [Abu Ishaq] dari [Wahb bin Jabir Al Khaiwani] dari [Abdullah bin 'Amr], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Cukuplah dosa bagi seseorang dengan ia menyia-nyiakan orang yang ia tanggung.\""},"1391":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٌ وَيَعْقُوبُ بْنُ كَعْبٍ وَهَذَا حَدِيثُهُ قَالَا حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ الزُّهْرِيِّ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَرَّهُ أَنْ يُبْسَطَ عَلَيْهِ فِي رِزْقِهِ وَيُنْسَأَ فِي أَثَرِهِ فَلْيَصِلْ رَحِمَهُ","id":"Telah menceritakan kepada Kami [Ahmad bin Shalih] dan [Ya'qub bin Ka'bin], dan ini adalah haditsnya, mereka berkata; telah menceritakan kepada Kami [Ibnu Wahb], ia berkata; telah mengabarkan kepadaku [Yunus] dari [Az Zuhri] dari [Anas], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Barang siapa yang ingin dilapangkan rizqinya dan dipanjangkan umurnya maka hendaknya ia menyambung kekerabatan.\""},"1392":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَالَ اللَّهُ أَنَا الرَّحْمَنُ وَهِيَ الرَّحِمُ شَقَقْتُ لَهَا اسْمًا مِنْ اسْمِي مَنْ وَصَلَهَا وَصَلْتُهُ وَمَنْ قَطَعَهَا بَتَتُّهُحَدَّثَنَا مُحَمَّدُ بْنُ الْمُتَوَكِّلِ الْعَسْقَلَانِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ حَدَّثَنِي أَبُو سَلَمَةَ أَنَّ الرَّدَّادَ اللَّيْثِيَّ أَخْبَرَهُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ","id":"Telah menceritakan kepada Kami [Musaddad] dan [Abu Bakr bin Abu Syaibah], mereka berkata; telah menceritakan kepada Kami [Sufyan] dari [Az Zuhri] dari [Abu Salamah] dari [Abdurrahman bin 'Auf], ia berkata; saya mendengar Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Allah berfirman: \"Aku adalah Ar Rahman (Yang Maha Pengasih), rahim (kekerabatan) telah aku ambil dari Namaku, barang siapa yang menyambungnya, maka Aku akan menyambung hubungan dengannya, dan barang siapa yang memutuskannya maka Aku akan memutuskan hubungan dengannya sama sekali.\" Telah menceritakan kepada Kami [Muhammad bin Al Mutawakkil Al 'Asqalani], telah menceritakan kepada Kami [Abdurrazzaq], telah mengabarkan kepada Kami [Ma'mar], dari [Az Zuhri], telah menceritakan kepadaku [Abu Salamah] bahwa [Ar Raddad Al Laitsi] telah mengabarkan kepadanya dari [Abdurrahman bin 'Auf] bahwa ia telah mendengar Rasulullah shallAllahu wa'alaihi wa sallam ……dengan makna seperti hadits tersebut. "},"1393":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَدْخُلُ الْجَنَّةَ قَاطِعُ رَحِمٍ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Sufyan] dari [Az Zuhri] dari [Muhammad bin Jubair bin Muth'im] dari [ayahnya] ia membawanya kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak akan masuk Surga orang yang memutuskan hubungan kekerabatan.\""},"1394":{"ar":"حَدَّثَنَا ابْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَعْمَشِ وَالْحَسَنِ بْنِ عَمْرٍو وَفِطْرٍ عَنْ مُجَاهِدٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ سُفْيَانُ وَلَمْ يَرْفَعْهُ سُلَيْمَانُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَفَعَهُ فِطْرٌ وَالْحَسَنُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ الْوَاصِلُ بِالْمُكَافِئِ وَلَكِنْ هُوَ الَّذِي إِذَا قُطِعَتْ رَحِمُهُ وَصَلَهَا","id":"Telah menceritakan kepada Kami [Ibnu Katsir], telah mengabarkan kepada Kami [Sufyan] dari [Al A'masy] dan [Al Hasan bin 'Amr], serta [Fithr] dari [Mujahid] dari [Abdullah bin 'Amr], Sufyan berkata; dan Sulaiman tidak menisbatkan perkataan tersebut kepada Nabi shallallahu 'alaihi wasallam sedangkan Fithir serta Al Hasan menisbatkannya kepada beliau. Ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Orang yang menyambung bukanlah orang yang membalas kebaikan orang akan tetapi ia adalah orang yang apabila hubungan kekerabatannya diputuskan maka ia menyambungnya.\""},"1395":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَخَطَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِيَّاكُمْ وَالشُّحَّ فَإِنَّمَا هَلَكَ مَنْ كَانَ قَبْلَكُمْ بِالشُّحِّ أَمَرَهُمْ بِالْبُخْلِ فَبَخِلُوا وَأَمَرَهُمْ بِالْقَطِيعَةِ فَقَطَعُوا وَأَمَرَهُمْ بِالْفُجُورِ فَفَجَرُوا","id":"Telah menceritakan kepada Kami [Hafsh bin Umar], telah menceritakan kepada Kami [Syu'bah] dari ['Amr bin Murrah], dari [Abdullah bin Al Harits] dari [Abu Katsir] dari [Abdullah bin 'Amr], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam berkhutbah, beliau bersabda: \"Jauhilah sifat pelit, karena sesungguhnya yang membinasakan orang sebelum kalian adalah sifat pelit. Mereka diperintahkan untuk bersifat bakhil maka merekapun bersifat bakhil dan mereka diperintahkan untuk memutuskan hubungan kekerabatan maka merekapun memutuskan hubungan kekerabatan, dan mereka diperintahkan untuk berbuat dosa maka merekapun berbuat dosa.\""},"1396":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَعِيلُ أَخْبَرَنَا أَيُّوبُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي مُلَيْكَةَ حَدَّثَتْنِي أَسْمَاءُ بِنْتُ أَبِي بَكْرٍ قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ مَا لِي شَيْءٌ إِلَّا مَا أَدْخَلَ عَلَيَّ الزُّبَيْرُ بَيْتَهُ أَفَأُعْطِي مِنْهُ قَالَ أَعْطِي وَلَا تُوكِي فَيُوكَى عَلَيْكِ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Isma'il], telah mengabarkan kepada Kami [Ayyub], telah menceritakan kepada Kami [Abdullah bin Abu Mulaikah], telah menceritakan kepadaku [Asma` binti Abu Bakr], ia berkata; wahai Rasulullah, aku tidak mempunyai apa-apa kecuali hanya apa yang telah dimasukkan Zubair kerumahnya, apakah aku boleh memberikannya? Beliau menjawab: \"Berikanlah dan janganlah kamu menahan pemberian, maka kamu juga akan diperlakukan sama seperti itu.\""},"1397":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَعِيلُ أَخْبَرَنَا أَيُّوبُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةِأَنَّهَا ذَكَرَتْ عِدَّةً مِنْ مَسَاكِينَ قَالَ أَبُو دَاوُد و قَالَ غَيْرُهُ أَوْ عِدَّةً مِنْ صَدَقَةٍ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطِي وَلَا تُحْصِي فَيُحْصَى عَلَيْكِ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Isma'il], telah mengabarkan kepada Kami [Ayyub] dari [Abdullah bin Abu Mulaikah] dari [Aisyah] bahwa ia telah menyebutkan beberapa orang miskin. Abu Daud berkata; sedangkan selainnya mengatakan; atau beberapa sedekah. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepadanya: \"Berikan dan jangan menghitung-hitung pemberianmu, sehingga akan dihitung pemberian kepadamu.\""},"1398":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا شُعْبَةُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ سُوَيْدِ بْنِ غَفَلَةَ قَالَغَزَوْتُ مَعَ زَيْدِ بْنِ صُوحَانَ وَسَلْمَانَ بْنِ رَبِيعَةَ فَوَجَدْتُ سَوْطًا فَقَالَا لِيَ اطْرَحْهُ فَقُلْتُ لَا وَلَكِنْ إِنْ وَجَدْتُ صَاحِبَهُ وَإِلَّا اسْتَمْتَعْتُ بِهِ فَحَجَجْتُ فَمَرَرْتُ عَلَى الْمَدِينَةِ فَسَأَلْتُ أُبَيَّ بْنَ كَعْبٍ فَقَالَ وَجَدْتُ صُرَّةً فِيهَا مِائَةُ دِينَارٍ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عَرِّفْهَا حَوْلًا فَعَرَّفْتُهَا حَوْلًا ثُمَّ أَتَيْتُهُ فَقَالَ عَرِّفْهَا حَوْلًا فَعَرَّفْتُهَا حَوْلًا ثُمَّ أَتَيْتُهُ فَقَالَ عَرِّفْهَا حَوْلًا فَعَرَّفْتُهَا حَوْلًا ثُمَّ أَتَيْتُهُ فَقُلْتُ لَمْ أَجِدْ مَنْ يَعْرِفُهَا فَقَالَ احْفَظْ عَدَدَهَا وَوِكَاءَهَا وَوِعَاءَهَا فَإِنْ جَاءَ صَاحِبُهَا وَإِلَّا فَاسْتَمْتِعْ بِهَا وَقَالَ وَلَا أَدْرِي أَثَلَاثًا قَالَ عَرِّفْهَا أَوْ مَرَّةً وَاحِدَةًحَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ بِمَعْنَاهُ قَالَ عَرِّفْهَا حَوْلًا وَقَالَ ثَلَاثَ مِرَارٍ قَالَ فَلَا أَدْرِي قَالَ لَهُ ذَلِكَ فِي سَنَةٍ أَوْ فِي ثَلَاثِ سِنِينَ حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا سَلَمَةُ بْنُ كُهَيْلٍ بِإِسْنَادِهِ وَمَعْنَاهُ قَالَ فِي التَّعْرِيفِ قَالَ عَامَيْنِ أَوْ ثَلَاثَةً وَقَالَ اعْرِفْ عَدَدَهَا وَوِعَاءَهَا وَوِكَاءَهَا زَادَ فَإِنْ جَاءَ صَاحِبُهَا فَعَرَفَ عَدَدَهَا وَوِكَاءَهَا فَادْفَعْهَا إِلَيْهِ قَالَ أَبُو دَاوُد لَيْسَ يَقُولُ هَذِهِ الْكَلِمَةَ إِلَّا حَمَّادٌ فِي هَذَا الْحَدِيثِ يَعْنِي فَعَرَفَ عَدَدَهَا","id":"Telah menceritakan kepada Kami [Muhammad bin Katsir], telah mengabarkan kepada Kami [Syu'bah] dari [Salamah bin Kuhail] dari [Suwaid bin Ghafalah], ia berkata; aku pernah berperang bersama Zaid bin Shuhan, serta Salman bin Rabi'ah, kemudian aku mendapatkan sebuah cambuk. Kemudian mereka berkata kepadaku; letakkan cambuk itu! Maka aku katakan; tidak, akan tetapi apabila aku mendapatkan pemiliknya maka akan aku berikan kepadanya, jika tidak maka aku akan menikmatinya. Kemudian aku melakukan haji dan melewati Madinah, kemudian aku bertanya kepada [Ubai bin Ka'b], kemudian ia berkata; aku pernah mendapatkan sebuah kantong yang berisi uang seratus dinar. Kemudian aku datang kepada Nabi shallallahu 'alaihi wasallam dan beliau berkata: \"Umumkan selama satu tahun.\" Lalu aku mengumumkannya selama satu tahun, kemudian aku datang kepada beliau, dan beliau berkata: \"Umumkan selama satu tahun.\" Lalu aku umumkan selama satu tahun. Kemudian aku datang kepada beliau dan beliau bersabda: \"Umumkan selama satu tahun.\" Lalu aku mengumumkannya selama satu tahun. Kemudian aku berkata; aku tidak mendapatkan orang yang mengakuinya. Lalu beliau bersabda: \"Simpanlah jumlahnya isinya dan kantong dan talinya. Jika datang pemiliknya maka serahkan dan jika tidak maka manfaatkanlah.\" Dia berkata; saya tidak tahu apakah mengatakannya tiga kali atau umumkanlah sekali saja. Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Yahya], dari [Syu'bah] semakna. Yaitu; \"Umumkanlah satu tahun\" dan dikatakan tiga kali, dan saya tidak mengetahuinya apakah itu dikatakan dalam satu tahun atau dalam tiga tahun. Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] telah menceritakan kepada kami [Salamah bin Kuhail] dengan sanadnya. Hammad menambahkan: \"Apabila pemiliknya telah datang dan mengetahui jumlahnya, serta talinya maka serahkan kepadanya.\" Abu Daud berkata; tidak ada yang mengatakan kalimat ini kecuali Hammad dalam hadits ini, yaitu kata \"dan mengetahui jumlahnya.\""},"1399":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ يَزِيدَ مَوْلَى الْمُنْبَعِثِ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّأَنَّ رَجُلًا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ اللُّقَطَةِ قَالَ عَرِّفْهَا سَنَةً ثُمَّ اعْرِفْ وِكَاءَهَا وَعِفَاصَهَا ثُمَّ اسْتَنْفِقْ بِهَا فَإِنْ جَاءَ رَبُّهَا فَأَدِّهَا إِلَيْهِ فَقَالَ يَا رَسُولَ اللَّهِ فَضَالَّةُ الْغَنَمِ فَقَالَ خُذْهَا فَإِنَّمَا هِيَ لَكَ أَوْ لِأَخِيكَ أَوْ لِلذِّئْبِ قَالَ يَا رَسُولَ اللَّهِ فَضَالَّةُ الْإِبِلِ فَغَضِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى احْمَرَّتْ وَجْنَتَاهُ أَوْ احْمَرَّ وَجْهُهُ وَقَالَ مَا لَكَ وَلَهَا مَعَهَا حِذَاؤُهَا وَسِقَاؤُهَا حَتَّى يَأْتِيَهَا رَبُّهَاحَدَّثَنَا ابْنُ السَّرْحِ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي مَالِكٌ بِإِسْنَادِهِ وَمَعْنَاهُ زَادَ سِقَاؤُهَا تَرِدُ الْمَاءَ وَتَأْكُلُ الشَّجَرَ وَلَمْ يَقُلْ خُذْهَا فِي ضَالَّةِ الشَّاءِ وَقَالَ فِي اللُّقَطَةِ عَرِّفْهَا سَنَةً فَإِنْ جَاءَ صَاحِبُهَا وَإِلَّا فَشَأْنُكَ بِهَا وَلَمْ يَذْكُرْ اسْتَنْفِقْ قَالَ أَبُو دَاوُد رَوَاهُ الثَّوْرِيُّ وَسُلَيْمَانُ بْنُ بِلَالٍ وَحَمَّادُ بْنُ سَلَمَةَ عَنْ رَبِيعَةَ مِثْلَهُ لَمْ يَقُولُوا خُذْهَا","id":"Telah menceritakan kepada Kami [Qutaibah bin Sa'id], telah menceritakan kepada Kami [Isma'il bin Ja'far], dari [Rabi'ah bin Abu Abdurrahman], dari [Yazid] mantan budak Al Munba'its, dari [Zaid bin Khalid Al Juhani], bahwa seorang laki-laki bertanya kepada Rasulullah shallAllahu wa'alaihi wa sallam mengenai barang temuan, beliau berkata: \"Umumkan satu tahun, kemudian ketahuilah talinya dan kantongnya kemudian nafkahkan kepada dirimu. Apabila pemiliknya datang maka berikan kepadanya.\" Lalu orang tersebut berkata; wahai Rasulullah, bagaimana dengan kambing yang tersesat? Beliau bersabda: \"Ambillah kambing tersebut, sesungguhnya kambing tersebut adalah milikmu atau saudaramu atau milik serigala.\" Ia berkata; wahai Rasulullah, bagaiamana dengan unta yang tersesat? Kemudian Rasulullah shallAllahu wa'alaihi wa sallam marah hingga kedua pipinya atau wajahnya memerah. Beliau berkata: \"Apa urusanmu dengannya? Ia memiliki sepatu, dan kantong air minum hingga pemiliknya mendapatkannya.\" Telah menceritakan kepada Kami [Ibnu As Sarh], telah menceritakan kepada Kami [Ibnu Wahb], telah mengabarkan kepadaku [Malik] dengan sanad dan maknanya. Ibnu Wahb menambahkan; kantong air minum, unta tersebut minum air dan memakan pohon. Dan beliau tidak mengatakan: \"Ambillah kambing yang hilang.\" Dan beliau berkata mengenai barang temuan: \"Umumkan selama satu tahun, apabila pemiliknya telah datang maka berikan kepadanya, jika tidak maka urusanmu dengannya.\" Dan beliau tidak menyebutkan nafkahkan kepada dirimu. Abu Daud berkata; [Ats Tsauri] dan [Sulaiman bin Bilal] serta [Hammad bin Salamah] dari [Rabi'ah] seperti itu seperti itu, mereka tidak menyebutkan; \"ambillah barang temuan tersebut.\""},"1400":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ وَهَارُونُ بْنُ عَبْدِ اللَّهِ الْمَعْنَى قَالَا حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ الضَّحَّاكِ يَعْنِي ابْنَ عُثْمَانَ عَنْ سَالِمٍ أَبِي النَّضْرِ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ اللُّقَطَةِ فَقَالَ عَرِّفْهَا سَنَةً فَإِنْ جَاءَ بَاغِيهَا فَأَدِّهَا إِلَيْهِ وَإِلَّا فَاعْرِفْ عِفَاصَهَا وَوِكَاءَهَا ثُمَّ كُلْهَا فَإِنْ جَاءَ بَاغِيهَا فَأَدِّهَا إِلَيْهِ","id":"Telah menceritakan kepada Kami [Muhammad bin Rafi'], dan [Harun bin Abdullah] secara makna, mereka berkata; telah menceritakan kepada Kami [Ibnu Abu Fudaik] dari [Adh Dhahhak yaitu Ibnu Utsman] dari [Salim Abu An Nadhr] dari [Busr bin Sa'id] dari [Zaid bin Khalid Al Juhani] bahwa Rasulullah shallAllahu wa'alaihi wa sallam ditanya mengenai barang temuan. Kemudian beliau berkata: \"Umumkan selama satu tahun, kemudian apabila orang yang mencarinya telah datang maka berikan kepadanya, jika tidak maka katahuilah kantongnya dan talinya kemudian makanlah, kemudian apabila orang yang mencarinya telah datang maka kembalikan kepadanya.\""},"1401":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَفْصٍ حَدَّثَنِي أَبِي حَدَّثَنِي إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ عَبَّادِ بْنِ إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ أَبِيهِ يَزِيدَ مَوْلَى الْمُنْبَعِثِ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ أَنَّهُ قَالَ سُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَ حَدِيثِ رَبِيعَةَقَالَ وَسُئِلَ عَنْ اللُّقَطَةِ فَقَالَ تُعَرِّفُهَا حَوْلًا فَإِنْ جَاءَ صَاحِبُهَا دَفَعْتَهَا إِلَيْهِ وَإِلَّا عَرَفْتَ وِكَاءَهَا وَعِفَاصَهَا ثُمَّ أَفِضْهَا فِي مَالِكَ فَإِنْ جَاءَ صَاحِبُهَا فَادْفَعْهَا إِلَيْهِحَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ يَحْيَى بْنِ سَعِيدٍ وَرَبِيعَةَ بِإِسْنَادِ قُتَيْبَةَ وَمَعْنَاهُ وَزَادَ فِيهِ فَإِنْ جَاءَ بَاغِيهَا فَعَرَفَ عِفَاصَهَا وَعَدَدَهَا فَادْفَعْهَا إِلَيْهِ و قَالَ حَمَّادٌ أَيْضًا عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ قَالَ أَبُو دَاوُد وَهَذِهِ الزِّيَادَةُ الَّتِي زَادَ حَمَّادُ بْنُ سَلَمَةَ فِي حَدِيثِ سَلَمَةَ بْنِ كُهَيْلٍ وَيَحْيَى بْنِ سَعِيدٍ وَعُبَيْدِ اللَّهِ بْنِ عُمَرَ وَرَبِيعَةَ إِنْ جَاءَ صَاحِبُهَا فَعَرَفَ عِفَاصَهَا وَوِكَاءَهَا فَادْفَعْهَا إِلَيْهِ لَيْسَتْ بِمَحْفُوظَةٍ فَعَرَفَ عِفَاصَهَا وَوِكَاءَهَا وَحَدِيثُ عُقْبَةَ بْنِ سُوَيْدٍ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْضًا قَالَ عَرِّفْهَا سَنَةً وَحَدِيثُ عُمَرَ بْنِ الْخَطَّابِ أَيْضًا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَرِّفْهَا سَنَةً","id":"Telah menceritakan kepada Kami [Ahmad bin Hafsh], telah menceritakan kepadaku [ayahku], telah menceritakan kepadaku [Ibrahim bin Thahman], dari ['Abbad bin Ishaq] dari [Abdullah bin Yazid] dari [ayahnya yaitu Yazid] mantan budak Al Munba'its dari [Zaid bin Khalid Al Juhani] bahwa ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam ditanya ….. kemudian ia menyebutkan seperti hadits Rabi'ah. Ia berkata; dan beliau ditanya mengenai barang temuan, lalu beliau mengatakan: \"Engkau umumkan selama satu tahun, kemudian apabila pemiliknya telah datang maka engkau serahkan kepadanya, jika tidak engkau ketahui talinya dan kantongnya, kemudian masukkan ke dalam hartamu, kemudian apabila pemiliknya datang maka serahkan kepadanya.\" Telah menceritakan kepada Kami [Musa bin Isma'il] dari [Hammad bin Salamah] dari [Yahya bin Sa'id] serta [Rabi'ah] dengan sanad Qutaibah, dan maknanya. Dan ia tambahkan dalam hadits tersebut: \"Kemudian apabila orang yang mencarinya telah datang dan mengetahui isinya dan jumlahnya maka serahkan kepadanya.\" [Hammad] juga mengatakan dari ['Ubaidullah bin Umar] dari ['Amr bin Syuiab] dari [ayahnya] dari [kakeknya] dari Nabi shallallahu 'alaihi wasallam seperti itu. Abu Daud berkata; dan tambahan yang disebutkan Hammad bin Salamah dalam hadits Salamah Kuhail, Yahya bin Sa'id serta 'Ubaidullah bin Umar dan Rabi'ah: \"Apabila pemiliknya telah datang dan mengetahui kantong serta talinya maka serahkan kepadanya\" bukanlah kalimat yang mahfuzh yaitu: \"dan mengetahui kandong dan talinya…\", sedangkan hadits Uqbah bin Suwaid dari ayahnya dari Nabi juga beliau bersabda: \"Umumkan selama satu tahun.\" Sedangkan hadits Umar bin Al Khathab juga dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Umumkan selama satu tahun.\""},"1402":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا خَالِدٌ يَعْنِي الطَّحَّانَ ح و حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ الْمَعْنَى عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي الْعَلَاءِ عَنْ مُطَرِّفٍ يَعْنِي ابْنَ عَبْدِ اللَّهِ عَنْ عِيَاضِ بْنِ حِمَارٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ وَجَدَ لُقَطَةً فَلْيُشْهِدْ ذَا عَدْلٍ أَوْ ذَوِي عَدْلٍ وَلَا يَكْتُمْ وَلَا يُغَيِّبْ فَإِنْ وَجَدَ صَاحِبَهَا فَلْيَرُدَّهَا عَلَيْهِ وَإِلَّا فَهُوَ مَالُ اللَّهِ عَزَّ وَجَلَّ يُؤْتِيهِ مَنْ يَشَاءُ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Khalid yaitu Ath Thahhan], dan telah diriwayatkan dari jalu yang lain: Telah menceritakan kepada Kami [Musa bin Isma'il], telah menceritakan kepada Kami [Wuhaib] secara makna, dari [Khalid Al Hadzdza`] dari [Abu Al 'Ala`] dari [Mutharrif yaitu Ibnu Abdullah] dari ['Iyadh bin Himar], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Barang siapa yang mendapatkan barang temuan, maka hendaknya ia memperlihatkan kepada orang yang adil dan tidak menyembunyikannya, kemudian apabila pemiliknya telah datang maka hendaknya ia mengembalikannya kepadanya. Jika tidak maka itu adalah harta Allah 'azza wajalla yang diberikan kepada orang yang Dia kehendaki.\""},"1403":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ بُكَيْرِ بْنِ الْأَشَجِّ عَنْ عُبَيْدِ اللَّهِ بْنِ مِقْسَمٍ حَدَّثَهُ عَنْ رَجُلٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ عَلِيَّ بْنَ أَبِي طَالِبٍ وَجَدَ دِينَارًا فَأَتَى بِهِ فَاطِمَةَ فَسَأَلَتْ عَنْهُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هُوَ رِزْقُ اللَّهِ عَزَّ وَجَلَّ فَأَكَلَ مِنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَكَلَ عَلِيٌّ وَفَاطِمَةُ فَلَمَّا كَانَ بَعْدَ ذَلِكَ أَتَتْهُ امْرَأَةٌ تَنْشُدُ الدِّينَارَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَلِيُّ أَدِّ الدِّينَارَ","id":"Telah menceritakan kepada Kami [Muhammad bin Al 'Ala`], telah menceritakan kepada Kami [Abdullah bin Wahb] dari ['Amr bin Al Harits] dari [Bukair bin Al Asyajj] dari ['Ubaidullah bin Miqsam] menceritakannya, dari [seorang laki-laki] dari [Abu Sa'id Al Khudri radliallahu 'anhu] bahwasanya Ali Bin Abu Thalib radliallahu 'anhu menemukan uang satu dinar, kemudian membawanya kepada Fathimah radliallahu 'anha, lalu ia menanyakannya kepada Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallla Allahu 'alaihi wa sallam berkata: itu adalah rizqi dari Allah 'azza wajalla, kemudian beliau memakannya dan begitu juga Ali serta Fathimah. Kemudian setelah itu seorang wanita datang kepada beliau mengumumkan kehilangan uang satu dinar, maka Rasulullah shallallahu 'alaihi wasallam mengatakan kepada Ali: wahai Ali, berikan uang satu dinar tersebut kepadanya. "},"1404":{"ar":"حَدَّثَنَا الْهَيْثَمُ بْنُ خَالِدٍ الْجُهَنِيُّ حَدَّثَنَا وَكِيعٌ عَنْ سَعْدِ بْنِ أَوْسٍ عَنْ بِلَالِ بْنِ يَحْيَى الْعَبْسِيِّ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُأَنَّهُ الْتَقَطَ دِينَارًا فَاشْتَرَى بِهِ دَقِيقًا فَعَرَفَهُ صَاحِبُ الدَّقِيقِ فَرَدَّ عَلَيْهِ الدِّينَارَ فَأَخَذَهُ عَلِيٌّ وَقَطَعَ مِنْهُ قِيرَاطَيْنِ فَاشْتَرَى بِهِ لَحْمًا","id":"Telah menceritakan kepada Kami [Al Haitsam bin Khalid Al Juhani], telah menceritakan kepada Kami [Waki'] dari [Sa'd bin Aus] dari [Bilal bin Yahya Al 'Absi] dari [Ali Bin Abu Thalib radliallahu 'anhu] bahwa ia menemukan uang satu dinar lalu dia menggunakannya untuk membeli tepung, pedagang tepung mengetahuinya, kemudian ia mengembalikan uang dinar tersebut kepadanya dan Ali pun mengambilnya lalu dia memotongn sebagian darinya dua kirath lalu ia gunakan untuk membeli daging. "},"1405":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ عَبْدِ الرَّحْمَنِ الدِّمَشْقِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبٍ عَنْ الْمُغِيرَةِ بْنِ زِيَادٍ عَنْ أَبِي الزُّبَيْرِ الْمَكِّيِّ أَنَّهُ حَدَّثَهُ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَرَخَّصَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْعَصَا وَالسَّوْطِ وَالْحَبْلِ وَأَشْبَاهِهِ يَلْتَقِطُهُ الرَّجُلُ يَنْتَفِعُ بِهِقَالَ أَبُو دَاوُد رَوَاهُ النُّعْمَانُ بْنُ عَبْدِ السَّلَامِ عَنْ الْمُغِيرَةِ أَبِي ��َلَمَةَ بِإِسْنَادِهِ وَرَوَاهُ شَبَابَةُ عَنْ مُغِيرَةَ بْنِ مُسْلِمٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَ كَانُوا لَمْ يَذْكُرُوا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada Kami [Sulaiman bin Abdurrahman Ad Damasyqi], telah menceritakan kepada Kami [Muhammad bin Syu'aib] dari [Al Mughirah bin Ziyad] dari [Abu Az Zubair Al Makki] bahwa ia menceritakan kepadanya, dari [Jabir bin Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam memberikan keringanan kepada Kami untuk menggunakan tongkat, pecut, tali dan yang semisalnya yang Kami temukan. Abu Daud berkata; hadits ini diriwayatkan [An Nu'man bin Abdussalam] dari [Al Mughirah Abu Salamah] dengan sanadnya. Dan diriwayatkan oleh [Syababah] dari [Al Mughirah bin Muslim] dari [Abu Az Zubair] dari [Jabir], ia berkata; mereka tidak menyebutkan Nabi Shalla Allahu 'alaihi wa sallam. "},"1406":{"ar":"حَدَّثَنَا مَخْلَدُ بْنُ خَالِدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ عَمْرِو بْنِ مُسْلِمٍ عَنْ عِكْرِمَةَ أَحْسَبُهُ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ضَالَّةُ الْإِبِلِ الْمَكْتُومَةُ غَرَامَتُهَا وَمِثْلُهَا مَعَهَا","id":"Telah menceritakan kepada Kami [Makhlad bin Khalid], telah menceritakan kepada Kami [Abdurrazzaq], telah mengabarkan kepada Kami [Ma'mar] dari ['Amr bin Muslim] dari [Ikrimah], aku mengira dari [Abu Hurairah] radliallahu 'anhu bahwa Nabi shalla Allahu 'alaihi wa sallam bersabda: \"Unta yang terlepas yang disembunyikan maka dendanya adalah seperti onta tersebut dan ditambah dengan yang semisalnya."},"1407":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ خَالِدِ بْنِ مَوْهَبٍ وَأَحْمَدُ بْنُ صَالِحٍ قَالَا حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو عَنْ بُكَيْرٍ عَنْ يَحْيَى بْنِ عَبْدِ الرَّحْمَنِ بْنِ حَاطِبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عُثْمَانَ التَّيْمِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ لُقَطَةِ الْحَاجِّقَالَ أَحْمَدُ قَالَ ابْنُ وَهْبٍ يَعْنِي فِي لُقَطَةِ الْحَاجِّ يَتْرُكُهَا حَتَّى يَجِدَهَا صَاحِبُهَا قَالَ ابْنُ مَوْهَبٍ عَنْ عَمْرٍو","id":"Telah menceritakan kepada Kami [Yazid bin Khalid bin Mauhib] serta [Ahmad bin Shalih], mereka berkata; telah menceritakan kepada Kami [Ibnu Wahb], telah mengabarkan kepadaku ['Amr] dari [Bukair] dari [Yahya bin Abdurrahman bin Hathib] dari [Abdurrahman bin Utsman At Taimi] bahwa Rasulullah shallAllahu wa'alaihi wa sallam melarang dari barang temuan dari orang yang melakukan haji. Ahmad berkata; Ibnu Wahb berkata mengenai barang temuan dari orang yang melakukan haji; ia tinggalkan hingga ditemukan pemiliknya. Ibnu Mauhib berkata; dari 'Amr. "},"1408":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ الْمَعْنَى قَالَا حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ سُفْيَانَ بْنِ حُسَيْنٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي سِ��َانٍ عَنْ ابْنِ عَبَّاسٍأَنَّ الْأَقْرَعَ بْنَ حَابِسٍ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ الْحَجُّ فِي كُلِّ سَنَةٍ أَوْ مَرَّةً وَاحِدَةً قَالَ بَلْ مَرَّةً وَاحِدَةً فَمَنْ زَادَ فَهُوَ تَطَوُّعٌقَالَ أَبُو دَاوُد هُوَ أَبُو سِنَانٍ الدُّؤَلِيُّ كَذَا قَالَ عَبْدُ الْجَلِيلِ بْنُ حُمَيْدٍ وَسُلَيْمَانُ بْنُ كَثِيرٍ جَمِيعًا عَنْ الزُّهْرِيِّ و قَالَ عُقَيْلٌ عَنْ سِنَانٍ","id":"Telah menceritakan kepada Kami [Zuhair bin Harb] dan [Utsman bin Abu Syaibah] secara makna, mereka berkata; telah menceritakan kepada Kami [Yazid bin Harun], dari [Sufyan bin Husain] dari [Az Zuhri] dari [Abu Sinan] dari [Ibnu Abbas] bahwa Al Aqra` bin Habis bertanya kepada Nabi shallallahu 'alaihi wasallam, ia berkata; wahai Rasulullah, apakah haji wajib pada setiap tahun atau satu kali? Beliau bersabda: \"Satu kali, barang siapa yang menambahkan maka hal tersebut adalah sebuah sunah.\" Abu Daud berkata; ia adalah Abu Sinan Ad Duali demikian yang dikatakan [Abdul Jalil bin Humaid] serta [Sulaiman bin Katsir] dari [Az Zuhri], sedangkan ['Uqail] mengatakan; dari [Sinan]. "},"1409":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ ابْنٍ لِأَبِي وَاقِدٍ اللَّيْثِيِّ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لِأَزْوَاجِهِ فِي حَجَّةِ الْوَدَاعِ هَذِهِ ثُمَّ ظُهُورَ الْحُصْرِ","id":"Telah menceritakan kepada Kami [An Nufaili] telah menceritakan kepada Kami [Abdul Aziz bin Muhammad] dari [Zaid bin Aslam] dari [anak Abu Waqid Al Laitsi] dari [ayahnya], ia berkata; saya mendengar Rasulullah shallAllahu wa'alaihi wa sallam berkata kepada para isterinya pada saat haji wada'; sesungguhnya haji tersebut adalah ini, kemudian kalian harus tinggal di rumah kalian dan tidak wajib berhaji. "},"1410":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ الثَّقَفِيُّ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِيهِ أَنَّ أَبَا هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحِلُّ لِامْرَأَةٍ مُسْلِمَةٍ تُسَافِرُ مَسِيرَةَ لَيْلَةٍ إِلَّا وَمَعَهَا رَجُلٌ ذُو حُرْمَةٍ مِنْهَاحَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ وَالنُّفَيْلِيُّ عَنْ مَالِكٍ ح و حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا بِشْرُ بْنُ عُمَرَ حَدَّثَنِي مَالِكٌ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ قَالَ الْحَسَنُ فِي حَدِيثِهِ عَنْ أَبِيهِ ثُمَّ اتَّفَقُوا عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ تُسَافِرَ يَوْمًا وَلَيْلَةً فَذَكَرَ مَعْنَاهُ قَالَ أَبُو دَاوُد وَلَمْ يَذْكُرْ الْقَعْنَبِيُّ وَالنُّفَيْلِيُّ عَنْ أَبِيهِ رَوَاهُ ابْنُ وَهْبٍ وَعُثْمَانُ بْنُ عُمَرَ عَنْ مَالِكٍ كَمَا قَالَ الْقَعْنَبِيُّ حَدَّثَنَا يُوسُفُ بْنُ مُوسَى عَنْ جَرِيرٍ عَنْ سُهَيْلٍ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَهُ إِلَّا أَنَّهُ قَالَ بَرِيدًا","id":"Telah menceritakan kepada Kami [Qutaibah bin Sa'id Ats Tsaqafi], telah menceritakan kepada Kami [Al Laits bin Sa'd] dari [Sa'id bin Abu Sa'id] dari [ayahnya] bahwa [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal bagi seorang wanita muslimah untuk bersafar sejauh perjalanan satu malam kecuali bersama dengan seorang laki-laki yang memiliki hubungan mahram dengannya.\" Telah menceritakan kepada Kami [Abdullah bin Maslamah] dan [An Nufaili] dari [Malik], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada Kami [Al Hasan bin Ali], telah menceritakan kepada Kami [Bisyr bin Umar], telah menceritakan kepadaku [Malik] dari [Sa'id bin Abu Sa'id], Al Hasan dalam haditsnya berkata; dari [ayahnya], kemudian mereka sama-sama dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: 'Tidak halal bagi seorang wanita yang beriman kepada Allah dan Hari Akhir untuk bersafar satu hari satu malam …. Ia menyebutkan maknanya. Abu Daud berkata; Al Qa'nabi dan An Nufaili tidak menyebutkan; dari ayahnya. [Ibnu Wahb], serta [Utsman bin Umar] telah meriwayatkan dari [Malik] sebagaimana yang dikatakan Al Qa'nabi. Telah menceritakan kepada Kami [Yusuf bin Musa] dari [Jarir] dari [Suhail] dari [Sa'id bin Abu Sa'id] dari [Abu Hurairah], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"…..\" kemudian ia menyebutkan hadits seperti itu hanya saja ia berkata; selama"},"1411":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَهَنَّادٌ أَنَّ أَبَا مُعَاوِيَةَ وَوَكِيعًا حَدَّثَاهُمْ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ تُسَافِرَ سَفَرًا فَوْقَ ثَلَاثَةِ أَيَّامٍ فَصَاعِدًا إِلَّا وَمَعَهَا أَبُوهَا أَوْ أَخُوهَا أَوْ زَوْجُهَا أَوْ ابْنُهَا أَوْ ذُو مَحْرَمٍ مِنْهَا","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah] dan [Hannad] bahwa [Abu Mu'awiyah] dan [Waki'] telah menceritakan kepada mereka dari [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Tidak halal bagi seorang wanita yang beriman kepada Allah dan Hari Akhir untuk bersafar lebih dari tiga hari, keculai bersama ayahnya atau saudaranya atau suaminya atau anaknya atau orang yang mahram dengannya.\""},"1412":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُسَافِرُ الْمَرْأَةُ ثَلَاثًا إِلَّا وَمَعَهَا ذُو مَحْرَمٍ","id":"Telah menceritakan kepada Kami [Ahamd bin Hanbal], telah menceritakan kepada Kami [Yahya bin Sa'id] dari ['Ubaidullah], ia berkata; telah menceritakan kepadaku [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak boleh seorang wanita bersafar tiga hari kecuali bersama mahramnya.\""},"1413":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍأَنَّ ابْنَ عُمَرَ كَانَ يُرْدِفُ مَوْلَاةً لَهُ يُقَالُ لَهَا صَفِيَّةُ تُسَافِرُ مَعَهُ إِلَى مَكَّةَ","id":"Telah menceritakan kepada Kami [Nashr bin Ali], telah menceritakan kepada Kami [Abu Ahmad], telah menceritakan kepada Kami [Sufyan] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma bahwa ia membonceng budak wanitanya yang bernama Shafiyyah ketika bepergian ke Mekkah."},"1414":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ يَعْنِي سُلَيْمَانَ بْنَ حَيَّانَ الْأَحْمَرَ عَنْ ابْنِ جُرَيْجٍ عَنْ عُمَرَ بْنِ عَطَاءٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا صَرُورَةَ فِي الْإِسْلَامِ","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Abu Khalid yaitu Sulaiman bin Hayyan Al Ahmar] dari [Ibnu Juraij] dari [Umar bin 'Atho`], dari ['Ikrimah] dari [Ibnu Abbas], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam: \"Tidak (ada) hidup membujang dalam Islam.\""},"1415":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْفُرَاتِ يَعْنِي أَبَا مَسْعُودٍ الرَّازِيَّ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْمَخْرَمِيُّ وَهَذَا لَفْظُهُ قَالَا حَدَّثَنَا شَبَابَةُ عَنْ وَرْقَاءَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَكَانُوا يَحُجُّونَ وَلَا يَتَزَوَّدُونَ قَالَ أَبُو مَسْعُودٍ كَانَ أَهْلُ الْيَمَنِ أَوْ نَاسٌ مِنْ أَهْلِ الْيَمَنِ يَحُجُّونَ وَلَا يَتَزَوَّدُونَ وَيَقُولُونَ نَحْنُ الْمُتَوَكِّلُونَ فَأَنْزَلَ اللَّهُ سُبْحَانَهُ{ وَتَزَوَّدُوا فَإِنَّ خَيْرَ الزَّادِ التَّقْوَى }الْآيَةَ","id":"Telah menceritakan kepada Kami [Ahmad bin Al Furat yaitu Abu Mas'ud Ar Razi], serta [Muhammad bin Abdullah Al Makhrami], dan ini adalah lafazhnya, mereka berkata; telah menceritakan kepada Kami [Syababah] dari [Warqa`] dari ['Amr bin Dinar] dari ['Ikrimah] dari [Ibnu Abbas], ia berkata; dahulu mereka pergi untuk melaksanakan haji, namun tidak membawa bekal. Abu Mas'ud berkata; dahulu penduduk Yaman atau orang-orang dari penduduk Yaman pergi melaksanakan haji namun tidak membawa bekal dan mereka mengatakan; Kami adalah orang-orang yang bertawakkal kepada Allah. Kemudian Allah menurunkan ayat: \"Dan berbekAllah, dan sebaik-baik bekal adalah ketakwaan.\""},"1416":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا جَرِيرٌ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ مُجَاهِدٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَقَرَأَ هَذِهِ الْآيَةَ{ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَبْتَغُوا فَضْلًا مِنْ رَبِّكُمْ }قَالَ كَانُوا لَا يَتَّجِرُونَ بِمِنًى فَأُمِرُوا بِالتِّجَارَةِ إِذَا أَفَاضُوا مِنْ عَرَفَاتٍ","id":"Telah menceritakan kepada Kami [Yusuf bin Musa] telah menceritakan kepada Kami [Jarir] dari [Yazid bin Abu Ziyad] dari [Mujahid] dari [Abdullah bin Abbas], ia membaca ayat \"Tidak ada dosa bagimu untuk mencari karunia (rezki hasil perniagaan) dari Tuhanmu.\" Ia berkata; dahulu mereka tidak mengadakan perdagangan di Mina, setelah ayat ini turun mereka diperintahkan untuk mengadakan perdagangan setelah mereka selesai dari arafat. "},"1417":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ مُحَمَّدُ بْنُ خَازِمٍ عَنْ الْحَسَنِ بْنِ عَمْرٍو عَنْ مِهْرَانَ أَبِي صَفْوَانَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَرَادَ الْحَجَّ فَلْيَتَعَجَّلْ","id":"Telah menceritakan kepada Kami [Musaddad] telah menceritakan kepada Kami [Abu Mu'awiyah, Muhammad bin Khazin] dari [Al Hasan bin 'Amr] dari [Mihran Abu Shawan] dari [Ibnu Abbas], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Barang siapa yang hendak berhaji, maka hendaknya ia bersegera.\""},"1418":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا الْعَلَاءُ بْنُ الْمُسَيِّبِ حَدَّثَنَا أَبُو أُمَامَةَ التَّيْمِيُّ قَالَكُنْتُ رَجُلًا أُكَرِّي فِي هَذَا الْوَجْهِ وَكَانَ نَاسٌ يَقُولُونَ لِي إِنَّهُ لَيْسَ لَكَ حَجٌّ فَلَقِيتُ ابْنَ عُمَرَ فَقُلْتُ يَا أَبَا عَبْدِ الرَّحْمَنِ إِنِّي رَجُلٌ أُكَرِّي فِي هَذَا الْوَجْهِ وَإِنَّ نَاسًا يَقُولُونَ لِي إِنَّهُ لَيْسَ لَكَ حَجٌّ فَقَالَ ابْنُ عُمَرَ أَلَيْسَ تُحْرِمُ وَتُلَبِّي وَتَطُوفُ بِالْبَيْتِ وَتُفِيضُ مِنْ عَرَفَاتٍ وَتَرْمِي الْجِمَارَ قَالَ قُلْتُ بَلَى قَالَ فَإِنَّ لَكَ حَجًّا جَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ عَنْ مِثْلِ مَا سَأَلْتَنِي عَنْهُ فَسَكَتَ عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يُجِبْهُ حَتَّى نَزَلَتْ هَذِهِ الْآيَةُ{ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَبْتَغُوا فَضْلًا مِنْ رَبِّكُمْ }فَأَرْسَلَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَرَأَ عَلَيْهِ هَذِهِ الْآيَةَ وَقَالَ لَكَ حَجٌّ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Abdul Wahid bin Ziyad], telah menceritakan kepada Kami [Al 'Ala` bin Al Musayyab], telah menceritakan kepada Kami [Abu Umamah At Taimi], ia berkata; aku menyewakan sesuatu pada saat perjalanan untuk berhaji, orang-orang mengatakan; engkau tidak mendapatkan pahala haji, kemudian aku menemui [Ibnu Umar] dan aku katakan; wahai Abdurrahman, aku adalah orang yang menyewakan sesuatu saat perjalanan untuk berhaji, dan orang-orang mengatakan bahwa aku tidak mendapatkan pahala haji? Maka Ibnu Umar berkata; bukankah kamu berihram, mengucapkan talbiyah (niat), dan melakukan thawaf di ka'bah, bertolak dari Arafah dan melempar jumrah? Aku menjawab: ya! Dia berkata; kamu mendapatkan pahala haji. Telah datang datang seorang laki-laki kepada Rasulullah shallallahu 'alaihi wasallam dan bertanyakan apa yang engkau tanyakan kepadaku, kemudian Nabi shalla Allahu 'alaihi wa sallam tidak menjawabnya hingga ayat ini turun: \"Tidak ada dosa bagimu untuk mencari karunia (rezki hasil perniagaan) dari Tuhanmu.\" Kemudian Rasulullah shallallahu 'alaihi wasallam mengutus seseorang untuk membacakan ayat ini dan mengatakan kepada orang yang bertanya: engkau mendapatkan pahala haji. "},"1419":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا حَمَّادُ بْنُ مَسْعَدَةَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّ النَّاسَ فِي أَوَّلِ الْحَجِّ كَانُوا يَتَبَايَعُونَ بِمِنًى وَعَرَفَةَ وَسُوقِ ذِي الْمَجَازِ وَمَوَاسِمِ الْحَجِّ فَخَافُوا الْبَيْعَ وَهُمْ حُرُمٌ فَأَنْزَلَ اللَّهُ سُبْحَانَهُ{ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَبْتَغُوا فَضْلًا مِنْ رَبِّكُمْ }فِي مَوَاسِمِ الْحَجِّقَالَ فَحَدَّثَنِي عُبَيْدُ بْنُ عُمَيْرٍ أَنَّهُ كَانَ يَقْرَؤُهَا فِي الْمُصْحَفِ حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ أَخْبَرَنِي ابْنُ أَبِي ذِئْبٍ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ قَالَ أَحْمَدُ بْنُ صَالِحٍ كَلَامًا مَعْنَاهُ أَنَّهُ مَوْلَى ابْنِ عَبَّاسٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ أَنَّ النَّاسَ فِي أَوَّلِ مَا كَانَ الْحَجُّ كَانُوا يَبِيعُونَ فَذَكَرَ مَعْنَاهُ إِلَى قَوْلِهِ مَوَاسِمِ الْحَجِّ","id":"Telah menceritakan kepada Kami [Muhammad bin Basysyar] telah menceritakan kepada Kami [Hammad bin Mas'adah], telah menceritakan kepada Kami [Ibnu Abu Dzi`bin] dari ['Atha` bin Abu Rabah] dari ['Ubaid bin 'Umair] dari [Abdullah bin Abbas] bahwa orang-orang ketika perkatama kali melakukan haji mereka tidak berjual beli di Mina serta 'Arafah dan pasar Dzul Majaz, serta pada musim-musim haji. Mereka khawatir berjual beli sementara mereka sedang berihram. Kemudian Allah menurunkan ayat: \"Tidak ada dosa bagimu untuk mencari karunia (rezki hasil perniagaan) dari Tuhanmu, \" Pada Musim-musim haji. Ia berkata; telah menceritakan kepadaku 'Ubaid bin 'Umair bahwa ia membaca ayat tersebut di dalam mushhaf. Telah menceritakan kepada Kami [Ahmad bin Shalih], telah menceritakan kepada Kami [Ibnu Abu Fudaik], telah mengabarkan kepada Kami [Ibnu Abu Dzi`b] dari ['Ubaid bin 'Umair]. Ahmad bin Shalih mengatakan sebuah perkataan yang maknanya bahwa ia adalah mantan budak Ibnu Abbas dari [Abdullah bin Abbas] bahwa pertama kali haji mereka berjual beli, …… -kemudian ia menyebutkan secara makna hingga perkataannya; dan musim-musim haji. "},"1420":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ إِبْرَاهِيمَ بْنِ عُقْبَةَ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالرَّوْحَاءِ فَلَقِيَ رَكْبًا فَسَلَّمَ عَلَيْهِمْ قَالَ مَنْ الْقَوْمُ فَقَالُوا الْمُسْلِمُونَ فَقَالُوا فَمَنْ أَنْتُمْ قَالُوا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَفَزِعَتْ امْرَأَةٌ فَأَخَذَتْ بِعَضُدِ صَبِيٍّ فَأَخْرَجَتْهُ مِنْ مِحَفَّتِهَا قَالَتْ يَا رَسُولَ اللَّهِ هَلْ لِهَذَا حَجٌّ قَالَ نَعَمْ وَلَكِ أَجْرٌ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Sufyan bin 'Uyainah] dari [Ibrahim bin 'Uqbah] dari [Kuraib] dari [Ibnu Abbas], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam pernah berada di Rauha`, kemudian bertemu dengan orang-orang yang menunggang kendaraan. Beliau bertanya: \"Siapakah kalian ini?\" Mereka berkata; Kami adalah orang-orang muslim. Kemudian mereka berkata; dan siapakah kalian? Para sahabat berkata; Rasulullah shallAllahu wa'alaihi wa sallam. Kemudian terdapat seorang wanita yang kaget, lalu ia memegang lengan seorang anak kecil dan mengeluarkannya dari tandunya dan berkata; wahai Rasulullah, apakah anak ini boleh melakukan haji? Beliau bersabda: \"Ya, dan engkau akan mendapatkan pahala.\""},"1421":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ ح و حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَوَقَّتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَهْلِ الْمَدِينَةِ ذَا الْحُلَيْفَةِ وَلِأَهْلِ الشَّامِ الْجُحْفَةَ وَلِأَهْلِ نَجْدٍ قَرْنَ وَبَلَغَنِي أَنَّهُ وَقَّتَ لِأَهْلِ الْيَمَنِ يَلَمْلَمَحَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ وَعَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ قَالَا وَقَّتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ وَقَالَ أَحَدُهُمَا وَلِأَهْلِ الْيَمَنِ يَلَمْلَمَ وَقَالَ أَحَدُهُمَا أَلَمْلَمَ قَالَ فَهُنَّ لَهُمْ وَلِمَنْ أَتَى عَلَيْهِنَّ مِنْ غَيْرِ أَهْلِهِنَّ مِمَّنْ كَانَ يُرِيدُ الْحَجَّ وَالْعُمْرَةَ وَمَنْ كَانَ دُونَ ذَلِكَ قَالَ ابْنُ طَاوُسٍ مِنْ حَيْثُ أَنْشَأَ قَالَ وَكَذَلِكَ حَتَّى أَهْلُ مَكَّةَ يُهِلُّونَ مِنْهَا","id":"Telah menceritakan kepada Kami [Qa'nabi], dari [Malik]. Dan telah diriwayatkan dari jalur yang lain: telah menceritakan kepada Kami [Ahmad bin Yunus], telah menceritakan kepada Kami [Malik] dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam menetapkan Dzul Hulaifah sebagai miqat bagi penduduk Madinah Al Juhfah, serta bagi penduduk Najd Qarnul manazil, dan telah sampai kepadaku berita bahwa beliau menetapkan Yalamlam sebagai miqat penduduk Yaman. Telah menceritakan kepada Kami [Sulaiman bin Harb], telah menceritakan kepada Kami [Hammad] dari ['Amr bin Dinar] dari [Thawus] dari [Ibnu Abbas], dan dari [Ibnu Thawus] dari [ayahnya], mereka berkata; Rasulullah shallAllahu wa'alaihi wa sallam telah menetapkan …… -secara makna-. Dan salah seorang diantara mereka berkata; dan Yalamlam sebagai miqat bagi penduduk Yaman. Sedangkan salah seorang dari mereka berkata; Alamlam. Beliau bersabda: Tempat-tempat tersebut adalah miqat untuk mereka dan orang yang datang ke tempat-tempat tersebut yang bukan penduduknya, diantara orang yang ingin berhaji dan berumrah. Dan orang yang diluar hal tersebut Thawus berkata; maka dari tempat ia memulai berihram.\" Ia berkata; dan seperti itu hingga penduduk Mekkah, mereka bertalbiyah darinya. "},"1422":{"ar":"حَدَّثَنَا هِشَامُ بْنُ بَهْرَامَ الْمَدَائِنِيُّ حَدَّثَنَا الْمُعَافِىُّ بْنُ عِمْرَانَ عَنْ أَفْلَحَ يَعْنِي ابْنَ حُمَيْدٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَّتَ لِأَهْلِ الْعِرَاقِ ذَاتَ عِرْقٍ","id":"Telah menceritakan kepada Kami [Hisyam bin Bahram Al Madaini], telah menceritakan kepada Kami [Al Mu'afi bin 'Imran] dari [Aflah yaitu Ibnu Humaid] dari [Al Qasim bin Muhammad] dari [Aisyah] radliallahu 'anha bahwa Rasulullah shallla Allahu 'alaihi wa sallam menetapkan Dzatu 'Irq sebagai miqat bagi penduduk Irak. "},"1423":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ حَنْبَلٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ مُحَمَّدِ بْنِ عَلِيِّ بْنِ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ قَالَوَقَّتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَهْلِ الْمَشْرِقِ الْعَقِيقَ","id":"Telah menceritakan kepada Kami [Ahmad bin Muhammad bin Hanbal], telah menceritakan kepada Kami [Waki'], telah menceritakan kepada Kami [Sufyan] dari [Yazid bin Abu Ziyad] dari [Muhammad bin Ali bin Abdullah bin Abbas] dari [Ibnu Abbas] radliallahu 'anhu, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: Bagi penduduk bagian timur miqatnya adalah Al 'Aqiq. "},"1424":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ يُحَنَّسَ عَنْ يَحْيَى بْنِ أَبِي سُفْيَانَ الْأَخْنَسِيِّ عَنْ جَدَّتِهِ حُكَيْمَةَ عَنْ أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّهَا سَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَهَلَّ بِحَجَّةٍ أَوْ عُمْرَةٍ مِنْ الْمَسْجِدِ الْأَقْصَى إِلَى الْمَسْجِدِ الْحَرَامِ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَمَا تَأَخَّرَ أَوْ وَجَبَتْ لَهُ الْجَنَّةُ شَكَّ عَبْدُ اللَّهِ أَيَّتُهُمَا قَالَقَالَ أَبُو دَاوُد يَرْحَمُ اللَّهُ وَكِيعًا أَحْرَمَ مِنْ بَيْتِ الْمَقْدِسِ يَعْنِي إِلَى مَكَّةَ","id":"Telah menceritakan kepada Kami [Ahmad bin Shalih], telah menceritakan kepada Kami [Ibnu Abu Fudaik] dari [Abdullah bin Abdurrahman bin Yuhannas] dari [Yahya bin Abu Sufyan Al Akhnasi] dari [neneknya yaitu Hukaimah] dari [Ummu Salamah] istri Nabi shalla Allahu 'alaihi wa sallam bahwa ia telah mendengar Nabi shalla Allahu 'alaihi wa sallam bersabda: \"Barangsiapa yang bertalbiyah untuk melakukan haji atau umrah dari Masjid Al Aqsha hingga Masjid Al Haram maka akan dihapuskan dosanya yang telah lalu dan yang akan datang, atau wajib ia mendapatkan Surga. Abdullah merasa ragu yang manakah yang beliau ucapkan. Abu Daud berkata; semoga Allah merahmati Waki' sebab dia telah melaksanakan ihram dari Baitul Maqdis sampai ke Mekkah. "},"1425":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ عَبْدُ اللَّهِ بْنُ عَمْرِو بْنِ أَبِي الْحَجَّاجِ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا عُتْبَةُ بْنُ عَبْدِ الْمَلِكِ السَّهْمِيُّ حَدَّثَنِي زُرَارَةُ بْنُ كُرِيْمٍ أَنَّ الْحَارِثَ بْنَ عَمْرٍو السَّهْمِيَّ حَدَّثَهُ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ بِمِنًى أَوْ بِعَرَفَاتٍ وَقَدْ أَطَافَ بِهِ النَّاسُ قَالَ فَتَجِيءُ الْأَعْرَابُ فَإِذَا رَأَوْا وَجْهَهُ قَالُوا هَذَا وَجْهٌ مُبَارَكٌ قَالَ وَوَقَّتَ ذَاتَ عِرْقٍ لِأَهْلِ الْعِرَاقِ","id":"Telah menceritakan kepada Kami [Abu Ma'mar Abdullah bin 'Amr bin Abu Al Hajjaj], telah menceritakan kepada Kami [Abdul Warits], telah menceritakan kepada Kami ['Utbah bin Abdul Malik As Sahmi], telah menceritakan kepadaku [Zurarah bin Kuraim] bahwa [Al Harits bin 'Amr As Sahmi] telah menceritakan kepadanya, ia berkata; saya datang kepada Rasulullah shallAllahu wa'alaihi wa sallam, sementara beliau berada di Mina atau 'Arafah, dan orang-orang telah mengelilingi beliau. Al Harits bin 'Amr berkata; kemudian beberapa orang badui datang dan melihat wajah beliau, mereka berkata; ini adalah wajah yang mendapat berkah. Al Harits berkata; dan beliau menetapkan Dzatu 'Irq sebagai miqat bagi penduduk Irak. "},"1426":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ عَنْ عُبَيْدِ اللَّهِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْنُفِسَتْ أَسْمَاءُ بِنْتُ عُمَيْسٍ بِمُحَمَّدِ بْنِ أَبِي بَكْرٍ بِالشَّجَرَةِ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَا بَكْرٍ أَنْ تَغْتَسِلَ فَتُهِلَّ","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami ['Abdah] dari ['Ubaidullah] dari [Abdurrahman bin Al Qasim] dari [ayahnya] dari [Aisyah], ia berkata; Asma` binti 'Umais mengalami nifas karena melahirkan Muhammad bin Abu Bakr di bawah pohon. Kemudian Rasulullah shallAllahu wa'alaihi wa sallam memerintahkan Abu Bakr agar Asma` mandi dan bertalbiyah. "},"1427":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى وَإِسْمَعِيلُ بْنُ إِبْرَاهِيمَ أَبُو مَعْمَرٍ قَالَا حَدَّثَنَا مَرْوَانُ بْنُ شُجَاعٍ عَنْ خُصَيْفٍ عَنْ عِكْرِمَةَ وَمُجَاهِدٍ وَعَطَاءٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْحَائِضُ وَالنُّفَسَاءُ إِذَا أَتَتَا عَلَى الْوَقْتِ تَغْتَسِلَانِ وَتُحْرِمَانِ وَتَقْضِيَانِ الْمَنَاسِكَ كُلَّهَا غَيْرَ الطَّوَافِ بِالْبَيْتِ قَالَ أَبُو مَعْمَرٍ فِي حَدِيثِهِ حَتَّى تَطْهُرَ وَلَمْ يَذْكُرْ ابْنُ عِيسَى عِكْرِمَةَ وَمُجَاهِدًا قَالَ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ وَلَمْ يَقُلْ ابْنُ عِيسَى كُلَّهَا قَالَ الْمَنَاسِكَ إِلَّا الطَّوَافَ بِالْبَيْتِ","id":"Telah menceritakan kepada Kami [Muhammad bin Isa] dan [Isma'il bin Ibrahim Abu Ma'mar], mereka berkata; telah menceritakan kepada Kami [Marwan bin Syuja'] dari [Khushaif] dari [Ikrimah] serta [Mujahid] dan ['Atha`] dari [Ibnu Abbas] bahwa Nabi Shalla Allahu 'alaihi wa sallam bersabda: \"Wanita yang mengalami haidh atau nifas apabila mendatangi miqat maka mereka mandi dan melakukan ihram serta melaksanakan seluruh ibadah haji kecuali thawaf di Ka'bah. Abu Ma'mar berkata di dalam haditsnya; hingga ia suci. Ibnu Isa tidak menyebutkan Ikrimah dan Mujahid, ia menyebutkan dari 'Atha` dari Ibnu Abbas, Ibnu Isa tidak menyebutkan; kata semuanya, ia menyebutkan; ibadah haji kecuali thawaf. "},"1428":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ ح و حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكُنْتُ أُطَيِّبُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِإِحْرَامِهِ قَبْلَ أَنْ يُحْرِمَ وَلِإِحْلَالِهِ قَبْلَ أَنْ يَطُوفَ بِالْبَيْتِ","id":"Telah menceritakan kepada Kami [Al Qa'nabi] dari [Malik], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada Kami [Ahmad bin Yunus], telah menceritakan kepada Kami [Malik] dari [Abdurrahman bin Al Qasim] dari [ayahnya] dari [Aisyah], ia berkata; aku memberi Rasulullah shallAllahu wa'alaihi wa sallam minyak wangi untuk ihramnya sebelum beliau melakukan ihram, dan untuk dalam keadaan tidak berihram sebelum beliau melakukan thawaf di Ka'bah. "},"1429":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ الْبَزَّازُ حَدَّثَنَا إِسْمَعِيلُ بْنُ زَكَرِيَّا عَنْ الْحَسَنِ بْنِ عُبَيْدِ اللَّهِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْكَأَنِّي أَنْظُرُ إِلَى وَبِيصِ الْمِسْكِ فِي مَفْرِقِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُحْرِمٌ","id":"Telah menceritakan kepada Kami [Muhammad bin Ash Shabbah Al Bazzaz], telah menceritakan kepada Kami [Isma'il bin Zakariya] dari [Al Hasan bin 'Ubaidullah] dari [Ibrahim] dari [Al Aswad] dari [Aisyah], ia berkata; seolah-olah aku melihat kilatan minyak wangi pada belahan rambut Rasulullah shallAllahu wa'alaihi wa sallam sementara beliau dalam keadaan berihram. "},"1430":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ يَعْنِي ابْنَ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُهِلُّ مُلَبِّدًا","id":"Telah menceritakan kepada Kami [Sulaiman bin Daud Al Mahri], telah menceritakan kepada Kami [Ibnu Wahb], telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Salim yaitu Ibnu Abdullah] dari [ayahnya], ia berkata; saya mendengar Nabi shallallahu 'alaihi wasallam bertalbiyah dalam keadaan mencelup rambutnya. "},"1431":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَبَّدَ رَأْسَهُ بِالْعَسَلِ","id":"Telah menceritakan kepada Kami ['Ubaidullah bin Umar], telah menceritakan kepada Kami [Abdul A'la], telah menceritakan kepada Kami [Muhammad bin Ishaq] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam mencelup rambut kepalanya menggunakan madu. "},"1432":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمِنْهَالِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ ابْنِ إِسْحَقَ الْمَعْنَى قَالَ قَالَ عَبْدُ اللَّهِ يَعْنِي ابْنَ أَبِي نَجِيحٍ حَدَّثَنِي مُجَاهِدٌ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهْدَى عَامَ الْحُدَيْبِيَةِ فِي هَدَايَا رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَمَلًا كَانَ لِأَبِي جَهْلٍ فِي رَأْسِهِ بُرَةُ فِضَّةٍ قَالَ ابْنُ مِنْهَالٍ بُرَةٌ مِنْ ذَهَبٍ زَادَ النُّفَيْلِيُّ يَغِيظُ بِذَلِكَ الْمُشْرِكِينَ","id":"Telah menceritakan kepada Kami [An Nufaili], telah menceritakan kepada Kami [Muhammad bin Salamah] telah menceritakan kepada Kami [Muhammad bin Ishaq], dan telah diriwayatkan melalui jalur yang lain: Telah menceritakan kepada Kami [Muhammad bin Al Minhal], telah menceritakan kepada Kami [Yazid bin Zurai'] dari [Ibnu Ishaq] secara makna, ia berkata; [Abdullah yaitu Ibnu Abu Najih] berkata; telah menceritakan kepada Kami [Mujahid] dari [Ibnu Abbas] bahwa Rasulullah shallAllahu wa'alaihi wa sallam berkurban dengan unta yang dahulu adalah milik Abu Jahl pada tahun terjadinya perjanjian Al Hudaibiyah diantara hewan-hewan kurban beliau. Pada kepala unta tersebut terdapat perak sebesar satu biji gandum. Ibnu Minhal berkata; emas sebesar biji gandum. An Nufaili menambahkan; hal tersebut menyebabkan orang-orang musyrik marah. "},"1433":{"ar":"حَدَّثَنَا ابْنُ السَّرْحِ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحَرَ عَنْ آلِ مُحَمَّدٍ فِي حَجَّةِ الْوَدَاعِ بَقَرَةً وَاحِدَةً","id":"Telah menceritakan kepada Kami [Ibnu As Sarh] telah menceritakan kepada Kami [Ibnu Wahb], telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari ['Amrah binti Abdurrahman] dari [Aisyah] isteri Nabi shallallahu 'alaihi wasallam bahwa Rasulullah shallAllahu wa'alaihi wa sallam pada saat haji wada' menyembelih untuk keluarga Muhammad satu ekor sapi. "},"1434":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ وَمُحَمَّدُ بْنُ مِهْرَانَ الرَّازِيُّ قَالَا حَدَّثَنَا الْوَلِيدُ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَبَحَ عَمَّنْ اعْتَمَرَ مِنْ نِسَائِهِ بَقَرَةً بَيْنَهُنَّ","id":"Telah menceritakan kepada Kami ['Amr bin Utsman], dan [Muhammad bin Mahran Ar Razi], mereka berkata; telah menceritakan kepada Kami [Al Walid] dari [Al Auza'i] dari [Yahya] dari [Abu Salamah] dari [Abu Hurairah] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam menyembelihkan satu ekor sapi untuk istri-istrinya yang melaksanakan umrah. "},"1435":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ وَحَفْصُ بْنُ عُمَرَ الْمَعْنَى قَالَا حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ أَبُو الْوَلِيدِ قَالَ سَمِعْتُ أَبَا حَسَّانَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الظُّهْرَ بِذِي الْحُلَيْفَةِ ثُمَّ دَعَا بِبَدَنَةٍ فَأَشْعَرَهَا مِنْ صَفْحَةِ سَنَامِهَا الْأَيْمَنِ ثُمَّ سَلَتَ عَنْهَا الدَّمَ وَقَلَّدَهَا بِنَعْلَيْنِ ثُمَّ أُتِيَ بِرَاحِلَتِهِ فَلَمَّا قَعَدَ عَلَيْهَا وَاسْتَوَتْ بِهِ عَلَى الْبَيْدَاءِ أَهَلَّ بِالْحَجِّحَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ بِهَذَا الْحَدِيثِ بِمَعْنَى أَبِي الْوَلِيدِ قَالَ ثُمَّ سَلَتَ الدَّمَ بِيَدِهِ قَالَ أَبُو دَاوُد رَوَاهُ هَمَّامٌ قَالَ سَلَتَ الدَّمَ عَنْهَا بِأُصْبُعِهِ قَالَ أَبُو دَاوُد هَذَا مِنْ سُنَنِ أَهْلِ الْبَصْرَةِ الَّذِي تَفَرَّدُوا بِهِ","id":"Telah menceritakan kepada Kami [Abu Al Walid Ath Thayalisi], dan [Hafsh bin Umar] secara makna, mereka berkata; telah menceritakan kepada Kami [Syu'bah] dari [Qatadah], ia berkata; [Abu Al Walid] berkata; saya mendengar [Abu Hassan] dari [Ibnu Abbas] bahwa Rasulullah shallAllahu wa'alaihi wa sallam melakukan shalat Zhuhur di Dzul Hulaifah kemudian meminta seekor unta lalu beliau melukainya dari sisi punuknya sebelah kanan, kemudian beliau menghentikan darah darinya, dan mengalunginya dengan dua sandal. Kemudian beliau diberi kendaraan, dan tatkala beliau telah duduk di atasnya dan unta tersebut telah menaiki Al Baida` maka beliau bertalbiah untuk melakukan haji. Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Yahya] dari [Syu'bah] dengan hadits ini semakna dengan hadits Abu Al Walid, ia berkata; kemudian beliau menghentikan darah menggunakan tangannya. Abu Daud berkata; hadits tersebut diriwayatkan oleh [Hammam], ia berkata; beliau menghentikan darah darinya menggunakan jari-jarinya. Abu Daud berkata; hal ini merupakan diantara kebiasaan-kebiasaan penduduk Bashrah yang menjadi kekhususan mereka. "},"1436":{"ar":"حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ الْمِسْوَرِ بْنِ مَخْرَمَةَ وَمَرْوَانُ بْنُ الْحَكَمِ أَنَّهُمَا قَالَاخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْحُدَيْبِيَةِ فَلَمَّا كَانَ بِذِي الُحُلَيْفَةِ قَلَّدَ الْهَدْيَ وَأَشْعَرَهُ وَأَحْرَمَ","id":"Telah menceritakan kepada Kami [Abdul A'la bin Hammad], telah menceritakan kepada Kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari ['Urwah] dari [Al Miswar bin Makhramah] serta [Marwan bin Al Hakam], bahwa mereka berdua berkata; Rasulullah shallallahu 'alaihi wasallam keluar pada tahun Hudaibiyah, tatkala beliau telah sampai di Dzul Hulaifah beliau mengalungi hewan kurbannya dan melukainya serta berihram. "},"1437":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ وَالْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهْدَى غَنَمًا مُقَلَّدَةً","id":"Telah menceritakan kepada Kami [Hannad] telah menceritakan kepada Kami [Waki'] dari [Sufyan] dari [Manshur] dan [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] bahwa Rasulullah shallAllahu wa'alaihi wa sallam berkurban dengan kambing yang telah digantungi kalung. "},"1438":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ أَبِي عَبْدِ الرَّحِيمِ قَالَ أَبُو دَاوُد أَبُو عَبْدِ الرَّحِيمِ خَالِدُ بْنُ أَبِي يَزِيدَ خَالُ مُحَمَّدٍ يَعْنِي ابْنَ سَلَمَةَ رَوَى عَنْهُ حَجَّاجُ بْنُ مُحَمَّدٍ عَنْ جَهْمِ بْنِ الْجَارُودِ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَأَهْدَى عُمَرُ بْنُ الْخَطَّابِ نَجِيبًا فَأَعْطَى بِهَا ثَلَاثَ مِائَةِ دِينَارٍ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أَهْدَيْتُ نَجِيبًا فَأَعْطَيْتُ بِهَا ثَلَاثَ مِائَةِ دِينَارٍ أَفَأَبِيعُهَا وَأَشْتَرِي بِثَمَنِهَا بُدْنًا قَالَ لَا انْحَرْهَا إِيَّاهَاقَالَ أَبُو دَاوُد هَذَا لِأَنَّهُ كَانَ أَشْعَرَهَا","id":"Telah menceritakan kepada Kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada Kami [Muhammad bin Salamah] dari [Abu Abdurrahim]. -Abu Daud berkata; Abu Abdurrahim adalah Khalid bin Abu Yazid, paman Muhammad bin Salamah-, darinya Hajjaj bin Muhammad dari [Jahm bin Al Jarud], dari [Salim bin Abdullah] dari [ayahnya], ia berkata: Umar bin Khathab berkurban dengan seekor unta yang kuat, ringan dan berlari cepat, kemudian ia menjualnya dengan harga tiga ratus dinar. kemudian ia mendatangi Nabi shalla Allahu 'alaihi wa sallam dan berkata: Wahai Rasulullah, aku berkurban dengan seekor unta, kemudian unta tersebut dibeli dengan harga tiga ratus dinar, aku menjualnya dan membeli unta lain dengan harga yang sama? Beliau menjawab: \"Tidak boleh! Sembelihlah unta tersebut!\" Abu Daud berkata: hal tersebut dikarenakan Umar telah melukainya sebagai tanda."},"1439":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ حَدَّثَنَا أَفْلَحُ بْنُ حُمَيْدٍ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ قَالَتْفَتَلْتُ قَلَائِدَ بُدْنِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِي ثُمَّ أَشْعَرَهَا وَقَلَّدَهَا ثُمَّ بَعَثَ بِهَا إِلَى الْبَيْتِ وَأَقَامَ بِالْمَدِينَةِ فَمَا حَرُمَ عَلَيْهِ شَيْءٌ كَانَ لَهُ حِلًّا","id":"Telah menceritakan kepada Kami [Abdullah bin Maslamah Al Qa'nabi], Telah menceritakan kepada Kami [Aflah bin Humaid] dari [Al Qasim] dari [Aisyah], ia berkata; aku menjalin kalung-kalung unta Rasulullah shallAllahu wa'alaihi wa sallam menggunakan tanganku, kemudian beliau melukainya sebagai tanda dan mengalunginya kemudian mengirimnya ke Ka'bah. Dan beliau bermukim di Madinah dan tidak ada sesuatupun yang haram baginya yang dahulunya adalah halal. "},"1440":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ خَالِدٍ الرَّمْلِيُّ الْهَمَدَانِيُّ وَقُتَيْبَةُ بْنُ سَعِيدٍ أَنَّ اللَّيْثَ بْنَ سَعْدٍ حَدَّثَهُمْ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ وَعَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُهْدِي مِنْ الْمَدِينَةِ فَأَفْتِلُ قَلَائِدَ هَدْيِهِ ثُمَّ لَا يَجْتَنِبُ شَيْئًا مِمَّا يَجْتَنِبُ الْمُحْرِمُ","id":"Telah menceritakan kepada Kami [Yazid bin Khalid Ar Ramli Al Hamdani], serta [Qutaibah bin Sa'id] bahwa [Al Laits bin Sa'd] telah menceritakan kepada mereka dari [Ibnu Syihab] dari ['Urwah] dan ['Amrah binti Abdurrahman] bahwa [Aisyah] radliallahu 'anha berkata; Rasulullah shallAllahu wa'alaihi wa sallam berkurban dari Madinah, dan aku yang menjalin kalung-kalung hewan kurbannya, kemudian beliau tidak menjauhi sesuatupun diantara perkara-perkara yang dijauhi orang yang berihram. "},"1441":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ وَعَنْ إِبْرَاهِيمَ زَعَمَ أَنَّهُ سَمِعَهُ مِنْهُمَا جَمِيعًا وَلَمْ يَحْفَظْ حَدِيثَ هَذَا مِنْ حَدِيثِ هَذَا وَلَا حَدِيثَ هَذَا مِنْ حَدِيثِ هَذَا قَالَا قَالَتْ أُمُّ الْمُؤْمِنِينَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْهَدْيِ فَأَنَا فَتَلْتُ قَلَائِدَهَا بِيَدِي مِنْ عِهْنٍ كَانَ عِنْدَنَا ثُمَّ أَصْبَحَ فِينَا حَلَالًا يَأْتِي مَا يَأْتِي الرَّجُلُ مِنْ أَهْلِهِ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Bisyr bin Al Mufadhdhal], telah menceritakan kepada Kami [Ibnu 'Aun] dari [Al Qasim bin Muhammad] dan [Ibrahim], ia mengaku bahwa ia telah mendengarnya dari keduanya, dan tidak dapat membedakan antara hadits ini dari hadits ini dan hadits ini dari hadits ini. Mereka berkata; telah berkata [Ummul mukminin]; Rasulullah shallAllahu wa'alaihi wa sallam mengirim hewan kurban, dan aku yang menjalin kalung-kalung hewan tersebut dengan tanganku dari bulu yang ada pada Kami, kemudian pada pagi hari beliau dalam keadaan tidak berihram, beliau melakukan apa yang dilakukan seorang laki-laki kepada isterinya. "},"1442":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا يَسُوقُ بَدَنَةً فَقَالَ ارْكَبْهَا قَالَ إِنَّهَا بَدَنَةٌ فَقَالَ ارْكَبْهَا وَيْلَكَ فِي الثَّانِيَةِ أَوْ فِي الثَّالِثَةِ","id":"Telah menceritakan kepada Kami [Al Qa'nabi], dari [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallAllahu wa'alaihi wa sallam melihat seorang laki-laki menuntun seekor unta. Kemudian beliau berkata: \"Naikilah unta tersebut!\" Ia berkata; unta tersebut adalah unta kurban, kemudian beliau berkata: \"Naikilah, merugilah engkau.\" Beliau mengucapkannya kedua atau ketiga kali. "},"1443":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِسَأَلْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ عَنْ رُكُوبِ الْهَدْيِ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ ارْكَبْهَا بِالْمَعْرُوفِ إِذَا أُلْجِئْتَ إِلَيْهَا حَتَّى تَجِدَ ظَهْرًا","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Yahya bin Sa'id] dari [Ibnu Juraij], telah mengabarkan kepadaku [Abu Az Zubair], aku bertanya kepada [Jabir bin Abdullah] mengenai menaiki hewan kurban. Kemudian ia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: Naikilah dengan cara yang ma'ruf, apabila kalian terpaksa untuk menaikinya hingga mendapatkan tunggannya. "},"1444":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ نَاجِيَةَ الْأَسْلَمِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ مَعَهُ بِهَدْيٍ فَقَالَ إِنْ عَطِبَ مِنْهَا شَيْءٌ فَانْحَرْهُ ثُمَّ اصْبُغْ نَعْلَهُ فِي دَمِهِ ثُمَّ خَلِّ بَيْنَهُ وَبَيْنَ النَّاسِ","id":"Telah menceritakan kepada Kami [Muhammad bin Katsir], telah mengabarkan kepada Kami [Abu Sufyan] dari [Hisyam] dari [ayahnya] dari [Najiyah Al Aslami] bahwa Rasulullah shallAllahu wa'alaihi wa sallam telah mengirim unta kurban bersamanya. Beliau berkata: \"Apabila sebagiannya telah mendekati kematian maka sembelihlah hewan tersebut, kemudian celupkan sandal kakinya ke dalam darahnya, kemudian biarkan dimanfaatkan orang-orang.\""},"1445":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ وَمُسَدَّدٌ قَالَا حَدَّثَنَا حَمَّادٌ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ وَهَذَا حَدِيثُ مُسَدَّدٍ عَنْ أَبِي التَّيَّاحِ عَنْ مُوسَى بْنِ سَلَمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فُلَانًا الْأَسْلَمِيَّ وَبَعَثَ مَعَهُ بِثَمَانِ عَشْرَةَ بَدَنَةً فَقَالَ أَرَأَيْتَ إِنْ أُزْحِفَ عَلَيَّ مِنْهَا شَيْءٌ قَالَ تَنْحَرُهَا ثُمَّ تَصْبُغُ نَعْلَهَا فِي دَمِهَا ثُمَّ اضْرِبْهَا عَلَى صَفْحَتِهَا وَلَا تَأْكُلْ مِنْهَا أَنْتَ وَلَا أَحَدٌ مِنْ أَصْحَابِكَ أَوْ قَالَ مِنْ أَهْلِ رُفْقَتِكَقَالَ أَبُو دَاوُد الَّذِي تَفَرَّدَ بِهِ مِنْ هَذَا الْحَدِيثِ قَوْلُهُ وَلَا تَأْكُلْ مِنْهَا أَنْتَ وَلَا أَحَدٌ مِنْ رُفْقَتِكَ وَقَالَ فِي حَدِيثِ عَبْدِ الْوَارِثِ ثُمَّ اجْعَلْهُ عَلَى صَفْحَتِهَا مَكَانَ اضْرِبْهَا قَالَ أَبُو دَاوُد سَمِعْت أَبَا سَلَمَةَ يَقُولُ إِذَا أَقَمْتَ الْإِسْنَادَ وَالْمَعْنَى كَفَاكَ","id":"Telah menceritakan kepada Kami [Sulaiman bin Harb], dan [Musaddad], mereka berkata; telah menceritakan kepada Kami [Hammad]. Dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Abdul Warits] dan ini adalah hadits Musaddad dari [Abu At Tayyah] dari [Musa bin Salamah] dari [Ibnu Abbas], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam mengutus Fulan Al Aslami dan mengirim bersamanya delapan belas unta kurban. Kemudian orang tersebut berkata; bagaimana pendapat anda apabila sebagiannya hampir mati dan tidak mampu berjalan? Beliau menjawab: \"Engkau sembelih, kemudian engkau celupkan sepatunya pada darahnya. Kemudian pukulkan sepatu kakinya ke sisi punuknya, dan jangan engkau serta seorangpun dari para sahabatmu memakan sebagian darinya.\" Atau ia berkata; \"Dari orang-orang yang bersahabat denganmu.\" Abu Daud berkata; yang tersendiri dari hadits ini adalah ucapannya; dan janganlah serta seorangpun dari para sahabatmu memakan sebagian darinya.\" Beliau berkata dalam hadits Abdul Warits: \"kemudian jadikan sepatu tersebut pada sisi punuk.\" Sebagai ganti kata; pululkan. Abu Daud berkata; saya mendengar Abu Salamah berkata; apabila engkau menyebutkan sanad dan makna maka sudah cukup. "},"1446":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُحَمَّدٌ وَيَعْلَى ابْنَا عُبَيْدٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا نَحَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بُدْنَهُ فَنَحَرَ ثَلَاثِينَ بِيَدِهِ وَأَمَرَنِي فَنَحَرْتُ سَائِرَهَا","id":"Telah menceritakan kepada Kami [Harun bin Abdullah], telah menceritakan kepada Kami [Muhammad] serta [Ya'la] kedua anak 'Ubaid, mereka berkata; telah menceritakan kepada Kami [Muhammad bin Ishaq], dari [Ibnu Abu Najih] dari [Mujahid] dari [Abdurrahman bin Abu Laila] dari [Ali radliallahu 'anhu], ia berkata; tatkala Rasulullah shallAllahu wa'alaihi wa sallam menyembelih untanya, beliau menyembelih tiga puluh ekor dengan tangannya dan memerintahkan aku untuk menyembelih sisanya. "},"1447":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ أَخْبَرَنَا عِيسَى ح و حَدَّثَنَا مُسَدَّدٌ أَخْبَرَنَا عِيسَى وَهَذَا لَفْظُ إِبْرَاهِيمَ عَنْ ثَوْرٍ عَنْ رَاشِدِ بْنِ سَعْدٍ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرِ بْنِ لُحَيٍّ عَنْ عَبْدِ اللَّهِ بْنِ قُرْطٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَعْظَمَ الْأَيَّامِ عِنْدَ اللَّهِ تَبَارَكَ وَتَعَالَى يَوْمُ النَّحْرِ ثُمَّ يَوْمُ الْقَرِّ قَالَ عِيسَى قَالَ ثَوْرٌ وَهُوَ الْيَوْمُ الثَّانِي وَقَالَ وَقُرِّبَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَدَنَاتٌ خَمْسٌ أَوْ سِتٌّ فَطَفِقْنَ يَزْدَلِفْنَ إِلَيْهِ بِأَيَّتِهِنَّ يَبْدَأُ فَلَمَّا وَجَبَتْ جُنُوبُهَا قَالَ فَتَكَلَّمَ بِكَلِمَةٍ خَفِيَّةٍ لَمْ أَفْهَمْهَا فَقُلْتُ مَا قَالَ قَالَ مَنْ شَاءَ اقْتَطَعَ","id":"Telah menceritakan kepada Kami [Ibrahim bin Musa Ar Razi], telah mengabarkan kepada Kami [Isa]. Dan telah diriwayatkan dari jalur yang lain: telah menceritakan kepada Kami [Musaddad], telah mengabarkan kepada Kami [Isa], dan ini adalah lafazh Ibrahim, dari [Tsaur] dari [Rasyid bin Sa'd] dari [Abdullah bin 'Amir bin Luhai] dari [Abdullah bin Qurth] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya hari yang teragung di sisi Allah tabaraka wa ta'ala adalah hari Nahr (Hari Raya Kurban), kemudian hari setelah hari Nahr.\" Isa berkata; Tsaur berkata; yaitu hari kedua. Ia berkata; dan telah didekatkan kepada Rasulullah shallAllahu wa'alaihi wa sallam lima atau enam ekor unta. Unta-unta tersebut mendekat kepadanya, beliau memulai dengan unta yang manapun. Kemudian tatkala telah terjatuh beliau mengucapkan sebuah kalimat yang samar, saya tidak memahaminya. Lalu saya katakan; apakah yang beliau katakana? Ia mengatakan; \"Barang siapa yang menginginkan maka boleh ia mengambil sepotong darinya.\""},"1448":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ حَرْمَلَةَ بْنِ عِمْرَانَ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ الْأَزْدِيِّ قَالَ سَمِعْتُ غُرْفَةَ بْنَ الْحَارِثِ الْكِنْدِيِّ قَالَشَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ وَأُتِيَ بِالْبُدْنِ فَقَالَ ادْعُوا لِي أَبَا حَسَنٍ فَدُعِيَ لَهُ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ فَقَالَ لَهُ خُذْ بِأَسْفَلِ الْحَرْبَةِ وَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَعْلَاهَا ثُمَّ طَعَنَا بِهَا فِي الْبُدْنِ فَلَمَّا فَرَغَ رَكِبَ بَغْلَتَهُ وَأَرْدَفَ عَلِيًّا رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada Kami [Muhammad bin Hatim], telah menceritakan kepada Kami [Abdurrahman bin Mahdi], telah menceritakan kepada Kami [Abdullah bin Al Mubarak] dari [Harmalah bin Imran] dari [Abdullah bin Harits Al Azdi], berkata: saya mendengar [Ghurfah bin Al Harits Al Kindi], ia berkata: aku telah menyaksikan Rasulullah shallallahu 'alaihi wasallam pada waktu haji wada' dan beliau diberi unta, lalu beliau berkata: panggillah Abu Hasan. Maka Ali Bin Abu Thalib radliallahu 'anhu dipanggil lalu, kemudian beliau berkata kepadanya: \"Peganglah bagian bawah tombak! Dan Rasulullah shallallahu 'alaihi wasallam memegang atasnya lalu mereka berdua menghujamkannya ke unta. Setelah selesai beliau menaiki bighalnya(jenis keledai) dan membonceng Ali Bin Abi Thalib radliallahu 'anhu. "},"1449":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ ابْنِ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ وَأَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ سَابِطٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابَهُ كَانُوا يَنْحَرُونَ الْبَدَنَةَ مَعْقُولَةَ الْيُسْرَى قَائِمَةً عَلَى مَا بَقِيَ مِنْ قَوَائِمِهَا","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Abu Khalid Al Ahmar] dari [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir], dan telah mengabarkan kepadaku [Abdurrahman bin Sabith] bahwa Nabi shallallahu 'alaihi wasallam dan para sahabatnya menyembelih unta yang diikat kaki kirinya dalam keadaan berdiri dengan kakinya yang lain. "},"1450":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا يُونُسُ أَخْبَرَنِي زِيَادُ بْنُ جُبَيْرٍ قَالَكُنْتُ مَعَ ابْنِ عُمَرَ بِمِنًى فَمَرَّ بِرَجُلٍ وَهُوَ يَنْحَرُ بَدَنَتَهُ وَهِيَ بَارِكَةٌ فَقَالَ ابْعَثْهَا قِيَامًا مُقَيَّدَةً سُنَّةَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Husyaim], telah mengabarkan kepada Kami [Yunus], telah mengabarkan kepadaku [Ziyad bin Jubair], ia berkata; aku pernah bersama [Ibnu Umar] di Mina, kemudian ia melewati seorang laki-laki yang menyembelih untanya dalam keadaan menderum. Kemudian Ibnu Umar berkata; bangkitkan unta tersebut dalam keadaan terikat, ikutilah sunah Muhammad shallallahu 'alaihi wasallam. "},"1451":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا سُفْيَانُ يَعْنِي ابْنَ عُيَيْنَةَ عَنْ عَبْدِ الْكَرِيمِ الْجَزَرِيِّ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَأَمَرَنِي رَسُولُ الل��َهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَقُومَ عَلَى بُدْنِهِ وَأَقْسِمَ جُلُودَهَا وَجِلَالَهَا وَأَمَرَنِي أَنْ لَا أُعْطِيَ الْجَزَّارَ مِنْهَا شَيْئًا وَقَالَ نَحْنُ نُعْطِيهِ مِنْ عِنْدِنَا","id":"Telah menceritakan kepada Kami ['Amr bin 'Aun], telah mengabarkan kepada Kami [Sufyan yaitu Ibnu 'Uyainah] dari [Abdul Karim Al Jazari] dari [Mujahid] dari [Abdurrahman bin Abu Laila] dari [Ali] radliallahu 'anhu, ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam memerintahkanku menyembelih untanya dan membagikan kulitnya serta segala yang ada diatasnya, dan beliau memerintahkan agar aku tidak memberikan sesuatupun kepada orang yang menyembelih. Beliau bersabda: \"Kami akan memberinya dari diri Kami.\""},"1452":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَنْصُورٍ حَدَّثَنَا يَعْقُوبُ يَعْنِي ابْنَ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ قَالَ حَدَّثَنِي خُصَيْفُ بْنُ عَبْدِ الرَّحْمَنِ الْجَزَرِيُّ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَقُلْتُ لِعَبْدِ اللَّهِ بْنِ عَبَّاسٍ يَا أَبَا الْعَبَّاسِ عَجِبْتُ لِاخْتِلَافِ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي إِهْلَالِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أَوْجَبَ فَقَالَ إِنِّي لَأَعْلَمُ النَّاسِ بِذَلِكَ إِنَّهَا إِنَّمَا كَانَتْ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَجَّةً وَاحِدَةً فَمِنْ هُنَاكَ اخْتَلَفُوا خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَاجًّا فَلَمَّا صَلَّى فِي مَسْجِدِهِ بِذِي الْحُلَيْفَةِ رَكْعَتَيْهِ أَوْجَبَ فِي مَجْلِسِهِ فَأَهَلَّ بِالْحَجِّ حِينَ فَرَغَ مِنْ رَكْعَتَيْهِ فَسَمِعَ ذَلِكَ مِنْهُ أَقْوَامٌ فَحَفِظْتُهُ عَنْهُ ثُمَّ رَكِبَ فَلَمَّا اسْتَقَلَّتْ بِهِ نَاقَتُهُ أَهَلَّ وَأَدْرَكَ ذَلِكَ مِنْهُ أَقْوَامٌ وَذَلِكَ أَنَّ النَّاسَ إِنَّمَا كَانُوا يَأْتُونَ أَرْسَالًا فَسَمِعُوهُ حِينَ اسْتَقَلَّتْ بِهِ نَاقَتُهُ يُهِلُّ فَقَالُوا إِنَّمَا أَهَلَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ اسْتَقَلَّتْ بِهِ نَاقَتُهُ ثُمَّ مَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا عَلَا عَلَى شَرَفِ الْبَيْدَاءِ أَهَلَّ وَأَدْرَكَ ذَلِكَ مِنْهُ أَقْوَامٌ فَقَالُوا إِنَّمَا أَهَلَّ حِينَ عَلَا عَلَى شَرَفِ الْبَيْدَاءِ وَايْمُ اللَّهِ لَقَدْ أَوْجَبَ فِي مُصَلَّاهُ وَأَهَلَّ حِينَ اسْتَقَلَّتْ بِهِ نَاقَتُهُ وَأَهَلَّ حِينَ عَلَا عَلَى شَرَفِ الْبَيْدَاءِقَالَ سَعِيدٌ فَمَنْ أَخَذَ بِقَوْلِ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ أَهَلَّ فِي مُصَلَّاهُ إِذَا فَرَغَ مِنْ رَكْعَتَيْهِ","id":"Telah menceritakan kepada Kami [Muhammad bin Manshur], telah menceritakan kepada Kami [Ya'qub yaitu Ibnu Ibrahim], telah menceritakan kepada Kami [ayahku] dari [Ibnu Ishaq], ia berkata; telah menceritakan kepadaku [Khushaif bin Abdurrahman Al Jazari], dari [Sa'id bin Jubair], ia berkata; aku katakan kepada [Abdullah bin Abbas], wahai Ibnu Abbas, aku heran terhadap perselisihan para sahabat Rasulullah shallAllahu wa'alaihi wa sallam mengenai talbiyah Rasulullah shallAllahu wa'alaihi wa sallam ketika beliau mengharuskan untuk berhaji. Lalu ia berkata; sungguh aku adalah orang yang paling tahu mengenai hal tersebut. Sesungguhnya haji tersebut dilakukan Rasulullah shallAllahu wa'alaihi wa sallam satu kali. Kemudian dari sana mereka berselisih. Rasulullah shallAllahu wa'alaihi wa sallam keluar untuk berhaji, kemudian tatkala beliau telah melakukan shalat dua raka'at di masjidnya di Dzul Hulaifah, beliau mewajibkan haji di majelisnya. Kemudian beliau bertalbiyah untuk melakukan haji ketika telah selesai dari dua raka'at tersebut. Lalu orang-orang mendengar hal tersebut dan aku hafal hal tersebut dari beliau. Kemudian beliau menaiki kendaraannya, lalu ketika untanya telah berada di tempat yang tinggi beliau bertalbiyah, dan hal tersebut didapatkan oleh orang-orang darinya. Sesungguhnya mereka datang bergelombang, lalu mereka mendengar beliau ketika untanya berada di tempat yang tinggi. Mereka berkata; sesungguhnya Rasulullah shallAllahu wa'alaihi wa sallam bertalbiyah ketika untanya berada di tempat yang tinggi. Kemudian Rasulullah berlalu, tatkala beliau telah berada di puncak Al Baida`, demi Allah sungguh beliau telah mewajibkan hajinya di tempat beliau melakukan shalat. Dan beliau bertalbiyah ketika untanya berada di tempat yang tinggi, dan beliau bertalbiyah tatkala berada di puncak Al Baida`. Sa'id berkata; barang siapa yang mengambil ucapan Abdullah bin Abbas maka ia bertalbiyah di tempat ia melakukan shalat apabila telah menyelesaikan shalat dua raka'at. "},"1453":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَبَيْدَاؤُكُمْ هَذِهِ الَّتِي تَكْذِبُونَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهَا مَا أَهَلَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا مِنْ عِنْدِ الْمَسْجِدِ يَعْنِي مَسْجِدَ ذِي الْحُلَيْفَةِ","id":"Telah menceritakan kepada Kami [Al Qa'nabi], dari [Malik] dari [Musa bin 'Uqbah] dari [Salim bin Abdullah] dari [ayahnya], ia berkata; Baida` kalian ini adalah Baida` yang padanya kalian mendustakan Rasulullah shallAllahu wa'alaihi wa sallam. Tidaklah Rasulullah shallAllahu wa'alaihi wa sallam bertalbiyah kecuali dari Masjid, yaitu Masjid Dzul Hulaifah. "},"1454":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ عُبَيْدِ بْنِ جُرَيْجٍأَنَّهُ قَالَ لِعَبْدِ اللَّهِ بْنِ عُمَرَ يَا أَبَا عَبْدِ الرَّحْمَنِ رَأَيْتُكَ تَصْنَعُ أَرْبَعًا لَمْ أَرَ أَحَدًا مِنْ أَصْحَابِكَ يَصْنَعُهَا قَالَ مَا هُنَّ يَا ابْنَ جُرَيْجٍ قَالَ رَأَيْتُكَ لَا تَمَسُّ مِنْ الْأَرْكَانِ إِلَّا الْيَمَانِيَّيْنِ وَرَأَيْتُكَ تَلْبَسُ النِّعَالَ السِّبْتِيَّةَ وَرَأَيْتُكَ تَصْبُغُ بِالصُّفْرَةِ وَرَأَيْتُكَ إِذَا كُنْتَ بِمَكَّةَ أَهَلَّ النَّاسُ إِذَا رَأَوْا الْهِلَالَ وَلَمْ تُهِلَّ أَنْتَ حَتَّى كَانَ يَوْمَ التَّرْوِيَةِ فَقَالَ عَبْدُ اللَّهِ بْنُ عُمَرَ أَمَّا الْأَرْكَانُ فَإِنِّي لَمْ أَرَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمَسُّ إِلَّا الْيَمَانِيَّيْنِ وَأَمَّا النِّعَالُ السِّبْتِيَّةُ فَإِنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَلْبَسُ النِّعَالَ الَّتِي لَيْسَ فِيهَا شَعْرٌ وَيَتَوَضَّأُ فِيهَا فَأَنَا أُحِبُّ أَنْ أَلْبَسَهَا وَأَمَّا الصُّفْرَةُ فَإِنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْبُغُ بِهَا فَأَنَا أُحِبُّ أَنْ أَصْبُغَ بِهَا وَأَمَّا الْإِهْلَالُ فَإِنِّي لَمْ أَرَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُهِلُّ حَتَّى تَنْبَعِثَ بِهِ رَاحِلَتُهُ","id":"Telah menceritakan kepada Kami [Al Qa'nabi] dari [Malik] dari [Sa'id bin Abu Sa'id Al Maqburi] dari ['Ubaid bin Juraij] bahwa ia berkata kepada [Abdullah bin Umar]; wahai Abu Abdurrahman, aku melihat engkau melakukan empat perkara yang tidak aku lihat seorang pun dari para sahabatmu melakukannya. Ia berkata; apakah itu wahai Ibnu Juraij? Ia berkata; aku melihatmu tidak menyentuh rukun kecuali dua rukun yamani, aku melihat engkau memakai sandal sibti (yang tidak berbulu), dan aku melihat engkau mencelup dengan shufrah (minyak yang terbuat dari campuran kunyit dan yang lainnya), dan aku melihat engkau apabila berada di Mekkah orang-orang bertalbiyah apabila melihat hilal sementara engkau tidak bertalbiyah hingga pada Hari Tarwiyah (yaitu tanggal delapan Dzul Hijjah). Kemudian Abdullah bin Umar berkata; adapun rukun, maka sesungguhnya aku tidak melihat Rasulullah shallAllahu wa'alaihi wa sallam menyentuh kecuali dua rukun Yamani, adapun sandal sibti (sandal dari yaman), maka sesungguhnya aku melihat Rasulullah shallAllahu wa'alaihi wa sallam memakai sandal yang tidak berambut, dan berwudhu dengan memakai sandal tersebut maka aku ingin memakainya, adapun shufrah, sesungguhnya aku telah melihat Rasulullah shallAllahu wa'alaihi wa sallam mencelup rambut dengan shufrah, maka aku ingin mencelup dengannya, adapun talbiyah, sesungguhnya aku tidak melihat Rasulullah shallAllahu wa'alaihi wa sallam bertalbiyah hingga kendaraan beliau berdiri. "},"1455":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ أَنَسٍ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ بِالْمَدِينَةِ أَرْبَعًا وَصَلَّى الْعَصْرَ بِذِي الْحُلَيْفَةِ رَكْعَتَيْنِ ثُمَّ بَاتَ بِذِي الْحُلَيْفَةِ حَتَّى أَصْبَحَ فَلَمَّا رَكِبَ رَاحِلَتَهُ وَاسْتَوَتْ بِهِ أَهَلَّ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Muhammad bin Bakr], telah menceritakan kepada Kami [Ibnu Juraij] dari [Muhammad bin Al Munkadir] dari [Anas], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam melakukan shalat Zhuhur di Madinah empat raka'at, dan Shalat 'Ashar Di Dzul Hulaifah dua raka'at, kemudian bermalam di Dzul Hulaifah hingga pagi hari. Kemudian tatkala beliau menaiki kendaraannya dan kendaraan tersebut telah berada di tempat yang tinggi beliau bertalbiyah. "},"1456":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا رَوْحٌ حَدَّثَنَا أَشْعَثُ عَنْ الْحَسَنِ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الظُّهْرَ ثُمَّ رَكِبَ رَاحِلَتَهُ فَلَمَّا عَلَا عَلَى جَبَلِ الْبَيْدَاءِ أَهَلَّ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Rauh], telah menceritakan kepada Kami [Aisyah'ats] dari [Al Hasan] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam melakukan Shalat Zhuhur kemudian menaiki kendaraannya, dan tatkala telah berada di atas gunung Baida` beliau bertalbiyah. "},"1457":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا وَهْبٌ يَعْنِي ابْنَ جَرِيرٍ قَالَ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ مُحَمَّدَ بْنَ إِسْحَقَ يُحَدِّثُ عَنْ أَبِي الزِّنَادِ عَنْ عَائِشَةَ بِنْتِ سَعْدِ بْنِ أَبِي وَقَّاصٍ قَالَتْ قَالَ سَعْدُ بْنُ أَبِي وَقَّاصٍكَانَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَخَذَ طَرِيقَ الْفُرْعِ أَهَلَّ إِذَا اسْتَقَلَّتْ بِهِ رَاحِلَتُهُ وَإِذَا أَخَذَ طَرِيقَ أُحُدٍ أَهَلَّ إِذَا أَشْرَفَ عَلَى جَبَلِ الْبَيْدَاءِ","id":"Telah menceritakan kepada Kami [Muhammad bin Basysyar], telah menceritakan kepada Kami [Wahb yaitu Ibnu Jarir], ia berkata; telah menceritakan kepada Kami [ayahku], ia berkata; saya mendengar [Muhammad bin Ishaq] menceritakan dari [Abu Az Zinad] dari [Aisyah binti Sa'd bin Abu Waqqash], ia berkata; [Sa'd bin Abu Waqqash] berkata; Nabi Shalla Allahu 'alaihi wa sallam apabila melewati jalan Al Fur' beliau bertalbiyah apabila kendaraannya sudah berada pada tempat yang tinggi, dan apabilla melewati jalan Uhud beliau bertalbiyah apabila sudah naik di atas gunung Baida`. "},"1458":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ عَنْ هِلَالِ بْنِ خَبَّابٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ ضُبَاعَةَ بِنْتَ الزُّبَيْرِ بْنِ عَبْدِ الْمُطَّلِبِ أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي أُرِيدُ الْحَجَّ أَشْتَرِطُ قَالَ نَعَمْ قَالَتْ فَكَيْفَ أَقُولُ قَالَ قُولِي لَبَّيْكَ اللَّهُمَّ لَبَّيْكَ وَمَحِلِّي مِنْ الْأَرْضِ حَيْثُ حَبَسْتَنِي","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami ['Abbad bin Al 'Awwam] dari [Hilal bin Khabbab] dari [Ikrimah] dari [Ibnu Abbas] bahwa Dhuba'ah binti Az Zubair bin Abdul Muththalib, ia datang kepada Rasulullah shallAllahu wa'alaihi wa sallam dan berkata; wahai Rasulullah, aku inggin berhaji, apakah boleh aku mengucapkan syarat? Beliau bersabda: \"Ya.\" Ia berkata; bagaimana saya mengucapkan? Beliau bersabda: \"Ucapkan; LABBAIKALLAAHUMMA LABBAIK WA MAHALLII MINAL ARDHI HAITSU HABASTANII (Ya Allah, aku memenuhi seruanMu, dan tempatku adalah dimana Engkau menahanku). "},"1459":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْرَدَ الْحَجَّ","id":"Telah menceritakan kepada Kami [Abdullah bin Maslamah Al Qa'nabi], telah menceritakan kepada Kami [Malik] dari [Abdurrahman bin Al Qasim] dari [ayahnya] dari [Aisyah] bahwa Rasulullah shallAllahu wa'alaihi wa sallam melakukan haji secara ifrad (melakukan haji secara terpisah dari umrah). "},"1460":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ أَبِي الْأَسْوَدِ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ نَوْفَلٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ حَجَّةِ الْوَدَاعِ فَمِنَّا مَنْ أَهَلَّ بِعُمْرَةٍ وَمِنَّا مَنْ أَهَلَّ بِحَجٍّ وَعُمْرَةٍ وَمِنَّا مَنْ أَهَلَّ بِالْحَجِّ وَأَهَلَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْحَجِّ فَأَمَّا مَنْ أَهَلَّ بِالْحَجِّ أَوْ جَمَعَ الْحَجَّ وَالْعُمْرَةَ فَلَمْ يُحِلُّوا حَتَّى كَانَ يَوْمَ النَّحْرِحَدَّثَنَا ابْنُ السَّرْحِ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي مَالِكٌ عَنْ أَبِي الْأَسْوَدِ بِإِسْنَادِهِ مِثْلَهُ زَادَ فَأَمَّا مَنْ أَهَلَّ بِعُمْرَةٍ فَأَحَلَّ","id":"Telah menceritakan kepada Kami [Al Qa'nabi Abdullah bin Maslamah] dari [Malik] dari [Abu Al Aswad Muhammad bin Abdurrahman bin Naufal] dari ['Urwah bin Az Zubair] dari [Aisyah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata; Kami keluar bersama Rasulullah shallAllahu wa'alaihi wa sallam pada tahun terjadinya haji wada'. Diantara Kami ada yang bertalbiyah untuk melakukan umrah dan diantara Kami ada yang bertalbiyah untuk melakukan haji dan umrah dan diantara Kami ada yang bertalbiyah untuk melakukan haji. Sedangkan Rasulullah shallAllahu wa'alaihi wa sallam bertalbiyah untuk melakukan haji. Adapun orang yang bertalbiyah untuk melakukan haji atau menggabungkan antara haji dan umrah, maka mereka tidak bertahallul hingga pada Hari Nahr (penyembelihan kurban). Telah menceritakan kepada Kami [Ibnu As Sarh], telah mengabarkan kepada Kami [Ibnu Wahb], telah mengabarkan kepadaku [Malik] dari [Abu Al Aswad] dengan sanadnya seperti itu. Ia menambahkan; adapun orang yang bertahlil untuk melakukan umrah maka ia bertahallul. "},"1461":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّهَا قَالَتْ خَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ فَأَهْلَلْنَا بِعُمْرَةٍ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ مَعَهُ هَدْيٌ فَلْيُهِلَّ بِالْحَجِّ مَعَ الْعُمْرَةِ ثُمَّ لَا يَحِلُّ حَتَّى يَحِلَّ مِنْهُمَا جَمِيعًا فَقَدِمْتُ مَكَّةَ وَأَنَا حَائِضٌ وَلَمْ أَطُفْ بِالْبَيْتِ وَلَا بَيْنَ الصَّفَا وَالْمَرْوَةِ فَشَكَوْتُ ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ انْقُضِي رَأْسَكِ وَامْتَشِطِي وَأَهِلِّي بِالْحَجِّ وَدَعِي الْعُمْرَةَ قَالَتْ فَفَعَلْتُ فَلَمَّا قَضَيْنَا الْحَجَّ أَرْسَلَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ إِلَى التَّنْعِيمِ فَاعْتَمَرْتُ فَقَالَ هَذِهِ مَكَانُ عُمْرَتِكِ قَالَتْ فَطَافَ الَّذِينَ أَهَلُّوا بِالْعُمْرَةِ بِالْبَيْتِ وَبَيْنَ الصَّفَا وَالْمَرْوَةِ ثُمَّ حَلُّوا ثُمَّ طَافُوا طَوَافًا آخَرَ بَعْدَ أَنْ رَجَعُوا مِنْ مِنًى لِحَجِّهِمْ وَأَمَّا الَّذِينَ كَانُوا جَمَعُوا الْحَجَّ وَالْعُمْرَةَ فَإِنَّمَا طَافُوا طَوَافًا وَاحِدًاقَالَ أَبُو دَاوُد رَوَاهُ إِبْرَاهِيمُ بْنُ سَعْدٍ وَمَعْمَرٌ عَنْ ابْنِ شِهَابٍ نَحْوَهُ لَمْ يَذْكُرُوا طَوَافَ الَّذِينَ أَهَلُّوا بِعُمْرَةٍ وَطَوَافَ الَّذِينَ جَمَعُوا الْحَجَّ وَالْعُمْرَةَ","id":"Telah menceritakan kepada Kami [Al Qa'nabi Abdullah bin Maslamah] dari [Malik] dari [Abu Al Aswad Muhammad bin Abdurrahman bin Naufal] dari ['Urwah bin Az Zubair] dari [Aisyah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata; Kami keluar bersama Rasulullah shallAllahu wa'alaihi wa sallam pada tahun terjadinya haji wada'. Diantara Kami ada yang bertalbiyah untuk melakukan umrah dan diantara Kami ada yang bertalbiyah untuk melakukan haji dan umrah dan diantara Kami ada yang bertalbiyah untuk melakukan haji. Sedangkan Rasulullah shallAllahu wa'alaihi wa sallam bertalbiyah untuk melakukan haji. Adapun orang yang bertalbiyah untuk melakukan haji atau menggabungkan antara haji dan umrah, maka mereka tidak bertahallul hingga pada Hari Nahr (penyembelihan kurban). Abu Daud berkata; [Ibrahim bin Sa'd] dan [Ma'mar] dari [Ibnu Syihab], yang seperti itu. Ia menambahkan; adapun orang yang bertahlil untuk melakukan umrah maka ia bertahallul. "},"1462":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ أَنَّهَا قَالَتْلَبَّيْنَا بِالْحَجِّ حَتَّى إِذَا كُنَّا بِسَرِفَ حِضْتُ فَدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أَبْكِي فَقَالَ مَا يُبْكِيكِ يَا عَائِشَةُ فَقُلْتُ حِضْتُ لَيْتَنِي لَمْ أَكُنْ حَجَجْتُ فَقَالَ سُبْحَانَ اللَّهِ إِنَّمَا ذَلِكَ شَيْءٌ كَتَبَهُ اللَّهُ عَلَى بَنَاتِ آدَمَ فَقَالَ انْسُكِي الْمَنَاسِكَ كُلَّهَا غَيْرَ أَنْ لَا تَطُوفِي بِالْبَيْتِ فَلَمَّا دَخَلْنَا مَكَّةَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ شَاءَ أَنْ يَجْعَلَهَا عُمْرَةً فَلْيَجْعَلْهَا عُمْرَةً إِلَّا مَنْ كَانَ مَعَهُ الْهَدْيُ قَالَتْ وَذَبَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ نِسَائِهِ الْبَقَرَ يَوْمَ النَّحْرِ فَلَمَّا كَانَتْ لَيْلَةُ الْبَطْحَاءِ وَطَهُرَتْ عَائِشَةُ قَالَتْ يَا رَسُولَ اللَّهِ أَتَرْجِعُ صَوَاحِبِي بِحَجٍّ وَعُمْرَةٍ وَأَرْجِعُ أَنَا بِالْحَجِّ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدَ الرَّحْمَنِ بْنَ أَبِي بَكْرٍ فَذَهَبَ بِهَا إِلَى التَّنْعِيمِ فَلَبَّتْ بِالْعُمْرَةِ","id":"Telah menceritakan kepada Kami [Abu Salamah Musa bin Isma'il], telah menceritakan kepada Kami [Hammad] dari [Abdurrahman bin Al Qasim] dari [ayahnya] dari [Aisyah] bahwa ia berkata; Kami bertalbiyah untuk melakukan haji, hingga setelah Kami berada di Saraf aku mengalami haid. Kemudian Rasulullah shallAllahu wa'alaihi wa sallam menemuiku sementara aku sedang dalam keadaan menangis. Lalu beliau berkata: \"Apa yang menyebabkanmu menangis wahai Aisyah?\" Aku katakan; aku telah mengalami haid, seandainya aku belum melakukan haji. Kemudian beliau bersabda: \"SubhanAllah, sesungguhnya hal tersebut adalah sesuatu yang telah Allah tetapkan pada anak-anak wanita Adam.\" Kemudian beliau bersabda: \"Lakukanlah seluruh ibadah haji, hanya saja janganlah engkau melakukan thawaf di Ka'bah.\" Kemudian tatkala Kami memasuki Mekkah Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Barang siapa yang menghendaki untuk menjadikannya sebagai umrah maka silahkan ia menjadikannya umrah, kecuali orang yang membawa hewan kurban.\" Aisyah berkata; Rasulullah shallAllahu wa'alaihi wa sallam menyembelihkan kurban untuk para isterinya satu ekor sapi pada hari Nahr. Kemudian tatkala pada malam singgah di Buthha` dan Aisyah telah suci, Aisyah berkata; wahai Rasulullah, apakah teman-temanku kembali dengan melakukan haji dan umrah sementara aku kembali hanya dengan melakukan haji? Kemudian Rasulullah shallAllahu wa'alaihi wa sallam memerintahkan Abdurrahman bin Abu Bakr untuk pergi ke Tan'im, kemudian ia bertalbiyah untuk melakukan umrah. "},"1463":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ الذُّهَلِيُّ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ اسْتَقْبَلْتُ مِنْ أَمْرِي مَا اسْتَدْبَرْتُ لَمَّا سُقْتُ الْهَدْيَ قَالَ مُحَمَّدٌ أَحْسَبُهُ قَالَ وَلَحَلَلْتُ مَعَ الَّذِينَ أَحَلُّوا مِنْ الْعُمْرَةِقَالَ أَرَادَ أَنْ يَكُونَ أَمْرُ النَّاسِ وَاحِدًا","id":"Telah menceritakan kepada Kami [Muhammad bin Yahya bin Faris Adz Dzuhali], telah menceritakan kepada Kami [Utsman bin Umar], telah mengabarkan kepada Kami [Yunus] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] bahwa Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Jika dulu tampak kepadaku perkara yang terlihat saat ini maka aku tidak akan berkurban dan aku akan menjadikannya sebagai umrah.\" Muhammad berkata; aku mengira beliau berkata: \"dan niscaya aku akan bertahallul bersama orang-orang yang bertahallul dari melakukan umrah.\" Ia berkata; beliau menghendaki kondisi semua orang adalah satu. "},"1464":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَأَقْبَلْنَا مُهِلِّينَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْحَجِّ مُفْرَدًا وَأَقْبَلَتْ عَائِشَةُ مُهِلَّةً بِعُمْرَةٍ حَتَّى إِذَا كَانَتْ بِسَرِفَ عَرَكَتْ حَتَّى إِذَا قَدِمْنَا طُفْنَا بِالْكَعْبَةِ وَبِالصَّفَا وَالْمَرْوَةِ فَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُحِلَّ مِنَّا مَنْ لَمْ يَكُنْ مَعَهُ هَدْيٌ قَالَ فَقُلْنَا حِلُّ مَاذَا فَقَالَ الْحِلُّ كُلُّهُ فَوَاقَعْنَا النِّسَاءَ وَتَطَيَّبْنَا بِالطِّيبِ وَلَبِسْنَا ثِيَابَنَا وَلَيْسَ بَيْنَنَا وَبَيْنَ عَرَفَةَ إِلَّا أَرْبَعُ لَيَالٍ ثُمَّ أَهْلَلْنَا يَوْمَ التَّرْوِيَةِ ثُمَّ دَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى عَائِشَةَ فَوَجَدَهَا تَبْكِي فَقَالَ مَا شَأْنُكِ قَالَتْ شَأْنِي أَنِّي قَدْ حِضْتُ وَقَدْ حَلَّ النَّاسُ وَلَمْ أَحْلُلْ وَلَمْ أَطُفْ بِالْبَيْتِ وَالنَّاسُ يَذْهَبُونَ إِلَى الْحَجِّ الْآنَ فَقَالَ إِنَّ هَذَا أَمْرٌ كَتَبَهُ اللَّهُ عَلَى بَنَاتِ آدَمَ فَاغْتَسِلِي ثُمَّ أَهِلِّي بِالْحَجِّ فَفَعَلَتْ وَوَقَفَتْ الْمَوَاقِفَ حَتَّى إِذَا طَهُرَتْ طَافَتْ بِالْبَيْتِ وَبِالصَّفَا وَالْمَرْوَةِ ثُمَّ قَالَ قَدْ حَلَلْتِ مِنْ حَجِّكِ وَعُمْرَتِكِ جَمِيعًا قَالَتْ يَا رَسُولَ اللَّهِ إِنِّي أَجِدُ فِي نَفْسِي أَنِّي لَمْ أَطُفْ بِالْبَيْتِ حِينَ حَجَجْتُ قَالَ فَاذْهَبْ بِهَا يَا عَبْدَ الرَّحْمَنِ فَأَعْمِرْهَا مِنْ التَّنْعِيمِ وَذَلِكَ لَيْلَةُ الْحَصْبَةِحَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرًا قَالَ دَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى عَائِشَةَ بِبَعْضِ هَذِهِ الْقِصَّةِ قَالَ عِنْدَ قَوْلِهِ وَأَهِلِّي بِالْحَجِّ ثُمَّ حُجِّي وَاصْنَعِي مَا يَصْنَعُ الْحَاجُّ غَيْرَ أَنْ لَا تَطُوفِي بِالْبَيْتِ وَلَا تُصَلِّي","id":"Telah menceritakan kepada Kami [Qutaibah bin Sa'id], Telah menceritakan kepada Kami [Al Laits] dari [Abu Az Zubair] dari [Jabir], ia berkata; Kami datang dalam keadaan bertalbiyah bersama Rasulullah shallAllahu wa'alaihi wa sallam untuk melakukan haji ifrad, sedangkan Aisyah datang dalam keadaan bertalbiyah untuk melakukan umrah hingga setelah ia sampai di Saraf, ia mengalami haid, hingga setalah Kami datang, Kami melakukan thawaf di Ka'bah dan di Shafa serta Marwa. Kemudian Rasulullah shallAllahu wa'alaihi wa sallam memerintahkan Kami agar orang yang tidak membawa hewan kurban melakukan tahallul. Kemudian Kami katakan; tahallul apa? Beliau mengatakan; tahallul secara menyeluruh. Kemudian Kami bercampur dengan para isteri Kami dan memakai minyak wangi, serta memakai pakaian Kami dan antara Kami dan 'Arafah hanya berjarak empat malam. Kemudian Kami bertalbiyah pada hari Tarwiyah. Kemudian Rasulullah shallAllahu wa'alaihi wa sallam menemui Aisyah dan mendapatinya dalam keadaan menangis. Lalu beliau berkata: \"Ada apa denganmu?\" Ia berkata; aku telah mengalami haid, orang-orang telah bertahallul, sementara aku belum bertahallul, dan belum melakukan thawaf di Ka'bah, serta orang-orang sedang pergi untuk melakukan haji sekarang. Kemudian beliau bersabda: \"Sesungguhnya hal ini adalah perkara yang telah Allah tetapkan atas anak-anak wanita Adam, maka mandilah, kemudian bertalbiyahlah untuk melakukan haji.\" Kemudian ia melakukannya dan berwukuf di tempat-tempat wukuf hingga setelah suci ia berthawaf di Ka'bah, serta Shafa dan Marwa. Kemudian beliau berkata: \"Engkau telah bertahallul dari haji dan umrahmu semua.\" Aisyah berkata; wahai Rasulullah, aku mendapati dalam perasaanku bahwa aku belum melakukan thawaf di Ka'bah ketika aku melakukan haji. Beliau bersabda: \"Wahai Abdurrahman, pergilah bersamanya dan umrahkanlah ia dari Tan'im.\" Dan hal tersebut terjadi pada malam hishbah (ketika singgah di Mihshab). Telah menceritakan kepada Kami [Ahmad bin Hanbal], ia berkata; telah menceritakan kepada Kami [Yahya bin Sa'id] dari [Ibnu Juraij], ia berkata; telah mengabarkan kepadaku [Abu Az Zubair] bahwa ia mendengar [Jabir] berkata; Nabi shallallahu 'alaihi wasallam menemui Aisyah …. -ia menceritakan sebagian kisah ini-, ia menyebutkan perkataan Rasulullah shallAllahu wa'alaihi wa sallam: \"dan bertalbiyahlah untuk melakukan haji, kemudian lakukan haji serta kerjakan apa yang dilakukan orang yang melakukan haji, hanya saja janganlah engkau melakukan thawaf di Ka'bah dan jangan melakukan shalat.\""},"1465":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ قَيْسِ بْنِ سَعْدٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ جَابِرٍ قَالَقَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ لِأَرْبَعِ لَيَالٍ خَلَوْنَ مِنْ ذِي الْحِجَّةِ فَلَمَّا طَافُوا بِالْبَيْتِ وَبِالصَّفَا وَالْمَرْوَةِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْعَلُوهَا عُمْرَةً إِلَّا مَنْ كَانَ مَعَهُ الْهَدْيَ فَلَمَّا كَانَ يَوْمُ التَّرْوِيَةِ أَهَلُّوا بِالْحَجِّ فَلَمَّا كَانَ يَوْمُ النَّحْرِ قَدِمُوا فَطَافُوا بِالْبَيْتِ وَلَمْ يَطُوفُوا بَيْنَ الصَّفَا وَالْمَرْوَةِ","id":"Telah menceritakan kepada Kami [Musa bin Isma'il], telah menceritakan kepada Kami [Hammad], dari [Qais bin Sa'd] dari ['Atho` bin Abu Rabah] dari [Jabir], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam datang bersama para sahabatnya selama empat malam selain malam Bulan Dzul Hijjah. Kemudian tatkala mereka telah melakukan thawaf di Ka'bah dan Shafa serta Marwa, Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Jadikanlah umrah, kecuali orang yang membawa hewan kurban.\" Kemudian pada saat Hari Tarwiyah, mereka bertalbiyah untuk melakukan haji. Dan ketika Hari Nahr mereka datang dan melakukan thawaf di Ka'bah, dan tidak berthawaf di Shafa serta Marwa. "},"1466":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ حَدَّثَنَا حَبِيبٌ يَعْنِي الْمُعَلِّمَ عَنْ عَطَاءٍ حَدَّثَنِي جَابِرُ بْنُ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهَلَّ هُوَ وَأَصْحَابُهُ بِالْحَجِّ وَلَيْسَ مَعَ أَحَدٍ مِنْهُمْ يَوْمَئِذٍ هَدْيٌ إِلَّا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَطَلْحَةَ وَكَانَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ قَدِمَ مِنْ الْيَمَنِ وَمَعَهُ الْهَدْيُ فَقَالَ أَهْلَلْتُ بِمَا أَهَلَّ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ أَصْحَابَهُ أَنْ يَجْعَلُوهَا عُمْرَةً يَطُوفُوا ثُمَّ يُقَصِّرُوا وَيُحِلُّوا إِلَّا مَنْ كَانَ مَعَهُ الْهَدْيُ فَقَالُوا أَنَنْطَلِقُ إِلَى مِنًى وَذُكُورُنَا تَقْطُرُ فَبَلَغَ ذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَوْ أَنِّي اسْتَقْبَلْتُ مِنْ أَمْرِي مَا اسْتَدْبَرْتُ مَا أَهْدَيْتُ وَلَوْلَا أَنَّ مَعِي الْهَدْيَ لَأَحْلَلْتُ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Abdul Wahhab Ats Tsaqafi], telah menceritakan kepada Kami [Habib yaitu Al Mu'allim] dari ['Atho`], telah menceritakan kepada Kami [Jabir bin Abdullah] bahwa Rasulullah shallAllahu wa'alaihi wa sallam melakukan talbiyah bersama para sahabatnya untuk melakukan haji, dan pada saat itu tidak ada seorang pun diantara mereka yang membawa hewan kurban kecuali Nabi shallallahu 'alaihi wasallam dan Thalhah. Ali radliallahu 'anhu datang dari Yaman dengan membawa hewan kurban, kemudian ia berkata; aku bertalbiyah seperti talbiyah Rasulullah shallAllahu wa'alaihi wa sallam. Dan Nabi shallallahu 'alaihi wasallam memerintahkan para sahabatnya agar menjadikannya umrah, mereka melakukan thawaf dan mencukur rambut serta bertahallul, kecuali orang yang membawa hewan kurban. Kemudian mereka berkata; apakah Kami pergi ke Mina, sementara dzakar-dzakar Kami meneteskan mani? Kemudian hal tersebut sampai kepada Rasulullah shallAllahu wa'alaihi wa sallam, lalu beliau berkata: \"Jika dulu tampak kepadaku perkara yang terlihat saat ini maka aku tidak akan berkurban, dan seandainya aku tidak membawa hewan kurban niscaya aku akan bertahallul.\""},"1467":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ أَنَّ مُحَمَّدَ بْنَ جَعْفَرٍ حَدَّثَهُمْ عَنْ شُعْبَ��َ عَنْ الْحَكَمِ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ هَذِهِ عُمْرَةٌ اسْتَمْتَعْنَا بِهَا فَمَنْ لَمْ يَكُنْ عِنْدَهُ هَدْيٌ فَلْيُحِلَّ الْحِلَّ كُلَّهُ وَقَدْ دَخَلَتْ الْعُمْرَةُ فِي الْحَجِّ إِلَى يَوْمِ الْقِيَامَةِقَالَ أَبُو دَاوُد هَذَا مُنْكَرٌ إِنَّمَا هُوَ قَوْلُ ابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah] bahwa [Muhammad bin Ja'far] telah menceritakan kepada mereka dari [Syu'bah] dari [Al Hakam] dari [Mujahid] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Ini adalah umrah yang kita nikmati, barang siapa yang tidak membawa hewan kurban maka hendaknya ia bertahallul secara menyeluruh, sungguh umrah telah masuk dalam haji hingga hari Kiamat.\" Abu Daud berkata; ini adalah hadits munkar, hal tersebut adalah perkataan Ibnu Abbas. "},"1468":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ شَوْكَرٍ وَأَحْمَدُ بْنُ مَنِيعٍ قَالَا حَدَّثَنَا هُشَيْمٌ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ قَالَ ابْنُ مَنِيعٍ أَخْبَرَنَا يَزِيدُ بْنُ أَبِي زِيَادٍ الْمَعْنَى عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَأَهَلَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْحَجِّ فَلَمَّا قَدِمَ طَافَ بِالْبَيْتِ وَبَيْنَ الصَّفَا وَالْمَرْوَةِ وَقَالَ ابْنُ شَوْكَرٍ وَلَمْ يُقَصِّرْ ثُمَّ اتَّفَقَا وَلَمْ يُحِلَّ مِنْ أَجْلِ الْهَدْيِ وَأَمَرَ مَنْ لَمْ يَكُنْ سَاقَ الْهَدْيَ أَنْ يَطُوفَ وَأَنْ يَسْعَى وَيُقَصِّرَ ثُمَّ يُحِلَّ زَادَ ابْنُ مَنِيعٍ فِي حَدِيثِهِ أَوْ يَحْلِقَ ثُمَّ يُحِلَّ","id":"Telah menceritakan kepada Kami [Al Hasan bin Syaukar], dan [Ahmad bin Mani'], mereka berkata; telah menceritakan kepada Kami [Husyaim] dari [Yazid bin Abu Ziyad], [Ibnu Mani'] berkata; telah mengabarkan kepada Kami [Yazid bin Abu Ziyad] secara makna dari [Mujahid] dari [Ibnu Abbas], ia berkata; Nabi shallallahu 'alaihi wasallam bertalbiyah untuk melakukan haji, kemudian tatkala datang, beliau berthawaf di Ka'bah, dan Shafa serta Marwa. Ibnu Syaukar berkata; dan beliau tidak mencukur rambut, kemudian keduanya bersepakat (dalam kalimat selanjutnya); dan beliau tidak bertahallul karena keberadaan hewan kurban, dan beliau memerintahkan orang yang tidak menuntun hewan kurban agar berthawaf dan bersa'i serta mencukur rambut, kemudian bertahallul. Ibnu Mani' dalam haditsnya menambahkan; atau menggundul rambut kemudian bertahallul."},"1469":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ قَالَ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا يَحْيَى بْنُ أَبِي إِسْحَقَ وَعَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ وَحُمَيْدٌ الطَّوِيلُ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُمْ سَمِعُوهُ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُلَبِّي بِالْحَجِّ وَالْعُمْرَةِ جَمِيعًا يَقُولُ لَبَّيْكَ عُمْرَةً وَحَجًّا لَبَّيْكَ عُمْرَةً وَحَجًّا","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], ia berkata; telah menceritakan kepada Kami [Husyaim], telah mengabarkan kepada Kami [Yahya bin Abu Ishaq] dan [Abdul Aziz bin Shuhaib] serta [Humaid Ath Thawil] dari [Anas bin Malik] bahwa mereka mendengarnya berkata; saya mendengar Rasulullah shallAllahu wa'alaihi wa sallam bertalbiyah untuk melakukan haji dan umrah secara bersamaan. Beliau mengucapkan: \"Labbaika 'umratan wa hajjan, labbaika 'umratan wa hajjan (aku memenuhi seruanMu untuk melakukan umrah dan haji.\""},"1470":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَاتَ بِهَا يَعْنِي بِذِي الُحُلَيْفَةِ حَتَّى أَصْبَحَ ثُمَّ رَكِبَ حَتَّى إِذَا اسْتَوَتْ بِهِ عَلَى الْبَيْدَاءِ حَمِدَ اللَّهُ وَسَبَّحَ وَكَبَّرَ ثُمَّ أَهَلَّ بِحَجٍّ وَعُمْرَةٍ وَأَهَلَّ النَّاسُ بِهِمَا فَلَمَّا قَدِمْنَا أَمَرَ النَّاسَ فَحَلُّوا حَتَّى إِذَا كَانَ يَوْمُ التَّرْوِيَةِ أَهَلُّوا بِالْحَجِّ وَنَحَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعَ بَدَنَاتٍ بِيَدِهِ قِيَامًاقَالَ أَبُو دَاوُد الَّذِي تَفَرَّدَ بِهِ يَعْنِي أَنَسًا مِنْ هَذَا الْحَدِيثِ أَنَّهُ بَدَأَ بِالْحَمْدِ وَالتَّسْبِيحِ وَالتَّكْبِيرِ ثُمَّ أَهَلَّ بِالْحَجِّ","id":"Telah menceritakan kepada Kami [Abu Salamah Musa bin Isma'il], telah menceritakan kepada Kami [Wuhaib], telah menceritakan kepada Kami [Ayyub] dari [Abu Qilabah] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam bermalam di sana yaitu di Dzul Hulaifah hingga pagi hari, kemudian menaiki kendaraan hingga setelah berada di atas Baida` beliau memuji Allah dan bertasbih serta bertakbir. Kemudian beliau bertalbiyah untuk melakukan haji dan umrah, dan orang-orang bertalbiyah untuk melakukan keduanya. Kemudian tatkala Kami datang beliau memerintahkan orang-orang agar bertahallul hingga ketika pada Hari Tarwiyah mereka bertalbiyah untuk melakukan haji, dan Rasulullah shallAllahu wa'alaihi wa sallam menyembelih tujuh unta dengan tangannya dalam keadaan berdiri. Abu Daud berkata; yang menjadi diriwayatkan Anas sendiri dari hadits ini adalah bahwa beliau memulai dengan memuji, bertasbih serta bertakbir kemudian bertalbiyah untuk melakukan haji. "},"1471":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُعِينٍ قَالَ حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا يُونُسُ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَكُنْتُ مَعَ عَلِيٍّ حِينَ أَمَّرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْيَمَنِ قَالَ فَأَصَبْتُ مَعَهُ أَوَاقِيَ فَلَمَّا قَدِمَ عَلِيٌّ مِنْ الْيَمَنِ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَجَدْتُ فَاطِمَةَ رَضِيَ اللَّهُ عَنْهَا قَدْ لَبِسَتْ ثِيَابًا صَبِيغًا وَقَدْ نَضَحَتْ الْبَيْتَ بِنَضُوحٍ فَقَالَتْ مَا لَكَ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَمَرَ أَصْحَابَهُ فَأَحَلُّوا قَالَ قُلْتُ لَهَا إِنِّي أَهْلَلْتُ بِإِهْلَالِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي كَيْفَ صَنَعْتَ فَقَالَ قُلْتُ أَهْلَلْتُ بِإِهْلَالِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَإِنِّي قَدْ سُقْتُ الْهَدْيَ وَقَرَنْتُ قَالَ فَقَالَ لِي انْحَرْ مِنْ الْبُدْنِ سَبْعًا وَسِتِّينَ أَوْ سِتًّا وَسِتِّينَ وَأَمْسِكْ لِنَفْسِكَ ثَلَاثًا وَثَلَاثِينَ أَوْ أَرْبَعًا وَثَلَاثِينَ وَأَمْسِكْ لِي مِنْ كُلِّ بَدَنَةٍ مِنْهَا بَضْعَةً","id":"Telah menceritakan kepada Kami [Yahya bin Ma'in], ia berkata; telah menceritakan kepada Kami [Hajjaj], telah menceritakan kepada Kami [Yunus] dari [Abu Ishaq] dari [Al Bara` bin 'Azib], ia berkata; aku pernah bersama Ali ketika Rasulullah shallAllahu wa'alaihi wa sallam mengangkatnya sebagai pemimpin di Yaman. Ia berkata; aku bersamanya mendapatkan uang beberapa uqiyah, kemudian tatkala Ali datang dari Yaman kepada Rasulullah shallAllahu wa'alaihi wa sallam, ia berkata; aku mendapati Fathimah radliallahu 'anha memakai pakaian yang longgar, ia telah memerciki rumah dengan minyak wangi. Kemudian ia berkata; ada apa denganmu? Sesungguhnya Rasulullah shallAllahu wa'alaihi wa sallam telah memerintahkan para sahabatnya agar bertahallul. Ali berkata; aku katakan kepadanya; aku telah bertalbiyah seperti talbiyahnya Rasulullah shallAllahu wa'alaihi wa sallam. Ali berkata; kemudian aku datang kepada Nabi shallallahu 'alaihi wasallam, kemudian beliau berkata kepadaku: bagaimana engkau berbuat? Ia berkata; aku katakan; aku bertalbiyah dengan talbiyah Nabi shallallahu 'alaihi wasallam. Beliau bersabda: \"Sungguh aku telah membawa hewan kurban, dan melakukan haji qiran.\" Ali berkata; kemudian beliau berkata kepadaku; sembelihlah enam puluh enam atau enam puluh enam unta dan tahanlah untuk dirimu tiga puluh tiga atau tiga puluh empat dan tahan untukku dari setiap unta tersebut antara tiga hingga sembilan ekor. "},"1472":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرُ بْنُ عَبْدِ الْحَمِيدِ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ قَالَ قَالَ الصُّبَيُّ بْنُ مَعْبَدٍأَهْلَلْتُ بِهِمَا مَعًا فَقَالَ عُمَرُ هُدِيتَ لِسُنَّةِ نَبِيِّكَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Jarir bin Abdul Hamid] dari [Manshur] dari [Abu Wail], ia berkata; [Ash Shubai bin Ma'bad] telah berkata; aku bertalbiyah untuk melakukan keduanya secara bersamaan. Kemudian [Umar] berkata; engkau telah mendapatkan petunjuk untuk mengikuti sunah Nabimu shallallahu 'alaihi wasallam. "},"1473":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ قُدَامَةَ بْنِ أَعْيَنَ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ الْمَعْنَى قَالَا حَدَّثَنَا جَرِيرُ بْنُ عَبْدِ الْحَمِيدِ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ قَالَ قَالَ الصُّبَيُّ بْنُ مَعْبَدٍكُنْتُ رَجُلًا أَعْرَابِيًّا نَصْرَانِيًّا فَأَسْلَمْتُ فَأَتَيْتُ رَجُلًا مِنْ عَشِيرَتِي يُقَالُ لَهُ هُذَيْمُ بْنُ ثُرْمُلَةَ فَقُلْتُ لَهُ يَا هَنَاهْ إِنِّي حَرِيصٌ عَلَى الْجِهَادِ وَإِنِّي وَجَدْتُ الْحَجَّ وَالْعُمْرَةَ مَكْتُوبَيْنِ عَلَيَّ فَكَيْفَ لِي بِأَنْ أَجْمَعَهُمَا قَالَ اجْمَعْهُمَا وَاذْبَحْ مَا اسْتَيْسَرَ مِنْ الْهَدْيِ فَأَهْلَلْتُ بِهِمَا مَعًا فَلَمَّا أَتَيْتُ الْعُذَيْبَ لَقِيَنِي سَلْمَانُ بْنُ رَبِيعَةَ وَزَيْدُ بْنُ صُوحَانَ وَأَنَا أُهِلُّ بِهِمَا جَمِيعًا فَقَالَ أَحَدُهُمَا لِلْآخَرِ مَا هَذَا بِأَفْقَهَ مِنْ بَعِيرِهِ قَالَ فَكَأَنَّمَا أُلْقِيَ عَلَيَّ جَبَلٌ حَتَّى أَتَيْتُ عُمَرَ بْنَ الْخَطَّابِ فَقُلْتُ لَهُ يَا أَمِيرَ الْمُؤْمِنِينَ إِنِّي كُنْتُ رَجُلًا أَعْرَابِيًّا نَصْرَانِيًّا وَإِنِّي أَسْلَمْتُ وَأَنَا حَرِيصٌ عَلَى الْجِهَادِ وَإِنِّي وَجَدْتُ الْحَجَّ وَالْعُمْرَةَ مَكْتُوبَيْنِ عَلَيَّ فَأَتَيْتُ رَجُلًا مِنْ قَوْمِي فَقَالَ لِي اجْمَعْهُمَا وَاذْبَحْ مَا اسْتَيْسَرَ مِنْ الْهَدْيِ وَإِنِّي أَهْلَلْتَ بِهِمَا مَعًا فَقَالَ لِي عُمَرُ رَضِيَ اللَّهُ عَنْهُ هُدِيتَ لِسُنَّةِ نَبِيِّكَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada Kami [Muhammad bin Qudamah bin A'yan] serta [Utsman bin Abu Syaibah] secara makna, mereka berkata; telah menceritakan kepada Kami [Jarir bin Abdul Hamid] dari [Manshur] dari [Abu Wail], ia berkata; [Ash Shubai bin Ma'bad] berkata; dahulu aku adalah orang badui yang beragama nasrani, kemudian aku masuk Islam, lalu aku menemui seseorang dari keluargaku yang dipanggil Hudzail bin Tsurmulah, kemudian aku katakan kepadanya; wahai orang ini, sesungguhnya aku sangat ingin untuk berjihad, dan aku mendapati haji dan umrah adalah sesuatu yang diwajibkan kepadaku, bagaimana aku menggabungkan keduanya? Ia berkata; ia berkata; gabungkan keduanya dan sembelihlah hewan kurban yang mudah bagimu untuk melakukan keduanya secara bersamaan. Kemudian tatkala aku datang ke 'Udzaib (nama sumber air milik Bani Tamim), aku berjumpa dengan Salman bin Rabi'ah dan Zaid bin Shuhan, sementara aku sedang bertalbiyah untuk melakukan keduanya secara bersamaan. Kemudian salah seorang dari mereka berkata kepada yang lainnya; orang ini tidak lebih pandai daripada untanya. Ash Shubai bin Ma'bad berkata; seolah-olah telah ditimpakan sebuah gunung kepadaku, hingga aku datang kepada [Umar bin Al Khathab] dan mengatakan kepadanya; wahai amirul mukminin, sesungguhnya dahulu aku adalah orang yang beragama nasrani, dan aku telah masuk Islam. Aku sangat berkeinginan untuk berjihad, sementara aku mendapati haji dan umrah diwajibkan atas diriku. Kemudian aku datang kepada seorang laki-laki dari kaumku, lalu ia berkata; gabungkan keduanya dan sembelihlah hewan kurban yang mudah. Dan kau telah bertalbiyah untuk melakukan keduanya secara bersamaan. Kemudian Umar radliallahu 'anhu berkata kepadaku; engkau telah mendapatkan petunjuk untuk melakukan sunah Nabimu shallallahu 'alaihi wasallam. "},"1474":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا مِسْكِينٌ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عِكْرِمَةَ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُ حَدَّثَنِي عُمَرُ بْنُ الْخَطَّابِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَتَانِي اللَّيْلَةَ آتٍ مِنْ عِنْدِ رَبِّي عَزَّ وَجَلَّ قَالَ وَهُوَ بِالْعَقِيقِ وَقَالَ صَلِّ فِي هَذَا الْوَادِي الْمُبَارَكِ وَقَالَ عُمْرَةٌ فِي حَجَّةٍقَالَ أَبُو دَاوُد رَوَاهُ الْوَلِيدُ بْنُ مُسْلِمٍ وَعُمَرُ بْنُ عَبْدِ الْوَاحِدِ فِي هَذَا الْحَدِيثِ عَنْ الْأَوْزَاعِيِّ وَقُلْ عُمْرَةٌ فِي حَجَّةٍ قَالَ أَبُو دَاوُد وَكَذَا رَوَاهُ عَلِيُّ بْنُ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ فِي هَذَا الْحَدِيثِ وَقَالَ وَقُلْ عُمْرَةٌ فِي حَجَّةٍ","id":"Telah menceritakan kepada Kami [An Nufaili] telah menceritakan kepada Kami [Miskin] dari [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Ikrimah], ia berkata; saya mendengar [Ibnu Abbas] berkata; telah menceritakan kepadaku [Umar bin Al Khathab] bahwa ia mendengar Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Tadi malam telah datang kepadaku malaikat yang datang dari sisi Tuhanku 'azza wajalla. beliau mengatakan -dan beliau berada di Al 'Aqiq-: \"Dan ia berkata; shalatlah di lembah yang mendapat berkah ini. Dan ia berkata; serta umrah dalam haji.\" Abu Daud berkata; hadits tersebut diriwayatkan oleh [Al Walid bin Muslim], serta [Umar bin Abdul Wahid] dalam hadits ini, dari [Al Auza'i]; dan katakan; umrah dalam haji. Abu Daud berkata; demikianlah yang diriwayatkan oleh [Ali bin Al Mubarak], dari [Yahya bin Abu Katsir] dalam haidts ini, dan ia menyebutkan kata; dan katakanlah; umrah dalam haji. "},"1475":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ نَجْدَةَ حَدَّثَنَا شُعَيْبُ بْنُ إِسْحَقَ عَنْ ابْنِ جُرَيْجٍ حَدَّثَنَا أَبُو بَكْرِ بْنِ خَلَّادٍ حَدَّثَنَا يَحْيَى الْمَعْنَى عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي الْحَسَنُ بْنُ مُسْلِمٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ مُعَاوِيَةَ بْنَ أَبِي سُفْيَانَ أَخْبَرَهُ قَالَقَصَّرْتُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِشْقَصٍ عَلَى الْمَرْوَةِ أَوْ رَأَيْتُهُ يُقَصِّرُ عَنْهُ عَلَى الْمَرْوَةِ بِمِشْقَصٍ قَالَ ابْنُ خَلَّادٍ إِنَّ مُعَاوِيَةَ لَمْ يَذْكُرْ أَخْبَرَهُ","id":"Telah menceritakan kepada Kami [Abdul Wahhab bin Najdah], telah menceritakan kepada Kami [Syu'aib bin Ishaq] dari [Ibnu Juraij], telah menceritakan kepada Kami [Abu Bakr bin Khallad], telah menceritakan kepada Kami [Yahya] secara makna, dari [Ibnu Juraij], telah mengabarkan kepadaku [Al Hasan bin Muslim] dari [Thawus] dari [Ibnu Abbas] bahwa [Mu'awiyah bin Abu Sufyan] telah mengabarkan kepadanya, ia berkata; aku memendekkan rambut Nabi shallallahu 'alaihi wasallam menggunakan bagian anak panah yang tajam di atas bukit Marwa, atau aku melihat beliau memendekkan rambut di atas bukit Marwa menggunakan bagian anak panah yang tajam. Ibnu Khallad berkata; sesungguhnya Mu'awiyah…. Ia tidak menyebutkan; telah mengabarkan kepadanya."},"1476":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ وَمَخْلَدُ بْنُ خَالِدٍ وَمُحَمَّدُ بْنُ يَحْيَى الْمَعْنَى قَالُوا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ أَنَّ مُعَاوِيَةَ قَالَ لَهُأَمَا عَلِمْتَ أَنِّي قَصَّرْتُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِشْقَصِ أَعْرَابِيٍّ عَلَى الْمَرْوَةِ زَادَ الْحَسَنُ فِي حَدِيثِهِ لِحَجَّتِهِ","id":"Telah menceritakan kepada Kami [Al Hasan bin Ali] serta [Makhlad bin Khalid] dan [Muhammad bin Yahya] secara makna. Mereka mengatakan; telah menceritakan kepada Kami [Abdurrazzaq], telah mengabarkan kepada Kami [Ma'mar] dari [Ibnu Thawus] dari [ayahnya], dari [Ibnu Abbas] bahwa [Mu'awiyah] berkata kepadanya; tidakkah engkau tahu bahwa aku yang memendekkan rambut Rasulullah shallAllahu wa'alaihi wa sallam menggunakan bagian anak panah yang tajam milik seorang badui di atas Bukit Marwa? Al Hasan menambahkan dalam haditsnya kata; untuk haji beliau. "},"1477":{"ar":"حَدَّثَنَا ابْنُ مُعَاذٍ أَخْبَرَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ مُسْلِمٍ الْقُرِّيِّ سَمِعَ ابْنَ عَبَّاسٍ يَقُولُأَهَلَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعُمْرَةٍ وَأَهَلَّ أَصْحَابُهُ بِحَجٍّ","id":"Telah menceritakan kepada Kami [Ibnu Mu'adz] telah mengabarkan kepada Kami [ayahku], telah menceritakan kepada Kami [Syu'bah], dari [Muslim Al Qurri], ia mendengar [Ibnu Abbas] berkata; Nabi shallallahu 'alaihi wasallam bertalbiyah untuk melakukan Umrah sedangkan para sahabatnya bertalbiyah untuk melakukan haji. "},"1478":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ حَفْصَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا قَالَتْيَا رَسُولَ اللَّهِ مَا شَأْنُ النَّاسِ قَدْ حَلُّوا وَلَمْ تُحْلِلْ أَنْتَ مِنْ عُمْرَتِكَ فَقَالَ إِنِّي لَبَّدْتُ رَأْسِي وَقَلَّدْتُ هَدْيِي فَلَا أُحِلُّ حَتَّى أَنْحَرَ الْهَدْيَ","id":"Telah menceritakan kepada Kami [Al Qa'nabi] dari [Malik] dari [Nafi'] dari [Abdullah bin Umar], dari [Hafshah] isteri Nabi shallallahu 'alaihi wasallam bahwa ia berkata; wahai Rasulullah, kenapa orang-orang telah bertahalul sementara anda belum bertahalul dari umrahmu? Beliau berkata; sesungguhnya aku telah mencelup rambut kepalaku dan mengalungi hewan kurbanku, maka aku tidak bertahalul hingga menyembelih kurban. "},"1479":{"ar":"حَدَّثَنَا هَنَّادٌ يَعْنِي ابْنَ السَّرِيِّ عَنْ ابْنِ أَبِي زَائِدَةَ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ سُلَيْمِ بْنِ الْأَسْوَدِ أَنَّ أَبَا ذَرٍّكَانَ يَقُولُ فِيمَنْ حَجَّ ثُمَّ فَسَخَهَا بِعُمْرَةٍ لَمْ يَكُنْ ذَلِكَ إِلَّا لِلرَّكْبِ الَّذِينَ كَانُوا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada Kami [Hannad yaitu Ibnu As Sari] dari [Ibnu Abu Zaidah], telah mengabarkan kepada Kami [Muhammad bin Ishaq] dari [Abdurrahman bin Al Aswad] dari [Sulaim bin Al Aswad] bahwa [Abu Dzar] berkata mengenai orang yang ingin haji lalu menggantinya dengan umrah; hal tersebut tidak berlaku kecuali hanya bagi orang yang berkendaraan ketika bersama Rasulullah shallla Allahu 'alaihi wa sallam. "},"1480":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ مُحَمَّدٍ أَخْبَرَنِي رَبِيعَةُ بْنُ أَبِي عَبْدِ الرَّحْمَنِ عَنْ الْحَارِثِ بْنِ بِلَالِ بْنِ الْحَارِثِ عَنْ أَبِيهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ فَسْخُ الْحَجِّ لَنَا خَاصَّةٌ أَوْ لِمَنْ بَعْدَنَا قَالَ بَلْ لَكُمْ خَاصَّةٌ","id":"Telah menceritakan kepada Kami [An Nufaili], telah menceritakan kepada Kami [Abdul Aziz yaitu Ibnu Muhammad], telah mengabarkan kepadaku [Rabi'ah bin Abu Abdurrahman] dari [Al Harits bin Bilal bin Al Harits] dari [ayahnya], ia berkata; aku katakan; wahai Rasulullah, mengganti haji khusus untuk kita atau untuk orang setelah kita? Beliau menjawab: \"Khusus untuk kita.\""},"1481":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَكَانَ الْفَضْلُ بْنُ عَبَّاسٍ رَدِيفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَتْهُ امْرَأَةٌ مِنْ خَثْعَمٍ تَسْتَفْتِيهِ فَجَعَلَ الْفَضْلُ يَنْظُرُ إِلَيْهَا وَتَنْظُرُ إِلَيْهِ فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْرِفُ وَجْهَ الْفَضْلِ إِلَى الشِّقِّ الْآخَرِ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ فَرِيضَةَ اللَّهِ عَلَى عِبَادِهِ فِي الْحَجِّ أَدْرَكَتْ أَبِي شَيْخًا كَبِيرًا لَا يَسْتَطِيعُ أَنْ يَثْبُتَ عَلَى الرَّاحِلَةِ أَفَأَحُجُّ عَنْهُ قَالَ نَعَمْ وَذَلِكَ فِي حَجَّةِ الْوَدَاعِ","id":"Telah menceritakan kepada Kami [Al Qa'nabi], dari [Malik] dari [Ibnu Syihab] dari [Sulaiman bin Yasar] dari [Abdullah bin Abbas], ia berkata; Al Fadhl bin Abbas pernah membonceng Rasulullah shallAllahu wa'alaihi wa sallam, kemudian datang seorang wanita dari Khats'am yang bertanya kepada beliau; dan Al Fadhl melihat kepadanya, dan wanita tersebut melihat kepadanya. Kemudian Rasulullah shallAllahu wa'alaihi wa sallam memalingkan wajah Al Fadhl ke sisi yang lain. Wanita tersebut berkata; wahai Rasulullah, sesungguhnya kewajiban yang Allah bebankan kepada para hambaNya untuk melakukan haji telah menjumpai ayahku yang tua renta, dan tidak mampu untuk duduk di atas kendaraan. Apakah aku boleh berhaji untuknya? Beliau mengatakan: \"Ya.\" Dan hal tersebut di saat terjadinya haji wada'. "},"1482":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ وَمُسْلِمُ بْنُ إِبْرَاهِيمَ بِمَعْنَاهُ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ النُّعْمَانِ بْنِ سَالِمٍ عَنْ عَمْرِو بْنِ أَوْسٍ عَنْ أَبِي رَزِينٍقَالَ حَفْصٌ فِي حَدِيثِهِ رَجُلٌ مِنْ بَنِي عَامِرٍ أَنْهِ قَال يَا رَسُولَ اللَّهِ إِنَّ أَبِي شَيْخٌ كَبِيرٌ لَا يَسْتَطِيعُ الْحَجَّ وَلَا الْعُمْرَةَ وَلَا الظَّعْنَ قَالَ احْجُجْ عَنْ أَبِيكَ وَاعْتَمِرْ","id":"Telah menceritakan kepada Kami [Hafsh bin Umar] dan [Muslim bin Ibrahim] secara makna, mereka berkata; telah menceritakan kepada Kami [Syu'bah] dari [An Nu'man bin Salim] dari ['Amr bin Aus] dari [Abu Razin], Hafsh berkata; dalam haditsnya; terdapat seorang laki-laki dari Bani Amir berkata; wahai Rasulullah, sesungguhnya ayahku telah tua renta, ia tidak mampu untuk melakukan haji dan umrah serta bersafar. Beliau bersabda: \"Berhaji dan berumrahlah untuk ayahmu!\""},"1483":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِسْمَعِيلَ الطَّالَقَانِيُّ وَهَنَّادُ بْنُ السَّرِيِّ الْمَعْنَى وَاحِدٌ قَالَ إِسْحَقُ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ ابْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ عَزْرَةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعَ رَجُلًا يَقُولُ لَبَّيْكَ عَنْ شُبْرُمَةَ قَالَ مَنْ شُبْرُمَةُ قَالَ أَخٌ لِي أَوْ قَرِيبٌ لِي قَالَ حَجَجْتَ عَنْ نَفْسِكَ قَالَ لَا قَالَ حُجَّ عَنْ نَفْسِكَ ثُمَّ حُجَّ عَنْ شُبْرُمَةَ","id":"Telah menceritakan kepada Kami [Ishaq bin Isma'il Ath Thalaqani] serta [Hannad bin As Sari] dengan satu makna, [Ishaq] berkata; telah menceritakan kepada Kami ['Abdah bin Sulaiman] dari [Ibnu Abu 'Arubah] dari [Qatadah] dari ['Azrah] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa Nabi shalla Allahu 'alaihi wa sallam mendengar seseorang mengucapkan; LABBAIKA 'AN SYUBRUMAH (ya Allah, aku memenuhi seruanmu untuk Syubrumah), beliau bertanya: \"Siapakah Syubrumah tersebut?\" Dia menjawab; saudaraku! Atau kerabatku! Beliau bertanya: \"Apakah engkau telah melaksanakan haji untuk dirimu sendiri?\" Dia menjawab; belum! Beliau berkata: \"Laksanakan haji untuk dirimu, kemudian berhajilah untuk Syubrumah.\""},"1484":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ تَلْبِيَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَبَّيْكَ اللَّهُمَّ لَبَّيْكَ لَبَّيْكَ لَا شَرِيكَ لَكَ لَبَّيْكَ إِنَّ الْحَمْدَ وَالنِّعْمَةَ لَكَ وَالْمُلْكَ لَا شَرِيكَ لَكَقَالَ وَكَانَ عَبْدُ اللَّهِ بْنُ عُمَرَ يَزِيدُ فِي تَلْبِيَتِهِ لَبَّيْكَ لَبَّيْكَ لَبَّيْكَ وَسَعْدَيْكَ وَالْخَيْرُ بِيَدَيْكَ وَالرَّغْبَاءُ إِلَيْكَ وَالْعَمَلُ حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا جَعْفَرٌ حَدَّثَنَا أَبِي عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ أَهَلَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ التَّلْبِيَةَ مِثْلَ حَدِيثِ ابْنِ عُمَرَ قَالَ وَالنَّاسُ يَزِيدُونَ ذَا الْمَعَارِجِ وَنَحْوَهُ مِنْ الْكَلَامِ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْمَعُ فَلَا يَقُولُ لَهُمْ شَيْئًا","id":"Telah menceritakan kepada Kami [Al Qa'nabi] dari [Malik] dari [Nafi'] dari [Abdullah bin Umar] bahwa talbiyah Rasulullah shallAllahu wa'alaihi wa sallam adalah: \"LABBAIKALLAAHUMMA LABBAIK, LABBAIKA LAA SYARIIKALAKA LABBAIK, INNAL HAMDA WAN NI'MATA LAKA WAL MULKA LAA SYARIIKALAK (aku memenuhi seruanMu ya Allah, aku memenuhi seruanMu, tidak ada sekutu bagiMu, aku memenuhi seruanMu. Sesunggguhnya segala puji dan kenikmatan, serta seluruh kerajaan adalah milikMu, tidak ada sekutu bagiMu). Nafi' berkata; dan Abdullah bin Umar menambahkan dalam talbiyah; LABBAIKA, LABBAIKA, LABBAIK, WA SA'DAIK, WAL KHAIRU BIYADAIK, WAR RAGHBU ILAIKA WAL 'AMALU (aku memenuhi seruanMu, aku memenuhi seruanMu, aku memenuhi seruanMu, dan dalam rangka untuk menyenangkanMu, segala kebaikan ada di tanganMu, harapan dan amalan tertuju kepadaMu). Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Yahya bin Sa'id], telah menceritakan kepada Kami [Ja'far], telah menceritakan kepada Kami [ayahku] dari [Jabir bin Abdullah], ia berkata; dan orang-orang menambahkan kata; Dzal ma'arij, dan semisalnya. Sedang Nabi shallallahu 'alaihi wasallam mendengar dan tidak mengatakan sesuatupun kepada mereka. "},"1485":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ خَلَّادِ بْنِ السَّائِبِ الْأَنْصَارِيِّ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَتَانِي جِبْرِيلُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَنِي أَنْ آمُرَ أَصْحَابِي وَمَنْ مَعِي أَنْ يَرْفَعُوا أَصْوَاتَهُمْ بِالْإِهْلَالِ أَوْ قَالَ بِالتَّلْبِيَةِ يُرِيدُ أَحَدَهُمَا","id":"Telah menceritakan kepada Kami [Al Qa'nabi] dari [Malik] dari [Abdullah bin Abu Bakr bin Muhammad bin 'Amr bin Hazm] dari [Abdul Malik bin Abu Bakr bin Abdurrahman bin Al Haritsb Hisyam] dari [Khallad bin As Saib Al Anshari] dari [ayahnya] bahwa Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Jibril shallallahu 'alaihi wasallam telah datang kepadaku dan memerintahkanku agar memerintahkan para sahabatku dan orang-orang yang bersamanya agar mengeraskan suara mereka ketika bertahlil atau beliau mengatakan dengan talbiyah.\" Beliau menginginkan salah satu darinya. "},"1486":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ عَنْ الْفَضْلِ بْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَبَّى حَتَّى رَمَى جَمْرَةَ الْعَقَبَةِ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal] telah menceritakan kepada Kami [Waki'] telah menceritakan kepada Kami [Ibnu Juraij] dari ['Atha`] dari [Ibnu Abbas] dari [Al Fadhl bin Abbas] bahwa Rasulullah shallAllahu wa'alaihi wa sallam bertalbiyah hingga melempar jumrah 'aqabah. "},"1487":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ قَالَغَدَوْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ مِنًى إِلَى عَرَفَاتٍ مِنَّا الْمُلَبِّي وَمِنَّا الْمُكَبِّرُ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal] telah menceritakan kepada Kami [Abdullah bin Numair], telah menceritakan kepada Kami [Yahya bin Sa'id] dari [Abdullah bin Abu Salamah] dari [Abdullah bin Abdullah bin Umar] dari [ayahnya], ia berkata; Kami pergi bersama Rasulullah shallAllahu wa'alaihi wa sallam dari Mina menuju 'Arafah, diantara Kami ada yang bertalbiyah dan diantara Kami ada yang bertakbir. "},"1488":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا هُشَيْمٌ عَنْ ابْنِ أَبِي لَيْلَى عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُلَبِّي الْمُعْتَمِرُ حَتَّى يَسْتَلِمَ الْحَجَرَقَالَ أَبُو دَاوُد رَوَاهُ عَبْدُ الْمَلِكِ بْنُ أَبِي سُلَيْمَانَ وَهَمَّامٌ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ مَوْقُوفًا","id":"Telah menceritakan kepada Kami [Musaddad] telah menceritakan kepada Kami [Husyaim] dari [Ibnu Abu Laila] dari ['Atho`] dari [Ibnu Abbas] dari Nabi shalla Allahu 'alaihi wa sallam berkata: \"Seorang yang melakukan umrah hendaknya mengucapkan talbiyah hingga mengusap hajar aswad. Abu Daud berkata: hadits tersebut diriwayatkan oleh [Abdul Malik bin Abu Sulaiman] dan [Hammam] dari ['Atho`] dari [Ibnu Abbas] secara mauquf. "},"1489":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ قَالَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْعَزِيزِ بْنِ أَبِي رِزْمَةَ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ أَخْبَرَنَا ابْنُ إِسْحَقَ عَنْ يَحْيَى بْنِ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ قَالَتْخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُجَّاجًا حَتَّى إِذَا كُنَّا بِالْعَرْجِ نَزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَزَلْنَا فَجَلَسَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا إِلَى جَنْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَلَسْتُ إِلَى جَنْبِ أَبِي وَكَانَتْ زِمَالَةُ أَبِي بَكْرٍ وَزِمَالَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاحِدَةً مَعَ غُلَامٍ لِأَبِي بَكْرٍ فَجَلَسَ أَبُو بَكْرٍ يَنْتَظِرُ أَنْ يَطْلُعَ عَلَيْهِ فَطَلَعَ وَلَيْسَ مَعَهُ بَعِيرُهُ قَالَ أَيْنَ بَعِيرُكَ قَالَ أَضْلَلْتُهُ الْبَارِحَةَ قَالَ فَقَالَ أَبُو بَكْرٍ بَعِيرٌ وَاحِدٌ تُضِلُّهُ قَالَ فَطَفِقَ يَضْرِبُهُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَبَسَّمُ وَيَقُولُ انْظُرُوا إِلَى هَذَا الْمُحْرِمِ مَا يَصْنَعُ قَالَ ابْنُ أَبِي رِزْمَةَ فَمَا يَزِيدُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَنْ يَقُولَ انْظُرُوا إِلَى هَذَا الْمُحْرِمِ مَا يَصْنَعُ وَيَتَبَسَّمُ","id":"telah menceritakan kepada Kami [Ahmad bin Hanbal], ia berkata; …. dan diriwayatkan dari jalur yang lain: telah menceritakan kepada Kami [Muhammad bin Abdul Aziz bin Abu Rizmah], telah mengabarkan kepada Kami [Abdullah bin Idris], telah mengabarkan kepada Kami [Ibnu Ishaq] dari [Yahya bin 'Abbad bin Abdullah bin Az Zubair], dari [ayahnya] dari [Asma` binti Abu Bakr], ia berkata; Kami keluar bersama Rasulullah shallla Allahu 'alaihi wa sallam untuk melaksanakan haji, hingga ketika Kami sampai di 'Arj, Rasulullah shallallahu 'alaihi wasallam singgah dan Kami pun singgah, dan Aisyah radliallahu 'anha duduk disisi Rasulullah shallla Allahu 'alaihi wa sallam dan aku duduk di sisi bapakku. Kendaraan yang membawa perbekalan Abu Bakar dan perbekalan Rasulullah shallla Allahu 'alaihi wa sallam satu bersama budak Abu Bakr. Abu Bakr duduk sambil menunggu budak tersebut muncul, lalu budak tersebut muncul, namun ia tidak membawa untanya. Abu Bakr bekata; dimanakah untamu? Budak tersebut menjawab: hilang, tadi malam. Abu Bakar berkata: unta satu engkau hilangkan! Abu Bakr memukulnya sementara Rasulullah shallla Allahu 'alaihi wa sallam hanya tersenyum seraya berkata: \"Lihatlah apa yang dilakukan orang yang sedang berihram ini!\" Ibnu Abu Rizmah berkata: dan Rasulullah shallallahu 'alaihi wasallam tidak lebih dari mengatakan: \"Lihatlah apa yang dilakukan orang yang sedang berihram ini!\" sambil tersenyum. "},"1490":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا هَمَّامٌ قَالَ سَمِعْتُ عَطَاءً أَخْبَرَنَا صَفْوَانُ بْنُ يَعْلَى بْنِ أُمَيَّةَ عَنْ أَبِيهِأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ بِالْجِعْرَانَةِ وَعَلَيْهِ أَثَرُ خَلُوقٍ أَوْ قَالَ صُفْرَةٍ وَعَلَيْهِ جُبَّةٌ فَقَالَ يَا رَسُولَ اللَّهِ كَيْفَ تَأْمُرُنِي أَنْ أَصْنَعَ فِي عُمْرَتِي فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَحْيَ فَلَمَّا سُرِّيَ عَنْهُ قَالَ أَيْنَ السَّائِلُ عَنْ الْعُمْرَةِ قَالَ اغْسِلْ عَنْكَ أَثَرَ الْخَلُوقِ أَوْ قَالَ أَثَرَ الصُّفْرَةِ وَاخْلَعْ الْجُبَّةَ عَنْكَ وَاصْنَعْ فِي عُمْرَتِكَ مَا صَنَعْتَ فِي حَجَّتِكَحَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ عَطَاءٍ عَنْ يَعْلَى بْنِ أُمَيَّةَ وَهُشيْمٌ عَنْ الْحَجَّاجِ عَنْ عَطَاءٍ عَنْ صَفْوَانَ بْنِ يَعْلَى عَنْ أَبِيهِ بِهَذِهِ الْقِصَّةِ قَالَ فِيهِ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اخْلَعْ جُبَّتَكَ فَخَلَعَهَا مِنْ رَأْسِهِ وَسَاقَ الْحَدِيثَ حَدَّثَنَا يَزِيدُ بْنُ خَالِدِ بْنِ عَبْدِ اللَّهِ بْنِ مَوْهَبٍ الْهَمَدَانِيُّ الرَّمْلِيُّ قَالَ حَدَّثَنِي اللَّيْثُ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ ابْنِ يَعْلَى ابْنِ مُنْيَةَ عَنْ أَبِيهِ بِهَذَا الْخَبَرِ قَالَ فِيهِ فَأَمَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَنْزِعَهَا نَزْعًا وَيَغْتَسِلَ مَرَّتَيْنِ أَوْ ثَلَاثًا وَسَاقَ الْحَدِيثَ حَدَّثَنَا عُقْبَةُ بْنُ مُكْرِمٍ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ قَيْسَ بْنَ سَعْدٍ يُحَدِّثُ عَنْ عَطَاءٍ عَنْ صَفْوَانَ بْنِ يَعْلَى بْنِ أُمَيَّةَ عَنْ أَبِيهِ أَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْجِعْرَانَةِ وَقَدْ أَحْرَمَ بِعُمْرَةٍ وَعَلَيْهِ جُبَّةٌ وَهُوَ مُصَفِّرٌ لِحْيَتَهُ وَرَأْسَهُ وَسَاقَ هَذَا الْحَدِيثَ","id":"Telah menceritakan kepada Kami [Muhammad bin Katsir], telah mengabarkan kepada Kami [Hammam], ia berkata; saya mendengar ['Atha`], telah mengabarkan kepada Kami [Shafwan bin Ya'la bin Umayyah] dari [ayahnya] bahwa seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam sementara beliau berada di Ji'ranah, dan pada diri orang tersebut terdapat bekas Khaluq (minyak yang terbuat dari kunyit dan yang lainnya) -atau ia mengatakan shufrah (sama dengan khaluq) - dan ia memakai jubbah, ia berkata; wahai Rasulullah, apa yang anda perintahkan agar aku lakukan dalam umrahku? Kemudian Allah tabaraka wa ta'ala menurunkan wahyu kepada Nabi shallallahu 'alaihi wasallam, kemudian tatkala telah hilang kesusahan darinya beliau mengatakan: \"Dimanakah orang yang bertanya mengenai Umrah tadi?\" Beliau bersabda: \"Sucilah bekas khaluq tersebut atau beliau mengatakan: bekas Shufrah tersebut, dan lepaskan jubbah darimu, serta perbuatlah pada umrahmu apa yang engkau perbuat pada hajimu.\" Telah menceritakan kepada Kami [Muhammad bin Isa], telah menceritakan kepada Kami [Abu 'Awanah] dari [Abu Bisyr] dari ['Atha`] dari [Ya'la bin Umayyah] dan [Husyaim] dari [Al Hajjaj] dari ['Atho`] dari [Shafwan bin Ya'la] dari [ayahnya] dengan sifat ini. Dalam hadits tersebut Ya'la mengatakan; kemudian Nabi shallallahu 'alaihi wasallam berkata kepadanya: \"Lepaskan jubahmu!\" kemudian ia melepaskan jubah tersebut dari kepalanya. Dan ia menyebutkan hadits tesebut. Telah menceritakan kepada Kami [Yazid bin Khalid bin Abdullah bin Mauhib Al Hamadani Ar Ramli], ia berkata; telah menceritakan kepadaku [Al Laits] dari ['Atha` bin Abu Rabah] dari [Ibnu Ya'la bin Munyah] dari [ayahnya] dengan berita ini. Padanya ia mengatakan; kemudian Rasulullah shallAllahu wa'alaihi wa sallam memerintahkan agar ia melepas jubah tersebut dan mandi dua kali, atau tiga kali. Dan ia menyebutkan hadits tersebut. Telah menceritakan kepada Kami ['Uqbah bin Mukrim], telah menceritakan kepada Kami [Wahb bin Jarir], telah menceritakan kepada Kami [ayahku], ia berkata; saya mendengar [Qais bin Sa'd] menceritakan dari ['Atha`] dari [Shafwan bin Ya'la bin Umayyah] dari [ayahnya], bahwa seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam di Ji'ranah, dan ia telah berihram untuk melakukan umrah dan ia memakai jubah, dan ia mencelup jenggot dan kepalanya dengan Shufrah…. Dan ia menyebutkan hadits ini. "},"1491":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَأَحْمَدُ بْنُ حَنْبَلٍ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَسَأَلَ رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَتْرُكُ الْمُحْرِمُ مِنْ الثِّيَابِ فَقَالَ لَا يَلْبَسُ الْقَمِيصَ وَلَا الْبُرْنُسَ وَلَا السَّرَاوِيلَ وَلَا الْعِمَامَةَ وَلَا ثَوْبًا مَسَّهُ وَرْسٌ وَلَا زَعْفَرَانٌ وَلَا الْخُفَّيْنِ إِلَّا لِمَنْ لَا يَجِدُ النَّعْلَيْنِ فَمَنْ لَمْ يَجِدْ النَّعْلَيْنِ فَلْيَلْبَسْ الْخُفَّيْنِ وَلْيَقْطَعْهُمَا حَتَّى يَكُونَا أَسْفَلَ مِنْ الْكَعْبَيْنِحَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ وَزَادَ وَلَا تَنْتَقِبُ الْمَرْأَةُ الْحَرَامُ وَلَا تَلْبَسُ الْقُفَّازَيْنِ قَالَ أَبُو دَاوُد وَقَدْ رَوَى هَذَا الْحَدِيثَ حَاتِمُ بْنُ إِسْمَعِيلَ وَيَحْيَى بْنُ أَيُّوبَ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَلَى مَا قَالَ اللَّيْثُ وَرَوَاهُ مُوسَى بْنُ طَارِقٍ عَنْ مُوسَى بْنِ عُقْبَةَ مَوْقُوفًا عَلَى ابْنِ عُمَرَ وَكَذَلِكَ رَوَاهُ عُبَيْدُ اللَّهِ بْنُ عُمَرَ وَمَالِكٌ وَأَيُّوبُ مَوْقُوفًا وَإِبْرَاهِيمُ بْنُ سَعِيدٍ الْمَدِينِيُّ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُحْرِمَةُ لَا تَنْتَقِبُ وَلَا تَلْبَسُ الْقُفَّازَيْنِ قَالَ أَبُو دَاوُد إِبْرَاهِيمُ بْنُ سَعِيدٍ الْمَدِينِيُّ شَيْخٌ مِنْ أَهْلِ الْمَدِينَةِ لَيْسَ لَهُ كَبِيرُ حَدِيثٍ","id":"Telah menceritakan kepada Kami [Musaddad] serta [Ahmad bin Hanbal], mereka berkata; telah menceritakan kepada Kami [Sufyan] dari [Az Zuhri] dari [Salim] dari [ayahnya], ia berkata; seorang laki-laki bertanya kepada Rasulullah shallAllahu wa'alaihi wa sallam; pakaian apakah yang ditinggalkan oleh orang yang berihram? Kemudian beliau bersabda: \"Ia tidak boleh memakai jubah, dan baju panjang yang bertutup kepala, celana panjang, sorban, dan baju yang diusap waras, dan kunyit, serta dua sepatu. Kecuali bagi orang yang tidak mendapatkan sandal, maka orang yang tidak mendapatkan sandal hendaknya ia memotong kedua sepatu tersebut hingga di bawah kedua mata kaki.\" Telah menceritakan kepada Kami [Abdullah bin Maslamah] dari [Malik] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam secara makna. Telah menceritakan kepada Kami [Qutaibah bin Sa'id], telah menceritakan kepada Kami [Al Laits] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam secara makna. Dan ia tambahkan kata; dan tidak boleh seorang wanita yang berihram memakai niqab (penutup wajah), dan tidak boleh memakai kaos tangan. Abu Daud berkata; hadits ini diriwayatkan oleh [Hatim bin Isma'il] dan [Yahya bin Ayyub] dari [Musa bin 'Uqbah] dari [Nafi'] sebagaimana yang dikatakan Al Laits. Dan hadits tersebut diriwayatkan oleh [Musa bin Thariq] dari [Musa bin 'Uqbah] secara mauquf kepada [Ibnu Umar]. Begitu juga hadits tersebut diriwayatkan oleh ['Ubaidullah bin Umar] serta [Malik] dan [Ayyub] secara mauquf, dan [Ibrahim bin Sa'id Al Madini] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam: \"Wanita yang berihram tidak boleh memakai niqab (penutup wajah) dan tidak boleh memakai kaos tangan.\" Abu Daud berkata; Ibrahim bin Sa'id Al Madini adalah seorang Syekh dari penduduk Madinah, ia tidak memiliki hadits yang banyak. "},"1492":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعِيدٍ الْمَدِينِيُّ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُحْرِمَةُ لَا تَنْتَقِبُ وَلَا تَلْبَسُ الْقُفَّازَيْنِ","id":"Telah menceritakan kepada Kami [Qutaibah bin Sa'id] telah menceritakan kepada Kami [Ibrahim bin Sa'id Al Madini] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Wanita yang berihram tidak boleh memakai niqab dan tidak boleh memakai kaos tangan.\""},"1493":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ قَالَ فَإِنَّ نَافِعًا مَوْلَى عَبْدِ اللَّهِ بْنِ عُمَرَ حَدَّثَنِي عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى النِّسَاءَ فِي إِحْرَامِهِنَّ عَنْ الْقُفَّازَيْنِ وَالنِّقَابِ وَمَا مَسَّ الْوَرْسُ وَالزَّعْفَرَانُ مِنْ الثِّيَابِ وَلْتَلْبَسْ بَعْدَ ذَلِكَ مَا أَحَبَّتْ مِنْ أَلْوَانِ الثِّيَابِ مُعَصْفَرًا أَوْ خَزًّا أَوْ حُلِيًّا أَوْ سَرَاوِيلَ أَوْ قَمِيصًا أَوْ خُفًّاقَالَ أَبُو دَاوُد رَوَى هَذَا الْحَدِيثَ عَنْ ابْنِ إِسْحَقَ عَنْ نَافِعٍ عَبْدَةُ بْنُ سُلَيْمَانَ وَمُحَمَّدُ بْنُ سَلَمَةَ إِلَى قَوْلِهِ وَمَا مَسَّ الْوَرْسُ وَالزَّعْفَرَانُ مِنْ الثِّيَابِ وَلَمْ يَذْكُرَا مَا بَعْدَهُ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal] telah menceritakan kepada Kami [Ya'qub], telah menceritakan kepada Kami [ayahku] dari [Ibnu Ishaq], ia berkata; sesungguhnya [Nafi'] mantan budak Abdullah bin Umar telah menceritakan kepadaku dari [Abdullah bin Umar] bahwa ia telah mendengar Rasulullah shallAllahu wa'alaihi wa sallam melarang para wanita ketika melakukan ihram dari memakai kaos tangan, serta niqab (penutup wajah), serta pakaian yang terolesi daun bidara serta kunyit, dan setelah itu silahkan ia melakai apa yang ia sukai dari berbagai warna pakaian, yang diwarnai kuning, sutera, atau perhiasan atau celana panjang, atau jubah atau sepatu. Abu Daud berkata; hadits ini diriwayatkan oleh ['Abdah bin Sulaiman], serta [Muhammad bin Salamah] dari [Ibnu Ishaq], dari [Nafi'] hingga perkataannya; serta pakaian yang terolesi Waras serta kunyit. Dan mereka berdua tidak menyebutkan setelah perkataan tersebut. "},"1494":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّهُ وَجَدَ الْقُرَّ فَقَالَ أَلْقِ عَلَيَّ ثَوْبًا يَا نَافِعُ فَأَلْقَيْتُ عَلَيْهِ بُرْنُسًا فَقَالَ تُلْقِي عَلَيَّ هَذَا وَقَدْ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَلْبَسَهُ الْمُحْرِمُ","id":"Telah menceritakan kepada Kami [Musa bin Isma'il], telah menceritakan kepada Kami [Hammad] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] bahwa ia merasakan dingin, kemudian ia berkata; lemparkan kepadaku satu pakaian wahai Nafi'. Kemudian aku melemparkan kepadanya pakaian yang bertutup kepala. Lalu ia berkata; apakah engkau pakaian ini kepadaku? Sungguh Rasulullah shallAllahu wa'alaihi wa sallam telah melarang orang yang bermuhrim memakai pakaian tersebut. "},"1495":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرِ بْنِ زَيْدٍ عَنْ ابْنِ عَبَّاسٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ السَّرَاوِيلُ لِمَنْ لَا يَجِدُ الْإِزَارَ وَالْخُفُّ لِمَنْ لَا يَجِدُ النَّعْلَيْنِقَالَ أَبُو دَاوُد هَذَا حَدِيثُ أَهْلِ مَكَّةَ وَمَرْجِعُهُ إِلَى الْبَصْرَةِ إِلَى جَابِرِ بْنِ زَيْدٍ وَالَّذِي تَفَرَّدَ بِهِ مِنْهُ ذِكْرُ السَّرَاوِيلِ وَلَمْ يَذْكُرْ الْقَطْعَ فِي الْخُفِّ","id":"Telah menceritakan kepada Kami [Sulaiman bin Harb], telah menceritakan kepada Kami [Hammad bin Zaid] dari ['Amr bin Dinar] dari [Jabir bin Zaid] dari [Ibnu Abbas], ia berkata; saya mendengar Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Celana panjang adalah untuk orang yang tidak mendapatkan sarung, sepatu adalah orang yang tidak mendapatkan sandal.\" Abu Daud berkata; ini adalah hadits penduduk Mekkah dan kembalinya ke Bashrah, kepada Jabir bin Zaid, dan yang menjadi kekhususan darinya adalah menyebutkan celana panjang dan tidak menyebutkan memotong sepatu."},"1496":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ الْجُنَيْدِ الدَّامِغَانِيُّ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ أَخْبَرَنِي عُمَرُ بْنُ سُوَيْدٍ الثَّقَفِيُّ قَالَ حَدَّثَتْنِي عَائِشَةُ بِنْتُ طَلْحَةَ أَنَّ عَائِشَةَ أُمَّ الْمُؤْمِنِينَ رَضِيَ اللَّهُ عَنْهَا حَدَّثَتْهَا قَالَتْكُنَّا نَخْرُجُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى مَكَّةَ فَنُضَمِّدُ جِبَاهَنَا بِالسُّكِّ الْمُطَيَّبِ عِنْدَ الْإِحْرَامِ فَإِذَا عَرِقَتْ إِحْدَانَا سَالَ عَلَى وَجْهِهَا فَيَرَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا يَنْهَاهَا","id":"Telah menceritakan kepada Kami [Al Husain bin Al Junaid Ad Damaghani], telah menceritakan kepada Kami [Abu Usamah], ia berkata; telah mengabarkan kepadaku [Umar bin Suwaid Ats Tsaqafi], ia berkata; [Aisyah binti Thalhah] telah menceritakan kepadaku bahwa [Aisyah] ummul mukminin radliallahu 'anha telah menceritakan kepadanya, ia berkata; Kami pernah keluar bersama Nabi shallallahu 'alaihi wasallam ke Mekkah, dan Kami membalut kening Kami dengan minyak wangi ketika berihram, apabila salah seorang daintara Kami berkeringat maka mengalir ke wajahnya, kemudian Nabi shallallahu 'alaihi wasallam melihatnya dan beliau tidak melarang Kami. "},"1497":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ قَالَ ذَكَرْتُ لِابْنِ شِهَابٍ فَقَالَ حَدَّثَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ يَعْنِي ابْنَ عُمَرَ كَانَ يَصْنَعُ ذَلِكَ يَعْنِي يَقْطَعُ الْخُفَّيْنِ لِلْمَرْأَةِ ��لْمُحْرِمَةِ ثُمَّ حَدَّثَتْهُ صَفِيَّةُ بِنْتُ أَبِي عُبَيْدٍ أَنَّ عَائِشَةَ حَدَّثَتْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ كَانَ رَخَّصَ لِلنِّسَاءِ فِي الْخُفَّيْنِ فَتَرَكَ ذَلِكَ","id":"Telah menceritakan kepada Kami [Qutaibah bin Sa'id], telah menceritakan kepada Kami [Ibnu Abu 'Adi] dari [Muhammad bin Ishaq], ia berkata; aku menyebutkan kepada [Ibnu Syihab], ia berkata; telah menceritakan kepadaku [Salim bin Abdullah] bahwa [Abdullah bin Umar] melakukan hal tersebut yaitu memotong sepatu untuk seorang wanita yang berihram, kemudian [Shafiyyah binti Abu 'Ubaid] menceritakan kepadanya bahwa [Aisyah] telah menceritakan kepadanya bahwa Rasulullah shallAllahu wa'alaihi wa sallam memberikan keringanan kepada para wanita untuk memakai sepatu, kemudian Ibnu meninggalkan hal tersebut (memotong sepatu untuk wanita). "},"1498":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَالَ سَمِعْتُ الْبَرَاءَ يَقُولُلَمَّا صَالَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهْلَ الْحُدَيْبِيَةِ صَالَحَهُمْ عَلَى أَنْ لَا يَدْخُلُوهَا إِلَّا بِجُلْبَانِ السِّلَاحِ فَسَأَلْتُهُ مَا جُلْبَانُ السِّلَاحِ قَالَ الْقِرَابُ بِمَا فِيهِ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Muhammad bin Ja'far], telah menceritakan kepada Kami [Syu'bah] dari [Abu Ishaq], ia berkata; saya mendengar [Al Bara`] berkata; tatkala Rasulullah shallAllahu wa'alaihi wa sallam berdamai dengan penduduk Hudaibiyah, beliau berdamai agar mereka tidak masuk Hudaibiyah kecuali dengan julban as silah, kemudian aku bertanya kepadanya mengenai julban as silah, beliau berkata: \"Sarung pedang dengan isinya.\""},"1499":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا يَزِيدُ بْنُ أَبِي زِيَادٍ عَنْ مُجَاهِدٍ عَنْ عَائِشَةَ قَالَتْكَانَ الرُّكْبَانُ يَمُرُّونَ بِنَا وَنَحْنُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُحْرِمَاتٌ فَإِذَا حَاذَوْا بِنَا سَدَلَتْ إِحْدَانَا جِلْبَابَهَا مِنْ رَأْسِهَا عَلَى وَجْهِهَا فَإِذَا جَاوَزُونَا كَشَفْنَاهُ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Husyaim], telah mengabarkan kepada Kami [Yazid bin Abu Ziyad] dari [Mujahid] dari [Aisyah] ia berkata; orang-orang yang berkendaraan melewati Kami sementara Kami sedang berihram bersama Rasulullah shallAllahu wa'alaihi wa sallam kemudian apabila mereka dekat dengan Kami maka salah seorang diantara Kami menutupkan jilbabnya dari kepala ke wajahnya, kemudian apabila mereka telah melewati Kami maka Kami membukanya. "},"1500":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ أَبِي عَبْدِ الرَّحِيمِ عَنْ زَيْدِ بْنِ أَبِي أُنَيْسَةَ عَنْ يَحْيَى بْنِ حُصَيْنٍ عَنْ أُمِّ الْحُصَيْنِ حَدَّثَتْهُ قَالَتْحَجَجْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَجَّةَ الْوَدَاعِ فَرَأَيْتُ أُسَامَةَ وَبِلَالًا وَأَحَدُهُمَا آخِذٌ بِخِطَامِ نَاقَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْآخَرُ رَافِعٌ ثَوْبَهُ لِيَسْتُرَهُ مِنْ الْحَرِّ حَتَّى رَمَى جَمْرَةَ الْعَقَبَةِ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Muhammad bin Salamah] dari [Abu Abdurrahim] dari [Zaid bin Abu Unaisah] dari [Yahya bin Hushain] dari [Ummu Al Hushain], ia telah menceritakan kepadanya, ia berkata; Kami telah berhaji bersama Nabi shallallahu 'alaihi wasallam pada saat haji wada', kemudian aku melihat Usamah dan Bilal, dan salah seorang dari mereka memegang tali kekang unta Nabi shallallahu 'alaihi wasallam sementara yang lain mengangkat pakaiannya agar menutupinya dari panas, hingga beliau melempar jumrah 'aqabah. "}};
